'use client'

import { useTranslations } from 'next-intl'
import { AboutLayout } from '@/components/AboutLayout'
import { HelpCircle, ChevronDown } from 'lucide-react'
import { useState } from 'react'
import { cn } from '@/lib/utils'

interface FaqPageClientProps {
    user?: {
        id: string
        email?: string
        user_metadata?: {
            avatar_url?: string
            full_name?: string
            name?: string
        }
    } | null
}

export function FaqPageClient({ user }: FaqPageClientProps) {
    const t = useTranslations('Faq')
    const tAbout = useTranslations('About')
    const [openItems, setOpenItems] = useState<string[]>([])

    const toggleItem = (key: string) => {
        setOpenItems(prev =>
            prev.includes(key)
                ? prev.filter(k => k !== key)
                : [...prev, key]
        )
    }

    const faqItems = [
        'whatIsSyriaHub',
        'howToJoin',
        'whatCanIPost',
        'howModeration',
        'canIEdit',
        'whatAreRoles',
        'howToBecome',
        'isContentFree'
    ]

    const categories = [
        { key: 'gettingStarted', items: ['whatIsSyriaHub', 'howToJoin'] },
        { key: 'content', items: ['whatCanIPost', 'canIEdit'] },
        { key: 'community', items: ['howModeration', 'whatAreRoles', 'howToBecome'] },
        { key: 'account', items: ['isContentFree'] }
    ]

    return (
        <AboutLayout user={user}>
            <div className="prose prose-lg dark:prose-invert max-w-none">
                <h2 className="text-2xl font-bold text-primary dark:text-secondary mb-6 flex items-center gap-3">
                    <HelpCircle className="w-7 h-7" />
                    {tAbout('faqTitle')}
                </h2>

                <div className="not-prose space-y-8">
                    {categories.map((category) => (
                        <div key={category.key}>
                            <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-4">
                                {t(`categories.${category.key}`)}
                            </h3>
                            <div className="space-y-2">
                                {category.items.map((itemKey) => {
                                    const isOpen = openItems.includes(itemKey)
                                    return (
                                        <div
                                            key={itemKey}
                                            className="border border-border dark:border-dark-border rounded-lg overflow-hidden"
                                        >
                                            <button
                                                onClick={() => toggleItem(itemKey)}
                                                className="w-full flex items-center justify-between p-4 text-start bg-gray-50 dark:bg-dark-bg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                                            >
                                                <span className="font-medium text-text dark:text-dark-text">
                                                    {t(`questions.${itemKey}.q`)}
                                                </span>
                                                <ChevronDown
                                                    className={cn(
                                                        "w-5 h-5 text-text-muted dark:text-dark-text-muted transition-transform flex-shrink-0 ms-4",
                                                        isOpen && "rotate-180"
                                                    )}
                                                />
                                            </button>
                                            <div
                                                className={cn(
                                                    "overflow-hidden transition-all duration-200",
                                                    isOpen ? "max-h-96" : "max-h-0"
                                                )}
                                            >
                                                <div className="p-4 bg-white dark:bg-dark-surface text-text-light dark:text-dark-text-muted">
                                                    {t(`questions.${itemKey}.a`)}
                                                </div>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </AboutLayout>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useTranslations } from 'next-intl'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { createClient } from '@/lib/supabase/client'
import { UserProgressCard } from '@/components/UserProgressCard'
import {
    Trophy,
    Star,
    Medal,
    Crown,
    Award,
    Users,
    Flame,
    Zap,
    BookOpen,
    MessageCircle,
    ThumbsUp,
    UserPlus,
    ClipboardCheck,
    UserCheck,
    Rocket,
    Lock,
    CheckCircle2,
    Loader2
} from 'lucide-react'
import { cn } from '@/lib/utils'

interface Achievement {
    id: string
    name: string
    description: string
    icon: string
    category: string
    xp_reward: number
    unlocked_at?: string
    criteria?: {
        type: string
        threshold?: number
    }
}

interface AchievementsData {
    unlocked: Achievement[]
    available: Achievement[]
    total_count: number
    unlocked_count: number
    completion_percentage: number
}

const iconMap: Record<string, React.ComponentType<{ className?: string }>> = {
    'footprints': Star,
    'pen-tool': BookOpen,
    'book-open': BookOpen,
    'lightbulb': Star,
    'hand-helping': Users,
    'award': Award,
    'trophy': Trophy,
    'message-circle': MessageCircle,
    'users': Users,
    'star': Star,
    'medal': Medal,
    'crown': Crown,
    'thumbs-up': ThumbsUp,
    'trending-up': Zap,
    'flame': Flame,
    'zap': Zap,
    'clipboard-check': ClipboardCheck,
    'user-check': UserCheck,
    'rocket': Rocket,
    'user-plus': UserPlus,
}

const categoryColors: Record<string, { bg: string, text: string, border: string }> = {
    contribution: {
        bg: 'bg-blue-50 dark:bg-blue-900/20',
        text: 'text-blue-600 dark:text-blue-400',
        border: 'border-blue-200 dark:border-blue-800'
    },
    community: {
        bg: 'bg-green-50 dark:bg-green-900/20',
        text: 'text-green-600 dark:text-green-400',
        border: 'border-green-200 dark:border-green-800'
    },
    expertise: {
        bg: 'bg-purple-50 dark:bg-purple-900/20',
        text: 'text-purple-600 dark:text-purple-400',
        border: 'border-purple-200 dark:border-purple-800'
    },
    special: {
        bg: 'bg-amber-50 dark:bg-amber-900/20',
        text: 'text-amber-600 dark:text-amber-400',
        border: 'border-amber-200 dark:border-amber-800'
    },
}

export default function AchievementsPage() {
    const [user, setUser] = useState<any>(null)
    const [achievements, setAchievements] = useState<AchievementsData | null>(null)
    const [loading, setLoading] = useState(true)
    const [checking, setChecking] = useState(false)
    const [activeTab, setActiveTab] = useState<'unlocked' | 'available'>('unlocked')
    const supabase = createClient()
    const t = useTranslations('Gamification')

    useEffect(() => {
        const fetchData = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            setUser(user)

            if (user) {
                // Fetch achievements
                const { data, error } = await supabase.rpc('get_user_achievements', {
                    p_user_id: user.id
                })

                if (!error && data?.success) {
                    setAchievements(data)
                }
            }
            setLoading(false)
        }
        fetchData()
    }, [supabase])

    const checkForNewAchievements = async () => {
        if (!user) return
        setChecking(true)

        const { data, error } = await supabase.rpc('check_and_unlock_achievements', {
            p_user_id: user.id
        })

        if (!error && data?.success) {
            // Refresh achievements list
            const { data: refreshed } = await supabase.rpc('get_user_achievements', {
                p_user_id: user.id
            })
            if (refreshed?.success) {
                setAchievements(refreshed)
            }
        }
        setChecking(false)
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
                <Navbar />
                <main className="flex-1 flex items-center justify-center">
                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                </main>
                <Footer />
            </div>
        )
    }

    if (!user) {
        return (
            <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
                <Navbar />
                <main className="flex-1 container-custom py-12">
                    <div className="text-center py-16">
                        <Lock className="w-16 h-16 mx-auto text-text-light dark:text-dark-text-muted mb-4" />
                        <h1 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
                            {t('signInToView')}
                        </h1>
                        <p className="text-text-light dark:text-dark-text-muted">
                            {t('signInDescription')}
                        </p>
                    </div>
                </main>
                <Footer />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            <main className="flex-1 container-custom py-8">
                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                    <div className="flex items-start gap-3">
                        <Trophy className="w-6 h-6 sm:w-8 sm:h-8 text-primary flex-shrink-0 mt-1" />
                        <div>
                            <h1 className="text-xl sm:text-2xl font-bold text-text dark:text-dark-text">
                                {t('pageTitle')}
                            </h1>
                            <p className="text-sm sm:text-base text-text-light dark:text-dark-text-muted mt-0.5">
                                {t('pageSubtitle')}
                            </p>
                        </div>
                    </div>
                    <button
                        onClick={checkForNewAchievements}
                        disabled={checking}
                        className="px-3 py-1.5 sm:px-4 sm:py-2 bg-primary text-white rounded-lg text-sm sm:text-base font-medium hover:bg-primary-dark transition-colors disabled:opacity-50 flex items-center gap-1.5 sm:gap-2 self-start sm:self-auto flex-shrink-0"
                    >
                        {checking ? (
                            <Loader2 className="w-3.5 h-3.5 sm:w-4 sm:h-4 animate-spin" />
                        ) : (
                            <Zap className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                        )}
                        <span className="whitespace-nowrap">{t('checkForNew')}</span>
                    </button>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Left Column - Progress Card */}
                    <div className="lg:col-span-1">
                        <UserProgressCard userId={user.id} />

                        {/* Stats Summary */}
                        {achievements && (
                            <div className="mt-6 p-6 bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border">
                                <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wide mb-4">
                                    {t('achievementProgress')}
                                </h3>
                                <div className="space-y-4">
                                    <div>
                                        <div className="flex justify-between text-sm mb-1">
                                            <span className="text-text-light dark:text-dark-text-muted">{t('completion')}</span>
                                            <span className="font-medium text-text dark:text-dark-text">
                                                {achievements.unlocked_count}/{achievements.total_count}
                                            </span>
                                        </div>
                                        <div className="h-2 bg-gray-100 dark:bg-dark-border rounded-full overflow-hidden">
                                            <div
                                                className="h-full bg-gradient-to-r from-primary to-secondary rounded-full transition-all"
                                                style={{ width: `${achievements.completion_percentage}%` }}
                                            />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4 pt-2">
                                        <div className="text-center p-3 bg-gray-50 dark:bg-dark-bg rounded-lg">
                                            <p className="text-xl font-bold text-primary">{achievements.unlocked_count}</p>
                                            <p className="text-xs text-text-light dark:text-dark-text-muted">{t('unlocked')}</p>
                                        </div>
                                        <div className="text-center p-3 bg-gray-50 dark:bg-dark-bg rounded-lg">
                                            <p className="text-xl font-bold text-text dark:text-dark-text">
                                                {achievements.total_count - achievements.unlocked_count}
                                            </p>
                                            <p className="text-xs text-text-light dark:text-dark-text-muted">{t('remaining')}</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Right Column - Achievements Grid */}
                    <div className="lg:col-span-2">
                        {/* Tabs */}
                        <div className="flex gap-2 mb-6">
                            <button
                                onClick={() => setActiveTab('unlocked')}
                                className={cn(
                                    "px-4 py-2 rounded-lg font-medium transition-colors",
                                    activeTab === 'unlocked'
                                        ? "bg-primary text-white dark:text-white"
                                        : "bg-gray-100 dark:bg-dark-surface text-text dark:text-dark-text hover:bg-gray-200 dark:hover:bg-dark-border"
                                )}
                            >
                                <CheckCircle2 className="w-4 h-4 inline mr-2" />
                                {t('unlocked')} ({achievements?.unlocked?.length || 0})
                            </button>
                            <button
                                onClick={() => setActiveTab('available')}
                                className={cn(
                                    "px-4 py-2 rounded-lg font-medium transition-colors",
                                    activeTab === 'available'
                                        ? "bg-primary text-white dark:text-white"
                                        : "bg-gray-100 dark:bg-dark-surface text-text dark:text-dark-text hover:bg-gray-200 dark:hover:bg-dark-border"
                                )}
                            >
                                <Lock className="w-4 h-4 inline mr-2" />
                                {t('available')} ({achievements?.available?.length || 0})
                            </button>
                        </div>

                        {/* Achievement Cards */}
                        <div className="grid gap-4 md:grid-cols-2">
                            {activeTab === 'unlocked' && achievements?.unlocked?.map((achievement) => {
                                const Icon = iconMap[achievement.icon] || Award
                                const colors = categoryColors[achievement.category] || categoryColors.special

                                return (
                                    <div
                                        key={achievement.id}
                                        className={cn(
                                            "p-4 rounded-xl border-2 transition-all",
                                            colors.bg,
                                            colors.border
                                        )}
                                    >
                                        <div className="flex items-start gap-4">
                                            <div className={cn(
                                                "p-3 rounded-xl shrink-0",
                                                colors.bg
                                            )}>
                                                <Icon className={cn("w-6 h-6", colors.text)} />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center justify-between gap-2 mb-1">
                                                    <h3 className="font-semibold text-lg text-text dark:text-dark-text leading-tight truncate pr-2">
                                                        {achievement.name}
                                                    </h3>
                                                    <CheckCircle2 className="w-5 h-5 text-green-500 shrink-0" />
                                                </div>
                                                <p className="text-sm text-text-light dark:text-dark-text-muted mb-3 line-clamp-2">
                                                    {achievement.description}
                                                </p>
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    <span className={cn(
                                                        "text-xs font-medium px-2.5 py-1 rounded-md bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400",
                                                    )}>
                                                        +{achievement.xp_reward} XP
                                                    </span>
                                                    {achievement.unlocked_at && (
                                                        <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                            {new Date(achievement.unlocked_at).toLocaleDateString()}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                )
                            })}

                            {activeTab === 'available' && achievements?.available?.map((achievement) => {
                                const Icon = iconMap[achievement.icon] || Award
                                const colors = categoryColors[achievement.category] || categoryColors.special

                                return (
                                    <div
                                        key={achievement.id}
                                        className="p-4 rounded-xl border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface/50 hover:bg-white dark:hover:bg-dark-surface transition-colors group"
                                    >
                                        <div className="flex items-start gap-4">
                                            <div className="p-3 rounded-xl bg-gray-50 dark:bg-dark-bg shrink-0 group-hover:bg-gray-100 dark:group-hover:bg-dark-border transition-colors">
                                                <Icon className={cn("w-6 h-6 transition-colors", colors.text)} />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center justify-between gap-2 mb-1">
                                                    <h3 className="font-semibold text-lg text-text dark:text-dark-text leading-tight truncate pr-2">
                                                        {achievement.name}
                                                    </h3>
                                                    <Lock className="w-4 h-4 text-text-light dark:text-dark-text-muted/60 shrink-0" />
                                                </div>
                                                <p className="text-sm text-text-light dark:text-dark-text-muted mb-3 line-clamp-2">
                                                    {achievement.description}
                                                </p>
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    <span className={cn(
                                                        "text-xs font-medium px-2.5 py-1 rounded-md capitalize",
                                                        colors.bg,
                                                        colors.text
                                                    )}>
                                                        {achievement.category}
                                                    </span>
                                                    <span className="text-xs font-medium px-2.5 py-1 rounded-md bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400">
                                                        +{achievement.xp_reward} XP
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                )
                            })}

                            {activeTab === 'unlocked' && (!achievements?.unlocked || achievements.unlocked.length === 0) && (
                                <div className="col-span-2 text-center py-12">
                                    <Trophy className="w-16 h-16 mx-auto text-text-light dark:text-dark-text-muted mb-4 opacity-50" />
                                    <h3 className="text-lg font-medium text-text dark:text-dark-text mb-2">
                                        {t('noAchievements')}
                                    </h3>
                                    <p className="text-text-light dark:text-dark-text-muted">
                                        {t('noAchievementsDesc')}
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { AdminSidebar } from '@/components/admin'
import { Button } from '@/components/ui/button'
import { Loader2, Award, Search, Pencil, Trash2, GitMerge, Check, X } from 'lucide-react'
import { useToast } from '@/components/ui/toast'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { useTranslations } from 'next-intl'
import { cn } from '@/lib/utils'

const SKILL_CATEGORIES = [
    'Research Methods',
    'Technical',
    'Domain Knowledge',
    'Work Field',
    'Practical Expertise'
]

interface Skill {
    id: string
    name: string
    category: string
    is_recognized: boolean
    created_by: string | null
    created_at: string
    user_count: number
    creator_name?: string | null
}

export default function AdminSkillsPage() {
    const t = useTranslations('Admin.skillsPage')
    const tCommon = useTranslations('Common')
    const [skills, setSkills] = useState<Skill[]>([])
    const [loading, setLoading] = useState(true)
    const [searchQuery, setSearchQuery] = useState('')
    const [categoryFilter, setCategoryFilter] = useState<string>('all')
    const [recognizedFilter, setRecognizedFilter] = useState<'all' | 'recognized' | 'user'>('all')

    // Edit dialog state
    const [editDialogOpen, setEditDialogOpen] = useState(false)
    const [editingSkill, setEditingSkill] = useState<Skill | null>(null)
    const [editName, setEditName] = useState('')
    const [editCategory, setEditCategory] = useState('')
    const [editRecognized, setEditRecognized] = useState(false)
    const [saving, setSaving] = useState(false)

    // Delete dialog state
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false)
    const [deletingSkill, setDeletingSkill] = useState<Skill | null>(null)
    const [deleting, setDeleting] = useState(false)

    // Merge dialog state
    const [mergeDialogOpen, setMergeDialogOpen] = useState(false)
    const [mergingSkill, setMergingSkill] = useState<Skill | null>(null)
    const [mergeTargetId, setMergeTargetId] = useState<string>('')
    const [merging, setMerging] = useState(false)

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()

    useEffect(() => {
        fetchSkills()
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    const fetchSkills = async () => {
        setLoading(true)
        try {
            // Get all skills with user count
            const { data: skillsData, error: skillsError } = await supabase
                .from('skills')
                .select('*')
                .order('name')

            if (skillsError) throw skillsError

            // Get user counts for each skill
            const { data: userSkillsCounts } = await supabase
                .from('user_skills')
                .select('skill_id')

            const countMap: Record<string, number> = {}
            userSkillsCounts?.forEach(us => {
                countMap[us.skill_id] = (countMap[us.skill_id] || 0) + 1
            })

            // Get creator names
            const creatorIds = skillsData?.filter(s => s.created_by).map(s => s.created_by) || []
            const { data: creators } = await supabase
                .from('users')
                .select('id, name')
                .in('id', creatorIds)

            const creatorMap: Record<string, string> = {}
            creators?.forEach(c => {
                creatorMap[c.id] = c.name || 'Unknown'
            })

            const enrichedSkills: Skill[] = (skillsData || []).map(s => ({
                ...s,
                user_count: countMap[s.id] || 0,
                creator_name: s.created_by ? creatorMap[s.created_by] : null
            }))

            setSkills(enrichedSkills)
        } catch (error) {
            console.error('Error fetching skills:', error)
            showToast(t('fetchFail'), 'error')
        } finally {
            setLoading(false)
        }
    }

    // Filter skills
    const filteredSkills = useMemo(() => {
        return skills.filter(skill => {
            // Search filter
            if (searchQuery && !skill.name.toLowerCase().includes(searchQuery.toLowerCase())) {
                return false
            }
            // Category filter
            if (categoryFilter !== 'all' && skill.category !== categoryFilter) {
                return false
            }
            // Recognized filter
            if (recognizedFilter === 'recognized' && !skill.is_recognized) {
                return false
            }
            if (recognizedFilter === 'user' && skill.is_recognized) {
                return false
            }
            return true
        })
    }, [skills, searchQuery, categoryFilter, recognizedFilter])

    // Available merge targets (exclude the skill being merged)
    const mergeTargets = useMemo(() => {
        if (!mergingSkill) return []
        return skills.filter(s => s.id !== mergingSkill.id).sort((a, b) => a.name.localeCompare(b.name))
    }, [skills, mergingSkill])

    const handleEditClick = (skill: Skill) => {
        setEditingSkill(skill)
        setEditName(skill.name)
        setEditCategory(skill.category)
        setEditRecognized(skill.is_recognized)
        setEditDialogOpen(true)
    }

    const handleSaveEdit = async () => {
        if (!editingSkill || !editName.trim()) return
        setSaving(true)

        try {
            const { error } = await supabase
                .from('skills')
                .update({
                    name: editName.trim(),
                    category: editCategory,
                    is_recognized: editRecognized
                })
                .eq('id', editingSkill.id)

            if (error) throw error

            showToast(t('updateSuccess'), 'success')
            setEditDialogOpen(false)
            fetchSkills()
        } catch (error) {
            console.error('Error updating skill:', error)
            showToast(t('updateFail'), 'error')
        } finally {
            setSaving(false)
        }
    }

    const handleDeleteClick = (skill: Skill) => {
        setDeletingSkill(skill)
        setDeleteDialogOpen(true)
    }

    const handleConfirmDelete = async () => {
        if (!deletingSkill) return
        setDeleting(true)

        try {
            // First delete all user_skills references
            await supabase
                .from('user_skills')
                .delete()
                .eq('skill_id', deletingSkill.id)

            // Then delete the skill
            const { error } = await supabase
                .from('skills')
                .delete()
                .eq('id', deletingSkill.id)

            if (error) throw error

            showToast(t('deleteSuccess'), 'success')
            setDeleteDialogOpen(false)
            fetchSkills()
        } catch (error) {
            console.error('Error deleting skill:', error)
            showToast(t('deleteFail'), 'error')
        } finally {
            setDeleting(false)
        }
    }

    const handleMergeClick = (skill: Skill) => {
        setMergingSkill(skill)
        setMergeTargetId('')
        setMergeDialogOpen(true)
    }

    const handleConfirmMerge = async () => {
        if (!mergingSkill || !mergeTargetId) return
        setMerging(true)

        try {
            // Update all user_skills to point to the target skill
            // First, get users who have both skills (to avoid duplicates)
            const { data: usersWithTarget } = await supabase
                .from('user_skills')
                .select('user_id')
                .eq('skill_id', mergeTargetId)

            const targetUserIds = new Set(usersWithTarget?.map(u => u.user_id) || [])

            // Update user_skills that don't conflict
            const { data: usersWithSource } = await supabase
                .from('user_skills')
                .select('user_id')
                .eq('skill_id', mergingSkill.id)

            // Delete duplicates (users who have both)
            for (const us of usersWithSource || []) {
                if (targetUserIds.has(us.user_id)) {
                    await supabase
                        .from('user_skills')
                        .delete()
                        .eq('skill_id', mergingSkill.id)
                        .eq('user_id', us.user_id)
                }
            }

            // Update remaining to point to target
            await supabase
                .from('user_skills')
                .update({ skill_id: mergeTargetId })
                .eq('skill_id', mergingSkill.id)

            // Delete the merged skill
            await supabase
                .from('skills')
                .delete()
                .eq('id', mergingSkill.id)

            showToast(t('mergeSuccess'), 'success')
            setMergeDialogOpen(false)
            fetchSkills()
        } catch (error) {
            console.error('Error merging skills:', error)
            showToast(t('mergeFail'), 'error')
        } finally {
            setMerging(false)
        }
    }

    const categoryColors: Record<string, string> = {
        'Research Methods': 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300',
        'Technical': 'bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300',
        'Domain Knowledge': 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300',
        'Work Field': 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300',
        'Practical Expertise': 'bg-rose-100 dark:bg-rose-900/30 text-rose-700 dark:text-rose-300',
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg">
            <Navbar />

            <div className="flex">
                <AdminSidebar />

                <main className="flex-1 p-3 sm:p-6 md:p-8 min-w-0">
                    <div className="max-w-6xl mx-auto">
                        {/* Header */}
                        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4 sm:mb-8">
                            <div>
                                <h1 className="text-xl sm:text-3xl font-display font-bold text-primary dark:text-dark-text">
                                    {t('title')}
                                </h1>
                                <p className="text-sm sm:text-base text-text-light dark:text-dark-text-muted mt-1 sm:mt-2">
                                    {t('subtitle')}
                                </p>
                            </div>
                            <div className="bg-primary/10 dark:bg-primary-light/10 text-primary dark:text-primary-light px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg font-medium text-sm sm:text-base self-start sm:self-auto">
                                {t('totalSkills', { count: skills.length })}
                            </div>
                        </div>

                        {/* Filters */}
                        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-3 sm:p-4 mb-4 sm:mb-6">
                            <div className="flex flex-col sm:flex-row gap-3 sm:gap-4">
                                {/* Search */}
                                <div className="flex-1 min-w-0 relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                                    <Input
                                        placeholder={t('searchPlaceholder')}
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        className="pl-10 bg-white dark:bg-dark-bg text-sm"
                                    />
                                </div>

                                {/* Category Filter */}
                                <Select
                                    value={categoryFilter}
                                    onValueChange={(value) => setCategoryFilter(value)}
                                >
                                    <SelectTrigger className="w-full sm:w-[180px] bg-white dark:bg-dark-surface text-sm">
                                        <SelectValue placeholder={t('allCategories')} />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">{t('allCategories')}</SelectItem>
                                        {SKILL_CATEGORIES.map(cat => (
                                            <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>

                                {/* Recognized Filter */}
                                <div className="flex rounded-lg border border-gray-200 dark:border-dark-border overflow-hidden w-full sm:w-auto">
                                    <button
                                        onClick={() => setRecognizedFilter('all')}
                                        className={cn(
                                            "flex-1 sm:flex-none px-2 sm:px-3 py-2 text-xs sm:text-sm transition-colors",
                                            recognizedFilter === 'all'
                                                ? "bg-primary text-white"
                                                : "bg-white dark:bg-dark-bg text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-border"
                                        )}
                                    >
                                        All
                                    </button>
                                    <button
                                        onClick={() => setRecognizedFilter('recognized')}
                                        className={cn(
                                            "flex-1 sm:flex-none px-2 sm:px-3 py-2 text-xs sm:text-sm transition-colors border-x border-gray-200 dark:border-dark-border",
                                            recognizedFilter === 'recognized'
                                                ? "bg-primary text-white"
                                                : "bg-white dark:bg-dark-bg text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-border"
                                        )}
                                    >
                                        {t('recognized')}
                                    </button>
                                    <button
                                        onClick={() => setRecognizedFilter('user')}
                                        className={cn(
                                            "flex-1 sm:flex-none px-2 sm:px-3 py-2 text-xs sm:text-sm transition-colors",
                                            recognizedFilter === 'user'
                                                ? "bg-primary text-white"
                                                : "bg-white dark:bg-dark-bg text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-border"
                                        )}
                                    >
                                        {t('userCreated')}
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Skills List */}
                        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
                            {loading ? (
                                <div className="p-12 flex justify-center">
                                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                                </div>
                            ) : filteredSkills.length === 0 ? (
                                <div className="p-12 text-center text-text-light dark:text-dark-text-muted">
                                    <Award className="w-12 h-12 mx-auto mb-4 opacity-20" />
                                    <p>{t('noSkills')}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-gray-100 dark:divide-dark-border">
                                    {filteredSkills.map((skill) => (
                                        <div key={skill.id} className="p-3 sm:p-4 hover:bg-gray-50 dark:hover:bg-dark-border/50 transition-colors">
                                            <div className="flex items-start sm:items-center gap-3 sm:gap-4">
                                                <div className={cn(
                                                    "p-2 rounded-lg flex-shrink-0",
                                                    skill.is_recognized ? "bg-primary/10" : "bg-gray-100 dark:bg-dark-border"
                                                )}>
                                                    <Award className={cn(
                                                        "w-4 h-4 sm:w-5 sm:h-5",
                                                        skill.is_recognized ? "text-green-600 dark:text-green-400" : "text-text-light dark:text-dark-text-muted"
                                                    )} />
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <div className="flex flex-wrap items-center gap-1.5 sm:gap-2">
                                                        <h3 className="font-medium text-sm sm:text-base text-text dark:text-dark-text">
                                                            {skill.name}
                                                        </h3>
                                                        {skill.is_recognized && (
                                                            <span className="px-1.5 sm:px-2 py-0.5 text-[10px] sm:text-xs rounded-full bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 font-medium">
                                                                {t('recognized')}
                                                            </span>
                                                        )}
                                                    </div>
                                                    <div className="flex flex-wrap items-center gap-2 mt-1">
                                                        <span className={cn(
                                                            "px-1.5 sm:px-2 py-0.5 text-[10px] sm:text-xs rounded-full font-medium",
                                                            categoryColors[skill.category] || 'bg-gray-100 dark:bg-dark-border text-gray-600 dark:text-gray-400'
                                                        )}>
                                                            {skill.category}
                                                        </span>
                                                        <span className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">
                                                            {t('usedBy', { count: skill.user_count })}
                                                        </span>
                                                        {skill.creator_name && (
                                                            <span className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted hidden sm:inline">
                                                                ΓÇó {t('createdBy')} {skill.creator_name}
                                                            </span>
                                                        )}
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-0.5 sm:gap-2 flex-shrink-0">
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => handleEditClick(skill)}
                                                        className="text-text-light dark:text-dark-text-muted hover:text-primary p-1.5 sm:p-2 h-auto"
                                                    >
                                                        <Pencil className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => handleMergeClick(skill)}
                                                        className="text-text-light dark:text-dark-text-muted hover:text-amber-600 p-1.5 sm:p-2 h-auto"
                                                    >
                                                        <GitMerge className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => handleDeleteClick(skill)}
                                                        className="text-text-light dark:text-dark-text-muted hover:text-red-600 p-1.5 sm:p-2 h-auto"
                                                    >
                                                        <Trash2 className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                                    </Button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </main>
            </div>

            {/* Edit Dialog */}
            <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>{t('editDialogTitle', { name: editingSkill?.name ?? '' })}</DialogTitle>
                        <DialogDescription>
                            {t('editDialogDesc')}
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label htmlFor="skillName" className="text-text dark:text-dark-text font-medium">
                                {t('skillName')}
                            </Label>
                            <Input
                                id="skillName"
                                value={editName}
                                onChange={(e) => setEditName(e.target.value)}
                                className="bg-white dark:bg-dark-bg"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="skillCategory" className="text-text dark:text-dark-text font-medium">
                                {t('skillCategory')}
                            </Label>
                            <Select
                                value={editCategory}
                                onValueChange={(value) => setEditCategory(value)}
                            >
                                <SelectTrigger className="w-full bg-white dark:bg-dark-surface">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    {SKILL_CATEGORIES.map(cat => (
                                        <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="flex items-center gap-3">
                            <button
                                type="button"
                                onClick={() => setEditRecognized(!editRecognized)}
                                className={cn(
                                    "w-10 h-6 rounded-full transition-colors relative",
                                    editRecognized ? "bg-primary" : "bg-gray-300 dark:bg-dark-border"
                                )}
                            >
                                <span className={cn(
                                    "absolute top-1 w-4 h-4 rounded-full bg-white transition-all",
                                    editRecognized ? "left-5" : "left-1"
                                )} />
                            </button>
                            <div>
                                <Label className="text-text dark:text-dark-text font-medium">
                                    {t('markRecognized')}
                                </Label>
                                <p className="text-xs text-text-light dark:text-dark-text-muted">
                                    {t('recognizedHint')}
                                </p>
                            </div>
                        </div>
                    </div>
                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button variant="outline" onClick={() => setEditDialogOpen(false)} disabled={saving}>
                            {tCommon('cancel')}
                        </Button>
                        <Button onClick={handleSaveEdit} disabled={saving || !editName.trim()}>
                            {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                            {tCommon('save')}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Delete Dialog */}
            <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle className="text-red-600 dark:text-red-400">
                            {t('deleteDialogTitle', { name: deletingSkill?.name ?? '' })}
                        </DialogTitle>
                        <DialogDescription>
                            {t('deleteDialogDesc')}
                        </DialogDescription>
                    </DialogHeader>
                    <div className="py-4">
                        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4">
                            <p className="text-sm text-red-700 dark:text-red-300">
                                {t('deleteWarning', { count: deletingSkill?.user_count ?? 0 })}
                            </p>
                        </div>
                    </div>
                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button variant="outline" onClick={() => setDeleteDialogOpen(false)} disabled={deleting}>
                            {tCommon('cancel')}
                        </Button>
                        <Button
                            variant="destructive"
                            onClick={handleConfirmDelete}
                            disabled={deleting}
                            className="bg-red-600 hover:bg-red-700 text-white"
                        >
                            {deleting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Trash2 className="w-4 h-4 mr-2" />}
                            {t('confirmDelete')}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Merge Dialog */}
            <Dialog open={mergeDialogOpen} onOpenChange={setMergeDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle className="text-amber-600 dark:text-amber-400">
                            {t('mergeDialogTitle', { name: mergingSkill?.name ?? '' })}
                        </DialogTitle>
                        <DialogDescription>
                            {t('mergeDialogDesc')}
                        </DialogDescription>
                    </DialogHeader>
                    <div className="py-4 space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="mergeTarget" className="text-text dark:text-dark-text font-medium">
                                {t('mergeInto')}
                            </Label>
                            <Select
                                value={mergeTargetId}
                                onValueChange={(value) => setMergeTargetId(value)}
                            >
                                <SelectTrigger className="w-full bg-white dark:bg-dark-surface">
                                    <SelectValue placeholder={t('selectMergeTarget')} />
                                </SelectTrigger>
                                <SelectContent>
                                    {mergeTargets.map(skill => (
                                        <SelectItem key={skill.id} value={skill.id}>
                                            {skill.name} ({skill.category})
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button variant="outline" onClick={() => setMergeDialogOpen(false)} disabled={merging}>
                            {tCommon('cancel')}
                        </Button>
                        <Button
                            onClick={handleConfirmMerge}
                            disabled={merging || !mergeTargetId}
                            className="bg-amber-600 hover:bg-amber-700 text-white"
                        >
                            {merging ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <GitMerge className="w-4 h-4 mr-2" />}
                            {t('confirmMerge')}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            <Footer />
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import {
    BarChart3, Eye, ThumbsUp, MessageSquare, Download,
    TrendingUp, TrendingDown, Quote, Shield, Users as UsersIcon,
    Calendar, Award, BookOpen, ArrowUpRight, Activity, HelpCircle,
    Sparkles, PenLine, ArrowRight, Lightbulb
} from 'lucide-react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { LineChart, Line, XAxis, YAxis, Tooltip as ChartTooltip, ResponsiveContainer, AreaChart, Area, CartesianGrid, ReferenceLine, Legend } from 'recharts'
import { format, subDays } from 'date-fns'
import { useTranslations } from 'next-intl'

interface ResearcherStats {
    totalViews: number
    totalVotes: number
    totalPosts: number
    publications: number
    totalInteractions: number
    totalCitations: number
    totalComments: number
    totalFollowers: number
    avgTrustScore: number
    // Trend data (vs last period)
    viewsTrend: number
    votesTrend: number
    followersTrend: number
    projects: number
}

interface TrendDataPoint {
    date: string
    views: number
    comments: number
    polls: number
    citations: number
    contributions: number
    baseline: number
}

interface TopPost {
    id: string
    title: string
    content_type: string
    view_count: number
    vote_count: number
    created_at: string
}

export default function ResearcherAnalyticsDashboard() {
    const [user, setUser] = useState<any>(null)
    const [loading, setLoading] = useState(true)
    const [stats, setStats] = useState<ResearcherStats | null>(null)
    const [topPosts, setTopPosts] = useState<TopPost[]>([])
    const [viewTrends, setViewTrends] = useState<TrendDataPoint[]>([])
    const [daysBack, setDaysBack] = useState(30)
    const router = useRouter()
    const supabase = useMemo(() => createClient(), [])
    const t = useTranslations('Analytics')

    // Check if this is a zero-state (no activity)
    // We consider it a zero state only if they have no publications (posts, surveys, polls) 
    // AND no meaningful interactions on the platform.
    const isZeroState = stats && (stats.publications || 0) === 0 && (stats.totalInteractions || 0) === 0

    useEffect(() => {
        async function loadData() {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push('/auth/login')
                return
            }
            setUser(user)

            // Fetch user's posts for top posts table
            const { data: posts } = await supabase
                .from('posts')
                .select('id, title, content_type, view_count, vote_count, created_at')
                .eq('author_id', user.id)
                .order('view_count', { ascending: false })

            const postList = posts || []
            setTopPosts(postList.slice(0, 5))

            // Fetch citations (posts that reference user's posts)
            const postIds = postList.map(p => p.id)
            let citationCount = 0
            if (postIds.length > 0) {
                const { count } = await supabase
                    .from('citations')
                    .select('*', { count: 'exact', head: true })
                    .in('target_post_id', postIds)
                citationCount = count || 0
            }

            // Fetch followers
            const { count: followerCount } = await supabase
                .from('follows')
                .select('*', { count: 'exact', head: true })
                .eq('following_id', user.id)

            // Fetch average trust score
            let avgTrust = 0
            if (postIds.length > 0) {
                const { data: trustProfiles } = await supabase
                    .from('trust_profiles')
                    .select('t1_source_score, t2_method_score, t3_proximity_score')
                    .in('content_id', postIds)

                if (trustProfiles && trustProfiles.length > 0) {
                    const totalScore = trustProfiles.reduce((sum, tp) =>
                        sum + ((tp.t1_source_score + tp.t2_method_score + tp.t3_proximity_score) / 3), 0)
                    avgTrust = Math.round(totalScore / trustProfiles.length)
                }
            }

            // Fetch REAL analytics data from API
            let analyticsData = {
                totalViews: 0,
                totalVotes: 0,
                totalCitations: 0,
                totalComments: 0,
                totalFollowers: 0,
                publications: 0,
                totalInteractions: 0,
                projects: 0,
                viewsTrend: 0,
                votesTrend: 0,
                followersTrend: 0,
                viewsOverTime: [] as { date: string; views: number; votes?: number }[]
            }

            try {
                const res = await fetch(`/api/analytics/researcher?days=${daysBack}`)
                if (res.ok) {
                    analyticsData = await res.json()
                }
            } catch (err) {
                console.warn('Failed to fetch researcher analytics:', err)
            }

            setStats({
                totalViews: analyticsData.totalViews,
                totalVotes: analyticsData.totalVotes,
                totalPosts: postList.length,
                publications: analyticsData.publications || postList.length,
                totalInteractions: analyticsData.totalInteractions || 0,
                totalCitations: analyticsData.totalCitations || citationCount,
                totalComments: analyticsData.totalComments || 0,
                totalFollowers: analyticsData.totalFollowers || followerCount || 0,
                avgTrustScore: avgTrust,
                viewsTrend: analyticsData.viewsTrend || 0,
                votesTrend: analyticsData.votesTrend || 0,
                followersTrend: analyticsData.followersTrend || 0,
                projects: analyticsData.projects || 0
            })

            // Use REAL trend data from API, or empty array
            const avgDailyViews = analyticsData.totalViews / Math.max(daysBack, 1)
            const trends: TrendDataPoint[] = (analyticsData.viewsOverTime || []).map((item: any) => ({
                date: item.date,
                views: item.views || 0,
                comments: item.comments || 0,
                polls: item.polls || 0,
                citations: item.citations || 0,
                contributions: item.contributions || 0,
                baseline: avgDailyViews
            }))

            // If no data from API, generate placeholder with zeros
            if (trends.length === 0 && postList.length > 0) {
                for (let i = daysBack - 1; i >= 0; i--) {
                    const date = format(subDays(new Date(), i), 'MMM d')
                    trends.push({
                        date,
                        views: 0,
                        comments: 0,
                        polls: 0,
                        citations: 0,
                        contributions: 0,
                        baseline: avgDailyViews
                    })
                }
            }

            setViewTrends(trends)
            setLoading(false)
        }

        loadData()
    }, [supabase, router, daysBack])

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-background dark:bg-dark-bg">
                <div className="h-12 w-12 animate-spin rounded-full border-b-2 border-primary" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col overflow-x-hidden">
            <Navbar />

