// Tooltip Component
function InfoTooltip({ children, content }: { children: React.ReactNode; content: string }) {
    const [show, setShow] = useState(false)

    return (
        <div className="relative inline-block">
            <div
                onMouseEnter={() => setShow(true)}
                onMouseLeave={() => setShow(false)}
            >
                {children}
            </div>
            {show && (
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs rounded-lg shadow-lg z-50 w-64 text-center">
                    {content}
                    <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-4 border-r-4 border-t-4 border-transparent border-t-gray-900 dark:border-t-gray-100" />
                </div>
            )}
        </div>
    )
}

// Stat Card Component
interface StatCardProps {
    icon: typeof Eye
    label: string
    value: number
    suffix?: string
    trend?: number
    daysBack?: number
    tooltip: string
    gradient: string
    iconColor: string
    t: any
}

function StatCard({ icon: Icon, label, value, suffix = '', trend, daysBack = 30, tooltip, gradient, iconColor, t }: StatCardProps) {
    const hasTrend = trend !== undefined && trend !== 0
    const isPositive = (trend || 0) > 0

    return (
        <div className="group bg-white dark:bg-dark-surface p-4 rounded-2xl border border-gray-200 dark:border-dark-border hover:border-gray-300 dark:hover:border-dark-border-hover transition-all hover:shadow-md min-w-0 overflow-hidden">
            <div className="flex items-start justify-between mb-3">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center bg-gradient-to-br ${gradient} group-hover:scale-105 transition-transform`}>
                    <Icon className={`w-5 h-5 ${iconColor}`} />
                </div>
                <InfoTooltip content={tooltip}>
                    <HelpCircle className="w-3.5 h-3.5 text-text-light/40 dark:text-dark-text-muted/40 cursor-help hover:text-text-light dark:hover:text-dark-text-muted transition-colors" />
                </InfoTooltip>
            </div>
            <p className="text-2xl font-bold text-text dark:text-dark-text tracking-tight">
                {value.toLocaleString()}{suffix}
            </p>
            <div className="flex items-center justify-between mt-1">
                <span className="text-xs text-text-light dark:text-dark-text-muted">{label}</span>
                {hasTrend && (
                    <span className={`flex items-center gap-0.5 text-xs font-medium ${isPositive ? 'text-green-500' : 'text-red-500'}`}>
                        {isPositive ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                        {isPositive ? t('trends.up', { percent: trend }) : t('trends.down', { percent: trend })}
                    </span>
                )}
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { AlertCircle, CheckCircle, Lock, Loader2 } from 'lucide-react'

export default function ResetPasswordPage() {
    const [password, setPassword] = useState('')
    const [confirmPassword, setConfirmPassword] = useState('')
    const [error, setError] = useState<string | null>(null)
    const [success, setSuccess] = useState(false)
    const [loading, setLoading] = useState(false)
    const router = useRouter()
    const supabase = createClient()

    async function handleResetPassword(e: React.FormEvent) {
        e.preventDefault()
        setError(null)

        if (password.length < 8) {
            setError('Password must be at least 8 characters')
            return
        }

        if (password !== confirmPassword) {
            setError('Passwords do not match')
            return
        }

        setLoading(true)

        try {
            const { error } = await supabase.auth.updateUser({
                password: password,
            })

            if (error) {
                setError(error.message)
                setLoading(false)
                return
            }

            setSuccess(true)

            // Redirect to login after 3 seconds
            setTimeout(() => {
                router.push('/auth/login')
            }, 3000)
        } catch (err) {
            setError('An unexpected error occurred')
            setLoading(false)
        }
    }

    if (success) {
        return (
            <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
                <Navbar />

                <main className="flex-1 flex items-center justify-center px-6 py-12">
                    <div className="w-full max-w-md text-center">
                        <div className="w-16 h-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center mx-auto mb-6">
                            <CheckCircle className="w-8 h-8 text-green-600 dark:text-green-400" />
                        </div>
                        <h2 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
                            Password updated!
                        </h2>
                        <p className="text-text-light dark:text-dark-text-muted mb-6">
                            Your password has been successfully reset. Redirecting to login...
                        </p>
                        <Link href="/auth/login">
                            <Button>Go to login</Button>
                        </Link>
                    </div>
                </main>

                <Footer />
            </div>
        )
    }

    return (
        <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
            <Navbar />

            <main className="flex-1 flex items-center justify-center px-6 py-12">
                <div className="w-full max-w-md">
                    {/* Error Message */}
                    {error && (
                        <div className="mb-6 p-4 rounded-2xl bg-accent/10 border border-accent/20">
                            <div className="flex items-start gap-3">
                                <AlertCircle className="w-5 h-5 text-accent mt-0.5" />
                                <div>
                                    <h3 className="font-semibold text-text dark:text-dark-text">Error</h3>
                                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">{error}</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Form Card */}
                    <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-8">
                        <div className="w-12 h-12 rounded-2xl bg-primary/10 dark:bg-primary/20 flex items-center justify-center mb-6">
                            <Lock className="w-6 h-6 text-primary" />
                        </div>

                        <h2 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
                            Set new password
                        </h2>
                        <p className="text-text-light dark:text-dark-text-muted mb-8">
                            Enter your new password below.
                        </p>

                        <form onSubmit={handleResetPassword} className="space-y-6">
                            <div className="space-y-2">
                                <Label htmlFor="password">New password</Label>
                                <Input
                                    id="password"
                                    name="password"
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    placeholder="At least 8 characters"
                                    required
                                    minLength={8}
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="confirmPassword">Confirm password</Label>
                                <Input
                                    id="confirmPassword"
                                    name="confirmPassword"
                                    type="password"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    placeholder="Re-enter your password"
                                    required
                                />
                            </div>

                            <Button type="submit" className="w-full" disabled={loading}>
                                {loading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                                {loading ? 'Updating...' : 'Update password'}
                            </Button>
                        </form>
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    )
}

import Link from 'next/link'
import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { SignupForm } from '@/components/auth/SignupForm'
import { verifyTurnstileToken } from '@/lib/turnstile'
import { getTranslations } from 'next-intl/server'
import { CheckCircle2, AlertCircle, Sparkles, Users, BookOpen, Ticket, Gift } from 'lucide-react'
import Image from 'next/image'

export default async function SignupPage({
  params,
  searchParams,
}: {
  params: Promise<{ locale: string }>
  searchParams: Promise<{ error?: string; success?: string; code?: string; email?: string }>
}) {
  const { locale } = await params
  const search = await searchParams
  const t = await getTranslations({ locale, namespace: 'Auth.signupPage' })
  const ta = await getTranslations({ locale, namespace: 'Auth' })
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (user) {
    redirect('/insights')
  }

  // Pre-validate invite code if provided in URL
  let preValidatedCode = ''
  let inviterName = ''
  if (search.code) {
    const { data } = await supabase.rpc('validate_invite_code', {
      p_code: search.code.toUpperCase().trim(),
    })
    if (data?.valid) {
      preValidatedCode = search.code.toUpperCase().trim()
      // Get inviter name
      if (data.inviter_id) {
        const { data: inviter } = await supabase
          .from('users')
          .select('name, email')
          .eq('id', data.inviter_id)
          .single()
        if (inviter) {
          inviterName = inviter.name || inviter.email?.split('@')[0] || ''
        }
      }
    }
  }

  async function handleSignup(formData: FormData) {
    'use server'

    const email = formData.get('email') as string
    const password = formData.get('password') as string
    const inviteCode = formData.get('inviteCode') as string
    const turnstileToken = formData.get('cf-turnstile-response') as string

    // Verify CAPTCHA if configured
    const captchaValid = await verifyTurnstileToken(turnstileToken)
    if (!captchaValid) {
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent('Security verification failed. Please try again.')}`)
    }

    if (!email || !password) {
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent('Email and password are required')}`)
    }

    if (!inviteCode) {
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent('Invite code is required')}`)
    }

    if (password.length < 6) {
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent('Password must be at least 6 characters')}`)
    }

    const supabase = await createClient()

    // Validate invite code first
    const { data: inviteValidation, error: inviteError } = await supabase.rpc('validate_invite_code', {
      p_code: inviteCode.toUpperCase().trim(),
    })

    if (inviteError || !inviteValidation?.valid) {
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent(inviteValidation?.error || 'Invalid invite code')}`)
    }

    // Create the account
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: `${process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000'}/auth/callback`,
        data: {
          invite_code: inviteCode.toUpperCase().trim(),
          invited_by: inviteValidation.inviter_id,
        },
      },
    })

    if (error) {
      console.error('Signup error:', error)
      redirect(`/${locale}/auth/signup?error=${encodeURIComponent(error.message)}&code=${encodeURIComponent(inviteCode)}`)
    }

    // Mark invite as used
    if (data.user) {
      await supabase.rpc('use_invite_code', {
        p_code: inviteCode.toUpperCase().trim(),
        p_user_id: data.user.id,
      })
    }

    if (data.user && !data.session) {
      redirect(`/${locale}/auth/signup?success=${encodeURIComponent('check-email')}`)
    }

    if (data.session) {
      redirect(`/${locale}/insights`)
    }

    redirect(`/${locale}/auth/signup?success=${encodeURIComponent('check-email')}`)
  }

  return (
    <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
      <Navbar />

      <main className="flex-1 flex">
        {/* Left - Branding Panel */}
        <div className="hidden lg:flex lg:w-1/2 bg-gradient-to-br from-primary via-primary-dark to-primary relative overflow-hidden">
          <div className="absolute inset-0 opacity-10">
            <div className="absolute top-20 right-20 w-72 h-72 bg-white rounded-full blur-3xl" />
            <div className="absolute bottom-20 left-20 w-96 h-96 bg-secondary rounded-full blur-3xl" />
          </div>

          <div className="relative z-10 flex flex-col justify-center px-16 py-12">
            <Link href="/" className="flex items-center gap-3 mb-12">
              <div className="w-12 h-12 bg-white/20 backdrop-blur rounded-xl flex items-center justify-center overflow-hidden">
                <Image src="/icons/icon-512x512.png" alt="SyriaHub" width={40} height={40} className="object-contain" />
              </div>
              <span className="font-bold text-2xl text-white">SyriaHub</span>
            </Link>

            <h1 className="text-4xl font-bold text-white mb-4">
              {t('joinTitle')}
            </h1>
            <p className="text-xl text-white/80 mb-12 max-w-md">
              {t('joinSubtitle')}
            </p>

            <div className="space-y-6">
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center flex-shrink-0">
                  <Ticket className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h3 className="font-semibold text-white">{t('inviteRequiredTitle')}</h3>
                  <p className="text-sm text-white/70">{t('inviteRequiredDesc')}</p>
                </div>
              </div>
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center flex-shrink-0">
                  <Users className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h3 className="font-semibold text-white">{t('qualityCommunityTitle')}</h3>
                  <p className="text-sm text-white/70">{t('qualityCommunityDesc')}</p>
                </div>
              </div>
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center flex-shrink-0">
                  <Gift className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h3 className="font-semibold text-white">{t('payItForwardTitle')}</h3>
                  <p className="text-sm text-white/70">{t('payItForwardDesc')}</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right - Form Panel */}
        <div className="flex-1 flex items-center justify-center px-6 py-12">
          <div className="w-full max-w-md">
            {/* Mobile Logo */}
            <div className="text-center mb-8 lg:hidden">
              <Link href="/" className="inline-flex items-center gap-2">
                <div className="w-10 h-10 bg-gradient-to-br from-primary to-secondary rounded-xl flex items-center justify-center overflow-hidden">
                  <Image src="/icons/icon-512x512.png" alt="SyriaHub" width={32} height={32} className="object-contain" />
                </div>
                <span className="font-bold text-2xl text-text dark:text-dark-text">SyriaHub</span>
              </Link>
            </div>

            {/* Invited by banner */}
            {inviterName && (
              <div className="mb-6 p-4 rounded-2xl bg-primary/10 border border-primary/20">
                <div className="flex items-center gap-3">
                  <Gift className="w-5 h-5 text-primary" />
                  <p className="text-sm text-text dark:text-dark-text">
                    {t.rich('invitedBy', {
                      name: (chunks) => <strong>{chunks}</strong>,
                      name_val: inviterName
                    })}
                  </p>
                </div>
              </div>
            )}

            {/* Success Message */}
            {search.success === 'check-email' && (
              <div className="mb-6 p-4 rounded-2xl bg-secondary/10 border border-secondary/20">
                <div className="flex items-start gap-3">
                  <CheckCircle2 className="w-5 h-5 text-secondary-dark mt-0.5" />
                  <div>
                    <h3 className="font-semibold text-text dark:text-dark-text">{t('checkEmailTitle')}</h3>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                      {t('checkEmailDesc')}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Error Message */}
            {search.error && (
              <div className="mb-6 p-4 rounded-2xl bg-accent/10 border border-accent/20">
                <div className="flex items-start gap-3">
                  <AlertCircle className="w-5 h-5 text-accent mt-0.5" />
                  <div>
                    <h3 className="font-semibold text-text dark:text-dark-text">{t('errorTitle')}</h3>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">{search.error}</p>
                  </div>
                </div>
              </div>
            )}

            {/* Form Card - Only show if not success */}
            {search.success !== 'check-email' && (
              <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-8">
                <h2 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
                  {t('createAccountTitle')}
                </h2>
                <p className="text-text-light dark:text-dark-text/90 mb-8">
                  {t('alreadyHaveAccount')}{' '}
                  <Link href="/auth/login" className="font-semibold text-primary dark:text-secondary-dark hover:text-primary-dark dark:hover:text-secondary transition-colors">
                    {ta('login')}
                  </Link>
                </p>

                <SignupForm preValidatedCode={preValidatedCode} preFilledEmail={search.email || ''} action={handleSignup} />

                <p className="mt-6 text-xs text-center text-text-light dark:text-dark-text/70">
                  {t('termsAgreeLong')}
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      <Footer />
    </div>
  )
}

"use client"

import { useState } from 'react'
import { useTranslations } from 'next-intl'
import { zodResolver } from '@hookform/resolvers/zod'
import { useForm } from 'react-hook-form'
import * as z from 'zod'
import { Button } from '@/components/ui/button'
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { useToast } from '@/components/ui/toast'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { Turnstile } from '@/components/ui/Turnstile'
import { Mail, MapPin, MessageSquare, Send } from 'lucide-react'

const formSchema = z.object({
    name: z.string().min(2, {
        message: "Name must be at least 2 characters.",
    }).max(100),
    email: z.string().email({
        message: "Please enter a valid email address.",
    }).max(255),
    subject: z.string().min(5, {
        message: "Subject must be at least 5 characters.",
    }).max(200),
    message: z.string().min(10, {
        message: "Message must be at least 10 characters.",
    }).max(5000),
    // Honeypot field - hidden from users, bots fill it
    company: z.string().max(0).optional(),
})

export default function ContactPage() {
    const t = useTranslations('Contact')
    const { showToast } = useToast()
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [turnstileToken, setTurnstileToken] = useState<string>('')

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            name: "",
            email: "",
            subject: "",
            message: "",
            company: "", // Honeypot
        },
    })

    async function onSubmit(values: z.infer<typeof formSchema>) {
        // Check if Turnstile is configured and token is required
        const siteKey = process.env.NEXT_PUBLIC_TURNSTILE_SITE_KEY
        if (siteKey && !turnstileToken) {
            showToast("Please complete the security verification.", "error")
            return
        }

        setIsSubmitting(true)
        try {
            const response = await fetch('/api/contact', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    ...values,
                    'cf-turnstile-response': turnstileToken || undefined,
                }),
            })

            if (!response.ok) throw new Error('Failed to send message')

            showToast("Message sent successfully!", "success")
            form.reset()
            setTurnstileToken('')
        } catch (error) {
            showToast("Failed to send message. Please try again.", "error")
        } finally {
            setIsSubmitting(false)
        }
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            <main className="flex-1 container-custom py-12 md:py-24">
                {/* Hero Section */}
                <div className="text-center max-w-2xl mx-auto mb-16 space-y-4">
                    <h1 className="text-4xl font-display font-bold text-text dark:text-dark-text tracking-tight">
                        {t('title')}
                    </h1>
                    <p className="text-lg text-text-light dark:text-dark-text-muted">
                        {t('subtitle')}
                    </p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24 items-start max-w-6xl mx-auto">
                    {/* Contact Info */}
                    <div className="space-y-8 lg:order-2">
                        <div className="bg-white dark:bg-dark-surface p-8 rounded-2xl border border-gray-100 dark:border-dark-border shadow-sm space-y-8">
                            <div>
                                <h3 className="text-xl font-semibold mb-6 flex items-center gap-2 text-text dark:text-dark-text">
                                    {t('contactInfo')}
                                </h3>

                                <div className="space-y-6">
                                    <div className="flex items-start gap-4">
                                        <div className="p-3 bg-primary/10 rounded-lg text-primary">
                                            <Mail className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <h4 className="font-medium text-text dark:text-dark-text mb-1">{t('emailLabel')}</h4>
                                            <a href="mailto:admin@pluragate.org" className="text-text-light dark:text-dark-text-muted hover:text-primary transition-colors block">
                                                admin@pluragate.org
                                            </a>
                                            <p className="text-xs text-text-light/70 dark:text-dark-text-muted/70 mt-1">
                                                {t('pluragateMember')}
                                            </p>
                                        </div>
                                    </div>

                                    <div className="flex items-start gap-4">
                                        <div className="p-3 bg-primary/10 rounded-lg text-primary">
                                            <MessageSquare className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <h4 className="font-medium text-text dark:text-dark-text mb-1">{t('supportLabel')}</h4>
                                            <p className="text-text-light dark:text-dark-text-muted">
                                                {t.rich('supportText', {
                                                    github: (chunks) => <a href="https://github.com/PluraGate" className="text-primary hover:underline hover:text-primary/80 dark:text-accent-light dark:hover:text-accent font-medium">{chunks}</a>
                                                })}
                                            </p>
                                        </div>
                                    </div>

                                    <div className="flex items-start gap-4">
                                        <div className="p-3 bg-primary/10 rounded-lg text-primary">
                                            <MapPin className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <h4 className="font-medium text-text dark:text-dark-text mb-1">{t('locationLabel')}</h4>
                                            <p className="text-text-light dark:text-dark-text-muted">
                                                {t('digitalOrg')}<br />
                                                {t('globalReach')}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="pt-6 border-t border-gray-100 dark:border-dark-border">
                                <p className="text-sm text-text-light dark:text-dark-text-muted">
                                    {t('privacyNote')}
                                </p>
                            </div>
                        </div>

                        <div className="text-center">
                            <p className="text-sm text-text-muted dark:text-dark-text-muted">
                                {t('operatingUnder')}
                            </p>
                        </div>
                    </div>

                    {/* Contact Form */}
                    <div className="lg:order-1">
                        <div className="bg-white dark:bg-dark-surface p-8 rounded-2xl border border-gray-100 dark:border-dark-border shadow-sm">
                            <Form {...form}>
                                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                                    <FormField
                                        control={form.control}
                                        name="name"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>{t('form.name')}</FormLabel>
                                                <FormControl>
                                                    <Input placeholder={t('placeholders.name')} {...field} className="bg-gray-50 dark:bg-dark-bg border-gray-200 dark:border-dark-border" />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="email"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>{t('form.email')}</FormLabel>
                                                <FormControl>
                                                    <Input placeholder={t('placeholders.email')} {...field} className="bg-gray-50 dark:bg-dark-bg border-gray-200 dark:border-dark-border" />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="subject"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>{t('form.subject')}</FormLabel>
                                                <FormControl>
                                                    <Input placeholder={t('placeholders.subject')} {...field} className="bg-gray-50 dark:bg-dark-bg border-gray-200 dark:border-dark-border" />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="message"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>{t('form.message')}</FormLabel>
                                                <FormControl>
                                                    <Textarea
                                                        placeholder={t('placeholders.message')}
                                                        className="min-h-[150px] bg-gray-50 dark:bg-dark-bg border-gray-200 dark:border-dark-border resize-none"
                                                        {...field}
                                                    />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    {/* Honeypot field - hidden from users, bots will fill it */}
                                    <FormField
                                        control={form.control}
                                        name="company"
                                        render={({ field }) => (
                                            <FormItem className="absolute opacity-0 pointer-events-none h-0 w-0 overflow-hidden" aria-hidden="true" tabIndex={-1}>
                                                <FormLabel>Company</FormLabel>
                                                <FormControl>
                                                    <Input
                                                        placeholder="Company name"
                                                        {...field}
                                                        tabIndex={-1}
                                                        autoComplete="off"
                                                    />
                                                </FormControl>
                                            </FormItem>
                                        )}
                                    />

                                    {/* Turnstile CAPTCHA */}
                                    <div className="flex justify-center">
                                        <Turnstile
                                            onSuccess={(token: string) => setTurnstileToken(token)}
                                            onExpire={() => setTurnstileToken('')}
                                            onError={() => setTurnstileToken('')}
                                        />
                                    </div>

                                    <Button type="submit" className="w-full" disabled={isSubmitting}>
                                        {isSubmitting ? (
                                            <>{t('form.sending')}</>
                                        ) : (
                                            <>
                                                <Send className="w-4 h-4 mr-2" />
                                                {t('form.send')}
                                            </>
                                        )}
                                    </Button>
                                </form>
                            </Form>
                        </div>
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    )
}

