import { notFound } from 'next/navigation'
import Link from 'next/link'
import { Settings, Users, Lock, Globe, Plus } from 'lucide-react'
import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
import { GroupActions } from '@/components/GroupActions'
import { GroupChat } from '@/components/GroupChat'

import { PostCard } from '@/components/PostCard'

interface GroupPageProps {
    params: Promise<{
        id: string
    }>
}

export default async function GroupPage(props: GroupPageProps) {
    const params = await props.params
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    // Fetch group details
    const { data: group, error } = await supabase
        .from('groups')
        .select('*')
        .eq('id', params.id)
        .single()

    if (error || !group) {
        notFound()
    }

    // Fetch members
    const { data: members } = await supabase
        .from('group_members')
        .select(`
      role,
      user:users(id, name, email, affiliation)
    `)
        .eq('group_id', group.id)

    // Fetch group posts
    const { data: posts } = await supabase
        .from('posts')
        .select(`
            *,
            author:users!posts_author_id_fkey(id, name, email)
        `)
        .eq('group_id', group.id)
        .order('created_at', { ascending: false })

    // Check if current user is a member
    const membership = members?.find((m: any) => m.user.id === user?.id)
    const isMember = !!membership
    const isAdmin = membership?.role === 'owner' || membership?.role === 'moderator'

    // If private and not a member, show access denied (unless admin/moderator global role, but let's stick to group rules)
    // Actually, the RLS should handle this, but for UX we might want to show a specific "Request Access" page.
    // For now, if RLS fails, the data fetch above would return null/error if policy is correct.
    // Our policy: "Groups viewable by members or public". So if private and not member, `group` will be null.
    // So the `notFound()` above handles unauthorized access effectively for private groups.

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg">
            <Navbar />

            <div className="bg-white dark:bg-dark-surface border-b border-gray-200 dark:border-dark-border">
                <div className="container-custom max-w-6xl py-8">
                    <div className="flex flex-col md:flex-row items-start justify-between gap-6">
                        <div>
                            <div className="flex items-center gap-3 mb-2">
                                <h1 className="text-3xl font-display font-bold text-primary dark:text-dark-text">
                                    {group.name}
                                </h1>
                                {group.visibility === 'public' ? (
                                    <span className="px-2 py-1 rounded-full bg-green-100 text-green-700 text-xs font-medium flex items-center gap-1">
                                        <Globe className="w-3 h-3" /> Public
                                    </span>
                                ) : (
                                    <span className="px-2 py-1 rounded-full bg-gray-100 text-gray-700 text-xs font-medium flex items-center gap-1">
                                        <Lock className="w-3 h-3" /> {group.visibility}
                                    </span>
                                )}
                            </div>
                            <p className="text-text-light dark:text-dark-text-muted max-w-3xl text-lg">
                                {group.description}
                            </p>
                        </div>

                        <div className="flex items-center gap-3">
                            <GroupActions
                                groupId={group.id}
                                isMember={isMember}
                                isAdmin={isAdmin}
                                visibility={group.visibility}
                            />
                        </div>
                    </div>
                </div>
            </div>

            <main className="container-custom max-w-6xl py-8">
                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Main Content (Posts) */}
                    <div className="lg:col-span-2 space-y-6">
                        <div className="flex items-center justify-between">
                            <h2 className="text-xl font-display font-semibold text-text dark:text-dark-text">
                                Group Discussions
                            </h2>
                            {isMember && (
                                <Link href={`/editor?groupId=${group.id}`} className="btn btn-sm btn-primary">
                                    <Plus className="w-4 h-4 mr-1" />
                                    New Post
                                </Link>
                            )}
                        </div>

                        {/* Group Posts */}
                        <div className="space-y-6">
                            {posts && posts.length > 0 ? (
                                posts.map((post: any) => (
                                    <PostCard key={post.id} post={post} />
                                ))
                            ) : (
                                <div className="card p-12 text-center border-dashed">
                                    <p className="text-text-light dark:text-dark-text-muted">
                                        No posts yet. Be the first to start a discussion!
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Sidebar (Members) */}
                    <aside className="space-y-6">
                        <div className="card p-6">
                            <div className="flex items-center justify-between mb-4">
                                <h3 className="font-display font-semibold text-lg text-primary dark:text-dark-text flex items-center gap-2">
                                    <Users className="w-5 h-5" />
                                    Members
                                </h3>
                                <span className="text-sm text-text-light dark:text-dark-text-muted">
                                    {members?.length || 0}
                                </span>
                            </div>

                            <div className="space-y-4">
                                {members?.slice(0, 5).map((member: any) => (
                                    <div key={member.user.id} className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-xs font-bold text-primary">
                                            {(member.user.name?.[0] || member.user.email?.[0] || '?').toUpperCase()}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-medium text-text dark:text-dark-text truncate">
                                                {member.user.name || 'Anonymous'}
                                            </p>
                                            {member.role !== 'member' && (
                                                <p className="text-xs text-primary dark:text-accent-light capitalize">
                                                    {member.role}
                                                </p>
                                            )}
                                        </div>
                                    </div>
                                ))}

                                {members && members.length > 5 && (
                                    <button className="text-sm text-primary hover:underline w-full text-center">
                                        View all members
                                    </button>
                                )}
                            </div>

                            {isAdmin && (
                                <div className="mt-6 pt-4 border-t border-gray-100 dark:border-dark-border">
                                    <Link
                                        href={`/groups/${group.id}/settings`}
                                        className="btn btn-outline w-full text-sm"
                                    >
                                        Manage Members
                                    </Link>
                                </div>
                            )}
                        </div>

                        {isMember && user && (
                            <GroupChat groupId={group.id} currentUserId={user.id} />
                        )}
                    </aside>
                </div>
            </main>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { ArrowLeft, Save, Trash2, UserPlus, Shield, UserX } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { Navbar } from '@/components/Navbar'
import { useToast } from '@/components/ui/toast'
import { InviteMemberDialog } from '@/components/InviteMemberDialog'

interface GroupSettingsPageProps {
    params: Promise<{
        id: string
    }>
}

export default function GroupSettingsPage(props: GroupSettingsPageProps) {
    const router = useRouter()
    const { showToast } = useToast()
    const supabase = createClient()

    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [group, setGroup] = useState<any>(null)
    const [members, setMembers] = useState<any[]>([])
    const [showInviteDialog, setShowInviteDialog] = useState(false)

    // Unwrap params
    const [groupId, setGroupId] = useState<string | null>(null)

    useEffect(() => {
        props.params.then(p => setGroupId(p.id))
    }, [props.params])

    useEffect(() => {
        if (!groupId) return

        async function fetchGroup() {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push('/auth/login')
                return
            }

            // Check permissions (must be owner or moderator)
            const { data: member } = await supabase
                .from('group_members')
                .select('role')
                .eq('group_id', groupId)
                .eq('user_id', user.id)
                .single()

            if (!member || (member.role !== 'owner' && member.role !== 'moderator')) {
                showToast('You do not have permission to edit this group', 'error')
                router.push(`/groups/${groupId}`)
                return
            }

            // Fetch group details
            const { data: groupData, error: groupError } = await supabase
                .from('groups')
                .select('*')
                .eq('id', groupId)
                .single()

            if (groupError) {
                console.error('Error fetching group:', groupError)
                return
            }

            setGroup(groupData)

            // Fetch members
            const { data: membersData, error: membersError } = await supabase
                .from('group_members')
                .select(`
                    *,
                    profile:users(
                        id,
                        full_name,
                        avatar_url,
                        email
                    )
                `)
                .eq('group_id', groupId)
                .order('joined_at', { ascending: false })

            if (membersError) {
                console.error('Error fetching members:', membersError)
            } else {
                setMembers(membersData || [])
            }

            setLoading(false)
        }

        fetchGroup()
    }, [groupId, router, showToast, supabase])

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault()
        setSaving(true)

        try {
            const { error } = await supabase
                .from('groups')
                .update({
                    name: group.name,
                    description: group.description,
                    visibility: group.visibility
                })
                .eq('id', groupId)

            if (error) throw error

            showToast('Group settings updated', 'success')
        } catch (error: any) {
            console.error('Error updating group:', error)
            showToast('Failed to update group', 'error')
        } finally {
            setSaving(false)
        }
    }

    const handleRemoveMember = async (memberId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return

        try {
            const { error } = await supabase
                .from('group_members')
                .delete()
                .eq('group_id', groupId)
                .eq('user_id', memberId)

            if (error) throw error

            setMembers(members.filter(m => m.user_id !== memberId))
            showToast('Member removed', 'success')
        } catch (error: any) {
            console.error('Error removing member:', error)
            showToast('Failed to remove member', 'error')
        }
    }

    const handleDeleteGroup = async () => {
        if (!confirm('Are you sure you want to delete this group? This action cannot be undone.')) return

        try {
            const { error } = await supabase
                .from('groups')
                .delete()
                .eq('id', groupId)

            if (error) throw error

            showToast('Group deleted', 'success')
            router.push('/groups')
        } catch (error: any) {
            console.error('Error deleting group:', error)
            showToast('Failed to delete group', 'error')
        }
    }

    if (loading || !groupId) {
        return (
            <div className="min-h-screen bg-background dark:bg-dark-bg">
                <Navbar />
                <div className="flex items-center justify-center h-[50vh]">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                </div>
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg">
            <Navbar />

            <div className="border-b border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface">
                <div className="container-custom max-w-4xl py-4">
                    <Link
                        href={`/groups/${groupId}`}
                        className="inline-flex items-center gap-2 text-text-light dark:text-dark-text-muted hover:text-primary dark:hover:text-accent-light transition-colors"
                    >
                        <ArrowLeft className="w-4 h-4" />
                        Back to Group
                    </Link>
                </div>
            </div>

            <main className="container-custom max-w-4xl py-12">
                <div className="flex items-center justify-between mb-8">
                    <h1 className="text-3xl font-display font-bold text-primary dark:text-dark-text">
                        Group Settings
                    </h1>
                    <button
                        onClick={() => setShowInviteDialog(true)}
                        className="btn btn-primary flex items-center gap-2"
                    >
                        <UserPlus className="w-4 h-4" />
                        Invite Members
                    </button>
                </div>

                <div className="grid gap-8 lg:grid-cols-3">
                    <div className="lg:col-span-2 space-y-6">
                        <section className="card p-6">
                            <h2 className="text-lg font-semibold text-text dark:text-dark-text mb-6">
                                General Information
                            </h2>

                            <form onSubmit={handleUpdate} className="space-y-6">
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        Group Name
                                    </label>
                                    <input
                                        type="text"
                                        value={group.name}
                                        onChange={(e) => setGroup({ ...group, name: e.target.value })}
                                        className="w-full rounded-lg border border-gray-300 px-4 py-2.5 focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30 dark:border-dark-border dark:bg-dark-bg dark:text-dark-text"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        Description
                                    </label>
                                    <textarea
                                        rows={4}
                                        value={group.description || ''}
                                        onChange={(e) => setGroup({ ...group, description: e.target.value })}
                                        className="w-full rounded-lg border border-gray-300 px-4 py-2.5 focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30 dark:border-dark-border dark:bg-dark-bg dark:text-dark-text"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        Visibility
                                    </label>
                                    <select
                                        value={group.visibility}
                                        onChange={(e) => setGroup({ ...group, visibility: e.target.value })}
                                        className="select-input"
                                    >
                                        <option value="private">Private (Invite Only)</option>
                                        <option value="restricted">Restricted (Request to Join)</option>
                                        <option value="public">Public (Open to All)</option>
                                    </select>
                                </div>

                                <div className="pt-4 flex justify-end">
                                    <button
                                        type="submit"
                                        disabled={saving}
                                        className="btn btn-primary flex items-center gap-2"
                                    >
                                        <Save className="w-4 h-4" />
                                        {saving ? 'Saving...' : 'Save Changes'}
                                    </button>
                                </div>
                            </form>
                        </section>

                        <section className="card p-6">
                            <h2 className="text-lg font-semibold text-text dark:text-dark-text mb-6">
                                Members ({members.length})
                            </h2>

                            <div className="space-y-4">
                                {members.map((member) => (
                                    <div key={member.id} className="flex items-center justify-between py-2 border-b border-gray-100 dark:border-dark-border last:border-0">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-medium">
                                                {member.profile?.full_name?.[0] || member.profile?.email?.[0] || '?'}
                                            </div>
                                            <div>
                                                <p className="font-medium text-text dark:text-dark-text">
                                                    {member.profile?.full_name || 'Unknown User'}
                                                </p>
                                                <p className="text-sm text-text-light dark:text-dark-text-muted">
                                                    {member.role}
                                                </p>
                                            </div>
                                        </div>

                                        {member.role !== 'owner' && (
                                            <button
                                                onClick={() => handleRemoveMember(member.user_id)}
                                                className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                                                title="Remove Member"
                                            >
                                                <UserX className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </section>
                    </div>

                    <aside className="space-y-6">
                        <div className="card p-6 border-red-100 dark:border-red-900/30">
                            <h3 className="text-lg font-semibold text-red-600 dark:text-red-400 mb-4">
                                Danger Zone
                            </h3>
                            <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                                Deleting a group is permanent and cannot be undone. All posts and member data will be lost.
                            </p>
                            <button
                                onClick={handleDeleteGroup}
                                className="btn w-full border-red-200 text-red-600 hover:bg-red-50 dark:border-red-900/50 dark:hover:bg-red-900/20 flex items-center justify-center gap-2"
                            >
                                <Trash2 className="w-4 h-4" />
                                Delete Group
                            </button>
                        </div>
                    </aside>
                </div>

                <InviteMemberDialog
                    groupId={groupId}
                    isOpen={showInviteDialog}
                    onClose={() => setShowInviteDialog(false)}
                />
            </main>
        </div>
    )
}

import Link from 'next/link'
import { Plus, Users, Search } from 'lucide-react'
import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
import { GroupCard } from '@/components/GroupCard'
import { getTranslations } from 'next-intl/server'

export default async function GroupsPage() {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    const t = await getTranslations('Groups')

    // Fetch user's groups
    const { data: myGroups } = await supabase
        .from('groups')
        .select(`
      *,
      members:group_members(count)
    `)
        .eq('group_members.user_id', user?.id) // This filter needs a join, but Supabase simple client might not support deep filtering easily on M:N without view or RPC. 
    // Actually, for M:N via join table, we usually query the join table.
    // Let's try a different approach: fetch group_members for this user, then fetch groups.
    // OR use the !inner join syntax if supported.

    // Simpler approach for now:
    // 1. Get group_ids from group_members
    // 2. Fetch groups with those IDs

    // Let's try the direct join first, if it fails we fallback.
    // Actually, supabase-js supports !inner on foreign tables to filter parent.
    // .select('*, group_members!inner(*)') .eq('group_members.user_id', user.id)

    let myGroupsData: any[] = []

    if (user) {
        const { data } = await supabase
            .from('groups')
            .select(`
        id,
        name,
        description,
        visibility,
        group_members!inner(user_id)
      `)
            .eq('group_members.user_id', user.id)

        // We also need member counts for these groups. 
        // It's often better to create a view or use a separate query for counts if performance matters.
        // For now, let's fetch counts separately or assume we can get them.
        // Actually, let's just fetch all public groups for "Discover" and filter "My Groups" in memory if dataset is small, 
        // or use proper queries.

        // Let's refine the query to get what we need for the card.
        // We need: id, name, description, visibility, member_count.

        // Query for My Groups
        const { data: myGroupsResult } = await supabase
            .from('groups')
            .select(`
            id,
            name,
            description,
            visibility,
            group_members!inner(user_id)
        `)
            .eq('group_members.user_id', user.id)

        if (myGroupsResult) {
            // Now fetch member counts for these groups
            const groupIds = myGroupsResult.map(g => g.id)
            if (groupIds.length > 0) {
                const { data: counts } = await supabase
                    .from('group_members')
                    .select('group_id')
                    .in('group_id', groupIds)

                // Aggregate counts
                const countMap = new Map()
                counts?.forEach(c => {
                    countMap.set(c.group_id, (countMap.get(c.group_id) || 0) + 1)
                })

                myGroupsData = myGroupsResult.map(g => ({
                    ...g,
                    member_count: countMap.get(g.id) || 0
                }))
            }
        }
    }

    // Fetch Discover Groups (Public groups not joined by user)
    // This is tricky in one query. Let's just fetch public groups and filter out joined ones in JS for MVP.
    const { data: publicGroups } = await supabase
        .from('groups')
        .select('id, name, description, visibility')
        .eq('visibility', 'public')
        .limit(20)

    // Calculate counts for public groups
    let discoverGroupsData: any[] = []
    if (publicGroups) {
        const publicIds = publicGroups.map(g => g.id)
        // Filter out groups user is already in
        const myGroupIds = new Set(myGroupsData.map(g => g.id))
        const filteredPublic = publicGroups.filter(g => !myGroupIds.has(g.id))

        if (filteredPublic.length > 0) {
            const { data: counts } = await supabase
                .from('group_members')
                .select('group_id')
                .in('group_id', filteredPublic.map(g => g.id))

            const countMap = new Map()
            counts?.forEach(c => {
                countMap.set(c.group_id, (countMap.get(c.group_id) || 0) + 1)
            })

            discoverGroupsData = filteredPublic.map(g => ({
                ...g,
                member_count: countMap.get(g.id) || 0
            }))
        }
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg">
            <Navbar />

            <main className="container-custom max-w-6xl py-12">
                <div className="flex flex-col md:flex-row items-start justify-between gap-6 mb-10">
                    <div>
                        <h1 className="text-3xl font-display font-bold text-primary dark:text-dark-text mb-2">
                            {t('title')}
                        </h1>
                        <p className="text-text-light dark:text-dark-text-muted max-w-2xl">
                            {t('subtitle')}
                        </p>
                    </div>

                    <Link
                        href="/groups/create"
                        className="btn btn-primary flex-shrink-0"
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        {t('createGroup')}
                    </Link>
                </div>

                {/* My Groups Section */}
                {user && (
                    <section className="mb-12">
                        <div className="flex items-center gap-2 mb-6">
                            <Users className="w-5 h-5 text-primary dark:text-accent-light" />
                            <h2 className="text-xl font-display font-semibold text-text dark:text-dark-text">
                                {t('myGroups')}
                            </h2>
                        </div>

                        {myGroupsData.length > 0 ? (
                            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                                {myGroupsData.map((group) => (
                                    <GroupCard key={group.id} group={group} />
                                ))}
                            </div>
                        ) : (
                            <div className="card p-8 text-center bg-gray-50 dark:bg-dark-surface/50 border-dashed">
                                <p className="text-text-light dark:text-dark-text-muted mb-4">
                                    {t('noGroupsDesc')}
                                </p>
                                <Link href="/groups/create" className="text-primary hover:underline font-medium">
                                    {t('createGroup')}
                                </Link>
                            </div>
                        )}
                    </section>
                )}

                {/* Discover Section */}
                <section>
                    <div className="flex items-center gap-2 mb-6">
                        <Search className="w-5 h-5 text-primary dark:text-accent-light" />
                        <h2 className="text-xl font-display font-semibold text-text dark:text-dark-text">
                            {t('discoverGroups')}
                        </h2>
                    </div>

                    {discoverGroupsData.length > 0 ? (
                        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                            {discoverGroupsData.map((group) => (
                                <GroupCard key={group.id} group={group} />
                            ))}
                        </div>
                    ) : (
                        <div className="card p-8 text-center">
                            <p className="text-text-light dark:text-dark-text-muted">
                                {t('noGroups')}
                            </p>
                        </div>
                    )}
                </section>
            </main>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { useTranslations } from 'next-intl'
import { User, Briefcase, BookOpen, MapPin, Globe, ArrowRight, Sparkles, CheckCircle2 } from 'lucide-react'
import Image from 'next/image'

export default function OnboardingPage() {
    const router = useRouter()
    const t = useTranslations('Onboarding')
    const [step, setStep] = useState(1)
    const [loading, setLoading] = useState(false)
    const [user, setUser] = useState<any>(null)
    const [formData, setFormData] = useState({
        name: '',
        bio: '',
        affiliation: '',
        location: '',
        website: '',
        research_interests: [] as string[],
    })

    useEffect(() => {
        const fetchUser = async () => {
            const supabase = createClient()
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push('/auth/login')
                return
            }
            setUser(user)

            // Get existing user data
            const { data: userData } = await supabase
                .from('users')
                .select('name, bio, affiliation, location, website, research_interests')
                .eq('id', user.id)
                .single()

            if (userData) {
                setFormData({
                    name: userData.name || '',
                    bio: userData.bio || '',
                    affiliation: userData.affiliation || '',
                    location: userData.location || '',
                    website: userData.website || '',
                    research_interests: userData.research_interests || [],
                })
            }
        }
        fetchUser()
    }, [router])

    const handleSave = async () => {
        if (!user) return
        setLoading(true)

        const supabase = createClient()
        const { error } = await supabase
            .from('users')
            .update({
                name: formData.name,
                bio: formData.bio,
                affiliation: formData.affiliation,
                location: formData.location,
                website: formData.website,
                research_interests: formData.research_interests,
            })
            .eq('id', user.id)

        setLoading(false)

        if (!error) {
            router.push('/insights')
        }
    }

    const steps = [
        { id: 1, title: t('step1Title'), icon: User },
        { id: 2, title: t('step2Title'), icon: Briefcase },
        { id: 3, title: t('step3Title'), icon: BookOpen },
    ]

    return (
        <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
            <Navbar />

            <main className="flex-1 container-custom py-12">
                <div className="max-w-2xl mx-auto">
                    {/* Header */}
                    <div className="text-center mb-12">
                        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-primary/10 text-primary mb-4">
                            <Sparkles className="w-4 h-4" />
                            <span className="text-sm font-medium">{t('setupWelcome')}</span>
                        </div>
                        <h1 className="text-3xl font-bold text-text dark:text-dark-text mb-2">
                            {t('title')}
                        </h1>
                        <p className="text-text-light dark:text-dark-text-muted">
                            {t('subtitle')}
                        </p>
                    </div>

                    {/* Progress Steps */}
                    <div className="flex items-center justify-center gap-4 mb-8">
                        {steps.map((s, idx) => (
                            <div key={s.id} className="flex items-center">
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${step >= s.id
                                    ? 'bg-primary text-white'
                                    : 'bg-gray-200 dark:bg-dark-border text-text-muted'
                                    }`}>
                                    {step > s.id ? <CheckCircle2 className="w-5 h-5" /> : <s.icon className="w-5 h-5" />}
                                </div>
                                {idx < steps.length - 1 && (
                                    <div className={`w-12 h-1 mx-2 rounded ${step > s.id ? 'bg-primary' : 'bg-gray-200 dark:bg-dark-border'
                                        }`} />
                                )}
                            </div>
                        ))}
                    </div>

                    {/* Form Card */}
                    <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-8">
                        {step === 1 && (
                            <div className="space-y-6">
                                <h2 className="text-xl font-semibold text-text dark:text-dark-text">
                                    {t('step1Title')}
                                </h2>
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        {t('nameLabel')}
                                    </label>
                                    <input
                                        type="text"
                                        value={formData.name}
                                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text"
                                        placeholder={t('namePlaceholder')}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        {t('bioLabel')}
                                    </label>
                                    <textarea
                                        value={formData.bio}
                                        onChange={(e) => setFormData({ ...formData, bio: e.target.value })}
                                        rows={4}
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text resize-none"
                                        placeholder={t('bioPlaceholder')}
                                    />
                                </div>
                            </div>
                        )}

                        {step === 2 && (
                            <div className="space-y-6">
                                <h2 className="text-xl font-semibold text-text dark:text-dark-text">
                                    {t('step2Title')}
                                </h2>
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        <Briefcase className="w-4 h-4 inline mr-2" />
                                        {t('affiliationLabel')}
                                    </label>
                                    <input
                                        type="text"
                                        value={formData.affiliation}
                                        onChange={(e) => setFormData({ ...formData, affiliation: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text"
                                        placeholder={t('affiliationPlaceholder')}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        <MapPin className="w-4 h-4 inline mr-2" />
                                        {t('locationLabel')}
                                    </label>
                                    <input
                                        type="text"
                                        value={formData.location}
                                        onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text"
                                        placeholder={t('locationPlaceholder')}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        <Globe className="w-4 h-4 inline mr-2" />
                                        {t('websiteLabel')}
                                    </label>
                                    <input
                                        type="url"
                                        value={formData.website}
                                        onChange={(e) => setFormData({ ...formData, website: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text"
                                        placeholder="https://"
                                    />
                                </div>
                            </div>
                        )}

                        {step === 3 && (
                            <div className="space-y-6 text-center">
                                <div className="w-20 h-20 mx-auto bg-primary/10 rounded-full flex items-center justify-center">
                                    <CheckCircle2 className="w-10 h-10 text-primary" />
                                </div>
                                <h2 className="text-xl font-semibold text-text dark:text-dark-text">
                                    {t('step3Title')}
                                </h2>
                                <p className="text-text-light dark:text-dark-text-muted">
                                    {t('step3Description')}
                                </p>
                            </div>
                        )}

                        {/* Navigation Buttons */}
                        <div className="flex justify-between mt-8">
                            {step > 1 ? (
                                <Button variant="outline" onClick={() => setStep(step - 1)}>
                                    {t('back')}
                                </Button>
                            ) : (
                                <div />
                            )}
                            {step < 3 ? (
                                <Button onClick={() => setStep(step + 1)} className="gap-2">
                                    {t('continue')}
                                    <ArrowRight className="w-4 h-4" />
                                </Button>
                            ) : (
                                <Button onClick={handleSave} disabled={loading} className="gap-2">
                                    {loading ? t('saving') : t('finish')}
                                </Button>
                            )}
                        </div>
                    </div>

                    {/* Skip Link */}
                    <p className="text-center mt-6 text-sm text-text-light dark:text-dark-text-muted">
                        <button onClick={() => router.push('/insights')} className="hover:text-primary transition-colors">
                            {t('skipForNow')}
                        </button>
                    </p>
                </div>
            </main>

            <Footer />
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useParams } from 'next/navigation'
import { Vote, Check, Loader2, AlertTriangle, Users } from 'lucide-react'
import { useToast } from '@/components/ui/toast'
import { generateBrowserFingerprint } from '@/lib/fingerprint'

interface PollOption {
    id: string
    text: string
    vote_count: number
}

interface Poll {
    id: string
    question: string
    description?: string
    options: PollOption[]
    is_multiple_choice: boolean
    show_results_before_vote: boolean
    total_votes: number
}

export default function PublicPollPage() {
    const params = useParams()
    const token = params.token as string
    const { showToast } = useToast()

    const [poll, setPoll] = useState<Poll | null>(null)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const [selectedOptions, setSelectedOptions] = useState<string[]>([])
    const [isVoting, setIsVoting] = useState(false)
    const [hasVoted, setHasVoted] = useState(false)
    const [userVote, setUserVote] = useState<string[] | null>(null)
    const [browserFingerprint, setBrowserFingerprint] = useState<string | null>(null)

    useEffect(() => {
        async function fetchPoll() {
            try {
                // Generate fingerprint first
                const fp = await generateBrowserFingerprint()
                setBrowserFingerprint(fp)

                const response = await fetch(`/api/public/poll/${token}`, {
                    headers: { 'x-browser-fingerprint': fp }
                })
                const data = await response.json()

                if (!response.ok) {
                    setError(data.error || 'Poll not found')
                    return
                }

                setPoll(data.poll)
                setHasVoted(data.hasVoted)
                setUserVote(data.userVote)
            } catch (err) {
                setError('Failed to load poll')
            } finally {
                setLoading(false)
            }
        }

        if (token) {
            fetchPoll()
        }
    }, [token])

    const handleOptionClick = (optionId: string) => {
        if (hasVoted) return

        if (poll?.is_multiple_choice) {
            setSelectedOptions(prev =>
                prev.includes(optionId)
                    ? prev.filter(id => id !== optionId)
                    : [...prev, optionId]
            )
        } else {
            setSelectedOptions([optionId])
        }
    }

    const handleVote = async () => {
        if (selectedOptions.length === 0) {
            showToast('Please select an option', 'error')
            return
        }

        setIsVoting(true)

        try {
            const response = await fetch(`/api/public/poll/${token}`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-browser-fingerprint': browserFingerprint || ''
                },
                body: JSON.stringify({ option_ids: selectedOptions })
            })

            const data = await response.json()

            if (!response.ok) {
                showToast(data.error || 'Failed to vote', 'error')
                return
            }

            // Update poll options with new counts
            if (data.options) {
                setPoll(prev => prev ? { ...prev, options: data.options, total_votes: prev.total_votes + 1 } : null)
            }

            setHasVoted(true)
            setUserVote(selectedOptions)
            showToast('Vote recorded!', 'success')
        } catch (err) {
            showToast('Failed to submit vote', 'error')
        } finally {
            setIsVoting(false)
        }
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-dark-bg dark:to-dark-surface flex items-center justify-center">
                <div className="text-center">
                    <Loader2 className="w-8 h-8 animate-spin text-primary mx-auto mb-4" />
                    <p className="text-text-light dark:text-dark-text-muted">Loading poll...</p>
                </div>
            </div>
        )
    }

    if (error) {
        return (
            <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-dark-bg dark:to-dark-surface flex items-center justify-center p-4">
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-8 max-w-md w-full text-center">
                    <AlertTriangle className="w-12 h-12 text-amber-500 mx-auto mb-4" />
                    <h1 className="text-xl font-semibold text-text dark:text-dark-text mb-2">
                        Poll Not Available
                    </h1>
                    <p className="text-text-light dark:text-dark-text-muted">
                        {error}
                    </p>
                </div>
            </div>
        )
    }

    const totalVotes = poll?.options.reduce((sum, opt) => sum + (opt.vote_count || 0), 0) || 0
    const showResults = hasVoted || poll?.show_results_before_vote

    return (
        <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-dark-bg dark:to-dark-surface py-8 px-4">
            <div className="max-w-lg mx-auto">
                {/* Poll Card */}
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                    {/* Header */}
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-10 h-10 bg-amber-100 dark:bg-amber-900/30 rounded-lg flex items-center justify-center">
                            <Vote className="w-5 h-5 text-amber-600 dark:text-amber-400" />
                        </div>
                        <div className="flex-1">
                            <h1 className="text-lg font-semibold text-text dark:text-dark-text">
                                {poll?.question}
                            </h1>
                            {poll?.is_multiple_choice && !hasVoted && (
                                <p className="text-xs text-text-light dark:text-dark-text-muted">
                                    Select multiple options
                                </p>
                            )}
                        </div>
                    </div>

                    {poll?.description && (
                        <p className="text-text-light dark:text-dark-text-muted mb-4">
                            {poll.description}
                        </p>
                    )}

                    {/* Options */}
                    <div className="space-y-2 mb-4">
                        {poll?.options.map((option) => {
                            const percentage = totalVotes > 0
                                ? Math.round((option.vote_count / totalVotes) * 100)
                                : 0
                            const isSelected = selectedOptions.includes(option.id)
                            const wasVotedFor = userVote?.includes(option.id)

                            return (
                                <button
                                    key={option.id}
                                    onClick={() => handleOptionClick(option.id)}
                                    disabled={hasVoted || isVoting}
                                    className={`
                                        w-full relative text-left p-4 rounded-lg border transition-all
                                        ${hasVoted
                                            ? 'cursor-default'
                                            : isSelected
                                                ? 'border-primary bg-primary/5'
                                                : 'border-gray-200 dark:border-dark-border hover:border-primary/50'
                                        }
                                    `}
                                >
                                    {/* Progress bar */}
                                    {showResults && (
                                        <div
                                            className={`absolute inset-0 rounded-lg transition-all ${wasVotedFor
                                                ? 'bg-primary/20'
                                                : 'bg-gray-100 dark:bg-dark-border/50'
                                                }`}
                                            style={{ width: `${percentage}%` }}
                                        />
                                    )}

                                    <div className="relative flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            {!hasVoted && (
                                                <div className={`
                                                    w-5 h-5 rounded-full border-2 flex items-center justify-center
                                                    ${isSelected
                                                        ? 'border-primary bg-primary text-white'
                                                        : 'border-gray-300 dark:border-dark-border'
                                                    }
                                                `}>
                                                    {isSelected && <Check className="w-3 h-3" />}
                                                </div>
                                            )}
                                            {wasVotedFor && (
                                                <Check className="w-5 h-5 text-primary" />
                                            )}
                                            <span className="text-text dark:text-dark-text font-medium">
                                                {option.text}
                                            </span>
                                        </div>
                                        {showResults && (
                                            <span className="text-sm font-medium text-text-light dark:text-dark-text-muted">
                                                {percentage}%
                                            </span>
                                        )}
                                    </div>
                                </button>
                            )
                        })}
                    </div>

                    {/* Footer */}
                    <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-dark-border">
                        <div className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted">
                            <Users className="w-4 h-4" />
                            {totalVotes} vote{totalVotes !== 1 ? 's' : ''}
                        </div>

                        {!hasVoted && selectedOptions.length > 0 && (
                            <button
                                onClick={handleVote}
                                disabled={isVoting}
                                className="btn btn-primary"
                            >
                                {isVoting ? (
                                    <>
                                        <Loader2 className="w-4 h-4 animate-spin mr-2" />
                                        Voting...
                                    </>
                                ) : (
                                    'Vote'
                                )}
                            </button>
                        )}

                        {hasVoted && (
                            <span className="text-sm text-emerald-600 dark:text-emerald-400 flex items-center gap-1">
                                <Check className="w-4 h-4" />
                                Voted
                            </span>
                        )}
                    </div>
                </div>

                {/* Footer */}
                <div className="text-center mt-8 text-sm text-text-light dark:text-dark-text-muted">
                    Powered by SyriaHub Research Lab
                </div>
            </div>
        </div>
    )
}

