interface PostPageProps {
  params: Promise<{
    id: string
    locale: string
  }>
}

/**
 * Checks if a string is a valid UUID v4
 */
function isUUID(str: string): boolean {
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i
  return uuidRegex.test(str)
}

// Generate dynamic metadata for SEO
export async function generateMetadata({ params }: PostPageProps): Promise<Metadata> {
  const { id } = await params
  const supabase = await createClient()

  // Determine if id is a UUID or a slug
  const isIdUUID = isUUID(id)

  let query = supabase
    .from('posts')
    .select(`
      id,
      title,
      content,
      tags,
      content_type,
      author: users!posts_author_id_fkey(name, email)
    `)

  if (isIdUUID) {
    query = query.eq('id', id)
  } else {
    query = query.eq('slug', id)
  }

  const { data: post } = await query.single()

  if (!post) {
    return {
      title: 'Post Not Found | SyriaHub',
      description: 'The requested post could not be found.',
    }
  }

  const authorName = (post.author as any)?.name || (post.author as any)?.email?.split('@')[0] || 'Anonymous'
  const description = post.content.replace(/[#*_`\[\]]/g, '').substring(0, 155) + '...'
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://syrealize.com'
  const ogImageUrl = `${siteUrl}/api/og?id=${post.id}`

  return {
    title: `${post.title} | SyriaHub`,
    description,
    authors: [{ name: authorName }],
    keywords: post.tags || [],
    openGraph: {
      title: post.title,
      description,
      type: 'article',
      url: `${siteUrl}/post/${post.id}`,
      images: [
        {
          url: ogImageUrl,
          width: 1200,
          height: 630,
          alt: post.title,
        },
      ],
      siteName: 'SyriaHub',
    },
    twitter: {
      card: 'summary_large_image',
      title: post.title,
      description,
      images: [ogImageUrl],
    },
    alternates: {
      canonical: `${siteUrl}/post/${post.id}`,
    },
  }
}

// Reading time calculator
function getReadingTime(content: string): number {
  const words = content.trim().split(/\s+/).length
  return Math.max(1, Math.ceil(words / 200))
}

export default async function PostPage(props: PostPageProps) {
  const params = await props.params
  const { id, locale } = params
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  let post: any = null
  let error: any = null

  // Determine if id is a UUID or a slug
  if (isUUID(id)) {
    // Lookup by UUID
    const result = await supabase
      .from('posts')
      .select(`
        *,
        author:users!posts_author_id_fkey(id, name, email, bio, affiliation, avatar_url)
      `)
      .eq('id', id)
      .single()

    post = result.data
    error = result.error

    // If post has a slug, redirect to the canonical slug URL (permanent redirect for SEO)
    if (post?.slug) {
      redirect(`/${locale}/post/${post.slug}`)
    }

    // If no slug, try to generate one (lazy backfill via RPC)
    if (post && !post.slug) {
      const { data: generatedSlug } = await supabase
        .rpc('get_post_slug', { p_post_id: id })

      if (generatedSlug) {
        // Redirect to the newly generated slug
        redirect(`/${locale}/post/${generatedSlug}`)
      }
    }
  } else {
    // Lookup by slug (primary method - SEO friendly)
    const result = await supabase
      .from('posts')
      .select(`
        *,
        author:users!posts_author_id_fkey(id, name, email, bio, affiliation, avatar_url)
      `)
      .eq('slug', id)
      .single()

    post = result.data
    error = result.error
  }

  if (error || !post) {
    console.error('Error fetching post:', error)
    notFound()
  }

  // Redirect events to the dedicated event page
  if (post.content_type === 'event') {
    redirect(`/events/${id}`)
  }

  let relatedPosts: any[] = []
  if (post.tags && post.tags.length > 0) {
    const { data } = await supabase
      .from('posts')
      .select(
        `
          id,
          title,
          tags,
          created_at,
          author:users(name, email)
        `
      )
      .neq('id', id)
      .overlaps('tags', post.tags)
      .limit(5)

    relatedPosts = data || []
  }

  const { data: citationData } = await supabase
    .from('citations')
    .select(
      `
        source_post_id,
        quote_content,
        posts!citations_source_post_id_fkey (
          id,
          title,
          created_at,
          author:users(name, email)
        )
      `
    )
    .eq('target_post_id', id)


  const citationBacklinks =
    citationData?.map((c: any) => ({
      ...c.posts,
      quote_content: c.quote_content
    })).filter((c: any) => c.id) || []

  const authorDisplay =
    post.author?.name || post.author?.email?.split('@')[0] || 'Anonymous'

  const readingTime = getReadingTime(post.content || '')

  // Fetch answers if it's a question
  let answers: any[] = []
  if (post.content_type === 'question') {
    const { data: answersData } = await supabase
      .from('posts')
      .select(`
        *,
        author:users(id, name, email),
        vote_count:post_votes(value)
      `)
      .eq('parent_id', id)
      .eq('content_type', 'answer')
      .order('is_accepted', { ascending: false })
      .order('created_at', { ascending: true })

    answers = answersData || []
  }

  // Fetch linked resources
  let linkedResources: any[] = []
  const { data: resourceLinksData } = await supabase
    .from('resource_post_links')
    .select(`
      resource_id,
      posts!resource_post_links_resource_id_fkey (
        id,
        title,
        metadata,
        created_at
      )
    `)
    .eq('post_id', id)


  // Fetch Schema Registry Values
  const { data: schemaValuesData } = await supabase
    .from('schema_post_field_values')
    .select(`
        value,
        field:schema_fields(field_key),
        version:schema_field_versions(display_name, field_type, registry_id)
    `)
    .eq('post_id', id)
    .eq('is_current', true)

  const schemaValues: SchemaFieldValue[] = (schemaValuesData || []).map((item: any) => {
    const field = Array.isArray(item.field) ? item.field[0] : item.field
    const version = Array.isArray(item.version) ? item.version[0] : item.version
    return {
      value: item.value,
      field: {
        display_name: version?.display_name || field?.field_key || 'Unknown',
        field_key: field?.field_key || ''
      },
      version: version
    }
  })

  if (resourceLinksData) {
    linkedResources = resourceLinksData
      .map((link: any) => link.posts)
      .filter((r: any) => r !== null)
  }

  const t = await getTranslations('Post')
  const tc = await getTranslations('Common')
  const tLicenses = await getTranslations('Licenses')

  // Get nonce for CSP compliance
  const headersList = await headers()
  const nonce = headersList.get('x-nonce') || undefined

  // Build JSON-LD structured data
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://syrealize.com'
  const hasAnswers = answers && answers.length > 0
  const isScholarly = citationBacklinks.length > 0 || (post.academic_impact_score && post.academic_impact_score > 0)

  const jsonLdData = post.content_type === 'question' && hasAnswers
    ? buildQAPageSchema(
      { ...post, author: post.author as any },
      answers.map((a: any) => ({ ...a, author: a.author as any })),
      { siteUrl }
    )
    : buildArticleSchema(
      { ...post, author: post.author as any },
      { type: isScholarly ? 'ScholarlyArticle' : 'Article', siteUrl }
    )

  return (
    <>
      <JsonLdScript data={jsonLdData} nonce={nonce} />
      <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
        <Navbar />

        {/* Hero Header with Cover Image Background - always shows cover (with Pluragate fallback) */}
        <header className="group relative overflow-hidden min-h-[250px] sm:min-h-[350px] md:min-h-[400px]">
          {/* Cover Image Background - uses Pluragate covers as fallback */}
          <PostHeroBackground coverImageUrl={post.cover_image_url} />

          {/* Header Content */}
          <div className="relative z-10">
            <div className="container-custom max-w-5xl py-6 px-6 md:px-8">
              {/* Top Row: Back Link + Mobile Quick Actions */}
              <div className="flex items-center justify-between mb-4 md:mb-8">
                {/* Back Link */}
                <Link
                  href="/insights"
                  className="inline-flex items-center gap-2 text-sm transition-colors text-white/80 hover:text-white"
                >
                  <ArrowLeft className="w-4 h-4" />
                  {t('backToInsights')}
                </Link>

                {/* Mobile Quick Actions - only visible on mobile */}
                <div className="flex items-center gap-1 md:hidden [&_button]:bg-white/20 [&_button]:backdrop-blur-sm [&_button]:text-white [&_button]:border-white/30 [&_button:hover]:bg-white/30">
                  {user && user.id !== post.author_id && (
                    <ForkButton
                      postId={post.id}
                      postTitle={post.title}
                      postContent={post.content}
                      postTags={post.tags || []}
                      iconOnly
                    />
                  )}
                  <BookmarkButton postId={post.id} className="!text-white hover:!bg-white/30" />
                  <PostMoreOptions postId={post.id} className="!text-white hover:!bg-white/30" />
                </div>
              </div>

              {/* Content Type Badge */}
              {post.content_type === 'question' && (
                <div className="mb-4">
                  <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-secondary/20 text-secondary-dark dark:text-secondary text-sm font-semibold">
                    <MessageSquare className="w-4 h-4" />
                    {t('question')}
                  </span>
                </div>
              )}

              {/* Title */}
              <h1 dir="auto" className="text-3xl sm:text-4xl lg:text-5xl font-bold leading-tight tracking-tight mb-4 md:mb-6 text-white">
                {post.title}
              </h1>

              {/* Forked From */}
              {post.forked_from && (
                <div className="flex items-center gap-2 mb-4 md:mb-6 text-sm text-white/80 bg-white/10 backdrop-blur-sm p-3 rounded-xl border border-white/20 w-fit">
                  <GitFork className="w-4 h-4 text-white" />
                  <span>{t('remixedFrom')}</span>
                  <Link href={`/post/${post.forked_from.id}`} className="font-semibold text-white hover:underline">
                    {post.forked_from.title}
                  </Link>
                </div>
              )}

              {/* Tags */}
              {post.tags && post.tags.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-4 md:mb-6">
                  {post.tags.map((tag: string) => (
                    <span
                      key={tag}
                      className="px-3 py-1.5 text-sm font-medium bg-white/20 backdrop-blur-sm text-white rounded-full hover:bg-white/30 transition-colors"
                    >
                      #{tag}
                    </span>
                  ))}
                </div>
              )}

              {/* Meta Row */}
              <div className="flex flex-wrap items-center gap-6 text-sm text-white/80">
                {/* Author */}
                <Link
                  href={`/profile/${post.author_id}`}
                  className="flex items-center gap-3 transition-colors hover:text-white"
                >
                  {post.author?.avatar_url ? (
                    <Image
                      src={post.author.avatar_url}
                      alt={authorDisplay}
                      width={40}
                      height={40}
                      className="w-10 h-10 rounded-full object-cover ring-2 ring-white/20"
                    />
                  ) : (
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-semibold">
                      {(post.author?.name?.[0] || post.author?.email?.[0] || 'U').toUpperCase()}
                    </div>
                  )}
                  <div>
                    <span className="font-semibold block text-white">{authorDisplay}</span>
                    {post.author?.affiliation && (
                      <span className="text-xs">{post.author.affiliation}</span>
                    )}
                  </div>
                </Link>

                <span className="text-gray-300 dark:text-gray-700">ΓÇó</span>

                {/* Date */}
                <div className="flex items-center gap-2">
                  <Calendar className="w-4 h-4" />
                  <time dateTime={post.created_at}>
                    {new Date(post.created_at).toLocaleDateString('en-US', {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                    })}
                  </time>
                </div>

                <span className="text-gray-300 dark:text-gray-700">ΓÇó</span>

                {/* Reading Time */}
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4" />
                  <span>{t('minRead', { count: readingTime })}</span>
                </div>

                {/* Knowledge Impact Score - if available */}
                {post.academic_impact_score && post.academic_impact_score > 0 && (
                  <>
                    <span className="text-gray-300 dark:text-gray-700">ΓÇó</span>
                    <div
                      className="flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 text-xs font-semibold"
                      title="Knowledge Impact Score: Based on quality citations and scholarly engagement"
                    >
                      <GraduationCap className="w-3.5 h-3.5" />
                      <span>{t('impact')}: {post.academic_impact_score.toFixed(1)}</span>
                    </div>
                  </>
                )}

                {/* License */}
                {post.license && (
                  <>
                    <span className="text-gray-300 dark:text-gray-700">ΓÇó</span>
                    <span className="px-2 py-1 rounded-full bg-gray-100 dark:bg-dark-bg text-xs">
                      {tLicenses(post.license.replace(/\./g, '_'))}
                    </span>
                  </>
                )}
              </div>

              {/* Action Buttons */}
              <div className="flex flex-wrap items-center gap-2 md:gap-3 mt-4 pt-4 md:mt-8 md:pt-6 border-t border-white/20 [&_button]:bg-white/20 [&_button]:backdrop-blur-sm [&_button]:text-white [&_button]:border-white/30 [&_button:hover]:bg-white/30">
                {user && user.id === post.author_id ? (
                  <>
                    <EditButton
                      postId={post.id}
                      postCreatedAt={post.created_at}
                      isAuthor={true}
                    />
                    <Link href={`/post/${post.id}/suggestions`}>
                      <Button variant="outline" size="sm" className="gap-2">
                        <GitPullRequest className="w-4 h-4" />
                        {t('suggestions')}
                      </Button>
                    </Link>
                  </>
                ) : (
                  <>
                    {/* ForkButton - hidden on mobile (shown in header) */}
                    <div className="hidden md:block">
                      <ForkButton
                        postId={post.id}
                        postTitle={post.title}
                        postContent={post.content}
                        postTags={post.tags || []}
                      />
                    </div>
                    <SuggestionDialog
                      postId={post.id}
                      originalContent={post.content}
                    />
                    {user && (
                      <Link href={`/correspondence/compose?post=${post.id}`}>
                        <Button variant="outline" size="sm" className="gap-2">
                          <HelpCircle className="w-4 h-4" />
                          {t('askAuthor')}
                        </Button>
                      </Link>
                    )}
                  </>
                )}

                {/* Cite Button - visible for all users */}
                <CiteButton
                  postId={post.id}
                  postTitle={post.title}
                  postAuthor={post.author}
                  postCreatedAt={post.created_at}
                  postContent={post.content}
                  postTags={post.tags}
                />

                {/* Download Button - for resources */}
                {post.content_type === 'resource' && post.metadata?.url && (
                  <a
                    href={post.metadata.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    download
                  >
                    <Button variant="outline" size="sm" className="gap-2">
                      <Download className="w-4 h-4" />
                      {t('download')}
                    </Button>
                  </a>
                )}

                <div className="flex-1 min-w-0 hidden md:block" />

                {/* Bookmark & More Options - hidden on mobile (shown in header) */}
                <div className="hidden md:flex items-center gap-2">
                  <BookmarkButton postId={post.id} className="!text-white hover:!bg-white/30" />
                  <PostMoreOptions postId={post.id} className="!text-white hover:!bg-white/30" />
                </div>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 container-custom max-w-5xl py-12 px-6 md:px-8 pb-40">
          <div className="grid lg:grid-cols-3 gap-12">
            {/* Main Content */}
            <article className="lg:col-span-2 space-y-12">
              {/* Rejection Banner - shown only to authors of rejected posts */}
              <RejectionBanner
                postId={post.id}
                postTitle={post.title}
                rejectionReason={post.rejection_reason}
                approvalStatus={post.approval_status || 'approved'}
                isAuthor={user?.id === post.author_id}
                contentType={post.content_type as 'post' | 'article' | 'question' | 'event'}
              />

              {/* Article Content */}
              <div dir="auto" className="prose lg:prose-lg max-w-none dark:prose-invert 
              prose-headings:font-bold prose-headings:text-text dark:prose-headings:text-dark-text 
              prose-h2:text-2xl prose-h2:mt-12 prose-h2:mb-4
              prose-h3:text-xl prose-h3:mt-8 prose-h3:mb-3
              prose-p:text-text-light prose-p:dark:text-dark-text-muted prose-p:leading-relaxed
              prose-a:text-primary dark:prose-a:text-primary-light prose-a:no-underline hover:prose-a:underline
              prose-strong:text-text dark:prose-strong:text-dark-text 
              prose-code:text-accent dark:prose-code:text-accent-light prose-code:bg-gray-100 dark:prose-code:bg-dark-surface prose-code:px-1.5 prose-code:py-0.5 prose-code:rounded
              prose-blockquote:border-l-4 prose-blockquote:border-primary prose-blockquote:bg-gray-50 dark:prose-blockquote:bg-dark-surface prose-blockquote:py-2 prose-blockquote:px-4 prose-blockquote:rounded-r-lg
              prose-img:rounded-xl prose-img:shadow-soft-md
              prose-ul:my-6 prose-li:my-1
            ">
                <TextSelectionHandler postId={post.id}>
                  <ReactMarkdown
                    remarkPlugins={[remarkGfm, remarkMath]}
                    rehypePlugins={[rehypeKatex]}
                  >
                    {post.content || ''}
                  </ReactMarkdown>
                </TextSelectionHandler>
              </div>

              {/* Data Visualizations */}
              {post.metadata?.chartBlocks && post.metadata.chartBlocks.length > 0 && (
                <LazyPostCharts
                  chartBlocks={post.metadata.chartBlocks}
                  linkedResources={linkedResources}
                />
              )}

              {/* Spatial Context - between content and citations */}
              <SpatialContextCard
                spatialCoverage={post.spatial_coverage}
                spatialGeometry={post.spatial_geometry}
                temporalStart={post.temporal_start}
                temporalEnd={post.temporal_end}
              />

              {/* References Section - what this post cites */}
              <ReferencesSection postId={post.id} />


              {/* Answers Section for Questions */}
              {post.content_type === 'question' && (
                <section className="space-y-8">
                  <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-bold text-text dark:text-dark-text">
                      {t('answers', { count: answers.length })}
                    </h2>
                  </div>

                  <AnswerList
                    answers={answers}
                    isQuestionAuthor={user?.id === post.author_id}
                  />

                  {/* Answer Form */}
                  {user ? (
                    <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                      <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-4">{t('yourAnswer')}</h3>
                      <AnswerForm questionId={post.id} />
                    </div>
                  ) : (
                    <div className="text-center py-12 bg-gray-50 dark:bg-dark-surface rounded-2xl">
                      <p className="text-text-light dark:text-dark-text-muted mb-4">
                        {t('signInToAnswer')}
                      </p>
                      <Link href="/auth/login">
                        <Button>{tc('signIn')}</Button>
                      </Link>
                    </div>
                  )}
                </section>
              )}

              {/* Comments Section */}
              {post.content_type !== 'question' && <CommentsSection postId={post.id} />}
            </article>

            {/* Sidebar */}
            <aside className="lg:col-span-1 space-y-6">
              {/* Author Card */}
              <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                <h3 className="font-semibold text-sm uppercase tracking-wider text-text-light dark:text-dark-text-muted mb-4">
                  {t('aboutAuthor')}
                </h3>
                <Link
                  href={`/profile/${post.author_id}`}
                  className="flex items-start gap-4 group"
                >
                  {post.author?.avatar_url ? (
                    <Image
                      src={post.author.avatar_url}
                      alt={authorDisplay}
                      width={56}
                      height={56}
                      className="w-14 h-14 rounded-2xl object-cover flex-shrink-0 group-hover:scale-105 transition-transform"
                    />
                  ) : (
                    <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-xl font-bold text-white flex-shrink-0 group-hover:scale-105 transition-transform">
                      {(post.author?.name?.[0] || post.author?.email?.[0] || 'U').toUpperCase()}
                    </div>
                  )}
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-text dark:text-dark-text group-hover:text-primary dark:group-hover:text-primary-light transition-colors">
                      {authorDisplay}
                    </p>
                    {post.author?.affiliation && (
                      <p className="text-sm text-text-light dark:text-dark-text-muted truncate">
                        {post.author.affiliation}
                      </p>
                    )}
                    {post.author?.bio && (
                      <p className="text-sm text-text-light dark:text-dark-text-muted line-clamp-2 mt-2">
                        {post.author.bio}
                      </p>
                    )}
                  </div>
                </Link>
              </div>

              {/* Related Posts */}
              {relatedPosts.length > 0 && (
                <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                  <h3 className="font-semibold text-sm uppercase tracking-wider text-text-light dark:text-dark-text-muted mb-4">
                    {t('relatedResearch')}
                  </h3>
                  <div className="space-y-4">
                    {relatedPosts.slice(0, 4).map((relPost: any) => (
                      <Link
                        key={relPost.id}
                        href={`/post/${relPost.id}`}
                        className="block group"
                      >
                        <h4 className="font-medium text-text dark:text-dark-text group-hover:text-primary dark:group-hover:text-primary-light transition-colors line-clamp-2 text-sm">
                          {relPost.title}
                        </h4>
                        <p className="text-xs text-text-light dark:text-dark-text-muted mt-1">
                          {new Date(relPost.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                        </p>
                      </Link>
                    ))}
                  </div>
                </div>
              )}

              {/* Citation Backlinks */}
              {citationBacklinks.length > 0 && (
                <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                  <h3 className="font-semibold text-sm uppercase tracking-wider text-text-light dark:text-dark-text-muted mb-4">
                    {t('citedBy')}
                  </h3>
                  <div className="space-y-4">
                    {citationBacklinks.slice(0, 4).map((citation: any) => (
                      <Link
                        key={citation.id}
                        href={`/post/${citation.id}`}
                        className="block group"
                      >
                        <h4 className="font-medium text-text dark:text-dark-text group-hover:text-primary dark:group-hover:text-primary-light transition-colors line-clamp-2 text-sm">
                          {citation.title}
                        </h4>
                        {citation.quote_content && (
                          <p className="text-xs text-text-light dark:text-dark-text-muted mt-1 italic line-clamp-2">
                            &quot;{citation.quote_content}&quot;
                          </p>
                        )}
                      </Link>
                    ))}
                  </div>
                </div>
              )}

              {/* Linked Resources */}
              <LinkedResourcesSection resources={linkedResources} />

              {/* Knowledge Graph */}
              <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                <h3 className="font-semibold text-sm uppercase tracking-wider text-text-light dark:text-dark-text-muted mb-4">
                  {t('knowledgeGraph')}
                </h3>
                <LazyKnowledgeGraph centerPostId={post.id} />
              </div>

              {/* Dynamic Schema Fields (Research Metadata) */}
              {schemaValues.length > 0 && (
                <SchemaFieldDisplay fields={schemaValues} />
              )}

              {/* Epistemic Recommendations - To Broaden This Inquiry */}
              <EpistemicRecommendations postId={post.id} postTags={post.tags || []} />
            </aside>
          </div>
        </main>

        {/* Session Tracker - adds post to research trail */}
        <PostSessionTracker postId={post.id} postTitle={post.title} postTags={post.tags || []} />

        {/* Citation Context Bar */}
        <CitationContextBar postId={post.id} currentTags={post.tags || []} />

        <Footer />
      </div>
    </>
  )
}

import { notFound } from 'next/navigation'
import Link from 'next/link'
import { ArrowLeft, Lock } from 'lucide-react'
import { createClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/service'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { ProfileHeader } from '@/components/ProfileHeader'
import { EndorsementSection } from '@/components/EndorsementSection'
import { UserActivityInsights } from '@/components/UserActivityInsights'
import { ProfileCompletionCard } from '@/components/ProfileCompletionCard'
import { getTranslations } from 'next-intl/server'
import { Metadata } from 'next'
import { buildProfileMetadata, buildPersonSchema, JsonLdScript } from '@/lib/seo'

interface ProfilePageProps {
  params: Promise<{
    id: string
  }>
}

// Generate dynamic metadata for SEO
export async function generateMetadata({ params }: ProfilePageProps): Promise<Metadata> {
  const { id } = await params
  const supabase = await createClient()

  const { data: profile } = await supabase
    .from('users')
    .select('id, name, bio, affiliation, avatar_url')
    .eq('id', id)
    .maybeSingle()

  if (!profile) {
    return {
      title: 'Researcher Not Found | SyriaHub',
      description: 'The requested profile could not be found.',
    }
  }

  // Check privacy settings
  const { data: prefData } = await supabase
    .from('user_preferences')
    .select('preferences')
    .eq('user_id', id)
    .maybeSingle()

  const privacySettings = prefData?.preferences?.privacy || { show_profile_public: true }

  // Don't index private profiles
  if (!privacySettings.show_profile_public) {
    return {
      title: 'Private Profile | SyriaHub',
      robots: { index: false, follow: false }
    }
  }

  return buildProfileMetadata(profile)
}

export default async function ProfilePage(props: ProfilePageProps) {
  const params = await props.params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  const t = await getTranslations('ProfileLabels')

  // Fetch profile data - use select('*') to avoid column mismatch issues
  const { data: profile, error: profileError } = await supabase
    .from('users')
    .select('*')
    .eq('id', params.id)
    .maybeSingle()

  if (profileError) {
    console.error('Profile fetch error:', profileError)
    notFound()
  }

  if (!profile) {
    notFound()
  }

  // Fetch user stats
  const { data: statsData } = await supabase
    .rpc('get_user_stats', { user_uuid: params.id })
    .maybeSingle()

  const stats = (statsData || {}) as {
    post_count?: number
    event_count?: number
    comment_count?: number
    citation_count?: number
    group_count?: number
    follower_count?: number
    academic_impact?: number
  }

  // Fetch target user's preferences for privacy settings
  const { data: prefData } = await supabase
    .from('user_preferences')
    .select('preferences')
    .eq('user_id', params.id)
    .maybeSingle()

  const privacySettings = prefData?.preferences?.privacy || {
    show_profile_public: true,
    show_email: false,
    allow_messages: true
  }

  const isOwnProfile = user?.id === params.id

  // Fetch viewer role to allow admin bypass for privacy
  let isViewerAdmin = false
  if (user && !isOwnProfile) {
    const { data: viewerData } = await supabase
      .from('users')
      .select('role')
      .eq('id', user.id)
      .maybeSingle()
    isViewerAdmin = viewerData?.role === 'admin' || viewerData?.role === 'moderator'
  }

  // Privacy Check: Block access if profile is private and viewer is not owner or admin
  if (!privacySettings.show_profile_public && !isOwnProfile && !isViewerAdmin) {
    return (
      <div className="min-h-screen bg-background dark:bg-dark-bg">
        <Navbar />
        <main className="container-custom max-w-4xl py-16 flex flex-col items-center text-center">
          <div className="w-24 h-24 bg-gray-100 dark:bg-dark-surface rounded-full flex items-center justify-center mb-6">
            <Lock className="w-10 h-10 text-gray-400" />
          </div>
          <h1 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
            This profile is private
          </h1>
          <p className="text-text-light dark:text-dark-text-muted mb-8">
            The user has chosen to keep their profile information private.
          </p>
          <Link
            href="/insights"
            className="px-6 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 transition-colors"
          >
            {t('backToInsights')}
          </Link>
        </main>
        <Footer />
      </div>
    )
  }


  // Create a mutable copy of the profile to modify
  const displayProfile = { ...profile }

  // Security: Explicitly redact email if privacy settings don't allow it
  // This ensures that even if the initial select('*') returned an email, 
  // it gets removed if the user wants it hidden and the viewer isn't the owner.
  if (!isOwnProfile && !privacySettings.show_email) {
    displayProfile.email = null
  }

  // Populate email for owner if available in auth session
  if (isOwnProfile && user?.email) {
    displayProfile.email = user.email
  }

  // Handle Email Privacy: Only fetch email if owner is viewing OR they've enabled show_email
  // Admins can see profile but must still respect email privacy choice
  if (!displayProfile.email && (isOwnProfile || privacySettings.show_email)) {
    const supabaseAdmin = createAdminClient()
    const { data: userWithEmail } = await supabaseAdmin
      .from('users')
      .select('email')
      .eq('id', params.id)
      .single()

    if (userWithEmail?.email) {
      displayProfile.email = userWithEmail.email
    }
  }

  // Fetch user badges
  const { data: userBadges } = await supabase
    .from('user_badges')
    .select('*, badge:badges(*)')
    .eq('user_id', params.id)

  // Fetch user's posts
  const { data: posts } = await supabase
    .from('posts')
    .select('*')
    .eq('author_id', params.id)
    .eq('status', 'published')
    .order('created_at', { ascending: false })

  // Fetch user's groups
  const { data: groupMembers } = await supabase
    .from('group_members')
    .select('group_id')
    .eq('user_id', params.id)

  let groups: any[] = []
  if (groupMembers && groupMembers.length > 0) {
    const groupIds = groupMembers.map(gm => gm.group_id)
    const { data: groupsData } = await supabase
      .from('groups')
      .select('*')
      .in('id', groupIds)
      .eq('visibility', 'public') // Only show public groups on profile

    groups = groupsData || []
  }



  // Build JSON-LD for public profiles only
  const jsonLdData = privacySettings.show_profile_public
    ? buildPersonSchema(displayProfile)
    : null

  return (
    <>
      {jsonLdData && <JsonLdScript data={jsonLdData} />}
      <div className="flex min-h-screen flex-col bg-background dark:bg-dark-bg overflow-x-hidden">
        <Navbar />

        {/* Back Navigation */}
        <div className="border-b border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface">
          <div className="container-custom w-full max-w-6xl py-4">
            <Link
              href="/insights"
              className="inline-flex items-center gap-2 text-text-light dark:text-dark-text-muted hover:text-primary dark:hover:text-accent-light transition-colors"
            >
              <ArrowLeft className="w-4 h-4" />
              {t('backToInsights')}
            </Link>
          </div>
        </div>

        <main className="container-custom w-full max-w-6xl py-8 flex-1">
          <ProfileHeader
            profile={displayProfile}
            stats={{
              post_count: Number(stats?.post_count || 0),
              event_count: Number(stats?.event_count || 0),
              comment_count: Number(stats?.comment_count || 0),
              citation_count: Number(stats?.citation_count || 0),
              group_count: Number(stats?.group_count || 0),
              follower_count: Number(stats?.follower_count || 0),
              academic_impact: Number(stats?.academic_impact || 0)
            }}
            badges={userBadges || []}
            isOwnProfile={isOwnProfile}
            privacySettings={privacySettings}
          />

          {/* Skills & Endorsements Section */}
          <div className="mb-8">
            <EndorsementSection
              userId={params.id}
              isOwnProfile={isOwnProfile}
            />
          </div>

          {/* Profile Completion - only show on own profile */}
          {isOwnProfile && (
            <div className="mb-8">
              <ProfileCompletionCard userId={params.id} />
            </div>
          )}

          <UserActivityInsights
            posts={posts || []}
            groups={groups}
          />
        </main>

        <Footer />
      </div>
    </>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { useToast } from '@/components/ui/toast'
import { GapContributions } from '@/components/GapContributions'
import { ResearchLabMobileNav } from '@/components/research-lab/ResearchLabMobileNav'
import {
    Search,
    Plus,
    Target,
    ChevronUp,
    Clock,
    User as UserIcon,
    MapPin,
    Calendar,
    Filter,
    TrendingUp,
    AlertCircle,
    CheckCircle2,
    Loader2,
    ArrowRight,
    Star,
    Database,
    FlaskConical,
    Users,
    History,
    FileText,
    Users2
} from 'lucide-react'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { ResearchGap, ResearchGapPriority, ResearchGapStatus, ResearchGapType } from '@/types'
import { User } from '@supabase/supabase-js'
import { formatDistanceToNow } from 'date-fns'
import { useTranslations } from 'next-intl'

const statusColors: Record<ResearchGapStatus, string> = {
    identified: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400',
    investigating: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
    addressed: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400',
    closed: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'
}

const priorityColors: Record<ResearchGapPriority, string> = {
    low: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400',
    medium: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
    high: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400',
    critical: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
}

const statusLabels: Record<ResearchGapStatus, string> = {
    identified: 'Identified',
    investigating: 'In Progress',
    addressed: 'Addressed',
    closed: 'Closed'
}

const gapTypeColors: Record<ResearchGapType, string> = {
    topical: 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300',
    data: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400',
    methodological: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400',
    population: 'bg-teal-100 text-teal-700 dark:bg-teal-900/30 dark:text-teal-400',
    outdated: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'
}

const gapTypeLabels: Record<ResearchGapType, string> = {
    topical: 'Topical Gap',
    data: 'Data Gap',
    methodological: 'Methodological',
    population: 'Population Gap',
    outdated: 'Outdated Research'
}

export default function ResearchGapsPage() {
    const t = useTranslations('ResearchGaps')
    const tCommon = useTranslations('Common')
    const supabase = createClient()
    const router = useRouter()
    const { showToast } = useToast()

    const [user, setUser] = useState<User | null>(null)
    const [gaps, setGaps] = useState<ResearchGap[]>([])
    const [loading, setLoading] = useState(true)
    const [searchQuery, setSearchQuery] = useState('')
    const [statusFilter, setStatusFilter] = useState<ResearchGapStatus | 'all'>('all')
    const [priorityFilter, setPriorityFilter] = useState<ResearchGapPriority | 'all'>('all')
    const [gapTypeFilter, setGapTypeFilter] = useState<ResearchGapType | 'all'>('all')
    const [strategicOnly, setStrategicOnly] = useState(false)
    const [showNewGapForm, setShowNewGapForm] = useState(false)
    const [userUpvotes, setUserUpvotes] = useState<Set<string>>(new Set())
    const [userInterests, setUserInterests] = useState<Set<string>>(new Set())

    // Form state for new gap
    const [newGapTitle, setNewGapTitle] = useState('')
    const [newGapDescription, setNewGapDescription] = useState('')
    const [newGapDiscipline, setNewGapDiscipline] = useState('')
    const [newGapPriority, setNewGapPriority] = useState<ResearchGapPriority>('medium')
    const [newGapType, setNewGapType] = useState<ResearchGapType>('topical')
    const [newGapIsStrategic, setNewGapIsStrategic] = useState(false)
    const [newGapSpatialContext, setNewGapSpatialContext] = useState('')
    const [submitting, setSubmitting] = useState(false)

    // Fetch user
    useEffect(() => {
        supabase.auth.getUser().then(({ data: { user } }) => {
            setUser(user)
        })
    }, [supabase])

    // Fetch gaps
    const fetchGaps = useCallback(async () => {
        setLoading(true)
        try {
            let query = supabase
                .from('research_gaps')
                .select(`
          *,
          creator:users!research_gaps_created_by_fkey(id, name, email, avatar_url),
          claimer:users!research_gaps_claimed_by_fkey(id, name, email)
        `)
                .order('upvote_count', { ascending: false })

            if (statusFilter !== 'all') {
                query = query.eq('status', statusFilter)
            }
            if (priorityFilter !== 'all') {
                query = query.eq('priority', priorityFilter)
            }
            if (gapTypeFilter !== 'all') {
                query = query.eq('gap_type', gapTypeFilter)
            }
            if (strategicOnly) {
                query = query.eq('is_strategic', true)
            }
            if (searchQuery) {
                query = query.or(`title.ilike.%${searchQuery}%,description.ilike.%${searchQuery}%`)
            }

            const { data, error } = await query

            if (error) throw error
            setGaps(data || [])
        } catch (error) {
            console.error('Error fetching gaps:', error)
            showToast(t('messages.loadFailed'), 'error')
        } finally {
            setLoading(false)
        }
    }, [supabase, statusFilter, priorityFilter, gapTypeFilter, strategicOnly, searchQuery, showToast, t])

    // Fetch user upvotes
    useEffect(() => {
        if (user) {
            supabase
                .from('research_gap_upvotes')
                .select('gap_id')
                .eq('user_id', user.id)
                .then(({ data }) => {
                    if (data) {
                        setUserUpvotes(new Set(data.map(u => u.gap_id)))
                    }
                })
        }
    }, [user, supabase])

    useEffect(() => {
        fetchGaps()
    }, [fetchGaps])

    // Handle upvote
    const handleUpvote = async (gapId: string) => {
        if (!user) {
            showToast(t('messages.signInToUpvote'), 'warning')
            return
        }

        const hasUpvoted = userUpvotes.has(gapId)

        try {
            if (hasUpvoted) {
                await supabase
                    .from('research_gap_upvotes')
                    .delete()
                    .eq('gap_id', gapId)
                    .eq('user_id', user.id)

                setUserUpvotes(prev => {
                    const next = new Set(prev)
                    next.delete(gapId)
                    return next
                })
            } else {
                await supabase
                    .from('research_gap_upvotes')
                    .insert({ gap_id: gapId, user_id: user.id })

                setUserUpvotes(prev => new Set([...prev, gapId]))
            }

            // Refresh to get updated count
            fetchGaps()
        } catch (error) {
            console.error('Error toggling upvote:', error)
            showToast(t('messages.voteFailed'), 'error')
        }
    }

    // Handle claim
    const handleClaim = async (gapId: string) => {
        if (!user) {
            showToast(t('messages.signInToClaim'), 'warning')
            return
        }

        try {
            await supabase
                .from('research_gaps')
                .update({
                    claimed_by: user.id,
                    claimed_at: new Date().toISOString(),
                    status: 'investigating'
                })
                .eq('id', gapId)

            showToast(t('messages.claimSuccess'), 'success')
            fetchGaps()
        } catch (error) {
            console.error('Error claiming gap:', error)
            showToast(t('messages.claimFailed'), 'error')
        }
    }

    // Handle new gap submission
    const handleSubmitGap = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!user) {
            showToast(t('messages.signInToSubmit'), 'warning')
            return
        }

        if (!newGapTitle.trim()) {
            showToast(t('messages.titleRequired'), 'warning')
            return
        }

        setSubmitting(true)

        try {
            const { error } = await supabase
                .from('research_gaps')
                .insert({
                    title: newGapTitle.trim(),
                    description: newGapDescription.trim() || null,
                    discipline: newGapDiscipline.trim() || null,
                    priority: newGapPriority,
                    gap_type: newGapType,
                    is_strategic: newGapIsStrategic,
                    spatial_context: newGapSpatialContext.trim() || null,
                    created_by: user.id,
                    status: 'identified'
                })

            if (error) throw error

            showToast(t('messages.submitSuccess'), 'success')
            setShowNewGapForm(false)
            setNewGapTitle('')
            setNewGapDescription('')
            setNewGapDiscipline('')
            setNewGapPriority('medium')
            setNewGapType('topical')
            setNewGapIsStrategic(false)
            setNewGapSpatialContext('')
            fetchGaps()
        } catch (error) {
            console.error('Error submitting gap:', error)
            showToast(t('messages.submitFailed'), 'error')
        } finally {
            setSubmitting(false)
        }
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            {/* Hero Header */}
            <header className="bg-gradient-to-br from-primary via-primary-dark to-primary relative overflow-hidden">
                <div className="absolute inset-0 opacity-10">
                    <div className="absolute top-0 right-0 w-96 h-96 bg-white rounded-full blur-3xl transform translate-x-1/2 -translate-y-1/2" />
                    <div className="absolute bottom-0 left-0 w-64 h-64 bg-secondary rounded-full blur-3xl transform -translate-x-1/2 translate-y-1/2" />
                </div>

                <div className="container-custom max-w-6xl relative z-10 py-12 md:py-16">
                    <div className="flex items-center gap-3 mb-4">
                        <Target className="w-6 h-6 text-white/80" />
                        <span className="text-sm font-semibold uppercase tracking-wider text-white/80">
                            {t('title')}
                        </span>
                    </div>
                    <h1 className="text-3xl md:text-4xl font-bold text-white mb-3">
                        {t('heading')}
                    </h1>
                    <p className="text-lg text-white/80 max-w-2xl mb-6">
                        {t('subtitle')}
                    </p>

                    {/* Search & Actions */}
                    <div className="flex flex-col sm:flex-row gap-3">
                        <div className="relative flex-1 max-w-md">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/50" />
                            <input
                                type="text"
                                placeholder={t('searchPlaceholder')}
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                                className="w-full pl-12 pr-4 py-3 rounded-xl bg-white/10 backdrop-blur-sm border border-white/20 text-white placeholder:text-white/50 focus:bg-white/20 focus:border-white/40 focus:outline-none transition-all"
                            />
                        </div>
                        <button
                            onClick={() => setShowNewGapForm(true)}
                            className="flex items-center justify-center gap-2 px-6 py-3 bg-white text-primary font-semibold rounded-xl hover:bg-white/90 transition-all shadow-sm"
                        >
                            <Plus className="w-5 h-5" />
                            {t('identifyGap')}
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-1 container-custom max-w-6xl py-8">
                {/* Filters */}
                <div className="flex flex-wrap items-center gap-3 mb-8">
                    <div className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted">
                        <Filter className="w-4 h-4" />
                        {t('filters')}:
                    </div>


                    <Select value={statusFilter} onValueChange={(value) => setStatusFilter(value as ResearchGapStatus | 'all')}>
                        <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder={t('allStatuses')} />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">{t('allStatuses')}</SelectItem>
                            <SelectItem value="identified">{t('statuses.identified')}</SelectItem>
                            <SelectItem value="investigating">{t('statuses.investigating')}</SelectItem>
                            <SelectItem value="addressed">{t('statuses.addressed')}</SelectItem>
                            <SelectItem value="closed">{t('statuses.closed')}</SelectItem>
                        </SelectContent>
                    </Select>

                    <Select value={priorityFilter} onValueChange={(value) => setPriorityFilter(value as ResearchGapPriority | 'all')}>
                        <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder={t('allPriorities')} />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">{t('allPriorities')}</SelectItem>
                            <SelectItem value="critical">{t('priorities.critical')}</SelectItem>
                            <SelectItem value="high">{t('priorities.high')}</SelectItem>
                            <SelectItem value="medium">{t('priorities.medium')}</SelectItem>
                            <SelectItem value="low">{t('priorities.low')}</SelectItem>
                        </SelectContent>
                    </Select>

                    <Select value={gapTypeFilter} onValueChange={(value) => setGapTypeFilter(value as ResearchGapType | 'all')}>
                        <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder={t('allTypes')} />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">{t('allTypes')}</SelectItem>
                            <SelectItem value="topical">{t('types.topical')}</SelectItem>
                            <SelectItem value="data">{t('types.data')}</SelectItem>
                            <SelectItem value="methodological">{t('types.methodological')}</SelectItem>
                            <SelectItem value="population">{t('types.population')}</SelectItem>
                            <SelectItem value="outdated">{t('types.outdated')}</SelectItem>
                        </SelectContent>
                    </Select>

                    <button
                        onClick={() => setStrategicOnly(!strategicOnly)}
                        className={`px-4 py-2 text-sm rounded-lg border flex items-center gap-2 transition-all ${strategicOnly
                            ? 'bg-amber-100 border-amber-300 text-amber-700 dark:bg-amber-900/30 dark:border-amber-700 dark:text-amber-400'
                            : 'border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-bg'
                            }`}
                    >
                        <Star className={`w-4 h-4 ${strategicOnly ? 'fill-current' : ''}`} />
                        {t('strategic')}
                    </button>

                    <div className="flex-1" />

                    <div className="text-sm text-text-light dark:text-dark-text-muted">
                        {gaps.length === 1 ? t('gapsFound', { count: gaps.length }) : t('gapsFoundPlural', { count: gaps.length })}
                    </div>
                </div>

                {/* Success Stories - Resolved Gaps Showcase */}
                {
                    gaps.filter(g => g.status === 'addressed' && g.addressed_by_post_id).length > 0 && statusFilter !== 'identified' && statusFilter !== 'investigating' && (
                        <div className="mb-8 p-5 bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800/50 rounded-xl">
                            <div className="flex items-center gap-2 mb-4">
                                <CheckCircle2 className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                                <h3 className="font-semibold text-emerald-800 dark:text-emerald-300">
                                    {t('successStories.title')}
                                </h3>
                            </div>
                            <p className="text-sm text-emerald-700 dark:text-emerald-400/80 mb-4">
                                {t('successStories.description')}
                            </p>
                            <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
                                {gaps
                                    .filter(g => g.status === 'addressed' && g.addressed_by_post_id)
                                    .slice(0, 3)
                                    .map(gap => (
                                        <Link
                                            key={gap.id}
                                            href={`/post/${gap.addressed_by_post_id}`}
                                            className="group p-3 bg-white dark:bg-dark-surface rounded-lg border border-emerald-100 dark:border-emerald-800/30 hover:border-emerald-300 dark:hover:border-emerald-700 transition-all"
                                        >
                                            <h4 className="text-sm font-medium text-text dark:text-dark-text line-clamp-2 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 transition-colors">
                                                {gap.title}
                                            </h4>
                                            <div className="flex items-center gap-1 mt-2 text-xs text-emerald-600 dark:text-emerald-400">
                                                <ArrowRight className="w-3.5 h-3.5" />
                                                {t('successStories.viewResearch')}
                                            </div>
                                        </Link>
                                    ))}
                            </div>
                        </div>
                    )
                }

                {/* New Gap Form Modal */}
                {
                    showNewGapForm && (
                        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                            <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border max-w-lg w-full max-h-[90vh] overflow-y-auto p-6">
                                <h2 className="text-xl font-bold text-text dark:text-dark-text mb-4">
                                    {t('form.title')}
                                </h2>
                                <form onSubmit={handleSubmitGap} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
