                                <Plus className="w-5 h-5" />
                                {t('identifyGap')}
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {gaps.map(gap => (
                                <div
                                    key={gap.id}
                                    className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-5 hover:border-primary/30 dark:hover:border-primary-light/30 transition-all"
                                >
                                    <div className="flex gap-4">
                                        {/* Upvote Button */}
                                        <div className="flex flex-col items-center gap-1">
                                            <button
                                                onClick={() => handleUpvote(gap.id)}
                                                className={`p-2 rounded-lg transition-all ${userUpvotes.has(gap.id)
                                                    ? 'bg-primary text-white'
                                                    : 'bg-gray-100 dark:bg-dark-bg text-text-light dark:text-dark-text-muted hover:bg-primary/10 hover:text-primary'
                                                    }`}
                                            >
                                                <ChevronUp className="w-5 h-5" />
                                            </button>
                                            <span className={`text-sm font-semibold ${userUpvotes.has(gap.id) ? 'text-primary' : 'text-text dark:text-dark-text'}`}>
                                                {gap.upvote_count}
                                            </span>
                                        </div>

                                        {/* Content */}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex flex-wrap items-center gap-2 mb-2">
                                                {/* Strategic Star */}
                                                {gap.is_strategic && (
                                                    <span className="px-2.5 py-0.5 rounded-full bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 text-xs font-medium flex items-center gap-1">
                                                        <Star className="w-3 h-3 fill-current" />
                                                        Strategic
                                                    </span>
                                                )}
                                                {/* Gap Type Badge */}
                                                {gap.gap_type && (
                                                    <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${gapTypeColors[gap.gap_type]}`}>
                                                        {gapTypeLabels[gap.gap_type]}
                                                    </span>
                                                )}
                                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColors[gap.status]}`}>
                                                    {statusLabels[gap.status]}
                                                </span>
                                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${priorityColors[gap.priority]}`}>
                                                    {t('card.priorityLabel', { priority: t(`priorities.${gap.priority}`) })}
                                                </span>
                                                {gap.discipline && (
                                                    <span className="px-2.5 py-0.5 rounded-full bg-gray-100 dark:bg-dark-bg text-xs font-medium text-text-light dark:text-dark-text-muted">
                                                        {gap.discipline}
                                                    </span>
                                                )}
                                            </div>

                                            <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-2 line-clamp-2">
                                                {gap.title}
                                            </h3>

                                            {gap.description && (
                                                <p className="text-sm text-text-light dark:text-dark-text-muted mb-3 line-clamp-2">
                                                    {gap.description}
                                                </p>
                                            )}

                                            <div className="flex flex-wrap items-center gap-4 text-xs text-text-light dark:text-dark-text-muted">
                                                {gap.spatial_context && (
                                                    <span className="flex items-center gap-1">
                                                        <MapPin className="w-3.5 h-3.5" />
                                                        {gap.spatial_context}
                                                    </span>
                                                )}
                                                <span className="flex items-center gap-1">
                                                    <Clock className="w-3.5 h-3.5" />
                                                    {formatDistanceToNow(new Date(gap.created_at), { addSuffix: true })}
                                                </span>
                                                {gap.creator && (
                                                    <span className="flex items-center gap-1">
                                                        <UserIcon className="w-3.5 h-3.5" />
                                                        {(gap.creator as any).name || (gap.creator as any).email?.split('@')[0]}
                                                    </span>
                                                )}
                                            </div>

                                            {/* Claim / Progress Section */}
                                            {gap.status === 'identified' && user && user.id !== gap.created_by && (
                                                <button
                                                    onClick={() => handleClaim(gap.id)}
                                                    className="mt-3 inline-flex items-center gap-2 px-4 py-2 text-sm font-semibold text-primary bg-primary/10 rounded-lg hover:bg-primary/20 transition-all"
                                                >
                                                    <Target className="w-4 h-4" />
                                                    {t('card.claimButton')}
                                                </button>
                                            )}

                                            {gap.status === 'investigating' && gap.claimer && (
                                                <div className="mt-3 flex items-center gap-2 text-sm text-blue-600 dark:text-blue-400">
                                                    <TrendingUp className="w-4 h-4" />
                                                    Being investigated by {(gap.claimer as any).name || (gap.claimer as any).email?.split('@')[0]}
                                                </div>
                                            )}
                                            {gap.status === 'addressed' && gap.addressed_by_post_id && (
                                                <Link
                                                    href={`/post/${gap.addressed_by_post_id}`}
                                                    className="mt-3 inline-flex items-center gap-2 text-sm font-semibold text-emerald-600 dark:text-emerald-400 hover:underline"
                                                >
                                                    <CheckCircle2 className="w-4 h-4" />
                                                    {t('card.viewAddressing')}
                                                    <ArrowRight className="w-4 h-4" />
                                                </Link>
                                            )}

                                            {/* Gap Contributions - formal collaboration system */}
                                            {gap.status !== 'closed' && (
                                                <GapContributions
                                                    gapId={gap.id}
                                                    gapClaimerId={gap.claimed_by || undefined}
                                                    className="mt-4"
                                                />
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )
                }
            </main >

            <ResearchLabMobileNav />
            <Footer />
        </div >
    )
}

import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { ResearchLabNav } from '@/components/research-lab/ResearchLabNav'
import { PollsList } from '@/components/research-lab/PollsList'

export default async function PollsPage({
    searchParams
}: {
    searchParams: Promise<{ create?: string }>
}) {
    const params = await searchParams
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    // Fetch polls - active ones and user's own (including closed)
    let pollsQuery = supabase
        .from('polls')
        .select(`
            *,
            author:users!author_id(name, email)
        `)
        .order('created_at', { ascending: false })

    // If user is logged in, show active polls OR their own polls
    if (user) {
        pollsQuery = pollsQuery.or(`is_active.eq.true,author_id.eq.${user.id}`)
    } else {
        pollsQuery = pollsQuery.eq('is_active', true)
    }

    const { data: polls } = await pollsQuery

    // Fetch user's votes
    const userVotes: Record<string, string[]> = {}
    if (user) {
        const { data: votes } = await supabase
            .from('poll_votes')
            .select('poll_id, option_ids')
            .eq('user_id', user.id)

        if (votes) {
            votes.forEach((vote: any) => {
                userVotes[vote.poll_id] = vote.option_ids
            })
        }
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            <div className="flex flex-1">
                {/* Sidebar - hidden on mobile */}
                <ResearchLabNav className="hidden md:flex" />

                {/* Main Content */}
                <main className="flex-1 container-custom py-8">
                    <PollsList
                        polls={polls || []}
                        userVotes={userVotes}
                        userId={user?.id}
                        showCreate={params.create === 'true'}
                    />
                </main>
            </div>

            <Footer />
        </div>
    )
}

import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { ResearchLabNav } from '@/components/research-lab/ResearchLabNav'
import { QuestionAdvisor } from '@/components/research-lab/QuestionAdvisor'

export default async function QuestionAdvisorPage() {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    // Check AI usage limits
    let usageLimits = null
    let questionHistory: any[] = []

    if (user) {
        const { data: limitsData } = await supabase.rpc('check_ai_usage_limit', {
            p_user_id: user.id,
            p_feature: 'question_advisor'
        })
        usageLimits = limitsData?.[0]

        // Fetch question history
        const { data: historyData } = await supabase
            .from('question_history')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false })
            .limit(20)

        questionHistory = historyData || []
    }

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            <div className="flex flex-1">
                {/* Sidebar - hidden on mobile */}
                <ResearchLabNav className="hidden md:flex" />

                {/* Main Content */}
                <main className="flex-1 container-custom py-8">
                    <QuestionAdvisor
                        userId={user?.id}
                        usageLimits={usageLimits}
                        initialHistory={questionHistory}
                    />
                </main>
            </div>

            <Footer />
        </div>
    )
}

import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
// Refreshed layout consistency for ResourceCard tags
import { Footer } from '@/components/Footer'
import { ResourceCard } from '@/components/ResourceCard'
import { ResourceFilters } from '@/components/ResourceFilters'
import { inferResourceType } from '@/lib/utils'
import Link from 'next/link'
import { UploadCloud, FolderOpen } from 'lucide-react'
import { getTranslations } from 'next-intl/server'

interface SearchParams {
    type?: string
    discipline?: string
    license?: string
    q?: string
    sort?: string
}

export default async function ResourcesPage({
    searchParams,
}: {
    searchParams: Promise<SearchParams>
}) {
    const params = await searchParams
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    const t = await getTranslations('Resources')

    // Build the query based on filters
    let query = supabase
        .from('posts')
        .select(`
            *,
            author:users!author_id(id, name, email, avatar_url)
        `)
        .eq('content_type', 'resource')
        .eq('status', 'published')

    // Apply filters
    if (params.type) {
        query = query.eq('metadata->>resource_type', params.type)
    }
    if (params.license) {
        query = query.eq('metadata->>license', params.license)
    }
    if (params.q) {
        query = query.or(`title.ilike.%${params.q}%,content.ilike.%${params.q}%`)
    }

    // Apply sorting
    if (params.sort === 'downloads') {
        query = query.order('metadata->downloads', { ascending: false, nullsFirst: false })
    } else if (params.sort === 'title') {
        query = query.order('title', { ascending: true })
    } else {
        query = query.order('created_at', { ascending: false })
    }

    const { data: resources } = await query

    // Filter by discipline client-side (requires tag lookup)
    let filteredResources = resources || []
    if (params.discipline && resources) {
        const { data: tags } = await supabase
            .from('tags')
            .select('label')
            .eq('discipline', params.discipline)

        const disciplineTags = tags?.map(t => t.label) || []
        filteredResources = resources.filter((r: any) =>
            r.tags?.some((tag: string) => disciplineTags.includes(tag))
        )
    }

    // Add linked_posts_count = 0 and infer type for each resource on the server
    const resourcesWithLinks = filteredResources.map((resource: any) => {
        const metadata = resource.metadata || {}
        // Explicitly calculate the resource type on the server to avoid client-side hydration issues
        const inferredType = (metadata.resource_type?.toLowerCase()) ||
            inferResourceType(metadata.mime_type, metadata.original_name, resource.title) ||
            'document'

        return {
            ...resource,
            linked_posts_count: 0,
            inferredType
        }
    })

    const hasFilters = params.type || params.discipline || params.license || params.q

    return (
        <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
            <Navbar />

            <main className="flex-1 container-custom py-12">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                    <div>
                        <h1 className="text-3xl font-display font-bold text-primary dark:text-dark-text mb-2">
                            {t('title')}
                        </h1>
                        <p className="text-text-light dark:text-dark-text-muted">
                            {t('subtitle')}
                        </p>
                    </div>

                    <Link
                        href="/resources/upload"
                        className="btn btn-primary flex items-center justify-center gap-2"
                    >
                        <UploadCloud className="w-5 h-5" />
                        {t('uploadResource')}
                    </Link>
                </div>

                <div className="grid md:grid-cols-[280px_1fr] gap-8">
                    {/* Filters Sidebar */}
                    <aside className="md:sticky md:top-24 h-fit">
                        <ResourceFilters />
                    </aside>

                    {/* Resources Grid */}
                    <div className="space-y-6">
                        {/* Results Count */}
                        {hasFilters && (
                            <div className="text-sm text-text-light dark:text-dark-text-muted">
                                {t('showingResults', { count: resourcesWithLinks.length })}
                                {params.q && <span> for &quot;{params.q}&quot;</span>}
                            </div>
                        )}

                        {resourcesWithLinks.length > 0 ? (
                            resourcesWithLinks.map((resource: any) => (
                                <ResourceCard
                                    key={resource.id}
                                    resource={resource}
                                    preCalculatedType={resource.inferredType}
                                />
                            ))
                        ) : (
                            <div className="text-center py-16 bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border">
                                <FolderOpen className="w-16 h-16 mx-auto text-gray-300 dark:text-dark-text-muted mb-4" />
                                <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-2">
                                    {hasFilters ? t('noResults') : t('noResources')}
                                </h3>
                                <p className="text-text-light dark:text-dark-text-muted mb-6 max-w-md mx-auto">
                                    {hasFilters ? t('noResultsDesc') : t('noResourcesDesc')}
                                </p>
                                {!hasFilters && (
                                    <Link
                                        href="/resources/upload"
                                        className="btn btn-outline"
                                    >
                                        {t('uploadResource')}
                                    </Link>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    )
}

