// GET: Fetch user's bookmarks
export async function GET(request: NextRequest) {
    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        if (!user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const { data: bookmarks, error } = await supabase
            .from('bookmarks')
            .select(`
                id,
                created_at,
                post:posts(
                    id,
                    title,
                    content,
                    tags,
                    status,
                    created_at,
                    author:users!posts_author_id_fkey(id, name, email)
                )
            `)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false })

        if (error) {
            console.error('Error fetching bookmarks:', error)
            return NextResponse.json({ error: 'Failed to fetch bookmarks' }, { status: 500 })
        }

        return NextResponse.json({ bookmarks })

    } catch (error) {
        console.error('Error in bookmarks GET:', error)
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
    }
}

// POST: Add a bookmark
async function handlePost(request: NextRequest) {
    // SECURITY: Validate origin for CSRF protection
    if (!validateOrigin(request)) {
        return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
    }
    
    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        if (!user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const body = await request.json()
        const { post_id } = body

        if (!post_id) {
            return NextResponse.json({ error: 'Post ID is required' }, { status: 400 })
        }

        // Check if already bookmarked
        const { data: existing } = await supabase
            .from('bookmarks')
            .select('id')
            .eq('user_id', user.id)
            .eq('post_id', post_id)
            .single()

        if (existing) {
            return NextResponse.json({ error: 'Already bookmarked' }, { status: 409 })
        }

        const { data: bookmark, error } = await supabase
            .from('bookmarks')
            .insert({
                user_id: user.id,
                post_id
            })
            .select()
            .single()

        if (error) {
            console.error('Error creating bookmark:', error)
            return NextResponse.json({ error: 'Failed to create bookmark' }, { status: 500 })
        }

        return NextResponse.json({ bookmark })

    } catch (error) {
        console.error('Error in bookmarks POST:', error)
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
    }
}

// DELETE: Remove a bookmark
async function handleDelete(request: NextRequest) {
    // SECURITY: Validate origin for CSRF protection
    if (!validateOrigin(request)) {
        return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
    }
    
    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        if (!user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const { searchParams } = new URL(request.url)
        const id = searchParams.get('id')
        const post_id = searchParams.get('post_id')

        if (!id && !post_id) {
            return NextResponse.json({ error: 'Bookmark ID or Post ID is required' }, { status: 400 })
        }

        let query = supabase.from('bookmarks').delete().eq('user_id', user.id)

        if (id) {
            query = query.eq('id', id)
        } else if (post_id) {
            query = query.eq('post_id', post_id)
        }

        const { error } = await query

        if (error) {
            console.error('Error deleting bookmark:', error)
            return NextResponse.json({ error: 'Failed to delete bookmark' }, { status: 500 })
        }

        return NextResponse.json({ success: true })

    } catch (error) {
        console.error('Error in bookmarks DELETE:', error)
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
    }
}

// SECURITY: Apply rate limiting to all mutation endpoints
export const POST = withRateLimit('write')(handlePost)
export const DELETE = withRateLimit('write')(handleDelete)

// Citations API - Delete citation
import { NextResponse } from 'next/server'
import { createServerClient, verifyAuth, canModify } from '@/lib/supabaseClient'
import {
  successResponse,
  handleSupabaseError,
  extractIdFromParams,
  withErrorHandling,
  notFoundResponse,
  forbiddenResponse,
  validateOrigin,
} from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'

/**
 * DELETE /api/citations/[id]
 * Delete a citation (source post owner, or moderator/admin)
 */
async function handleDeleteCitation(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
): Promise<NextResponse> {
  // CSRF protection
  if (!validateOrigin(request)) {
    return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
  }

  const { id } = await params
  const citationId = extractIdFromParams({ id })
  
  // Verify authentication
  const user = await verifyAuth()
  
  const supabase = await createServerClient()

  // Get the citation with source post info
  const { data: citation, error: fetchError } = await supabase
    .from('citations')
    .select(`
      *,
      source_post:posts!citations_source_post_id_fkey(id, author_id)
    `)
    .eq('id', citationId)
    .single()

  if (fetchError || !citation) {
    if (fetchError?.code === 'PGRST116') {
      return notFoundResponse('Citation not found')
    }
    return handleSupabaseError(fetchError)
  }

  // Check if user can delete (owner of source post, or moderator/admin)
  const sourcePost = citation.source_post as any
  if (!(await canModify(sourcePost.author_id))) {
    return forbiddenResponse('You can only delete citations from your own posts')
  }

  // Delete citation
  const { error } = await supabase
    .from('citations')
    .delete()
    .eq('id', citationId)

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse({ message: 'Citation deleted successfully' })
}

export const DELETE = withRateLimit('write')(withErrorHandling(handleDeleteCitation))

// Citations API - Create and manage post citations (internal and external)
import { NextResponse } from 'next/server'
import { createServerClient, verifyAuth, canModify } from '@/lib/supabaseClient'
import {
  successResponse,
  errorResponse,
  handleSupabaseError,
  parseRequestBody,
  validateRequiredFields,
  getQueryParams,
  withErrorHandling,
  forbiddenResponse,
  validateOrigin,
} from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'

interface CreateInternalCitationInput {
  source_post_id: string
  target_post_id: string
  quote_content?: string
}

interface CreateExternalCitationInput {
  source_post_id: string
  external_url?: string
  external_doi?: string
  external_title?: string
  external_author?: string
  external_year?: number
  external_source?: string
}

type CreateCitationInput = (CreateInternalCitationInput | CreateExternalCitationInput) & {
  type?: 'internal' | 'external'
}

/**
 * GET /api/citations
 * Get citations for a post
 * Query params: source_post_id, target_post_id, type, limit, offset
 */
async function handleGetCitations(request: Request): Promise<NextResponse> {
  const supabase = await createServerClient()
  const params = getQueryParams(request)

  const sourcePostId = params.get('source_post_id')
  const targetPostId = params.get('target_post_id')
  const citationType = params.get('type') as 'internal' | 'external' | null
  const limit = parseInt(params.get('limit') || '50', 10)
  const offset = parseInt(params.get('offset') || '0', 10)

  if (!sourcePostId && !targetPostId) {
    return errorResponse('Either source_post_id or target_post_id is required', 422)
  }

  let query = supabase
    .from('citations')
    .select(`
      *,
      source_post:posts!citations_source_post_id_fkey(id, title, author_id, created_at, author:users(name, email)),
      target_post:posts!citations_target_post_id_fkey(id, title, author_id, created_at, author:users(name, email)),
      creator:users!citations_created_by_fkey(id, name, email)
    `)
    .order('created_at', { ascending: false })
    .range(offset, offset + limit - 1)

  if (sourcePostId) {
    query = query.eq('source_post_id', sourcePostId)
  }

  if (targetPostId) {
    query = query.eq('target_post_id', targetPostId)
  }

  if (citationType) {
    query = query.eq('type', citationType)
  }

  const { data, error } = await query

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse({
    citations: data || [],
    pagination: {
      limit,
      offset,
      total: data?.length || 0,
    },
  })
}

/**
 * POST /api/citations
 * Create a citation (authenticated users)
 * Supports both internal (SyriaHub post) and external (DOI/URL) citations
 */
async function handleCreateCitation(request: Request): Promise<NextResponse> {
  // CSRF protection
  if (!validateOrigin(request)) {
    return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
  }

  // Verify authentication
  const user = await verifyAuth()

  const supabase = await createServerClient()

  // Parse request body
  const body = await parseRequestBody<CreateCitationInput>(request)

  // Validate source_post_id is always required
  validateRequiredFields(body, ['source_post_id'])

  const {
    source_post_id,
    type = 'internal',
  } = body

  // Verify source post exists
  const { data: sourcePost, error: sourceError } = await supabase
    .from('posts')
    .select('id')
    .eq('id', source_post_id)
    .single()

  if (sourceError || !sourcePost) {
    return errorResponse('Source post not found', 404)
  }

  // Handle internal citations
  if (type === 'internal') {
    const { target_post_id, quote_content } = body as CreateInternalCitationInput

    if (!target_post_id) {
      return errorResponse('target_post_id is required for internal citations', 422)
    }

    // Validate that posts are different
    if (source_post_id === target_post_id) {
      return errorResponse('A post cannot cite itself', 422)
    }

    // Verify target post exists
    const { data: targetPost, error: targetError } = await supabase
      .from('posts')
      .select('id')
      .eq('id', target_post_id)
      .single()

    if (targetError || !targetPost) {
      return errorResponse('Target post not found', 404)
    }

    // Check if citation already exists
    const { data: existingCitation } = await supabase
      .from('citations')
      .select('id')
      .eq('source_post_id', source_post_id)
      .eq('target_post_id', target_post_id)
      .single()

    if (existingCitation) {
      return errorResponse('Citation already exists', 409)
    }

    // Create internal citation
    const { data, error } = await supabase
      .from('citations')
      .insert({
        source_post_id,
        target_post_id,
        quote_content: quote_content || null,
        type: 'internal',
        created_by: user.id,
      })
      .select(`
        *,
        source_post:posts!citations_source_post_id_fkey(id, title),
        target_post:posts!citations_target_post_id_fkey(id, title)
      `)
      .single()

    if (error) {
      return handleSupabaseError(error)
    }

    return successResponse(data, 201)
  }

  // Handle external citations
  if (type === 'external') {
    const {
      external_url,
      external_doi,
      external_title,
      external_author,
      external_year,
      external_source
    } = body as CreateExternalCitationInput

    // Require at least DOI or URL
    if (!external_doi && !external_url) {
      return errorResponse('External citations require either external_doi or external_url', 422)
    }

    // Check for duplicate external citation (same source post + DOI or URL)
    let duplicateQuery = supabase
      .from('citations')
      .select('id')
      .eq('source_post_id', source_post_id)
      .eq('type', 'external')

    if (external_doi) {
      // Note: DOI will be normalized by database trigger
      duplicateQuery = duplicateQuery.eq('external_doi', external_doi.toLowerCase().trim())
    } else if (external_url) {
      duplicateQuery = duplicateQuery.eq('external_url', external_url)
    }

    const { data: existingExternal } = await duplicateQuery.single()

    if (existingExternal) {
      return errorResponse('This external source is already cited in this post', 409)
    }

    // Create external citation
    const { data, error } = await supabase
      .from('citations')
      .insert({
        source_post_id,
        target_post_id: null, // External citations don't link to internal posts
        type: 'external',
        created_by: user.id,
        external_url: external_url || null,
        external_doi: external_doi || null, // Will be normalized by trigger
        external_title: external_title || null,
        external_author: external_author || null,
        external_year: external_year || null,
        external_source: external_source || null,
      })
      .select('*')
      .single()

    if (error) {
      return handleSupabaseError(error)
    }

    return successResponse(data, 201)
  }

  return errorResponse('Invalid citation type. Must be "internal" or "external"', 422)
}

export const GET = withErrorHandling(handleGetCitations, {
  cache: {
    maxAge: 300,
    staleWhileRevalidate: 900,
  },
})
export const POST = withRateLimit('write')(withErrorHandling(handleCreateCitation))

// Comments API - Update and Delete single comment
import { NextResponse } from 'next/server'
import { createServerClient, verifyAuth, canModify } from '@/lib/supabaseClient'
import {
  successResponse,
  errorResponse,
  handleSupabaseError,
  parseRequestBody,
  extractIdFromParams,
  withErrorHandling,
  notFoundResponse,
  forbiddenResponse,
  withOriginValidation,
} from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'

interface UpdateCommentInput {
  content: string
}

/**
 * PUT /api/comments/[id]
 * Update a comment (owner only)
 */
async function handleUpdateComment(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
): Promise<NextResponse> {
  const { id } = await params
  const commentId = extractIdFromParams({ id })
  
  // Verify authentication
  const user = await verifyAuth()
  
  const supabase = await createServerClient()

  // Get the comment to check ownership
  const { data: comment, error: fetchError } = await supabase
    .from('comments')
    .select('user_id')
    .eq('id', commentId)
    .single()

  if (fetchError) {
    if (fetchError.code === 'PGRST116') {
      return notFoundResponse('Comment not found')
    }
    return handleSupabaseError(fetchError)
  }

  // Only the comment owner can edit (not moderators)
  if (comment.user_id !== user.id) {
    return forbiddenResponse('You can only edit your own comments')
  }

  // Parse request body
  const body = await parseRequestBody<UpdateCommentInput>(request)
  
  if (!body.content || body.content.length < 1) {
    return errorResponse('Comment content cannot be empty', 422)
  }

  if (body.content.length > 5000) {
    return errorResponse('Comment content is too long (max 5000 characters)', 422)
  }

  // Update comment
  const { data, error } = await supabase
    .from('comments')
    .update({ content: body.content })
    .eq('id', commentId)
    .select(`
      *,
      user:users!comments_user_id_fkey(id, name, email, role)
    `)
    .single()

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse(data)
}

/**
 * DELETE /api/comments/[id]
 * Delete a comment (owner, moderator, or admin)
 */
async function handleDeleteComment(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
): Promise<NextResponse> {
  const { id } = await params
  const commentId = extractIdFromParams({ id })
  
  // Verify authentication
  const user = await verifyAuth()
  
  const supabase = await createServerClient()

  // Get the comment to check ownership
  const { data: comment, error: fetchError } = await supabase
    .from('comments')
    .select('user_id')
    .eq('id', commentId)
    .single()

  if (fetchError) {
    if (fetchError.code === 'PGRST116') {
      return notFoundResponse('Comment not found')
    }
    return handleSupabaseError(fetchError)
  }

  // Check if user can delete this comment
  if (!(await canModify(comment.user_id))) {
    return forbiddenResponse('You do not have permission to delete this comment')
  }

  // Delete comment
  const { error } = await supabase
    .from('comments')
    .delete()
    .eq('id', commentId)

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse({ message: 'Comment deleted successfully' })
}

export const PUT = withRateLimit('write')(withOriginValidation(withErrorHandling(handleUpdateComment)))
export const DELETE = withRateLimit('write')(withOriginValidation(withErrorHandling(handleDeleteComment)))

import { NextRequest, NextResponse } from 'next/server'
import { createClient as createServerClient } from '@/lib/supabase/server'
import { createClient as createAdminClient } from '@supabase/supabase-js'
import { validateOrigin } from '@/lib/apiUtils'
import { sendEmail, emailTemplates } from '@/lib/email'
import { applyRateLimit } from '@/lib/rateLimit'
import { verifyTurnstileToken } from '@/lib/turnstile'
import { z } from 'zod'

// SECURITY: Strict input validation schema
const contactSchema = z.object({
    name: z.string().min(2, 'Name too short').max(100, 'Name too long').trim(),
    email: z.string().email('Invalid email').max(255, 'Email too long').toLowerCase().trim(),
    subject: z.string().min(5, 'Subject too short').max(200, 'Subject too long').trim(),
    message: z.string().min(10, 'Message too short').max(5000, 'Message too long').trim(),
    // Honeypot field - should always be empty from real users
    company: z.string().max(0, 'Invalid submission').optional(),
    // Turnstile token (optional - only required if configured)
    'cf-turnstile-response': z.string().optional(),
})


export async function POST(request: NextRequest) {
    // 1. Rate Limiting (Prevent Spam)
    const rateLimit = await applyRateLimit(request, 'write')
    if (!rateLimit.allowed && rateLimit.response) {
        return rateLimit.response
    }

    // 2. CSRF protection
    if (!validateOrigin(request)) {
        return NextResponse.json({ error: 'Invalid origin' }, { status: 403 })
    }

    try {
        const body = await request.json()

        // 3. Honeypot check - if 'company' field has value, it's likely a bot
        if (body.company && body.company.length > 0) {
            // Return fake success to not alert the bot
            console.log('[Security] Honeypot triggered, rejecting submission')
            return NextResponse.json({ success: true })
        }

        // 4. Turnstile verification (if configured)
        const turnstileToken = body['cf-turnstile-response']
        const isTurnstileValid = await verifyTurnstileToken(turnstileToken)
        if (!isTurnstileValid) {
            console.log('[Security] Turnstile verification failed')
            return NextResponse.json(
                { error: 'Security verification failed. Please try again.' },
                { status: 403 }
            )
        }

        // 5. Strict input validation
        const parseResult = contactSchema.safeParse(body)
        if (!parseResult.success) {
            const firstError = parseResult.error.issues[0]
            return NextResponse.json(
                { error: firstError?.message || 'Invalid input' },
                { status: 400 }
            )
        }

        const { name, email, subject, message } = parseResult.data

        let dbSuccess = false
        let emailSuccess = false
        const errors: string[] = []

        // 5. Try Database Insert
        try {
            // Use Service Role key if available to bypass RLS
            const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY
            const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL

            console.log(`[Contact] Service Role Key present: ${!!serviceRoleKey}`)

            let supabase

            if (serviceRoleKey && supabaseUrl) {
                supabase = createAdminClient(supabaseUrl, serviceRoleKey, {
                    auth: {
                        persistSession: false,
                        autoRefreshToken: false,
                    }
                })
            } else {
                console.log('[Contact] Using standard server client (Warning: RLS may block non-registered users)')
                supabase = await createServerClient()
            }

            const { error: dbError } = await supabase
                .from('contact_messages')
                .insert({
                    name,
                    email,
                    subject,
                    message,
                    status: 'new'
                })

            if (dbError) {
                console.error('[Contact] DB Error:', dbError)
                // Log full error for debugging
                console.error('[Contact] DB Error Details:', JSON.stringify(dbError, null, 2))
                errors.push(`DB Error: ${dbError.message}`)
            } else {
                console.log('[Contact] DB Insert Success')
                dbSuccess = true
            }
        } catch (err: any) {
            console.error('[Contact] DB Exception:', err)
            errors.push(`DB Exception: ${err.message}`)
        }

        // 6. Try Sending Email
        try {
            const adminEmail = process.env.CONTACT_EMAIL || 'admin@pluragate.org'
            const emailTemplate = emailTemplates.contactFormSubmission(name, email, subject, message)

            const emailSent = await sendEmail({
                to: adminEmail,
                subject: emailTemplate.subject,
                html: emailTemplate.html
            })

            if (!emailSent) {
                console.error('[Contact] Email failed to send (check previous logs)')
                errors.push('Email failed to send')
            } else {
                console.log('[Contact] Email Send Success')
                emailSuccess = true
            }
        } catch (err: any) {
            console.error('[Contact] Email Exception:', err)
            errors.push(`Email Exception: ${err.message}`)
        }

        // 7. Determine Response
        // Success if EITHER worked (we don't want to lose the message if one fails)
        if (dbSuccess || emailSuccess) {
            return NextResponse.json({
                success: true,
                warning: (!dbSuccess || !emailSuccess) ? 'Partial success' : null
            })
        } else {
            console.error('[Contact] All methods failed:', errors)
            return NextResponse.json(
                { error: 'Failed to process message', details: errors },
                { status: 500 }
            )
        }

    } catch (error) {
        console.error('[Contact] Unhandled API error:', error)
        return NextResponse.json(
            { error: 'Internal server error' },
            { status: 500 }
        )
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { withRateLimit } from '@/lib/rateLimit'

async function handleGet(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const postId = searchParams.get('id')
    const format = searchParams.get('format') || 'markdown'

    if (!postId) {
      return NextResponse.json({ error: 'Post ID is required' }, { status: 400 })
    }

    const supabase = await createClient()

    // Fetch the post with author
    const { data: post, error } = await supabase
      .from('posts')
      .select(`
        id,
        title,
        content,
        tags,
        created_at,
        updated_at,
        content_type,
        license,
        author:users!posts_author_id_fkey(name, email)
      `)
      .eq('id', postId)
      .single()

    if (error || !post) {
      return NextResponse.json({ error: 'Post not found' }, { status: 404 })
    }

    const authorName = (post.author as any)?.name || (post.author as any)?.email?.split('@')[0] || 'Anonymous'
    const publishedDate = new Date(post.created_at).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })

    if (format === 'markdown') {
      // Generate Markdown export
      const markdown = generateMarkdown(post, authorName, publishedDate)

      return new NextResponse(markdown, {
        status: 200,
        headers: {
          'Content-Type': 'text/markdown; charset=utf-8',
          'Content-Disposition': `attachment; filename="${sanitizeFilename(post.title)}.md"`,
        },
      })
    } else if (format === 'json') {
      // Generate JSON export
      const json = {
        title: post.title,
        author: authorName,
        content: post.content,
        tags: post.tags || [],
        publishedAt: post.created_at,
        updatedAt: post.updated_at,
        contentType: post.content_type,
        license: post.license,
        exportedAt: new Date().toISOString(),
      }

      return NextResponse.json(json, {
        headers: {
          'Content-Disposition': `attachment; filename="${sanitizeFilename(post.title)}.json"`,
        },
      })
    } else if (format === 'html') {
      // Generate HTML export
      const html = generateHTML(post, authorName, publishedDate)

      return new NextResponse(html, {
        status: 200,
        headers: {
          'Content-Type': 'text/html; charset=utf-8',
          'Content-Disposition': `attachment; filename="${sanitizeFilename(post.title)}.html"`,
        },
      })
    } else if (format === 'bibtex') {
      // Generate BibTeX export for academic references
      const bibtex = generateBibTeX(post, authorName, postId)

      return new NextResponse(bibtex, {
        status: 200,
        headers: {
          'Content-Type': 'application/x-bibtex; charset=utf-8',
          'Content-Disposition': `attachment; filename="${sanitizeFilename(post.title)}.bib"`,
        },
      })
    } else if (format === 'ris') {
      // Generate RIS export for reference managers
      const ris = generateRIS(post, authorName, postId)

      return new NextResponse(ris, {
        status: 200,
        headers: {
          'Content-Type': 'application/x-research-info-systems; charset=utf-8',
          'Content-Disposition': `attachment; filename="${sanitizeFilename(post.title)}.ris"`,
        },
      })
    }

    return NextResponse.json({ error: 'Invalid format. Use markdown, json, html, bibtex, or ris.' }, { status: 400 })
  } catch (error) {
    console.error('Export error:', error)
    return NextResponse.json({ error: 'Failed to export post' }, { status: 500 })
  }
}


function sanitizeFilename(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 50)
}

function generateMarkdown(post: any, authorName: string, publishedDate: string): string {
  const tags = post.tags?.length ? post.tags.map((t: string) => `#${t}`).join(' ') : ''

  return `---
title: "${post.title}"
author: "${authorName}"
date: "${publishedDate}"
type: "${post.content_type || 'article'}"
license: "${post.license || 'CC-BY-4.0'}"
tags: [${post.tags?.map((t: string) => `"${t}"`).join(', ') || ''}]
---

# ${post.title}

**Author:** ${authorName}  
**Published:** ${publishedDate}  
${tags ? `**Tags:** ${tags}` : ''}

---

${post.content}

---

*Exported from [SyriaHub](https://syriahub.com) on ${new Date().toLocaleDateString()}*
`
}

