// Generate mock analysis for testing without API key
function generateMockAnalysis(question: string): any {
    const questionLower = question.toLowerCase()

    // Basic heuristics for mock scoring
    const hasSpecificTerms = /how|what|why|when|where|which|who/i.test(question)
    const isLong = question.length > 50
    const hasQuestionMark = question.includes('?')
    const hasBiasWords = /best|worst|always|never|should|must|obviously/i.test(question)
    const isVague = /things|stuff|something|anything/i.test(question)

    let clarityScore = 50
    if (hasSpecificTerms) clarityScore += 15
    if (hasQuestionMark) clarityScore += 10
    if (isLong && !isVague) clarityScore += 10
    if (!isVague) clarityScore += 10
    if (!hasBiasWords) clarityScore += 5
    clarityScore = Math.min(100, clarityScore)

    let measurabilityScore = 40
    if (/measure|effect|impact|relationship|correlation|cause|result/i.test(question)) {
        measurabilityScore += 30
    }
    if (/how many|how much|what percent|rate|frequency/i.test(question)) {
        measurabilityScore += 20
    }
    measurabilityScore = Math.min(100, measurabilityScore)

    const scopeAssessment = question.length < 30 ? 'too_narrow' :
        question.length > 200 ? 'too_broad' : 'appropriate'

    const biases = []
    if (/best|worst/i.test(question)) biases.push('Superlative language suggests predetermined conclusions')
    if (/should/i.test(question)) biases.push('Prescriptive framing may limit objective analysis')
    if (/obviously|clearly/i.test(question)) biases.push('Assumption language indicates potential confirmation bias')

    return {
        clarity_score: clarityScore,
        scope_analysis: {
            assessment: scopeAssessment,
            explanation: scopeAssessment === 'appropriate'
                ? 'The scope of your question appears well-defined and researchable within typical constraints.'
                : scopeAssessment === 'too_broad'
                    ? 'Your question covers a wide scope. Consider narrowing down to specific variables, time periods, or populations.'
                    : 'Your question may be too specific. Consider broadening to ensure sufficient data availability.'
        },
        bias_detection: {
            has_bias: biases.length > 0,
            biases: biases
        },
        visibility: {
            score: measurabilityScore,
            explanation: measurabilityScore >= 70
                ? 'Your question includes measurable concepts that can be operationalized for research.'
                : 'Consider making your question more specific about what will be measured or observed.'
        },
        suggestions: [
            hasSpecificTerms ? 'Good use of interrogative words.' : 'Start with a clear interrogative (how, what, why).',
            hasQuestionMark ? '' : 'End your question with a question mark for clarity.',
            isVague ? 'Replace vague terms with specific concepts.' : '',
            hasBiasWords ? 'Consider using more neutral language.' : ''
        ].filter(Boolean),
        refined_versions: [
            `What is the relationship between ${extractKeyTerms(question)} in the context of ${getRandomContext()}?`,
            `How does ${extractKeyTerms(question)} affect ${getRandomOutcome()} among ${getRandomPopulation()}?`,
            `To what extent does ${extractKeyTerms(question)} influence ${getRandomOutcome()}?`
        ]
    }
}

function extractKeyTerms(question: string): string {
    const words = question.replace(/[?.,!]/g, '').split(' ')
    const stopWords = ['the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being', 'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could', 'should', 'may', 'might', 'can', 'how', 'what', 'why', 'when', 'where', 'which', 'who']
    const keywords = words.filter(w => w.length > 3 && !stopWords.includes(w.toLowerCase()))
    return keywords.slice(0, 3).join(' and ') || 'the studied variables'
}

function getRandomContext(): string {
    const contexts = ['modern organizations', 'educational settings', 'urban environments', 'developing economies', 'digital platforms']
    return contexts[Math.floor(Math.random() * contexts.length)]
}

function getRandomOutcome(): string {
    const outcomes = ['performance outcomes', 'behavioral patterns', 'decision-making processes', 'social dynamics', 'economic indicators']
    return outcomes[Math.floor(Math.random() * outcomes.length)]
}

function getRandomPopulation(): string {
    const populations = ['young adults', 'professionals', 'students', 'community members', 'stakeholders']
    return populations[Math.floor(Math.random() * populations.length)]
}

// Reports API - Update report status (moderators only)
import { NextResponse } from 'next/server'
import { createServerClient, verifyRole, getCurrentUser } from '@/lib/supabaseClient'
import {
  successResponse,
  errorResponse,
  handleSupabaseError,
  parseRequestBody,
  extractIdFromParams,
  withErrorHandling,
  notFoundResponse,
  validateOrigin,
} from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'
import type { ReportStatus } from '@/types'

interface UpdateReportInput {
  status: ReportStatus
  action?: 'delete_content' | 'warn_user' | 'none'
  notes?: string
}

/**
 * PUT /api/reports/[id]
 * Update report status (moderators and admins only)
 */
async function handleUpdateReport(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
): Promise<NextResponse> {
  // CSRF protection
  if (!validateOrigin(request)) {
    return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
  }

  const { id } = await params
  const reportId = extractIdFromParams({ id })
  
  // Verify user is moderator or admin
  const user = await verifyRole(['moderator', 'admin'])
  
  const supabase = await createServerClient()

  // Parse request body
  const body = await parseRequestBody<UpdateReportInput>(request)
  
  if (!body.status) {
    return errorResponse('Status is required', 422)
  }

  // Validate status value
  const validStatuses: ReportStatus[] = ['pending', 'reviewing', 'resolved', 'dismissed']
  if (!validStatuses.includes(body.status)) {
    return errorResponse('Invalid status value', 422)
  }

  // Check if report exists
  const { data: report, error: fetchError } = await supabase
    .from('reports')
    .select('*, post:posts(id, author_id), comment:comments(id, user_id)')
    .eq('id', reportId)
    .single()

  if (fetchError || !report) {
    if (fetchError?.code === 'PGRST116') {
      return notFoundResponse('Report not found')
    }
    return handleSupabaseError(fetchError)
  }

  // Handle actions if specified
  if (body.action === 'delete_content') {
    if (report.content_type === 'post' && report.post_id) {
      const { error: deleteError } = await supabase
        .from('posts')
        .delete()
        .eq('id', report.post_id)

      if (deleteError) {
        console.error('Failed to delete reported post:', deleteError)
      }
    } else if (report.content_type === 'comment' && report.comment_id) {
      const { error: deleteError } = await supabase
        .from('comments')
        .delete()
        .eq('id', report.comment_id)

      if (deleteError) {
        console.error('Failed to delete reported comment:', deleteError)
      }
    }
  }

  // Update report status
  const { data, error } = await supabase
    .from('reports')
    .update({
      status: body.status,
      reviewed_by: user.id,
      reviewed_at: new Date().toISOString(),
    })
    .eq('id', reportId)
    .select(`
      *,
      post:posts!reports_post_id_fkey(id, title),
      comment:comments!reports_comment_id_fkey(id, content),
      reporter:users!reports_reporter_id_fkey(id, name, email),
      reviewer:users!reports_reviewed_by_fkey(id, name, email)
    `)
    .single()

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse(data)
}

/**
 * DELETE /api/reports/[id]
 * Delete a report (moderators and admins only)
 */
async function handleDeleteReport(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
): Promise<NextResponse> {
  // CSRF protection
  if (!validateOrigin(request)) {
    return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
  }

  const { id } = await params
  const reportId = extractIdFromParams({ id })
  
  // Verify user is moderator or admin
  await verifyRole(['moderator', 'admin'])
  
  const supabase = await createServerClient()

  // Delete report
  const { error } = await supabase
    .from('reports')
    .delete()
    .eq('id', reportId)

  if (error) {
    if (error.code === 'PGRST116') {
      return notFoundResponse('Report not found')
    }
    return handleSupabaseError(error)
  }

  return successResponse({ message: 'Report deleted successfully' })
}

export const PUT = withRateLimit('write')(withErrorHandling(handleUpdateReport))
export const DELETE = withRateLimit('write')(withErrorHandling(handleDeleteReport))

// Reports API - Create and list reports
import { NextResponse } from 'next/server'
import { createServerClient, verifyAuth, isModerator } from '@/lib/supabaseClient'
import {
  successResponse,
  errorResponse,
  handleSupabaseError,
  parseRequestBody,
  validateRequiredFields,
  getQueryParams,
  withErrorHandling,
  forbiddenResponse,
  withOriginValidation,
} from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'
import type { CreateReportInput } from '@/types'

/**
 * GET /api/reports
 * List reports (moderators and admins only)
 * Query params: status, post_id, limit, offset
 */
async function handleGetReports(request: Request): Promise<NextResponse> {
  // Verify user is moderator or admin
  const user = await verifyAuth()
  
  if (!(await isModerator())) {
    return forbiddenResponse('Only moderators and admins can view reports')
  }

  const supabase = await createServerClient()
  const params = getQueryParams(request)
  
  // Get query parameters
  const status = params.get('status')
  const postId = params.get('post_id')
  const limit = parseInt(params.get('limit') || '20', 10)
  const offset = parseInt(params.get('offset') || '0', 10)

  // Build query
  let query = supabase
    .from('reports')
    .select(`
      *,
      post:posts!reports_post_id_fkey(id, title, content),
      reporter:users!reports_reporter_id_fkey(id, name, email)
    `)
    .order('created_at', { ascending: false })
    .range(offset, offset + limit - 1)

  // Apply filters
  if (status) {
    query = query.eq('status', status)
  }

  if (postId) {
    query = query.eq('post_id', postId)
  }

  const { data, error, count } = await query

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse({
    reports: data || [],
    pagination: {
      limit,
      offset,
      total: count || data?.length || 0,
    },
  })
}

/**
 * POST /api/reports
 * Create a new report (authenticated users only)
 */
async function handleCreateReport(request: Request): Promise<NextResponse> {
  // Verify authentication
  const user = await verifyAuth()

  const supabase = await createServerClient()
  
  // Parse request body
  const body = await parseRequestBody<CreateReportInput>(request)
  
  // Validate required fields
  validateRequiredFields(body, ['post_id', 'reason'])
  
  const { post_id, reason } = body

  // Validate reason length
  if (reason.length < 10) {
    return errorResponse('Report reason must be at least 10 characters', 422)
  }

  // Verify that the post exists
  const { data: post, error: postError } = await supabase
    .from('posts')
    .select('id')
    .eq('id', post_id)
    .single()

  if (postError || !post) {
    return errorResponse('Post not found', 404)
  }

  // Check if user already reported this post
  const { data: existingReport } = await supabase
    .from('reports')
    .select('id')
    .eq('post_id', post_id)
    .eq('reporter_id', user.id)
    .single()

  if (existingReport) {
    return errorResponse('You have already reported this post', 409)
  }

  // Create report
  const { data, error } = await supabase
    .from('reports')
    .insert({
      post_id,
      reporter_id: user.id,
      reason,
      status: 'pending',
    })
    .select(`
      *,
      post:posts!reports_post_id_fkey(id, title),
      reporter:users!reports_reporter_id_fkey(id, name, email)
    `)
    .single()

  if (error) {
    return handleSupabaseError(error)
  }

  return successResponse(data, 201)
}

export const GET = withErrorHandling(handleGetReports)
// SECURITY: Apply rate limiting (report type - stricter) and origin validation for CSRF
export const POST = withRateLimit('report')(withOriginValidation(withErrorHandling(handleCreateReport)))

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { validateOrigin } from '@/lib/apiUtils'
import { withRateLimit } from '@/lib/rateLimit'
import OpenAI from 'openai'

// Lazy-init: avoid crashing the build when OPENAI_API_KEY is not set
let _openai: OpenAI | null = null
function getOpenAI(): OpenAI {
    if (!_openai) {
        _openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })
    }
    return _openai
}

// ============================================
// POST: Semantic search with explainability
// ============================================
async function handlePost(request: NextRequest) {
    // CSRF protection - prevents cross-site abuse of OpenAI API calls
    if (!validateOrigin(request)) {
        return NextResponse.json({ error: 'Invalid request origin' }, { status: 403 })
    }

    const startTime = Date.now()

    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        const body = await request.json()
        const {
            query,
            filters = {},
            explain = true,
            limit = 20,
            offset = 0
        } = body

        if (!query || query.trim().length < 2) {
            return NextResponse.json({ error: 'Query must be at least 2 characters' }, { status: 400 })
        }

        // Generate embedding for query
        let queryEmbedding: number[] = []
        try {
            const embeddingResponse = await getOpenAI().embeddings.create({
                model: 'text-embedding-3-small',
                input: query.trim()
            })
            queryEmbedding = embeddingResponse.data[0].embedding
        } catch (embError) {
            console.error('Embedding error:', embError)
            // Fall back to text-based search
            return fallbackTextSearch(supabase, query, filters, limit, offset, startTime, user?.id)
        }

        // Extract filters
        const {
            disciplines,
            evidence_tiers,
            conflict_phase,
            min_trust_score = 0,
            primary_evidence_only = false
        } = filters

        // Call semantic search function
        const { data: searchResults, error: searchError } = await supabase.rpc('semantic_search', {
            p_query_embedding: `[${queryEmbedding.join(',')}]`,
            p_limit: limit,
            p_disciplines: disciplines || null,
            p_evidence_tiers: primary_evidence_only ? ['primary'] : (evidence_tiers || null),
            p_conflict_phase: conflict_phase || null,
            p_min_trust_score: min_trust_score
        })

        if (searchError) {
            console.error('Semantic search error:', searchError)
            return fallbackTextSearch(supabase, query, filters, limit, offset, startTime, user?.id)
        }

        // If semantic search returned no results (e.g., no embeddings in database), fall back to text search
        if (!searchResults || searchResults.length === 0) {
            return fallbackTextSearch(supabase, query, filters, limit, offset, startTime, user?.id)
        }

        // Enrich results with full data and explanations
        const enrichedResults = await Promise.all(
            (searchResults || []).map(async (result: {
                content_id: string
                content_type: string
                similarity: number
                evidence_tier: string
                trust_score: number
                final_score: number
            }) => {
                // Get content details
                let content: Record<string, unknown> | null = null
                if (result.content_type === 'post') {
                    const { data } = await supabase
                        .from('posts')
                        .select('id, title, content, tags, author_id, created_at, author:users!posts_author_id_fkey(name)')
                        .eq('id', result.content_id)
                        .single()
                    content = data
                }

                if (!content) return null

                // Get trust profile
                const { data: trustProfile } = await supabase
                    .from('trust_profiles')
                    .select('*')
                    .eq('content_id', result.content_id)
                    .eq('content_type', result.content_type)
                    .single()

                // Get linked resources
                const { data: linkedResources } = await supabase
                    .from('linked_resources')
                    .select('resource_type, title')
                    .eq('source_id', result.content_id)
                    .eq('source_type', result.content_type)
                    .limit(5)

                // Get contradictions
                const { data: contradictions } = await supabase
                    .from('content_relationships')
                    .select('source_id, source_type, relationship_detail')
                    .eq('target_id', result.content_id)
                    .eq('target_type', result.content_type)
                    .eq('relationship', 'contradicts')
                    .limit(3)

                // Build explanation
                const explanation = explain ? buildExplanation(
                    query,
                    content,
                    result,
                    trustProfile,
                    linkedResources || [],
                    contradictions || []
                ) : null

                return {
                    id: result.content_id,
                    type: result.content_type,
                    title: content.title as string,
                    snippet: truncateText(content.content as string, 200),
                    similarity_score: result.similarity,
                    final_score: result.final_score,
                    evidence_tier: result.evidence_tier,
                    trust_profile: trustProfile,
                    explanation,
                    linked_resources: (linkedResources || []).map((lr: { resource_type: string; title: string }) => ({
                        type: lr.resource_type,
                        title: lr.title,
                        connection: 'References'
                    })),
                    contradictions: (contradictions || []).map((c: { source_id: string; source_type: string; relationship_detail: string }) => ({
                        content_id: c.source_id,
                        content_type: c.source_type,
                        detail: c.relationship_detail
                    }))
                }
            })
        )

        // Filter out nulls
        const validResults = enrichedResults.filter(Boolean)

        // Create search session for analytics
        const searchDuration = Date.now() - startTime
        const { data: session } = await supabase
            .from('search_sessions')
            .insert({
                user_id: user?.id || null,
                query_text: query,
                disciplines: disciplines || [],
                evidence_tiers: evidence_tiers || [],
                conflict_phase: conflict_phase || null,
                result_count: validResults.length,
                top_result_id: validResults[0]?.id || null,
                search_duration_ms: searchDuration
            })
            .select('id')
            .single()

        return NextResponse.json({
            session_id: session?.id,
            results: validResults,
            total_count: validResults.length,
            search_duration_ms: searchDuration,
            query_disciplines: disciplines || []
        })
    } catch (error) {
        console.error('Research search error:', error)
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
    }
}

// Fallback to text search if embeddings fail
async function fallbackTextSearch(
    supabase: Awaited<ReturnType<typeof createClient>>,
    query: string,
    filters: Record<string, unknown>,
    limit: number,
    offset: number,
    startTime: number,
    userId?: string
) {
    // SECURITY: Escape LIKE pattern special characters to prevent pattern injection
    const sanitizedQuery = query.replace(/[%_\\]/g, '\\$&')
    const { data, error } = await supabase
        .from('posts')
        .select(`
      id, title, content, tags, created_at,
      author:users!posts_author_id_fkey(name)
    `)
        .or(`title.ilike.%${sanitizedQuery}%,content.ilike.%${sanitizedQuery}%`)
        .eq('status', 'published')
        .range(offset, offset + limit - 1)

    if (error) {
        return NextResponse.json({ error: 'Search failed' }, { status: 500 })
    }

    const results = (data || []).map((post: Record<string, unknown>) => ({
        id: post.id,
        type: 'post',
        title: post.title,
        snippet: truncateText(post.content as string, 200),
        similarity_score: null,
        final_score: null,
        evidence_tier: 'secondary',
        trust_profile: null,
        explanation: {
            match_reasons: [{ reason: `Text match for "${query}"`, weight: 1.0 }],
            supporting_evidence: [],
            credibility_score: 50,
            credibility_breakdown: {},
            data_gaps: [{ gap: 'Semantic search unavailable', severity: 'low' }],
            uncertainty_flags: []
        },
        linked_resources: [],
        contradictions: []
    }))

    return NextResponse.json({
        session_id: null,
        results,
        total_count: results.length,
        search_duration_ms: Date.now() - startTime,
        query_disciplines: [],
        fallback: true
    })
}

// Build explanation for a search result
function buildExplanation(
    query: string,
    content: Record<string, unknown>,
    result: { similarity: number; trust_score: number },
    trustProfile: Record<string, unknown> | null,
    linkedResources: { resource_type: string }[],
    contradictions: { relationship_detail: string }[]
) {
    const matchReasons = []
    const supportingEvidence = []
    const dataGaps = []
    const uncertaintyFlags = []

    // Query matching
    const title = (content.title as string || '').toLowerCase()
    const queryTerms = query.toLowerCase().split(' ')
    const matchedTerms = queryTerms.filter(term => title.includes(term))

    if (matchedTerms.length > 0) {
        matchReasons.push({
            reason: `Query terms "${matchedTerms.join(', ')}" found in title`,
            weight: 0.3
        })
    }

    matchReasons.push({
        reason: `Semantic similarity: ${(result.similarity * 100).toFixed(1)}%`,
        weight: 0.4
    })

    // Trust score contribution
    if (result.trust_score >= 70) {
        matchReasons.push({ reason: 'High trust profile', weight: 0.2 })
    } else if (result.trust_score >= 50) {
        matchReasons.push({ reason: 'Medium trust profile', weight: 0.1 })
    }

    // Linked resources
    if (linkedResources.length > 0) {
        const types = [...new Set(linkedResources.map(lr => lr.resource_type))]
        supportingEvidence.push({
            type: 'linked_resource',
            count: linkedResources.length,
            detail: `Linked to ${linkedResources.length} resources`,
            types
        })
    }

    // Data gaps
    if (!trustProfile) {
        dataGaps.push({ gap: 'No trust profile available', severity: 'medium' })
    } else {
        if (!(trustProfile as { t3_firsthand: boolean }).t3_firsthand) {
            dataGaps.push({ gap: 'No first-hand field verification', severity: 'medium' })
        }
        if ((trustProfile as { t4_is_time_sensitive: boolean }).t4_is_time_sensitive) {
            const timestamp = (trustProfile as { t4_data_timestamp: string }).t4_data_timestamp
            if (timestamp && new Date(timestamp) < new Date(Date.now() - 365 * 24 * 60 * 60 * 1000)) {
                dataGaps.push({ gap: 'Data may be outdated (over 1 year)', severity: 'medium' })
            }
        }
    }

    // Contradictions
    if (contradictions.length > 0) {
        uncertaintyFlags.push({
            flag: `Contradicted by ${contradictions.length} source(s)`,
            detail: contradictions[0]?.relationship_detail
        })
    }

    // Calculate credibility score
    const credibilityScore = Math.min(100, Math.max(0,
        (trustProfile ? Math.round(result.trust_score) : 50) +
        (linkedResources.length * 5) -
        (contradictions.length * 10) -
        (dataGaps.length * 5)
    ))

    return {
        match_reasons: matchReasons,
        supporting_evidence: supportingEvidence,
        credibility_score: credibilityScore,
        credibility_breakdown: trustProfile ? {
            source: (trustProfile as { t1_source_score: number }).t1_source_score,
            method: (trustProfile as { t2_method_score: number }).t2_method_score,
            proximity: (trustProfile as { t3_proximity_score: number }).t3_proximity_score,
            temporal: (trustProfile as { t4_temporal_score: number }).t4_temporal_score,
            validation: (trustProfile as { t5_validation_score: number }).t5_validation_score
        } : {},
        data_gaps: dataGaps,
        uncertainty_flags: uncertaintyFlags
    }
}

// Truncate text to specified length
function truncateText(text: string, maxLength: number): string {
    if (!text) return ''
    if (text.length <= maxLength) return text
    return text.substring(0, maxLength).trim() + '...'
}

