                    {/* Tags */}
                    {currentType !== 'user' && currentType !== 'group' && (
                        <div>
                            <h3 className="flex items-center gap-2 font-semibold mb-3 text-sm text-text dark:text-dark-text">
                                <TagIcon className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
