        </div>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import { ThumbsUp, ThumbsDown, Check, User as UserIcon } from 'lucide-react'
import { Post } from '@/types'
import { formatDistanceToNow } from 'date-fns'
import { cn } from '@/lib/utils'

interface AnswerCardProps {
    answer: Post
    userVote?: number // 1, -1, or undefined
    isQuestionAuthor: boolean
    onVote?: (value: 1 | -1) => void
    onAccept?: () => void
}

export function AnswerCard({ answer, userVote: initialUserVote, isQuestionAuthor, onVote, onAccept }: AnswerCardProps) {
    const [voteCount, setVoteCount] = useState(answer.vote_count || 0)
    const [userVote, setUserVote] = useState<number | undefined>(initialUserVote)
    const [isVoting, setIsVoting] = useState(false)
    const [isAccepting, setIsAccepting] = useState(false)

    const handleVote = async (value: 1 | -1) => {
        if (isVoting) return

        const previousVote = userVote
        const previousCount = voteCount

        let newVoteCount = voteCount
        if (userVote === value) {
            setUserVote(undefined)
            newVoteCount -= value
        } else {
            if (userVote) {
                newVoteCount -= userVote
            }
            setUserVote(value)
            newVoteCount += value
        }
        setVoteCount(newVoteCount)
        setIsVoting(true)

        try {
            const response = await fetch(`/api/posts/${answer.id}/vote`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value })
            })

            if (!response.ok) throw new Error('Vote failed')

            const data = await response.json()
            if (data.voteCount !== undefined) {
                setVoteCount(data.voteCount)
            }
        } catch (error) {
            setUserVote(previousVote)
            setVoteCount(previousCount)
            console.error('Failed to vote:', error)
        } finally {
            setIsVoting(false)
        }
    }

    const handleAccept = async () => {
        if (isAccepting || answer.is_accepted) return
        setIsAccepting(true)
        try {
            await onAccept?.()
        } finally {
            setIsAccepting(false)
        }
    }

    return (
        <div className={cn(
            "card transition-colors group relative",
            answer.is_accepted ? "border-green-500/50 bg-green-50/10 dark:bg-green-900/10" : "hover:border-primary/50"
        )}>
            <div className="p-6 flex gap-6">
                {/* Voting Side */}
                <div className="flex flex-col items-center gap-2 pt-1">
                    <button
                        onClick={() => handleVote(1)}
                        disabled={isVoting}
                        className={cn(
                            "p-1 rounded hover:bg-gray-100 dark:hover:bg-dark-surface-hover transition-colors",
                            userVote === 1 ? "text-primary" : "text-gray-400"
                        )}
                    >
                        <ThumbsUp className="w-5 h-5" />
                    </button>

                    <span className="font-bold text-lg text-text dark:text-dark-text">
                        {voteCount}
                    </span>

                    <button
                        onClick={() => handleVote(-1)}
                        disabled={isVoting}
                        className={cn(
                            "p-1 rounded hover:bg-gray-100 dark:hover:bg-dark-surface-hover transition-colors",
                            userVote === -1 ? "text-red-500" : "text-gray-400"
                        )}
                    >
                        <ThumbsDown className="w-5 h-5" />
                    </button>

                    {answer.is_accepted && (
                        <div className="mt-2 text-green-600 dark:text-green-400 flex flex-col items-center" title="Accepted Answer">
                            <Check className="w-6 h-6" />
                        </div>
                    )}
                </div>

                {/* Content Side */}
                <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted">
                            <Link
                                href={`/profile/${answer.author_id}`}
                                className="flex items-center gap-2 hover:text-primary dark:hover:text-accent-light transition-colors"
                            >
                                <UserIcon className="w-4 h-4" />
                                <span className="font-medium">
                                    {answer.author?.name || 'Anonymous'}
                                </span>
                            </Link>
                            <span>ΓÇó</span>
                            <span>{formatDistanceToNow(new Date(answer.created_at), { addSuffix: true })}</span>
                        </div>

                        {isQuestionAuthor && !answer.is_accepted && (
                            <button
                                onClick={handleAccept}
                                disabled={isAccepting}
                                className="text-xs font-medium px-3 py-1.5 rounded-full border border-gray-200 dark:border-dark-border hover:border-green-500 hover:text-green-600 dark:hover:text-green-400 transition-colors flex items-center gap-1"
                            >
                                <Check className="w-3 h-3" />
                                Accept Answer
                            </button>
                        )}
                    </div>

                    <div className="prose dark:prose-invert max-w-none text-text dark:text-dark-text">
                        <p className="whitespace-pre-wrap">{answer.content}</p>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { useToast } from './ui/toast'
import { Save } from 'lucide-react'

interface AnswerFormProps {
    questionId: string
}

export function AnswerForm({ questionId }: AnswerFormProps) {
    const [content, setContent] = useState('')
    const [submitting, setSubmitting] = useState(false)
    const { showToast } = useToast()
    const router = useRouter()
    const supabase = createClient()

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!content.trim()) return

        setSubmitting(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error('You must be logged in to answer')

            const { error } = await supabase
                .from('posts')
                .insert({
                    content: content.trim(),
                    content_type: 'answer',
                    parent_id: questionId,
                    author_id: user.id,
                    status: 'published',
                    title: 'Answer' // Required by schema but not used for answers usually
                })

            if (error) throw error

            setContent('')
            showToast('Answer posted successfully', 'success')
            router.refresh()
        } catch (error: any) {
            console.error('Failed to post answer:', error)
            showToast(error.message || 'Failed to post answer', 'error')
        } finally {
            setSubmitting(false)
        }
    }

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder="Write your answer here..."
                className="w-full min-h-[150px] p-4 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all resize-y"
                required
            />
            <div className="flex justify-end">
                <button
                    type="submit"
                    disabled={submitting || !content.trim()}
                    className="btn btn-primary flex items-center gap-2"
                >
                    <Save className="w-4 h-4" />
                    {submitting ? 'Posting...' : 'Post Answer'}
                </button>
            </div>
        </form>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { AnswerCard } from './AnswerCard'
import { Post } from '@/types'
import { useToast } from './ui/toast'

interface AnswerListProps {
    answers: Post[]
    isQuestionAuthor: boolean
}

export function AnswerList({ answers: initialAnswers, isQuestionAuthor }: AnswerListProps) {
    const [answers, setAnswers] = useState(initialAnswers)
    const { showToast } = useToast()
    const router = useRouter()

    const handleAccept = async (answerId: string) => {
        try {
            const response = await fetch(`/api/posts/${answerId}/accept`, {
                method: 'POST'
            })

            if (!response.ok) {
                const data = await response.json()
                throw new Error(data.error || 'Failed to accept answer')
            }

            // Update local state
            setAnswers(prev => prev.map(a => ({
                ...a,
                is_accepted: a.id === answerId
            })).sort((a, b) => (a.id === answerId ? -1 : 1))) // Move accepted to top

            showToast('Answer marked as accepted', 'success')
            router.refresh() // Refresh server data to ensure consistency
        } catch (error: any) {
            console.error('Accept error:', error)
            showToast(error.message, 'error')
        }
    }

    return (
        <div className="space-y-6">
            {answers.map(answer => (
                <AnswerCard
                    key={answer.id}
                    answer={answer}
                    isQuestionAuthor={isQuestionAuthor}
                    onAccept={() => handleAccept(answer.id)}
                />
            ))}
        </div>
    )
}

'use client'

import { useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Scale, Send, Loader2, CheckCircle, AlertCircle } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog'
import { useToast } from '@/components/ui/toast'


interface AppealButtonProps {
    postId: string
    postTitle?: string
    onAppealSubmitted?: () => void
}

/**
 * AppealButton allows authors of flagged posts to dispute the moderation decision.
 * Only visible when post is flagged and user is the author.
 */
export function AppealButton({ postId, postTitle, onAppealSubmitted }: AppealButtonProps) {
    const [isOpen, setIsOpen] = useState(false)
    const [reason, setReason] = useState('')
    const [submitting, setSubmitting] = useState(false)
    const [submitted, setSubmitted] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()


    async function handleSubmit() {
        if (!reason.trim()) {
            setError('Please provide a reason for your appeal.')
            return
        }

        if (reason.trim().length < 20) {
            setError('Please provide a more detailed explanation (at least 20 characters).')
            return
        }

        setSubmitting(true)
        setError(null)

        try {
            // Get current user
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                throw new Error('You must be logged in to submit an appeal.')
            }

            // Check if appeal already exists
            const { data: existingAppeal } = await supabase
                .from('moderation_appeals')
                .select(`
                    id, 
                    status,
                    deliberation:jury_deliberations(final_decision)
                `)
                .eq('post_id', postId)
                .eq('user_id', user.id)
                .single()

            if (existingAppeal) {
                if (existingAppeal.status === 'pending') {
                    throw new Error('You already have a pending appeal for this post.')
                } else if (existingAppeal.status === 'rejected') {
                    throw new Error('Your previous appeal was rejected. You cannot submit another appeal.')
                }
            }

            // Submit appeal
            const { error: insertError } = await supabase
                .from('moderation_appeals')
                .insert({
                    post_id: postId,
                    user_id: user.id,
                    dispute_reason: reason.trim()
                })

            if (insertError) throw insertError

            setSubmitted(true)
            showToast('Appeal submitted successfully!', 'success')
            onAppealSubmitted?.()

            // Close after a moment
            setTimeout(() => {
                setIsOpen(false)
                setSubmitted(false)
                setReason('')
            }, 2000)

        } catch (err: any) {
            setError(err.message || 'Failed to submit appeal. Please try again.')
        } finally {
            setSubmitting(false)
        }
    }

    return (
        <>
            <Button
                variant="outline"
                size="sm"
                onClick={() => setIsOpen(true)}
                className="gap-2 text-orange-600 dark:text-orange-400 border-orange-200 dark:border-orange-800 hover:bg-orange-50 dark:hover:bg-orange-900/20"
            >
                <Scale className="w-4 h-4" />
                Appeal Decision
            </Button>

            <Dialog open={isOpen} onOpenChange={setIsOpen}>
                <DialogContent className="max-w-lg">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Scale className="w-5 h-5 text-orange-500" />
                            Appeal Content Flag
                        </DialogTitle>
                        <DialogDescription>
                            Your post {postTitle && <span className="font-medium">&quot;{postTitle}&quot;</span>} has been flagged for review.
                            If you believe this was a mistake, you can submit an appeal.
                        </DialogDescription>
                    </DialogHeader>

                    {submitted ? (
                        <div className="py-8 text-center">
                            <CheckCircle className="w-12 h-12 text-green-500 mx-auto mb-4" />
                            <h3 className="font-semibold text-lg mb-2">Appeal Submitted!</h3>
                            <p className="text-sm text-text-light dark:text-dark-text-muted">
                                Our moderation team will review your appeal and respond shortly.
                            </p>
                        </div>
                    ) : (
                        <>
                            <div className="space-y-4 py-4">
                                <div>
                                    <label className="block text-sm font-medium mb-2">
                                        Why should this decision be reversed?
                                    </label>
                                    <textarea
                                        value={reason}
                                        onChange={(e) => {
                                            setReason(e.target.value)
                                            setError(null)
                                        }}
                                        placeholder="Please explain why you believe your content was incorrectly flagged. Be specific and provide context..."
                                        className="w-full h-32 px-3 py-2 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder:text-text-light dark:placeholder:text-dark-text-muted focus:outline-none focus:ring-2 focus:ring-primary resize-none"
                                        disabled={submitting}
                                    />
                                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-1">
                                        {reason.length}/500 characters
                                    </p>
                                </div>

                                {error && (
                                    <div className="flex items-start gap-2 p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 text-sm">
                                        <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
                                        <span>{error}</span>
                                    </div>
                                )}

                                <div className="p-3 rounded-lg bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
                                    <h4 className="font-medium text-sm text-blue-700 dark:text-blue-400 mb-1">
                                        What happens next?
                                    </h4>
                                    <ul className="text-xs text-blue-600 dark:text-blue-300 space-y-1">
                                        <li>ΓÇó Your appeal will be reviewed by our moderation team</li>
                                        <li>ΓÇó You&apos;ll receive a notification when a decision is made</li>
                                        <li>ΓÇó If approved, your content will be restored</li>
                                    </ul>
                                </div>
                            </div>

                            <DialogFooter>
                                <Button
                                    variant="outline"
                                    onClick={() => setIsOpen(false)}
                                    disabled={submitting}
                                >
                                    Cancel
                                </Button>
                                <Button
                                    onClick={handleSubmit}
                                    disabled={submitting || !reason.trim()}
                                    className="gap-2"
                                >
                                    {submitting ? (
                                        <>
                                            <Loader2 className="w-4 h-4 animate-spin" />
                                            Submitting...
                                        </>
                                    ) : (
                                        <>
                                            <Send className="w-4 h-4" />
                                            Submit Appeal
                                        </>
                                    )}
                                </Button>
                            </DialogFooter>
                        </>
                    )}
                </DialogContent>
            </Dialog>
        </>
    )
}

/**
 * Inline appeal status badge
 */
export function AppealStatus({ status, decision }: { status: 'pending' | 'approved' | 'rejected', decision?: string | null }) {
    const isSplit = status === 'rejected' && decision === 'split';

    const config = {
        pending: {
            label: 'Appeal Pending',
            className: 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400'
        },
        approved: {
            label: 'Appeal Approved',
            className: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400'
        },
        rejected: {
            label: isSplit ? 'Appeal Rejected (No Consensus)' : 'Appeal Rejected',
            className: 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400'
        }
    }

    const { label, className } = config[status]

    return (
        <span
            className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${className}`}
            title={isSplit ? 'The jury could not reach a majority consensus, so the original decision stands.' : undefined}
        >
            <Scale className="w-3 h-3" />
            {label}
        </span>
    )
}

import React from 'react';
import { Badge, UserBadge } from '@/types';
import { CheckCircle, Star, ShieldCheck, Award } from 'lucide-react';

interface BadgeDisplayProps {
    badges: UserBadge[];
    size?: 'sm' | 'md' | 'lg';
}

const BadgeDisplay: React.FC<BadgeDisplayProps> = ({ badges, size = 'md' }) => {
    if (!badges || badges.length === 0) return null;

    const getIcon = (iconName: string) => {
        switch (iconName) {
            case 'verified':
                return <ShieldCheck className={getSizeClass(size)} />;
            case 'star':
                return <Star className={getSizeClass(size)} />;
            case 'check_circle':
                return <CheckCircle className={getSizeClass(size)} />;
            default:
                return <Award className={getSizeClass(size)} />;
        }
    };

    const getSizeClass = (s: 'sm' | 'md' | 'lg') => {
        switch (s) {
            case 'sm': return 'w-4 h-4';
            case 'md': return 'w-6 h-6';
            case 'lg': return 'w-8 h-8';
            default: return 'w-6 h-6';
        }
    };

    return (
        <div className="flex flex-wrap gap-2">
            {badges.map((userBadge) => {
                const badge = userBadge.badge;
                if (!badge) return null;

                return (
                    <div
                        key={userBadge.id}
                        className="relative group cursor-help text-primary"
                        title={badge.description}
                    >
                        {getIcon(badge.icon_url)}
                        <span className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 text-xs text-white bg-gray-900 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-10">
                            {badge.name}: {badge.description}
                        </span>
                    </div>
                );
            })}
        </div>
    );
};

export default BadgeDisplay;

