    config: ChartConfig
    linkedResources: Resource[]
    onChange: (config: ChartConfig) => void
    onRemove: () => void
    isEditing?: boolean
}

export function ChartBlock({
    config,
    linkedResources,
    onChange,
    onRemove,
    isEditing = true
}: ChartBlockProps) {
    const t = useTranslations('Editor')
    const [chartData, setChartData] = useState<ChartData[]>([])
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [showSettings, setShowSettings] = useState(false)
    const [availableKeys, setAvailableKeys] = useState<string[]>([])

    // Filter to only show dataset resources
    const datasetResources = linkedResources.filter(
        r => r.metadata?.resource_type === 'dataset' ||
            r.metadata?.mime_type?.includes('json') ||
            r.metadata?.mime_type?.includes('csv')
    )

    const CHART_TYPES: { id: ChartType; label: string; icon: typeof BarChart3 }[] = [
        { id: 'bar', label: t('chart.types.bar') || 'Bar', icon: BarChart3 },
        { id: 'line', label: t('chart.types.line') || 'Line', icon: LineChart },
        { id: 'pie', label: t('chart.types.pie') || 'Pie', icon: PieChart },
        { id: 'area', label: t('chart.types.area') || 'Area', icon: AreaChart },
    ]

    const loadResourceData = useCallback(async () => {
        if (!config.resourceId) return

        const resource = linkedResources.find(r => r.id === config.resourceId)
        if (!resource?.metadata?.url) {
            setError('Resource URL not found')
            return
        }

        setLoading(true)
        setError(null)

        try {
            const response = await fetch(resource.metadata.url)
            const text = await response.text()

            let data: ChartData[] = []

            // Try parsing as JSON first
            if (resource.metadata.mime_type?.includes('json') || resource.metadata.url?.endsWith('.json')) {
                const json = JSON.parse(text)

                // Handle different JSON structures
                if (json.results && Array.isArray(json.results)) {
                    // Poll/Survey export format
                    data = json.results.map((item: { option: string; votes: number; percentage: number }) => ({
                        name: item.option,
                        value: item.votes,
                        percentage: item.percentage
                    }))
                } else if (json.responses && Array.isArray(json.responses)) {
                    // Survey responses - aggregate by question
                    // For now, show response count over time or first question stats
                    data = [{ name: 'Responses', value: json.responses.length }]
                } else if (Array.isArray(json)) {
                    // Direct array of objects
                    data = json.slice(0, 20).map((item: Record<string, unknown>, index: number) => {
                        const keys = Object.keys(item)
                        const nameKey = config.nameKey || keys.find(k => typeof item[k] === 'string') || 'name'
                        const valueKey = config.dataKey || keys.find(k => typeof item[k] === 'number') || 'value'

                        return {
                            name: String(item[nameKey] || `Item ${index + 1}`),
                            value: Number(item[valueKey]) || 0,
                            ...item as Record<string, string | number>
                        }
                    })

                    // Extract available keys for settings
                    if (json.length > 0) {
                        setAvailableKeys(Object.keys(json[0]))
                    }
                } else {
                    throw new Error('Unsupported JSON structure')
                }
            } else if (resource.metadata.mime_type?.includes('csv') || resource.metadata.url?.endsWith('.csv')) {
                // Parse CSV
                const lines = text.split('\n').filter(line => line.trim() && !line.startsWith('#'))
                if (lines.length < 2) {
                    throw new Error('CSV needs header and data rows')
                }

                const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''))
                setAvailableKeys(headers)

                const nameIndex = config.nameKey ? headers.indexOf(config.nameKey) : 0
                const valueIndex = config.dataKey ? headers.indexOf(config.dataKey) : 1

                data = lines.slice(1, 21).map((line, index) => {
                    const values = line.split(',').map(v => v.trim().replace(/^"|"$/g, ''))
                    return {
                        name: values[nameIndex] || `Row ${index + 1}`,
                        value: parseFloat(values[valueIndex]) || 0
                    }
                })
            } else {
                throw new Error('Unsupported file format')
            }

            setChartData(data)
        } catch (err) {
            console.error('Error loading chart data:', err)
            setError(err instanceof Error ? err.message : 'Failed to load data')
        } finally {
            setLoading(false)
        }
    }, [config.resourceId, config.nameKey, config.dataKey, linkedResources])

    useEffect(() => {
        if (config.resourceId) {
            loadResourceData()
        }
    }, [config.resourceId, loadResourceData])

    const renderChart = () => {
        if (chartData.length === 0) {
            return (
                <div className="h-full flex items-center justify-center text-text-light dark:text-dark-text-muted">
                    <Database className="w-8 h-8 mr-2 opacity-50" />
                    <span>{t('chart.noData') || 'No data to display'}</span>
                </div>
            )
        }

        switch (config.chartType) {
            case 'line':
                return (
                    <RechartsLine data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
                        <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                        <YAxis tick={{ fontSize: 12 }} />
                        <Tooltip />
                        {config.showLegend && <Legend />}
                        <Line type="monotone" dataKey="value" stroke="#6366F1" strokeWidth={2} dot={{ fill: '#6366F1' }} />
                    </RechartsLine>
                )
            case 'pie':
                return (
                    <RechartsPie data={chartData}>
                        <Pie
                            data={chartData}
                            dataKey="value"
                            nameKey="name"
                            cx="50%"
                            cy="50%"
                            outerRadius={80}
                            label={({ name, percent }) => `${name} (${((percent ?? 0) * 100).toFixed(0)}%)`}
                        >
                            {chartData.map((_, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <Tooltip />
                        {config.showLegend && <Legend />}
                    </RechartsPie>
                )
            case 'area':
                return (
                    <RechartsArea data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
                        <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                        <YAxis tick={{ fontSize: 12 }} />
                        <Tooltip />
                        {config.showLegend && <Legend />}
                        <Area type="monotone" dataKey="value" stroke="#10B981" fill="#10B98133" />
                    </RechartsArea>
                )
            case 'bar':
            default:
                return (
                    <RechartsBar data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
                        <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                        <YAxis tick={{ fontSize: 12 }} />
                        <Tooltip />
                        {config.showLegend && <Legend />}
                        <Bar dataKey="value" fill="#6366F1" radius={[4, 4, 0, 0]}>
                            {chartData.map((_, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Bar>
                    </RechartsBar>
                )
        }
    }

    // If no resource is selected, show the selector
    if (!config.resourceId) {
        return (
            <div className="border-2 border-dashed border-gray-200 dark:border-dark-border rounded-xl p-6">
                <div className="text-center">
                    <BarChart3 className="w-12 h-12 mx-auto text-gray-300 dark:text-dark-text-muted mb-3" />
                    <h3 className="font-medium text-text dark:text-dark-text mb-2">
                        {t('chart.selectResource') || 'Select a Dataset'}
                    </h3>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                        {t('chart.selectResourceDesc') || 'Choose a linked dataset resource to visualize'}
                    </p>

                    {datasetResources.length === 0 ? (
                        <p className="text-sm text-amber-600 dark:text-amber-400">
                            {t('chart.noDatasets') || 'No dataset resources linked. Link a dataset first in the Resources section above.'}
                        </p>
                    ) : (
                        <div className="space-y-2 max-w-md mx-auto">
                            {datasetResources.map(resource => (
                                <button
                                    key={resource.id}
                                    onClick={() => onChange({
                                        ...config,
                                        resourceId: resource.id,
                                        resourceTitle: resource.title
                                    })}
                                    className="w-full flex items-center gap-3 p-3 text-left border border-gray-200 dark:border-dark-border rounded-lg hover:border-primary hover:bg-primary/5 transition-colors"
                                >
                                    <Database className="w-5 h-5 text-emerald-500" />
                                    <div className="flex-1 min-w-0">
                                        <p className="font-medium text-text dark:text-dark-text truncate">
                                            {resource.title}
                                        </p>
                                        <p className="text-xs text-text-light dark:text-dark-text-muted">
                                            {resource.metadata?.source_type === 'poll' ? 'Poll Results' :
                                                resource.metadata?.source_type === 'survey' ? 'Survey Results' : 'Dataset'}
                                        </p>
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}

                    {isEditing && (
                        <button
                            onClick={onRemove}
                            className="mt-4 text-sm text-text-light hover:text-error transition-colors"
                        >
                            {t('chart.removeBlock') || 'Remove Chart Block'}
                        </button>
                    )}
                </div>
            </div>
        )
    }

    return (
        <div className="border border-gray-200 dark:border-dark-border rounded-xl overflow-hidden bg-white dark:bg-dark-surface">
            {/* Header */}
            <div className="px-4 py-3 border-b border-gray-200 dark:border-dark-border flex items-center justify-between bg-gray-50 dark:bg-dark-bg">
                <div className="flex items-center gap-2">
                    <BarChart3 className="w-4 h-4 text-primary" />
                    <span className="font-medium text-sm text-text dark:text-dark-text">
                        {config.title || config.resourceTitle}
                    </span>
                </div>

                {isEditing && (
                    <div className="flex items-center gap-1">
                        <button
                            onClick={loadResourceData}
                            className="p-1.5 text-text-light hover:text-text dark:hover:text-dark-text transition-colors"
                            title="Refresh data"
                        >
                            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                        </button>
                        <button
                            onClick={() => setShowSettings(!showSettings)}
                            className="p-1.5 text-text-light hover:text-text dark:hover:text-dark-text transition-colors"
                            title="Chart settings"
                        >
                            <Settings className="w-4 h-4" />
                        </button>
                        <button
                            onClick={onRemove}
                            className="p-1.5 text-text-light hover:text-error transition-colors"
                            title="Remove chart"
                        >
                            <X className="w-4 h-4" />
                        </button>
                    </div>
                )}
            </div>

            {/* Settings Panel */}
            {showSettings && isEditing && (
                <div className="px-4 py-3 border-b border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg space-y-3">
                    <div className="flex items-center gap-4 flex-wrap">
                        <div>
                            <label className="block text-xs text-text-light dark:text-dark-text-muted mb-1">
                                {t('chart.chartType') || 'Chart Type'}
                            </label>
                            <div className="flex gap-1">
                                {CHART_TYPES.map(type => (
                                    <button
                                        key={type.id}
                                        onClick={() => onChange({ ...config, chartType: type.id })}
                                        className={`p-2 rounded-lg transition-colors ${config.chartType === type.id
                                                ? 'bg-primary text-white'
                                                : 'bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border text-text-light hover:border-primary'
                                            }`}
                                        title={type.label}
                                    >
                                        <type.icon className="w-4 h-4" />
                                    </button>
                                ))}
                            </div>
                        </div>

                        {availableKeys.length > 0 && (
                            <>
                                <div>
                                    <label className="block text-xs text-text-light dark:text-dark-text-muted mb-1">
                                        {t('chart.nameColumn') || 'Name Column'}
                                    </label>
                                    <select
                                        value={config.nameKey || ''}
                                        onChange={(e) => onChange({ ...config, nameKey: e.target.value })}
                                        className="select-input"
                                    >
                                        <option value="">Auto</option>
                                        {availableKeys.map(key => (
                                            <option key={key} value={key}>{key}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs text-text-light dark:text-dark-text-muted mb-1">
                                        {t('chart.valueColumn') || 'Value Column'}
                                    </label>
                                    <select
                                        value={config.dataKey || ''}
                                        onChange={(e) => onChange({ ...config, dataKey: e.target.value })}
                                        className="select-input"
                                    >
                                        <option value="">Auto</option>
                                        {availableKeys.map(key => (
                                            <option key={key} value={key}>{key}</option>
                                        ))}
                                    </select>
                                </div>
                            </>
                        )}

                        <div>
                            <label className="block text-xs text-text-light dark:text-dark-text-muted mb-1">
                                {t('chart.chartTitle') || 'Chart Title'}
                            </label>
                            <input
                                type="text"
                                value={config.title || ''}
                                onChange={(e) => onChange({ ...config, title: e.target.value })}
                                placeholder={config.resourceTitle}
                                className="input input-sm w-40"
                            />
                        </div>

                        <label className="flex items-center gap-2 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={config.showLegend || false}
                                onChange={(e) => onChange({ ...config, showLegend: e.target.checked })}
                                className="rounded border-gray-300"
                            />
                            <span className="text-sm text-text dark:text-dark-text">
                                {t('chart.showLegend') || 'Show Legend'}
                            </span>
                        </label>
                    </div>

                    <button
                        onClick={() => onChange({
                            ...config,
                            resourceId: '',
                            resourceTitle: ''
                        })}
                        className="text-sm text-text-light hover:text-primary transition-colors"
                    >
                        {t('chart.changeDataset') || 'Change Dataset'}
                    </button>
                </div>
            )}

            {/* Chart Area */}
            <div className="p-4">
                {loading ? (
                    <div className="h-64 flex items-center justify-center">
                        <Loader2 className="w-8 h-8 animate-spin text-primary" />
                    </div>
                ) : error ? (
                    <div className="h-64 flex items-center justify-center text-error">
                        <AlertCircle className="w-6 h-6 mr-2" />
                        <span>{error}</span>
                    </div>
                ) : (
                    <div className="h-64">
                        <ResponsiveContainer width="100%" height="100%">
                            {renderChart()}
                        </ResponsiveContainer>
                    </div>
                )}
            </div>
        </div>
    )
}

// Read-only version for post display
export function ChartBlockDisplay({ config, resourceUrl }: { config: ChartConfig; resourceUrl?: string }) {
    const [chartData, setChartData] = useState<ChartData[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        if (!resourceUrl) {
            setError('Resource not found')
            setLoading(false)
            return
        }

        const loadData = async () => {
            try {
                const response = await fetch(resourceUrl)
                const text = await response.text()

                let data: ChartData[] = []

                if (resourceUrl.endsWith('.json')) {
                    const json = JSON.parse(text)
                    if (json.results && Array.isArray(json.results)) {
                        data = json.results.map((item: { option: string; votes: number }) => ({
                            name: item.option,
                            value: item.votes
                        }))
                    } else if (Array.isArray(json)) {
                        data = json.slice(0, 20).map((item: Record<string, unknown>, index: number) => ({
                            name: String(item[config.nameKey || 'name'] || `Item ${index + 1}`),
                            value: Number(item[config.dataKey || 'value']) || 0
                        }))
                    }
                }

                setChartData(data)
            } catch (err) {
                setError('Failed to load chart data')
            } finally {
                setLoading(false)
            }
        }

        loadData()
    }, [resourceUrl, config.nameKey, config.dataKey])

    const renderChart = () => {
        if (chartData.length === 0) return null

        const ChartComponent = {
            line: RechartsLine,
            pie: RechartsPie,
            area: RechartsArea,
            bar: RechartsBar
        }[config.chartType] || RechartsBar

        if (config.chartType === 'pie') {
            return (
                <RechartsPie data={chartData}>
                    <Pie
                        data={chartData}
                        dataKey="value"
                        nameKey="name"
                        cx="50%"
                        cy="50%"
                        outerRadius={80}
                        label
                    >
                        {chartData.map((_, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip />
                    {config.showLegend && <Legend />}
                </RechartsPie>
            )
        }

        return (
            <RechartsBar data={chartData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                {config.showLegend && <Legend />}
                <Bar dataKey="value" fill="#6366F1">
                    {chartData.map((_, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                </Bar>
            </RechartsBar>
        )
    }

    if (loading) {
        return (
            <div className="h-64 flex items-center justify-center bg-gray-50 dark:bg-dark-bg rounded-xl">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    if (error) {
        return (
            <div className="h-64 flex items-center justify-center bg-gray-50 dark:bg-dark-bg rounded-xl text-error">
                <AlertCircle className="w-6 h-6 mr-2" />
                <span>{error}</span>
            </div>
        )
    }

    return (
        <div className="border border-gray-200 dark:border-dark-border rounded-xl overflow-hidden bg-white dark:bg-dark-surface my-4">
            {config.title && (
                <div className="px-4 py-3 border-b border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg">
                    <div className="flex items-center gap-2">
                        <BarChart3 className="w-4 h-4 text-primary" />
                        <span className="font-medium text-sm text-text dark:text-dark-text">
                            {config.title}
                        </span>
                    </div>
                </div>
            )}
            <div className="p-4 h-64">
                <ResponsiveContainer width="100%" height="100%">
                    {renderChart()}
                </ResponsiveContainer>
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { Link } from '@/navigation'
import { createClient } from '@/lib/supabase/client'
import { Link2, ArrowRight, X, ChevronDown, ChevronUp, MoreHorizontal } from 'lucide-react'
import { useTranslations } from 'next-intl'
import { cn } from '@/lib/utils'

interface RelatedPost {
    id: string
    title: string
    tags: string[]
    discipline: string
    connectionType: 'citation' | 'tag-overlap' | 'fork'
    contentType?: string
}

interface CitationContextBarProps {
    postId: string
    currentTags?: string[]
}

export function CitationContextBar({ postId, currentTags = [] }: CitationContextBarProps) {
    const [relatedPosts, setRelatedPosts] = useState<RelatedPost[]>([])
    const [tagColors, setTagColors] = useState<Record<string, string>>({})
    const [isExpanded, setIsExpanded] = useState(false) // Collapsed by default
    const [showAll, setShowAll] = useState(false)
    const [isVisible, setIsVisible] = useState(true)
    const [loading, setLoading] = useState(true)
    const [animatedTextIndex, setAnimatedTextIndex] = useState(0)
    const supabase = useMemo(() => createClient(), [])
    const t = useTranslations('Post')

    // Animated text cycling
    useEffect(() => {
        if (relatedPosts.length === 0 || isExpanded) return

        const interval = setInterval(() => {
            setAnimatedTextIndex((prev) => (prev + 1) % 2)
        }, 3000) // Switch every 3 seconds

        return () => clearInterval(interval)
    }, [relatedPosts.length, isExpanded])

    useEffect(() => {
        async function fetchRelatedContent() {
            try {
                // Fetch tag colors first
                const { data: tags } = await supabase.from('tags').select('label, color')
                if (tags) {
                    const colors: Record<string, string> = {}
                    tags.forEach((tag: any) => {
                        colors[tag.label] = tag.color
                    })
                    setTagColors(colors)
                }

                const related: RelatedPost[] = []

                // 1. Fetch citations (posts that cite or are cited by this post)
                const { data: citationsOut } = await supabase
                    .from('citations')
                    .select(`
            target_post_id,
            posts!citations_target_post_id_fkey(id, title, tags, content_type)
          `)
                    .eq('source_post_id', postId)
                    .limit(3)

                citationsOut?.forEach((c: any) => {
                    if (c.posts) {
                        related.push({
                            id: c.posts.id,
                            title: c.posts.title,
                            tags: c.posts.tags || [],
                            discipline: c.posts.tags?.[0] || 'Research',
                            connectionType: 'citation',
                            contentType: c.posts.content_type
                        })
                    }
                })

                const { data: citationsIn } = await supabase
                    .from('citations')
                    .select(`
            source_post_id,
            posts!citations_source_post_id_fkey(id, title, tags, content_type)
          `)
                    .eq('target_post_id', postId)
                    .limit(3)

                citationsIn?.forEach((c: any) => {
                    if (c.posts && !related.find(r => r.id === c.posts.id)) {
                        related.push({
                            id: c.posts.id,
                            title: c.posts.title,
                            tags: c.posts.tags || [],
                            discipline: c.posts.tags?.[0] || 'Research',
                            connectionType: 'citation',
                            contentType: c.posts.content_type
                        })
                    }
                })

                // 2. Fetch posts with overlapping tags (cross-disciplinary)
                if (currentTags.length > 0) {
                    const { data: tagOverlap } = await supabase
                        .from('posts')
                        .select('id, title, tags, content_type')
                        .neq('id', postId)
                        .overlaps('tags', currentTags)
                        .limit(5)

                    tagOverlap?.forEach((post: any) => {
                        if (!related.find(r => r.id === post.id)) {
                            // Find the first tag that's different from the current post's primary tag
                            const crossDiscipline = post.tags?.find(
                                (t: string) => currentTags[0] && t !== currentTags[0]
                            ) || post.tags?.[0]

                            related.push({
                                id: post.id,
                                title: post.title,
                                tags: post.tags || [],
                                discipline: crossDiscipline || 'Research',
                                connectionType: 'tag-overlap',
                                contentType: post.content_type
                            })
                        }
                    })
                }

                // 3. Fetch forks
                const { data: forks } = await supabase
                    .from('posts')
                    .select('id, title, tags, content_type')
                    .eq('forked_from_id', postId)
                    .limit(2)

                forks?.forEach((fork: any) => {
                    if (!related.find(r => r.id === fork.id)) {
                        related.push({
                            id: fork.id,
                            title: fork.title,
                            tags: fork.tags || [],
                            discipline: fork.tags?.[0] || 'Research',
                            connectionType: 'fork',
                            contentType: fork.content_type
                        })
                    }
                })

                setRelatedPosts(related.slice(0, 10)) // Keep more for "View more"
            } catch (error) {
                console.error('Error fetching related content:', error)
            } finally {
                setLoading(false)
            }
        }

        fetchRelatedContent()
    }, [postId, currentTags, supabase])

    if (!isVisible || loading || relatedPosts.length === 0) {
        return null
    }

    const getConnectionLabel = (type: string) => {
        switch (type) {
            case 'citation': return t('cites') // Check if 'cites' exists or add it
            case 'tag-overlap': return t('relatedTo')
            case 'fork': return t('inspired') // Check if 'inspired' exists or add it
            default: return t('connectsTo') // Check if 'connectsTo' exists or add it
        }
    }

    // Group by discipline for cross-disciplinary display
    const disciplineGroups = relatedPosts.reduce((acc, post) => {
        const discipline = post.discipline
        if (!acc[discipline]) {
            acc[discipline] = []
        }
        acc[discipline].push(post)
        return acc
    }, {} as Record<string, RelatedPost[]>)

    const disciplineCount = Object.keys(disciplineGroups).length
    const firstPostTitle = relatedPosts[0]?.title || 'Related content'

    // Animated text options
    const animatedTexts = [
        t('connectionsAcross', { count: relatedPosts.length, disciplines: disciplineCount }),
        `${t('relatedTo')}: ${firstPostTitle.length > 40 ? firstPostTitle.slice(0, 37) + '...' : firstPostTitle}`
    ]

    // Limit displayed items based on showAll state
    const displayLimit = showAll ? Object.keys(disciplineGroups).length : 3
    const visibleDisciplineEntries = Object.entries(disciplineGroups).slice(0, displayLimit)
    const hasMore = Object.keys(disciplineGroups).length > 3

    return (
        <div className="fixed bottom-8 z-40 left-4 right-28 md:left-0 md:right-0 md:px-6 mx-auto max-w-4xl">
            <style>{`
                @media (max-width: 768px) {
                    .global-fab {
                        bottom: 2rem !important;
                    }
                }
            `}</style>
            <div className="bg-white/95 dark:bg-dark-surface/95 backdrop-blur-xl rounded-2xl border border-gray-200 dark:border-dark-border shadow-soft-lg overflow-hidden">
                {/* Header */}
                <div
                    className="flex items-center justify-between px-4 py-3 cursor-pointer hover:bg-gray-50 dark:hover:bg-dark-bg/50 transition-colors"
                    onClick={() => setIsExpanded(!isExpanded)}
                >
                    <div className="flex items-center gap-3 flex-1 min-w-0">
                        <div className="p-1.5 rounded-lg bg-primary/10 flex-shrink-0">
                            <Link2 className="w-4 h-4 text-primary" />
                        </div>
                        <span className="text-sm font-semibold text-text dark:text-dark-text whitespace-nowrap">
                            {t('contextualThreads')}
                        </span>
                        {/* Animated text with fixed width and horizontal scroll for long text */}
                        <div className="relative overflow-hidden flex-1 min-w-0 h-5">
                            <div
                                className="absolute inset-0 flex items-center whitespace-nowrap animate-fade-in"
                                key={animatedTextIndex}
                            >
                                <span
                                    className={`text-xs text-text-light dark:text-gray-400 ${animatedTexts[animatedTextIndex].length > 45 ? 'animate-marquee' : ''}`}
                                >
                                    {animatedTexts[animatedTextIndex]}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={(e) => {
                                e.stopPropagation()
                                setIsVisible(false)
                            }}
                            className="p-1 rounded-lg hover:bg-gray-200 dark:hover:bg-dark-border transition-colors"
                            aria-label="Close"
                        >
                            <X className="w-4 h-4 text-text-light dark:text-gray-400" />
                        </button>
                        {isExpanded ? (
                            <ChevronDown className="w-4 h-4 text-text-light dark:text-gray-400" />
                        ) : (
                            <ChevronUp className="w-4 h-4 text-text-light dark:text-gray-400" />
                        )}
                    </div>
                </div>

                {/* Content - Progressive Disclosure */}
                {
                    isExpanded && (
                        <div className="px-4 pb-4 space-y-3 max-h-[60vh] overflow-y-auto custom-scrollbar">
                            {visibleDisciplineEntries.map(([discipline, posts]) => (
                                <div key={discipline} className="flex flex-col md:flex-row items-start gap-2 md:gap-3 p-2 rounded-lg hover:bg-gray-50 dark:hover:bg-dark-bg/30 transition-colors">
                                    {/* Discipline Badge */}
                                    <span
                                        className="px-2 py-0.5 rounded-full text-xs font-medium whitespace-nowrap min-w-fit text-white"
                                        style={{ backgroundColor: tagColors[discipline] || '#6B7280' }}
                                    >
                                        {discipline}
                                    </span>

                                    <div className="flex-1 min-w-0 space-y-1 w-full">
                                        {posts.map((post) => (
                                            <Link
                                                key={post.id}
                                                href={post.contentType === 'resource' ? `/resources/${post.id}` : `/post/${post.id}`}
                                                className="block group"
                                            >
                                                <span className="text-sm font-medium text-text dark:text-dark-text truncate group-hover:text-primary dark:group-hover:text-accent-light transition-colors">
                                                    {post.title}
                                                </span>
                                            </Link>
                                        ))}
                                    </div>

                                    <ArrowRight className="w-4 h-4 text-text-light dark:text-dark-text-muted flex-shrink-0" />
                                </div>
                            ))}

                            {/* View More Button */}
                            {hasMore && !showAll && (
                                <button
                                    onClick={() => setShowAll(true)}
                                    className="flex items-center gap-2 text-sm text-primary hover:text-primary-dark transition-colors mx-auto"
                                >
                                    <MoreHorizontal className="w-4 h-4" />
                                    {t('viewAllDisciplines', { count: Object.keys(disciplineGroups).length })}
                                </button>
                            )}

                            {/* Collapse button when expanded */}
                            {showAll && hasMore && (
                                <button
                                    onClick={() => setShowAll(false)}
                                    className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted hover:text-text transition-colors mx-auto"
                                >
                                    <ChevronUp className="w-4 h-4" />
                                    {t('showLess')}
                                </button>
                            )}
                        </div>
                    )
                }
            </div >
        </div >
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Quote, Copy, Check, FileEdit, ChevronDown } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { useToast } from '@/components/ui/toast'
import { useTranslations } from 'next-intl'
import { generateCitation, CitationFormat } from '@/lib/citations'

interface CiteButtonProps {
    postId: string
    postTitle: string
    postAuthor?: {
        name?: string | null
        email?: string | null
        affiliation?: string | null
    } | null
    postCreatedAt?: string
    postContent?: string
    postTags?: string[]
}

interface Draft {
    id: string
    title: string
    updated_at: string
}

export function CiteButton({
    postId,
    postTitle,
    postAuthor,
    postCreatedAt,
    postContent,
    postTags
}: CiteButtonProps) {
    const [drafts, setDrafts] = useState<Draft[]>([])
    const [loadingDrafts, setLoadingDrafts] = useState(false)
    const [showCopyCitation, setShowCopyCitation] = useState(false)
    const [copiedFormat, setCopiedFormat] = useState<string | null>(null)
    const supabase = useMemo(() => createClient(), [])
    const router = useRouter()
    const { showToast } = useToast()
    const t = useTranslations('Post')

    // Fetch user's active drafts
    useEffect(() => {
        async function fetchDrafts() {
            setLoadingDrafts(true)
            try {
                const { data: { user } } = await supabase.auth.getUser()
                if (!user) return

                const { data } = await supabase
                    .from('posts')
                    .select('id, title, updated_at')
                    .eq('author_id', user.id)
                    .eq('status', 'draft')
                    .order('updated_at', { ascending: false })
                    .limit(5)

                setDrafts(data || [])
            } catch (error) {
                console.error('Error fetching drafts:', error)
            } finally {
                setLoadingDrafts(false)
            }
        }

        fetchDrafts()
    }, [supabase])

    // Add citation to a specific draft
    const addToDraft = async (draftId: string) => {
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                showToast('Please sign in to add citations', 'error')
                return
            }

            // Create citation linking draft to this post
            const { error } = await supabase
                .from('citations')
                .insert({
                    source_post_id: draftId,
                    target_post_id: postId,
                    type: 'internal',
                    created_by: user.id,
                })

            if (error) {
                if (error.code === '23505') { // Unique violation
                    showToast('This reference is already in your draft', 'warning')
                } else {
                    throw error
                }
                return
            }

            showToast(`Added reference to your draft`, 'success')
            router.push(`/editor?id=${draftId}`)
        } catch (error: any) {
            console.error('Error adding citation:', JSON.stringify(error, Object.getOwnPropertyNames(error), 2))
            showToast('Failed to add reference', 'error')
        }
    }

    // Generate citation data for export
    const citationData = {
        id: postId,
        title: postTitle,
        author: {
            name: postAuthor?.name || undefined,
            email: postAuthor?.email || undefined,
            affiliation: postAuthor?.affiliation || undefined,
        },
        content: postContent,
        tags: postTags,
        created_at: postCreatedAt || new Date().toISOString(),
        url: typeof window !== 'undefined' ? `${window.location.origin}/post/${postId}` : undefined,
    }

    // Copy citation in specific format
    const copyCitation = (format: CitationFormat) => {
        try {
            const citation = generateCitation(citationData, format)
            navigator.clipboard.writeText(citation)
            setCopiedFormat(format)
            setTimeout(() => setCopiedFormat(null), 2000)
            showToast(`${format.toUpperCase()} citation copied`, 'success')
        } catch (error) {
            console.error('Error copying citation:', error)
            showToast('Failed to copy citation', 'error')
        }
    }

    return (
        <>
            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button variant="outline" size="sm" className="gap-2">
                        <Quote className="w-4 h-4" />
                        {t('citeThis')}
                        <ChevronDown className="w-3 h-3 opacity-60" />
                    </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="start" className="w-64">
                    {/* Add to Draft Section */}
                    {drafts.length > 0 && (
                        <>
                            <div className="px-2 py-1.5 text-xs font-semibold text-text-light dark:text-dark-text-muted">
                                {t('addReference')}
                            </div>
                            {drafts.map((draft) => (
                                <DropdownMenuItem
                                    key={draft.id}
                                    onClick={() => addToDraft(draft.id)}
                                    className="cursor-pointer"
                                >
                                    <FileEdit className="w-4 h-4 mr-2 text-primary" />
                                    <span className="truncate">{draft.title || 'Untitled draft'}</span>
                                </DropdownMenuItem>
                            ))}
                            <DropdownMenuSeparator />
                        </>
                    )}

                    {/* Start New Post with this as Reference */}
                    <DropdownMenuItem
                        onClick={() => router.push(`/editor?critique_of=${postId}`)}
                        className="cursor-pointer"
                    >
                        <FileEdit className="w-4 h-4 mr-2" />
                        {t('citeInNewPost')}
                    </DropdownMenuItem>

                    <DropdownMenuSeparator />

                    {/* Copy Citation */}
                    <DropdownMenuItem
                        onClick={() => setShowCopyCitation(true)}
                        className="cursor-pointer"
                    >
                        <Copy className="w-4 h-4 mr-2" />
                        {t('copyCitation')}
                    </DropdownMenuItem>
                </DropdownMenuContent>
            </DropdownMenu>

            {/* Copy Citation Dialog */}
            <Dialog open={showCopyCitation} onOpenChange={setShowCopyCitation}>
                <DialogContent className="sm:max-w-md">
                    <DialogHeader>
                        <DialogTitle>{t('copyCitation')}</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-3" role="list" aria-label="Citation formats">
                        {(['apa', 'chicago', 'mla', 'bibtex', 'ris'] as CitationFormat[]).map((format) => (
                            <button
                                key={format}
                                onClick={() => copyCitation(format)}
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter' || e.key === ' ') {
                                        e.preventDefault()
                                        copyCitation(format)
                                    }
                                }}
                                className="w-full flex items-center justify-between p-3 rounded-lg border border-gray-200 dark:border-dark-border hover:bg-gray-50 dark:hover:bg-dark-bg focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 dark:focus:ring-offset-dark-surface transition-colors text-left"
                                role="listitem"
                                aria-label={`Copy ${format.toUpperCase()} citation`}
                            >
                                <div>
                                    <span className="font-semibold text-text dark:text-dark-text">
                                        {format.toUpperCase()}
                                    </span>
                                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-0.5">
                                        {format === 'apa' && 'American Psychological Association'}
                                        {format === 'chicago' && 'Chicago Manual of Style'}
                                        {format === 'bibtex' && 'LaTeX bibliography format'}
                                        {format === 'mla' && 'Modern Language Association'}
                                        {format === 'ris' && 'Zotero, Mendeley, EndNote'}
                                    </p>
                                </div>
                                {copiedFormat === format ? (
                                    <Check className="w-5 h-5 text-green-500" aria-hidden="true" />
                                ) : (
                                    <Copy className="w-5 h-5 text-text-light dark:text-dark-text-muted" aria-hidden="true" />
                                )}
                            </button>
                        ))}
                        <div className="text-xs text-text-light dark:text-dark-text-muted pt-3 border-t border-gray-100 dark:border-dark-border">
                            <p className="text-center mb-1.5 font-medium">Choose based on discipline</p>
                            <div className="flex flex-wrap justify-center gap-x-3 gap-y-1">
                                <span>APA ΓåÆ social sciences</span>
                                <span>Chicago ΓåÆ history</span>
                                <span>MLA ΓåÆ humanities</span>
                                <span>BibTeX ΓåÆ LaTeX</span>
                                <span>RIS ΓåÆ reference managers</span>
                            </div>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import { UserAvatar } from '@/components/ui/UserAvatar'
import { MessageSquare, ChevronDown, ChevronUp, CornerDownRight, Loader2 } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'

interface Comment {
    id: string
    content: string
    created_at: string
    user_id: string
    post_id: string
    parent_id: string | null
    user?: {
        id: string
        name: string
        email: string
        avatar_url?: string
    }
    children?: Comment[]
}

interface CommentTreeProps {
    postId: string
    comments: Comment[]
    onCommentAdded?: () => void
}

interface CommentNodeProps {
    comment: Comment
    depth: number
    postId: string
    onReply: (parentId: string, content: string) => Promise<void>
}

function CommentNode({ comment, depth, postId, onReply }: CommentNodeProps) {
    const t = useTranslations('Comments')
    const tForms = useTranslations('Forms')
    const tCommon = useTranslations('Common')
    const { formatDate } = useDateFormatter()
    const [isCollapsed, setIsCollapsed] = useState(false)
    const [isReplying, setIsReplying] = useState(false)
    const [replyContent, setReplyContent] = useState('')
    const [submitting, setSubmitting] = useState(false)

    const handleSubmitReply = async () => {
        if (!replyContent.trim()) return
        setSubmitting(true)
        try {
            await onReply(comment.id, replyContent)
            setReplyContent('')
            setIsReplying(false)
        } finally {
            setSubmitting(false)
        }
    }

    const hasChildren = comment.children && comment.children.length > 0
    const maxDepth = 4 // Max visual nesting depth

    return (
        <div className={cn('relative', depth > 0 && 'ms-4 ps-4 border-s border-gray-200 dark:border-dark-border')}>
            <div className="py-3">
                {/* Comment Header */}
                <div className="flex items-start gap-3">
                    {comment.user?.id ? (
                        <Link href={`/profile/${comment.user.id}`} className="shrink-0 hover:opacity-80 transition-opacity">
                            <UserAvatar
                                name={comment.user?.name}
                                email={comment.user?.email}
                                avatarUrl={comment.user?.avatar_url}
                                size="sm"
                            />
                        </Link>
                    ) : (
                        <UserAvatar
                            name={comment.user?.name}
                            email={comment.user?.email}
                            avatarUrl={comment.user?.avatar_url}
                            size="sm"
                        />
                    )}
                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                            {comment.user?.id ? (
                                <Link href={`/profile/${comment.user.id}`} className="text-sm font-medium text-text dark:text-dark-text hover:text-primary dark:hover:text-accent-light transition-colors">
                                    {comment.user?.name || t('anonymous')}
                                </Link>
                            ) : (
                                <span className="text-sm font-medium text-text dark:text-dark-text">
                                    {comment.user?.name || t('anonymous')}
                                </span>
                            )}
                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                {formatDate(comment.created_at, 'distance')}
                            </span>
                        </div>

                        {/* Comment Content */}
                        <p className="mt-1 text-sm text-text dark:text-dark-text whitespace-pre-wrap">
                            {comment.content}
                        </p>

                        {/* Actions */}
                        <div className="flex items-center gap-3 mt-2">
                            {depth < maxDepth && (
                                <button
                                    onClick={() => setIsReplying(!isReplying)}
                                    className="text-xs text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text flex items-center gap-1"
                                >
                                    <CornerDownRight className="w-3 h-3" />
                                    {t('reply')}
                                </button>
                            )}

                            {hasChildren && (
                                <button
                                    onClick={() => setIsCollapsed(!isCollapsed)}
                                    className="text-xs text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text flex items-center gap-1"
                                >
                                    {isCollapsed ? (
                                        <>
                                            <ChevronDown className="w-3 h-3" />
                                            {t('showReplies', { count: comment.children!.length })}
                                        </>
                                    ) : (
                                        <>
                                            <ChevronUp className="w-3 h-3" />
                                            {t('hideReplies')}
                                        </>
                                    )}
                                </button>
                            )}
                        </div>

                        {/* Reply Form */}
                        {isReplying && (
                            <div className="mt-3 space-y-2">
                                <textarea
                                    value={replyContent}
                                    onChange={(e) => setReplyContent(e.target.value)}
                                    placeholder={tForms('writeReply')}
                                    rows={2}
                                    className="w-full px-3 py-2 text-sm rounded-md border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-text dark:text-dark-text resize-none focus:outline-none focus:ring-1 focus:ring-primary"
                                />
                                <div className="flex items-center gap-2">
                                    <button
                                        onClick={handleSubmitReply}
                                        disabled={submitting || !replyContent.trim()}
                                        className="px-3 py-1 text-xs font-medium rounded-md bg-primary text-white hover:bg-primary-dark disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        {submitting ? (
                                            <Loader2 className="w-3 h-3 animate-spin" />
                                        ) : (
                                            t('reply')
                                        )}
                                    </button>
                                    <button
                                        onClick={() => setIsReplying(false)}
                                        className="px-3 py-1 text-xs text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text"
                                    >
                                        {tCommon('cancel')}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Children */}
            {
                hasChildren && !isCollapsed && (
                    <div>
                        {comment.children!.map((child) => (
                            <CommentNode
                                key={child.id}
                                comment={child}
                                depth={depth + 1}
                                postId={postId}
                                onReply={onReply}
                            />
                        ))}
                    </div>
                )}
        </div>
    )
}

export function CommentTree({ postId, comments, onCommentAdded }: CommentTreeProps) {
    const router = useRouter()
    const supabase = createClient()
    const [user, setUser] = useState<any>(null)
    const [newComment, setNewComment] = useState('')
    const [submitting, setSubmitting] = useState(false)
    const t = useTranslations('Comments')

    useEffect(() => {
        supabase.auth.getUser().then(({ data: { user } }) => {
            setUser(user)
        })
    }, [supabase])

    // Build tree structure from flat comments
    const buildTree = (flatComments: Comment[]): Comment[] => {
        const map = new Map<string, Comment>()
        const roots: Comment[] = []

        // First pass: create map
        flatComments.forEach(comment => {
            map.set(comment.id, { ...comment, children: [] })
        })

        // Second pass: build tree
        flatComments.forEach(comment => {
            const node = map.get(comment.id)!
            if (comment.parent_id && map.has(comment.parent_id)) {
                map.get(comment.parent_id)!.children!.push(node)
            } else {
                roots.push(node)
            }
        })

        return roots
    }

    const commentTree = buildTree(comments)

    const handleAddComment = async (parentId: string | null, content: string) => {
        if (!user) {
            router.push('/login')
            return
        }

        try {
            const { error } = await supabase.from('comments').insert({
                post_id: postId,
                user_id: user.id,
                content,
                parent_id: parentId,
            })

            if (error) {
                console.error('Supabase error adding comment:', error.message, error.code, error.details)
                throw error
            }
            onCommentAdded?.()
        } catch (error: any) {
            console.error('Error adding comment:', error?.message || error?.code || JSON.stringify(error))
        }
    }

    const handleNewComment = async () => {
        if (!newComment.trim()) return
        setSubmitting(true)
        try {
            await handleAddComment(null, newComment)
            setNewComment('')
        } finally {
            setSubmitting(false)
        }
    }

    return (
        <div className="space-y-6">
            {/* New Comment Form */}
            <div className="space-y-3">
                <h3 className="text-sm font-medium text-text dark:text-dark-text flex items-center gap-2">
                    <MessageSquare className="w-4 h-4" />
                    {comments.length === 1 ? t('commentsCount', { count: comments.length }) : t('commentsCountPlural', { count: comments.length })}
                </h3>

                {user ? (
                    <div className="flex gap-3">
                        <UserAvatar
                            name={user.user_metadata?.name}
                            email={user.email}
                            avatarUrl={user.user_metadata?.avatar_url}
                            size="sm"
                        />
                        <div className="flex-1 space-y-2">
                            <textarea
                                value={newComment}
                                onChange={(e) => setNewComment(e.target.value)}
                                placeholder={t('writeComment')}
                                rows={3}
                                className="w-full px-3 py-2 text-sm rounded-md border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-text dark:text-dark-text resize-none focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                            <button
                                onClick={handleNewComment}
                                disabled={submitting || !newComment.trim()}
                                className="px-4 py-1.5 text-sm font-medium rounded-md bg-primary text-white hover:bg-primary-dark disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {submitting ? (
                                    <Loader2 className="w-4 h-4 animate-spin inline mr-1" />
                                ) : null}
                                {t('postComment')}
                            </button>
                        </div>
                    </div>
                ) : (
                    <div className="text-center py-4 text-sm text-text-light dark:text-dark-text-muted">
                        <Link href="/login" className="text-primary dark:text-accent-light hover:underline">
                            Sign in
                        </Link>{' '}
                        to join the discussion.
                    </div>
                )}
            </div>

            {/* Comments Tree */}
            {commentTree.length > 0 ? (
                <div className="divide-y divide-gray-100 dark:divide-dark-border">
                    {commentTree.map((comment) => (
                        <CommentNode
                            key={comment.id}
                            comment={comment}
                            depth={0}
                            postId={postId}
                            onReply={(parentId, content) => handleAddComment(parentId, content)}
                        />
                    ))}
                </div>
            ) : (
                <p className="text-center py-8 text-sm text-text-light dark:text-dark-text-muted">
                    {t('noCommentsDesc')}
                </p>
            )}
        </div>
    )
}

'use client'

import { useEffect, useMemo, useState, useCallback } from 'react'
import { MessageCircle, Loader2 } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { CommentTree } from '@/components/CommentTree'
import { useTranslations } from 'next-intl'

interface Comment {
  id: string
  content: string
  created_at: string
  user_id: string
  post_id: string
  parent_id: string | null
  user?: {
    id: string
    name: string
    email: string
    avatar_url?: string
  }
}

interface CommentsSectionProps {
  postId: string
}

export function CommentsSection({ postId }: CommentsSectionProps) {
  const { showToast } = useToast()
  const supabase = useMemo(() => createClient(), [])
  const [comments, setComments] = useState<Comment[]>([])
  const [loading, setLoading] = useState(true)
  const t = useTranslations('Comments')

  const fetchComments = useCallback(async () => {
    try {
      setLoading(true)
      const response = await fetch(`/api/comments?post_id=${postId}`)
      const payload = await response.json()

      if (!response.ok || !payload.success) {
        showToast(payload.error || 'Unable to load comments.', 'error')
        return
      }

      // Transform the API response to match CommentTree's expected format
      const transformedComments = (payload.data?.comments || []).map((c: any) => ({
        id: c.id,
        content: c.content,
        created_at: c.created_at,
        user_id: c.user_id,
        post_id: c.post_id,
        parent_id: c.parent_id,
        user: c.user ? {
          id: c.user.id,
          name: c.user.name,
          email: c.user.email,
          avatar_url: c.user.avatar_url,
        } : undefined,
      }))

      setComments(transformedComments)
    } catch (error) {
      console.error('Comments fetch error:', error)
      showToast('Failed to load comments.', 'error')
    } finally {
      setLoading(false)
    }
  }, [postId, showToast])

  useEffect(() => {
    fetchComments()
  }, [fetchComments])

  // Realtime subscription for new comments on this post
  useEffect(() => {
    const channel = supabase
      .channel(`comments:${postId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'comments',
          filter: `post_id=eq.${postId}`,
        },
        async (payload) => {
          // Fetch the full comment with user data
          const { data: newComment } = await supabase
            .from('comments')
            .select(`
              *,
              user:users!comments_user_id_fkey(id, name, email, avatar_url)
            `)
            .eq('id', payload.new.id)
            .single()

          if (newComment) {
            const transformedComment: Comment = {
              id: newComment.id,
              content: newComment.content,
              created_at: newComment.created_at,
              user_id: newComment.user_id,
              post_id: newComment.post_id,
              parent_id: newComment.parent_id,
              user: newComment.user ? {
                id: newComment.user.id,
                name: newComment.user.name,
                email: newComment.user.email,
                avatar_url: newComment.user.avatar_url,
              } : undefined,
            }

            setComments((prev) => {
              // Avoid duplicates (in case we also did a manual refresh)
              if (prev.some(c => c.id === transformedComment.id)) {
                return prev
              }
              return [...prev, transformedComment]
            })
          }
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [postId, supabase])

  if (loading) {
    return (
      <section className="mt-10">
        <div className="flex items-center gap-2 mb-6">
          <MessageCircle className="w-5 h-5 text-primary dark:text-accent-light" />
          <h2 className="text-xl font-display font-semibold text-primary dark:text-dark-text">
            {t('discussion')}
          </h2>
        </div>
        <div className="flex items-center justify-center py-8 text-text-light dark:text-dark-text-muted">
          <Loader2 className="w-5 h-5 animate-spin mr-2" />
          {t('loadingComments')}
        </div>
      </section>
    )
  }

  return (
    <section className="mt-10">
      <div className="flex items-center gap-2 mb-6">
        <MessageCircle className="w-5 h-5 text-primary dark:text-accent-light" />
        <h2 className="text-xl font-display font-semibold text-primary dark:text-dark-text">
          {t('discussion')}
        </h2>
        <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-primary/10 dark:bg-accent-light/20 text-primary dark:text-accent-light">
          {comments.length}
        </span>
      </div>

      <div className="card p-6">
        <CommentTree
          postId={postId}
          comments={comments}
          onCommentAdded={fetchComments}
        />
      </div>
    </section>
  )
}

'use client'

import { AlertTriangle, ExternalLink, FileText, Info } from 'lucide-react'
import Link from 'next/link'
import type { DataConflict } from '@/types/advanced'

interface ConflictWarningProps {
    conflicts: DataConflict[]
    compact?: boolean
}

export function ConflictWarning({ conflicts, compact = false }: ConflictWarningProps) {
    if (!conflicts || conflicts.length === 0) return null

    if (compact) {
        return (
            <div className="flex items-center gap-2 text-red-600 dark:text-red-400 text-sm">
                <AlertTriangle className="w-4 h-4" />
                <span>{conflicts.length} data conflict{conflicts.length !== 1 ? 's' : ''} detected</span>
            </div>
        )
    }

    return (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl p-4">
            <div className="flex items-start gap-3">
                <div className="shrink-0 p-2 bg-red-100 dark:bg-red-900/40 rounded-lg">
                    <AlertTriangle className="w-5 h-5 text-red-600 dark:text-red-400" />
                </div>

                <div className="flex-1 min-w-0">
                    <h4 className="font-medium text-red-800 dark:text-red-300 mb-2">
                        Data Conflict Detected
                    </h4>

                    <div className="space-y-3">
                        {conflicts.map((conflict) => (
                            <ConflictItem key={conflict.id} conflict={conflict} />
                        ))}
                    </div>

                    <p className="mt-3 text-xs text-red-600/80 dark:text-red-400/80">
                        Contradictions are surfaced, not averaged. Review both sources to understand the discrepancy.
                    </p>
                </div>
            </div>
        </div>
    )
}

interface ConflictItemProps {
    conflict: DataConflict
}

function ConflictItem({ conflict }: ConflictItemProps) {
    const getConflictTypeLabel = (type: string) => {
        switch (type) {
            case 'existence': return 'Existence Conflict'
            case 'state': return 'State/Condition Conflict'
            case 'attribute': return 'Attribute Conflict'
            case 'temporal': return 'Temporal Conflict'
            default: return 'Data Conflict'
        }
    }

    const getResolutionBadge = (resolution: string) => {
        switch (resolution) {
            case 'field_wins':
                return <span className="px-2 py-0.5 text-xs rounded-full bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400">Field data prioritized</span>
            case 'external_wins':
                return <span className="px-2 py-0.5 text-xs rounded-full bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400">External data prioritized</span>
            case 'needs_review':
                return <span className="px-2 py-0.5 text-xs rounded-full bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400">Needs review</span>
            case 'unresolved':
                return <span className="px-2 py-0.5 text-xs rounded-full bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400">Unresolved</span>
            default:
                return null
        }
    }

    return (
        <div className="bg-white/50 dark:bg-dark-bg/50 rounded-lg p-3 text-sm">
            <div className="flex items-center justify-between mb-2">
                <span className="font-medium text-red-700 dark:text-red-300">
                    {getConflictTypeLabel(conflict.conflict_type)}
                </span>
                {getResolutionBadge(conflict.resolution)}
            </div>

            <div className="grid grid-cols-2 gap-3">
                {/* External claim */}
                <div className="space-y-1">
                    <div className="text-xs text-text-light flex items-center gap-1">
                        <ExternalLink className="w-3 h-3" />
                        External ({conflict.external_source_id.toUpperCase()})
                    </div>
                    <p className="text-red-600 dark:text-red-400">{conflict.external_claim}</p>
                    {conflict.external_timestamp && (
                        <p className="text-xs text-text-light">
                            {new Date(conflict.external_timestamp).toLocaleDateString()}
                        </p>
                    )}
                </div>

                {/* Field claim */}
                <div className="space-y-1">
                    <div className="text-xs text-text-light flex items-center gap-1">
                        <FileText className="w-3 h-3" />
                        Field Data
                    </div>
                    <p className="text-green-600 dark:text-green-400">{conflict.field_claim}</p>
                    {conflict.field_timestamp && (
                        <p className="text-xs text-text-light">
                            {new Date(conflict.field_timestamp).toLocaleDateString()}
                        </p>
                    )}
                </div>
            </div>

            {conflict.conflict_detail && (
                <p className="mt-2 text-xs text-text-light border-t border-red-200 dark:border-red-800 pt-2">
                    {conflict.conflict_detail}
                </p>
            )}

            {conflict.suggested_action && !conflict.action_taken && (
                <div className="mt-2 flex items-center gap-2 text-xs text-amber-600 dark:text-amber-400">
                    <Info className="w-3 h-3" />
                    Suggested: {conflict.suggested_action.replace(/_/g, ' ')}
                </div>
            )}
        </div>
    )
}

// Inline warning for search results
interface InlineConflictBadgeProps {
    count: number
    onClick?: () => void
}

export function InlineConflictBadge({ count, onClick }: InlineConflictBadgeProps) {
    if (count === 0) return null

    return (
        <button
            onClick={onClick}
            className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors"
        >
            <AlertTriangle className="w-3 h-3" />
            {count} conflict{count !== 1 ? 's' : ''}
        </button>
    )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { useToast } from '@/components/ui/toast'
import { Pencil, Loader2, User, Building2, MapPin, Globe, Sparkles, ImageIcon } from 'lucide-react'
import { useRouter } from 'next/navigation'
import { ImageUpload } from '@/components/ImageUpload'
import { CoverImageUpload } from '@/components/CoverImageUpload'
import { useTranslations } from 'next-intl'

interface Profile {
    id: string
    name: string
    bio: string | null
    affiliation: string | null
    location: string | null
    website: string | null
    research_interests: string[] | null
    avatar_url: string | null
    cover_image_url: string | null
}

interface EditProfileDialogProps {
    profile: Profile
}

export function EditProfileDialog({ profile }: EditProfileDialogProps) {
    const [open, setOpen] = useState(false)
    const [loading, setLoading] = useState(false)
    const [formData, setFormData] = useState({
        name: profile.name || '',
        bio: profile.bio || '',
        affiliation: profile.affiliation || '',
        location: profile.location || '',
        website: profile.website || '',
        research_interests: profile.research_interests?.join(', ') || '',
        avatar_url: profile.avatar_url || '',
        cover_image_url: profile.cover_image_url || ''
    })

    const supabase = createClient()
    const { showToast } = useToast()
    const router = useRouter()
    const t = useTranslations('Profile')
    const tCommon = useTranslations('Common')

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const interestsArray = formData.research_interests
                .split(',')
                .map(s => s.trim())
                .filter(s => s.length > 0)

            // First verify user is authenticated
            const { data: { user }, error: authError } = await supabase.auth.getUser()
            if (authError || !user) {
                throw new Error('You must be logged in to update your profile')
            }

            const { error, data } = await supabase
                .from('users')
                .update({
                    name: formData.name,
                    bio: formData.bio,
                    affiliation: formData.affiliation,
                    location: formData.location,
                    website: formData.website,
                    research_interests: interestsArray,
                    avatar_url: formData.avatar_url,
                    cover_image_url: formData.cover_image_url || null
                })
                .eq('id', profile.id)
                .select()

            if (error) {
                console.error('Supabase error details:', {
                    message: error.message,
                    code: error.code,
                    details: error.details,
                    hint: error.hint
                })
                throw new Error(error.message || 'Failed to update profile')
            }

            // Check if the update actually affected any rows
            if (!data || data.length === 0) {
                throw new Error('No profile was updated. You may not have permission to edit this profile.')
            }

            showToast('Your profile has been successfully updated.', 'success')

            // Dispatch event to update ProfileCompletionCard
            window.dispatchEvent(new CustomEvent('profile-updated'))

            setOpen(false)
            router.refresh()
        } catch (error: unknown) {
            // Better error logging for Supabase PostgrestError
            const errorMessage = error instanceof Error
                ? error.message
                : typeof error === 'object' && error !== null
                    ? JSON.stringify(error, null, 2)
                    : String(error)
            console.error('Error updating profile:', errorMessage, error)

            // Check for specific error types
            const supabaseError = error as { message?: string; code?: string; details?: string }
            const displayMessage = supabaseError?.message || supabaseError?.details || 'Failed to update profile. Please try again.'
            showToast(displayMessage, 'error')
        } finally {
            setLoading(false)
        }
    }

    // Parse interests for preview
    const interestsList = formData.research_interests
        .split(',')
        .map(s => s.trim())
        .filter(s => s.length > 0)

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button variant="outline" size="sm" className="gap-2">
                    <Pencil className="w-4 h-4" />
                    {t('editProfile')}
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[540px] p-0 overflow-hidden max-h-[90vh] overflow-y-auto">
                {/* Cover Image Section */}
                <div className="relative">
                    {formData.cover_image_url ? (
                        <div
                            className="h-32 bg-cover bg-center"
                            style={{ backgroundImage: `url(${formData.cover_image_url})` }}
                        />
                    ) : (
                        <div className="h-32 bg-gradient-to-br from-primary via-primary-dark to-secondary" />
                    )}

                    {/* Always visible cover edit button - positioned left to avoid dialog X */}
                    <div className="absolute top-3 left-3">
                        <CoverImageUpload
                            value={formData.cover_image_url}
                            onChange={(url) => setFormData({ ...formData, cover_image_url: url || '' })}
                            userId={profile.id}
                            compact
                        />
                    </div>

                    {/* Header text overlay */}
                    <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/60 to-transparent">
                        <DialogHeader>
                            <DialogTitle className="text-white text-xl font-bold">{t('editProfile')}</DialogTitle>
                            <p className="text-white/70 text-sm">{t('updateInfo')}</p>
                        </DialogHeader>
                    </div>
                </div>

                {/* Avatar - overlapping header */}
                <div className="relative -mt-10 flex justify-center mb-2">
                    <ImageUpload
                        bucket="avatars"
                        path={profile.id}
                        currentImage={formData.avatar_url}
                        onUploadComplete={(url) => setFormData({ ...formData, avatar_url: url })}
                    />
                </div>

                <form onSubmit={handleSubmit} className="px-6 pb-6 space-y-5">
                    {/* Name field - prominent */}
                    <div className="space-y-2">
                        <Label htmlFor="name" className="text-sm font-medium flex items-center gap-2 text-text dark:text-dark-text">
                            <User className="w-4 h-4 text-gray-400" />
                            {t('displayName')}
                        </Label>
                        <Input
                            id="name"
                            value={formData.name}
                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            required
                            className="h-11 text-base font-medium"
                            placeholder="Your full name"
                        />
                    </div>

                    {/* Bio field */}
                    <div className="space-y-2">
                        <Label htmlFor="bio" className="text-sm font-semibold">
                            {t('bio')}
                        </Label>
                        <Textarea
                            id="bio"
                            value={formData.bio}
                            onChange={(e) => setFormData({ ...formData, bio: e.target.value })}
                            placeholder="Share a little about yourself and your research focus..."
                            className="resize-none h-24"
                        />
                        <p className="text-xs text-text-light dark:text-dark-text-muted">
                            {formData.bio.length}/300 {t('characters')}
                        </p>
                    </div>

                    {/* Two-column layout */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="affiliation" className="text-sm font-medium flex items-center gap-2 text-text dark:text-dark-text">
                                <Building2 className="w-4 h-4 text-gray-400" />
                                {t('affiliation')}
                            </Label>
                            <Input
                                id="affiliation"
                                value={formData.affiliation}
                                onChange={(e) => setFormData({ ...formData, affiliation: e.target.value })}
                                placeholder="University / Org"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="location" className="text-sm font-medium flex items-center gap-2 text-text dark:text-dark-text">
                                <MapPin className="w-4 h-4 text-gray-400" />
                                {t('location')}
                                <span className="text-xs text-gray-400 font-normal">({tCommon('optional')})</span>
                            </Label>
                            <Input
                                id="location"
                                value={formData.location}
                                onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                                placeholder="City, Country"
                            />
                        </div>
                    </div>

                    {/* Website */}
                    <div className="space-y-2">
                        <Label htmlFor="website" className="text-sm font-medium flex items-center gap-2 text-text dark:text-dark-text">
                            <Globe className="w-4 h-4 text-gray-400" />
                            {t('website')}
                        </Label>
                        <Input
                            id="website"
                            type="url"
                            value={formData.website}
                            onChange={(e) => setFormData({ ...formData, website: e.target.value })}
                            placeholder="https://yourwebsite.com"
                        />
                    </div>

                    {/* Research Interests */}
                    <div className="space-y-2">
                        <Label htmlFor="interests" className="text-sm font-medium flex items-center gap-2 text-text dark:text-dark-text">
                            <Sparkles className="w-4 h-4 text-gray-400" />
                            {t('researchInterests')}
                        </Label>
                        <Input
                            id="interests"
                            value={formData.research_interests}
                            onChange={(e) => setFormData({ ...formData, research_interests: e.target.value })}
                            placeholder="e.g. Public Health, Migration, Policy"
                        />
                        {interestsList.length > 0 && (
                            <div className="flex flex-wrap gap-2 pt-2">
                                {interestsList.map((interest, i) => (
                                    <span
                                        key={i}
                                        className="px-2.5 py-1 text-xs font-medium bg-primary/10 text-primary dark:bg-primary-light/10 dark:text-primary-light rounded-full"
                                    >
                                        {interest}
                                    </span>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Actions */}
                    <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-dark-border">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={() => setOpen(false)}
                            className="text-text-light dark:text-dark-text-muted"
                        >
                            {tCommon('cancel')}
                        </Button>
                        <Button type="submit" disabled={loading} className="min-w-[120px]">
                            {loading ? (
                                <>
                                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                    {tCommon('saving')}
                                </>
                            ) : (
                                t('saveChanges')
                            )}
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import { SkillBadge } from './SkillBadge'
import { UserAvatar } from '@/components/ui/UserAvatar'
import { useToast } from '@/components/ui/toast'
import { Button } from '@/components/ui/button'
import { Plus, ChevronDown, ChevronUp, Award, Users, Search } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface Endorser {
    id: string
    name: string | null
    avatar_url: string | null
}

interface UserSkill {
    skill_id: string
    skill_name: string
    skill_category: string
    is_recognized: boolean
    endorsement_count: number
    endorsers: Endorser[]
}

interface EndorsementSectionProps {
    userId: string
    isOwnProfile: boolean
}

const SKILL_CATEGORIES = [
    'Research Methods',
    'Technical',
    'Domain Knowledge',
    'Work Field',
    'Practical Expertise'
]

export function EndorsementSection({ userId, isOwnProfile }: EndorsementSectionProps) {
    const [skills, setSkills] = useState<UserSkill[]>([])
    const [loading, setLoading] = useState(true)
    const [currentUserId, setCurrentUserId] = useState<string | null>(null)
    const [endorsedSkills, setEndorsedSkills] = useState<Set<string>>(new Set())
    const [showAddSkill, setShowAddSkill] = useState(false)
    const [expandedSkill, setExpandedSkill] = useState<string | null>(null)
    const [newSkillName, setNewSkillName] = useState('')
    const [newSkillCategory, setNewSkillCategory] = useState(SKILL_CATEGORIES[0])
    const [availableSkills, setAvailableSkills] = useState<any[]>([])
    const [searchQuery, setSearchQuery] = useState('')
    const [addingSkill, setAddingSkill] = useState(false)
    const [loadingSkills, setLoadingSkills] = useState(false)
    const [inputFocused, setInputFocused] = useState(false)

    const dropdownRef = useRef<HTMLDivElement>(null)
    const supabase = createClient()
    const { showToast } = useToast()
    const t = useTranslations('ProfileLabels')
    const [isCollapsed, setIsCollapsed] = useState(false)

    // Click outside handler to close dropdown
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setInputFocused(false)
            }
        }

        document.addEventListener('mousedown', handleClickOutside)
        return () => document.removeEventListener('mousedown', handleClickOutside)
    }, [])

    // Load user skills and endorsements
    useEffect(() => {
        async function loadData() {
            try {
                // Get current user
                const { data: { user } } = await supabase.auth.getUser()
                setCurrentUserId(user?.id || null)

                // Get user's skills with endorsements
                const { data: userSkills, error } = await supabase
                    .rpc('get_user_endorsements', { p_user_id: userId })

                if (error && error.message) {
                    console.warn('Endorsements RPC unavailable, using fallback:', error.message)
                    // Fallback: load skills directly
                    const { data: fallbackSkills } = await supabase
                        .from('user_skills')
                        .select(`
                            skill_id,
                            skills(id, name, category, is_recognized)
                        `)
                        .eq('user_id', userId)

                    if (fallbackSkills) {
                        setSkills(fallbackSkills.map((us: any) => ({
                            skill_id: us.skill_id,
                            skill_name: us.skills?.name || 'Unknown',
                            skill_category: us.skills?.category || 'Other',
                            is_recognized: us.skills?.is_recognized || false,
                            endorsement_count: 0,
                            endorsers: []
                        })))
                    }
                } else if (userSkills) {
                    setSkills(userSkills)
                }

                // Check which skills current user has endorsed
                if (user && user.id !== userId) {
                    const { data: myEndorsements } = await supabase
                        .from('endorsements')
                        .select('skill_id')
                        .eq('endorser_id', user.id)
                        .eq('endorsed_user_id', userId)

                    if (myEndorsements) {
                        setEndorsedSkills(new Set(myEndorsements.map(e => e.skill_id)))
                    }
                }
            } catch (error) {
                console.error('Error:', error)
            } finally {
                setLoading(false)
            }
        }

        loadData()
    }, [userId, supabase])

    // Load available skills for adding
    useEffect(() => {
        if (!showAddSkill) return

        async function loadAvailableSkills() {
            setLoadingSkills(true)
            const { data } = await supabase
                .from('skills')
                .select('*')
                .order('is_recognized', { ascending: false })
                .order('name')

            if (data) {
                // Filter out skills user already has
                const userSkillIds = new Set(skills.map(s => s.skill_id))
                setAvailableSkills(data.filter(s => !userSkillIds.has(s.id)))
            }
            setLoadingSkills(false)
        }

        loadAvailableSkills()
    }, [showAddSkill, skills, supabase])

    const handleEndorse = async (skillId: string) => {
        if (!currentUserId || currentUserId === userId) return

        const hasEndorsed = endorsedSkills.has(skillId)

        try {
            if (hasEndorsed) {
                // Remove endorsement
                await supabase
                    .from('endorsements')
                    .delete()
                    .eq('endorser_id', currentUserId)
                    .eq('endorsed_user_id', userId)
                    .eq('skill_id', skillId)

                setEndorsedSkills(prev => {
                    const next = new Set(prev)
                    next.delete(skillId)
                    return next
                })
                setSkills(prev => prev.map(s =>
                    s.skill_id === skillId
                        ? { ...s, endorsement_count: Math.max(0, s.endorsement_count - 1) }
                        : s
                ))
                showToast('Endorsement removed', 'success')
            } else {
                // Add endorsement
                await supabase
                    .from('endorsements')
                    .insert({
                        endorser_id: currentUserId,
                        endorsed_user_id: userId,
                        skill_id: skillId
                    })

                setEndorsedSkills(prev => new Set([...prev, skillId]))
                setSkills(prev => prev.map(s =>
                    s.skill_id === skillId
                        ? { ...s, endorsement_count: s.endorsement_count + 1 }
                        : s
                ))
                showToast('Skill endorsed!', 'success')
            }
        } catch (error: any) {
            showToast(error.message || 'Failed to update endorsement', 'error')
        }
    }

    const handleAddSkill = async (skillId: string) => {
        if (!currentUserId) return
        setAddingSkill(true)

        try {
            await supabase
                .from('user_skills')
                .insert({
                    user_id: userId,
                    skill_id: skillId
                })

            // Reload skills
            const skill = availableSkills.find(s => s.id === skillId)
            if (skill) {
                setSkills(prev => [...prev, {
                    skill_id: skill.id,
                    skill_name: skill.name,
                    skill_category: skill.category,
                    is_recognized: skill.is_recognized,
                    endorsement_count: 0,
                    endorsers: []
                }])
            }

            setShowAddSkill(false)
            setSearchQuery('')
            showToast('Skill added to your profile', 'success')

            // Notify ProfileCompletionCard to refresh
            window.dispatchEvent(new CustomEvent('profile-updated'))
        } catch (error: any) {
            showToast(error.message || 'Failed to add skill', 'error')
        } finally {
            setAddingSkill(false)
        }
    }

    const handleCreateAndAddSkill = async () => {
        if (!currentUserId || !newSkillName.trim()) return
        setAddingSkill(true)

        try {
            // Create skill using RPC function
            const { data: skillId, error } = await supabase
                .rpc('find_or_create_skill', {
                    p_name: newSkillName.trim(),
                    p_category: newSkillCategory,
                    p_created_by: currentUserId
                })

            if (error) throw error

            // Add to user's skills
            await supabase
                .from('user_skills')
                .insert({
                    user_id: userId,
                    skill_id: skillId
                })

            setSkills(prev => [...prev, {
                skill_id: skillId,
                skill_name: newSkillName.trim(),
                skill_category: newSkillCategory,
                is_recognized: false,
                endorsement_count: 0,
                endorsers: []
            }])

            setShowAddSkill(false)
            setNewSkillName('')
            showToast('Custom skill added', 'success')

            // Notify ProfileCompletionCard to refresh
            window.dispatchEvent(new CustomEvent('profile-updated'))
        } catch (error: any) {
            showToast(error.message || 'Failed to create skill', 'error')
        } finally {
            setAddingSkill(false)
        }
    }

    const handleRemoveSkill = async (skillId: string) => {
        if (!currentUserId) return

        try {
            await supabase
                .from('user_skills')
                .delete()
                .eq('user_id', userId)
                .eq('skill_id', skillId)

            setSkills(prev => prev.filter(s => s.skill_id !== skillId))
            showToast('Skill removed', 'success')
        } catch (error: any) {
            showToast(error.message || 'Failed to remove skill', 'error')
        }
    }

    // Group skills by category
    const skillsByCategory = skills.reduce<Record<string, UserSkill[]>>((acc, skill) => {
        const cat = skill.skill_category
        if (!acc[cat]) acc[cat] = []
        acc[cat].push(skill)
        return acc
    }, {})

    // Filter available skills by search - show all when query is empty or partial match
    const searchTerm = (searchQuery || newSkillName).toLowerCase().trim()
    const filteredAvailableSkills = searchTerm
        ? availableSkills.filter(s => s.name.toLowerCase().includes(searchTerm))
        : availableSkills

    if (loading) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                <div className="animate-pulse space-y-4">
                    <div className="h-6 bg-gray-200 dark:bg-dark-border rounded w-1/3"></div>
                    <div className="flex gap-2 flex-wrap">
                        {[1, 2, 3, 4].map(i => (
                            <div key={i} className="h-8 w-24 bg-gray-200 dark:bg-dark-border rounded-full"></div>
                        ))}
                    </div>
                </div>
            </div>
        )
    }



    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6 transition-all">
            {/* Header */}
            <div className="flex items-center justify-between mb-4 gap-4">
                <button
                    onClick={() => setIsCollapsed(!isCollapsed)}
                    className="flex items-center gap-2 group hover:opacity-80 transition-opacity min-w-0 text-left"
                >
                    <Award className="w-5 h-5 text-primary shrink-0" />
                    <h3 className="text-lg font-semibold text-text dark:text-dark-text truncate">
                        {t('skillsEndorsements')}
                    </h3>
                    {skills.length > 0 && (
                        <span className="hidden xs:inline-flex items-center justify-center px-2 py-0.5 rounded-full bg-primary/10 text-primary text-xs font-medium shrink-0">
                            {skills.reduce((sum, s) => sum + s.endorsement_count, 0)}
                        </span>
                    )}
                </button>
                <div className="flex items-center gap-2 shrink-0">
                    {isOwnProfile && (
                        <Button
                            variant="outline"
                            size="sm"
                            className="whitespace-nowrap"
                            onClick={(e: React.MouseEvent) => {
                                e.stopPropagation()
                                setShowAddSkill(!showAddSkill)
                                if (isCollapsed) setIsCollapsed(false)
                            }}
                        >
                            <Plus className="w-4 h-4 sm:me-1" />
                            <span className="hidden sm:inline">{t('addSkill')}</span>
                        </Button>
                    )}
                    <button
                        onClick={() => setIsCollapsed(!isCollapsed)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-dark-bg rounded-lg transition-colors text-gray-400 dark:text-gray-500 hover:text-primary"
                    >
                        {isCollapsed ? <ChevronDown className="w-5 h-5" /> : <ChevronUp className="w-5 h-5" />}
                    </button>
                </div>
            </div>

            {/* Collapsible Content */}
            <div className={cn(
                "overflow-hidden transition-all duration-300",
                isCollapsed ? "max-h-0 opacity-0" : "max-h-[2000px] opacity-100"
            )}>
                {/* Add Skill Panel - Unified Autocomplete Design */}
                {showAddSkill && isOwnProfile && (
                    <div className="mb-6 p-4 bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border shadow-sm">
                        <div className="space-y-3">
                            {/* Unified Search/Add Input */}
                            <div className="relative" ref={dropdownRef}>
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 dark:text-gray-500" />
                                    <input
                                        type="text"
                                        value={searchQuery || newSkillName}
                                        onChange={(e) => {
                                            setSearchQuery(e.target.value)
                                            setNewSkillName(e.target.value)
                                        }}
                                        onFocus={() => setInputFocused(true)}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' && (searchQuery || newSkillName).trim()) {
                                                e.preventDefault()
                                                // If there are matching skills, add the first one
                                                if (filteredAvailableSkills.length > 0) {
                                                    handleAddSkill(filteredAvailableSkills[0].id)
                                                } else {
                                                    // No matches, create custom skill
                                                    handleCreateAndAddSkill()
                                                }
                                            }
                                            if (e.key === 'Escape') {
                                                setShowAddSkill(false)
                                                setSearchQuery('')
                                                setNewSkillName('')
                                                setInputFocused(false)
                                            }
                                        }}
                                        placeholder="Type a skill name..."
                                        autoFocus
                                        className="w-full h-10 pl-10 pr-4 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder:text-gray-400 dark:placeholder:text-gray-500 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all"
                                    />
                                </div>

                                {/* Autocomplete Dropdown - Shows only when input is focused */}
                                {inputFocused && (
                                    <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-dark-surface rounded-lg border border-gray-200 dark:border-dark-border shadow-lg overflow-hidden z-10 max-h-64 overflow-y-auto">
                                        {loadingSkills ? (
                                            <div className="px-3 py-4 text-center text-sm text-gray-500 dark:text-gray-400">
                                                Loading skills...
                                            </div>
                                        ) : filteredAvailableSkills.length > 0 ? (
                                            <>
                                                {filteredAvailableSkills.slice(0, 8).map((skill, index) => (
                                                    <button
                                                        key={skill.id}
                                                        onClick={() => handleAddSkill(skill.id)}
                                                        disabled={addingSkill}
                                                        className={cn(
                                                            "w-full flex items-center justify-between px-3 py-2.5 text-left transition-colors",
                                                            index === 0
                                                                ? "bg-primary/5 dark:bg-primary/10 border-l-2 border-primary"
                                                                : "hover:bg-gray-50 dark:hover:bg-dark-bg"
                                                        )}
                                                    >
                                                        <span className="flex items-center gap-2">
                                                            <Award className={cn(
                                                                "w-4 h-4",
                                                                skill.is_recognized
                                                                    ? "text-primary"
                                                                    : "text-gray-400 dark:text-gray-500"
                                                            )} />
                                                            <span className="font-medium text-text dark:text-dark-text">
                                                                {skill.name}
                                                            </span>
                                                        </span>
                                                        <span className="text-xs text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-dark-bg px-2 py-0.5 rounded">
                                                            {skill.category}
                                                        </span>
                                                    </button>
                                                ))}
                                                {filteredAvailableSkills.length > 8 && (
                                                    <div className="px-3 py-2 text-xs text-gray-500 dark:text-gray-400 bg-gray-50 dark:bg-dark-bg text-center">
                                                        +{filteredAvailableSkills.length - 8} more results
                                                    </div>
                                                )}
                                            </>
                                        ) : (
                                            /* No matches - show create option */
                                            <div className="p-3">
                                                <div className="flex items-center justify-between">
                                                    <span className="text-sm text-text-light dark:text-dark-text-muted">
                                                        No matching skills found
                                                    </span>
                                                </div>
                                                {/* Category selector - always visible above add button */}
                                                <div className="mt-3 flex items-center gap-2">
                                                    <span className="text-xs text-gray-500 dark:text-gray-400 whitespace-nowrap">Category:</span>
                                                    <select
                                                        value={newSkillCategory}
                                                        onChange={(e) => setNewSkillCategory(e.target.value)}
                                                        className="flex-1 h-8 text-xs rounded-md border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text px-2 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary appearance-none cursor-pointer"
                                                        style={{
                                                            backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
                                                            backgroundPosition: 'right 0.5rem center',
                                                            backgroundRepeat: 'no-repeat',
                                                            backgroundSize: '1.5em 1.5em',
                                                            paddingRight: '2.5rem'
                                                        }}
                                                    >
                                                        {SKILL_CATEGORIES.map(cat => (
                                                            <option key={cat} value={cat} className="bg-white dark:bg-dark-bg text-text dark:text-dark-text">{cat}</option>
                                                        ))}
                                                    </select>
                                                </div>
                                                <button
                                                    onClick={handleCreateAndAddSkill}
                                                    disabled={addingSkill || !(searchQuery || newSkillName).trim()}
                                                    className="w-full mt-3 flex items-center justify-center gap-2 px-3 py-2.5 bg-primary hover:bg-primary/90 text-white rounded-lg font-medium text-sm transition-colors disabled:opacity-50"
                                                >
                                                    <Plus className="w-4 h-4" />
                                                    Add &quot;{(searchQuery || newSkillName).trim()}&quot; as new skill
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>

                            {/* Helper Text */}
                            <p className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                                <span className="inline-block w-4 h-4 bg-gray-100 dark:bg-dark-border rounded text-center text-[10px] leading-4 font-mono">Γå╡</span>
                                Press Enter to add ΓÇó Esc to cancel
                            </p>
                        </div>
                    </div>
                )}

                {/* Skills by Category */}
                {skills.length === 0 ? (
                    <p className="text-text-light dark:text-dark-text-muted text-sm">
                        {isOwnProfile
                            ? 'Add skills to your profile so others can endorse you.'
                            : 'No skills added yet.'}
                    </p>
                ) : (
                    <div className="space-y-4">
                        {Object.entries(skillsByCategory).map(([category, catSkills]) => (
                            <div key={category}>
                                <h4 className="text-xs font-medium text-text-light dark:text-dark-text-muted uppercase tracking-wide mb-2">
                                    {t(category.toLowerCase().replace(' ', '') as any) || category}
                                </h4>
                                <div className="flex flex-wrap gap-2">
                                    {catSkills.map(skill => (
                                        <div key={skill.skill_id} className="relative group">
                                            <SkillBadge
                                                skillId={skill.skill_id}
                                                name={skill.skill_name}
                                                category={skill.skill_category}
                                                isRecognized={skill.is_recognized}
                                                endorsementCount={skill.endorsement_count}
                                                hasEndorsed={endorsedSkills.has(skill.skill_id)}
                                                onEndorse={currentUserId ? () => handleEndorse(skill.skill_id) : undefined}
                                                isOwnProfile={isOwnProfile}
                                            />
                                            {/* Expand endorsers */}
                                            {skill.endorsement_count > 0 && (
                                                <button
                                                    onClick={() => setExpandedSkill(
                                                        expandedSkill === skill.skill_id ? null : skill.skill_id
                                                    )}
                                                    className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                                >
                                                    {expandedSkill === skill.skill_id
                                                        ? <ChevronUp className="w-3 h-3" />
                                                        : <ChevronDown className="w-3 h-3" />
                                                    }
                                                </button>
                                            )}
                                            {/* Remove button for own profile */}
                                            {isOwnProfile && (
                                                <button
                                                    onClick={() => handleRemoveSkill(skill.skill_id)}
                                                    className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-red-500 text-white text-xs flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                                >
                                                    ├ù
                                                </button>
                                            )}
                                        </div>
                                    ))}
                                </div>
                                {/* Expanded endorsers list */}
                                {catSkills.map(skill => (
                                    expandedSkill === skill.skill_id && skill.endorsers.length > 0 && (
                                        <div key={`${skill.skill_id}-endorsers`} className="mt-3 p-3 bg-gray-50 dark:bg-dark-surface-hover rounded-lg">
                                            <div className="flex items-center gap-2 mb-2">
                                                <Users className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                                <span className="text-sm text-text-light dark:text-dark-text-muted">
                                                    Endorsed by:
                                                </span>
                                            </div>
                                            <div className="flex flex-wrap gap-2">
                                                {skill.endorsers.map((endorser: Endorser) => (
                                                    <Link
                                                        key={endorser.id}
                                                        href={`/profile/${endorser.id}`}
                                                        className="flex items-center gap-2 px-2 py-1 bg-white dark:bg-dark-surface rounded-full border border-gray-200 dark:border-dark-border hover:border-primary/50 transition-colors"
                                                    >
                                                        <UserAvatar
                                                            name={endorser.name}
                                                            avatarUrl={endorser.avatar_url}
                                                            size="sm"
                                                        />
                                                        <span className="text-sm text-text dark:text-dark-text hover:text-primary transition-colors">
                                                            {endorser.name || 'Anonymous'}
                                                        </span>
                                                    </Link>
                                                ))}
                                            </div>
                                        </div>
                                    )
                                ))}
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { useTranslations } from 'next-intl'
import { hasSeenOnboarding, markOnboardingShown } from '@/lib/sessionContext'
import {
    X,
    BookOpen,
    Scale,
    Lightbulb,
    Search,
    Users,
    FileText,
    ArrowRight,
    ArrowLeft,
    Sparkles,
    Target,
    Globe,
    Calendar,
    PenSquare,
    Bot,
    GitFork,
    MessageSquare,
    BarChart3
} from 'lucide-react'
import { Button } from '@/components/ui/button'

interface Step {
    id: number
    titleKey: string
    subtitleKey: string
    content: React.ReactNode
    icon: React.ElementType
    iconBg: string
}

export function EpistemicOnboarding() {
    const t = useTranslations('Onboarding')
    const [isOpen, setIsOpen] = useState(false)
    const [currentStep, setCurrentStep] = useState(0)

    useEffect(() => {
        // Session-based onboarding - only shows once per session
        if (!hasSeenOnboarding()) {
            const timer = setTimeout(() => setIsOpen(true), 800)
            return () => clearTimeout(timer)
        }
    }, [])

    const handleDismiss = () => {
        markOnboardingShown()
        setIsOpen(false)
    }

    const handleNext = () => {
        if (currentStep < steps.length - 1) {
            setCurrentStep(prev => prev + 1)
        } else {
            handleDismiss()
        }
    }

    const handleBack = () => {
        if (currentStep > 0) {
            setCurrentStep(prev => prev - 1)
        }
    }

    const steps: Step[] = [
        {
            id: 0,
            titleKey: 'welcome.title',
            subtitleKey: 'welcome.subtitle',
            icon: Globe,
            iconBg: 'bg-primary/10 text-primary',
            content: (
                <div className="space-y-6">
                    <p className="text-base text-text-light dark:text-dark-text-muted leading-relaxed">
                        {t('welcome.description')}
                    </p>

                    <div className="grid grid-cols-2 gap-4">
                        <HighlightCard
                            icon={Target}
                            title={t('welcome.mission')}
                            description={t('welcome.missionDesc')}
                        />
                        <HighlightCard
                            icon={Users}
                            title={t('welcome.community')}
                            description={t('welcome.communityDesc')}
                        />
                    </div>

                    <div className="p-4 bg-gradient-to-r from-primary/5 to-secondary/5 dark:from-primary/10 dark:to-secondary/10 rounded-xl border border-primary/10">
                        <p className="text-sm text-text dark:text-dark-text text-center font-medium">
                            {t('welcome.tagline')}
                        </p>
                    </div>
                </div>
            )
        },
        {
            id: 1,
            titleKey: 'create.title',
            subtitleKey: 'create.subtitle',
            icon: PenSquare,
            iconBg: 'bg-secondary/10 text-secondary',
            content: (
                <div className="space-y-5">
                    <p className="text-base text-text-light dark:text-dark-text-muted leading-relaxed">
                        {t('create.description')}
                    </p>


                    <div className="grid gap-4">
                        <FeatureRow
                            icon={FileText}
                            title={t('create.articles')}
                            description={t('create.articlesDesc')}
                            highlight
                        />
                        <FeatureRow
                            icon={GitFork}
                            title={t('create.fork')}
                            description={t('create.forkDesc')}
                            highlight
                        />
                        <FeatureRow
                            icon={MessageSquare}
                            title={t('create.questions')}
                            description={t('create.questionsDesc')}
                        />
                        <FeatureRow
                            icon={Calendar}
                            title={t('create.events')}
                            description={t('create.eventsDesc')}
                        />
                    </div>
                </div>
            )
        },
        {
            id: 2,
            titleKey: 'researchLab.title',
            subtitleKey: 'researchLab.subtitle',
            icon: Lightbulb,
            iconBg: 'bg-amber-500/10 text-amber-600 dark:text-amber-400',
            content: (
                <div className="space-y-5">
                    <p className="text-base text-text-light dark:text-dark-text-muted leading-relaxed">
                        {t('researchLab.description')}
                    </p>

                    <div className="grid gap-4">
                        <FeatureRow
                            icon={Search}
                            title={t('researchLab.search')}
                            description={t('researchLab.searchDesc')}
                            tag="Available Now"
                        />
                        <FeatureRow
                            icon={Bot}
                            title={t('researchLab.advisor')}
                            description={t('researchLab.advisorDesc')}
                            tag="Available Now"
                        />
                        <FeatureRow
                            icon={BarChart3}
                            title={t('researchLab.surveys')}
                            description={t('researchLab.surveysDesc')}
                            tag="Available Now"
                        />
                        <FeatureRow
                            icon={Sparkles}
                            title={t('researchLab.graph')}
                            description={t('researchLab.graphDesc')}
                            tag="Available Now"
                        />
                    </div>
                </div>
            )
        },
        {
            id: 3,
            titleKey: 'epistemic.title',
            subtitleKey: 'epistemic.subtitle',
            icon: Scale,
            iconBg: 'bg-accent/10 text-accent',
            content: (
                <div className="space-y-5">
                    <p className="text-base text-text-light dark:text-dark-text-muted leading-relaxed">
                        {t('epistemic.description')}
                    </p>

                    <div className="space-y-4">
                        <PrincipleCard
                            number="1"
                            title={t('epistemic.principle1')}
                            description={t('epistemic.principle1Desc')}
                        />
                        <PrincipleCard
                            number="2"
                            title={t('epistemic.principle2')}
                            description={t('epistemic.principle2Desc')}
                        />
                        <PrincipleCard
                            number="3"
                            title={t('epistemic.principle3')}
                            description={t('epistemic.principle3Desc')}
                        />
                    </div>

                    <div className="p-4 bg-primary/5 dark:bg-primary/10 rounded-xl border border-primary/20">
                        <p className="text-sm text-text dark:text-dark-text italic text-center leading-relaxed">
                            {t('epistemic.tagline')}
                        </p>
                    </div>
                </div>
            )
        }
    ]

    if (!isOpen) return null

    const CurrentIcon = steps[currentStep].icon

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-3 sm:p-4 md:p-6 bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="relative w-full max-w-2xl max-h-[calc(100vh-1.5rem)] sm:max-h-[calc(100vh-2rem)] bg-white dark:bg-dark-surface rounded-2xl sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col">
                {/* Close Button */}
                <button
                    onClick={handleDismiss}
                    className="absolute top-3 right-3 sm:top-5 sm:right-5 z-10 p-1.5 sm:p-2 rounded-full text-text-light dark:text-dark-text-muted hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                    aria-label={t('closeOnboarding')}
                >
                    <X className="w-4 h-4 sm:w-5 sm:h-5" />
                </button>

                {/* Progress Indicator */}
                <div className="absolute top-4 sm:top-6 left-1/2 -translate-x-1/2 flex gap-1.5 sm:gap-2 z-10">
                    {steps.map((step, idx) => (
                        <button
                            key={step.id}
                            onClick={() => setCurrentStep(idx)}
                            className={`h-1.5 sm:h-2 rounded-full transition-all duration-300 ${idx === currentStep
                                ? 'bg-primary w-6 sm:w-8'
                                : idx < currentStep
                                    ? 'bg-primary/40 w-1.5 sm:w-2'
                                    : 'bg-gray-200 dark:bg-dark-border w-1.5 sm:w-2'
                                }`}
                            aria-label={`Step ${idx + 1}`}
                        />
                    ))}
                </div>

                {/* Main Content - Scrollable */}
                <div className="pt-12 sm:pt-16 pb-4 sm:pb-8 px-4 sm:px-8 md:px-12 overflow-y-auto flex-1">
                    {/* Icon & Title */}
                    <div className="text-center mb-5 sm:mb-8">
                        <div className={`inline-flex p-3 sm:p-4 rounded-xl sm:rounded-2xl ${steps[currentStep].iconBg} mb-3 sm:mb-5`}>
                            <CurrentIcon className="w-7 h-7 sm:w-10 sm:h-10" />
                        </div>
                        <h2 className="text-xl sm:text-2xl md:text-3xl font-bold text-text dark:text-dark-text mb-1 sm:mb-2">
                            {t(steps[currentStep].titleKey)}
                        </h2>
                        <p className="text-sm sm:text-base text-text-light dark:text-dark-text-muted">
                            {t(steps[currentStep].subtitleKey)}
                        </p>
                    </div>

                    {/* Step Content */}
                    <div className="min-h-[200px] sm:min-h-[280px] md:min-h-[300px]">
                        {steps[currentStep].content}
                    </div>
                </div>

                {/* Footer Navigation - Fixed at bottom */}
                <div className="px-4 sm:px-8 md:px-12 py-4 sm:py-6 md:pb-8 flex items-center justify-between gap-2 sm:gap-4 border-t border-gray-100 dark:border-dark-border bg-white dark:bg-dark-surface flex-shrink-0">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={handleBack}
                        disabled={currentStep === 0}
                        className={`gap-1 sm:gap-2 text-sm sm:text-base ${currentStep === 0 ? 'invisible' : ''}`}
                    >
                        <ArrowLeft className="w-3 h-3 sm:w-4 sm:h-4" />
                        <span className="hidden sm:inline">{t('back')}</span>
                    </Button>

                    <div className="flex items-center gap-1 sm:gap-2">
                        <span className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted font-medium">
                            {currentStep + 1}
                        </span>
                        <span className="text-text-light/50 dark:text-dark-text-muted/50">/</span>
                        <span className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">
                            {steps.length}
                        </span>
                    </div>

                    <Button
                        size="sm"
                        onClick={handleNext}
                        className="gap-1 sm:gap-2 bg-primary hover:bg-primary-dark text-white text-sm sm:text-base px-3 sm:px-6"
                    >
                        {currentStep === steps.length - 1 ? (
                            <span className="whitespace-nowrap">{t('beginResearch')}</span>
                        ) : (
                            <>
                                {t('next')}
                                <ArrowRight className="w-3 h-3 sm:w-4 sm:h-4" />
                            </>
                        )}
                    </Button>
                </div>
            </div>
        </div>
    )
}

