                                {onGoHome && (
                                    <Button
                                        variant="ghost"
                                        onClick={onGoHome}
                                        size="lg"
                                        className="flex-1 sm:flex-none text-text-light dark:text-dark-text-muted hover:text-primary dark:hover:text-primary-light"
                                    >
                                        <Home className="w-4 h-4 mr-2" />
                                        Home
                                    </Button>
                                )}
                            </div>
