'use client'

import Link from 'next/link'
import { Edit, Trash2 } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { useState } from 'react'

interface EventActionsProps {
    eventId: string
    isAuthor: boolean
}

export function EventActions({ eventId, isAuthor }: EventActionsProps) {
    const router = useRouter()
    const [isDeleting, setIsDeleting] = useState(false)
    const [showConfirmation, setShowConfirmation] = useState(false)

    if (!isAuthor) return null

    const handleDeleteClick = () => {
        setShowConfirmation(true)
    }

    const handleCancelDelete = () => {
        setShowConfirmation(false)
    }

    const handleConfirmDelete = async () => {
        setIsDeleting(true)
        const supabase = createClient()

        try {
            const { data, error } = await supabase
                .from('posts')
                .delete()
                .eq('id', eventId)
                .select()

            if (error) {
                console.error('Error deleting event:', error)
                alert('Failed to delete event: ' + error.message)
                setIsDeleting(false)
                setShowConfirmation(false)
            } else if (!data || data.length === 0) {
                alert('Could not delete event. You may not have permission.')
                setIsDeleting(false)
                setShowConfirmation(false)
            } else {
                router.push('/events')
                router.refresh()
            }
        } catch (error: any) {
            console.error('Error:', error)
            alert('An error occurred: ' + (error.message || 'Unknown error'))
            setIsDeleting(false)
            setShowConfirmation(false)
        }
    }

    return (
        <div className="space-y-3 mb-6">
            <Link
                href={`/events/${eventId}/edit`}
                className="flex items-center justify-center gap-2 w-full px-4 py-2 bg-secondary/10 text-secondary-dark rounded-lg hover:bg-secondary/20 transition-colors font-medium"
            >
                <Edit className="w-4 h-4" />
                Edit Event
            </Link>

            {showConfirmation ? (
                <div className="flex gap-2">
                    <button
                        onClick={handleCancelDelete}
                        disabled={isDeleting}
                        className="flex-1 px-3 py-2 text-sm text-text dark:text-dark-text rounded-lg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors font-medium"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleConfirmDelete}
                        disabled={isDeleting}
                        className="flex-1 px-3 py-2 text-sm bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors font-medium flex items-center justify-center gap-1.5"
                    >
                        {isDeleting ? (
                            <div className="w-3.5 h-3.5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        ) : (
                            <Trash2 className="w-3.5 h-3.5" />
                        )}
                        {isDeleting ? 'Deleting...' : 'Confirm Delete'}
                    </button>
                </div>
            ) : (
                <button
                    onClick={handleDeleteClick}
                    className="flex items-center justify-center gap-2 w-full px-4 py-2 text-red-600 dark:text-red-400 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors font-medium"
                >
                    <Trash2 className="w-4 h-4" />
                    Delete Event
                </button>
            )}
        </div>
    )
}

'use client'

import Link from 'next/link'
import Image from 'next/image'
import { Calendar, MapPin, Users, Clock, AlertTriangle, Trash2, X } from 'lucide-react'
import { format } from 'date-fns'
import { TagChip } from './TagChip'
import { BookmarkButton } from './BookmarkButton'
import { getAvatarGradient, getInitials } from '@/lib/utils'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { useState, useEffect } from 'react'
import { User } from '@supabase/supabase-js'
import { useTranslations } from 'next-intl'

interface EventMetadata {
    start_time: string
    end_time?: string
    location: string
    link?: string
    status?: 'scheduled' | 'cancelled' | 'postponed'
}

interface EventPost {
    id: string
    title: string
    content: string
    created_at: string
    author_id?: string
    author?: { name?: string | null, email?: string | null } | null
    tags?: string[]
    metadata: EventMetadata
    rsvp_count?: number
    approval_status?: 'pending' | 'approved' | 'rejected'
    cover_image_url?: string | null
}

interface EventCardProps {
    event: EventPost
    currentUser?: User | null
    isPast?: boolean
}

export function EventCard({ event, currentUser, isPast = false }: EventCardProps) {
    const router = useRouter()
    const t = useTranslations('Common')
    const tEvents = useTranslations('Events')
    const [isDeleting, setIsDeleting] = useState(false)
    const [showConfirmation, setShowConfirmation] = useState(false)
    const [hasMounted, setHasMounted] = useState(false)

    useEffect(() => {
        setHasMounted(true)
    }, [])

    const startDate = new Date(event.metadata.start_time)
    const endDate = event.metadata.end_time ? new Date(event.metadata.end_time) : null
    const status = event.metadata.status || 'scheduled'
    const isAuthor = currentUser?.id === event.author_id

    const handleDeleteClick = (e: React.MouseEvent) => {
        e.preventDefault()
        e.stopPropagation()
        setShowConfirmation(true)
    }

    const handleCancelDelete = (e: React.MouseEvent) => {
        e.preventDefault()
        e.stopPropagation()
        setShowConfirmation(false)
    }

    const handleConfirmDelete = async (e: React.MouseEvent) => {
        e.preventDefault()
        e.stopPropagation()

        setIsDeleting(true)
        const supabase = createClient()

        try {
            const { data, error } = await supabase
                .from('posts')
                .delete()
                .eq('id', event.id)
                .select()

            if (error) {
                console.error('Error deleting event:', error)
                alert('Failed to delete event: ' + error.message)
            } else if (!data || data.length === 0) {
                alert('Could not delete event. You may not have permission.')
            } else {
                router.refresh()
            }
        } catch (error: any) {
            console.error('Error:', error)
            alert('An error occurred: ' + (error.message || 'Unknown error'))
        } finally {
            setIsDeleting(false)
            setShowConfirmation(false)
        }
    }

    if (isDeleting) {
        return (
            <div className="card h-[200px] flex items-center justify-center bg-gray-50 dark:bg-dark-surface/50 opacity-50">
                <div className="flex flex-col items-center gap-2">
                    <div className="w-6 h-6 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                    <span className="text-sm text-text-light">{t('deleting')}</span>
                </div>
            </div>
        )
    }

    return (
        <div className="card hover:border-primary/50 transition-colors group flex flex-col md:flex-row overflow-hidden relative min-h-[160px]">
            {/* Actions for Author (Delete) and all users (Bookmark) */}
            <div className="absolute top-3 right-3 z-30 flex items-center gap-2 pointer-events-auto">
                {isPast && hasMounted && (
                    <div className="flex-shrink-0 inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold bg-gray-500/20 text-gray-400 dark:bg-gray-600/30 dark:text-gray-300 shadow-sm border border-gray-400/20 dark:border-gray-500/30">
                        <Clock className="w-3.5 h-3.5 flex-shrink-0" />
                        <span className="translate-y-[1.65px]">{tEvents('ended')}</span>
                    </div>
                )}
                {event.approval_status === 'rejected' && hasMounted && (
                    <div className="flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold bg-red-600 text-white shadow-lg border border-red-500 animate-fade-in-up">
                        <AlertTriangle className="w-3.5 h-3.5" />
                        {tEvents('rejected')}
                    </div>
                )}
                <div className="flex items-center bg-white/90 dark:bg-dark-surface/90 backdrop-blur-md rounded-full border border-gray-100 dark:border-dark-border shadow-sm">
                    <BookmarkButton postId={event.id} className="p-2" />
                </div>

                {isAuthor && (
                    <>
                        {showConfirmation ? (
                            <div className="flex items-center gap-1 bg-white dark:bg-dark-surface rounded-full shadow-md border border-gray-200 dark:border-dark-border p-1">
                                <button
                                    onClick={handleCancelDelete}
                                    className="p-1.5 text-text-light hover:text-text dark:text-dark-text-muted dark:hover:text-dark-text rounded-full hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                                    title={t('cancel')}
                                >
                                    <X className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={handleConfirmDelete}
                                    className="px-2.5 py-1 text-xs font-medium bg-red-600 text-white rounded-full hover:bg-red-700 transition-colors flex items-center gap-1"
                                >
                                    <Trash2 className="w-3 h-3" />
                                    {t('delete')}
                                </button>
                            </div>
                        ) : (
                            <button
                                onClick={handleDeleteClick}
                                className="p-2.5 text-text-light hover:text-red-600 dark:text-dark-text-muted dark:hover:text-red-400 bg-white/80 dark:bg-dark-surface/80 rounded-full shadow-sm border border-gray-100 dark:border-dark-border hover:border-red-200 dark:hover:border-red-800 transition-colors"
                                title={tEvents('deleteEvent')}
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        )}
                    </>
                )}
            </div>

            {/* Date Badge with optional background image */}
            <div className={`
                min-w-[120px] p-6 flex flex-col items-center justify-center text-center border-b md:border-b-0 md:border-r border-gray-100 dark:border-dark-border relative overflow-hidden
                ${status === 'cancelled' ? 'bg-red-50 dark:bg-red-900/10' :
                    status === 'postponed' ? 'bg-amber-50 dark:bg-amber-900/10' :
                        'bg-primary/5 dark:bg-primary/10'}
            `}>
                {/* Background image with overlay */}
                {event.cover_image_url && (
                    <>
                        <Image
                            src={event.cover_image_url}
                            alt=""
                            fill
                            className="absolute inset-0 object-cover opacity-40"
                            sizes="(max-width: 768px) 100vw, 33vw"
                        />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/30 to-black/10" />
                    </>
                )}
                <span className={`relative z-10 text-sm font-bold uppercase tracking-wider ${status === 'cancelled' ? 'text-red-600 dark:text-red-400' :
                    status === 'postponed' ? 'text-amber-600 dark:text-amber-400' :
                        event.cover_image_url ? 'text-white' : 'text-primary'
                    }`}>
                    {status === 'scheduled' ? format(startDate, 'MMM') : status}
                </span>
                <span className={`relative z-10 text-3xl font-bold my-1 ${event.cover_image_url ? 'text-white drop-shadow-md' : 'text-text dark:text-dark-text'}`}>
                    {format(startDate, 'd')}
                </span>
                <span className={`relative z-10 text-sm ${event.cover_image_url ? 'text-white/80' : 'text-text-light dark:text-dark-text-muted'}`}>
                    {format(startDate, 'yyyy')}
                </span>
            </div>

            <div className="p-6 flex-1 min-w-0">
                <div className="flex flex-col gap-4 h-full justify-between">
                    <div>
                        <div className="flex items-start justify-between gap-4 mb-2">
                            <Link href={`/events/${event.id}`} className="group-hover:text-primary transition-colors">
                                <h3 className={`text-xl font-bold line-clamp-2 ${status === 'cancelled' || event.approval_status === 'rejected' ? 'text-text-light dark:text-dark-text-muted line-through' : 'text-text dark:text-dark-text'}`}>
                                    {event.title}
                                </h3>
                            </Link>
                        </div>

                        <div className="flex flex-wrap gap-4 text-sm text-text-light dark:text-dark-text-muted mb-4">
                            <div className="flex items-center gap-1.5" suppressHydrationWarning>
                                <Clock className="w-4 h-4" />
                                <span>
                                    {hasMounted ? (
                                        <>
                                            {format(startDate, 'h:mm a')}
                                            {endDate && ` - ${format(endDate, 'h:mm a')}`}
                                        </>
                                    ) : (
                                        '--:--'
                                    )}
                                </span>
                            </div>
                            <div className="flex items-center gap-1.5">
                                <MapPin className="w-4 h-4" />
                                <span className="truncate max-w-[200px]">{event.metadata.location}</span>
                            </div>
                        </div>

                        <p className="text-text-light dark:text-dark-text-muted line-clamp-2 mb-4 text-sm">
                            {event.content}
                        </p>
                    </div>

                    <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-100 dark:border-dark-border">
                        <div className="flex flex-wrap gap-2">
                            {event.tags?.slice(0, 3).map(tag => (
                                <TagChip key={tag} tag={tag} size="sm" />
                            ))}
                        </div>

                        <div className="flex items-center gap-1.5 text-sm font-medium text-text dark:text-dark-text">
                            <Users className="w-4 h-4 text-primary" />
                            <span>{event.rsvp_count || 0} {t('attending')}</span>
                        </div>
                    </div>

                    {/* Author & Footer */}
                    <div className="flex items-center justify-between mt-4 pt-4 border-t border-gray-100 dark:border-dark-border">
                        {event.author && (
                            <div className="flex items-center gap-2">
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-medium text-white ${getAvatarGradient(event.author_id)}`}>
                                    {getInitials(event.author.name || undefined, event.author.email || undefined)}
                                </div>
                                <span className="text-sm text-text-light dark:text-dark-text-muted truncate max-w-[150px]">
                                    {event.author.name || event.author.email?.split('@')[0]}
                                </span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { Download, FileText, FileJson, Globe, ChevronDown, Check, Loader2, BookOpen, GraduationCap } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
    DropdownMenuSeparator,
    DropdownMenuLabel,
} from '@/components/ui/dropdown-menu'
import { useToast } from '@/components/ui/toast'
import {
    generateCitation,
    downloadCitation,
    getCitationFileExtension,
    type CitationFormat,
    type CitationData
} from '@/lib/citations'

interface ExportButtonProps {
    postId: string
    postTitle: string
    postAuthor?: {
        name?: string
        email?: string
    }
    postCreatedAt?: string
    postTags?: string[]
    postContent?: string
}

type ExportFormat = 'markdown' | 'html' | 'json'

const documentFormats = {
    markdown: { label: 'Markdown (.md)', icon: FileText, ext: 'md' },
    html: { label: 'HTML (.html)', icon: Globe, ext: 'html' },
    json: { label: 'JSON (.json)', icon: FileJson, ext: 'json' },
}

const citationFormats: { format: CitationFormat; label: string }[] = [
    { format: 'bibtex', label: 'BibTeX (.bib)' },
    { format: 'ris', label: 'RIS (Zotero, EndNote)' },
    { format: 'apa', label: 'APA 7th Edition' },
    { format: 'mla', label: 'MLA 9th Edition' },
    { format: 'chicago', label: 'Chicago 17th Edition' },
]

export function ExportButton({
    postId,
    postTitle,
    postAuthor,
    postCreatedAt,
    postTags,
    postContent
}: ExportButtonProps) {
    const [exporting, setExporting] = useState(false)
    const [lastExported, setLastExported] = useState<string | null>(null)
    const { showToast } = useToast()

    const handleExport = async (format: ExportFormat) => {
        setExporting(true)
        try {
            const response = await fetch(`/api/export?id=${postId}&format=${format}`)

            if (!response.ok) {
                throw new Error('Export failed')
            }

            // Get the blob and create download
            const blob = await response.blob()
            const filename = `${postTitle.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').substring(0, 50)}.${documentFormats[format].ext}`

            const url = URL.createObjectURL(blob)
            const a = document.createElement('a')
            a.href = url
            a.download = filename
            document.body.appendChild(a)
            a.click()
            document.body.removeChild(a)
            URL.revokeObjectURL(url)

            setLastExported(format)
            showToast(`Exported as ${documentFormats[format].label}`, 'success')
        } catch (error) {
            console.error('Export error:', error)
            showToast('Failed to export post', 'error')
        } finally {
            setExporting(false)
        }
    }

    const handleCitationExport = (format: CitationFormat) => {
        try {
            const citationData: CitationData = {
                id: postId,
                title: postTitle,
                author: postAuthor || { name: 'Unknown Author' },
                created_at: postCreatedAt || new Date().toISOString(),
                tags: postTags,
                content: postContent,
                url: typeof window !== 'undefined'
                    ? `${window.location.origin}/post/${postId}`
                    : undefined,
            }

            // For text formats, copy to clipboard
            if (format === 'apa' || format === 'mla' || format === 'chicago') {
                const citation = generateCitation(citationData, format)
                navigator.clipboard.writeText(citation)
                showToast(`${format.toUpperCase()} citation copied to clipboard`, 'success')
            } else {
                // For BibTeX and RIS, download as file
                downloadCitation(citationData, format)
                showToast(`Downloaded ${format.toUpperCase()} file`, 'success')
            }

            setLastExported(format)
        } catch (error) {
            console.error('Citation export error:', error)
            showToast('Failed to generate citation', 'error')
        }
    }

    return (
        <DropdownMenu>
            <DropdownMenuTrigger asChild>
                <Button variant="outline" className="gap-2" disabled={exporting}>
                    {exporting ? (
                        <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                        <Download className="w-4 h-4" />
                    )}
                    Export
                    <ChevronDown className="w-3 h-3" />
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-56">
                {/* Document Formats */}
                <DropdownMenuLabel className="flex items-center gap-2 text-xs">
                    <FileText className="w-3.5 h-3.5" />
                    Document Formats
                </DropdownMenuLabel>
                {(Object.entries(documentFormats) as [ExportFormat, typeof documentFormats.markdown][]).map(([format, config]) => {
                    const Icon = config.icon
                    return (
                        <DropdownMenuItem
                            key={format}
                            onClick={() => handleExport(format)}
                            className="flex items-center gap-2 cursor-pointer"
                        >
                            <Icon className="w-4 h-4" />
                            {config.label}
                            {lastExported === format && (
                                <Check className="w-3 h-3 ml-auto text-green-500" />
                            )}
                        </DropdownMenuItem>
                    )
                })}

                <DropdownMenuSeparator />

                {/* Citation Formats */}
                <DropdownMenuLabel className="flex items-center gap-2 text-xs">
                    <GraduationCap className="w-3.5 h-3.5" />
                    Citation Formats
                </DropdownMenuLabel>
                {citationFormats.map(({ format, label }) => (
                    <DropdownMenuItem
                        key={format}
                        onClick={() => handleCitationExport(format)}
                        className="flex items-center gap-2 cursor-pointer"
                    >
                        <BookOpen className="w-4 h-4" />
                        {label}
                        {lastExported === format && (
                            <Check className="w-3 h-3 ml-auto text-green-500" />
                        )}
                    </DropdownMenuItem>
                ))}
            </DropdownMenuContent>
        </DropdownMenu>
    )
}

'use client'

import React from 'react'
import Link from 'next/link'
import { cn, stripMarkdown } from '@/lib/utils'
import { Clock, ArrowUpRight, TrendingUp, Calendar } from 'lucide-react'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import { useCoverWithFallback } from '@/lib/coverImages'

type FeaturedSize = 'large' | 'medium' | 'small'

interface FeaturedPostProps {
    post: {
        id: string
        title: string
        content?: string
        excerpt?: string
        created_at: string
        author?: {
            id: string
            name?: string
            email?: string
            avatar_url?: string
        }
        tags?: string[]
        views?: number
        cover_image_url?: string | null
        content_type?: string | null
        metadata?: {
            start_time?: string
            end_time?: string
            location?: string
            status?: string
        } | null
    }
    size?: FeaturedSize
    showTrending?: boolean
    accentColor?: 'primary' | 'accent' | 'secondary'
    className?: string
}

// Get reading time
function getReadingTime(content?: string): number {
    if (!content) return 3
    const words = content.trim().split(/\s+/).length
    return Math.max(1, Math.ceil(words / 200))
}

// Get initials
function getInitials(name?: string, email?: string): string {
    if (name) return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)
    if (email) return email[0].toUpperCase()
    return 'U'
}

// Accent color classes
const accentClasses = {
    primary: {
        bg: 'bg-primary',
        bgLight: 'bg-primary/10 dark:bg-primary-light/20',
        text: 'text-primary dark:text-primary-light',
        gradient: 'from-primary/80 via-primary/60 to-primary/40',
    },
    accent: {
        bg: 'bg-accent',
        bgLight: 'bg-accent/20',
        text: 'text-accent-dark dark:text-accent',
        gradient: 'from-accent/80 via-accent/60 to-accent/40',
    },
    secondary: {
        bg: 'bg-secondary',
        bgLight: 'bg-secondary/20',
        text: 'text-secondary-dark dark:text-secondary',
        gradient: 'from-secondary/80 via-secondary/60 to-secondary/40',
    },
}

// Format event date
function formatEventDate(dateString?: string, locale: string = 'en'): string {
    if (!dateString) return 'Date TBD'
    const date = new Date(dateString)
    return date.toLocaleDateString(locale === 'ar' ? 'ar-SA' : 'en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

export function FeaturedPost({
    post,
    size = 'large',
    showTrending = false,
    accentColor = 'primary',
    className,
}: FeaturedPostProps) {
    const t = useTranslations('Landing')
    const { formatDate, locale } = useDateFormatter()
    const readingTime = getReadingTime(post.content)
    const colors = accentClasses[accentColor]
    const isEvent = post.content_type === 'event'

    // Get cover image with theme-aware fallback
    const coverImage = useCoverWithFallback(post.cover_image_url, size === 'large' ? 'large' : 'medium')

    // Format event date using calendar-aware formatting
    const eventDate = isEvent && post.metadata?.start_time ? formatDate(post.metadata.start_time, 'medium') : ''

    // Large variant - full hero-style card
    if (size === 'large') {
        return (
            <Link
                href={isEvent ? `/events/${post.id}` : `/post/${post.id}`}
                className={cn(
                    'group relative flex flex-col justify-end',
                    'h-full min-h-[280px] md:min-h-[350px]',
                    'rounded-3xl overflow-hidden',
                    'transition-all duration-500',
                    'hover:shadow-soft-xl',
                    'bg-white dark:bg-gray-900', // Fix for white flickering
                    'isolation-auto', // Fix stacking context
                    className
                )}
            >
                {/* Background */}
                <div className="absolute inset-0">
                    <div
                        className="absolute inset-0 bg-cover bg-center transition-transform duration-700 group-hover:scale-105 will-change-transform"
                        style={{ backgroundImage: `url(${coverImage})` }}
                    />
                    {/* Overlay - semi-transparent to show cover image */}
                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/30 to-black/10" />
                </div>

                {/* Content */}
                <div className="relative z-10 p-8 md:p-10 space-y-6">
                    {/* Top Row */}
                    <div className="flex items-center justify-between">
                        {/* Tags */}
                        {post.tags && post.tags.length > 0 && (
                            <div className="flex flex-wrap gap-2">
                                {post.tags.slice(0, 3).map((tag) => (
                                    <span
                                        key={tag}
                                        className="px-3 py-1.5 text-xs font-semibold bg-white/20 backdrop-blur-sm text-white rounded-full uppercase tracking-wider"
                                    >
                                        {tag}
                                    </span>
                                ))}
                            </div>
                        )}

                        {/* Badges */}
                        <div className="flex gap-2">
                            {showTrending && (
                                <div className="flex items-center gap-2 px-3 py-1.5 bg-accent rounded-full shadow-sm">
                                    <TrendingUp className="w-3.5 h-3.5 text-white" />
                                    <span className="text-xs font-bold text-white uppercase tracking-wider">
                                        {t('trending')}
                                    </span>
                                </div>
                            )}
                            {isEvent && (
                                <div className="flex items-center gap-2 px-3 py-1.5 bg-primary rounded-full shadow-sm">
                                    <Calendar className="w-3.5 h-3.5 text-white" />
                                    <span className="text-xs font-bold text-white uppercase tracking-wider">
                                        {t('event')}
                                    </span>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Title */}
                    <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold text-white leading-tight tracking-tight">
                        {post.title}
                    </h2>

                    {/* Excerpt */}
                    {post.excerpt && (
                        <p className="text-lg text-white/80 line-clamp-2 max-w-2xl">
                            {stripMarkdown(post.excerpt)}
                        </p>
                    )}

                    {/* Footer */}
                    <div className="flex items-center justify-between pt-4 border-t border-white/20">
                        {/* Author */}
                        {post.author && (
                            <div className="flex items-center gap-3">
                                <div className={cn(
                                    'w-10 h-10 rounded-full flex items-center justify-center',
                                    'text-sm font-bold text-white',
                                    'bg-white/20 backdrop-blur-sm'
                                )}>
                                    {getInitials(post.author.name, post.author.email)}
                                </div>
                                <div>
                                    <div className="font-medium text-white">
                                        {post.author.name || post.author.email?.split('@')[0]}
                                    </div>
                                    <div className="text-sm text-white/60">
                                        {isEvent ? eventDate : formatDate(post.created_at, 'medium')}
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Read more */}
                        <div className="flex items-center gap-4">
                            {!isEvent && (
                                <div className="flex items-center gap-1.5 text-white/70">
                                    <Clock className="w-4 h-4" />
                                    <span className="text-sm">{t('minRead', { count: readingTime })}</span>
                                </div>
                            )}
                            <div className="w-12 h-12 rounded-full bg-white/10 backdrop-blur-sm flex items-center justify-center transition-all group-hover:bg-white group-hover:scale-110">
                                <ArrowUpRight className="w-5 h-5 text-white group-hover:text-primary transition-colors" />
                            </div>
                        </div>
                    </div>
                </div>
            </Link>
        )
    }

    // Medium variant - balanced card
    if (size === 'medium') {
        return (
            <Link
                href={isEvent ? `/events/${post.id}` : `/post/${post.id}`}
                className={cn(
                    'group relative flex flex-col justify-end',
                    'h-full min-h-[280px]',
                    'rounded-2xl overflow-hidden',
                    'transition-all duration-300',
                    'hover:shadow-soft-lg hover:-translate-y-1',
                    'bg-white dark:bg-gray-900',
                    className
                )}
            >
                {/* Background */}
                <div className="absolute inset-0">
                    <div
                        className="absolute inset-0 bg-cover bg-center transition-transform duration-500 group-hover:scale-105 will-change-transform"
                        style={{ backgroundImage: `url(${coverImage})` }}
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent" />
                </div>

                {/* Content */}
                <div className="relative z-10 p-6 space-y-3">
                    <div className="flex items-center justify-between">
                        {post.tags && post.tags.length > 0 && !isEvent && (
                            <span className="text-xs font-semibold uppercase tracking-wider text-white/80">
                                {post.tags[0]}
                            </span>
                        )}
                        {isEvent && (
                            <span className="text-xs font-bold text-white bg-primary/80 backdrop-blur-md px-2 py-0.5 rounded-full uppercase tracking-wider">
                                {t('event')}
                            </span>
                        )}
                    </div>

                    <h3 className="text-xl md:text-2xl font-bold text-white leading-tight line-clamp-2">
                        {post.title}
                    </h3>

                    <div className="flex items-center gap-4 text-sm text-white/70">
                        {isEvent ? (
                            <div className="flex items-center gap-1.5 font-medium text-white/90">
                                <Calendar className="w-4 h-4" />
                                <span>{eventDate}</span>
                            </div>
                        ) : (
                            <span>{t('minRead', { count: readingTime })}</span>
                        )}

                        {post.views !== undefined && !isEvent && (
                            <>
                                <span>ΓÇó</span>
                                <span>{post.views} views</span>
                            </>
                        )}
                    </div>
                </div>
            </Link>
        )
    }

    // Small variant - compact card
    return (
        <Link
            href={isEvent ? `/events/${post.id}` : `/post/${post.id}`}
            className={cn(
                'group flex flex-col h-full',
                'p-5 rounded-xl',
                'bg-white dark:bg-dark-surface',
                'border border-gray-100 dark:border-dark-border',
                'transition-all duration-200',
                'hover:shadow-soft-md hover:-translate-y-0.5',
                className
            )}
        >
            {/* Category indicator */}
            <div className="flex items-center gap-2 mb-3">
                {isEvent ? (
                    <span className="text-[11px] font-medium text-text-light dark:text-dark-text-muted bg-gray-100/80 dark:bg-dark-border/50 backdrop-blur-sm px-2.5 py-1 rounded-full uppercase tracking-wider">
                        {t('event')}
                    </span>
                ) : (
                    <>
                        <div className={cn('w-2 h-2 rounded-full', colors.bg)} />
                        <span className={cn('text-xs font-semibold uppercase tracking-wider', colors.text)}>
                            {post.tags?.[0] || 'Research'}
                        </span>
                    </>
                )}
            </div>

            <h3 className="text-base font-semibold text-text dark:text-dark-text line-clamp-2 group-hover:text-primary transition-colors flex-1">
                {post.title}
            </h3>

            <div className="mt-4 pt-3 border-t border-gray-100 dark:border-dark-border flex items-center justify-between text-xs text-text-muted dark:text-dark-text-muted">
                {isEvent ? (
                    <div className="flex items-center gap-1.5 w-full">
                        <Calendar className="w-3.5 h-3.5" />
                        <span>{eventDate}</span>
                    </div>
                ) : (
                    <>
                        <span>{formatDate(post.created_at, 'short')}</span>
                        <span>{t('minRead', { count: readingTime })}</span>
                    </>
                )}
            </div>
        </Link>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useTranslations } from 'next-intl'
import { useRouter } from 'next/navigation'
import { X, BookOpen, MessageSquare, Quote, PenSquare, ArrowRight, Sparkles, ChevronRight } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { hasSeenOnboarding } from '@/lib/sessionContext'

const FIRST_CONTRIBUTION_KEY = 'syriahub_first_contribution_shown'
const FIRST_CONTRIBUTION_COMPLETED_KEY = 'syriahub_first_contribution_completed'

interface ContributionStep {
    id: 'browse' | 'comment' | 'cite' | 'publish'
    icon: React.ElementType
    titleKey: string
    descriptionKey: string
    actionKey: string
    href: string
}

export function FirstContributionPrompt() {
    const t = useTranslations('FirstContribution')
    const router = useRouter()
    const [isVisible, setIsVisible] = useState(false)
    const [currentStepIndex, setCurrentStepIndex] = useState(0)
    const [completedSteps, setCompletedSteps] = useState<string[]>([])

    const steps: ContributionStep[] = [
        {
            id: 'browse',
            icon: BookOpen,
            titleKey: 'browse.title',
            descriptionKey: 'browse.description',
            actionKey: 'browse.action',
            href: '/insights'
        },
        {
            id: 'comment',
            icon: MessageSquare,
            titleKey: 'comment.title',
            descriptionKey: 'comment.description',
            actionKey: 'comment.action',
            href: '/insights'
        },
        {
            id: 'cite',
            icon: Quote,
            titleKey: 'cite.title',
            descriptionKey: 'cite.description',
            actionKey: 'cite.action',
            href: '/research-lab'
        },
        {
            id: 'publish',
            icon: PenSquare,
            titleKey: 'publish.title',
            descriptionKey: 'publish.description',
            actionKey: 'publish.action',
            href: '/editor'
        }
    ]

    useEffect(() => {
        // Load completed steps from local storage
        if (typeof window === 'undefined') return

        try {
            const saved = localStorage.getItem('syriahub_contribution_steps')
            if (saved) {
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setCompletedSteps(JSON.parse(saved))
            }
        } catch {
            // Ignore parse errors
        }
    }, [])

    useEffect(() => {
        // Only show after onboarding has been completed
        if (typeof window === 'undefined') return

        const hasSeenPrompt = localStorage.getItem(FIRST_CONTRIBUTION_KEY)
        const hasCompletedPrompt = localStorage.getItem(FIRST_CONTRIBUTION_COMPLETED_KEY)

        // Show prompt if:
        // 1. User has completed onboarding
        // 2. User hasn't dismissed this prompt
        // 3. User hasn't completed all steps
        if (hasSeenOnboarding() && !hasSeenPrompt && !hasCompletedPrompt) {
            // Delay appearance to not overwhelm
            const timer = setTimeout(() => setIsVisible(true), 2000)
            return () => clearTimeout(timer)
        }
    }, [])

    const handleDismiss = () => {
        localStorage.setItem(FIRST_CONTRIBUTION_KEY, 'true')
        setIsVisible(false)
    }

    const handleStepClick = (step: ContributionStep, index: number) => {
        // Mark this step as the current focus
        setCurrentStepIndex(index)

        // Navigate to the relevant page
        router.push(step.href)

        // Mark step as completed (optimistically)
        const newCompleted = [...completedSteps, step.id]
        setCompletedSteps(newCompleted)
        localStorage.setItem('syriahub_contribution_steps', JSON.stringify(newCompleted))

        // If all steps completed, mark the whole prompt as done
        if (newCompleted.length >= steps.length) {
            localStorage.setItem(FIRST_CONTRIBUTION_COMPLETED_KEY, 'true')
            setIsVisible(false)
        }
    }

    const handleSkipAll = () => {
        localStorage.setItem(FIRST_CONTRIBUTION_KEY, 'true')
        setIsVisible(false)
    }

    if (!isVisible) return null

    const CurrentIcon = steps[currentStepIndex].icon

    return (
        <div className="fixed bottom-6 end-6 z-40 w-full max-w-sm animate-slide-up">
            <div className="bg-white dark:bg-dark-surface rounded-2xl shadow-2xl border border-gray-100 dark:border-dark-border overflow-hidden">
                {/* Header */}
                <div className="relative px-5 pt-5 pb-4 bg-gradient-to-r from-primary/5 via-secondary/5 to-accent/5 dark:from-primary/10 dark:via-secondary/10 dark:to-accent/10">
                    <button
                        onClick={handleDismiss}
                        className="absolute top-3 end-3 p-1.5 rounded-full text-text-light dark:text-dark-text-muted hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                        aria-label={t('dismiss')}
                    >
                        <X className="w-4 h-4" />
                    </button>

                    <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-primary/10 dark:bg-primary/20 rounded-xl">
                            <Sparkles className="w-5 h-5 text-primary" />
                        </div>
                        <div>
                            <h3 className="text-base font-semibold text-text dark:text-dark-text">
                                {t('title')}
                            </h3>
                            <p className="text-xs text-text-light dark:text-dark-text-muted">
                                {t('subtitle')}
                            </p>
                        </div>
                    </div>

                    {/* Progress bar */}
                    <div className="flex gap-1.5 mt-4">
                        {steps.map((step, idx) => (
                            <div
                                key={step.id}
                                className={`h-1.5 flex-1 rounded-full transition-colors ${completedSteps.includes(step.id)
                                    ? 'bg-primary'
                                    : 'bg-gray-200 dark:bg-dark-border'
                                    }`}
                            />
                        ))}
                    </div>
                </div>

                {/* Steps */}
                <div className="px-3 py-3 space-y-1 max-h-64 overflow-y-auto">
                    {steps.map((step, idx) => {
                        const StepIcon = step.icon
                        const isCompleted = completedSteps.includes(step.id)
                        const isCurrent = idx === currentStepIndex && !isCompleted

                        return (
                            <button
                                key={step.id}
                                onClick={() => handleStepClick(step, idx)}
                                className={`w-full flex items-center gap-3 p-3 rounded-xl text-start transition-all ${isCompleted
                                    ? 'bg-primary/5 dark:bg-primary/10'
                                    : isCurrent
                                        ? 'bg-gray-50 dark:bg-dark-bg ring-2 ring-primary/20'
                                        : 'hover:bg-gray-50 dark:hover:bg-dark-bg'
                                    }`}
                            >
                                <div className={`p-2 rounded-lg ${isCompleted
                                    ? 'bg-primary/20 text-primary'
                                    : 'bg-gray-100 dark:bg-dark-border text-text-light dark:text-dark-text-muted'
                                    }`}>
                                    <StepIcon className="w-4 h-4" />
                                </div>

                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2">
                                        <span className={`text-sm font-medium ${isCompleted
                                            ? 'text-primary line-through'
                                            : 'text-text dark:text-dark-text'
                                            }`}>
                                            {t(step.titleKey)}
                                        </span>
                                        {isCompleted && (
                                            <span className="text-[10px] px-1.5 py-0.5 bg-primary/10 text-primary rounded-full font-medium">
                                                Γ£ô
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-xs text-text-light dark:text-dark-text-muted truncate">
                                        {t(step.descriptionKey)}
                                    </p>
                                </div>

                                <ChevronRight className={`w-4 h-4 flex-shrink-0 ${isCompleted
                                    ? 'text-primary'
                                    : 'text-gray-300 dark:text-dark-border'
                                    }`} />
                            </button>
                        )
                    })}
                </div>

                {/* Footer */}
                <div className="px-5 py-3 border-t border-gray-100 dark:border-dark-border flex items-center justify-between">
                    <button
                        onClick={handleSkipAll}
                        className="text-xs text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text transition-colors"
                    >
                        {t('skipForNow')}
                    </button>

                    <span className="text-xs text-text-light/60 dark:text-dark-text-muted/60">
                        {completedSteps.length}/{steps.length} {t('completed')}
                    </span>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { UserPlus, UserCheck, Loader2 } from 'lucide-react'
import { cn } from '@/lib/utils'

interface FollowButtonProps {
    userId: string
    className?: string
    variant?: 'default' | 'compact'
}

export function FollowButton({ userId, className, variant = 'default' }: FollowButtonProps) {
    const [isFollowing, setIsFollowing] = useState(false)
    const [loading, setLoading] = useState(true)
    const [toggling, setToggling] = useState(false)
    const supabase = createClient()

    useEffect(() => {
        const checkFollowStatus = async () => {
            try {
                const { data: { user } } = await supabase.auth.getUser()

                if (user && user.id !== userId) {
                    const { data } = await supabase
                        .from('follows')
                        .select('id')
                        .eq('follower_id', user.id)
                        .eq('following_id', userId)
                        .maybeSingle()

                    setIsFollowing(!!data)
                }
            } catch (error) {
                // Not following or not logged in
            } finally {
                setLoading(false)
            }
        }

        checkFollowStatus()
    }, [userId, supabase])

    const toggleFollow = async () => {
        setToggling(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()

            if (!user) return
            if (user.id === userId) return // Can't follow yourself

            if (isFollowing) {
                await supabase
                    .from('follows')
                    .delete()
                    .eq('follower_id', user.id)
                    .eq('following_id', userId)

                setIsFollowing(false)
            } else {
                await supabase
                    .from('follows')
                    .insert({ follower_id: user.id, following_id: userId })

                setIsFollowing(true)
            }
        } catch (error) {
            console.error('Error toggling follow:', error)
        } finally {
            setToggling(false)
        }
    }

    // Don't show button for own profile
    const [isOwnProfile, setIsOwnProfile] = useState(false)
    useEffect(() => {
        const checkOwnProfile = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            setIsOwnProfile(user?.id === userId)
        }
        checkOwnProfile()
    }, [userId, supabase])

    if (loading || isOwnProfile) {
        return null
    }

    if (variant === 'compact') {
        return (
            <button
                onClick={toggleFollow}
                disabled={toggling}
                className={cn(
                    'p-1.5 rounded-md transition-colors',
                    isFollowing
                        ? 'text-primary dark:text-accent-light'
                        : 'text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text',
                    className
                )}
                title={isFollowing ? 'Unfollow' : 'Follow'}
            >
                {toggling ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                ) : isFollowing ? (
                    <UserCheck className="w-4 h-4" />
                ) : (
                    <UserPlus className="w-4 h-4" />
                )}
            </button>
        )
    }

    return (
        <button
            onClick={toggleFollow}
            disabled={toggling}
            className={cn(
                'px-3 py-1.5 text-sm rounded-md border transition-colors',
                isFollowing
                    ? 'border-primary dark:border-accent-light text-primary dark:text-accent-light'
                    : 'border-gray-300 dark:border-dark-border text-text-light dark:text-dark-text-muted hover:border-gray-400 dark:hover:border-gray-600',
                className
            )}
        >
            {toggling ? (
                <Loader2 className="w-4 h-4 animate-spin inline mr-1" />
            ) : isFollowing ? (
                <>
                    <UserCheck className="w-4 h-4 inline mr-1" />
                    Following
                </>
            ) : (
                <>
                    <UserPlus className="w-4 h-4 inline mr-1" />
                    Follow
                </>
            )}
        </button>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { GitFork, Loader2 } from 'lucide-react'
import { useTranslations } from 'next-intl'
import { useToast } from '@/components/ui/toast'

interface ForkButtonProps {
    postId: string
    postTitle: string
    postContent: string
    postTags: string[]
    iconOnly?: boolean
}

export function ForkButton({ postId, postTitle, postContent, postTags, iconOnly }: ForkButtonProps) {
    const [isForking, setIsForking] = useState(false)
    const router = useRouter()
    const supabase = createClient()
    const { showToast } = useToast()
    const t = useTranslations('Post')
    const tc = useTranslations('Common')

    const handleFork = async () => {
        setIsForking(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()

            if (!user) {
                showToast(t('loginRequired'), 'error')
                return
            }

            // Create a new post as a fork (Remix)
            const { data: newPost, error: forkError } = await supabase
                .from('posts')
                .insert({
                    title: t('remixOf', { title: postTitle }),
                    content: postContent,
                    tags: postTags,
                    content_type: 'article', // Assuming 'article' as a default or inherited from original
                    author_id: user.id,
                    forked_from_id: postId,
                    status: 'published'
                })
                .select()
                .single()

            if (forkError) throw forkError

            showToast(t('suggestionSuccess'), 'success')
            // Redirect to the new post
            router.push(`/editor?id=${newPost.id}`)
        } catch (error) {
            console.error('Error remixing post:', error)
            showToast(t('suggestionError'), 'error')
        } finally {
            setIsForking(false)
        }
    }

    return (
        <Button
            variant="outline"
            size={iconOnly ? "icon" : "sm"}
            onClick={handleFork}
            disabled={isForking}
            className={iconOnly ? "" : "gap-2"}
            title={t('remix')}
        >
            {isForking ? <Loader2 className="h-4 w-4 animate-spin" /> : <GitFork className="h-4 w-4" />}
            {!iconOnly && (isForking ? t('remixing') : t('remix'))}
        </Button>
    )
}

'use client'

import React, { useEffect, useState, useCallback } from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { cn, getInitials, getAvatarGradient } from '@/lib/utils'
import { createClient } from '@/lib/supabase/client'
import {
    BookOpen,
    Users,
    Lightbulb,
    Database,
    Send,
    ExternalLink,
    Clock,
    ChevronDown,
    ChevronUp,
    Plus
} from 'lucide-react'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import { Button } from '@/components/ui/button'

interface GapContribution {
    id: string
    gap_id: string
    user_id: string
    contribution_type: 'reading_suggestion' | 'collaboration_offer' | 'methodological_note' | 'data_pointer'
    content: string
    resource_url?: string
    resource_title?: string
    expertise_offered?: string
    availability_notes?: string
    status: 'active' | 'archived' | 'accepted'
    created_at: string
    user?: {
        id: string
        name?: string
        email?: string
        avatar_url?: string
    }
}

interface GapContributionsProps {
    gapId: string
    gapClaimerId?: string
    className?: string
}

const contributionTypeConfig = {
    reading_suggestion: {
        icon: BookOpen,
        label: 'Reading Suggestion',
        description: 'Recommend a resource',
        color: 'text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20'
    },
    collaboration_offer: {
        icon: Users,
        label: 'Collaboration Offer',
        description: 'Offer to work together',
        color: 'text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-900/20'
    },
    methodological_note: {
        icon: Lightbulb,
        label: 'Methodological Note',
        description: 'Suggest an approach',
        color: 'text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-900/20'
    },
    data_pointer: {
        icon: Database,
        label: 'Data Pointer',
        description: 'Link to relevant data',
        color: 'text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20'
    }
}

export function GapContributions({ gapId, gapClaimerId, className }: GapContributionsProps) {
    const t = useTranslations('GapContributions')
    const { formatDate } = useDateFormatter()
    const [contributions, setContributions] = useState<GapContribution[]>([])
    const [loading, setLoading] = useState(true)
    const [showForm, setShowForm] = useState(false)
    const [expanded, setExpanded] = useState(true)
    const [currentUserId, setCurrentUserId] = useState<string | null>(null)

    // Form state
    const [formType, setFormType] = useState<GapContribution['contribution_type']>('reading_suggestion')
    const [formContent, setFormContent] = useState('')
    const [formResourceUrl, setFormResourceUrl] = useState('')
    const [formResourceTitle, setFormResourceTitle] = useState('')
    const [formExpertise, setFormExpertise] = useState('')
    const [formAvailability, setFormAvailability] = useState('')
    const [submitting, setSubmitting] = useState(false)

    const fetchContributions = useCallback(async () => {
        const supabase = createClient()

        const { data, error } = await supabase
            .from('gap_contributions')
            .select(`
                *,
                user:users!user_id (id, name, email, avatar_url)
            `)
            .eq('gap_id', gapId)
            .eq('status', 'active')
            .order('created_at', { ascending: false })

        if (!error && data) {
            setContributions(data as GapContribution[])
        }
        setLoading(false)
    }, [gapId])

    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect -- Intentional initial data fetch
        fetchContributions()

        // Get current user
        const supabase = createClient()
        supabase.auth.getUser().then(({ data }) => {
            setCurrentUserId(data.user?.id || null)
        })
    }, [fetchContributions])

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!currentUserId || !formContent.trim()) return

        setSubmitting(true)
        const supabase = createClient()

        const contributionData = {
            gap_id: gapId,
            user_id: currentUserId,
            contribution_type: formType,
            content: formContent.trim(),
            resource_url: formResourceUrl.trim() || null,
            resource_title: formResourceTitle.trim() || null,
            expertise_offered: formExpertise.trim() || null,
            availability_notes: formAvailability.trim() || null,
            status: 'active'
        }

        const { error } = await supabase
            .from('gap_contributions')
            .insert(contributionData)

        if (!error) {
            // Reset form
            setFormContent('')
            setFormResourceUrl('')
            setFormResourceTitle('')
            setFormExpertise('')
            setFormAvailability('')
            setShowForm(false)
            fetchContributions()

            // Send notification to claimer if applicable
            if (gapClaimerId && gapClaimerId !== currentUserId) {
                await supabase.from('notifications').insert({
                    user_id: gapClaimerId,
                    type: 'gap_contribution',
                    title: t('notificationTitle'),
                    message: t('notificationMessage'),
                    link: `/research-gaps?highlight=${gapId}`,
                    read: false
                })
            }
        }

        setSubmitting(false)
    }

    const typeConfig = contributionTypeConfig[formType]

    return (
        <div className={cn('rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden', className)}>
            {/* Header */}
            <button
                onClick={() => setExpanded(!expanded)}
                className="w-full flex items-center justify-between p-4 bg-gray-50 dark:bg-dark-surface/50 hover:bg-gray-100 dark:hover:bg-dark-surface transition-colors"
            >
                <div className="flex items-center gap-2">
                    <BookOpen className="w-5 h-5 text-text-muted dark:text-dark-text-muted" />
                    <h3 className="text-base font-semibold text-text dark:text-dark-text">
                        {t('title')}
                    </h3>
                    <span className="px-2 py-0.5 text-xs font-medium bg-gray-200 dark:bg-dark-border rounded-full">
                        {contributions.length}
                    </span>
                </div>
                {expanded ? (
                    <ChevronUp className="w-5 h-5 text-text-muted" />
                ) : (
                    <ChevronDown className="w-5 h-5 text-text-muted" />
                )}
            </button>

            {expanded && (
                <div className="p-4 bg-white dark:bg-dark-bg">
                    {/* Add contribution button */}
                    {currentUserId && !showForm && (
                        <Button
                            variant="outline"
                            size="sm"
                            className="mb-4 w-full"
                            onClick={() => setShowForm(true)}
                        >
                            <Plus className="w-4 h-4 mr-1.5" />
                            {t('addContribution')}
                        </Button>
                    )}

                    {/* Contribution form */}
                    {showForm && (
                        <form onSubmit={handleSubmit} className="mb-6 p-4 rounded-lg border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-surface/50">
                            {/* Type selector */}
                            <div className="mb-4">
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                    {t('contributionType')}
                                </label>
                                <div className="grid grid-cols-2 gap-2">
                                    {(Object.keys(contributionTypeConfig) as GapContribution['contribution_type'][]).map((type) => {
                                        const config = contributionTypeConfig[type]
                                        const Icon = config.icon
                                        return (
                                            <button
                                                key={type}
                                                type="button"
                                                onClick={() => setFormType(type)}
                                                className={cn(
                                                    'flex items-center gap-2 p-3 rounded-lg border text-left transition-all',
                                                    formType === type
                                                        ? 'border-primary bg-primary/5 dark:bg-primary/10'
                                                        : 'border-gray-200 dark:border-dark-border hover:border-gray-300'
                                                )}
                                            >
                                                <Icon className={cn('w-4 h-4', formType === type ? 'text-primary' : 'text-text-muted')} />
                                                <span className={cn(
                                                    'text-sm font-medium',
                                                    formType === type ? 'text-primary' : 'text-text dark:text-dark-text'
                                                )}>
                                                    {t(`type.${type}`)}
                                                </span>
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>

                            {/* Content */}
                            <div className="mb-4">
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                    {t('content')} *
                                </label>
                                <textarea
                                    value={formContent}
                                    onChange={(e) => setFormContent(e.target.value)}
                                    placeholder={t(`placeholder.${formType}`)}
                                    className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg text-sm text-text dark:text-dark-text placeholder:text-text-muted resize-none focus:ring-2 focus:ring-primary/50 focus:border-primary"
                                    rows={3}
                                    required
                                />
                            </div>

                            {/* Resource URL (for reading_suggestion and data_pointer) */}
                            {(formType === 'reading_suggestion' || formType === 'data_pointer') && (
                                <div className="mb-4 grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                            {t('resourceUrl')}
                                        </label>
                                        <input
                                            type="url"
                                            value={formResourceUrl}
                                            onChange={(e) => setFormResourceUrl(e.target.value)}
                                            placeholder="https://..."
                                            className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg text-sm text-text dark:text-dark-text placeholder:text-text-muted focus:ring-2 focus:ring-primary/50 focus:border-primary"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                            {t('resourceTitle')}
                                        </label>
                                        <input
                                            type="text"
                                            value={formResourceTitle}
                                            onChange={(e) => setFormResourceTitle(e.target.value)}
                                            placeholder={t('resourceTitlePlaceholder')}
                                            className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg text-sm text-text dark:text-dark-text placeholder:text-text-muted focus:ring-2 focus:ring-primary/50 focus:border-primary"
                                        />
                                    </div>
                                </div>
                            )}

                            {/* Collaboration offer fields */}
                            {formType === 'collaboration_offer' && (
                                <div className="mb-4 grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                            {t('expertiseOffered')}
                                        </label>
                                        <input
                                            type="text"
                                            value={formExpertise}
                                            onChange={(e) => setFormExpertise(e.target.value)}
                                            placeholder={t('expertisePlaceholder')}
                                            className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg text-sm text-text dark:text-dark-text placeholder:text-text-muted focus:ring-2 focus:ring-primary/50 focus:border-primary"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                            {t('availabilityNotes')}
                                        </label>
                                        <input
                                            type="text"
                                            value={formAvailability}
                                            onChange={(e) => setFormAvailability(e.target.value)}
                                            placeholder={t('availabilityPlaceholder')}
                                            className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-dark-border bg-white dark:bg-dark-bg text-sm text-text dark:text-dark-text placeholder:text-text-muted focus:ring-2 focus:ring-primary/50 focus:border-primary"
                                        />
                                    </div>
                                </div>
                            )}

                            {/* Actions */}
                            <div className="flex items-center justify-end gap-2">
                                <Button
                                    type="button"
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => setShowForm(false)}
                                    disabled={submitting}
                                >
                                    {t('cancel')}
                                </Button>
                                <Button
                                    type="submit"
                                    size="sm"
                                    disabled={submitting || !formContent.trim()}
                                >
                                    <Send className="w-4 h-4 mr-1.5" />
                                    {submitting ? t('submitting') : t('submit')}
                                </Button>
                            </div>
                        </form>
                    )}

                    {/* Contributions list */}
                    {loading ? (
                        <div className="space-y-3">
                            {[1, 2].map((i) => (
                                <div key={i} className="h-24 rounded-lg bg-gray-100 dark:bg-dark-surface animate-pulse" />
                            ))}
                        </div>
                    ) : contributions.length === 0 ? (
                        <div className="text-center py-8">
                            <BookOpen className="w-10 h-10 text-text-muted dark:text-dark-text-muted mx-auto mb-3 opacity-50" />
                            <p className="text-sm text-text-muted dark:text-dark-text-muted">
                                {t('noContributions')}
                            </p>
                            <p className="text-xs text-text-muted dark:text-dark-text-muted mt-1">
                                {t('beFirstToContribute')}
                            </p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {contributions.map((contribution) => {
                                const config = contributionTypeConfig[contribution.contribution_type]
                                const Icon = config.icon
                                return (
                                    <article
                                        key={contribution.id}
                                        className="p-4 rounded-lg border border-gray-100 dark:border-dark-border bg-white dark:bg-dark-surface"
                                    >
                                        {/* Header */}
                                        <div className="flex items-start gap-3 mb-3">
                                            {/* User avatar */}
                                            <Link href={`/profile/${contribution.user_id}`} className="shrink-0 hover:opacity-80 transition-opacity">
                                                {contribution.user?.avatar_url ? (
                                                    <Image
                                                        src={contribution.user.avatar_url}
                                                        alt=""
                                                        width={32}
                                                        height={32}
                                                        className="w-8 h-8 rounded-full object-cover"
                                                    />
                                                ) : (
                                                    <div className={cn(
                                                        'w-8 h-8 rounded-full flex items-center justify-center text-xs font-medium text-white',
                                                        getAvatarGradient(contribution.user_id)
                                                    )}>
                                                        {getInitials(contribution.user?.name, contribution.user?.email)}
                                                    </div>
                                                )}
                                            </Link>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    <Link
                                                        href={`/profile/${contribution.user_id}`}
                                                        className="text-sm font-medium text-text dark:text-dark-text hover:text-primary transition-colors"
                                                    >
                                                        {contribution.user?.name || contribution.user?.email?.split('@')[0]}
                                                    </Link>
                                                    <span className={cn(
                                                        'inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium rounded-full',
                                                        config.color
                                                    )}>
                                                        <Icon className="w-3 h-3" />
                                                        {t(`type.${contribution.contribution_type}`)}
                                                    </span>
                                                </div>
                                                <div className="flex items-center gap-1 text-xs text-text-muted dark:text-dark-text-muted mt-0.5">
                                                    <Clock className="w-3 h-3" />
                                                    <span>{formatDate(contribution.created_at, 'short')}</span>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Content */}
                                        <p className="text-sm text-text dark:text-dark-text whitespace-pre-wrap">
                                            {contribution.content}
                                        </p>

                                        {/* Resource link */}
                                        {contribution.resource_url && (
                                            <a
                                                href={contribution.resource_url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="mt-3 flex items-center gap-2 p-2 rounded-lg bg-gray-50 dark:bg-dark-bg border border-gray-100 dark:border-dark-border hover:border-primary/30 transition-colors"
                                            >
                                                <ExternalLink className="w-4 h-4 text-primary dark:text-primary-light flex-shrink-0" />
                                                <span className="text-sm text-primary dark:text-primary-light truncate">
                                                    {contribution.resource_title || contribution.resource_url}
                                                </span>
                                            </a>
                                        )}

                                        {/* Collaboration offer details */}
                                        {contribution.contribution_type === 'collaboration_offer' && (
                                            <div className="mt-3 grid grid-cols-2 gap-3 text-xs">
                                                {contribution.expertise_offered && (
                                                    <div className="p-2 rounded-lg bg-purple-50 dark:bg-purple-900/10">
                                                        <span className="font-medium text-purple-700 dark:text-purple-300">
                                                            {t('expertise')}:
                                                        </span>
                                                        <span className="text-purple-600 dark:text-purple-400 ml-1">
                                                            {contribution.expertise_offered}
                                                        </span>
                                                    </div>
                                                )}
                                                {contribution.availability_notes && (
                                                    <div className="p-2 rounded-lg bg-purple-50 dark:bg-purple-900/10">
                                                        <span className="font-medium text-purple-700 dark:text-purple-300">
                                                            {t('availability')}:
                                                        </span>
                                                        <span className="text-purple-600 dark:text-purple-400 ml-1">
                                                            {contribution.availability_notes}
                                                        </span>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </article>
                                )
                            })}
                        </div>
                    )}
                </div>
            )}
        </div>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import { Settings, UserPlus, LogIn } from 'lucide-react'
import { InviteMemberDialog } from '@/components/InviteMemberDialog'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { useRouter } from 'next/navigation'

interface GroupActionsProps {
    groupId: string
    isMember: boolean
    isAdmin: boolean
    visibility: 'public' | 'private'
}

export function GroupActions({ groupId, isMember, isAdmin, visibility }: GroupActionsProps) {
    const [isInviteOpen, setIsInviteOpen] = useState(false)
    const [loading, setLoading] = useState(false)
    const { showToast } = useToast()
    const router = useRouter()
    const supabase = createClient()

    const handleJoin = async () => {
        setLoading(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push('/auth/login')
                return
            }

            const { error } = await supabase
                .from('group_members')
                .insert({
                    group_id: groupId,
                    user_id: user.id,
                    role: 'member'
                })

            if (error) throw error

            showToast('Joined group successfully', 'success')
            router.refresh()
        } catch (error: any) {
            console.error('Error joining group:', error)
            // If already a member (duplicate key), just refresh
            if (error.code === '23505' || error.message?.includes('duplicate key')) {
                showToast('You are already a member of this group', 'info')
                router.refresh()
            } else {
                showToast(error.message || 'Failed to join group', 'error')
            }
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="flex items-center gap-3">
            {!isMember && (
                <button
                    onClick={handleJoin}
                    disabled={loading}
                    className="btn btn-primary flex items-center gap-2"
                >
                    <LogIn className="w-4 h-4" />
                    {loading ? 'Joining...' : 'Join Group'}
                </button>
            )}

            {isMember && (
                <>
                    {isAdmin && (
                        <>
                            <button
                                onClick={() => setIsInviteOpen(true)}
                                className="btn btn-secondary flex items-center gap-2"
                            >
                                <UserPlus className="w-4 h-4" />
                                Invite
                            </button>

                            <Link
                                href={`/groups/${groupId}/settings`}
                                className="btn btn-outline flex items-center gap-2"
                            >
                                <Settings className="w-4 h-4" />
                                Settings
                            </Link>
                        </>
                    )}
                </>
            )}

            <InviteMemberDialog
                groupId={groupId}
                isOpen={isInviteOpen}
                onClose={() => setIsInviteOpen(false)}
            />
        </div>
    )
}

'use client'

import { useState, useMemo, useCallback } from 'react'
import Link from 'next/link'
import { ArrowRight, Filter, X } from 'lucide-react'
import { useTranslations, useLocale } from 'next-intl'
import { TagsCloud } from '@/components/TagsCloud'
import { BentoGrid, BentoGridItem } from '@/components/BentoGrid'
import { MagazineCard } from '@/components/MagazineCard'
import { FeaturedPost } from '@/components/FeaturedPost'
import { TrendingPosts } from '@/components/TrendingPosts'
import { ActivityInsightsCompact } from '@/components/ActivityInsights'
import { RelatedAuthors } from '@/components/RelatedAuthors'
import { SuggestedPostsCarousel } from '@/components/SuggestedPosts'
import { LatestResourcesSidebar } from '@/components/LatestResourcesSidebar'

interface Post {
  id: string
  title: string
  slug: string
  content?: string
  excerpt?: string
  created_at: string
  tags?: string[]
  cover_image?: string
  content_type?: string
  author?: {
    id: string
    name?: string
    email?: string
    avatar_url?: string
  }
  [key: string]: any
}

interface HomeContentFilterProps {
  featuredPosts: Post[]
  recentPosts: Post[]
  userId: string
  latestResources: Post[]
}

export function HomeContentFilter({ featuredPosts, recentPosts, userId, latestResources }: HomeContentFilterProps) {
  const t = useTranslations('Landing')
  const tForms = useTranslations('Forms')
  const tResources = useTranslations('Resources')
  const locale = useLocale()
  const [filterQuery, setFilterQuery] = useState('')

  // Normalize text for better Arabic/multilingual search
  // Removes diacritics and normalizes Unicode for consistent matching
  const normalizeText = (text: string) => {
    return text
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '') // Remove diacritics (Latin)
      .replace(/[\u064B-\u0652]/g, '') // Remove Arabic diacritics (tashkeel)
      .replace(/[╪ú╪Ñ╪ó╪º]/g, '╪º') // Normalize Alef variations
      .replace(/[┘ë╪ª]/g, '┘è') // Normalize Ya variations
      .replace(/╪⌐/g, '┘ç') // Normalize Ta Marbuta
  }

  // Filter posts based on query (searches title, content, excerpt, tags, and author name)
  const filterPosts = useCallback((posts: Post[]) => {
    if (!filterQuery.trim()) return posts

    const query = normalizeText(filterQuery)
    return posts.filter(post => {
      const title = normalizeText(post.title || '')
      const content = normalizeText(post.content || '')
      const excerpt = normalizeText(post.excerpt || '')
      const tags = normalizeText(post.tags?.join(' ') || '')
      const authorName = normalizeText(post.author?.name || '')

      return (
        title.includes(query) ||
        content.includes(query) ||
        excerpt.includes(query) ||
        tags.includes(query) ||
        authorName.includes(query)
      )
    })
  }, [filterQuery])

  const filteredFeatured = useMemo(() => filterPosts(featuredPosts), [filterPosts, featuredPosts])
  const filteredRecent = useMemo(() => filterPosts(recentPosts), [filterPosts, recentPosts])
  // Resources in sidebar are not filtered to match other sidebar items behavior

  const hasResults = filteredFeatured.length > 0 || filteredRecent.length > 0
  const isFiltering = filterQuery.trim().length > 0

  return (
    <>
      {/* Filter Bar */}
      <div className="mb-12 flex justify-center">
        <div className="relative w-full max-w-md">
          <div className="absolute inset-y-0 ltr:left-0 rtl:right-0 ltr:pl-4 rtl:pr-4 flex items-center pointer-events-none">
            <Filter className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
          </div>
          <input
            type="text"
            dir="auto"
            value={filterQuery}
            onChange={(e) => setFilterQuery(e.target.value)}
            placeholder={tForms('filterPlaceholder')}
            className="w-full ltr:pl-12 rtl:pr-12 ltr:pr-10 rtl:pl-10 py-3 text-sm rounded-full border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-text dark:text-dark-text placeholder:text-text-light dark:placeholder:text-dark-text-muted focus:ring-2 focus:ring-primary focus:border-transparent transition-all ltr:text-left rtl:text-right"
          />
          {filterQuery && (
            <button
              onClick={() => setFilterQuery('')}
              className="absolute inset-y-0 ltr:right-0 rtl:left-0 ltr:pr-4 rtl:pl-4 flex items-center text-text-light hover:text-text dark:text-dark-text-muted dark:hover:text-dark-text transition-colors"
            >
              <X className="w-4 h-4" />
            </button>
          )}
        </div>
      </div>

      {/* Tags Cloud */}
      <div className="mb-16">
        <h2 className="text-2xl font-display font-semibold text-center mb-8 text-primary dark:text-dark-text">
          {t('popularTopics')}
        </h2>
        <TagsCloud />
      </div>

      {/* No Results Message */}
      {isFiltering && !hasResults && (
        <div className="text-center py-16">
          <p className="text-lg text-text-light dark:text-dark-text-muted mb-2">
            {t('noFilterResults')}
          </p>
          <button
            onClick={() => setFilterQuery('')}
            className="text-primary hover:text-primary-dark font-medium"
          >
            {t('clearFilter')}
          </button>
        </div>
      )}



      {/* Featured Posts - Bento Grid */}
      {filteredFeatured.length > 0 && (
        <div className="mb-16">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-3xl font-display font-bold text-text dark:text-dark-text">
              {t('featured')}
              {isFiltering && (
                <span className="ltr:ml-2 rtl:mr-2 text-sm font-normal text-text-light dark:text-dark-text-muted">
                  ({filteredFeatured.length})
                </span>
              )}
            </h2>
            <Link
              href="/insights"
              className="text-primary dark:text-secondary hover:text-primary-dark dark:hover:text-secondary-light font-medium flex items-center gap-2 transition-colors"
            >
              {t('viewAll')}
              <ArrowRight className="w-4 h-4" />
            </Link>
          </div>

          <BentoGrid columns={4} gap="md">
            {/* Large featured post */}
            {filteredFeatured[0] && (
              <BentoGridItem size="2x2">
                <FeaturedPost post={filteredFeatured[0]} size="large" showTrending />
              </BentoGridItem>
            )}

            {/* Medium posts */}
            {filteredFeatured[1] && (
              <BentoGridItem size="1x1">
                <FeaturedPost post={filteredFeatured[1]} size="small" accentColor="accent" />
              </BentoGridItem>
            )}
            {filteredFeatured[2] && (
              <BentoGridItem size="1x1">
                <FeaturedPost post={filteredFeatured[2]} size="small" accentColor="secondary" />
              </BentoGridItem>
            )}

            {/* Horizontal card */}
            {filteredFeatured[3] && (
              <BentoGridItem size="2x1">
                <MagazineCard post={filteredFeatured[3]} variant="horizontal" className="h-full" />
              </BentoGridItem>
            )}
          </BentoGrid>
        </div>
      )}

      {/* Two-column layout: Recent posts + Sidebar */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Content Column - Recent Posts as Magazine Cards */}
        <div className="lg:col-span-2 space-y-12">
          {filteredRecent.length > 0 && (
            <div>
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-display font-semibold text-text dark:text-dark-text">
                  {t('recentResearch')}
                  {isFiltering && (
                    <span className="ltr:ml-2 rtl:mr-2 text-sm font-normal text-text-light dark:text-dark-text-muted">
                      ({filteredRecent.length})
                    </span>
                  )}
                </h2>
              </div>

              <div className="grid gap-6 md:grid-cols-2">
                {filteredRecent.map((post: any) => (
                  <MagazineCard key={post.id} post={post} variant="standard" />
                ))}
              </div>
            </div>
          )}

          {filteredRecent.length === 0 && filteredFeatured.length === 0 && !isFiltering && (
            <div className="text-center py-16 text-text-light dark:text-dark-text-muted">
              <p className="text-lg mb-4">{t('noPosts')}</p>
              <Link href="/editor" className="btn btn-primary">
                {t('createPost')}
              </Link>
            </div>
          )}

          {/* Suggested Posts Carousel */}
          {!isFiltering && <SuggestedPostsCarousel limit={4} />}
        </div>

        {/* Sidebar Column - "Context Stack" */}
        <div className="space-y-6">
          {/* Section Header */}
          <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wide">
            {t('context')}
          </h3>

          {/* Active Discussions */}
          <div>
            <TrendingPosts />
          </div>

          {/* Recent Activity */}
          <div>
            <ActivityInsightsCompact limit={5} />
          </div>

          {/* Latest Resources */}
          {latestResources.length > 0 && (
            <div className="card p-4">
              <LatestResourcesSidebar resources={latestResources} locale={locale} />
            </div>
          )}

          {/* Related Researchers */}
          <div className="card p-4">
            <RelatedAuthors currentUserId={userId} limit={4} />
          </div>
        </div>
      </div>
    </>
  )
}

'use client'

import { useState, useRef } from 'react'
import Image from 'next/image'
import { Upload, Loader2, Image as ImageIcon } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { useToast } from '@/components/ui/toast'
import { ImageCropModal } from './ImageCropModal'
import { useTranslations } from 'next-intl'

interface ImageUploadProps {
    bucket: 'avatars' | 'post_images'
    path?: string // Optional subpath
    onUploadComplete: (url: string) => void
    currentImage?: string | null
    className?: string
    enableCrop?: boolean
    cropShape?: 'round' | 'rect'
    aspectRatio?: number
}

export function ImageUpload({
    bucket,
    path = '',
    onUploadComplete,
    currentImage,
    className = '',
    enableCrop = true,
    cropShape = 'round',
    aspectRatio = 1
}: ImageUploadProps) {
    const [uploading, setUploading] = useState(false)
    const [preview, setPreview] = useState<string | null>(currentImage || null)
    const [cropModalOpen, setCropModalOpen] = useState(false)
    const [selectedImage, setSelectedImage] = useState<string | null>(null)
    const fileInputRef = useRef<HTMLInputElement>(null)
    const { showToast } = useToast()
    const supabase = createClient()
    const t = useTranslations('Profile')

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!e.target.files || e.target.files.length === 0) {
            return
        }

        const file = e.target.files[0]

        // Validate file type
        if (!file.type.startsWith('image/')) {
            showToast('Please select an image file', 'error')
            return
        }

        // Create object URL for cropping
        const objectUrl = URL.createObjectURL(file)

        if (enableCrop) {
            // Open crop modal
            setSelectedImage(objectUrl)
            setCropModalOpen(true)
        } else {
            // Upload directly without cropping
            await uploadImage(file)
        }

        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = ''
        }
    }

    const uploadImage = async (file: File | Blob) => {
        const fileExt = file instanceof File ? file.name.split('.').pop() : 'jpg'
        // SECURITY: Use crypto.randomUUID() for secure filename generation
        const fileName = `${path ? path + '/' : ''}${crypto.randomUUID()}.${fileExt}`
        const filePath = fileName

        setUploading(true)

        try {
            const { error: uploadError } = await supabase.storage
                .from(bucket)
                .upload(filePath, file)

            if (uploadError) {
                throw uploadError
            }

            const { data: { publicUrl } } = supabase.storage
                .from(bucket)
                .getPublicUrl(filePath)

            setPreview(publicUrl)
            onUploadComplete(publicUrl)
            showToast('Image uploaded successfully', 'success')
        } catch (error: any) {
            console.error('Error uploading image:', error)
            showToast('Error uploading image', 'error')
            setPreview(currentImage || null)
        } finally {
            setUploading(false)
        }
    }

    const handleCropComplete = async (croppedBlob: Blob) => {
        // Upload the cropped image
        await uploadImage(croppedBlob)

        // Clean up
        if (selectedImage) {
            URL.revokeObjectURL(selectedImage)
            setSelectedImage(null)
        }
    }

    const handleCropModalClose = () => {
        setCropModalOpen(false)
        if (selectedImage) {
            URL.revokeObjectURL(selectedImage)
            setSelectedImage(null)
        }
    }

    const handleRemove = () => {
        setPreview(null)
        onUploadComplete('')
        if (fileInputRef.current) {
            fileInputRef.current.value = ''
        }
    }

    const previewStyle = cropShape === 'round'
        ? "w-32 h-32 rounded-full"
        : "w-full aspect-video rounded-xl"

    return (
        <>
            <div className={`flex flex-col items-center gap-4 ${className}`}>
                <div
                    className={`relative group cursor-pointer overflow-hidden border-2 border-gray-200 dark:border-dark-border bg-gray-100 dark:bg-dark-surface flex items-center justify-center transition-colors hover:border-primary dark:hover:border-primary ${previewStyle}`}
                    onClick={() => fileInputRef.current?.click()}
                >
                    {preview ? (
                        <>
                            <Image
                                src={preview}
                                alt="Upload preview"
                                fill
                                className="object-cover object-center"
                            />
                            <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                <Upload className="w-6 h-6 text-white" />
                            </div>
                        </>
                    ) : (
                        <ImageIcon className="w-8 h-8 text-gray-400" />
                    )}

                    {uploading && (
                        <div className="absolute inset-0 flex items-center justify-center bg-white/80 dark:bg-dark-bg/80">
                            <Loader2 className="w-8 h-8 animate-spin text-primary" />
                        </div>
                    )}
                </div>

                <div className="flex gap-2 justify-center">
                    <Button
                        type="button"
                        variant="default"
                        size="sm"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={uploading}
                        className="bg-primary text-white hover:bg-primary-dark"
                    >
                        {preview ? t('changeImage') : t('uploadImage')}
                    </Button>
                    {preview && (
                        <Button
                            type="button"
                            variant="outline"
                            size="sm"
                            onClick={(e) => {
                                e.stopPropagation()
                                handleRemove()
                            }}
                            disabled={uploading}
                            className="border-red-300 text-red-600 hover:bg-red-50 dark:border-red-800 dark:text-red-400 dark:hover:bg-red-900/30"
                        >
                            {t('remove')}
                        </Button>
                    )}
                </div>

                <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleFileSelect}
                    className="hidden"
                />
            </div>

            {/* Crop Modal */}
            {selectedImage && (
                <ImageCropModal
                    open={cropModalOpen}
                    onClose={handleCropModalClose}
                    imageSrc={selectedImage}
                    onCropComplete={handleCropComplete}
                    aspectRatio={aspectRatio}
                    cropShape={cropShape}
                />
            )}
        </>
    )
}

'use client'

import { useState } from 'react'
import { X, Mail, Send } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { useTranslations } from 'next-intl'

interface InviteMemberDialogProps {
    groupId: string
    isOpen: boolean
    onClose: () => void
}

export function InviteMemberDialog({ groupId, isOpen, onClose }: InviteMemberDialogProps) {
    const t = useTranslations('Groups')
    const tCommon = useTranslations('Common')
    const { showToast } = useToast()
    const supabase = createClient()

    const [email, setEmail] = useState('')
    const [loading, setLoading] = useState(false)

    if (!isOpen) return null

    const handleInvite = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error('Not authenticated')

            if (!email || !email.includes('@')) {
                throw new Error('Please enter a valid email address')
            }

            // Generate a random token
            const token = crypto.randomUUID()

            const { error } = await supabase
                .from('group_invitations')
                .insert({
                    group_id: groupId,
                    inviter_id: user.id,
                    invitee_email: email,
                    token: token,
                    status: 'pending'
                })

            if (error) {
                if (error.code === '23505') { // Unique violation
                    throw new Error('This user has already been invited')
                }
                throw error
            }

            showToast(`Invitation sent to ${email}`, 'success')
            setEmail('')
            onClose()

        } catch (error: any) {
            console.error('Error sending invite:', error)
            showToast(error.message || 'Failed to send invitation', 'error')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
            <div className="bg-white dark:bg-dark-surface rounded-xl shadow-xl w-full max-w-md mx-4 overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="flex items-center justify-between p-4 border-b border-gray-100 dark:border-dark-border">
                    <h3 className="font-semibold text-lg text-text dark:text-dark-text">
                        {t('inviteMember')}
                    </h3>
                    <button
                        onClick={onClose}
                        className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <form onSubmit={handleInvite} className="p-6">
                    <p className="text-sm text-text-light dark:text-dark-text-muted mb-6">
                        {t('inviteDescription')}
                    </p>

                    <div className="space-y-4">
                        <div className="relative">
                            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                            <input
                                type="email"
                                required
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="colleague@example.com"
                                className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-gray-300 focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30 dark:border-dark-border dark:bg-dark-bg dark:text-dark-text"
                            />
                        </div>

                        <div className="flex justify-end gap-3 pt-2">
                            <button
                                type="button"
                                onClick={onClose}
                                className="px-4 py-2 text-sm font-medium text-text-light hover:text-text dark:text-dark-text-muted dark:hover:text-dark-text transition-colors"
                            >
                                {tCommon('cancel')}
                            </button>
                            <button
                                type="submit"
                                disabled={loading}
                                className="btn btn-primary flex items-center gap-2"
                            >
                                {loading ? (
                                    'Sending...'
                                ) : (
                                    <>
                                        <Send className="w-4 h-4" />
                                        {t('sendInvite')}
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog'
import {
    Scale, Clock, Users, CheckCircle, XCircle,
    MinusCircle, AlertTriangle, Loader2, ChevronRight
} from 'lucide-react'
import type { JuryCase, JuryVoteValue } from '@/types/advanced'

interface JuryPanelProps {
    userId: string
}

export function JuryPanel({ userId }: JuryPanelProps) {
    const [cases, setCases] = useState<JuryCase[]>([])
    const [loading, setLoading] = useState(true)
    const [selectedCase, setSelectedCase] = useState<JuryCase | null>(null)
    const [voteDialogOpen, setVoteDialogOpen] = useState(false)
    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()


    const fetchCases = useCallback(async () => {
        try {
            const response = await fetch('/api/jury?status=active')
            const data = await response.json()

            if (data.cases) {
                setCases(data.cases)
            }
        } catch (error) {
            console.error('Error fetching jury cases:', error)
            showToast('Failed to load jury cases', 'error')
        } finally {
            setLoading(false)
        }
    }, [showToast])

    useEffect(() => {
        fetchCases()
    }, [fetchCases])


    function getTimeRemaining(deadline: string): string {
        const now = new Date()
        const end = new Date(deadline)
        const diff = end.getTime() - now.getTime()

        if (diff <= 0) return 'Expired'

        const hours = Math.floor(diff / (1000 * 60 * 60))
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60))

        if (hours > 24) {
            const days = Math.floor(hours / 24)
            return `${days}d ${hours % 24}h remaining`
        }

        return `${hours}h ${minutes}m remaining`
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    if (cases.length === 0) {
        return (
            <div className="text-center py-12 bg-background-alt/50 rounded-xl">
                <Scale className="w-12 h-12 mx-auto mb-4 text-text-light/50" />
                <h3 className="text-lg font-medium mb-2">No Active Jury Cases</h3>
                <p className="text-text-light">You don&apos;t have any jury assignments at the moment.</p>
            </div>
        )
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-semibold flex items-center gap-2">
                    <Scale className="w-5 h-5" />
                    Jury Duty
                </h2>
                <span className="text-sm text-text-light">
                    {cases.length} active case{cases.length !== 1 ? 's' : ''}
                </span>
            </div>

            {cases.map((juryCase) => (
                <JuryCaseCard
                    key={juryCase.id}
                    juryCase={juryCase}
                    timeRemaining={getTimeRemaining(juryCase.deadline)}
                    onVote={() => {
                        setSelectedCase(juryCase)
                        setVoteDialogOpen(true)
                    }}
                />
            ))}

            {selectedCase && (
                <VoteDialog
                    open={voteDialogOpen}
                    onClose={() => setVoteDialogOpen(false)}
                    juryCase={selectedCase}
                    onVoteSubmitted={() => {
                        setVoteDialogOpen(false)
                        fetchCases()
                    }}
                />
            )}
        </div>
    )
}

interface JuryCaseCardProps {
    juryCase: JuryCase
    timeRemaining: string
    onVote: () => void
}

function JuryCaseCard({ juryCase, timeRemaining, onVote }: JuryCaseCardProps) {
    const appeal = juryCase.appeal
    const isUrgent = timeRemaining.includes('h') && !timeRemaining.includes('d')

    return (
        <div className="bg-white dark:bg-dark-card rounded-xl border border-gray-200 dark:border-dark-border p-5 hover:shadow-lg transition-shadow">
            <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                    {/* Post title */}
                    <h3 className="font-medium text-lg mb-2 truncate">
                        {appeal?.post?.title || 'Appeal Case'}
                    </h3>

                    {/* Appeal reason preview */}
                    <p className="text-sm text-text-light dark:text-dark-text-muted line-clamp-2 mb-3">
                        <span className="font-medium">Appeal reason: </span>
                        {appeal?.dispute_reason}
                    </p>

                    {/* Stats */}
                    <div className="flex items-center gap-4 text-sm">
                        <span className="flex items-center gap-1 text-text-light">
                            <Users className="w-4 h-4" />
                            {juryCase.total_votes}/{juryCase.required_votes} votes
                        </span>
                        <span className={`flex items-center gap-1 ${isUrgent ? 'text-orange-600' : 'text-text-light'}`}>
                            <Clock className="w-4 h-4" />
                            {timeRemaining}
                        </span>
                    </div>
                </div>

                <Button onClick={onVote} className="shrink-0 gap-2">
                    Cast Vote
                    <ChevronRight className="w-4 h-4" />
                </Button>
            </div>
        </div>
    )
}

interface VoteDialogProps {
    open: boolean
    onClose: () => void
    juryCase: JuryCase
    onVoteSubmitted: () => void
}

function VoteDialog({ open, onClose, juryCase, onVoteSubmitted }: VoteDialogProps) {
    const [vote, setVote] = useState<JuryVoteValue | null>(null)
    const [reasoning, setReasoning] = useState('')
    const [submitting, setSubmitting] = useState(false)
    const { showToast } = useToast()

    async function handleSubmit() {
        if (!vote || reasoning.length < 20) {
            showToast('Please select a vote and provide reasoning (min 20 chars)', 'error')
            return
        }

        setSubmitting(true)
        try {
            const response = await fetch('/api/jury', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    deliberation_id: juryCase.id,
                    vote,
                    reasoning
                })
            })

            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || 'Failed to submit vote')
            }

            showToast(data.message || 'Vote submitted successfully', 'success')
            onVoteSubmitted()
        } catch (error: any) {
            showToast(error.message || 'Failed to submit vote', 'error')
        } finally {
            setSubmitting(false)
        }
    }

    const appeal = juryCase.appeal

    return (
        <Dialog open={open} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Scale className="w-5 h-5 text-primary" />
                        Cast Your Vote
                    </DialogTitle>
                    <DialogDescription>
                        Review the flagged content and the author&apos;s appeal, then cast your vote.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-6 py-4">
                    {/* Case Details */}
                    <div className="bg-background-alt dark:bg-dark-bg rounded-lg p-4">
                        <h4 className="font-medium mb-2">Flagged Content</h4>
                        <p className="font-semibold">{appeal?.post?.title}</p>
                        <p className="text-sm text-text-light mt-1 line-clamp-3">
                            {typeof appeal?.post?.content === 'string'
                                ? appeal.post.content.substring(0, 200) + '...'
                                : ''}
                        </p>
                    </div>

                    <div className="bg-orange-50 dark:bg-orange-900/20 rounded-lg p-4 border border-orange-200 dark:border-orange-800">
                        <h4 className="font-medium mb-2 text-orange-800 dark:text-orange-300">
                            Author&apos;s Appeal
                        </h4>
                        <p className="text-sm">{appeal?.dispute_reason}</p>
                    </div>

                    {/* Vote Options */}
                    <div>
                        <h4 className="font-medium mb-3">Your Decision</h4>
                        <div className="grid grid-cols-3 gap-3">
                            <VoteOption
                                value="uphold"
                                label="Uphold Flag"
                                description="Content should remain flagged"
                                icon={<XCircle className="w-5 h-5" />}
                                selected={vote === 'uphold'}
                                onClick={() => setVote('uphold')}
                                color="red"
                            />
                            <VoteOption
                                value="overturn"
                                label="Overturn"
                                description="Restore the content"
                                icon={<CheckCircle className="w-5 h-5" />}
                                selected={vote === 'overturn'}
                                onClick={() => setVote('overturn')}
                                color="green"
                            />
                            <VoteOption
                                value="abstain"
                                label="Abstain"
                                description="Cannot decide"
                                icon={<MinusCircle className="w-5 h-5" />}
                                selected={vote === 'abstain'}
                                onClick={() => setVote('abstain')}
                                color="gray"
                            />
                        </div>
                    </div>

                    {/* Reasoning */}
                    <div>
                        <label className="block font-medium mb-2">
                            Explain Your Decision <span className="text-red-500">*</span>
                        </label>
                        <textarea
                            value={reasoning}
                            onChange={(e) => setReasoning(e.target.value)}
                            placeholder="Provide your reasoning for this decision (minimum 20 characters)..."
                            className="w-full h-32 px-3 py-2 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg resize-none"
                        />
                        <p className="text-xs text-text-light mt-1">
                            {reasoning.length}/20 minimum characters
                        </p>
                    </div>

                    {/* Warning */}
                    <div className="flex items-start gap-2 text-sm text-amber-700 dark:text-amber-400 bg-amber-50 dark:bg-amber-900/20 p-3 rounded-lg">
                        <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
                        <p>
                            Your vote is anonymous until the deliberation concludes.
                            Once submitted, you cannot change your vote.
                        </p>
                    </div>
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={onClose} disabled={submitting}>
                        Cancel
                    </Button>
                    <Button
                        onClick={handleSubmit}
                        disabled={!vote || reasoning.length < 20 || submitting}
                        className="gap-2"
                    >
                        {submitting ? (
                            <Loader2 className="w-4 h-4 animate-spin" />
                        ) : (
                            <Scale className="w-4 h-4" />
                        )}
                        Submit Vote
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    )
}

interface VoteOptionProps {
    value: JuryVoteValue
    label: string
    description: string
    icon: React.ReactNode
    selected: boolean
    onClick: () => void
    color: 'red' | 'green' | 'gray'
}

function VoteOption({ label, description, icon, selected, onClick, color }: VoteOptionProps) {
    const colorClasses = {
        red: selected
            ? 'border-red-500 bg-red-50 dark:bg-red-900/30 text-red-700 dark:text-red-300'
            : 'border-gray-200 dark:border-dark-border hover:border-red-300',
        green: selected
            ? 'border-green-500 bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-300'
            : 'border-gray-200 dark:border-dark-border hover:border-green-300',
        gray: selected
            ? 'border-gray-500 bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300'
            : 'border-gray-200 dark:border-dark-border hover:border-gray-400'
    }

    return (
        <button
            onClick={onClick}
            className={`p-4 rounded-lg border-2 text-center transition-all ${colorClasses[color]}`}
        >
            <div className="flex justify-center mb-2">{icon}</div>
            <div className="font-medium text-sm">{label}</div>
            <div className="text-xs text-text-light mt-1">{description}</div>
        </button>
    )
}

'use client'

import { useEffect, useState, useRef, useMemo, useCallback } from 'react'
import { useTranslations } from 'next-intl'
import { createClient } from '@/lib/supabase/client'
import { useTheme } from 'next-themes'
import {
    ZoomIn,
    ZoomOut,
    RotateCcw,
    Info,
    ExternalLink,
    Maximize2,
    Minimize2,
    Search,
    Loader2,
    X
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'

// Types
interface KnowledgeGraphProps {
    centerPostId: string
}

interface GraphNode {
    id: string
    title: string
    group: 'center' | 'fork' | 'citation' | 'related' | 'author'
    tag: string
    authorName?: string
    contentType: 'post' | 'resource'
}

interface GraphEdge {
    source: string
    target: string
    type: 'fork' | 'citation' | 'shared_tag' | 'shared_author'
}

type RelationType = 'fork' | 'citation' | 'shared_tag' | 'shared_author'

// Design System Colors
const THEME_COLORS = {
    primary: '#1A3D40',
    primaryLight: '#2A5558',
    secondary: '#4AA3A5',
    accent: '#C9A227',         // Golden amber like reference
    citation: '#C41E3A',       // Heritage Red for citations
    textLight: '#5A6A72',
    darkBg: '#0F1419',         // Darker background like reference
    darkSurface: '#1A2028',
    lightBg: '#FAFAFA',
    lightSurface: '#FFFFFF',
    textDark: '#2A3A42',
    textDarkMode: '#E8EDEE'
}

// Node colors by relationship type
const NODE_COLORS: Record<string, { bg: string, border: string, text: string }> = {
    center: { bg: THEME_COLORS.secondary, border: THEME_COLORS.primaryLight, text: '#FFFFFF' },
    fork: { bg: THEME_COLORS.accent, border: '#B8911F', text: '#1A1A1A' },
    citation: { bg: THEME_COLORS.citation, border: '#A31830', text: '#FFFFFF' },
    related: { bg: THEME_COLORS.primaryLight, border: THEME_COLORS.primary, text: '#FFFFFF' },
    author: { bg: '#6366F1', border: '#4F46E5', text: '#FFFFFF' }
}

const RELATION_LABELS: Record<RelationType, string> = {
    fork: 'Fork',
    citation: 'Cites This',
    shared_tag: 'Related Topic',
    shared_author: 'Same Author'
}

// Edge descriptions for hover tooltips
const EDGE_DESCRIPTIONS: Record<RelationType, string> = {
    fork: 'This work was derived from or built upon the original',
    citation: 'This work references or cites the original',
    shared_tag: 'These works share common topics or themes',
    shared_author: 'These works are by the same author'
}

// Helper component for dialog canvas - fully self-contained with its own state
function DialogGraphCanvas({
    nodes,
    edges,
    calculatePositions,
    expanded
}: {
    nodes: GraphNode[]
    edges: GraphEdge[]
    calculatePositions: (width: number, height: number) => Map<string, { x: number, y: number }>
    expanded: boolean
}) {
    const containerRef = useRef<HTMLDivElement>(null)
    const canvasRef = useRef<HTMLCanvasElement>(null)
    const [positions, setPositions] = useState<Map<string, { x: number, y: number }>>(new Map())
    const [zoomLevel, setZoomLevel] = useState(0.9)
    const [draggedNode, setDraggedNode] = useState<string | null>(null)
    const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 })
    const [hoveredNode, setHoveredNode] = useState<GraphNode | null>(null)
    const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null) // For click-to-show-info panel
    const [hoveredEdge, setHoveredEdge] = useState<GraphEdge | null>(null)
    const hasDragged = useRef(false)

    const t = useTranslations('KnowledgeGraph')

    const RELATION_LABELS: Record<RelationType, string> = {
        fork: t('relations.fork'),
        citation: t('relations.citation'),
        shared_tag: t('relations.shared_tag'),
        shared_author: t('relations.shared_author')
    }

    const EDGE_DESCRIPTIONS: Record<RelationType, string> = {
        fork: t('highlightFork'), // Need to make sure these match or add to en/ar.json
        citation: t('highlightCitation'),
        shared_tag: t('highlightTopic'),
        shared_author: t('highlightAuthor')
    }

    // Initialize positions when dialog opens
    useEffect(() => {
        if (expanded && containerRef.current && nodes.length > 0) {
            const timer = setTimeout(() => {
                if (containerRef.current) {
                    const rect = containerRef.current.getBoundingClientRect()
                    const newPositions = calculatePositions(rect.width, rect.height)
                    setPositions(newPositions)
                }
            }, 50)
            return () => clearTimeout(timer)
        }
    }, [expanded, nodes, calculatePositions])

    // Draw function for dialog
    const drawDialogGraph = useCallback(() => {
        if (!canvasRef.current || !containerRef.current || positions.size === 0) return

        const canvas = canvasRef.current
        const rect = containerRef.current.getBoundingClientRect()
        const width = rect.width
        const height = rect.height
        const ctx = canvas.getContext('2d')
        if (!ctx) return

        const dpr = window.devicePixelRatio || 1
        canvas.width = width * dpr
        canvas.height = height * dpr
        canvas.style.width = `${width}px`
        canvas.style.height = `${height}px`
        ctx.scale(dpr, dpr)

        // Clear
        ctx.fillStyle = THEME_COLORS.darkBg
        ctx.fillRect(0, 0, width, height)

        // Apply zoom
        ctx.save()
        const centerX = width / 2
        const centerY = height / 2
        ctx.translate(centerX, centerY)
        ctx.scale(zoomLevel, zoomLevel)
        ctx.translate(-centerX, -centerY)

        // Draw edges with semantic styling
        edges.forEach(edge => {
            const sourcePos = positions.get(edge.source)
            const targetPos = positions.get(edge.target)
            if (!sourcePos || !targetPos) return

            const midX = (sourcePos.x + targetPos.x) / 2
            const midY = (sourcePos.y + targetPos.y) / 2
            const dx = targetPos.x - sourcePos.x
            const dy = targetPos.y - sourcePos.y
            const dist = Math.sqrt(dx * dx + dy * dy)
            const curvature = dist * 0.15
            const perpX = -dy / dist * curvature
            const perpY = dx / dist * curvature

            const edgeColor = edge.type === 'citation' ? THEME_COLORS.citation :
                edge.type === 'fork' ? THEME_COLORS.accent :
                    edge.type === 'shared_author' ? '#6366F1' : THEME_COLORS.secondary

            const isHovered = hoveredEdge?.source === edge.source && hoveredEdge?.target === edge.target

            // Apply glow effect when hovered
            if (isHovered) {
                ctx.shadowColor = edgeColor
                ctx.shadowBlur = 12
            }

            ctx.beginPath()
            ctx.moveTo(sourcePos.x, sourcePos.y)
            ctx.quadraticCurveTo(midX + perpX, midY + perpY, targetPos.x, targetPos.y)

            // Solid for forks (derived work), dashed for citations
            if (edge.type === 'citation' || edge.type === 'shared_tag') {
                ctx.setLineDash([6, 4])
            } else {
                ctx.setLineDash([])
            }

            // Thicker when hovered
            ctx.lineWidth = isHovered ? 3 : 2
            ctx.strokeStyle = isHovered ? edgeColor : `${edgeColor}60`
            ctx.stroke()

            // Reset
            ctx.setLineDash([])
            ctx.shadowColor = 'transparent'
            ctx.shadowBlur = 0
        })

        // Draw nodes
        nodes.forEach(node => {
            const pos = positions.get(node.id)
            if (!pos) return

            const colors = NODE_COLORS[node.group]
            const isCenter = node.group === 'center'
            const isHovered = hoveredNode?.id === node.id
            const nodeWidth = isCenter ? 110 : 90
            const nodeHeight = isCenter ? 44 : 36
            const radius = 6

            if (isHovered || isCenter) {
                ctx.shadowColor = `${colors.bg}40`
                ctx.shadowBlur = 15
                ctx.shadowOffsetY = 4
            }

            ctx.beginPath()
            ctx.roundRect(pos.x - nodeWidth / 2, pos.y - nodeHeight / 2, nodeWidth, nodeHeight, radius)
            ctx.fillStyle = colors.bg
            ctx.fill()
            ctx.strokeStyle = colors.border
            ctx.lineWidth = isHovered ? 3 : 2
            ctx.stroke()

            ctx.shadowColor = 'transparent'
            ctx.shadowBlur = 0
            ctx.shadowOffsetY = 0

            ctx.fillStyle = colors.text
            ctx.font = `${isCenter ? '600' : '500'} ${isCenter ? 12 : 11}px Inter, system-ui, sans-serif`
            ctx.textAlign = 'center'
            ctx.textBaseline = 'middle'
            const title = node.title.length > 12 ? node.title.substring(0, 11) + 'ΓÇª' : node.title
            ctx.fillText(title, pos.x, pos.y - (isCenter ? 5 : 3))

            ctx.font = '500 9px Inter, system-ui, sans-serif'
            ctx.fillStyle = `${colors.text}99`
            const tag = node.tag.length > 12 ? node.tag.substring(0, 11) + 'ΓÇª' : node.tag
            ctx.fillText(tag, pos.x, pos.y + (isCenter ? 10 : 8))
        })

        ctx.restore()
    }, [nodes, edges, positions, zoomLevel, hoveredNode, hoveredEdge])

    // Redraw when positions/zoom change
    useEffect(() => {
        drawDialogGraph()
    }, [drawDialogGraph])

    // Get node at position (adjusted for zoom)
    const getNodeAtPosition = useCallback((x: number, y: number, rect: DOMRect): GraphNode | null => {
        if (positions.size === 0) return null
        const centerX = rect.width / 2
        const centerY = rect.height / 2
        // Adjust for zoom - transform screen coords back to canvas coords
        const adjustedX = centerX + (x - centerX) / zoomLevel
        const adjustedY = centerY + (y - centerY) / zoomLevel

        for (const node of nodes) {
            const pos = positions.get(node.id)
            if (!pos) continue
            const isCenter = node.group === 'center'
            const nodeWidth = isCenter ? 110 : 90
            const nodeHeight = isCenter ? 44 : 36

            // Check if click is within node bounds
            if (adjustedX >= pos.x - nodeWidth / 2 && adjustedX <= pos.x + nodeWidth / 2 &&
                adjustedY >= pos.y - nodeHeight / 2 && adjustedY <= pos.y + nodeHeight / 2) {
                return node
            }
        }
        return null
    }, [nodes, positions, zoomLevel])

    const handleMouseDown = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top
        hasDragged.current = false
        const node = getNodeAtPosition(x, y, rect)
        if (node) {
            const pos = positions.get(node.id)
            if (pos) {
                // Adjust for zoom
                const centerX = rect.width / 2
                const centerY = rect.height / 2
                const adjustedX = centerX + (x - centerX) / zoomLevel
                const adjustedY = centerY + (y - centerY) / zoomLevel
                setDraggedNode(node.id)
                setDragOffset({ x: adjustedX - pos.x, y: adjustedY - pos.y })
            }
        }
    }, [getNodeAtPosition, positions, zoomLevel])

    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top

        if (draggedNode) {
            hasDragged.current = true
            const centerX = rect.width / 2
            const centerY = rect.height / 2
            const adjustedX = centerX + (x - centerX) / zoomLevel
            const adjustedY = centerY + (y - centerY) / zoomLevel
            const padding = 70
            const newX = Math.max(padding, Math.min(rect.width - padding, adjustedX - dragOffset.x))
            const newY = Math.max(padding, Math.min(rect.height - padding, adjustedY - dragOffset.y))

            setPositions(prev => {
                const next = new Map(prev)
                next.set(draggedNode, { x: newX, y: newY })
                return next
            })
        } else {
            // Check for node hover first
            const node = getNodeAtPosition(x, y, rect)
            setHoveredNode(node)

            // Only check for edge hover if not hovering a node
            if (!node && containerRef.current) {
                const centerX = rect.width / 2
                const centerY = rect.height / 2
                const adjustedX = centerX + (x - centerX) / zoomLevel
                const adjustedY = centerY + (y - centerY) / zoomLevel

                // Find if hovering near an edge
                let foundEdge: GraphEdge | null = null
                for (const edge of edges) {
                    const sourcePos = positions.get(edge.source)
                    const targetPos = positions.get(edge.target)
                    if (!sourcePos || !targetPos) continue

                    // Check distance to line (simplified - check distance to midpoint)
                    const midX = (sourcePos.x + targetPos.x) / 2
                    const midY = (sourcePos.y + targetPos.y) / 2
                    const dist = Math.sqrt((adjustedX - midX) ** 2 + (adjustedY - midY) ** 2)

                    if (dist < 30) {
                        foundEdge = edge
                        break
                    }
                }
                setHoveredEdge(foundEdge)
            } else {
                setHoveredEdge(null)
            }

            e.currentTarget.style.cursor = node ? 'pointer' : 'default'
        }
    }, [draggedNode, dragOffset, getNodeAtPosition, zoomLevel, edges, positions])

    const handleMouseUp = useCallback(() => {
        setDraggedNode(null)
    }, [])

    const handleClick = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        if (hasDragged.current) {
            hasDragged.current = false
            return
        }
        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top
        const node = getNodeAtPosition(x, y, rect)

        // Click to select node (shows info panel)
        if (node) {
            setSelectedNode(node)
        } else {
            // Click on empty space clears selection
            setSelectedNode(null)
        }
    }, [getNodeAtPosition])


    const resetLayout = useCallback(() => {
        if (containerRef.current) {
            const rect = containerRef.current.getBoundingClientRect()
            setPositions(calculatePositions(rect.width, rect.height))
        }
        setZoomLevel(0.9)
    }, [calculatePositions])

    return (
        <div ref={containerRef} className="absolute inset-0">
            <canvas
                ref={canvasRef}
                className="absolute inset-0"
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
                onClick={handleClick}
            />

            {/* Info Panel - Always visible */}
            <div className="absolute top-3 left-3 z-10 bg-[#1A2028]/95 backdrop-blur-md rounded-lg border border-dark-border p-4 shadow-lg w-[280px]">
                {/* Header */}
                <div className="text-[10px] text-dark-text-muted uppercase tracking-wider mb-3 pb-2 border-b border-dark-border">
                    {t('nodeDetails')}
                </div>

                {selectedNode ? (
                    <>
                        {/* Relationship Badge */}
                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                <div className="w-3 h-3 rounded" style={{ backgroundColor: NODE_COLORS[selectedNode.group].bg }} />
                                <span className="text-xs font-medium text-dark-text uppercase tracking-wide">
                                    {RELATION_LABELS[selectedNode.group as RelationType] || selectedNode.group}
                                </span>
                            </div>
                            <button
                                onClick={() => setSelectedNode(null)}
                                className="text-dark-text-muted hover:text-dark-text transition-colors p-1 hover:bg-dark-border/30 rounded"
                            >
                                <X className="w-3.5 h-3.5" />
                            </button>
                        </div>

                        {/* Title */}
                        <div className="text-base font-semibold text-dark-text mb-2 leading-tight">
                            {selectedNode.title}
                        </div>

                        {/* Author */}
                        {selectedNode.authorName && (
                            <div className="flex items-center gap-2 text-sm text-dark-text-muted mb-2">
                                <span className="text-dark-text-muted/60">By</span>
                                <span className="text-dark-text">{selectedNode.authorName}</span>
                            </div>
                        )}

                        {/* Tag */}
                        <div className="inline-block bg-dark-border/40 text-xs text-dark-text-muted px-2 py-1 rounded mb-3">
                            #{selectedNode.tag}
                        </div>

                        {/* Relationship Explanation */}
                        <div className="bg-dark-border/20 rounded p-2 mb-3">
                            <div className="text-[10px] text-dark-text-muted uppercase tracking-wider mb-1">{t('connection')}</div>
                            <div className="text-xs text-dark-text">
                                {selectedNode.group === 'center' && t('currentlyViewing')}
                                {selectedNode.group === 'fork' && t('highlightFork')}
                                {selectedNode.group === 'citation' && t('highlightCitation')}
                                {selectedNode.group === 'related' && t('highlightTopic')}
                                {selectedNode.group === 'author' && t('highlightAuthor')}
                            </div>
                        </div>

                        {/* Action Button */}
                        {selectedNode.group !== 'center' && (
                            <Button
                                onClick={() => window.location.href = selectedNode.contentType === 'resource' ? `/resources/${selectedNode.id}` : `/post/${selectedNode.id}`}
                                className="w-full bg-secondary hover:bg-secondary/80 text-white text-sm h-9 font-medium"
                            >
                                {selectedNode.contentType === 'resource' ? t('viewResource') : t('viewPost')} ΓåÆ
                            </Button>
                        )}
                        {selectedNode.group === 'center' && (
                            <div className="text-center text-xs text-secondary py-2">
                                {t('currentlyViewing')}
                            </div>
                        )}
                    </>
                ) : hoveredEdge ? (
                    <>
                        {/* Edge Hover Info */}
                        <div className="flex items-center gap-2 mb-3">
                            <div className="w-8 h-0.5" style={{
                                backgroundColor: hoveredEdge.type === 'citation' ? THEME_COLORS.citation :
                                    hoveredEdge.type === 'fork' ? THEME_COLORS.accent : THEME_COLORS.secondary,
                            }} />
                            <span className="text-sm font-medium text-dark-text uppercase tracking-wide">
                                {RELATION_LABELS[hoveredEdge.type]}
                            </span>
                        </div>
                        <div className="text-sm text-dark-text">
                            {EDGE_DESCRIPTIONS[hoveredEdge.type]}
                        </div>
                    </>
                ) : (
                    <>
                        {/* Empty State - Instructions */}
                        <div className="text-center py-4">
                            <div className="text-4xl mb-3 opacity-40">≡ƒöì</div>
                            <div className="text-sm text-dark-text mb-2">{t('selectNode')}</div>
                            <div className="text-xs text-dark-text-muted leading-relaxed">
                                {t('exploreHint')}
                            </div>
                        </div>

                        {/* Quick Stats */}
                        <div className="border-t border-dark-border pt-3 mt-3">
                            <div className="text-[10px] text-dark-text-muted uppercase tracking-wider mb-2">{t('graphOverview')}</div>
                            <div className="grid grid-cols-2 gap-2 text-xs">
                                <div className="bg-dark-border/30 rounded p-2 text-center">
                                    <div className="text-lg font-bold text-dark-text">{nodes.length}</div>
                                    <div className="text-dark-text-muted">{t('nodes')}</div>
                                </div>
                                <div className="bg-dark-border/30 rounded p-2 text-center">
                                    <div className="text-lg font-bold text-dark-text">{edges.length}</div>
                                    <div className="text-dark-text-muted">{t('connections')}</div>
                                </div>
                            </div>
                        </div>
                    </>
                )}
            </div>

            {/* Controls */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-10 flex items-center gap-1 bg-[#1A2028]/95 backdrop-blur-md rounded-full border border-dark-border p-1.5 shadow-lg">
                <Button variant="ghost" size="icon" onClick={() => setZoomLevel(z => Math.min(z * 1.2, 2))} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Zoom in">
                    <ZoomIn className="w-4 h-4" />
                </Button>
                <Button variant="ghost" size="icon" onClick={() => setZoomLevel(z => Math.max(z / 1.2, 0.4))} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Zoom out">
                    <ZoomOut className="w-4 h-4" />
                </Button>
                <div className="h-4 w-px bg-dark-border mx-1" />
                <Button variant="ghost" size="icon" onClick={resetLayout} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Reset layout">
                    <RotateCcw className="w-4 h-4" />
                </Button>
            </div>

            {/* Legend */}
            <div className="absolute top-3 right-3 z-10 bg-[#1A2028]/90 backdrop-blur-md rounded-lg border border-dark-border p-3 shadow-sm">
                <div className="text-[10px] text-dark-text-muted uppercase tracking-wide mb-2">{t('nodeTypes')}</div>
                <div className="flex flex-wrap gap-3 text-xs mb-3">
                    {Object.entries(NODE_COLORS).filter(([key]) => key !== 'center').map(([key, colors]) => (
                        <div key={key} className="flex items-center gap-1.5">
                            <div className="w-3 h-3 rounded" style={{ backgroundColor: colors.bg }} />
                            <span className="text-dark-text-muted capitalize">
                                {key === 'related' ? t('relations.shared_tag') : (RELATION_LABELS[key as RelationType] || key)}
                            </span>
                        </div>
                    ))}
                </div>
                <div className="text-[10px] text-dark-text-muted uppercase tracking-wide mb-2">{t('edgeTypes')}</div>
                <div className="flex flex-col gap-1.5 text-xs">
                    <div className="flex items-center gap-2">
                        <div className="w-5 h-0.5 bg-dark-text-muted" />
                        <span className="text-dark-text-muted">{t('legendSolid')}</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="w-5 h-0 border-t-2 border-dashed border-dark-text-muted" />
                        <span className="text-dark-text-muted">{t('legendDashed')}</span>
                    </div>
                </div>
            </div>

            {/* Purpose Hint */}
            <div className="absolute bottom-16 left-1/2 -translate-x-1/2 z-10 text-xs text-dark-text-muted/70 text-center">
                {t('exploreHint')}
            </div>
        </div>
    )
}

export function KnowledgeGraph({ centerPostId }: KnowledgeGraphProps) {
    const [nodes, setNodes] = useState<GraphNode[]>([])
    const [edges, setEdges] = useState<GraphEdge[]>([])
    const [loading, setLoading] = useState(true)
    const [expanded, setExpanded] = useState(false)
    const [hoveredNode, setHoveredNode] = useState<GraphNode | null>(null)
    const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 })
    const t = useTranslations('KnowledgeGraph')

    const containerRef = useRef<HTMLDivElement>(null)
    const canvasRef = useRef<HTMLCanvasElement>(null)
    const dialogCanvasRef = useRef<HTMLCanvasElement>(null)

    const supabase = useMemo(() => createClient(), [])
    const { resolvedTheme } = useTheme()
    const isDark = resolvedTheme === 'dark'

    // Node positions (will be calculated once and stored)
    const [nodePositions, setNodePositions] = useState<Map<string, { x: number, y: number }>>(new Map())
    const [dialogPositions, setDialogPositions] = useState<Map<string, { x: number, y: number }>>(new Map())
    const [draggedNode, setDraggedNode] = useState<string | null>(null)
    const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 })
    const [zoomLevel, setZoomLevel] = useState(0.85) // Start slightly zoomed out
    const [dialogZoomLevel, setDialogZoomLevel] = useState(0.85)
    const hasDragged = useRef(false) // Track if actual dragging occurred
    const dialogContainerRef = useRef<HTMLDivElement>(null)

    // Fetch graph data
    const fetchGraphData = useCallback(async () => {
        try {
            const { data: centerPost } = await supabase
                .from('posts')
                .select('id, title, forked_from_id, tags, author_id, content_type, users:author_id(name)')
                .eq('id', centerPostId)
                .single()

            if (!centerPost) return

            const newNodes: GraphNode[] = []
            const newEdges: GraphEdge[] = []
            const nodeIds = new Set<string>()

            const addNode = (post: any, group: GraphNode['group'], contentType: 'post' | 'resource' = 'post') => {
                if (nodeIds.has(post.id)) return
                nodeIds.add(post.id)
                // Detect content type from the post data, override if it's a resource
                const detectedType = post.content_type === 'resource' ? 'resource' : contentType
                newNodes.push({
                    id: post.id,
                    title: post.title || post.name || 'Untitled',
                    group,
                    tag: post.tags?.[0] || post.resource_type || 'Research',
                    authorName: post.users?.name || post.created_by_user?.name || 'Unknown',
                    contentType: detectedType
                })
            }

            // Center node - detect content type
            const centerContentType = (centerPost as any).content_type === 'resource' ? 'resource' : 'post'
            addNode({ ...centerPost, users: (centerPost as any).users }, 'center', centerContentType)

            // Parent fork
            if (centerPost.forked_from_id) {
                const { data: parent } = await supabase
                    .from('posts')
                    .select('id, title, tags, author_id, content_type, users:author_id(name)')
                    .eq('id', centerPost.forked_from_id)
                    .single()
                if (parent) {
                    addNode(parent, 'fork')
                    newEdges.push({ source: parent.id, target: centerPost.id, type: 'fork' })
                }
            }

            // Child forks
            const { data: forks } = await supabase
                .from('posts')
                .select('id, title, tags, author_id, content_type, users:author_id(name)')
                .eq('forked_from_id', centerPostId)
                .eq('status', 'published')
                .limit(4)

            forks?.forEach(fork => {
                addNode(fork, 'fork')
                newEdges.push({ source: centerPost.id, target: fork.id, type: 'fork' })
            })

            // Citations
            const { data: citations } = await supabase
                .from('citations')
                .select('source_post_id, posts!citations_source_post_id_fkey(id, title, tags, author_id, content_type, users:author_id(name))')
                .eq('target_post_id', centerPostId)
                .limit(4)

            citations?.forEach((citation: any) => {
                if (citation.posts) {
                    addNode(citation.posts, 'citation')
                    newEdges.push({ source: citation.posts.id, target: centerPost.id, type: 'citation' })
                }
            })

            // Related by tag
            const primaryTag = centerPost.tags?.[0]
            if (primaryTag) {
                const { data: shared } = await supabase
                    .from('posts')
                    .select('id, title, tags, author_id, content_type, users:author_id(name)')
                    .contains('tags', [primaryTag])
                    .neq('id', centerPostId)
                    .eq('status', 'published')
                    .limit(3)

                shared?.forEach(post => {
                    if (!nodeIds.has(post.id)) {
                        addNode(post, 'related')
                        newEdges.push({ source: centerPost.id, target: post.id, type: 'shared_tag' })
                    }
                })
            }

            // Same author
            if (centerPost.author_id) {
                const { data: authorPosts } = await supabase
                    .from('posts')
                    .select('id, title, tags, author_id, content_type, users:author_id(name)')
                    .eq('author_id', centerPost.author_id)
                    .neq('id', centerPostId)
                    .eq('status', 'published')
                    .limit(3)

                authorPosts?.forEach(post => {
                    if (!nodeIds.has(post.id)) {
                        addNode(post, 'author')
                        newEdges.push({ source: centerPost.id, target: post.id, type: 'shared_author' })
                    }
                })
            }

            setNodes(newNodes)
            setEdges(newEdges)
        } catch (err) {
            console.error('Error fetching graph data:', err)
        } finally {
            setLoading(false)
        }
    }, [centerPostId, supabase])

    useEffect(() => { fetchGraphData() }, [fetchGraphData])

    // Calculate initial positions in a clean layout
    const calculatePositions = useCallback((width: number, height: number) => {
        const positions = new Map<string, { x: number, y: number }>()
        const centerX = width / 2
        const centerY = height / 2

        // Group nodes by type
        const centerNode = nodes.find(n => n.group === 'center')
        const forkNodes = nodes.filter(n => n.group === 'fork')
        const citationNodes = nodes.filter(n => n.group === 'citation')
        const relatedNodes = nodes.filter(n => n.group === 'related')
        const authorNodes = nodes.filter(n => n.group === 'author')

        // Center node
        if (centerNode) {
            positions.set(centerNode.id, { x: centerX, y: centerY })
        }

        // Arrange other nodes in concentric arcs
        const arrangeInArc = (nodeList: GraphNode[], radius: number, startAngle: number, sweep: number) => {
            const count = nodeList.length
            if (count === 0) return
            const angleStep = sweep / Math.max(count - 1, 1)
            nodeList.forEach((node, i) => {
                const angle = startAngle + (count === 1 ? sweep / 2 : i * angleStep)
                positions.set(node.id, {
                    x: centerX + Math.cos(angle) * radius,
                    y: centerY + Math.sin(angle) * radius
                })
            })
        }

        // Distribute by type in different directions - even wider spacing
        const radius1 = Math.min(width, height) * 0.42
        const radius2 = Math.min(width, height) * 0.48

        arrangeInArc(forkNodes, radius1, -Math.PI * 0.85, Math.PI * 0.6)     // Top-left arc (wider sweep)
        arrangeInArc(citationNodes, radius1, Math.PI * 0.15, Math.PI * 0.6)  // Bottom-right arc
        arrangeInArc(relatedNodes, radius2, -Math.PI * 0.1, Math.PI * 0.25)  // Right side
        arrangeInArc(authorNodes, radius2, Math.PI * 0.9, Math.PI * 0.25)    // Left side

        return positions
    }, [nodes])

    // Initialize positions when nodes change
    useEffect(() => {
        if (nodes.length > 0 && containerRef.current) {
            const rect = containerRef.current.getBoundingClientRect()
            const positions = calculatePositions(rect.width, rect.height)
            setNodePositions(positions)
        }
    }, [nodes, calculatePositions])

    // Draw the graph on canvas
    const drawGraph = useCallback((canvas: HTMLCanvasElement | null, width: number, height: number) => {
        if (!canvas || nodePositions.size === 0) return

        const ctx = canvas.getContext('2d')
        if (!ctx) return

        // Set canvas size with device pixel ratio for sharp rendering
        const dpr = window.devicePixelRatio || 1
        canvas.width = width * dpr
        canvas.height = height * dpr
        canvas.style.width = `${width}px`
        canvas.style.height = `${height}px`
        ctx.scale(dpr, dpr)

        // Clear - always use dark background
        ctx.fillStyle = THEME_COLORS.darkBg
        ctx.fillRect(0, 0, width, height)

        // Apply zoom transform
        ctx.save()
        const centerX = width / 2
        const centerY = height / 2
        ctx.translate(centerX, centerY)
        ctx.scale(zoomLevel, zoomLevel)
        ctx.translate(-centerX, -centerY)

        // Draw edges first (behind nodes) with semantic styling
        edges.forEach(edge => {
            const sourcePos = nodePositions.get(edge.source)
            const targetPos = nodePositions.get(edge.target)
            if (!sourcePos || !targetPos) return

            // Calculate control points for bezier curve
            const midX = (sourcePos.x + targetPos.x) / 2
            const midY = (sourcePos.y + targetPos.y) / 2
            const dx = targetPos.x - sourcePos.x
            const dy = targetPos.y - sourcePos.y
            const dist = Math.sqrt(dx * dx + dy * dy)

            // Perpendicular offset for curve
            const curvature = dist * 0.15
            const perpX = -dy / dist * curvature
            const perpY = dx / dist * curvature

            // Solid for forks (derived work), dashed for citations
            if (edge.type === 'citation' || edge.type === 'shared_tag') {
                ctx.setLineDash([5, 3])
            } else {
                ctx.setLineDash([])
            }

            ctx.beginPath()
            ctx.moveTo(sourcePos.x, sourcePos.y)
            ctx.quadraticCurveTo(midX + perpX, midY + perpY, targetPos.x, targetPos.y)

            // Edge color based on type
            const edgeColor = edge.type === 'citation' ? THEME_COLORS.citation :
                edge.type === 'fork' ? THEME_COLORS.accent :
                    edge.type === 'shared_author' ? '#6366F1' :
                        THEME_COLORS.secondary

            ctx.lineWidth = 2
            ctx.strokeStyle = `${edgeColor}60`
            ctx.stroke()

            // Reset line dash
            ctx.setLineDash([])
        })

        // Draw nodes
        nodes.forEach(node => {
            const pos = nodePositions.get(node.id)
            if (!pos) return

            const colors = NODE_COLORS[node.group]
            const isCenter = node.group === 'center'
            const isHovered = hoveredNode?.id === node.id

            // Node dimensions - narrower nodes
            const nodeWidth = isCenter ? 110 : 90
            const nodeHeight = isCenter ? 44 : 36
            const radius = 6

            // Shadow
            if (isHovered || isCenter) {
                ctx.shadowColor = `${colors.bg}40`
                ctx.shadowBlur = 15
                ctx.shadowOffsetY = 4
            }

            // Draw rounded rectangle
            ctx.beginPath()
            ctx.roundRect(pos.x - nodeWidth / 2, pos.y - nodeHeight / 2, nodeWidth, nodeHeight, radius)
            ctx.fillStyle = colors.bg
            ctx.fill()
            ctx.strokeStyle = colors.border
            ctx.lineWidth = isHovered ? 3 : 2
            ctx.stroke()

            // Reset shadow
            ctx.shadowColor = 'transparent'
            ctx.shadowBlur = 0
            ctx.shadowOffsetY = 0

            // Title text
            ctx.fillStyle = colors.text
            ctx.font = `${isCenter ? '600' : '500'} ${isCenter ? 12 : 11}px Inter, system-ui, sans-serif`
            ctx.textAlign = 'center'
            ctx.textBaseline = 'middle'

            const title = node.title.length > 12 ? node.title.substring(0, 11) + 'ΓÇª' : node.title
            ctx.fillText(title, pos.x, pos.y - (isCenter ? 5 : 3))

            // Tag badge
            ctx.font = '500 9px Inter, system-ui, sans-serif'
            ctx.fillStyle = `${colors.text}99`
            const tag = node.tag.length > 12 ? node.tag.substring(0, 11) + 'ΓÇª' : node.tag
            ctx.fillText(tag, pos.x, pos.y + (isCenter ? 10 : 8))
        })

        // Restore context after zoom transform
        ctx.restore()

    }, [nodes, edges, nodePositions, hoveredNode, zoomLevel])


    // Redraw on position or zoom changes
    useEffect(() => {
        if (canvasRef.current && containerRef.current) {
            const rect = containerRef.current.getBoundingClientRect()
            drawGraph(canvasRef.current, rect.width, rect.height)
        }
    }, [nodePositions, drawGraph, hoveredNode, zoomLevel])

    // Handle mouse events for dragging and hovering
    const getNodeAtPosition = useCallback((x: number, y: number): GraphNode | null => {
        for (const node of nodes) {
            const pos = nodePositions.get(node.id)
            if (!pos) continue
            const isCenter = node.group === 'center'
            const nodeWidth = isCenter ? 110 : 90
            const nodeHeight = isCenter ? 44 : 36

            if (x >= pos.x - nodeWidth / 2 && x <= pos.x + nodeWidth / 2 &&
                y >= pos.y - nodeHeight / 2 && y <= pos.y + nodeHeight / 2) {
                return node
            }
        }
        return null
    }, [nodes, nodePositions])

    const handleMouseDown = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top
        const node = getNodeAtPosition(x, y)

        hasDragged.current = false // Reset on mousedown

        if (node) {
            const pos = nodePositions.get(node.id)
            if (pos) {
                setDraggedNode(node.id)
                setDragOffset({ x: x - pos.x, y: y - pos.y })
            }
        }
    }, [getNodeAtPosition, nodePositions])

    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top

        if (draggedNode) {
            hasDragged.current = true // Mark that we actually dragged

            // Bounded dragging - keep nodes within container
            const padding = 70
            const newX = Math.max(padding, Math.min(rect.width - padding, x - dragOffset.x))
            const newY = Math.max(padding, Math.min(rect.height - padding, y - dragOffset.y))

            setNodePositions(prev => {
                const next = new Map(prev)
                next.set(draggedNode, { x: newX, y: newY })
                return next
            })
        } else {
            // Hover detection
            const node = getNodeAtPosition(x, y)
            setHoveredNode(node)
            setTooltipPos({ x: e.clientX, y: e.clientY })

            // Change cursor
            e.currentTarget.style.cursor = node ? 'pointer' : 'default'
        }
    }, [draggedNode, dragOffset, getNodeAtPosition])

    const handleMouseUp = useCallback(() => {
        setDraggedNode(null)
    }, [])

    const handleClick = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
        // Don't navigate if we actually dragged
        if (hasDragged.current) {
            hasDragged.current = false
            return
        }

        const rect = e.currentTarget.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top
        const node = getNodeAtPosition(x, y)

        if (node && node.group !== 'center') {
            const route = node.contentType === 'resource' ? '/resources/' : '/post/'
            window.location.href = `${route}${node.id}`
        }
    }, [getNodeAtPosition])

    const resetLayout = useCallback(() => {
        if (containerRef.current) {
            const rect = containerRef.current.getBoundingClientRect()
            const positions = calculatePositions(rect.width, rect.height)
            setNodePositions(positions)
        }
        setZoomLevel(0.85)
    }, [calculatePositions])

    const zoomIn = useCallback(() => {
        setZoomLevel(prev => Math.min(prev * 1.2, 2))
    }, [])

    const zoomOut = useCallback(() => {
        setZoomLevel(prev => Math.max(prev / 1.2, 0.4))
    }, [])

    // Handle resize
    useEffect(() => {
        const handleResize = () => {
            if (containerRef.current && canvasRef.current) {
                const rect = containerRef.current.getBoundingClientRect()
                drawGraph(canvasRef.current, rect.width, rect.height)
            }
        }

        const observer = new ResizeObserver(handleResize)
        if (containerRef.current) {
            observer.observe(containerRef.current)
        }

        return () => observer.disconnect()
    }, [drawGraph])

    if (loading) {
        return (
            <div className="relative border border-dark-border rounded-xl overflow-hidden bg-[#0F1419] h-[400px] w-full flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-secondary" />
            </div>
        )
    }

    if (nodes.length <= 1) {
        return (
            <div className="relative border border-dark-border rounded-xl overflow-hidden bg-[#0F1419] h-[200px] w-full flex items-center justify-center">
                <p className="text-dark-text-muted text-sm">{t('noConnections')}</p>
            </div>
        )
    }

    return (
        <>
            <div
                ref={containerRef}
                className="relative border border-dark-border rounded-xl overflow-hidden bg-[#0F1419] h-[400px] w-full"
            >
                <canvas
                    ref={canvasRef}
                    className="absolute inset-0"
                    onMouseDown={handleMouseDown}
                    onMouseMove={handleMouseMove}
                    onMouseUp={handleMouseUp}
                    onMouseLeave={handleMouseUp}
                    onClick={handleClick}
                />

                {/* Controls */}
                <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-10 flex items-center gap-1 bg-[#1A2028]/95 backdrop-blur-md rounded-full border border-dark-border p-1.5 shadow-lg">
                    <Button variant="ghost" size="icon" onClick={zoomIn} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Zoom in">
                        <ZoomIn className="w-4 h-4" />
                    </Button>
                    <Button variant="ghost" size="icon" onClick={zoomOut} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Zoom out">
                        <ZoomOut className="w-4 h-4" />
                    </Button>
                    <div className="h-4 w-px bg-dark-border mx-1" />
                    <Button variant="ghost" size="icon" onClick={resetLayout} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Reset layout">
                        <RotateCcw className="w-4 h-4" />
                    </Button>
                    <div className="h-4 w-px bg-dark-border mx-1" />
                    <Button variant="ghost" size="icon" onClick={() => setExpanded(true)} className="h-8 w-8 rounded-full text-dark-text-muted hover:text-dark-text hover:bg-dark-border/50" title="Expand">
                        <Maximize2 className="w-4 h-4" />
                    </Button>
                </div>

                {/* Legend */}
                <div className="absolute top-3 right-3 z-10 bg-[#1A2028]/90 backdrop-blur-md rounded-lg border border-dark-border p-2 shadow-sm">
                    <div className="flex flex-wrap gap-2 text-[10px]">
                        {Object.entries(NODE_COLORS).slice(0, 4).map(([key, colors]) => (
                            <div key={key} className="flex items-center gap-1">
                                <div className="w-2.5 h-2.5 rounded" style={{ backgroundColor: colors.bg }} />
                                <span className="text-dark-text-muted">
                                    {key === 'center' ? t('legend.center') :
                                        key === 'fork' ? t('legend.fork') :
                                            key === 'citation' ? t('legend.citation') :
                                                key === 'related' ? t('legend.topic') : key}
                                </span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Tooltip */}
                {hoveredNode && hoveredNode.group !== 'center' && (
                    <div
                        className="fixed z-50 pointer-events-none"
                        style={{ left: tooltipPos.x + 10, top: tooltipPos.y + 10 }}
                    >
                        <div className="bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-lg shadow-xl p-3 min-w-[180px]">
                            <div className="text-xs font-medium text-text-muted dark:text-dark-text-muted mb-1">
                                {RELATION_LABELS[edges.find(e => e.source === hoveredNode.id || e.target === hoveredNode.id)?.type || 'shared_tag']}
                            </div>
                            <div className="font-semibold text-sm text-text dark:text-dark-text">
                                {hoveredNode.title}
                            </div>
                            {hoveredNode.authorName && (
                                <div className="text-xs text-text-light dark:text-dark-text-muted mt-1">
                                    {t('byAuthor', { author: hoveredNode.authorName })}
                                </div>
                            )}
                            <div className="text-xs text-secondary dark:text-secondary-light mt-1">
                                {hoveredNode?.contentType === 'resource' ? t('viewResource') : t('viewPost')} ΓåÆ
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Expanded Dialog */}
            <Dialog open={expanded} onOpenChange={setExpanded}>
                <DialogContent className="max-w-[95vw] w-[95vw] h-[90vh] flex flex-col p-0 gap-0 bg-[#0F1419] overflow-hidden">
                    <DialogHeader className="p-4 border-b border-dark-border flex-shrink-0">
                        <div className="flex items-center justify-between">
                            <DialogTitle className="text-dark-text">{t('explorerTitle')}</DialogTitle>
                        </div>
                    </DialogHeader>
                    <div className="flex-1 relative overflow-hidden bg-[#0F1419]">
                        <DialogGraphCanvas
                            nodes={nodes}
                            edges={edges}
                            calculatePositions={calculatePositions}
                            expanded={expanded}
                        />
                    </div>
                </DialogContent>
            </Dialog>
        </>
    )
}

