'use client'

import React from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { cn, stripMarkdown, getInitials, getAvatarGradient } from '@/lib/utils'
import { Clock, Bookmark, Eye, Calendar } from 'lucide-react'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import { useCoverWithFallback } from '@/lib/coverImages'

export type MagazineCardVariant = 'featured' | 'standard' | 'compact' | 'horizontal'

interface MagazineCardProps {
    post: {
        id: string
        title: string
        content?: string
        excerpt?: string
        created_at: string
        author?: {
            id: string
            name?: string
            email?: string
            avatar_url?: string
        }
        tags?: string[]
        views?: number
        cover_image_url?: string | null
        content_type?: string | null
        metadata?: {
            start_time?: string
            end_time?: string
            location?: string
            status?: string
        } | null
    }
    variant?: MagazineCardVariant
    className?: string
    priority?: boolean
    showImage?: boolean
}

// Estimated reading time calculation
function getReadingTime(content?: string): number {
    if (!content) return 2
    const wordsPerMinute = 200
    const words = content.trim().split(/\s+/).length
    return Math.max(1, Math.ceil(words / wordsPerMinute))
}



export function MagazineCard({
    post,
    variant = 'standard',
    className,
    priority = false,
    showImage = true,
}: MagazineCardProps) {
    const { formatDate, locale } = useDateFormatter()
    const t = useTranslations('Landing')
    const readingTime = getReadingTime(post.content)
    const isEvent = post.content_type === 'event'
    const rawExcerpt = post.excerpt || post.content || ''
    const excerpt = stripMarkdown(rawExcerpt).substring(0, 150).trim() + (rawExcerpt.length > 150 ? '...' : '')

    // Format relative time with locale support
    const formatRelativeTime = (dateString: string): string => {
        const date = new Date(dateString)
        const now = new Date()
        const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000)

        // Use generic relative time for recent posts
        if (diffInSeconds < 60) return locale === 'ar' ? '╪º┘ä╪ó┘å' : 'Just now'
        if (diffInSeconds < 3600) return locale === 'ar' ? `┘à┘å╪░ ${Math.floor(diffInSeconds / 60)} ╪»` : `${Math.floor(diffInSeconds / 60)}m ago`
        if (diffInSeconds < 86400) return locale === 'ar' ? `┘à┘å╪░ ${Math.floor(diffInSeconds / 3600)} ╪│` : `${Math.floor(diffInSeconds / 3600)}h ago`
        if (diffInSeconds < 604800) return locale === 'ar' ? `┘à┘å╪░ ${Math.floor(diffInSeconds / 86400)} ┘è` : `${Math.floor(diffInSeconds / 86400)}d ago`

        return formatDate(date, 'short')
    }

    // Format event date with locale support
    const formatEventDate = (dateString?: string): string => {
        if (!dateString) return locale === 'ar' ? '╪º┘ä╪¬╪º╪▒┘è╪« ╪║┘è╪▒ ┘à╪¡╪»╪»' : 'Date TBD'
        return formatDate(dateString, 'medium')
    }

    const eventDate = isEvent ? formatEventDate(post.metadata?.start_time) : ''

    // Get cover image with theme-aware fallback
    const coverImage = useCoverWithFallback(post.cover_image_url, 'medium')

    // Featured variant - large card with image background
    if (variant === 'featured') {
        return (
            <Link
                href={post.content_type === 'event' ? `/events/${post.id}` : `/post/${post.id}`}
                className={cn(
                    'group relative flex flex-col justify-end h-full min-h-[320px] p-6 md:p-8',
                    'rounded-2xl overflow-hidden',
                    'bg-gradient-to-br from-gray-900 to-gray-800',
                    'transition-all duration-300',
                    'hover:shadow-soft-xl',
                    className
                )}
            >
                {/* Background image with fallback */}
                {showImage && (
                    <div
                        className="absolute inset-0 bg-cover bg-center transition-transform duration-500 group-hover:scale-105 will-change-transform"
                        style={{ backgroundImage: `url(${coverImage})` }}
                    />
                )}

                {/* Overlay gradient - semi-transparent to show cover image */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-black/10" />

                {/* Content */}
                <div className="relative z-10 space-y-4">
                    {/* Tags */}
                    {post.tags && post.tags.length > 0 && (
                        <div className="flex flex-wrap gap-2">
                            {post.tags.slice(0, 2).map((tag) => (
                                <span
                                    key={tag}
                                    className="px-3 py-1 text-xs font-medium bg-white/20 backdrop-blur-sm text-white rounded-full"
                                >
                                    {tag}
                                </span>
                            ))}
                        </div>
                    )}

                    {/* Title */}
                    <h3 className="text-2xl md:text-3xl font-bold text-white leading-tight group-hover:text-primary-light transition-colors">
                        {post.title}
                    </h3>

                    {/* Meta */}
                    <div className="flex items-center gap-4 text-sm text-white/70">
                        {post.author && (
                            <div className="flex items-center gap-2">
                                {post.author.avatar_url ? (
                                    <Image
                                        src={post.author.avatar_url}
                                        alt={post.author.name || ''}
                                        width={24}
                                        height={24}
                                        className="w-6 h-6 rounded-full object-cover"
                                    />
                                ) : (
                                    <div className={cn(
                                        'w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-medium text-white',
                                        getAvatarGradient(post.author.id)
                                    )}>
                                        {getInitials(post.author.name, post.author.email)}
                                    </div>
                                )}
                                <span>{post.author.name || post.author.email?.split('@')[0]}</span>
                            </div>
                        )}
                        {isEvent ? (
                            <div className="flex items-center gap-1 text-white bg-primary/20 backdrop-blur-sm px-2 py-0.5 rounded-full border border-primary/30">
                                <Calendar className="w-3.5 h-3.5 text-primary-light" />
                                <span className="text-primary-light font-medium">{eventDate}</span>
                            </div>
                        ) : (
                            <>
                                <div className="flex items-center gap-1">
                                    <Clock className="w-3.5 h-3.5" />
                                    <span className="truncate max-w-[80px]">{t('minRead', { count: readingTime })}</span>
                                </div>
                                <span className="text-white/50">┬╖</span>
                                <span>{formatRelativeTime(post.created_at)}</span>
                            </>
                        )}
                    </div>
                </div>
            </Link>
        )
    }

    // Horizontal variant - image on left, text on right
    if (variant === 'horizontal') {
        return (
            <Link
                href={post.content_type === 'event' ? `/events/${post.id}` : `/post/${post.id}`}
                className={cn(
                    'group flex gap-4 p-4 rounded-xl bg-white dark:bg-dark-surface',
                    'border border-gray-100 dark:border-dark-border',
                    'transition-all duration-300',
                    'hover:shadow-soft-md hover:-translate-y-0.5',
                    className
                )}
            >
                {/* Image */}
                {showImage && (
                    <div className="flex-shrink-0 w-24 h-24 md:w-32 md:h-32 rounded-lg overflow-hidden bg-gray-100 dark:bg-dark-border">
                        <div
                            className="w-full h-full bg-cover bg-center transition-transform duration-300 group-hover:scale-105 will-change-transform"
                            style={{ backgroundImage: `url(${coverImage})` }}
                        />
                    </div>
                )}

                {/* Content */}
                <div className="flex-1 min-w-0 flex flex-col justify-center">
                    {post.tags && post.tags.length > 0 && (
                        <span className="text-xs font-medium text-primary dark:text-primary-light mb-1">
                            {post.tags[0]}
                        </span>
                    )}

                    <h3 className="text-base md:text-lg font-semibold text-text dark:text-dark-text line-clamp-2 group-hover:text-primary transition-colors">
                        {post.title}
                    </h3>

                    <div className="flex items-center gap-3 mt-2 text-xs text-text-muted dark:text-dark-text-muted">
                        <div className="flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            <span className="truncate max-w-[80px]">{t('minRead', { count: readingTime })}</span>
                        </div>
                        <span>┬╖</span>
                        <span>{formatRelativeTime(post.created_at)}</span>
                    </div>
                </div>
            </Link>
        )
    }

    // Compact variant - minimal text-only card
    if (variant === 'compact') {
        return (
            <Link
                href={post.content_type === 'event' ? `/events/${post.id}` : `/post/${post.id}`}
                className={cn(
                    'group block p-4 rounded-xl',
                    'bg-gray-50 dark:bg-dark-surface/50',
                    'border border-transparent hover:border-gray-200 dark:hover:border-dark-border',
                    'transition-all duration-200',
                    className
                )}
            >
                {post.tags && post.tags.length > 0 && (
                    <span className="text-xs font-medium text-primary dark:text-primary-light uppercase tracking-wider">
                        {post.tags[0]}
                    </span>
                )}

                <h3 className="mt-1 text-base font-semibold text-text dark:text-dark-text line-clamp-2 group-hover:text-primary transition-colors">
                    {post.title}
                </h3>

                <p className="mt-2 text-sm text-text-light dark:text-dark-text-muted line-clamp-2">
                    {excerpt}
                </p>

                <div className="mt-3 flex items-center justify-between text-xs text-text-muted dark:text-dark-text-muted">
                    <div className="flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        <span className="truncate max-w-[80px]">{t('minRead', { count: readingTime })}</span>
                    </div>
                    <span>{formatRelativeTime(post.created_at)}</span>
                </div>
            </Link>
        )
    }

    // Standard variant - default magazine card
    return (
        <Link
            href={`/post/${post.id}`}
            className={cn(
                'group flex flex-col h-full rounded-2xl overflow-hidden',
                'bg-white dark:bg-dark-surface',
                'border border-gray-100 dark:border-dark-border',
                'transition-all duration-300',
                'hover:shadow-soft-lg hover:-translate-y-1',
                className
            )}
        >
            {/* Image */}
            {showImage && (
                <div className="relative aspect-[16/10] overflow-hidden bg-gray-100 dark:bg-dark-border">
                    <div
                        className="absolute inset-0 bg-cover bg-center transition-transform duration-500 group-hover:scale-105 will-change-transform"
                        style={{ backgroundImage: `url(${coverImage})` }}
                    />

                    {/* Bookmark icon */}
                    <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <div className="p-2 bg-white/90 dark:bg-dark-surface/90 backdrop-blur-sm rounded-full shadow-sm">
                            <Bookmark className="w-4 h-4 text-text dark:text-dark-text" />
                        </div>
                    </div>

                    {/* Event Banner */}
                    {post.content_type === 'event' && (
                        <div className="absolute bottom-0 left-0 right-0 bg-primary/90 backdrop-blur-sm py-1.5 px-4 flex items-center justify-center gap-2 text-white">
                            <Calendar className="w-3.5 h-3.5" />
                            <span className="text-xs font-bold uppercase tracking-wide">{t('event')}</span>
                        </div>
                    )}
                </div>
            )}

            {/* Content */}
            <div className="flex-1 flex flex-col p-5">
                {/* Tags */}
                {post.tags && post.tags.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-3">
                        {post.tags.slice(0, 2).map((tag) => (
                            <span
                                key={tag}
                                className="px-2.5 py-0.5 text-xs font-medium bg-primary/10 text-primary dark:bg-white/5 dark:text-white/50 rounded-full"
                            >
                                {tag}
                            </span>
                        ))}
                    </div>
                )}

                {/* Title */}
                <h3 className="text-lg font-semibold text-text dark:text-dark-text line-clamp-2 group-hover:text-primary transition-colors leading-snug">
                    {post.title}
                </h3>

                {/* Excerpt */}
                <p className="mt-2 text-sm text-text-light dark:text-dark-text-muted line-clamp-2 flex-1">
                    {excerpt}
                </p>

                {/* Footer */}
                <div className="mt-4 pt-4 border-t border-gray-100 dark:border-dark-border flex items-center justify-between">
                    {/* Author */}
                    {post.author && (
                        <div className="flex items-center gap-2">
                            {post.author.avatar_url ? (
                                <Image
                                    src={post.author.avatar_url}
                                    alt={post.author.name || ''}
                                    width={28}
                                    height={28}
                                    className="w-7 h-7 rounded-full object-cover"
                                />
                            ) : (
                                <div className={cn(
                                    'w-7 h-7 rounded-full flex items-center justify-center text-xs font-medium text-white',
                                    getAvatarGradient(post.author.id)
                                )}>
                                    {getInitials(post.author.name, post.author.email)}
                                </div>
                            )}
                            <span className="text-sm text-text-light dark:text-dark-text-muted truncate max-w-[100px]">
                                {post.author.name || post.author.email?.split('@')[0]}
                            </span>
                        </div>
                    )}

                    {/* Meta */}
                    <div className="flex items-center gap-2 text-xs text-text-muted dark:text-dark-text-muted">
                        <div className="flex items-center gap-1">
                            <Clock className="w-3.5 h-3.5" />
                            <span className="truncate max-w-[80px]">{t('minRead', { count: readingTime })}</span>
                        </div>
                        <span>┬╖</span>
                        <span>{formatRelativeTime(post.created_at)}</span>
                        {post.views !== undefined && post.views > 0 && (
                            <>
                                <span>┬╖</span>
                                <div className="flex items-center gap-1">
                                    <Eye className="w-3.5 h-3.5" />
                                    <span>{post.views}</span>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </Link>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import {
    AlertTriangle,
    Clock,
    CheckCircle2,
    XCircle,
    Filter,
    ArrowUpDown,
    Eye,
    MessageSquare,
    Flag,
    ChevronDown,
    ExternalLink
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { formatDistanceToNow } from 'date-fns'
import { useTranslations } from 'next-intl'

type Severity = 'low' | 'medium' | 'critical'
type SortOption = 'severity' | 'time' | 'type'

interface Report {
    id: string
    post_id: string
    reason: string
    details: string | null
    status: 'pending' | 'reviewing' | 'resolved' | 'dismissed'
    severity?: Severity
    confidence_score?: number
    created_at: string
    reporter_id: string
    post?: {
        id: string
        title: string
        author_id: string
    }
    reporter?: {
        name: string
        email: string
    }
}

interface ModerationTriageProps {
    onReportAction?: (reportId: string, action: 'resolve' | 'dismiss') => void
}

/**
 * Calculate severity based on report reason and optional AI confidence score
 */
function calculateSeverity(reason: string, confidenceScore?: number): Severity {
    const criticalReasons = ['hate_speech', 'harassment', 'violence', 'illegal_content', 'spam']
    const mediumReasons = ['misinformation', 'plagiarism', 'inappropriate', 'off_topic']

    // If we have AI confidence score, use thresholds
    if (confidenceScore !== undefined) {
        if (confidenceScore >= 0.7) return 'critical'
        if (confidenceScore >= 0.4) return 'medium'
        return 'low'
    }

    // Fallback to reason-based categorization
    if (criticalReasons.includes(reason)) return 'critical'
    if (mediumReasons.includes(reason)) return 'medium'
    return 'low'
}

export function ModerationTriage({ onReportAction }: ModerationTriageProps) {
    const t = useTranslations('ModerationTriage')
    const tCommon = useTranslations('Common')
    const [reports, setReports] = useState<Report[]>([])
    const [loading, setLoading] = useState(true)
    const [sortBy, setSortBy] = useState<SortOption>('severity')
    const [filterSeverity, setFilterSeverity] = useState<Severity | 'all'>('all')
    const [selectedReports, setSelectedReports] = useState<Set<string>>(new Set())
    const [processing, setProcessing] = useState(false)
    const supabase = useMemo(() => createClient(), [])

    const severityConfig = useMemo(() => ({
        critical: {
            label: t('severity.critical'),
            color: 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 border-red-200 dark:border-red-800',
            dotColor: 'bg-red-500',
            sortOrder: 0
        },
        medium: {
            label: t('severity.medium'),
            color: 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-amber-300 border-yellow-200 dark:border-yellow-800',
            dotColor: 'bg-yellow-500',
            sortOrder: 1
        },
        low: {
            label: t('severity.low'),
            color: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-emerald-300 border-green-200 dark:border-green-800',
            dotColor: 'bg-green-500',
            sortOrder: 2
        }
    }), [t])


    const fetchReports = useCallback(async () => {
        setLoading(true)
        try {
            const { data, error } = await supabase
                .from('reports')
                .select(`
          *,
          post:posts(id, title, author_id),
          reporter:users!reports_reporter_id_fkey(name, email)
        `)
                .in('status', ['pending', 'reviewing'])
                .order('created_at', { ascending: false })

            if (error) throw error

            // Enrich reports with calculated severity
            const enrichedReports = (data || []).map(report => ({
                ...report,
                severity: calculateSeverity(report.reason, report.confidence_score)
            }))

            setReports(enrichedReports)
        } catch (error) {
            console.error('Error fetching reports:', error)
        } finally {
            setLoading(false)
        }
    }, [supabase])

    useEffect(() => {
        fetchReports()
    }, [fetchReports])


    // Sort and filter reports
    const processedReports = useMemo(() => {
        let filtered = reports

        // Apply severity filter
        if (filterSeverity !== 'all') {
            filtered = filtered.filter(r => r.severity === filterSeverity)
        }

        // Apply sorting
        return [...filtered].sort((a, b) => {
            switch (sortBy) {
                case 'severity':
                    return (severityConfig[a.severity || 'low'].sortOrder) -
                        (severityConfig[b.severity || 'low'].sortOrder)
                case 'time':
                    return new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
                case 'type':
                    return a.reason.localeCompare(b.reason)
                default:
                    return 0
            }
        })
    }, [reports, sortBy, filterSeverity, severityConfig])

    // Severity counts
    const severityCounts = useMemo(() => ({
        critical: reports.filter(r => r.severity === 'critical').length,
        medium: reports.filter(r => r.severity === 'medium').length,
        low: reports.filter(r => r.severity === 'low').length
    }), [reports])

    async function handleAction(reportId: string, action: 'resolve' | 'dismiss') {
        try {
            const newStatus = action === 'resolve' ? 'resolved' : 'dismissed'

            const { error } = await supabase
                .from('reports')
                .update({ status: newStatus })
                .eq('id', reportId)

            if (error) throw error

            setReports(prev => prev.filter(r => r.id !== reportId))
            selectedReports.delete(reportId)
            setSelectedReports(new Set(selectedReports))

            onReportAction?.(reportId, action)
        } catch (error) {
            console.error('Error updating report:', error)
        }
    }

    async function handleBulkAction(action: 'resolve' | 'dismiss') {
        if (selectedReports.size === 0) return
        setProcessing(true)

        try {
            const newStatus = action === 'resolve' ? 'resolved' : 'dismissed'

            const { error } = await supabase
                .from('reports')
                .update({ status: newStatus })
                .in('id', Array.from(selectedReports))

            if (error) throw error

            setReports(prev => prev.filter(r => !selectedReports.has(r.id)))
            setSelectedReports(new Set())
        } catch (error) {
            console.error('Error bulk updating reports:', error)
        } finally {
            setProcessing(false)
        }
    }

    function toggleSelect(reportId: string) {
        const newSelected = new Set(selectedReports)
        if (newSelected.has(reportId)) {
            newSelected.delete(reportId)
        } else {
            newSelected.add(reportId)
        }
        setSelectedReports(newSelected)
    }

    function selectAll() {
        if (selectedReports.size === processedReports.length) {
            setSelectedReports(new Set())
        } else {
            setSelectedReports(new Set(processedReports.map(r => r.id)))
        }
    }

    if (loading) {
        return (
            <div className="space-y-4">
                {[1, 2, 3].map(i => (
                    <div key={i} className="h-24 rounded-xl bg-gray-100 dark:bg-dark-surface animate-pulse" />
                ))}
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Severity Summary */}
            <div className="grid grid-cols-3 gap-4">
                {(['critical', 'medium', 'low'] as Severity[]).map(severity => (
                    <button
                        key={severity}
                        onClick={() => setFilterSeverity(filterSeverity === severity ? 'all' : severity)}
                        className={`p-4 rounded-xl border transition-all ${filterSeverity === severity
                            ? severityConfig[severity].color + ' ring-2 ring-offset-2 dark:ring-offset-dark-bg ring-current'
                            : 'bg-white dark:bg-dark-surface border-gray-200 dark:border-dark-border hover:border-gray-300 text-text dark:text-gray-400'
                            }`}
                    >
                        <div className="flex items-center justify-between">
                            <span className="text-2xl font-bold">{severityCounts[severity]}</span>
                            <div className={`w-3 h-3 rounded-full ${severityConfig[severity].dotColor}`} />
                        </div>
                        <span className="text-sm font-medium mt-1 block text-text-light dark:text-gray-300">{severityConfig[severity].label}</span>
                    </button>
                ))}
            </div>

            {/* Controls */}
            <div className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <select
                            value={sortBy}
                            onChange={(e) => setSortBy(e.target.value as SortOption)}
                            className="select-input appearance-none pr-8 text-sm"
                        >
                            <option value="severity">{t('sortBy.severity')}</option>
                            <option value="time">{t('sortBy.time')}</option>
                            <option value="type">{t('sortBy.type')}</option>
                        </select>
                        <ArrowUpDown className="absolute right-2 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light pointer-events-none" />
                    </div>

                    {selectedReports.size > 0 && (
                        <div className="flex items-center gap-2">
                            <Button
                                size="sm"
                                variant="outline"
                                onClick={() => handleBulkAction('resolve')}
                                disabled={processing}
                                className="gap-1"
                            >
                                <CheckCircle2 className="w-4 h-4" />
                                {t('actions.resolve')} ({selectedReports.size})
                            </Button>
                            <Button
                                size="sm"
                                variant="outline"
                                onClick={() => handleBulkAction('dismiss')}
                                disabled={processing}
                                className="gap-1"
                            >
                                <XCircle className="w-4 h-4" />
                                {t('actions.dismiss')} ({selectedReports.size})
                            </Button>
                        </div>
                    )}
                </div>

                <button
                    onClick={selectAll}
                    className="text-sm text-text-light dark:text-gray-400 hover:text-primary dark:hover:text-primary-light hover:underline"
                >
                    {selectedReports.size === processedReports.length ? t('deselectAll') : t('selectAll')}
                </button>
            </div>

            {/* Reports List */}
            {processedReports.length === 0 ? (
                <div className="text-center py-12 text-text-light dark:text-dark-text-muted">
                    <CheckCircle2 className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p>{t('noReports')}</p>
                </div>
            ) : (
                <div className="space-y-3">
                    {processedReports.map(report => (
                        <div
                            key={report.id}
                            className={`p-4 rounded-xl border transition-all ${selectedReports.has(report.id)
                                ? 'border-primary bg-primary/5'
                                : 'border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface'
                                }`}
                        >
                            <div className="flex items-start gap-4">
                                {/* Checkbox */}
                                <input
                                    type="checkbox"
                                    checked={selectedReports.has(report.id)}
                                    onChange={() => toggleSelect(report.id)}
                                    className="mt-1 w-4 h-4 rounded border-gray-300 text-primary focus:ring-primary"
                                />

                                {/* Severity Indicator */}
                                <div className={`flex-shrink-0 px-2.5 py-1 rounded-full text-xs font-medium ${severityConfig[report.severity || 'low'].color
                                    }`}>
                                    {severityConfig[report.severity || 'low'].label}
                                    {report.confidence_score !== undefined && (
                                        <span className="ml-1 opacity-75">
                                            ({Math.round(report.confidence_score * 100)}%)
                                        </span>
                                    )}
                                </div>

                                {/* Report Content */}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-start justify-between gap-4">
                                        <div>
                                            <h4 className="font-medium text-text dark:text-dark-text">
                                                {report.post?.title || tCommon('deletedPost')}
                                            </h4>
                                            <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                                                <span className="font-medium capitalize">{report.reason.replace('_', ' ')}</span>
                                                {report.details && ` ΓÇö "${report.details}"`}
                                            </p>
                                        </div>
                                        <span className="text-xs text-text-light dark:text-dark-text-muted flex-shrink-0">
                                            {formatDistanceToNow(new Date(report.created_at), { addSuffix: true })}
                                        </span>
                                    </div>

                                    {/* Reporter Info */}
                                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-2">
                                        {t('reportedBy', { name: report.reporter?.name || report.reporter?.email?.split('@')[0] || tCommon('anonymous') })}
                                    </p>

                                    {/* Actions */}
                                    <div className="flex items-center gap-2 mt-3">
                                        <Link href={`/post/${report.post_id}`} target="_blank">
                                            <Button size="sm" variant="outline" className="gap-1">
                                                <Eye className="w-3.5 h-3.5" />
                                                {t('viewPost')}
                                            </Button>
                                        </Link>
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={() => handleAction(report.id, 'resolve')}
                                            className="gap-1 text-green-600 hover:text-green-700 hover:bg-green-50"
                                        >
                                            <CheckCircle2 className="w-3.5 h-3.5" />
                                            {t('actions.resolve')}
                                        </Button>
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={() => handleAction(report.id, 'dismiss')}
                                            className="gap-1 text-gray-600 hover:text-gray-700"
                                        >
                                            <XCircle className="w-3.5 h-3.5" />
                                            {t('actions.dismiss')}
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useMemo } from 'react'
import Link from 'next/link'
import {
    Bell,
    BellOff,
    Check,
    CheckCheck,
    MessageSquare,
    AtSign,
    UserPlus,
    GitFork,
    Quote,
    ThumbsUp,
    AlertTriangle,
    X,
    Settings,
    Loader2
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { formatDistanceToNow } from 'date-fns'
import { useNotifications } from '@/components/NotificationsProvider'

const CLEARED_NOTIFICATIONS_KEY = 'syriahub_cleared_notifications'

interface Notification {
    id: string
    type: 'mention' | 'reply' | 'follow' | 'fork' | 'citation' | 'like' | 'system' | 'moderation'
    title: string
    message: string
    url?: string
    is_read: boolean
    created_at: string
    metadata?: {
        actor_name?: string
        actor_avatar?: string
        post_title?: string
        [key: string]: any
    }
}

type NotificationFilter = 'all' | 'unread' | 'mentions' | 'social' | 'system'

const notificationIcons: Record<string, any> = {
    mention: AtSign,
    reply: MessageSquare,
    follow: UserPlus,
    fork: GitFork,
    citation: Quote,
    like: ThumbsUp,
    system: Bell,
    moderation: AlertTriangle,
}

const notificationColors: Record<string, string> = {
    mention: 'text-blue-500 bg-blue-50 dark:bg-blue-900/20',
    reply: 'text-green-500 bg-green-50 dark:bg-green-900/20',
    follow: 'text-purple-500 bg-purple-50 dark:bg-purple-900/20',
    fork: 'text-orange-500 bg-orange-50 dark:bg-orange-900/20',
    citation: 'text-teal-500 bg-teal-50 dark:bg-teal-900/20',
    like: 'text-pink-500 bg-pink-50 dark:bg-pink-900/20',
    system: 'text-gray-500 bg-gray-50 dark:bg-gray-900/20',
    moderation: 'text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20',
}

// Helper to load cleared IDs from localStorage
function loadClearedIds(): Set<string> {
    if (typeof window === 'undefined') return new Set()
    try {
        const stored = localStorage.getItem(CLEARED_NOTIFICATIONS_KEY)
        if (stored) {
            return new Set(JSON.parse(stored))
        }
    } catch (e) {
        console.error('Failed to load cleared notifications:', e)
    }
    return new Set()
}

// Helper to save cleared IDs to localStorage
function saveClearedIds(ids: Set<string>) {
    if (typeof window === 'undefined') return
    try {
        localStorage.setItem(CLEARED_NOTIFICATIONS_KEY, JSON.stringify([...ids]))
    } catch (e) {
        console.error('Failed to save cleared notifications:', e)
    }
}

export function NotificationCenter({ userId }: { userId: string }) {
    const [isOpen, setIsOpen] = useState(false)
    const { notifications, unreadCount, markAsRead, markAllAsRead, deleteNotification } = useNotifications()
    const [filter, setFilter] = useState<NotificationFilter>('all')
    const [markingAll, setMarkingAll] = useState(false)
    const [clearedIds, setClearedIds] = useState<Set<string>>(() => {
        // Initialize from localStorage (only runs on client)
        if (typeof window !== 'undefined') {
            return loadClearedIds()
        }
        return new Set()
    })

    const handleMarkAllAsRead = async () => {
        setMarkingAll(true)
        // Mark as read AND hide from dropdown (persisted to localStorage)
        const allIds = notifications.map(n => n.id)
        const newClearedIds = new Set([...clearedIds, ...allIds])
        setClearedIds(newClearedIds)
        saveClearedIds(newClearedIds)
        await markAllAsRead()
        setMarkingAll(false)
    }

    const filteredNotifications = useMemo(() => {
        // Filter out cleared notifications
        const visibleList = (notifications as any[]).filter(n => !clearedIds.has(n.id))
        
        switch (filter) {
            case 'unread':
                return visibleList.filter(n => !n.is_read)
            case 'mentions':
                return visibleList.filter(n => n.type === 'mention' || n.type === 'reply')
            case 'social':
                return visibleList.filter(n => ['follow', 'like', 'fork', 'citation'].includes(n.type))
            case 'system':
                return visibleList.filter(n => n.type === 'system' || n.type === 'moderation')
            default:
                return visibleList
        }
    }, [notifications, filter, clearedIds])

    return (
        <div className="relative">
            {/* Trigger Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="relative p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-dark-surface transition-colors focus:outline-none focus:ring-2 focus:ring-primary"
                aria-label={`Notifications${unreadCount > 0 ? ` (${unreadCount} unread)` : ''}`}
                aria-expanded={isOpen}
                aria-haspopup="true"
            >
                <Bell className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 w-5 h-5 flex items-center justify-center bg-red-500 text-white text-xs font-bold rounded-full border-2 border-white dark:border-dark-bg transition-all animate-in zoom-in">
                        {unreadCount > 9 ? '9+' : unreadCount}
                    </span>
                )}
            </button>

            {/* Dropdown Panel */}
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsOpen(false)}
                        aria-hidden="true"
                    />

                    {/* Panel */}
                    <div
                        className="absolute right-0 top-full mt-2 w-96 max-h-[70vh] bg-white dark:bg-dark-surface rounded-2xl shadow-xl border border-gray-200 dark:border-dark-border overflow-hidden z-50 flex flex-col"
                        role="dialog"
                        aria-label="Notifications"
                    >
                        {/* Header */}
                        <div className="px-4 py-3 border-b border-gray-100 dark:border-dark-border flex-shrink-0">
                            <div className="flex items-center justify-between mb-3">
                                <h3 className="font-semibold text-text dark:text-dark-text">Notifications</h3>
                                <div className="flex items-center gap-1">
                                    {unreadCount > 0 && (
                                        <Button
                                            size="sm"
                                            variant="ghost"
                                            onClick={handleMarkAllAsRead}
                                            disabled={markingAll}
                                            className="text-xs gap-1"
                                        >
                                            {markingAll ? (
                                                <Loader2 className="w-3.5 h-3.5 animate-spin" />
                                            ) : (
                                                <CheckCheck className="w-3.5 h-3.5" />
                                            )}
                                            Mark all as read
                                        </Button>
                                    )}
                                    <Link href="/settings/notifications">
                                        <Button size="sm" variant="ghost" className="p-1.5">
                                            <Settings className="w-4 h-4" />
                                        </Button>
                                    </Link>
                                </div>
                            </div>

                            {/* Filter Tabs */}
                            <div className="flex gap-1">
                                {(['all', 'unread', 'mentions', 'social', 'system'] as const).map(f => (
                                    <button
                                        key={f}
                                        onClick={() => setFilter(f)}
                                        className={`px-2.5 py-1 text-xs rounded-full capitalize transition-colors ${filter === f
                                            ? 'bg-primary text-white'
                                            : 'bg-gray-100 dark:bg-dark-bg text-text-light dark:text-dark-text-muted hover:bg-gray-200 dark:hover:bg-dark-border'
                                            }`}
                                    >
                                        {f}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Notifications List */}
                        <div className="flex-1 overflow-y-auto">
                            {filteredNotifications.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-12 text-center">
                                    <BellOff className="w-10 h-10 text-text-light dark:text-dark-text-muted opacity-50 mb-3" />
                                    <p className="text-sm text-text-light dark:text-dark-text-muted">
                                        {filter === 'all' ? 'No notifications yet' : `No ${filter} notifications`}
                                    </p>
                                </div>
                            ) : (
                                <div className="divide-y divide-gray-100 dark:divide-dark-border">
                                    {filteredNotifications.map(notification => (
                                        <NotificationItem
                                            key={notification.id}
                                            notification={notification}
                                            onRead={markAsRead}
                                            onDelete={deleteNotification}
                                            onClose={() => setIsOpen(false)}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Footer */}
                        {notifications.length > 0 && (
                            <div className="px-4 py-2 border-t border-gray-100 dark:border-dark-border flex-shrink-0">
                                <Link
                                    href="/notifications"
                                    onClick={() => setIsOpen(false)}
                                    className="text-xs text-primary hover:underline"
                                >
                                    View all notifications ΓåÆ
                                </Link>
                            </div>
                        )}
                    </div>
                </>
            )}
        </div>
    )
}

interface NotificationItemProps {
    notification: any
    onRead: (id: string) => void
    onDelete: (id: string) => void
    onClose: () => void
}

function NotificationItem({ notification, onRead, onDelete, onClose }: NotificationItemProps) {
    const Icon = notificationIcons[notification.type] || Bell
    const colorClass = notificationColors[notification.type] || 'text-gray-500 bg-gray-50 dark:bg-gray-900/20'

    const handleClick = () => {
        if (!notification.is_read) {
            onRead(notification.id)
        }
        if (notification.url || notification.link) {
            onClose()
        }
    }

    const content = (
        <div
            className={`px-4 py-3 hover:bg-gray-50 dark:hover:bg-dark-bg transition-colors ${!notification.is_read ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''
                }`}
        >
            <div className="flex gap-3">
                {/* Icon */}
                <div className={`w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 ${colorClass}`}>
                    <Icon className="w-4 h-4" />
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                    <p className={`text-sm ${!notification.is_read ? 'font-medium' : ''} text-text dark:text-dark-text line-clamp-2`}>
                        {notification.title || notification.content}
                    </p>
                    {notification.message && (
                        <p className="text-xs text-text-light dark:text-dark-text-muted mt-0.5 line-clamp-2">
                            {notification.message}
                        </p>
                    )}
                    <span className="text-xs text-text-light dark:text-dark-text-muted mt-1 block">
                        {formatDistanceToNow(new Date(notification.created_at), { addSuffix: true })}
                    </span>
                </div>

                {/* Actions */}
                <div className="flex items-start gap-1 flex-shrink-0">
                    {!notification.is_read && (
                        <button
                            onClick={(e) => {
                                e.preventDefault()
                                e.stopPropagation()
                                onRead(notification.id)
                            }}
                            className="p-1 rounded hover:bg-gray-200 dark:hover:bg-dark-surface transition-colors"
                            title="Mark as read"
                        >
                            <Check className="w-3.5 h-3.5 text-text-light" />
                        </button>
                    )}
                    <button
                        onClick={(e) => {
                            e.preventDefault()
                            e.stopPropagation()
                            onDelete(notification.id)
                        }}
                        className="p-1 rounded hover:bg-gray-200 dark:hover:bg-dark-surface transition-colors"
                        title="Delete"
                    >
                        <X className="w-3.5 h-3.5 text-text-light" />
                    </button>
                </div>
            </div>
        </div>
    )

    const url = notification.url || notification.link

    if (url) {
        return (
            <Link href={url} onClick={handleClick}>
                {content}
            </Link>
        )
    }

    return <div onClick={handleClick}>{content}</div>
}

export function NotificationBell({ userId }: { userId: string }) {
    return <NotificationCenter userId={userId} />
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Bell, Check, MessageSquare, Award, CheckCircle } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'
import { cn } from '@/lib/utils'
import { NotificationSkeleton } from '@/components/ui/skeleton'
import { NoNotificationsIllustration } from '@/components/ui/EmptyState'
import { useTranslations } from 'next-intl'
import { useNotifications } from '@/components/NotificationsProvider'

interface NotificationListProps {
    onClose?: () => void
}

export function NotificationList({ onClose }: NotificationListProps) {
    const { notifications, markAsRead, markAllAsRead } = useNotifications()
    const [hoveredId, setHoveredId] = useState<string | null>(null)
    const [loading] = useState(false) // loading is handled in provider or initial fetch
    const router = useRouter()
    const t = useTranslations('Notifications')

    const handleNotificationClick = async (notification: any) => {
        if (!notification.is_read) {
            await markAsRead(notification.id)
        }
        if (onClose) onClose()
        if (notification.url) {
            router.push(notification.url)
        }
    }

    const getIcon = (type: string) => {
        switch (type) {
            case 'badge': return <Award className="w-5 h-5 text-yellow-500" />
            case 'solution': return <CheckCircle className="w-5 h-5 text-green-500" />
            case 'reply': return <MessageSquare className="w-5 h-5 text-blue-500" />
            default: return <Bell className="w-5 h-5 text-gray-500 dark:text-gray-400" />
        }
    }

    // Empty state with illustration
    if (notifications.length === 0) {
        return (
            <div className="w-full max-w-sm bg-white dark:bg-dark-surface rounded-xl shadow-xl border border-gray-200 dark:border-dark-border overflow-hidden animate-fade-in-up">
                <div className="p-4 border-b border-gray-200 dark:border-dark-border bg-gray-50/50 dark:bg-dark-bg/50">
                    <h3 className="font-semibold text-sm text-text dark:text-dark-text">{t('title')}</h3>
                </div>
                <div className="py-8 px-4 text-center">
                    <NoNotificationsIllustration className="w-32 h-32 mx-auto mb-4 opacity-80" />
                    <p className="text-sm font-medium text-text dark:text-dark-text mb-1">{t('allCaughtUp')}</p>
                    <p className="text-xs text-text-light dark:text-dark-text-muted">
                        {t('noNotificationsYet')}
                    </p>
                </div>
            </div>
        )
    }

    return (
        <div className="w-full max-w-sm bg-white dark:bg-dark-surface rounded-xl shadow-xl border border-gray-200 dark:border-dark-border overflow-hidden animate-fade-in-up">
            <div className="p-4 border-b border-gray-200 dark:border-dark-border flex justify-between items-center bg-gray-50/50 dark:bg-dark-bg/50">
                <h3 className="font-semibold text-sm text-text dark:text-dark-text">{t('title')}</h3>
                <button
                    onClick={() => markAllAsRead()}
                    className="text-xs text-secondary hover:text-secondary-light transition-colors font-medium"
                >
                    {t('markAllAsRead')}
                </button>
            </div>
            <div className="max-h-[400px] overflow-y-auto">
                {notifications.map((notification, index) => (
                    <div
                        key={notification.id}
                        onClick={() => handleNotificationClick(notification)}
                        onMouseEnter={() => setHoveredId(notification.id)}
                        onMouseLeave={() => setHoveredId(null)}
                        className={cn(
                            "p-4 border-b border-gray-100 dark:border-dark-border cursor-pointer",
                            "hover:bg-gray-50 dark:hover:bg-dark-border/50 transition-all duration-200",
                            "flex gap-3 relative group",
                            !notification.is_read ? "bg-primary/5 dark:bg-primary/10" : "opacity-70",
                            "animate-fade-in-up"
                        )}
                        style={{ animationDelay: `${index * 50}ms` }}
                    >
                        {/* Icon with subtle background */}
                        <div className="mt-0.5 flex-shrink-0 w-9 h-9 rounded-full bg-gray-100 dark:bg-dark-border flex items-center justify-center">
                            {getIcon(notification.type)}
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                            <p className={cn(
                                "text-sm text-gray-900 dark:text-gray-100 leading-snug",
                                !notification.is_read && "font-semibold"
                            )}>
                                {notification.id.startsWith('temp-') ? notification.content : notification.title || notification.content}
                            </p>
                            <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-2 mt-0.5">
                                {notification.message}
                            </p>
                            <p className="text-xs text-gray-400 dark:text-gray-500 mt-1.5">
                                {formatDistanceToNow(new Date(notification.created_at), { addSuffix: true })}
                            </p>
                        </div>

                        {/* Unread indicator / Mark as read button */}
                        <div className="flex-shrink-0 flex items-start pt-1">
                            {!notification.is_read && (
                                <>
                                    {/* Blue dot when not hovered */}
                                    <div className={cn(
                                        "w-2.5 h-2.5 rounded-full bg-primary transition-opacity",
                                        "shadow-sm shadow-primary/30",
                                        hoveredId === notification.id && "opacity-0"
                                    )} />
                                    {/* Check button on hover */}
                                    <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            markAsRead(notification.id);
                                        }}
                                        className={cn(
                                            "absolute right-3 top-3 p-1.5 rounded-full",
                                            "bg-primary/10 text-primary hover:bg-primary hover:text-white",
                                            "transition-all duration-200",
                                            hoveredId === notification.id ? "opacity-100 scale-100" : "opacity-0 scale-75"
                                        )}
                                        title="Mark as read"
                                    >
                                        <Check className="w-3.5 h-3.5" />
                                    </button>
                                </>
                            )}
                        </div>
                    </div>
                ))}
            </div>
            <div className="p-3 border-t border-gray-200 dark:border-dark-border bg-gray-50/50 dark:bg-dark-bg/50">
                <Link
                    href="/notifications"
                    onClick={() => onClose?.()}
                    className="block text-center text-sm font-medium text-secondary hover:text-secondary-light transition-colors"
                >
                    {t('viewAllNotifications')}
                </Link>
            </div>
        </div>
    )
}

'use client'

import { useState, useMemo } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import {
    Bell,
    Check,
    CheckCheck,
    MessageSquare,
    AtSign,
    UserPlus,
    Award,
    CheckCircle,
    Trash2,
    Loader2,
    ArrowLeft,
    Reply
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { useToast } from '@/components/ui/toast'
import { NoNotificationsIllustration } from '@/components/ui/EmptyState'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import { useNotifications } from '@/components/NotificationsProvider'

type FilterType = 'all' | 'unread' | 'reply' | 'mention' | 'badge' | 'system'

const filterKeys: { value: FilterType; labelKey: string }[] = [
    { value: 'all', labelKey: 'types.all' },
    { value: 'unread', labelKey: 'types.unread' },
    { value: 'reply', labelKey: 'types.replies' },
    { value: 'mention', labelKey: 'types.mentions' },
    { value: 'badge', labelKey: 'types.badges' },
    { value: 'system', labelKey: 'types.system' },
]

const typeIcons: Record<string, any> = {
    badge: Award,
    solution: CheckCircle,
    reply: MessageSquare,
    mention: AtSign,
    follow: UserPlus,
    system: Bell,
}

const typeColors: Record<string, string> = {
    badge: 'text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20',
    solution: 'text-green-500 bg-green-50 dark:bg-green-900/20',
    reply: 'text-blue-500 bg-blue-50 dark:bg-blue-900/20',
    mention: 'text-purple-500 bg-purple-50 dark:bg-purple-900/20',
    follow: 'text-teal-500 bg-teal-50 dark:bg-teal-900/20',
    system: 'text-gray-500 bg-gray-50 dark:bg-gray-900/20',
}

export function NotificationsPageContent({ userId }: { userId: string }) {
    const t = useTranslations('Notifications')
    const { formatSaved } = useDateFormatter()
    const { notifications, unreadCount, markAsRead, markAllAsRead } = useNotifications()
    const [filter, setFilter] = useState<FilterType>('all')
    const [markingAll, setMarkingAll] = useState(false)
    const [replyingTo, setReplyingTo] = useState<string | null>(null)
    const [replyContent, setReplyContent] = useState('')
    const [submittingReply, setSubmittingReply] = useState(false)

    const router = useRouter()
    const { showToast } = useToast()

    const handleMarkAllAsRead = async () => {
        setMarkingAll(true)
        await markAllAsRead()
        setMarkingAll(false)
        showToast('All notifications marked as read.', 'success')
    }

    const filteredNotifications = useMemo(() => {
        const list = notifications as any[]
        if (filter === 'all') return list
        if (filter === 'unread') return list.filter(n => !n.is_read)
        return list.filter(n => n.type === filter)
    }, [notifications, filter])

    const handleNotificationClick = (notification: any) => {
        if (!notification.is_read) {
            markAsRead(notification.id)
        }
        const url = notification.url || notification.link
        if (url) {
            router.push(url)
        }
    }

    const handleReply = async (notification: any) => {
        if (!replyContent.trim() || !notification.post_id) return

        setSubmittingReply(true)
        try {
            const response = await fetch('/api/comments', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    content: replyContent.trim(),
                    post_id: notification.post_id,
                    parent_id: notification.comment_id || null,
                }),
            })

            if (!response.ok) {
                throw new Error('Failed to post reply')
            }

            showToast('Reply posted successfully!', 'success')
            setReplyContent('')
            setReplyingTo(null)
            // Mark as read after replying
            if (!notification.is_read) {
                markAsRead(notification.id)
            }
        } catch (error) {
            console.error('Error posting reply:', error)
            showToast('Failed to post reply.', 'error')
        } finally {
            setSubmittingReply(false)
        }
    }

    const getIcon = (type: string) => {
        const Icon = typeIcons[type] || Bell
        return <Icon className="w-5 h-5" />
    }

    return (
        <div className="w-full max-w-3xl mx-auto">
            <div className="mb-8">
                <div className="flex items-center gap-2 mb-2">
                    <Link
                        href="/feed"
                        className="p-1 -ml-1 rounded-md hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                    >
                        <ArrowLeft className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
                    </Link>
                    <h1 className="text-2xl font-display font-bold text-text dark:text-dark-text">
                        {t('title')}
                    </h1>
                    {unreadCount > 0 && (
                        <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-primary text-white">
                            {t('unreadCount', { count: unreadCount })}
                        </span>
                    )}
                </div>
                <p className="text-sm text-text-light dark:text-dark-text-muted">
                    {t('subtitle')}
                </p>
            </div>

            <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <div className="flex flex-wrap items-center gap-2">
                    {filterKeys.map(option => (
                        <button
                            key={option.value}
                            onClick={() => setFilter(option.value)}
                            className={cn(
                                'px-3 py-1.5 text-sm font-medium rounded-full transition-colors',
                                filter === option.value
                                    ? 'bg-primary text-white'
                                    : 'bg-gray-100 dark:bg-dark-surface text-text-light dark:text-dark-text-muted hover:bg-gray-200 dark:hover:bg-dark-border'
                            )}
                        >
                            {t(option.labelKey)}
                        </button>
                    ))}
                </div>

                {unreadCount > 0 && (
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleMarkAllAsRead}
                        disabled={markingAll}
                    >
                        {markingAll ? (
                            <Loader2 className="w-4 h-4 animate-spin mr-2" />
                        ) : (
                            <CheckCheck className="w-4 h-4 mr-2" />
                        )}
                        {t('markAllAsRead')}
                    </Button>
                )}
            </div>

            <div className="w-full">
                {filteredNotifications.length === 0 ? (
                    <div className="card p-8 text-center">
                        <NoNotificationsIllustration className="w-32 h-32 mx-auto mb-4 opacity-80" />
                        <p className="text-sm font-medium text-text dark:text-dark-text mb-1">
                            {filter === 'all' ? t('allCaughtUp') : t('noFilteredNotifications', { filter: t(filterKeys.find(f => f.value === filter)?.labelKey ?? 'types.all') })}
                        </p>
                        <p className="text-xs text-text-light dark:text-dark-text-muted">
                            {filter === 'all'
                                ? t('noNotificationsYet').split('.')[1]?.trim() || t('noNotificationsYet')
                                : t('tryChangingFilter')}
                        </p>
                    </div>
                ) : (
                    <div className="card overflow-hidden divide-y divide-gray-100 dark:divide-dark-border">
                        {filteredNotifications.map(notification => (
                            <div
                                key={notification.id}
                                className={cn(
                                    'p-4 transition-colors',
                                    !notification.is_read && 'bg-primary/5 dark:bg-primary/10'
                                )}
                            >
                                <div className="flex gap-3">
                                    {/* Icon */}
                                    <div className={cn(
                                        'flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center',
                                        typeColors[notification.type] || typeColors.system
                                    )}>
                                        {getIcon(notification.type)}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0">
                                        <div
                                            onClick={() => handleNotificationClick(notification)}
                                            className="cursor-pointer"
                                        >
                                            <p className={cn(
                                                'text-sm text-text dark:text-dark-text',
                                                !notification.is_read && 'font-semibold'
                                            )}>
                                                {notification.title || notification.content}
                                            </p>
                                            {notification.message && (
                                                <p className="text-sm text-text-light dark:text-dark-text-muted line-clamp-2 mt-0.5">
                                                    {notification.message}
                                                </p>
                                            )}
                                            <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">
                                                {formatSaved(new Date(notification.created_at))}
                                            </p>
                                        </div>

                                        {/* Inline Reply */}
                                        {notification.type === 'reply' && notification.post_id && (
                                            <div className="mt-2">
                                                {replyingTo === notification.id ? (
                                                    <div className="space-y-2">
                                                        <textarea
                                                            value={replyContent}
                                                            onChange={(e) => setReplyContent(e.target.value)}
                                                            placeholder={t('replyPlaceholder')}
                                                            rows={2}
                                                            className="w-full px-3 py-2 text-sm rounded-md border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text resize-none focus:outline-none focus:ring-1 focus:ring-primary"
                                                        />
                                                        <div className="flex items-center gap-2">
                                                            <Button
                                                                size="sm"
                                                                onClick={() => handleReply(notification)}
                                                                disabled={submittingReply || !replyContent.trim()}
                                                            >
                                                                {submittingReply ? (
                                                                    <Loader2 className="w-3 h-3 animate-spin mr-1" />
                                                                ) : (
                                                                    <Reply className="w-3 h-3 mr-1" />
                                                                )}
                                                                {t('reply')}
                                                            </Button>
                                                            <Button
                                                                variant="ghost"
                                                                size="sm"
                                                                onClick={() => {
                                                                    setReplyingTo(null)
                                                                    setReplyContent('')
                                                                }}
                                                            >
                                                                {t('cancel')}
                                                            </Button>
                                                        </div>
                                                    </div>
                                                ) : (
                                                    <button
                                                        onClick={() => setReplyingTo(notification.id)}
                                                        className="text-xs text-primary dark:text-primary-light hover:text-primary-dark dark:hover:text-white flex items-center gap-1"
                                                    >
                                                        <Reply className="w-3 h-3" />
                                                        {t('quickReply')}
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>

                                    {/* Actions */}
                                    <div className="flex-shrink-0 flex items-start gap-1">
                                        {!notification.is_read && (
                                            <button
                                                onClick={() => markAsRead(notification.id)}
                                                className="p-1.5 rounded-full text-text-light dark:text-dark-text-muted hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                                                title={t('markAsRead')}
                                            >
                                                <Check className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    )
}

'use client'

import { createContext, useContext, useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { useRouter } from 'next/navigation'

type Notification = {
    id: string
    type: string
    title?: string
    message?: string
    content: string
    url?: string
    link?: string
    resource_id?: string
    resource_type?: string
    is_read: boolean
    created_at: string
    metadata?: any
}

type NotificationsContextType = {
    notifications: Notification[]
    unreadCount: number
    markAsRead: (id: string) => Promise<void>
    markAllAsRead: () => Promise<void>
    deleteNotification: (id: string) => Promise<void>
}

const NotificationsContext = createContext<NotificationsContextType | undefined>(undefined)

export function NotificationsProvider({ children }: { children: React.ReactNode }) {
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [userId, setUserId] = useState<string | null>(null)
    const supabase = createClient()
    const { showToast } = useToast()
    const router = useRouter()

    // Fetch initial user
    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            setUserId(data.user?.id || null)
        })
    }, [supabase])

    // Fetch notifications and subscribe to realtime
    useEffect(() => {
        if (!userId) return

        // Initial fetch
        const fetchNotifications = async () => {
            const { data } = await supabase
                .from('notifications')
                .select('*')
                .eq('user_id', userId)
                .order('created_at', { ascending: false })
                .limit(20)

            if (data) setNotifications(data)
        }

        fetchNotifications()

        // Realtime subscription
        const channel = supabase
            .channel('notifications')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'notifications',
                    filter: `user_id=eq.${userId}`
                },
                (payload) => {
                    const newNotification = payload.new as Notification
                    setNotifications(prev => [newNotification, ...prev])
                    showToast(newNotification.title || newNotification.content, 'info')
                }
            )
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'notifications',
                    filter: `user_id=eq.${userId}`
                },
                (payload) => {
                    const updated = payload.new as Notification
                    setNotifications(prev => prev.map(n => n.id === updated.id ? updated : n))
                }
            )
            .on(
                'postgres_changes',
                {
                    event: 'DELETE',
                    schema: 'public',
                    table: 'notifications'
                },
                (payload) => {
                    const deletedId = payload.old.id
                    setNotifications(prev => prev.filter(n => n.id !== deletedId))
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [userId, supabase, showToast])

    const markAsRead = async (id: string) => {
        // Optimistic update
        setNotifications(prev =>
            prev.map(n => n.id === id ? { ...n, is_read: true } : n)
        )

        await supabase
            .from('notifications')
            .update({ is_read: true })
            .eq('id', id)
    }

    const markAllAsRead = async () => {
        // Optimistic update
        setNotifications(prev => prev.map(n => ({ ...n, is_read: true })))

        await supabase
            .from('notifications')
            .update({ is_read: true })
            .eq('user_id', userId)
            .eq('is_read', false)
    }

    const deleteNotification = async (id: string) => {
        // Optimistic update
        setNotifications(prev => prev.filter(n => n.id !== id))

        await supabase
            .from('notifications')
            .delete()
            .eq('id', id)
    }

    const unreadCount = notifications.filter(n => !n.is_read).length

    return (
        <NotificationsContext.Provider value={{ notifications, unreadCount, markAsRead, markAllAsRead, deleteNotification }}>
            {children}
        </NotificationsContext.Provider>
    )
}

export const useNotifications = () => {
    const context = useContext(NotificationsContext)
    if (context === undefined) {
        throw new Error('useNotifications must be used within a NotificationsProvider')
    }
    return context
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogFooter,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { UserAvatar } from '@/components/ui/UserAvatar'
import {
    Sparkles,
    User,
    BookOpen,
    ArrowRight,
    Upload,
    Check
} from 'lucide-react'
import { useTranslations } from 'next-intl'

interface OnboardingModalProps {
    userId: string
    userEmail: string
    userName?: string
}

const ONBOARDING_STEPS = [
    {
        id: 'welcome',
        title: 'Welcome to SyriaHub',
        description: 'Your journey into collaborative research begins here.',
        icon: Sparkles,
    },
    {
        id: 'profile',
        title: 'Complete Your Profile',
        description: 'Tell the community about yourself and your research interests.',
        icon: User,
    },
    {
        id: 'explore',
        title: 'Start Exploring',
        description: 'Browse topics, follow researchers, and engage with the community.',
        icon: BookOpen,
    },
]

export function OnboardingModal({ userId, userEmail, userName }: OnboardingModalProps) {
    const t = useTranslations('Onboarding')
    const tProfile = useTranslations('Profile')
    const tCommon = useTranslations('Common')
    const [isOpen, setIsOpen] = useState(false)
    const [currentStep, setCurrentStep] = useState(0)
    const [name, setName] = useState(userName || '')
    const [bio, setBio] = useState('')
    const [affiliation, setAffiliation] = useState('')
    const [saving, setSaving] = useState(false)
    const router = useRouter()
    const supabase = createClient()

    // Check if user needs onboarding
    useEffect(() => {
        const checkOnboarding = async () => {
            const onboardingComplete = localStorage.getItem(`onboarding_complete_${userId}`)
            if (onboardingComplete) return

            // Check if user has completed profile
            const { data: profile } = await supabase
                .from('users')
                .select('bio, affiliation')
                .eq('id', userId)
                .single()

            // Show onboarding if bio and affiliation are empty
            if (!profile?.bio && !profile?.affiliation) {
                setIsOpen(true)
            }
        }

        checkOnboarding()
    }, [userId, supabase])

    const handleNext = () => {
        if (currentStep < ONBOARDING_STEPS.length - 1) {
            setCurrentStep(currentStep + 1)
        }
    }

    const handlePrevious = () => {
        if (currentStep > 0) {
            setCurrentStep(currentStep - 1)
        }
    }

    const handleSaveProfile = async () => {
        setSaving(true)
        try {
            await supabase
                .from('users')
                .update({
                    name: name || userName,
                    bio,
                    affiliation,
                })
                .eq('id', userId)

            localStorage.setItem(`onboarding_complete_${userId}`, 'true')
            setIsOpen(false)
            router.refresh()
        } catch (error) {
            console.error('Failed to save profile:', error)
        } finally {
            setSaving(false)
        }
    }

    const handleSkip = () => {
        localStorage.setItem(`onboarding_complete_${userId}`, 'true')
        setIsOpen(false)
    }

    const currentStepData = ONBOARDING_STEPS[currentStep]
    const StepIcon = currentStepData.icon

    return (
        <Dialog open={isOpen} onOpenChange={setIsOpen}>
            <DialogContent className="sm:max-w-md bg-white dark:bg-dark-surface max-h-[90vh] overflow-y-auto">
                <DialogHeader className="pt-2 sm:pt-0">
                    <div className="flex items-center justify-center mb-3 sm:mb-4">
                        <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-lg bg-gray-100 dark:bg-dark-bg flex items-center justify-center">
                            <StepIcon className="w-5 h-5 sm:w-6 sm:h-6 text-text dark:text-dark-text" />
                        </div>
                    </div>
                    <DialogTitle className="text-center text-lg sm:text-xl">
                        {currentStepData.title}
                    </DialogTitle>
                    <DialogDescription className="text-center text-sm sm:text-base">
                        {currentStepData.description}
                    </DialogDescription>
                </DialogHeader>

                {/* Step content */}
                <div className="py-3 sm:py-4">
                    {currentStep === 0 && (
                        <div className="text-center space-y-3 sm:space-y-4">
                            <div className="flex justify-center">
                                <UserAvatar name={userName} email={userEmail} size="xl" />
                            </div>
                            <p className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">
                                {userName ? `Welcome, ${userName}.` : 'Welcome.'} Ready to contribute?
                            </p>
                            <div className="grid grid-cols-3 gap-2 sm:gap-3 pt-3 sm:pt-4">
                                <div className="text-center p-2 sm:p-3 rounded-lg border border-gray-200 dark:border-dark-border">
                                    <div className="text-xs sm:text-sm font-medium text-text dark:text-dark-text">Publish</div>
                                    <div className="text-[10px] sm:text-xs text-text-light dark:text-dark-text-muted mt-0.5">Share research</div>
                                </div>
                                <div className="text-center p-2 sm:p-3 rounded-lg border border-gray-200 dark:border-dark-border">
                                    <div className="text-xs sm:text-sm font-medium text-text dark:text-dark-text">Deliberate</div>
                                    <div className="text-[10px] sm:text-xs text-text-light dark:text-dark-text-muted mt-0.5">Collaborate</div>
                                </div>
                                <div className="text-center p-2 sm:p-3 rounded-lg border border-gray-200 dark:border-dark-border">
                                    <div className="text-xs sm:text-sm font-medium text-text dark:text-dark-text">Grow</div>
                                    <div className="text-[10px] sm:text-xs text-text-light dark:text-dark-text-muted mt-0.5">Establish credibility</div>
                                </div>
                            </div>
                        </div>
                    )}

                    {currentStep === 1 && (
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                                    {tProfile('displayName')}
                                </label>
                                <input
                                    type="text"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    placeholder="Your name"
                                    className="input dark:bg-dark-bg dark:text-dark-text dark:border-dark-border"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                                    {tProfile('bio')}
                                </label>
                                <textarea
                                    value={bio}
                                    onChange={(e) => setBio(e.target.value)}
                                    placeholder="Tell us about yourself and your research interests..."
                                    rows={3}
                                    className="input resize-none dark:bg-dark-bg dark:text-dark-text dark:border-dark-border"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                                    {tProfile('affiliation')}
                                </label>
                                <input
                                    type="text"
                                    value={affiliation}
                                    onChange={(e) => setAffiliation(e.target.value)}
                                    placeholder="University, Organization, or Independent"
                                    className="input dark:bg-dark-bg dark:text-dark-text dark:border-dark-border"
                                />
                            </div>
                        </div>
                    )}

                    {currentStep === 2 && (
                        <div className="space-y-3 sm:space-y-4 text-center">
                            <div className="space-y-2 sm:space-y-3">
                                <div className="flex items-center gap-2 sm:gap-3 p-2 sm:p-3 rounded-lg bg-gray-50 dark:bg-dark-bg text-left">
                                    <Check className="w-4 h-4 sm:w-5 sm:h-5 text-green-500 flex-shrink-0" />
                                    <span className="text-xs sm:text-sm text-text dark:text-dark-text">
                                        Browse the <strong>Research Stream</strong> for latest work
                                    </span>
                                </div>
                                <div className="flex items-center gap-2 sm:gap-3 p-2 sm:p-3 rounded-lg bg-gray-50 dark:bg-dark-bg text-left">
                                    <Check className="w-4 h-4 sm:w-5 sm:h-5 text-green-500 flex-shrink-0" />
                                    <span className="text-xs sm:text-sm text-text dark:text-dark-text">
                                        <strong>Explore</strong> topics and trending tags
                                    </span>
                                </div>
                                <div className="flex items-center gap-2 sm:gap-3 p-2 sm:p-3 rounded-lg bg-gray-50 dark:bg-dark-bg text-left">
                                    <Check className="w-4 h-4 sm:w-5 sm:h-5 text-green-500 flex-shrink-0" />
                                    <span className="text-xs sm:text-sm text-text dark:text-dark-text">
                                        Join <strong>Groups</strong> to collaborate
                                    </span>
                                </div>
                                <div className="flex items-center gap-2 sm:gap-3 p-2 sm:p-3 rounded-lg bg-gray-50 dark:bg-dark-bg text-left">
                                    <Check className="w-4 h-4 sm:w-5 sm:h-5 text-green-500 flex-shrink-0" />
                                    <span className="text-xs sm:text-sm text-text dark:text-dark-text">
                                        Ask <strong>Questions</strong> to solve problems
                                    </span>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Step indicators */}
                <div className="flex justify-center gap-1.5 sm:gap-2 mb-3 sm:mb-4">
                    {ONBOARDING_STEPS.map((_, index) => (
                        <div
                            key={index}
                            className={`w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full transition-all ${index === currentStep
                                ? 'w-5 sm:w-6 bg-primary dark:bg-accent-light'
                                : index < currentStep
                                    ? 'bg-primary/50 dark:bg-accent-light/50'
                                    : 'bg-gray-200 dark:bg-dark-border'
                                }`}
                        />
                    ))}
                </div>

                <DialogFooter className="gap-2 flex-col-reverse sm:flex-row">
                    {currentStep > 0 && (
                        <Button
                            variant="outline"
                            onClick={handlePrevious}
                            className="w-full sm:w-auto sm:flex-none"
                        >
                            {tCommon('back')}
                        </Button>
                    )}

                    {currentStep === 0 && (
                        <button
                            onClick={handleSkip}
                            className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted hover:underline py-2 sm:py-0"
                        >
                            {t('skipForNow')}
                        </button>
                    )}

                    {currentStep < ONBOARDING_STEPS.length - 1 ? (
                        <Button onClick={handleNext} className="w-full sm:w-auto sm:flex-none btn-press">
                            {tCommon('next')}
                            <ArrowRight className="w-4 h-4 ml-2" />
                        </Button>
                    ) : (
                        <Button
                            onClick={handleSaveProfile}
                            disabled={saving}
                            className="w-full sm:w-auto sm:flex-none btn-press"
                        >
                            {saving ? t('saving') : t('getStarted')}
                            <Sparkles className="w-4 h-4 ml-2" />
                        </Button>
                    )}
                </DialogFooter>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { ShieldAlert, ShieldCheck, Loader2, Info } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { InfoHint } from '@/components/ui/InfoHint'

interface PlagiarismCheckButtonProps {
    postVersionId: string
}

export function PlagiarismCheckButton({ postVersionId }: PlagiarismCheckButtonProps) {
    const [loading, setLoading] = useState(false)
    const [result, setResult] = useState<any>(null)
    const { showToast } = useToast()
    const supabase = createClient()

    // Load existing result on mount
    useEffect(() => {
        async function loadResult() {
            const { data } = await supabase
                .from('plagiarism_checks')
                .select('*')
                .eq('post_version_id', postVersionId)
                .single()

            if (data) setResult(data)
        }
        loadResult()
    }, [postVersionId, supabase])

    const handleCheck = async () => {
        setLoading(true)
        try {
            const response = await fetch('/api/plagiarism/check', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ postVersionId }),
            })

            const data = await response.json()

            if (!response.ok) throw new Error(data.error || 'Check failed')

            setResult(data)
            showToast('Plagiarism check completed', 'success')
        } catch (error: any) {
            console.error('Plagiarism check error:', error)
            showToast(error.message, 'error')
        } finally {
            setLoading(false)
        }
    }

    if (result) {
        const isClean = !result.flagged
        const score = result.score || 0

        return (
            <div className={`p-4 rounded-lg border ${isClean
                ? 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-900'
                : 'bg-amber-50 border-amber-200 dark:bg-amber-900/20 dark:border-amber-900'}`}
            >
                <div className="flex items-start gap-3">
                    {isClean ? (
                        <ShieldCheck className="w-5 h-5 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
                    ) : (
                        <ShieldAlert className="w-5 h-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
                    )}
                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                            <p className={`text-sm font-semibold ${isClean
                                ? 'text-green-800 dark:text-green-300'
                                : 'text-amber-800 dark:text-amber-300'}`}
                            >
                                {isClean ? 'Original Content' : 'Review Recommended'}
                            </p>
                            <InfoHint
                                content="Plagiarism check compares your content against a database of sources to detect potential duplication. Lower scores indicate more original content."
                            />
                        </div>

                        <p className="text-xs text-text-light dark:text-dark-text-muted mt-1">
                            <strong>{score}% similarity</strong> ΓÇö {isClean
                                ? 'Content appears to be original'
                                : 'Some sections may need citation or rewording'}
                        </p>


                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="flex items-center gap-2">
            <Button
                variant="outline"
                size="sm"
                onClick={handleCheck}
                disabled={loading}
                className="gap-2"
            >
                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <ShieldAlert className="w-4 h-4" />}
                Check Originality
            </Button>
            <InfoHint
                content="Run a plagiarism check to compare this content against existing research using semantic similarity."
            />
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { AlertTriangle, CheckCircle, ExternalLink, FileSearch, X, Eye } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'

interface PlagiarismMatch {
    source_url?: string
    source_title?: string
    matched_text?: string
    similarity?: number
}

interface PlagiarismDetailsProps {
    postId?: string
    postVersionId?: string
    score?: number
    matches?: PlagiarismMatch[]
    variant?: 'badge' | 'inline' | 'full'
}

/**
 * Displays plagiarism check results with:
 * - Visual similarity percentage
 * - Matched source links
 * - Highlighted matched text (in modal)
 */
export function PlagiarismDetails({
    postId,
    postVersionId,
    score: initialScore,
    matches: initialMatches,
    variant = 'badge'
}: PlagiarismDetailsProps) {
    const [score, setScore] = useState<number | null>(initialScore ?? null)
    const [matches, setMatches] = useState<PlagiarismMatch[]>(initialMatches || [])
    const [loading, setLoading] = useState(!initialScore && !initialMatches)
    const [showModal, setShowModal] = useState(false)
    const supabase = useMemo(() => createClient(), [])

    useEffect(() => {
        if (initialScore !== undefined || initialMatches) {
            setLoading(false)
            return
        }

        async function fetchPlagiarismData() {
            try {
                const { data, error } = await supabase
                    .from('plagiarism_checks')
                    .select('score, sources, status, flagged')
                    .eq(postVersionId ? 'post_version_id' : 'post_id', postVersionId || postId)
                    .order('created_at', { ascending: false })
                    .limit(1)
                    .single()

                if (error) {
                    // No plagiarism check exists yet
                    setScore(null)
                    return
                }

                setScore(data.score / 100) // Normalize to 0-1

                // Parse sources if available
                if (data.sources) {
                    try {
                        const parsedSources = typeof data.sources === 'string'
                            ? JSON.parse(data.sources)
                            : data.sources
                        setMatches(parsedSources)
                    } catch {
                        setMatches([])
                    }
                }
            } catch (error) {
                console.error('Error fetching plagiarism data:', error)
            } finally {
                setLoading(false)
            }
        }

        if (postId || postVersionId) {
            fetchPlagiarismData()
        }
    }, [postId, postVersionId, initialScore, initialMatches, supabase])

    if (loading) {
        return variant === 'badge' ? null : (
            <div className="animate-pulse h-4 w-20 bg-gray-200 dark:bg-dark-surface rounded" />
        )
    }

    // No plagiarism data or score is below threshold
    if (score === null || score < 0.3) {
        return null
    }

    const isHighRisk = score >= 0.7
    const isMediumRisk = score >= 0.5

    const getColorClasses = () => {
        if (isHighRisk) return 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 border-red-200 dark:border-red-800'
        if (isMediumRisk) return 'bg-orange-100 dark:bg-orange-900/30 text-orange-700 dark:text-orange-400 border-orange-200 dark:border-orange-800'
        return 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 border-yellow-200 dark:border-yellow-800'
    }

    const percentScore = Math.round(score * 100)

    // Badge variant - compact inline display
    if (variant === 'badge') {
        return (
            <>
                <button
                    onClick={() => setShowModal(true)}
                    className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full text-xs font-medium border ${getColorClasses()} hover:opacity-80 transition-opacity`}
                >
                    <AlertTriangle className="w-3 h-3" />
                    <span>{percentScore}% match</span>
                </button>

                <PlagiarismModal
                    isOpen={showModal}
                    onClose={() => setShowModal(false)}
                    score={score}
                    matches={matches}
                />
            </>
        )
    }

    // Inline variant - for cards/lists
    if (variant === 'inline') {
        return (
            <>
                <div className={`flex items-center gap-2 p-3 rounded-lg border ${getColorClasses()}`}>
                    <AlertTriangle className="w-4 h-4 flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                        <span className="text-sm font-medium">
                            {isHighRisk ? 'High similarity detected' : 'Potential similarity detected'}
                        </span>
                        <span className="text-sm opacity-75 ml-1">({percentScore}% match)</span>
                    </div>
                    <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => setShowModal(true)}
                        className="gap-1 text-xs"
                    >
                        <Eye className="w-3.5 h-3.5" />
                        Details
                    </Button>
                </div>

                <PlagiarismModal
                    isOpen={showModal}
                    onClose={() => setShowModal(false)}
                    score={score}
                    matches={matches}
                />
            </>
        )
    }

    // Full variant - expanded view
    return (
        <>
            <div className={`p-4 rounded-xl border ${getColorClasses()}`}>
                <div className="flex items-start gap-3">
                    <div className="p-2 rounded-lg bg-white/50 dark:bg-black/20">
                        <FileSearch className="w-5 h-5" />
                    </div>
                    <div className="flex-1">
                        <h4 className="font-semibold text-sm">
                            {isHighRisk ? 'ΓÜá∩╕Å High Similarity Alert' : 'Similarity Notice'}
                        </h4>
                        <p className="text-sm mt-1 opacity-80">
                            This content shows {percentScore}% similarity with existing sources.
                        </p>

                        {/* Similarity Bar */}
                        <div className="mt-3">
                            <div className="flex items-center justify-between text-xs mb-1">
                                <span>Similarity Score</span>
                                <span className="font-medium">{percentScore}%</span>
                            </div>
                            <div className="h-2 rounded-full bg-white/50 dark:bg-black/20 overflow-hidden">
                                <div
                                    className={`h-full rounded-full transition-all ${isHighRisk ? 'bg-red-500' : isMediumRisk ? 'bg-orange-500' : 'bg-yellow-500'
                                        }`}
                                    style={{ width: `${percentScore}%` }}
                                />
                            </div>
                        </div>

                        {/* Sources Preview */}
                        {matches.length > 0 && (
                            <div className="mt-3 space-y-2">
                                <span className="text-xs font-medium">Matched Sources:</span>
                                {matches.slice(0, 2).map((match, idx) => (
                                    <div key={idx} className="text-xs flex items-center gap-2">
                                        <ExternalLink className="w-3 h-3 flex-shrink-0" />
                                        <span className="truncate">
                                            {match.source_title || match.source_url || `Source ${idx + 1}`}
                                        </span>
                                    </div>
                                ))}
                                {matches.length > 2 && (
                                    <span className="text-xs opacity-75">+{matches.length - 2} more</span>
                                )}
                            </div>
                        )}

                        <Button
                            size="sm"
                            variant="outline"
                            onClick={() => setShowModal(true)}
                            className="mt-4 gap-1"
                        >
                            <Eye className="w-3.5 h-3.5" />
                            View Matched Text
                        </Button>
                    </div>
                </div>
            </div>

            <PlagiarismModal
                isOpen={showModal}
                onClose={() => setShowModal(false)}
                score={score}
                matches={matches}
            />
        </>
    )
}

interface PlagiarismModalProps {
    isOpen: boolean
    onClose: () => void
    score: number
    matches: PlagiarismMatch[]
}

function PlagiarismModal({ isOpen, onClose, score, matches }: PlagiarismModalProps) {
    const percentScore = Math.round(score * 100)
    const isHighRisk = score >= 0.7

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl max-h-[80vh] overflow-hidden flex flex-col">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <FileSearch className="w-5 h-5" />
                        Plagiarism Check Results
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-6 overflow-y-auto flex-1 pr-2">
                    {/* Score Summary */}
                    <div className={`p-4 rounded-xl ${isHighRisk
                        ? 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800'
                        : 'bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800'
                        }`}>
                        <div className="flex items-center justify-between mb-2">
                            <span className="font-medium text-sm">Overall Similarity</span>
                            <span className={`text-2xl font-bold ${isHighRisk ? 'text-red-600 dark:text-red-400' : 'text-yellow-600 dark:text-yellow-400'
                                }`}>
                                {percentScore}%
                            </span>
                        </div>
                        <div className="h-3 rounded-full bg-white/50 dark:bg-black/20 overflow-hidden">
                            <div
                                className={`h-full rounded-full ${isHighRisk ? 'bg-red-500' : 'bg-yellow-500'}`}
                                style={{ width: `${percentScore}%` }}
                            />
                        </div>
                        <p className="text-xs mt-2 opacity-75">
                            {isHighRisk
                                ? 'This content has significant overlap with existing sources. Review recommended.'
                                : 'Some similarity detected. May require attribution or revision.'}
                        </p>
                    </div>

                    {/* Matched Sources */}
                    <div>
                        <h3 className="font-semibold text-sm mb-3">Matched Sources ({matches.length})</h3>
                        {matches.length === 0 ? (
                            <p className="text-sm text-text-light dark:text-dark-text-muted">
                                Detailed source information not available.
                            </p>
                        ) : (
                            <div className="space-y-3">
                                {matches.map((match, idx) => (
                                    <div
                                        key={idx}
                                        className="p-4 rounded-lg border border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-bg"
                                    >
                                        <div className="flex items-start justify-between gap-3 mb-2">
                                            <h4 className="font-medium text-sm">
                                                {match.source_title || `Source ${idx + 1}`}
                                            </h4>
                                            {match.similarity !== undefined && (
                                                <span className="text-xs px-2 py-0.5 rounded-full bg-gray-200 dark:bg-dark-surface">
                                                    {Math.round(match.similarity * 100)}% match
                                                </span>
                                            )}
                                        </div>

                                        {match.source_url && (
                                            <a
                                                href={match.source_url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="text-xs text-primary hover:underline flex items-center gap-1 mb-2"
                                            >
                                                <ExternalLink className="w-3 h-3" />
                                                {match.source_url}
                                            </a>
                                        )}

                                        {match.matched_text && (
                                            <div className="mt-2 p-3 rounded bg-yellow-50 dark:bg-yellow-900/10 border-l-2 border-yellow-400">
                                                <span className="text-xs font-medium text-yellow-700 dark:text-yellow-400 block mb-1">
                                                    Matched Text:
                                                </span>
                                                <p className="text-sm text-text-light dark:text-dark-text-muted italic">
                                                    &quot;{match.matched_text}&quot;
                                                </p>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Help Text */}
                    <div className="p-4 rounded-lg bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
                        <h4 className="font-medium text-sm text-blue-700 dark:text-blue-400 mb-1">
                            What should I do?
                        </h4>
                        <ul className="text-xs text-blue-600 dark:text-blue-300 space-y-1">
                            <li>ΓÇó Review the matched sections and add proper citations if needed</li>
                            <li>ΓÇó Paraphrase or rewrite content that&apos;s too similar to sources</li>
                            <li>ΓÇó If you believe this is a false positive, you can file an appeal</li>
                        </ul>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Eye, Users, Clock, TrendingUp, ArrowUp, ArrowDown, BarChart3, Percent } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'

interface Analytics {
    total_views: number
    unique_viewers: number
    avg_read_time: number
    avg_scroll_depth: number
    views_today: number
    views_this_week: number
    views_this_month: number
    viewsOverTime: { date: string; views: number }[]
}

interface PostAnalyticsDashboardProps {
    postId: string
    postTitle: string
}

export function PostAnalyticsDashboard({ postId, postTitle }: PostAnalyticsDashboardProps) {
    const [analytics, setAnalytics] = useState<Analytics | null>(null)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        async function fetchAnalytics() {
            try {
                const response = await fetch(`/api/analytics?postId=${postId}`)
                if (!response.ok) {
                    throw new Error('Failed to fetch analytics')
                }
                const data = await response.json()
                setAnalytics(data)
            } catch (err) {
                setError('Unable to load analytics')
            } finally {
                setLoading(false)
            }
        }

        fetchAnalytics()
    }, [postId])

    if (loading) {
        return <AnalyticsSkeleton />
    }

    if (error || !analytics) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6 text-center">
                <BarChart3 className="w-8 h-8 text-text-light dark:text-dark-text-muted mx-auto mb-2" />
                <p className="text-text-light dark:text-dark-text-muted">{error || 'No analytics available'}</p>
            </div>
        )
    }

    const formatReadTime = (seconds: number) => {
        if (seconds < 60) return `${Math.round(seconds)}s`
        const minutes = Math.floor(seconds / 60)
        const secs = Math.round(seconds % 60)
        return `${minutes}m ${secs}s`
    }

    const formatScrollDepth = (depth: number) => `${Math.round(depth * 100)}%`

    // Calculate trend (comparing this week to last week estimate)
    const weeklyTrend = analytics.views_this_week > analytics.views_this_month / 4 ? 'up' : 'down'
    const trendPercent = analytics.views_this_month > 0
        ? Math.round(((analytics.views_this_week * 4) / analytics.views_this_month - 1) * 100)
        : 0

    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-dark-border">
                <div className="flex items-center gap-2">
                    <BarChart3 className="w-5 h-5 text-primary" />
                    <h3 className="font-semibold text-text dark:text-dark-text">Analytics</h3>
                </div>
                <p className="text-sm text-text-light dark:text-dark-text-muted mt-1 line-clamp-1">
                    {postTitle}
                </p>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-4 p-4">
                {/* Total Views */}
                <StatCard
                    icon={Eye}
                    label="Total Views"
                    value={analytics.total_views.toLocaleString()}
                    trend={weeklyTrend === 'up' ? `+${trendPercent}%` : undefined}
                    trendUp={weeklyTrend === 'up'}
                />

                {/* Unique Viewers */}
                <StatCard
                    icon={Users}
                    label="Unique Viewers"
                    value={analytics.unique_viewers.toLocaleString()}
                />

                {/* Avg Read Time */}
                <StatCard
                    icon={Clock}
                    label="Avg Read Time"
                    value={formatReadTime(analytics.avg_read_time)}
                />

                {/* Scroll Depth */}
                <StatCard
                    icon={Percent}
                    label="Avg Scroll Depth"
                    value={formatScrollDepth(analytics.avg_scroll_depth)}
                />
            </div>

            {/* Time Period Stats */}
            <div className="px-4 pb-4">
                <div className="bg-gray-50 dark:bg-dark-bg rounded-xl p-4">
                    <h4 className="text-sm font-medium text-text dark:text-dark-text mb-3">Views by Period</h4>
                    <div className="space-y-3">
                        <PeriodRow label="Today" value={analytics.views_today} total={analytics.total_views} />
                        <PeriodRow label="This Week" value={analytics.views_this_week} total={analytics.total_views} />
                        <PeriodRow label="This Month" value={analytics.views_this_month} total={analytics.total_views} />
                    </div>
                </div>
            </div>

            {/* Mini Chart */}
            {analytics.viewsOverTime && analytics.viewsOverTime.length > 0 && (
                <div className="px-4 pb-4">
                    <MiniChart data={analytics.viewsOverTime} />
                </div>
            )}
        </div>
    )
}

// Stat Card Component
interface StatCardProps {
    icon: any
    label: string
    value: string
    trend?: string
    trendUp?: boolean
}

function StatCard({ icon: Icon, label, value, trend, trendUp }: StatCardProps) {
    return (
        <div className="p-3 bg-gray-50 dark:bg-dark-bg rounded-xl">
            <div className="flex items-center gap-2 mb-2">
                <Icon className="w-4 h-4 text-primary" />
                <span className="text-xs text-text-light dark:text-dark-text-muted">{label}</span>
            </div>
            <div className="flex items-end gap-2">
                <span className="text-xl font-bold text-text dark:text-dark-text">{value}</span>
                {trend && (
                    <span className={`flex items-center text-xs font-medium ${trendUp ? 'text-green-500' : 'text-red-500'}`}>
                        {trendUp ? <ArrowUp className="w-3 h-3" /> : <ArrowDown className="w-3 h-3" />}
                        {trend}
                    </span>
                )}
            </div>
        </div>
    )
}

// Period Row Component
interface PeriodRowProps {
    label: string
    value: number
    total: number
}

function PeriodRow({ label, value, total }: PeriodRowProps) {
    const percentage = total > 0 ? (value / total) * 100 : 0

    return (
        <div className="flex items-center gap-3">
            <span className="text-sm text-text-light dark:text-dark-text-muted w-24">{label}</span>
            <div className="flex-1 h-2 bg-gray-200 dark:bg-dark-border rounded-full overflow-hidden">
                <div
                    className="h-full bg-primary rounded-full transition-all duration-500"
                    style={{ width: `${Math.min(percentage, 100)}%` }}
                />
            </div>
            <span className="text-sm font-medium text-text dark:text-dark-text w-12 text-right">
                {value}
            </span>
        </div>
    )
}

// Mini Chart Component
interface MiniChartProps {
    data: { date: string; views: number }[]
}

function MiniChart({ data }: MiniChartProps) {
    const maxViews = Math.max(...data.map(d => d.views), 1)

    return (
        <div className="bg-gray-50 dark:bg-dark-bg rounded-xl p-4">
            <h4 className="text-sm font-medium text-text dark:text-dark-text mb-3">Views (Last 30 Days)</h4>
            <div className="flex items-end gap-1 h-20">
                {data.slice(-30).map((day, i) => (
                    <div
                        key={day.date}
                        className="flex-1 bg-primary/20 hover:bg-primary/40 rounded-t transition-colors cursor-pointer group relative"
                        style={{ height: `${(day.views / maxViews) * 100}%`, minHeight: day.views > 0 ? '4px' : '2px' }}
                    >
                        {/* Tooltip */}
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                            {day.views} views
                            <br />
                            {new Date(day.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    )
}

// Skeleton Loader
function AnalyticsSkeleton() {
    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden animate-pulse">
            <div className="p-4 border-b border-gray-100 dark:border-dark-border">
                <div className="h-5 bg-gray-200 dark:bg-dark-border rounded w-24" />
                <div className="h-4 bg-gray-200 dark:bg-dark-border rounded w-40 mt-2" />
            </div>
            <div className="grid grid-cols-2 gap-4 p-4">
                {[1, 2, 3, 4].map(i => (
                    <div key={i} className="p-3 bg-gray-50 dark:bg-dark-bg rounded-xl">
                        <div className="h-3 bg-gray-200 dark:bg-dark-border rounded w-16 mb-2" />
                        <div className="h-6 bg-gray-200 dark:bg-dark-border rounded w-12" />
                    </div>
                ))}
            </div>
        </div>
    )
}

'use client'

import Link from 'next/link'
import Image from 'next/image'
import { MessageSquare, Quote, Clock, GitFork, GraduationCap } from 'lucide-react'
import { TagChip } from './TagChip'
import { ReportButton } from '@/components/ReportButton'
import { BookmarkButton } from '@/components/BookmarkButton'
import { ReviewBadgeInline } from '@/components/ReviewBadge'
import { PlagiarismDetails } from '@/components/PlagiarismDetails'
import { Post } from '@/types'
import { stripMarkdown, cn, getInitials, getAvatarGradient } from '@/lib/utils'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import { useTranslations } from 'next-intl'

interface PostCardProps {
  post: Post & {
    author?: {
      id?: string
      name?: string
      full_name?: string
      email?: string
      avatar_url?: string
      is_verified_author?: boolean
    } | null
    approval_status?: 'pending' | 'approved' | 'flagged' | 'rejected'
    approved_by_role?: 'moderator' | 'admin' | null
  }
  showAuthor?: boolean
}

export function PostCard({ post, showAuthor = true }: PostCardProps) {
  const { formatDate } = useDateFormatter()
  const getExcerpt = (content: string, maxLength: number = 150) => {
    const plainText = stripMarkdown(content)
    if (plainText.length <= maxLength) return plainText
    return plainText.substring(0, maxLength).trim() + '...'
  }

  const displayAuthor =
    post.author?.name ||
    post.author?.full_name ||
    post.author?.email?.split('@')[0] ||
    'Anonymous'

  // Reading time calculation
  const getReadingTime = (content: string): number => {
    const wordsPerMinute = 200
    const words = content.trim().split(/\s+/).length
    return Math.max(1, Math.ceil(words / wordsPerMinute))
  }
  const readingTime = getReadingTime(post.content)

  // Knowledge impact score display helper
  const impactScore = post.academic_impact_score || 0
  const hasImpact = impactScore > 0

  const tLicenses = useTranslations('Licenses')

  return (
    <article className="card card-premium card-glow card-hover p-6 group">
      <Link
        href={`/post/${post.id}`}
        className="focus-ring rounded-lg block"
      >
        {/* Post Header */}
        <div className="flex items-start justify-between gap-4 mb-3">
          <div>
            {post.forked_from_id && (
              <span className="text-xs text-text-light dark:text-dark-text-muted flex items-center gap-1 mb-1">
                <GitFork className="w-3 h-3" />
                Forked
              </span>
            )}
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-display font-semibold text-xl text-primary dark:text-dark-text group-hover:text-secondary dark:group-hover:text-secondary-light transition-colors line-clamp-2">
                {post.title}
              </h3>
              <ReviewBadgeInline
                status={post.approval_status}
                approverRole={post.approved_by_role}
                isVerifiedAuthor={post.author?.is_verified_author}
              />
              {/* Knowledge Impact Badge - shows when score > 0 */}
              {hasImpact && (
                <span
                  className="flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 border border-emerald-200 dark:border-emerald-800"
                  title={`Knowledge Impact Score: ${impactScore.toFixed(1)} - Based on quality citations and scholarly engagement`}
                >
                  <GraduationCap className="w-3 h-3" />
                  {impactScore.toFixed(1)}
                </span>
              )}
            </div>
          </div>
          {post.license && (
            <span className="text-[10px] px-2 py-0.5 rounded-full bg-gray-100 dark:bg-dark-surface text-text-light dark:text-dark-text-muted border border-gray-200 dark:border-dark-border whitespace-nowrap">
              {tLicenses(post.license.replace(/\./g, '_'))}
            </span>
          )}
        </div>

        {/* Post Content Preview */}
        <p className="text-text-light dark:text-dark-text-muted leading-relaxed line-clamp-3 mb-4">
          {getExcerpt(post.content)}
        </p>

        {/* Tags */}
        {post.tags && post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mb-4">
            {post.tags.slice(0, 3).map((tag) => (
              <TagChip key={tag} tag={tag} size="sm" />
            ))}
            {post.tags.length > 3 && (
              <span className="text-xs text-text-light dark:text-dark-text-muted">
                +{post.tags.length - 3} more
              </span>
            )}
          </div>
        )}

        {/* Post Meta */}
        <div className="flex items-center gap-3 text-sm text-text-light dark:text-dark-text-muted mb-4">
          {showAuthor && post.author && (
            <div className="flex items-center gap-2">
              {post.author.avatar_url ? (
                <Image
                  src={post.author.avatar_url}
                  alt={displayAuthor}
                  width={24}
                  height={24}
                  className="w-6 h-6 rounded-full object-cover"
                />
              ) : (
                <div className={cn(
                  'w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-medium text-white',
                  getAvatarGradient(post.author.id || post.author_id)
                )}>
                  {getInitials(post.author.name, post.author.email)}
                </div>
              )}
              <span className="hover:text-primary dark:hover:text-accent-light transition-colors">
                {displayAuthor}
              </span>
            </div>
          )}

          <span className="text-text-muted/50">┬╖</span>

          <div className="flex items-center gap-1">
            <Clock className="w-3.5 h-3.5" aria-hidden="true" />
            <span>{readingTime} min read</span>
          </div>

          <span className="text-text-muted/50">┬╖</span>

          <time dateTime={post.created_at}>
            {formatDate(post.created_at, 'distance')}
          </time>
        </div>
      </Link>

      <div className="flex items-center justify-between mt-4 pt-4 border-t border-gray-100 dark:border-dark-border">
        <div className="flex items-center gap-4">
          <Link
            href={`/post/${post.id}`}
            className="flex items-center gap-1.5 text-sm text-text-light dark:text-dark-text-muted hover:text-primary dark:hover:text-accent-light transition-colors"
          >
            <MessageSquare className="w-4 h-4" />
            <span>{post.comment_count || 0} Comments</span>
          </Link>
          <div className="flex items-center gap-1.5 text-sm text-text-light dark:text-dark-text-muted">
            <Quote className="w-4 h-4" />
            <span>{post.citation_count || 0} Citations</span>
          </div>
        </div>

        <div className="flex items-center gap-1">
          <BookmarkButton postId={post.id} />
          <ReportButton postId={post.id} />
        </div>
      </div>
    </article>
  )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { format } from 'date-fns'
import { History, X, ChevronLeft, ChevronRight, User as UserIcon, FileDiff } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { PostVersion } from '@/types'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { PlagiarismCheckButton } from './PlagiarismCheckButton'
import { diffWords } from 'diff'
import Markdown from 'react-markdown'

interface PostHistoryDialogProps {
    postId: string
    isOpen: boolean
    onClose: () => void
}

export function PostHistoryDialog({ postId, isOpen, onClose }: PostHistoryDialogProps) {
    const supabase = useMemo(() => createClient(), [])
    const [versions, setVersions] = useState<PostVersion[]>([])
    const [loading, setLoading] = useState(true)
    const [selectedVersion, setSelectedVersion] = useState<PostVersion | null>(null)
    const [showDiff, setShowDiff] = useState(false)

    useEffect(() => {
        async function loadVersions() {
            setLoading(true)
            const { data, error } = await supabase
                .from('post_versions')
                .select('*')
                .eq('post_id', postId)
                .order('version_number', { ascending: false })

            if (error) {
                console.error('Error loading versions:', error)
            } else {
                setVersions(data || [])
                if (data && data.length > 0) {
                    setSelectedVersion(data[0])
                }
            }
            setLoading(false)
        }

        if (isOpen && postId) {
            loadVersions()
        }
    }, [isOpen, postId, supabase])

    const renderDiff = () => {
        if (!selectedVersion) return null

        // Find previous version (the one with the next index since we sort desc)
        const currentIndex = versions.findIndex(v => v.id === selectedVersion.id)
        const prevVersion = versions[currentIndex + 1]

        if (!prevVersion) {
            return (
                <div className="p-4 bg-yellow-50 dark:bg-yellow-900/20 text-yellow-800 dark:text-yellow-200 rounded-lg mb-4">
                    This is the first version. No previous content to compare.
                </div>
            )
        }

        const diff = diffWords(prevVersion.content, selectedVersion.content)

        return (
            <div className="prose dark:prose-invert max-w-none whitespace-pre-wrap">
                {diff.map((part, index) => {
                    const color = part.added ? 'bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-200' :
                        part.removed ? 'bg-red-100 dark:bg-red-900/40 text-red-800 dark:text-red-200 line-through' : ''
                    return (
                        <span key={index} className={color}>
                            {part.value}
                        </span>
                    )
                })}
            </div>
        )
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="max-w-4xl max-h-[85vh] flex flex-col p-0 gap-0 bg-white dark:bg-dark-surface">
                <DialogHeader className="p-6 border-b border-gray-100 dark:border-dark-border">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-primary/10 rounded-lg">
                                <History className="w-5 h-5 text-primary" />
                            </div>
                            <div>
                                <DialogTitle className="text-xl font-display font-bold text-text dark:text-dark-text">
                                    Version History
                                </DialogTitle>
                                <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                                    View previous versions of this post
                                </p>
                            </div>
                        </div>
                        {selectedVersion && (
                            <Button
                                variant={showDiff ? "default" : "outline"}
                                size="sm"
                                onClick={() => setShowDiff(!showDiff)}
                                className="gap-2 mr-8"
                            >
                                <FileDiff className="w-4 h-4" />
                                {showDiff ? 'Hide Changes' : 'Show Changes'}
                            </Button>
                        )}
                    </div>
                </DialogHeader>

                <div className="flex flex-1 overflow-hidden min-h-[500px]">
                    {/* Sidebar - Version List */}
                    <div className="w-1/3 border-r border-gray-100 dark:border-dark-border overflow-y-auto bg-gray-50/50 dark:bg-dark-bg/50">
                        {loading ? (
                            <div className="p-8 text-center text-text-light dark:text-dark-text-muted">
                                Loading history...
                            </div>
                        ) : versions.length === 0 ? (
                            <div className="p-8 text-center text-text-light dark:text-dark-text-muted">
                                No history available
                            </div>
                        ) : (
                            <div className="divide-y divide-gray-100 dark:divide-dark-border">
                                {versions.map((version) => (
                                    <button
                                        key={version.id}
                                        onClick={() => {
                                            setSelectedVersion(version)
                                            setShowDiff(false) // Reset diff view on switch
                                        }}
                                        className={`w-full text-left p-4 transition-colors hover:bg-gray-100 dark:hover:bg-dark-surface ${selectedVersion?.id === version.id
                                            ? 'bg-white dark:bg-dark-surface shadow-sm border-l-4 border-primary'
                                            : 'border-l-4 border-transparent'
                                            }`}
                                    >
                                        <div className="flex items-center justify-between mb-1">
                                            <span className="text-sm font-semibold text-text dark:text-dark-text">
                                                Version {version.version_number}
                                            </span>
                                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                {format(new Date(version.created_at), 'MMM d, yyyy HH:mm')}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-text-light dark:text-dark-text-muted">
                                            <UserIcon className="w-3 h-3" />
                                            <span>Editor ID: {version.editor_id?.slice(0, 8)}...</span>
                                        </div>
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Main Content - Version Preview */}
                    <div className="flex-1 overflow-y-auto p-8 bg-white dark:bg-dark-surface">
                        {selectedVersion ? (
                            <div className="space-y-6">
                                <div>
                                    <h2 className="text-2xl font-bold text-text dark:text-dark-text mb-2">
                                        {selectedVersion.title}
                                    </h2>
                                    <div className="flex flex-wrap gap-2">
                                        {selectedVersion.tags?.map((tag) => (
                                            <span
                                                key={tag}
                                                className="px-2 py-1 rounded-full bg-gray-100 dark:bg-dark-bg text-xs font-medium text-text-light dark:text-dark-text-muted"
                                            >
                                                #{tag}
                                            </span>
                                        ))}
                                    </div>
                                    <div className="mt-4">
                                        <PlagiarismCheckButton postVersionId={selectedVersion.id} />
                                    </div>
                                </div>

                                {showDiff ? renderDiff() : (
                                    <div className="prose prose-sm dark:prose-invert max-w-none">
                                        <Markdown>{selectedVersion.content}</Markdown>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="h-full flex items-center justify-center text-text-light dark:text-dark-text-muted">
                                Select a version to view details
                            </div>
                        )}
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { CheckCircle, Circle, User, FileText, Camera, Award, Shield, MapPin, Building, Globe, Image, ChevronDown, ChevronUp } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface ProfileCompletion {
    success: boolean
    percentage: number
    core_score: number
    core_max: number
    bonus_xp: number
    missing_core: string[]
    optional_completed: string[]
    is_complete: boolean
    skill_count: number
    endorsement_count: number
}

interface ProfileCompletionCardProps {
    userId: string
    compact?: boolean
}

const CORE_FIELDS = [
    { id: 'name', label: 'Display Name', icon: User, tip: 'Add your name for attribution' },
    { id: 'bio', label: 'Bio (30+ chars)', icon: FileText, tip: 'Describe your expertise' },
    { id: 'avatar', label: 'Profile Photo', icon: Camera, tip: 'Add a photo or avatar' },
    { id: 'skills', label: 'Add a Skill', icon: Award, tip: 'Show your areas of expertise' },
]

const OPTIONAL_FIELDS = [
    { id: 'cover_image', label: 'Cover Image', icon: Image, xp: 10 },
    { id: 'affiliation', label: 'Affiliation', icon: Building, xp: 15 },
    { id: 'location', label: 'Location', icon: MapPin, xp: 10, privacy: true },
    { id: 'website', label: 'Website', icon: Globe, xp: 10 },
    { id: 'endorsements_3', label: '3+ Endorsements', icon: Award, xp: 20 },
    { id: 'skills_5', label: '5+ Skills', icon: Award, xp: 15 },
]

export function ProfileCompletionCard({ userId, compact = false }: ProfileCompletionCardProps) {
    const t = useTranslations('ProfileCompletion')
    const [completion, setCompletion] = useState<ProfileCompletion | null>(null)
    const [loading, setLoading] = useState(true)
    const [refreshKey, setRefreshKey] = useState(0)
    const [isCollapsed, setIsCollapsed] = useState(true)
    const supabase = createClient()

    // Load completion data
    useEffect(() => {
        async function loadCompletion() {
            setLoading(true)
            const { data, error } = await supabase.rpc('get_profile_completion', {
                p_user_id: userId
            })

            if (!error && data?.success) {
                setCompletion(data)
                // Auto-expand if incomplete (less than 100%)
                if (!data.is_complete && !data.success) {
                    setIsCollapsed(false)
                } else if (!data.is_complete) {
                    setIsCollapsed(false)
                }
            }
            setLoading(false)
        }

        loadCompletion()
    }, [userId, supabase, refreshKey])

    // Listen for profile update events
    useEffect(() => {
        const handleProfileUpdate = () => {
            setRefreshKey(prev => prev + 1)
        }

        // Listen for custom 'profile-updated' event
        window.addEventListener('profile-updated', handleProfileUpdate)

        return () => {
            window.removeEventListener('profile-updated', handleProfileUpdate)
        }
    }, [])

    if (loading) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                <div className="animate-pulse flex items-center gap-4">
                    <div className="w-16 h-16 bg-gray-200 dark:bg-dark-border rounded-full" />
                    <div className="flex-1 space-y-2">
                        <div className="h-4 bg-gray-200 dark:bg-dark-border rounded w-1/2" />
                        <div className="h-3 bg-gray-200 dark:bg-dark-border rounded w-3/4" />
                    </div>
                </div>
            </div>
        )
    }

    if (!completion) return null

    const { percentage, missing_core, optional_completed, bonus_xp, is_complete } = completion

    // Calculate progress ring
    const circumference = 2 * Math.PI * 28
    const strokeDashoffset = circumference - (percentage / 100) * circumference



    if (compact) {
        return (
            <div className="flex items-center gap-3 px-3 py-2 rounded-lg">
                {/* Mini progress ring */}
                <div className="relative w-10 h-10">
                    <svg className="w-10 h-10 -rotate-90">
                        <circle
                            cx="20" cy="20" r="16"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="3"
                            className="text-gray-200 dark:text-dark-border"
                        />
                        <circle
                            cx="20" cy="20" r="16"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="3"
                            strokeDasharray={2 * Math.PI * 16}
                            strokeDashoffset={2 * Math.PI * 16 - (percentage / 100) * 2 * Math.PI * 16}
                            strokeLinecap="round"
                            className={cn(
                                percentage === 100 ? "text-emerald-500" : "text-primary"
                            )}
                        />
                    </svg>
                    <span className="absolute inset-0 flex items-center justify-center text-xs font-semibold text-text dark:text-dark-text">
                        {percentage}%
                    </span>
                </div>
                <div>
                    <p className="text-sm font-medium text-text dark:text-dark-text">
                        {is_complete ? t('complete') : t('completeProfile')}
                    </p>
                    {bonus_xp > 0 && (
                        <p className="text-xs text-primary">+{bonus_xp} bonus XP</p>
                    )}
                </div>
            </div>
        )
    }

    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4 transition-all">
            {/* Header with progress ring and Toggle */}
            <div className="flex items-center justify-between mb-4">
                <button
                    onClick={() => setIsCollapsed(!isCollapsed)}
                    className="flex items-center gap-3 flex-1 group hover:opacity-80 transition-opacity"
                >
                    <div className="relative w-10 h-10">
                        <svg className="w-10 h-10 -rotate-90">
                            <circle
                                cx="20" cy="20" r="16"
                                fill="none"
                                stroke="currentColor"
                                strokeWidth="3"
                                className="text-gray-200 dark:text-dark-border"
                            />
                            <circle
                                cx="20" cy="20" r="16"
                                fill="none"
                                stroke="currentColor"
                                strokeWidth="3"
                                strokeDasharray={2 * Math.PI * 16}
                                strokeDashoffset={2 * Math.PI * 16 - (percentage / 100) * 2 * Math.PI * 16}
                                strokeLinecap="round"
                                className={cn(
                                    "transition-all duration-500",
                                    percentage === 100 ? "text-emerald-500" : "text-primary"
                                )}
                            />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center">
                            {is_complete ? (
                                <CheckCircle className="w-4 h-4 text-emerald-500" />
                            ) : (
                                <span className="text-xs font-bold text-text dark:text-dark-text">{percentage}%</span>
                            )}
                        </div>
                    </div>
                    <div className="text-left">
                        <h3 className="text-lg font-semibold text-text dark:text-dark-text">
                            {is_complete ? t('complete') : t('completeYourProfile')}
                        </h3>
                        <p className="text-sm text-text-light dark:text-dark-text-muted">
                            {is_complete
                                ? t('bonusXpEarned', { count: bonus_xp })
                                : t('itemsRemaining', { count: missing_core.length })
                            }
                        </p>
                    </div>
                </button>

                <button
                    onClick={() => setIsCollapsed(!isCollapsed)}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-dark-bg rounded-lg transition-colors text-gray-400 dark:text-gray-500 hover:text-primary"
                >
                    {isCollapsed ? <ChevronDown className="w-5 h-5" /> : <ChevronUp className="w-5 h-5" />}
                </button>
            </div>

            {/* Collapsible Content */}
            <div className={cn(
                "overflow-hidden transition-all duration-300",
                isCollapsed ? "max-h-0 opacity-0" : "max-h-[1000px] opacity-100"
            )}>
                {/* Missing core fields */}
                {missing_core.length > 0 && (
                    <div className="space-y-2 mb-4">
                        <p className="text-xs font-medium text-text-light dark:text-dark-text-muted uppercase tracking-wide">
                            {t('suggested')}
                        </p>
                        {CORE_FIELDS.filter(f => missing_core.includes(f.id)).map(field => (
                            <div
                                key={field.id}
                                className="flex items-center gap-3 px-3 py-2 rounded-lg bg-gray-50 dark:bg-dark-bg"
                            >
                                <Circle className="w-4 h-4 text-gray-400" />
                                <field.icon className="w-4 h-4 text-primary" />
                                <span className="text-sm text-text dark:text-dark-text">{field.label}</span>
                            </div>
                        ))}
                    </div>
                )}

                {/* Optional bonus fields */}
                {is_complete && (
                    <div className="space-y-2">
                        <p className="text-xs font-medium text-text-light dark:text-dark-text-muted uppercase tracking-wide">
                            {t('optionalExtras')}
                        </p>
                        {OPTIONAL_FIELDS.filter(f => !optional_completed.includes(f.id)).slice(0, 3).map(field => (
                            <div
                                key={field.id}
                                className="flex items-center justify-between px-3 py-2 rounded-lg bg-gray-50 dark:bg-dark-bg"
                            >
                                <div className="flex items-center gap-3">
                                    <field.icon className="w-4 h-4 text-gray-400" />
                                    <span className="text-sm text-text-light dark:text-dark-text-muted">
                                        {field.label}
                                        {field.privacy && (
                                            <span className="text-xs ml-1 text-gray-400">(optional)</span>
                                        )}
                                    </span>
                                </div>
                                <span className="text-xs font-medium text-primary">+{field.xp} XP</span>
                            </div>
                        ))}
                    </div>
                )}

                {/* Privacy note */}
                <p className="mt-4 text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                    <Shield className="w-3 h-3" />
                    {t('privacyNote')}
                </p>
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Label } from '@/components/ui/label'
import { useToast } from '@/components/ui/toast'
import { ImageUpload } from '@/components/ImageUpload'
import { Loader2 } from 'lucide-react'

interface ProfileEditFormProps {
    profile: any
}

export function ProfileEditForm({ profile }: ProfileEditFormProps) {
    const [loading, setLoading] = useState(false)
    const [formData, setFormData] = useState({
        name: profile.name || '',
        bio: profile.bio || '',
        affiliation: profile.affiliation || '',
        avatar_url: profile.avatar_url || ''
    })

    const router = useRouter()
    const { showToast } = useToast()
    const supabase = createClient()

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const { error } = await supabase
                .from('users')
                .update({
                    name: formData.name,
                    bio: formData.bio,
                    affiliation: formData.affiliation,
                    avatar_url: formData.avatar_url
                })
                .eq('id', profile.id)

            if (error) throw error

            showToast('Profile updated successfully', 'success')
            router.push(`/profile/${profile.id}`)
            router.refresh()
        } catch (error: any) {
            console.error('Error updating profile:', error)
            showToast('Failed to update profile', 'error')
        } finally {
            setLoading(false)
        }
    }

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="flex justify-center mb-6">
                <ImageUpload
                    bucket="avatars"
                    path={profile.id} // Store in a folder named after the user ID
                    currentImage={formData.avatar_url}
                    onUploadComplete={(url) => setFormData({ ...formData, avatar_url: url })}
                />
            </div>

            <div className="space-y-2">
                <Label htmlFor="name">Full Name</Label>
                <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    required
                />
            </div>

            <div className="space-y-2">
                <Label htmlFor="affiliation">Affiliation</Label>
                <Input
                    id="affiliation"
                    value={formData.affiliation}
                    onChange={(e) => setFormData({ ...formData, affiliation: e.target.value })}
                    placeholder="University, Organization, or Company"
                />
            </div>

            <div className="space-y-2">
                <Label htmlFor="bio">Bio</Label>
                <Textarea
                    id="bio"
                    value={formData.bio}
                    onChange={(e) => setFormData({ ...formData, bio: e.target.value })}
                    placeholder="Tell us about yourself..."
                    rows={4}
                />
            </div>

            <div className="flex justify-end gap-4 pt-4">
                <Button
                    type="button"
                    variant="outline"
                    onClick={() => router.back()}
                    disabled={loading}
                >
                    Cancel
                </Button>
                <Button type="submit" disabled={loading}>
                    {loading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                    Save Changes
                </Button>
            </div>
        </form>
    )
}

'use client'

import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { EditProfileDialog } from './EditProfileDialog'
