                {/* Stats Toggle Header */}
                <button
                    onClick={() => setStatsOpen(!statsOpen)}
                    className="w-full flex items-center justify-between mt-6 py-3 px-3 border-t border-gray-100 dark:border-white/10 group hover:bg-gray-50/50 dark:hover:bg-white/5 transition-colors rounded-lg"
                >
                    <div className="flex items-center gap-4">
                        <span className="text-sm font-medium text-gray-600 dark:text-gray-300 group-hover:text-primary dark:group-hover:text-white transition-colors">
                            {t('knowledgeImpactStats')}
                        </span>
                        {!statsOpen && (
                            <div className="flex items-center gap-3 text-sm animate-in fade-in duration-300">
                                <div className="h-4 w-px bg-gray-200 dark:bg-white/10" />
                                <div className="flex items-center gap-1.5 text-text-light dark:text-dark-text-muted">
                                    <GraduationCap className="w-3.5 h-3.5" />
                                    <span>
                                        {t('impact')}: <span className="font-semibold text-text dark:text-dark-text">{stats?.academic_impact || 0}</span>
                                    </span>
                                </div>
                                <div className="flex items-center gap-1.5 text-text-light dark:text-dark-text-muted">
                                    <FileText className="w-3.5 h-3.5" />
                                    <span>
                                        {t('posts')}: <span className="font-semibold text-text dark:text-dark-text">{stats?.post_count || 0}</span>
                                    </span>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="p-1.5 hover:bg-gray-100 dark:hover:bg-dark-bg rounded-lg transition-colors text-gray-400 dark:text-gray-500 group-hover:text-primary dark:group-hover:text-white">
                        {statsOpen ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                    </div>
                </button>

                {/* Stats with visual bars - Collapsible */}
                <div className={cn(
                    "grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6 sm:gap-8 overflow-hidden transition-all duration-300 ease-in-out",
                    statsOpen ? "max-h-[500px] opacity-100 mt-5 pb-2" : "max-h-0 opacity-0 mt-0"
                )} suppressHydrationWarning>
                    <StatItem
                        icon={FileText}
                        value={stats?.post_count || 0}
                        label={t('posts')}
                        maxValue={50}
                        color="primary"
                        mounted={mounted}
                    />
                    <StatItem
                        icon={CalendarDays}
                        value={stats?.event_count || 0}
                        label={t('events')}
                        maxValue={20}
                        color="secondary"
                        mounted={mounted}
                    />
                    <StatItem
                        icon={Quote}
                        value={stats?.citation_count || 0}
                        label={t('citations')}
                        maxValue={100}
                        color="accent"
                        mounted={mounted}
                    />
                    <StatItem
                        icon={Users}
                        value={stats?.follower_count || 0}
                        label={t('followers')}
                        maxValue={200}
                        color="accent"
                        mounted={mounted}
                    />
                    <StatItem
                        icon={GraduationCap}
                        value={stats?.academic_impact || 0}
                        label={t('knowledgeImpact')}
                        maxValue={100}
                        color="emerald"
                        tooltip="Knowledge Impact: How this work contributes to the collective understanding through citations and reuse"
                        mounted={mounted}
                    />
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { createClient } from '@/lib/supabase/client'
import {
    FolderKanban,
    Users,
    FileText,
    Calendar,
    Eye,
    Lock,
    Globe,
    ChevronRight,
    Plus
} from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'

interface Project {
    id: string
    title: string
    description: string | null
    cover_image_url: string | null
    status: 'draft' | 'active' | 'completed' | 'archived'
    visibility: 'public' | 'private' | 'members_only'
    created_at: string
    post_count: number
    member_count: number
    view_count: number
    tags: string[]
    created_by: {
        name?: string
        email?: string
    } | null
}

interface ProjectCardProps {
    project: Project
    variant?: 'default' | 'compact'
}

export function ProjectCard({ project, variant = 'default' }: ProjectCardProps) {
    const creatorName = project.created_by?.name ||
        project.created_by?.email?.split('@')[0] ||
        'Unknown'

    const statusColors = {
        draft: 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400',
        active: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400',
        completed: 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400',
        archived: 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400',
    }

    const visibilityIcons = {
        public: Globe,
        private: Lock,
        members_only: Users,
    }
    const VisibilityIcon = visibilityIcons[project.visibility]

    if (variant === 'compact') {
        return (
            <Link
                href={`/project/${project.id}`}
                className="flex items-center gap-3 p-3 rounded-lg border border-gray-200 dark:border-dark-border hover:border-primary dark:hover:border-primary-light transition-colors"
            >
                <div className="w-12 h-12 rounded-lg bg-gradient-to-br from-primary to-secondary flex items-center justify-center flex-shrink-0">
                    <FolderKanban className="w-6 h-6 text-white" />
                </div>
                <div className="flex-1 min-w-0">
                    <h4 className="font-medium text-text dark:text-dark-text truncate">
                        {project.title}
                    </h4>
                    <div className="flex items-center gap-3 text-xs text-text-light dark:text-dark-text-muted">
                        <span className="flex items-center gap-1">
                            <FileText className="w-3 h-3" />
                            {project.post_count}
                        </span>
                        <span className="flex items-center gap-1">
                            <Users className="w-3 h-3" />
                            {project.member_count}
                        </span>
                    </div>
                </div>
                <ChevronRight className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
            </Link>
        )
    }

    return (
        <Link
            href={`/project/${project.id}`}
            className="group block card card-hover overflow-hidden"
        >
            {/* Cover Image */}
            {project.cover_image_url ? (
                <div className="relative h-40 bg-gray-100 dark:bg-dark-surface overflow-hidden">
                    <Image
                        src={project.cover_image_url}
                        alt={project.title}
                        fill
                        className="object-cover group-hover:scale-105 transition-transform duration-300"
                        sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent" />
                    <div className="absolute bottom-3 left-3 flex items-center gap-2">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColors[project.status]}`}>
                            {project.status}
                        </span>
                        <span className="p-1 rounded-full bg-black/30 text-white" title={project.visibility}>
                            <VisibilityIcon className="w-3.5 h-3.5" />
                        </span>
                    </div>
                </div>
            ) : (
                <div className="relative h-40 bg-gradient-to-br from-primary/20 to-secondary/20 flex items-center justify-center">
                    <FolderKanban className="w-16 h-16 text-primary/50" />
                    <div className="absolute bottom-3 left-3 flex items-center gap-2">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColors[project.status]}`}>
                            {project.status}
                        </span>
                        <span className="p-1 rounded-full bg-white/50 dark:bg-black/30 text-text-light dark:text-dark-text-muted" title={project.visibility}>
                            <VisibilityIcon className="w-3.5 h-3.5" />
                        </span>
                    </div>
                </div>
            )}

            {/* Content */}
            <div className="p-4">
                <h3 className="font-semibold text-lg text-text dark:text-dark-text group-hover:text-primary dark:group-hover:text-primary-light transition-colors line-clamp-1">
                    {project.title}
                </h3>

                {project.description && (
                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1 line-clamp-2">
                        {project.description}
                    </p>
                )}

                {/* Tags */}
                {project.tags && project.tags.length > 0 && (
                    <div className="flex flex-wrap gap-1 mt-3">
                        {project.tags.slice(0, 3).map((tag) => (
                            <span
                                key={tag}
                                className="px-2 py-0.5 bg-gray-100 dark:bg-dark-surface text-xs text-text-light dark:text-dark-text-muted rounded-full"
                            >
                                {tag}
                            </span>
                        ))}
                        {project.tags.length > 3 && (
                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                +{project.tags.length - 3}
                            </span>
                        )}
                    </div>
                )}

                {/* Stats */}
                <div className="flex items-center justify-between mt-4 pt-3 border-t border-gray-100 dark:border-dark-border">
                    <div className="flex items-center gap-4 text-sm text-text-light dark:text-dark-text-muted">
                        <span className="flex items-center gap-1.5">
                            <FileText className="w-4 h-4" />
                            {project.post_count} posts
                        </span>
                        <span className="flex items-center gap-1.5">
                            <Users className="w-4 h-4" />
                            {project.member_count}
                        </span>
                    </div>
                    <span className="text-xs text-text-light dark:text-dark-text-muted">
                        {formatDistanceToNow(new Date(project.created_at), { addSuffix: true })}
                    </span>
                </div>
            </div>
        </Link>
    )
}

/**
 * List of projects with optional filters
 */
interface ProjectListProps {
    userId?: string
    limit?: number
    showCreateButton?: boolean
}

export function ProjectList({ userId, limit = 10, showCreateButton = false }: ProjectListProps) {
    const [projects, setProjects] = useState<Project[]>([])
    const [loading, setLoading] = useState(true)
    const supabase = useMemo(() => createClient(), [])

    useEffect(() => {
        async function fetchProjects() {
            try {
                let query = supabase
                    .from('projects')
                    .select(`
            *,
            created_by:users!projects_created_by_fkey(name, email)
          `)
                    .order('created_at', { ascending: false })
                    .limit(limit)

                if (userId) {
                    query = query.or(`created_by.eq.${userId},project_members.user_id.eq.${userId}`)
                } else {
                    query = query.eq('visibility', 'public')
                }

                const { data, error } = await query

                if (error) throw error
                setProjects(data || [])
            } catch (error) {
                console.error('Error fetching projects:', error)
            } finally {
                setLoading(false)
            }
        }

        fetchProjects()
    }, [userId, limit, supabase])

    if (loading) {
        return (
            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                {[1, 2, 3].map((i) => (
                    <div key={i} className="h-64 rounded-2xl bg-gray-100 dark:bg-dark-surface animate-pulse" />
                ))}
            </div>
        )
    }

    if (projects.length === 0) {
        return (
            <div className="text-center py-12">
                <FolderKanban className="w-12 h-12 mx-auto text-text-light dark:text-dark-text-muted opacity-50 mb-4" />
                <p className="text-text-light dark:text-dark-text-muted">No projects yet</p>
                {showCreateButton && (
                    <Link
                        href="/project/new"
                        className="inline-flex items-center gap-2 mt-4 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark transition-colors"
                    >
                        <Plus className="w-4 h-4" />
                        Create Project
                    </Link>
                )}
            </div>
        )
    }

    return (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {projects.map((project) => (
                <ProjectCard key={project.id} project={project} />
            ))}
        </div>
    )
}

'use client'

import Link from 'next/link'
import { useState } from 'react'
import { MessageSquare, ThumbsUp, ThumbsDown, ArrowRight, CheckCircle } from 'lucide-react'
import { Post } from '@/types'
import { formatDistanceToNow } from 'date-fns'
import { cn } from '@/lib/utils'

interface QuestionCardProps {
    post: Post
    userVote?: number // 1, -1, or undefined
    onVote?: (value: 1 | -1) => void
}

export function QuestionCard({ post, userVote: initialUserVote, onVote }: QuestionCardProps) {
    const [voteCount, setVoteCount] = useState(post.vote_count || 0)
    const [userVote, setUserVote] = useState<number | undefined>(initialUserVote)
    const [isVoting, setIsVoting] = useState(false)

    const handleVote = async (value: 1 | -1) => {
        if (isVoting) return

        // Optimistic update
        const previousVote = userVote
        const previousCount = voteCount

        let newVoteCount = voteCount
        if (userVote === value) {
            // Toggle off
            setUserVote(undefined)
            newVoteCount -= value
        } else {
            // Change vote or new vote
            if (userVote) {
                newVoteCount -= userVote // Remove old vote
            }
            setUserVote(value)
            newVoteCount += value
        }
        setVoteCount(newVoteCount)
        setIsVoting(true)

        try {
            const response = await fetch(`/api/posts/${post.id}/vote`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value })
            })

            if (!response.ok) {
                throw new Error('Vote failed')
            }

            // Optional: Update with server count if returned
            const data = await response.json()
            if (data.voteCount !== undefined) {
                setVoteCount(data.voteCount)
            }
        } catch (error) {
            // Revert on error
            setUserVote(previousVote)
            setVoteCount(previousCount)
            console.error('Failed to vote:', error)
        } finally {
            setIsVoting(false)
        }
    }

    return (
        <div className="card hover:border-primary/50 transition-colors group">
            <div className="p-6 flex gap-6">
                {/* Voting Side */}
                <div className="flex flex-col items-center gap-2 pt-1">
                    <button
                        onClick={(e) => {
                            e.preventDefault()
                            handleVote(1)
                        }}
                        disabled={isVoting}
                        className={cn(
                            "p-1 rounded hover:bg-gray-100 dark:hover:bg-dark-surface-hover transition-colors",
                            userVote === 1 ? "text-primary" : "text-gray-400"
                        )}
                    >
                        <ThumbsUp className="w-5 h-5" />
                    </button>

                    <span className="font-bold text-lg text-text dark:text-dark-text">
                        {voteCount}
                    </span>

                    <button
                        onClick={(e) => {
                            e.preventDefault()
                            handleVote(-1)
                        }}
                        disabled={isVoting}
                        className={cn(
                            "p-1 rounded hover:bg-gray-100 dark:hover:bg-dark-surface-hover transition-colors",
                            userVote === -1 ? "text-red-500" : "text-gray-400"
                        )}
                    >
                        <ThumbsDown className="w-5 h-5" />
                    </button>
                </div>

                {/* Content Side */}
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-2">
                        <span className="px-2 py-0.5 rounded-full bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 text-xs font-medium">
                            Question
                        </span>
                        {post.accepted_answer_id && (
                            <span className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300 text-xs font-medium">
                                <CheckCircle className="w-3 h-3" />
                                Solved
                            </span>
                        )}
                        <span className="text-sm text-text-light dark:text-dark-text-muted">
                            Posted by {post.author?.name || 'Anonymous'} ΓÇó {formatDistanceToNow(new Date(post.created_at), { addSuffix: true })}
                        </span>
                    </div>

                    <Link href={`/post/${post.id}`} className="block group-hover:text-primary transition-colors">
                        <h3 className="text-xl font-bold text-text dark:text-dark-text mb-2 truncate">
                            {post.title}
                        </h3>
                    </Link>

                    <p className="text-text-light dark:text-dark-text-muted line-clamp-2 mb-4">
                        {post.content}
                    </p>

                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="flex items-center gap-1.5 text-sm text-text-light dark:text-dark-text-muted">
                                <MessageSquare className="w-4 h-4" />
                                <span>{post.comment_count || 0} answers</span>
                            </div>

                            <div className="flex gap-2">
                                {post.tags?.map(tag => (
                                    <span key={tag} className="text-xs px-2 py-1 rounded-md bg-gray-100 dark:bg-dark-surface-hover text-text-light dark:text-dark-text-muted">
                                        #{tag}
                                    </span>
                                ))}
                            </div>
                        </div>

                        <Link
                            href={`/post/${post.id}`}
                            className="btn btn-ghost btn-sm flex items-center gap-2"
                        >
                            Answer this
                            <ArrowRight className="w-4 h-4" />
                        </Link>
                    </div>
                </div >
            </div >
        </div >
    )
}

'use client'

import { useState, useEffect } from 'react'
import { BookOpen, Clock, Target, Tag, TrendingUp, Calendar, Star } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'

interface ReadingStats {
    total_posts_read: number
    posts_completed: number
    total_reading_time: number
    posts_read_this_week: number
    posts_read_this_month: number
    avg_read_time: number
}

interface FavoriteTopic {
    tag: string
    read_count: number
}

interface ReadingActivity {
    date: string
    posts_read: number
    minutes_read: number
}

interface ReadingInsightsProps {
    userId: string
    compact?: boolean
}

export function ReadingInsights({ userId, compact = false }: ReadingInsightsProps) {
    const [stats, setStats] = useState<ReadingStats | null>(null)
    const [topics, setTopics] = useState<FavoriteTopic[]>([])
    const [activity, setActivity] = useState<ReadingActivity[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        async function fetchReadingData() {
            const supabase = createClient()

            try {
                // Get reading stats
                const { data: statsData } = await supabase.rpc('get_user_reading_stats', {
                    p_user_id: userId,
                })
                if (statsData) setStats(statsData)

                // Get favorite topics
                const { data: topicsData } = await supabase.rpc('get_favorite_topics', {
                    p_user_id: userId,
                    p_limit: 5,
                })
                if (topicsData) setTopics(topicsData)

                // Get activity
                const { data: activityData } = await supabase.rpc('get_reading_activity', {
                    p_user_id: userId,
                    p_days: 30,
                })
                if (activityData) setActivity(activityData)
            } catch (error) {
                console.error('Failed to fetch reading insights:', error)
            } finally {
                setLoading(false)
            }
        }

        fetchReadingData()
    }, [userId])

    if (loading) {
        return <ReadingInsightsSkeleton compact={compact} />
    }

    if (!stats || stats.total_posts_read === 0) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6 text-center">
                <BookOpen className="w-8 h-8 text-text-light dark:text-dark-text-muted mx-auto mb-2" />
                <p className="text-text-light dark:text-dark-text-muted">No reading activity yet</p>
                <p className="text-sm text-text-light/70 dark:text-dark-text-muted/70 mt-1">
                    Start exploring posts to see your reading insights
                </p>
            </div>
        )
    }

    const formatTime = (seconds: number) => {
        const hours = Math.floor(seconds / 3600)
        const minutes = Math.floor((seconds % 3600) / 60)
        if (hours > 0) return `${hours}h ${minutes}m`
        return `${minutes}m`
    }

    const completionRate = stats.total_posts_read > 0
        ? Math.round((stats.posts_completed / stats.total_posts_read) * 100)
        : 0

    if (compact) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                <div className="flex items-center justify-between mb-3">
                    <h3 className="font-semibold text-text dark:text-dark-text flex items-center gap-2">
                        <BookOpen className="w-4 h-4 text-primary" />
                        Reading Stats
                    </h3>
                </div>
                <div className="grid grid-cols-3 gap-3 text-center">
                    <div>
                        <p className="text-2xl font-bold text-text dark:text-dark-text">{stats.total_posts_read}</p>
                        <p className="text-xs text-text-light dark:text-dark-text-muted">Posts Read</p>
                    </div>
                    <div>
                        <p className="text-2xl font-bold text-text dark:text-dark-text">{formatTime(stats.total_reading_time)}</p>
                        <p className="text-xs text-text-light dark:text-dark-text-muted">Total Time</p>
                    </div>
                    <div>
                        <p className="text-2xl font-bold text-text dark:text-dark-text">{completionRate}%</p>
                        <p className="text-xs text-text-light dark:text-dark-text-muted">Completed</p>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-dark-border">
                <h3 className="font-semibold text-text dark:text-dark-text flex items-center gap-2">
                    <BookOpen className="w-5 h-5 text-primary" />
                    Reading Insights
                </h3>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 p-4">
                <StatCard
                    icon={BookOpen}
                    value={stats.total_posts_read.toString()}
                    label="Posts Read"
                    color="primary"
                />
                <StatCard
                    icon={Clock}
                    value={formatTime(stats.total_reading_time)}
                    label="Total Time"
                    color="accent"
                />
                <StatCard
                    icon={Target}
                    value={`${completionRate}%`}
                    label="Completion Rate"
                    color="secondary"
                />
                <StatCard
                    icon={TrendingUp}
                    value={stats.posts_read_this_week.toString()}
                    label="This Week"
                    color="green"
                />
            </div>

            {/* Favorite Topics */}
            {topics.length > 0 && (
                <div className="px-4 pb-4">
                    <div className="bg-gray-50 dark:bg-dark-bg rounded-xl p-4">
                        <h4 className="text-sm font-medium text-text dark:text-dark-text mb-3 flex items-center gap-2">
                            <Star className="w-4 h-4 text-amber-500" />
                            Favorite Topics
                        </h4>
                        <div className="flex flex-wrap gap-2">
                            {topics.map((topic, i) => (
                                <span
                                    key={topic.tag}
                                    className={`px-3 py-1.5 rounded-full text-sm font-medium ${i === 0
                                            ? 'bg-primary/20 text-primary'
                                            : i === 1
                                                ? 'bg-accent/20 text-accent-dark'
                                                : 'bg-gray-200 dark:bg-dark-border text-text-light dark:text-dark-text-muted'
                                        }`}
                                >
                                    #{topic.tag}
                                    <span className="ml-1.5 text-xs opacity-70">({topic.read_count})</span>
                                </span>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* Activity Heatmap */}
            {activity.length > 0 && (
                <div className="px-4 pb-4">
                    <ActivityHeatmap data={activity} />
                </div>
            )}
        </div>
    )
}

// Stat Card
interface StatCardProps {
    icon: any
    value: string
    label: string
    color: 'primary' | 'accent' | 'secondary' | 'green'
}

const colorClasses = {
    primary: 'bg-primary/10 text-primary',
    accent: 'bg-accent/10 text-accent-dark',
    secondary: 'bg-secondary/10 text-secondary-dark',
    green: 'bg-green-500/10 text-green-600',
}

function StatCard({ icon: Icon, value, label, color }: StatCardProps) {
    return (
        <div className="p-3 bg-gray-50 dark:bg-dark-bg rounded-xl">
            <div className={`w-8 h-8 rounded-lg ${colorClasses[color]} flex items-center justify-center mb-2`}>
                <Icon className="w-4 h-4" />
            </div>
            <p className="text-xl font-bold text-text dark:text-dark-text">{value}</p>
            <p className="text-xs text-text-light dark:text-dark-text-muted">{label}</p>
        </div>
    )
}

// Activity Heatmap
function ActivityHeatmap({ data }: { data: ReadingActivity[] }) {
    // Create a map for quick lookup
    const activityMap = new Map(data.map(d => [d.date, d]))

    // Generate last 30 days
    const days = Array.from({ length: 30 }, (_, i) => {
        const date = new Date()
        date.setDate(date.getDate() - (29 - i))
        return date.toISOString().split('T')[0]
    })

    const maxPosts = Math.max(...data.map(d => d.posts_read), 1)

    return (
        <div className="bg-gray-50 dark:bg-dark-bg rounded-xl p-4">
            <h4 className="text-sm font-medium text-text dark:text-dark-text mb-3 flex items-center gap-2">
                <Calendar className="w-4 h-4 text-primary" />
                Reading Activity (Last 30 Days)
            </h4>
            <div className="flex gap-1 flex-wrap">
                {days.map(day => {
                    const activity = activityMap.get(day)
                    const intensity = activity ? activity.posts_read / maxPosts : 0

                    return (
                        <div
                            key={day}
                            className="w-4 h-4 rounded-sm transition-colors group relative cursor-pointer"
                            style={{
                                backgroundColor: intensity > 0
                                    ? `rgba(99, 102, 241, ${0.2 + intensity * 0.8})`
                                    : 'rgba(156, 163, 175, 0.2)',
                            }}
                        >
                            {/* Tooltip */}
                            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                                {activity ? `${activity.posts_read} posts, ${activity.minutes_read}m` : 'No activity'}
                                <br />
                                {new Date(day).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                            </div>
                        </div>
                    )
                })}
            </div>
            <div className="flex items-center gap-2 mt-3 text-xs text-text-light dark:text-dark-text-muted">
                <span>Less</span>
                {[0.2, 0.4, 0.6, 0.8, 1].map((level, i) => (
                    <div
                        key={i}
                        className="w-3 h-3 rounded-sm"
                        style={{ backgroundColor: `rgba(99, 102, 241, ${level})` }}
                    />
                ))}
                <span>More</span>
            </div>
        </div>
    )
}

// Skeleton
function ReadingInsightsSkeleton({ compact }: { compact?: boolean }) {
    if (compact) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4 animate-pulse">
                <div className="h-5 bg-gray-200 dark:bg-dark-border rounded w-24 mb-3" />
                <div className="grid grid-cols-3 gap-3">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="text-center">
                            <div className="h-8 bg-gray-200 dark:bg-dark-border rounded mb-1" />
                            <div className="h-3 bg-gray-200 dark:bg-dark-border rounded w-12 mx-auto" />
                        </div>
                    ))}
                </div>
            </div>
        )
    }

    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden animate-pulse">
            <div className="p-4 border-b border-gray-100 dark:border-dark-border">
                <div className="h-5 bg-gray-200 dark:bg-dark-border rounded w-32" />
            </div>
            <div className="grid grid-cols-4 gap-4 p-4">
                {[1, 2, 3, 4].map(i => (
                    <div key={i} className="p-3 bg-gray-50 dark:bg-dark-bg rounded-xl">
                        <div className="w-8 h-8 bg-gray-200 dark:bg-dark-border rounded-lg mb-2" />
                        <div className="h-6 bg-gray-200 dark:bg-dark-border rounded w-12 mb-1" />
                        <div className="h-3 bg-gray-200 dark:bg-dark-border rounded w-16" />
                    </div>
                ))}
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import { BookOpen, ExternalLink, FileText, Loader2 } from 'lucide-react'
import { useTranslations } from 'next-intl'

interface InternalCitation {
    id: string
    type: 'internal'
    quote_content?: string | null
    target_post: {
        id: string
        title: string
        created_at: string
        author?: {
            name?: string | null
            email?: string | null
        } | null
    }
}

interface ExternalCitation {
    id: string
    type: 'external'
    external_url?: string | null
    external_doi?: string | null
    external_title?: string | null
    external_author?: string | null
    external_year?: number | null
    external_source?: string | null
}

type Citation = InternalCitation | ExternalCitation

interface ReferencesSectionProps {
    postId: string
}

export function ReferencesSection({ postId }: ReferencesSectionProps) {
    const [citations, setCitations] = useState<Citation[]>([])
    const [loading, setLoading] = useState(true)
    const supabase = useMemo(() => createClient(), [])
    const t = useTranslations('Post')

    useEffect(() => {
        async function fetchReferences() {
            if (!postId) {
                setLoading(false)
                return
            }

            try {
                // Fetch citations with a joined query matching the pattern in PostPage
                // We are explicit about the table and the foreign key relationship
                const { data, error } = await supabase
                    .from('citations')
                    .select(`
                        id,
                        type,
                        quote_content,
                        external_url,
                        external_doi,
                        external_title,
                        external_author,
                        external_year,
                        external_source,
                        target_post:posts!citations_target_post_id_fkey (
                            id,
                            title,
                            created_at,
                            author:users!posts_author_id_fkey (
                                name,
                                email
                            )
                        )
                    `)
                    .eq('source_post_id', postId)
                    .order('created_at', { ascending: true })

                if (error) {
                    console.error('ReferencesSection: Supabase error object:', JSON.stringify(error, Object.getOwnPropertyNames(error), 2))
                    console.error('ReferencesSection: Supabase error details:', {
                        message: error.message,
                        code: error.code,
                        details: error.details,
                        hint: error.hint
                    })
                    return
                }

                if (!data) {
                    setCitations([])
                    return
                }

                setCitations(data as Citation[])
            } catch (err: any) {
                console.error('ReferencesSection: Caught exception', {
                    message: err.message || 'Unknown error',
                    stack: err.stack,
                    fullError: err
                })
            } finally {
                setLoading(false)
            }
        }

        fetchReferences()
    }, [postId, supabase])

    if (loading) {
        return (
            <div className="flex items-center justify-center py-8">
                <Loader2 className="w-5 h-5 animate-spin text-text-light" />
            </div>
        )
    }

    if (citations.length === 0) {
        return null // Don't show empty section
    }

    const internalCitations = citations.filter((c): c is InternalCitation => c.type === 'internal')
    const externalCitations = citations.filter((c): c is ExternalCitation => c.type === 'external')

    return (
        <section className="border-t border-gray-200 dark:border-dark-border pt-8 mt-8">
            <div className="flex items-center gap-2 mb-6">
                <BookOpen className="w-5 h-5 text-primary dark:text-primary-light" />
                <h2 className="text-xl font-bold text-text dark:text-dark-text">
                    {t('references')} ({citations.length})
                </h2>
            </div>

            <div className="space-y-6">
                {/* Internal (SyriaHub) References */}
                {internalCitations.length > 0 && (
                    <div>
                        <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider mb-3 flex items-center gap-2">
                            <FileText className="w-4 h-4" />
                            {t('internalReference')}
                        </h3>
                        <ol className="list-decimal list-inside space-y-3 pl-1">
                            {internalCitations.map((citation) => (
                                <li key={citation.id} className="text-sm">
                                    <Link
                                        href={`/post/${citation.target_post.id}`}
                                        className="text-primary dark:text-primary-light hover:underline font-medium"
                                    >
                                        {citation.target_post.title}
                                    </Link>
                                    <span className="text-text-light dark:text-dark-text-muted">
                                        {' '}ΓÇö {citation.target_post.author?.name || citation.target_post.author?.email?.split('@')[0] || 'Anonymous'}
                                        {citation.target_post.created_at && (
                                            <> ({new Date(citation.target_post.created_at).getFullYear()})</>
                                        )}
                                    </span>
                                    {citation.quote_content && (
                                        <blockquote className="mt-1 pl-3 border-l-2 border-gray-300 dark:border-dark-border text-text-light dark:text-dark-text-muted italic text-xs line-clamp-2">
                                            &quot;{citation.quote_content}&quot;
                                        </blockquote>
                                    )}
                                </li>
                            ))}
                        </ol>
                    </div>
                )}

                {/* External References */}
                {externalCitations.length > 0 && (
                    <div>
                        <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider mb-3 flex items-center gap-2">
                            <ExternalLink className="w-4 h-4" />
                            {t('externalReference')}
                        </h3>
                        <ol className="list-decimal list-inside space-y-3 pl-1" start={internalCitations.length + 1}>
                            {externalCitations.map((citation) => {
                                const url = citation.external_url || (citation.external_doi ? `https://doi.org/${citation.external_doi}` : null)
                                const displayTitle = citation.external_title || citation.external_doi || citation.external_url || 'Unknown source'

                                return (
                                    <li key={citation.id} className="text-sm">
                                        {url ? (
                                            <a
                                                href={url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="text-primary dark:text-primary-light hover:underline font-medium inline-flex items-center gap-1"
                                            >
                                                {displayTitle}
                                                <ExternalLink className="w-3 h-3 flex-shrink-0" />
                                            </a>
                                        ) : (
                                            <span className="font-medium text-text dark:text-dark-text">{displayTitle}</span>
                                        )}
                                        <span className="text-text-light dark:text-dark-text-muted">
                                            {citation.external_author && <> ΓÇö {citation.external_author}</>}
                                            {citation.external_year && <> ({citation.external_year})</>}
                                            {citation.external_source && <> ΓÇó {citation.external_source}</>}
                                        </span>
                                        {citation.external_doi && (
                                            <span className="text-xs text-text-light dark:text-dark-text-muted ml-2">
                                                DOI: {citation.external_doi}
                                            </span>
                                        )}
                                    </li>
                                )
                            })}
                        </ol>
                    </div>
                )}
            </div>
        </section>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { AlertTriangle, Send, Loader2, CheckCircle, Clock } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"

interface RejectionBannerProps {
    postId: string
    postTitle: string
    rejectionReason: string | null
    approvalStatus: string
    isAuthor: boolean
    contentType?: 'post' | 'article' | 'question' | 'event'
}

interface Appeal {
    id: string
    status: 'pending' | 'approved' | 'rejected' | 'revision_requested'
    dispute_reason: string
    admin_response: string | null
    created_at: string
}

export function RejectionBanner({
    postId,
    postTitle,
    rejectionReason,
    approvalStatus,
    isAuthor,
    contentType = 'post'
}: RejectionBannerProps) {
    const [appealDialogOpen, setAppealDialogOpen] = useState(false)
    const [appealReason, setAppealReason] = useState('')
    const [submitting, setSubmitting] = useState(false)
    const [existingAppeal, setExistingAppeal] = useState<Appeal | null>(null)
    const [appealCount, setAppealCount] = useState(0)
    const [loading, setLoading] = useState(true)

    const MAX_APPEALS = 3
    const supabase = createClient()
    const { showToast } = useToast()

    // Fetch existing appeal and count on mount
    useEffect(() => {
        // Only fetch if this should render
        if (approvalStatus !== 'rejected' || !isAuthor) return

        const fetchAppealData = async () => {
            // Get most recent appeal
            const { data, error } = await supabase
                .from('moderation_appeals')
                .select('id, status, dispute_reason, admin_response, created_at')
                .eq('post_id', postId)
                .order('created_at', { ascending: false })
                .limit(1)
                .single()

            console.log('RejectionBanner - Appeal fetch:', { postId, data, error })
            setExistingAppeal(data)

            // Get total appeal count for this post
            const { count } = await supabase
                .from('moderation_appeals')
                .select('*', { count: 'exact', head: true })
                .eq('post_id', postId)

            setAppealCount(count || 0)
            setLoading(false)
        }
        fetchAppealData()
    }, [postId, supabase, approvalStatus, isAuthor])

    // Only render for rejected posts and for the author
    if (approvalStatus !== 'rejected' || !isAuthor) {
        return null
    }

    const handleSubmitAppeal = async () => {
        if (appealCount >= MAX_APPEALS) {
            showToast('You have reached the maximum number of appeals for this content.', 'error')
            return
        }

        if (!appealReason.trim()) {
            showToast('Please provide a reason for your appeal.', 'error')
            return
        }

        setSubmitting(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error('Not authenticated')

            const { error } = await supabase
                .from('moderation_appeals')
                .insert({
                    post_id: postId,
                    user_id: user.id,
                    dispute_reason: appealReason.trim()
                })

            if (error) {
                console.error('Appeal insert error:', error.message, error.code, error.details)
                throw new Error(error.message || 'Failed to insert appeal')
            }

            showToast('Your appeal has been submitted. You will be notified when it\'s reviewed.', 'success')
            setAppealDialogOpen(false)
            setAppealReason('')

            // Refresh appeal status
            const { data } = await supabase
                .from('moderation_appeals')
                .select('id, status, dispute_reason, admin_response, created_at')
                .eq('post_id', postId)
                .order('created_at', { ascending: false })
                .limit(1)
                .single()
            setExistingAppeal(data)
        } catch (error: any) {
            console.error('Error submitting appeal:', error.message || error)
            showToast(error.message || 'Failed to submit appeal. Please try again.', 'error')
        } finally {
            setSubmitting(false)
        }
    }

    const getAppealStatusBadge = (status: string) => {
        const badges = {
            pending: { icon: Clock, className: 'text-yellow-600 bg-yellow-100 dark:bg-yellow-900/30', label: 'Under Review' },
            approved: { icon: CheckCircle, className: 'text-green-600 bg-green-100 dark:bg-green-900/30', label: 'Approved' },
            rejected: { icon: AlertTriangle, className: 'text-red-600 bg-red-100 dark:bg-red-900/30', label: 'Denied' },
            revision_requested: { icon: AlertTriangle, className: 'text-blue-600 bg-blue-100 dark:bg-blue-900/30', label: 'Changes Required' }
        }
        const badge = badges[status as keyof typeof badges] || badges.pending
        const Icon = badge.icon
        return (
            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-medium ${badge.className}`}>
                <Icon className="w-4 h-4" />
                {badge.label}
            </span>
        )
    }

    return (
        <>
            <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl p-5 mb-6">
                <div className="flex items-start gap-4">
                    <div className="flex-shrink-0 p-2 bg-red-100 dark:bg-red-900/40 rounded-lg">
                        <AlertTriangle className="w-6 h-6 text-red-600 dark:text-red-400" />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-lg font-semibold text-red-900 dark:text-red-200 mb-1">
                            This post has been rejected
                        </h3>
                        {rejectionReason && (
                            <p className="text-red-700 dark:text-red-300 mb-4">
                                <strong>Reason:</strong> {rejectionReason}
                            </p>
                        )}

                        {/* Appeal Status */}
                        {loading ? (
                            <div className="flex items-center gap-2 text-sm text-red-600 dark:text-red-400">
                                <Loader2 className="w-4 h-4 animate-spin" />
                                Checking appeal status...
                            </div>
                        ) : existingAppeal && existingAppeal.status !== 'approved' ? (
                            // Show appeal status only if pending or rejected (not approved, as that's from a previous cycle)
                            <div className="bg-white dark:bg-dark-surface border border-red-200 dark:border-dark-border rounded-lg p-4 space-y-3">
                                <div className="flex items-center justify-between">
                                    <span className="text-sm font-medium text-text dark:text-dark-text">Appeal Status</span>
                                    {getAppealStatusBadge(existingAppeal.status)}
                                </div>
                                <p className="text-sm text-text-light dark:text-dark-text-muted">
                                    <strong>Your appeal:</strong> {existingAppeal.dispute_reason}
                                </p>
                                {existingAppeal.admin_response && (
                                    <p className="text-sm text-text-light dark:text-dark-text-muted border-t border-gray-100 dark:border-dark-border pt-3">
                                        <strong>Admin response:</strong> {existingAppeal.admin_response}
                                    </p>
                                )}
                                {existingAppeal.status === 'rejected' && (
                                    appealCount >= MAX_APPEALS ? (
                                        <p className="text-sm text-red-600 dark:text-red-400 mt-2">
                                            You have used all {MAX_APPEALS} appeals for this content.
                                        </p>
                                    ) : (
                                        <div className="flex items-center gap-3 mt-2">
                                            <Button
                                                onClick={() => setAppealDialogOpen(true)}
                                                variant="outline"
                                                size="sm"
                                                className="border-red-300 dark:border-red-700 text-red-700 dark:text-red-300 hover:bg-red-100 dark:hover:bg-red-900/30"
                                            >
                                                <Send className="w-4 h-4 mr-2" />
                                                Submit New Appeal
                                            </Button>
                                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                {MAX_APPEALS - appealCount} appeal{MAX_APPEALS - appealCount !== 1 ? 's' : ''} remaining
                                            </span>
                                        </div>
                                    )
                                )}
                                {existingAppeal.status === 'revision_requested' && (
                                    <div className="flex items-center gap-3 mt-2">
                                        <a
                                            href={contentType === 'event' ? `/events/${postId}/edit` : `/editor?edit=${postId}`}
                                            className="inline-flex items-center px-4 py-2 rounded-lg text-sm font-medium bg-blue-600 hover:bg-blue-700 text-white transition-colors"
                                        >
                                            Edit {contentType === 'event' ? 'Event' : 'Post'}
                                        </a>
                                        <span className="text-xs text-text-light dark:text-dark-text-muted">
                                            Make the requested changes and resubmit
                                        </span>
                                    </div>
                                )}
                            </div>
                        ) : (
                            // No relevant appeal (new rejection or previous appeal was approved before re-rejection)
                            appealCount >= MAX_APPEALS ? (
                                <p className="text-sm text-red-600 dark:text-red-400">
                                    You have used all {MAX_APPEALS} appeals for this content.
                                </p>
                            ) : (
                                <div className="flex items-center gap-3">
                                    <Button
                                        onClick={() => setAppealDialogOpen(true)}
                                        variant="outline"
                                        className="border-red-300 dark:border-red-700 text-red-700 dark:text-red-300 hover:bg-red-100 dark:hover:bg-red-900/30"
                                    >
                                        <Send className="w-4 h-4 mr-2" />
                                        Submit an Appeal
                                    </Button>
                                    <span className="text-xs text-text-light dark:text-dark-text-muted">
                                        {MAX_APPEALS - appealCount} appeal{MAX_APPEALS - appealCount !== 1 ? 's' : ''} remaining
                                    </span>
                                </div>
                            )
                        )}
                    </div>
                </div>
            </div>

            {/* Appeal Dialog */}
            <Dialog open={appealDialogOpen} onOpenChange={setAppealDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Appeal Rejection</DialogTitle>
                        <DialogDescription>
                            Explain why you believe &quot;{postTitle}&quot; should not have been rejected.
                            Your appeal will be reviewed by our moderation team.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        {rejectionReason && (
                            <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-3">
                                <p className="text-sm text-red-700 dark:text-red-300">
                                    <strong>Rejection reason:</strong> {rejectionReason}
                                </p>
                            </div>
                        )}
                        <div className="space-y-2">
                            <Label htmlFor="appeal-reason" className="text-text dark:text-dark-text font-medium">
                                Your Appeal <span className="text-red-500">*</span>
                            </Label>
                            <textarea
                                id="appeal-reason"
                                value={appealReason}
                                onChange={(e) => setAppealReason(e.target.value)}
                                placeholder="Explain why this rejection should be reconsidered..."
                                rows={5}
                                className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder:text-text-light dark:placeholder:text-dark-text-muted focus:outline-none focus:ring-2 focus:ring-primary resize-none"
                            />
                            <p className="text-xs text-text-light dark:text-dark-text-muted">
                                Be specific and respectful. Provide any context that supports your case.
                            </p>
                        </div>
                    </div>
                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button variant="outline" onClick={() => setAppealDialogOpen(false)} disabled={submitting}>
                            Cancel
                        </Button>
                        <Button
                            onClick={handleSubmitAppeal}
                            disabled={submitting || !appealReason.trim()}
                        >
                            {submitting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Send className="w-4 h-4 mr-2" />}
                            Submit Appeal
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </>
    )
}

'use client'

import { useState } from 'react'
import { MessageSquareMore } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { useRouter } from 'next/navigation'
import { useTranslations } from 'next-intl'

interface RequestClarificationButtonProps {
    postId: string
    authorId: string
    currentUserId?: string
    locale?: string
}

export function RequestClarificationButton({
    postId,
    authorId,
    currentUserId,
    locale = 'en'
}: RequestClarificationButtonProps) {
    const router = useRouter()
    const t = useTranslations('Correspondence')

    // Don't show if user is the author or not logged in
    if (!currentUserId || currentUserId === authorId) {
        return null
    }

    const handleClick = () => {
        router.push(`/${locale}/correspondence/compose?post=${postId}`)
    }

    return (
        <Button
            variant="outline"
            className="gap-2"
            onClick={handleClick}
        >
            <MessageSquareMore className="w-4 h-4" />
            {t('requestClarification')}
        </Button>
    )
}

'use client'

import { Link } from '@/navigation'
import { useTranslations } from 'next-intl'
import Image from 'next/image'
import { FileText, Download, Calendar, Database, FileType, Wrench, Film, FileSpreadsheet, Link2, Clock, PenTool } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'
import { TagChip } from './TagChip'
import { cn, getInitials, getAvatarGradient, inferResourceType } from '@/lib/utils'
import { useDateFormatter } from '@/hooks/useDateFormatter'

interface ResourceMetadata {
    url: string
    size: number
    mime_type: string
    original_name: string
    downloads: number
    license?: string
    resource_type?: 'dataset' | 'paper' | 'tool' | 'media' | 'template' | 'design'
}

interface ResourcePost {
    id: string
    title: string
    content: string
    created_at: string
    author?: {
        id?: string
        name?: string | null
        email?: string | null
        avatar_url?: string | null
    } | null
    author_id?: string
    tags?: string[]
    metadata: ResourceMetadata
    linked_posts_count?: number
}

interface ResourceCardProps {
    resource: ResourcePost
    preCalculatedType?: string
}

const RESOURCE_TYPE_CONFIG = {
    dataset: { icon: Database, label: 'Dataset', color: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' },
    paper: { icon: FileType, label: 'Paper', color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' },
    tool: { icon: Wrench, label: 'Tool', color: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400' },
    media: { icon: Film, label: 'Media', color: 'bg-pink-100 text-pink-700 dark:bg-pink-900/30 dark:text-pink-400' },
    template: { icon: FileSpreadsheet, label: 'Template', color: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400' },
    design: { icon: PenTool, label: 'Design', color: 'bg-cyan-100 text-cyan-700 dark:bg-cyan-900/30 dark:text-cyan-400' },
    document: { icon: FileText, label: 'Resource', color: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-400' },
}

export function ResourceCard({ resource, preCalculatedType }: ResourceCardProps) {
    const formatSize = (bytes: number) => {
        if (typeof bytes !== 'number' || bytes <= 0) return null
        const k = 1024
        const sizes = ['B', 'KB', 'MB', 'GB']
        const i = Math.floor(Math.log(bytes) / Math.log(k))
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
    }

    const displayAuthor = resource.author?.name || resource.author?.email?.split('@')[0] || 'Anonymous'
    const metadata = resource.metadata || {}

    // Prioritize pre-calculated type from server, then fallback to client inference or default
    const resourceType = (preCalculatedType?.toLowerCase() as keyof typeof RESOURCE_TYPE_CONFIG) ||
        (metadata.resource_type?.toLowerCase() as keyof typeof RESOURCE_TYPE_CONFIG) ||
        (inferResourceType(metadata.mime_type, metadata.original_name, resource.title) as keyof typeof RESOURCE_TYPE_CONFIG) ||
        'document'

    const typeConfig = RESOURCE_TYPE_CONFIG[resourceType]
    const TypeIcon = typeConfig?.icon || FileText

    const sizeDisplay = formatSize(metadata.size)

    const { formatDate } = useDateFormatter()

    const t = useTranslations('Common')
    const tLicenses = useTranslations('Licenses')

    return (
        <div className="card hover:border-primary/50 transition-colors group p-4 sm:p-6">
            {/* Mobile Layout */}
            <div className="flex flex-col gap-4 sm:hidden">
                {/* Top row: Icon and Badges */}
                <div className="flex items-start justify-between gap-3">
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center flex-shrink-0 ${typeConfig ? typeConfig.color : 'bg-primary/10 dark:bg-primary/20 text-primary'
                        }`}>
                        <TypeIcon className="w-6 h-6" />
                    </div>
                    <div className="flex items-center gap-2 flex-wrap justify-end">
                        {typeConfig && (
                            <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${typeConfig.color}`}>
                                {typeConfig.label}
                            </span>
                        )}
                        {sizeDisplay && (
                            <span className="text-[10px] font-mono font-bold bg-primary/5 dark:bg-primary/20 border border-primary/10 dark:border-primary/30 px-2 py-0.5 rounded text-primary dark:text-secondary-light">
                                {sizeDisplay}
                            </span>
                        )}
                    </div>
                </div>

                {/* Title - full width, no truncation */}
                <Link href={`/resources/${resource.id}`} className="group-hover:text-primary transition-colors">
                    <h3 className="text-lg font-bold text-text dark:text-dark-text leading-snug">
                        {resource.title}
                    </h3>
                </Link>

                {/* Description */}
                <p className="text-text-light dark:text-dark-text-muted line-clamp-2 text-sm">
                    {resource.content}
                </p>

                {/* Tags - horizontal scroll on mobile */}
                {resource.tags && resource.tags.length > 0 && (
                    <div className="flex flex-wrap gap-1.5">
                        {resource.tags.map(tag => (
                            <TagChip key={tag} tag={tag} size="sm" />
                        ))}
                    </div>
                )}

                {/* Footer - stacked on mobile */}
                <div className="flex flex-col gap-3 text-sm text-text-light dark:text-dark-text-muted border-t border-gray-100 dark:border-dark-border pt-4">
                    {/* Author and Date */}
                    <div className="flex items-center gap-3 flex-wrap">
                        <div className="flex items-center gap-2">
                            {resource.author?.avatar_url ? (
                                <Image
                                    src={resource.author.avatar_url}
                                    alt={displayAuthor}
                                    width={20}
                                    height={20}
                                    className="w-5 h-5 rounded-full object-cover"
                                />
                            ) : (
                                <div className={cn(
                                    'w-5 h-5 rounded-full flex items-center justify-center text-[9px] font-medium text-white',
                                    getAvatarGradient(resource.author?.id || undefined)
                                )}>
                                    {getInitials(resource.author?.name || undefined)}
                                </div>
                            )}
                            <span className="text-xs">{displayAuthor}</span>
                        </div>

                        <span className="text-text-muted/50">┬╖</span>

                        <div className="flex items-center gap-1 text-xs">
                            <Clock className="w-3 h-3" aria-hidden="true" />
                            <span>{formatDate(resource.created_at, 'distance')}</span>
                        </div>
                    </div>

                    {/* License and Downloads */}
                    <div className="flex items-center justify-between">
                        {metadata.license && (
                            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-secondary/10 dark:bg-secondary/20 text-secondary-dark dark:text-secondary-light border border-secondary/20 dark:border-secondary/40 text-[10px] font-bold uppercase tracking-tight">
                                <span>{tLicenses(metadata.license.replace(/\./g, '_'))}</span>
                            </div>
                        )}
                        <div className="flex items-center gap-1.5 text-primary dark:text-secondary-light font-bold text-[10px] uppercase tracking-wider">
                            <Download className="w-3.5 h-3.5" />
                            <span>{metadata.downloads || 0} {t('downloads')}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Desktop Layout */}
            <div className="hidden sm:flex gap-6">
                <div className="flex-shrink-0">
                    <div className={`w-16 h-16 rounded-lg flex items-center justify-center ${typeConfig ? typeConfig.color : 'bg-primary/10 dark:bg-primary/20 text-primary'
                        }`}>
                        <TypeIcon className="w-8 h-8" />
                    </div>
                </div>

                <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-4 mb-2">
                        <div className="flex items-center gap-3 min-w-0">
                            <Link href={`/resources/${resource.id}`} className="group-hover:text-primary transition-colors min-w-0">
                                <h3 className="text-xl font-bold text-text dark:text-dark-text truncate" title={resource.title}>
                                    {resource.title}
                                </h3>
                            </Link>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                            {typeConfig && (
                                <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${typeConfig.color}`}>
                                    {typeConfig.label}
                                </span>
                            )}
                            {sizeDisplay && (
                                <span className="text-[10px] font-mono font-bold bg-primary/5 dark:bg-primary/20 border border-primary/10 dark:border-primary/30 px-2 py-1 rounded text-primary dark:text-secondary-light transition-colors">
                                    {sizeDisplay}
                                </span>
                            )}
                        </div>
                    </div>

                    <p className="text-text-light dark:text-dark-text-muted line-clamp-2 mb-4 text-sm">
                        {resource.content}
                    </p>

                    <div className="flex flex-wrap gap-2 mb-4">
                        {resource.tags?.map(tag => (
                            <TagChip key={tag} tag={tag} size="sm" />
                        ))}
                    </div>

                    <div className="flex items-center justify-between text-sm text-text-light dark:text-dark-text-muted border-t border-gray-100 dark:border-dark-border pt-4">
                        <div className="flex items-center gap-3 flex-wrap">
                            <div className="flex items-center gap-2">
                                {resource.author?.avatar_url ? (
                                    <Image
                                        src={resource.author.avatar_url}
                                        alt={displayAuthor}
                                        width={24}
                                        height={24}
