                                        getAvatarGradient(resource.author?.id || undefined)
                                    )}>
                                        {getInitials(resource.author?.name || undefined)}
                                    </div>
                                )}
                                <span className="hover:text-primary dark:hover:text-accent-light transition-colors whitespace-nowrap">
                                    {displayAuthor}
