'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { Button } from '@/components/ui/button'
import { CheckCircle, HelpCircle, XCircle, Clock } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface RsvpButtonProps {
    eventId: string
    initialStatus?: 'going' | 'maybe' | 'not_going' | null
    onRsvpChange?: (status: string) => void
    eventDate?: string // ISO date string for the event start time
}

export function RsvpButton({ eventId, initialStatus, onRsvpChange, eventDate }: RsvpButtonProps) {
    const [status, setStatus] = useState(initialStatus)
    const [loading, setLoading] = useState(false)
    const supabase = createClient()
    const { showToast } = useToast()
    const t = useTranslations('RSVP')

    // Check if event has passed
    const isPastEvent = eventDate ? new Date(eventDate) < new Date() : false

    const handleRsvp = async (newStatus: 'going' | 'maybe' | 'not_going') => {
        if (loading || isPastEvent) return
        setLoading(true)

        try {
            const { data: { user } } = await supabase.auth.getUser()

            if (!user) {
                showToast('Please sign in to RSVP.', 'error')
                return
            }

            // If clicking same status, remove RSVP (toggle off)
            if (status === newStatus) {
                const { error } = await supabase
                    .from('event_rsvps')
                    .delete()
                    .eq('event_id', eventId)
                    .eq('user_id', user.id)

                if (error) throw error
                setStatus(null)
                onRsvpChange?.('removed')
            } else {
                // Upsert new status
                const { error } = await supabase
                    .from('event_rsvps')
                    .upsert({
                        event_id: eventId,
                        user_id: user.id,
                        status: newStatus
                    }, {
                        onConflict: 'event_id, user_id'
                    })

                if (error) throw error
                setStatus(newStatus)
                onRsvpChange?.(newStatus)
            }

        } catch (error: any) {
            console.error('RSVP error:', error.message || error)
            showToast('Failed to update RSVP. ' + (error.message || ''), 'error')
        } finally {
            setLoading(false)
        }
    }

    // Show "Event has ended" message for past events
    if (isPastEvent) {
        return (
            <div className="flex items-center justify-center gap-2 w-full py-2 px-4 rounded-lg bg-gray-100 dark:bg-dark-surface text-gray-500 dark:text-gray-400 text-sm">
                <Clock className="w-4 h-4" />
                <span>{t('eventEnded')}</span>
            </div>
        )
    }

    return (
        <div className="flex gap-2 w-full">
            <Button
                variant="outline"
                size="sm"
                onClick={() => handleRsvp('going')}
                disabled={loading}
                className={cn(
                    "relative overflow-hidden transition-all duration-300 border flex-1 whitespace-nowrap",
                    status === 'going'
                        ? "bg-emerald-50 text-emerald-600 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-800"
                        : "hover:bg-emerald-50 hover:text-emerald-600 dark:hover:bg-emerald-950/20 dark:hover:text-emerald-400 dark:hover:border-emerald-800/50"
                )}
            >
                <CheckCircle className={cn(
                    "w-4 h-4 mr-1.5 flex-shrink-0 transition-transform",
                    status === 'going' && "scale-110"
                )} />
                <span className="font-medium">{t('going')}</span>
                {status === 'going' && (
                    <span className="absolute inset-0 border-2 border-emerald-500/50 rounded-md pointer-events-none" />
                )}
            </Button>

            <Button
                variant="outline"
                size="sm"
                onClick={() => handleRsvp('maybe')}
                disabled={loading}
                className={cn(
                    "relative overflow-hidden transition-all duration-300 border flex-1 whitespace-nowrap",
                    status === 'maybe'
                        ? "bg-amber-50 text-amber-600 border-amber-200 dark:bg-amber-950/30 dark:text-amber-400 dark:border-amber-800"
                        : "hover:bg-amber-50 hover:text-amber-600 dark:hover:bg-amber-950/20 dark:hover:text-amber-400 dark:hover:border-amber-800/50"
                )}
            >
                <HelpCircle className={cn(
                    "w-4 h-4 mr-1.5 flex-shrink-0 transition-transform",
                    status === 'maybe' && "scale-110"
                )} />
                <span className="font-medium">{t('maybe')}</span>
                {status === 'maybe' && (
                    <span className="absolute inset-0 border-2 border-amber-500/50 rounded-md pointer-events-none" />
                )}
            </Button>

            <Button
                variant="outline"
                size="sm"
                onClick={() => handleRsvp('not_going')}
                disabled={loading}
                className={cn(
                    "relative overflow-hidden transition-all duration-300 border flex-1 whitespace-nowrap",
                    status === 'not_going'
                        ? "bg-rose-50 text-rose-600 border-rose-200 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-800"
                        : "hover:bg-rose-50 hover:text-rose-600 dark:hover:bg-rose-950/20 dark:hover:text-rose-400 dark:hover:border-rose-800/50"
                )}
            >
                <XCircle className={cn(
                    "w-4 h-4 mr-1.5 flex-shrink-0 transition-transform",
                    status === 'not_going' && "scale-110"
                )} />
                <span className="font-medium">{t('cantGo')}</span>
                {status === 'not_going' && (
                    <span className="absolute inset-0 border-2 border-rose-500/50 rounded-md pointer-events-none" />
                )}
            </Button>
        </div>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import {
    Bookmark, Globe, Database, Calendar, ExternalLink, Trash2,
    Clock, AlertTriangle, Search, SortAsc, SortDesc, Filter
} from 'lucide-react'
import { CopyCitationButton } from '@/components/CopyCitationButton'
import { useTranslations } from 'next-intl'
import { useDateFormatter } from '@/hooks/useDateFormatter'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"

interface SavedPost {
    id: string
    title: string
    content?: string
    tags?: string[]
    created_at: string
    author?: { id: string; name: string; email?: string }
    bookmark_id: string
}

interface SavedReference {
    id: string
    title: string
    url: string
    snippet?: string
    source?: string
    citation?: string
    created_at: string
}

interface SavedEvent {
    id: string
    title: string
    event_date?: string
    location?: string
    description?: string
    created_at: string
    bookmark_id: string
}

interface SavedItemsManagerProps {
    posts: SavedPost[]
    references: SavedReference[]
    events?: SavedEvent[]
}

type ItemType = 'all' | 'posts' | 'events' | 'web'
type SortOrder = 'newest' | 'oldest' | 'alphabetical'

export function SavedItemsManager({ posts, references, events = [] }: SavedItemsManagerProps) {
    const t = useTranslations('Saved')
    const tCommon = useTranslations('Common')
    const { formatDate } = useDateFormatter()
    const [activeFilter, setActiveFilter] = useState<ItemType>('all')
    const [sortOrder, setSortOrder] = useState<SortOrder>('newest')
    const [localPosts, setLocalPosts] = useState(posts)
    const [localReferences, setLocalReferences] = useState(references)
    const [localEvents, setLocalEvents] = useState(events)
    const [deleting, setDeleting] = useState<string | null>(null)

    // Remove a bookmarked post
    const removePost = async (bookmarkId: string) => {
        setDeleting(bookmarkId)
        try {
            const res = await fetch(`/api/bookmarks?id=${bookmarkId}`, { method: 'DELETE' })
            if (res.ok) {
                setLocalPosts(prev => prev.filter(p => p.bookmark_id !== bookmarkId))
            }
        } catch (error) {
            console.error('Error removing post:', error)
        } finally {
            setDeleting(null)
        }
    }

    // Remove a web reference
    const removeReference = async (id: string) => {
        setDeleting(id)
        try {
            const res = await fetch(`/api/saved-references?id=${id}`, { method: 'DELETE' })
            if (res.ok) {
                setLocalReferences(prev => prev.filter(r => r.id !== id))
            }
        } catch (error) {
            console.error('Error removing reference:', error)
        } finally {
            setDeleting(null)
        }
    }

    // Remove an event bookmark
    const removeEvent = async (bookmarkId: string) => {
        setDeleting(bookmarkId)
        try {
            const res = await fetch(`/api/bookmarks?id=${bookmarkId}`, { method: 'DELETE' })
            if (res.ok) {
                setLocalEvents(prev => prev.filter(e => e.bookmark_id !== bookmarkId))
            }
        } catch (error) {
            console.error('Error removing event:', error)
        } finally {
            setDeleting(null)
        }
    }

    // Sort items by date or alphabetically
    const sortItems = <T extends { title: string; created_at: string }>(items: T[]): T[] => {
        return [...items].sort((a, b) => {
            if (sortOrder === 'alphabetical') {
                return a.title.localeCompare(b.title)
            }
            const dateA = new Date(a.created_at).getTime()
            const dateB = new Date(b.created_at).getTime()
            return sortOrder === 'newest' ? dateB - dateA : dateA - dateB
        })
    }

    // Get counts
    const counts = {
        all: localPosts.length + localReferences.length + localEvents.length,
        posts: localPosts.length,
        events: localEvents.length,
        web: localReferences.length
    }

    // Filter buttons configuration
    const filterButtons: { type: ItemType; icon: typeof Database; label: string; color: string }[] = [
        { type: 'all', icon: Bookmark, label: t('tabs.all'), color: 'gray' },
        { type: 'posts', icon: Database, label: t('tabs.posts'), color: 'primary' },
        { type: 'events', icon: Calendar, label: t('tabs.events'), color: 'purple' },
        { type: 'web', icon: Globe, label: t('tabs.web'), color: 'blue' }
    ]

    const getColorClasses = (color: string, isActive: boolean) => {
        if (!isActive) return 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
        switch (color) {
            case 'primary': return 'bg-primary/20 text-primary dark:bg-teal-800/50 dark:text-teal-300'
            case 'blue': return 'bg-blue-100 text-blue-600 dark:bg-blue-800/50 dark:text-blue-300'
            case 'purple': return 'bg-purple-100 text-purple-600 dark:bg-purple-800/50 dark:text-purple-300'
            default: return 'bg-gray-200 dark:bg-dark-surface text-gray-800 dark:text-white'
        }
    }

    return (
        <div>
            {/* Header with filters and sort */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 sm:gap-4 mb-6">
                {/* Type Filters - Horizontal scroll on mobile */}
                <div className="overflow-x-auto -mx-4 px-4 sm:mx-0 sm:px-0 sm:overflow-visible">
                    <div className="flex items-center gap-1 p-1 bg-gray-100 dark:bg-dark-border rounded-lg w-max sm:w-auto">
                        {filterButtons.map(({ type, icon: Icon, label, color }) => (
                            <button
                                key={type}
                                onClick={() => setActiveFilter(type)}
                                className={`flex items-center gap-1.5 px-2.5 sm:px-3 py-1.5 rounded-md text-xs sm:text-sm font-medium transition-colors whitespace-nowrap ${getColorClasses(color, activeFilter === type)}`}
                            >
                                <Icon className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                <span className="hidden xs:inline">{label}</span>
                                <span className={`text-xs px-1.5 py-0.5 rounded-full ${activeFilter === type ? 'bg-white/50 dark:bg-black/40 dark:text-white' : 'bg-gray-200 dark:bg-black/20 dark:text-white'}`}>
                                    {counts[type]}
                                </span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Sort dropdown */}
                <div className="flex flex-col sm:flex-row sm:items-center gap-1 sm:gap-2 flex-shrink-0">
                    <span className="hidden sm:block text-sm font-medium text-gray-600 dark:text-gray-300">{t('sort')}</span>
                    <Select value={sortOrder} onValueChange={(value) => setSortOrder(value as SortOrder)}>
                        <SelectTrigger className="w-full sm:w-[160px] bg-white dark:bg-dark-surface">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="newest">{t('newestFirst')}</SelectItem>
                            <SelectItem value="oldest">{t('oldestFirst')}</SelectItem>
                            <SelectItem value="alphabetical">{t('alphabetical')}</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* Items List */}
            <div className="space-y-4">
                {/* Posts */}
                {(activeFilter === 'all' || activeFilter === 'posts') && sortItems(localPosts).map((post) => (
                    <div
                        key={post.id}
                        className="bg-white dark:bg-dark-surface rounded-xl border border-primary/20 dark:border-primary/30 p-4 hover:shadow-md transition-all group"
                    >
                        <div className="flex items-start justify-between gap-4">
                            <div className="flex items-start gap-3 flex-1 min-w-0">
                                <div className="shrink-0 w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
                                    <Database className="w-4 h-4 text-primary" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <Link
                                            href={`/post/${post.id}`}
                                            className="font-medium text-gray-900 dark:text-gray-100 hover:text-primary transition-colors line-clamp-1"
                                        >
                                            {post.title}
                                        </Link>
                                        <span className="text-xs px-1.5 py-0.5 bg-teal-100 dark:bg-teal-900/50 text-teal-700 dark:text-teal-300 rounded font-medium">
                                            {t('types.post')}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-3 text-xs text-gray-500 dark:text-gray-400">
                                        {post.author?.name && <span>{post.author.name}</span>}
                                        <span className="flex items-center gap-1">
                                            <Clock className="w-3 h-3" />
                                            {t('savedOn', { date: formatDate(post.created_at, 'short') })}
                                        </span>
                                    </div>
                                </div>
                            </div>
                            <button
                                onClick={() => removePost(post.bookmark_id)}
                                disabled={deleting === post.bookmark_id}
                                className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors disabled:opacity-50"
                                title={t('removeFromSaved')}
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                ))}

                {/* Events */}
                {(activeFilter === 'all' || activeFilter === 'events') && sortItems(localEvents).map((event) => (
                    <div
                        key={event.id}
                        className="bg-white dark:bg-dark-surface rounded-xl border border-purple-200 dark:border-purple-900/30 p-4 hover:shadow-md transition-all group"
                    >
                        <div className="flex items-start justify-between gap-4">
                            <div className="flex items-start gap-3 flex-1 min-w-0">
                                <div className="shrink-0 w-8 h-8 rounded-lg bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center">
                                    <Calendar className="w-4 h-4 text-purple-500" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <Link
                                            href={`/events/${event.id}`}
                                            className="font-medium text-gray-900 dark:text-gray-100 hover:text-purple-600 transition-colors line-clamp-1"
                                        >
                                            {event.title}
                                        </Link>
                                        <span className="text-xs px-1.5 py-0.5 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded font-medium">
                                            {t('types.event')}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-3 text-xs text-gray-500 dark:text-gray-400">
                                        {event.event_date && <span>{formatDate(event.event_date, 'medium')}</span>}
                                        {event.location && <span>ΓÇó {event.location}</span>}
                                        <span className="flex items-center gap-1">
                                            <Clock className="w-3 h-3" />
                                            {t('savedOn', { date: formatDate(event.created_at, 'short') })}
                                        </span>
                                    </div>
                                </div>
                            </div>
                            <button
                                onClick={() => removeEvent(event.bookmark_id)}
                                disabled={deleting === event.bookmark_id}
                                className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors disabled:opacity-50"
                                title={t('removeFromSaved')}
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                ))}           {/* Web References */}
                {(activeFilter === 'all' || activeFilter === 'web') && sortItems(localReferences).map((ref) => (
                    <div
                        key={ref.id}
                        className="bg-white dark:bg-dark-surface rounded-xl border border-blue-100 dark:border-blue-900/30 p-4 hover:shadow-md transition-all group"
                    >
                        <div className="flex items-start justify-between gap-4">
                            <div className="flex items-start gap-3 flex-1 min-w-0">
                                <div className="shrink-0 w-8 h-8 rounded-lg bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center">
                                    <Globe className="w-4 h-4 text-blue-500" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <a
                                            href={ref.url}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="font-medium text-gray-900 dark:text-gray-100 hover:text-blue-600 transition-colors line-clamp-1"
                                        >
                                            {ref.title}
                                        </a>
                                        <span className="text-xs px-1.5 py-0.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded font-medium">
                                            {t('types.web')}
                                        </span>
                                        <span className="text-xs px-1.5 py-0.5 bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 rounded flex items-center gap-1">
                                            <AlertTriangle className="w-3 h-3" />
                                            {t('unassessed')}
                                        </span>
                                    </div>
                                    {ref.snippet && (
                                        <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-1 mb-1">{ref.snippet}</p>
                                    )}
                                    <div className="flex items-center gap-3 text-xs text-gray-500 dark:text-gray-400">
                                        {ref.source && <span className="flex items-center gap-1"><Globe className="w-3 h-3 text-blue-500" />{ref.source}</span>}
                                        <span className="flex items-center gap-1">
                                            <Clock className="w-3 h-3" />
                                            {t('savedOn', { date: formatDate(ref.created_at, 'short') })}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-2 mt-2">
                                        <a
                                            href={ref.url}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex items-center gap-1 text-xs text-gray-500 hover:text-blue-600 transition-colors"
                                        >
                                            <ExternalLink className="w-3 h-3" />
                                            {t('open')}
                                        </a>
                                        {ref.citation && <CopyCitationButton citation={ref.citation} />}
                                    </div>
                                </div>
                            </div>
                            <button
                                onClick={() => removeReference(ref.id)}
                                disabled={deleting === ref.id}
                                className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors disabled:opacity-50"
                                title={t('removeFromSaved')}
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                ))}

                {/* Empty State */}
                {counts[activeFilter] === 0 && (
                    <div className="text-center py-16">
                        <Bookmark className="w-12 h-12 mx-auto text-gray-300 dark:text-dark-border mb-4" />
                        <h2 className="text-lg font-medium text-gray-900 dark:text-gray-100 mb-2">
                            {t('empty.title', { type: t(`empty.${activeFilter}`) })}
                        </h2>
                        <p className="text-gray-500 dark:text-gray-400 mb-6">
                            {t(`empty.${activeFilter}Desc`)}
                        </p>
                        <Link href={activeFilter === 'web' ? '/research-lab/search' : '/feed'} className="btn btn-primary">
                            {activeFilter === 'web' ? t('empty.goToSearch') : t('empty.exploreContent')}
                        </Link>
                    </div>
                )}
            </div>
        </div >
    )
}

'use client'

import { useState } from 'react'
import {
    Settings,
    Bell,
    Palette,
    Eye,
    Lock,
    FileEdit,
    Sun,
    Moon,
    Monitor,
    Check,
    RotateCcw,
    Ticket,
    MessageSquarePlus,
    X,
    Shield
} from 'lucide-react'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { NumberInput } from "@/components/ui/NumberInput"
import { Button } from '@/components/ui/button'
import { usePreferences, type UserPreferences } from '@/contexts/PreferencesContext'
import { useToast } from '@/components/ui/toast'
import { InviteManager } from '@/components/InviteManager'
import { FeedbackSection } from '@/components/feedback'
import { useTranslations } from 'next-intl'
import { TwoFactorSetup } from '@/components/auth/TwoFactorSetup'

interface SettingsPageProps {
    user: {
        id: string
        email?: string
    }
}

export function SettingsPage({ user }: SettingsPageProps) {
    const { preferences, updatePreference, updateNestedPreference, resetToDefaults, loading } = usePreferences()
    const { showToast } = useToast()
    const t = useTranslations('Settings')
    const [activeSection, setActiveSection] = useState<'notifications' | 'appearance' | 'display' | 'privacy' | 'security' | 'editor' | 'invites' | 'feedback'>('appearance')

    const handleUpdate = async (section: keyof UserPreferences, key: string, value: any) => {
        try {
            // @ts-expect-error - Dynamic key access for settings
            await updateNestedPreference(section, key, value)
            showToast(t('saved'), 'success')
        } catch (error) {
            showToast(t('saveFailed') || 'Failed to save settings', 'error')
        }
    }

    const [showResetConfirm, setShowResetConfirm] = useState(false)

    const handleReset = async () => {
        try {
            await resetToDefaults()
            showToast(t('settingsReset'), 'success')
            setShowResetConfirm(false)
        } catch (error) {
            console.error('[SettingsPage] Error during handleReset:', error)
            showToast(t('resetFailed') || 'Failed to reset settings', 'error')
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <div className="animate-spin w-8 h-8 border-2 border-primary border-t-transparent rounded-full" />
            </div>
        )
    }

    const sections = [
        { id: 'appearance', label: t('appearance'), icon: Palette },
        { id: 'notifications', label: t('notifications'), icon: Bell },
        { id: 'display', label: t('displaySettings.title'), icon: Eye },
        { id: 'privacy', label: t('privacyTab'), icon: Lock },
        { id: 'security', label: t('security'), icon: Shield },
        { id: 'editor', label: t('editorSettings.title'), icon: FileEdit },
        { id: 'invites', label: t('invitesSection.title'), icon: Ticket },
        { id: 'feedback', label: t('feedbackSection.title'), icon: MessageSquarePlus },
    ] as const

    return (
        <div className="max-w-4xl mx-auto">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 sm:mb-8">
                <div className="flex items-center gap-3">
                    <Settings className="w-6 h-6 sm:w-8 sm:h-8 text-primary" />
                    <h1 className="text-xl sm:text-2xl font-display font-bold text-text dark:text-dark-text">
                        {t('title')}
                    </h1>
                </div>

                <div className="flex items-center gap-2 overflow-hidden px-1 py-1">
                    {showResetConfirm ? (
                        <div className="flex items-center gap-2 animate-in fade-in slide-in-from-right-4 duration-300">
                            <span className="text-xs sm:text-sm font-medium text-destructive dark:text-red-400 mr-1 sm:mr-2 whitespace-nowrap">
                                {t('confirmReset')}
                            </span>
                            <div className="flex items-center bg-gray-100 dark:bg-dark-surface rounded-lg p-1 border border-gray-200 dark:border-dark-border shadow-sm">
                                <Button
                                    variant="destructive"
                                    size="sm"
                                    onClick={handleReset}
                                    className="gap-1 sm:gap-2 h-7 sm:h-8 px-2 sm:px-3 rounded-md shadow-sm text-xs sm:text-sm"
                                >
                                    <Check className="w-3 h-3 sm:w-3.5 sm:h-3.5" />
                                    {t('confirm')}
                                </Button>
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => setShowResetConfirm(false)}
                                    className="h-7 sm:h-8 px-2 sm:px-3 rounded-md hover:bg-gray-200 dark:hover:bg-dark-bg transition-colors text-xs sm:text-sm"
                                >
                                    {t('cancel')}
                                </Button>
                            </div>
                        </div>
                    ) : (
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setShowResetConfirm(true)}
                            className="gap-1 sm:gap-2 hover:bg-destructive/5 hover:text-destructive hover:border-destructive transition-all duration-300 group text-xs sm:text-sm"
                        >
                            <RotateCcw className="w-3.5 h-3.5 sm:w-4 sm:h-4 group-hover:rotate-[-45deg] transition-transform" />
                            <span className="hidden sm:inline">{t('resetToDefaults')}</span>
                            <span className="sm:hidden">Reset</span>
                        </Button>
                    )}
                </div>
            </div>

            {/* Mobile Navigation - Horizontal scrollable tabs */}
            <div className="md:hidden mb-4">
                <div className="relative">
                    {/* Left fade indicator */}
                    <div className="absolute left-0 top-0 bottom-0 w-4 bg-gradient-to-r from-background dark:from-dark-bg to-transparent pointer-events-none z-10" />
                    {/* Right fade indicator */}
                    <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-background dark:from-dark-bg to-transparent pointer-events-none z-10" />
                    <div
                        className="overflow-x-auto scrollbar-hide touch-pan-x"
                        style={{ WebkitOverflowScrolling: 'touch' }}
                    >
                        <div className="flex gap-2 px-4 py-1" style={{ width: 'max-content' }}>
                            {sections.map(section => {
                                const Icon = section.icon
                                return (
                                    <button
                                        key={section.id}
                                        onClick={() => setActiveSection(section.id)}
                                        className={`flex items-center gap-1.5 px-3 py-2 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${activeSection === section.id
                                            ? 'bg-primary text-white'
                                            : 'text-text-light dark:text-dark-text-muted bg-gray-100 dark:bg-dark-surface hover:bg-gray-200 dark:hover:bg-dark-border'
                                            }`}
                                    >
                                        <Icon className="w-3.5 h-3.5" />
                                        {section.label}
                                    </button>
                                )
                            })}
                        </div>
                    </div>
                </div>
                {/* Scroll hint text */}
                <p className="text-[10px] text-text-light/60 dark:text-dark-text-muted/60 text-center mt-1">
                    ΓåÉ Swipe to see more ΓåÆ
                </p>
            </div>

            <div className="flex flex-col md:flex-row gap-4 md:gap-8">
                {/* Sidebar - Hidden on mobile */}
                <nav className="hidden md:block w-48 flex-shrink-0">
                    <ul className="space-y-1">
                        {sections.map(section => {
                            const Icon = section.icon
                            return (
                                <li key={section.id}>
                                    <button
                                        onClick={() => setActiveSection(section.id)}
                                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg text-left transition-colors ${activeSection === section.id
                                            ? 'bg-primary text-white'
                                            : 'text-text-light dark:text-dark-text-muted hover:bg-gray-100 dark:hover:bg-dark-surface'
                                            }`}
                                    >
                                        <Icon className="w-4 h-4" />
                                        {section.label}
                                    </button>
                                </li>
                            )
                        })}
                    </ul>
                </nav>

                {/* Content */}
                <div className="flex-1 card p-4 sm:p-6">
                    {/* Appearance */}
                    {activeSection === 'appearance' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('appearance')}
                            </h2>

                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-3">
                                    {t('theme.title')}
                                </label>
                                <div className="flex flex-col sm:flex-row gap-2 sm:gap-3">
                                    {[
                                        { value: 'light', label: t('theme.light'), icon: Sun },
                                        { value: 'dark', label: t('theme.dark'), icon: Moon },
                                        { value: 'system', label: t('theme.system'), icon: Monitor },
                                    ].map(option => {
                                        const Icon = option.icon
                                        const isSelected = preferences.theme === option.value
                                        return (
                                            <button
                                                key={option.value}
                                                onClick={() => updatePreference('theme', option.value as UserPreferences['theme'])}
                                                className={`flex-1 flex items-center justify-center gap-2 px-3 sm:px-4 py-2.5 sm:py-3 rounded-xl border-2 transition-all ${isSelected
                                                    ? 'border-primary bg-primary text-white shadow-sm'
                                                    : 'border-gray-200 dark:border-dark-border text-text dark:text-dark-text hover:border-primary/50 hover:bg-gray-50 dark:hover:bg-dark-bg'
                                                    }`}
                                            >
                                                <Icon className="w-4 h-4 sm:w-5 sm:h-5" />
                                                <span className="font-medium text-sm sm:text-base">{option.label}</span>
                                                {isSelected && <Check className="w-3.5 h-3.5 sm:w-4 sm:h-4" />}
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Notifications */}
                    {activeSection === 'notifications' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('notificationSettings.title')}
                            </h2>

                            <div className="space-y-4">
                                <h3 className="text-xs sm:text-sm font-medium text-text-light dark:text-dark-text-muted uppercase tracking-wide">
                                    {t('notificationSettings.emailNotifications')}
                                </h3>

                                <ToggleSetting
                                    label={t('notificationSettings.mentions')}
                                    description={t('notificationSettings.mentionsDesc')}
                                    checked={preferences.notifications.email_mentions}
                                    onChange={(v) => handleUpdate('notifications', 'email_mentions', v)}
                                />
                                <ToggleSetting
                                    label={t('notificationSettings.replies')}
                                    description={t('notificationSettings.repliesDesc')}
                                    checked={preferences.notifications.email_replies}
                                    onChange={(v) => handleUpdate('notifications', 'email_replies', v)}
                                />
                                <ToggleSetting
                                    label={t('notificationSettings.newFollowers')}
                                    description={t('notificationSettings.newFollowersDesc')}
                                    checked={preferences.notifications.email_follows}
                                    onChange={(v) => handleUpdate('notifications', 'email_follows', v)}
                                />

                                <div className="pt-4">
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        {t('notificationSettings.emailDigest')}
                                    </label>
                                    <Select
                                        value={preferences.notifications.email_digest}
                                        onValueChange={(value) => handleUpdate('notifications', 'email_digest', value)}
                                    >
                                        <SelectTrigger className="w-full bg-white dark:bg-dark-surface">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="never">{t('notificationSettings.never')}</SelectItem>
                                            <SelectItem value="daily">{t('notificationSettings.daily')}</SelectItem>
                                            <SelectItem value="weekly">{t('notificationSettings.weekly')}</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Display */}
                    {activeSection === 'display' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('displaySettings.title')}
                            </h2>

                            <ToggleSetting
                                label={t('displaySettings.compactMode')}
                                description={t('displaySettings.compactModeDesc')}
                                checked={preferences.display.compact_mode}
                                onChange={(v) => handleUpdate('display', 'compact_mode', v)}
                            />
                            <ToggleSetting
                                label={t('displaySettings.showAvatars')}
                                description={t('displaySettings.showAvatarsDesc')}
                                checked={preferences.display.show_avatars}
                                onChange={(v) => handleUpdate('display', 'show_avatars', v)}
                            />

                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                    {t('displaySettings.postsPerPage')}
                                </label>
                                <Select
                                    value={preferences.display.posts_per_page.toString()}
                                    onValueChange={(value) => handleUpdate('display', 'posts_per_page', parseInt(value))}
                                >
                                    <SelectTrigger className="w-full">
                                        <SelectValue placeholder={preferences.display.posts_per_page.toString()} />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="10">10</SelectItem>
                                        <SelectItem value="20">20</SelectItem>
                                        <SelectItem value="50">50</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                    {t('displaySettings.defaultSort')}
                                </label>
                                <Select
                                    value={preferences.display.default_sort}
                                    onValueChange={(value) => handleUpdate('display', 'default_sort', value)}
                                >
                                    <SelectTrigger className="w-full">
                                        <SelectValue placeholder={t(`displaySettings.${preferences.display.default_sort === 'recent' ? 'mostRecent' : preferences.display.default_sort === 'popular' ? 'mostPopular' : 'trending'}`)} />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="recent">{t('displaySettings.mostRecent')}</SelectItem>
                                        <SelectItem value="popular">{t('displaySettings.mostPopular')}</SelectItem>
                                        <SelectItem value="trending">{t('displaySettings.trending')}</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div className="pt-4 border-t border-gray-100 dark:border-dark-border">
                                <ToggleSetting
                                    label={t('displaySettings.guidedReadingMode')}
                                    description={t('displaySettings.guidedReadingModeDesc')}
                                    checked={preferences.display.guided_reading_mode}
                                    onChange={(v) => handleUpdate('display', 'guided_reading_mode', v)}
                                />
                            </div>

                            <div className="pt-4 border-t border-gray-100 dark:border-dark-border">
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                    {t('displaySettings.calendarSystem')}
                                </label>
                                <p className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted mb-3">
                                    {t('displaySettings.calendarSystemDesc')}
                                </p>
                                <div className="flex flex-col sm:flex-row gap-2 sm:gap-3">
                                    {[
                                        { value: 'hijri', label: t('displaySettings.hijri') },
                                        { value: 'gregorian', label: t('displaySettings.gregorian') },
                                    ].map(option => {
                                        const isSelected = preferences.calendar === option.value
                                        return (
                                            <button
                                                key={option.value}
                                                onClick={() => updatePreference('calendar', option.value as 'hijri' | 'gregorian')}
                                                className={`flex-1 flex items-center justify-center gap-2 px-3 sm:px-4 py-2.5 sm:py-3 rounded-xl border-2 transition-all ${isSelected
                                                    ? 'border-primary bg-primary text-white'
                                                    : 'border-gray-200 dark:border-dark-border text-text-light dark:text-dark-text hover:border-primary/50 hover:bg-gray-50 dark:hover:bg-dark-bg'
                                                    }`}
                                            >
                                                <span className="font-medium text-sm sm:text-base">{option.label}</span>
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Privacy */}
                    {activeSection === 'privacy' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('privacySectionSettings.title')}
                            </h2>

                            <ToggleSetting
                                label={t('privacySectionSettings.publicProfile')}
                                description={t('privacySectionSettings.publicProfileDesc')}
                                checked={preferences.privacy.show_profile_public}
                                onChange={(v) => handleUpdate('privacy', 'show_profile_public', v)}
                            />
                            <ToggleSetting
                                label={t('privacySectionSettings.showEmail')}
                                description={t('privacySectionSettings.showEmailDesc')}
                                checked={preferences.privacy.show_email}
                                onChange={(v) => handleUpdate('privacy', 'show_email', v)}
                            />
                            <ToggleSetting
                                label={t('privacySectionSettings.allowMessages')}
                                description={t('privacySectionSettings.allowMessagesDesc')}
                                checked={preferences.privacy.allow_messages}
                                onChange={(v) => handleUpdate('privacy', 'allow_messages', v)}
                            />
                        </div>
                    )}

                    {/* Security */}
                    {activeSection === 'security' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('security')}
                            </h2>
                            <p className="text-sm sm:text-base text-text-light dark:text-dark-text-muted mb-6">
                                {t('securityDescription')}
                            </p>
                            <TwoFactorSetup userId={user.id} />
                        </div>
                    )}

                    {/* Editor */}
                    {activeSection === 'editor' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('editorSettings.title')}
                            </h2>

                            <ToggleSetting
                                label={t('editorSettings.autosave')}
                                description={t('editorSettings.autosaveDesc')}
                                checked={preferences.editor.autosave}
                                onChange={(v) => handleUpdate('editor', 'autosave', v)}
                            />

                            {preferences.editor.autosave && (
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        {t('editorSettings.autosaveInterval')}
                                    </label>
                                    <NumberInput
                                        min={10}
                                        max={120}
                                        step={5}
                                        value={preferences.editor.autosave_interval}
                                        onChange={(val) => handleUpdate('editor', 'autosave_interval', val)}
                                        className="w-full sm:w-auto"
                                    />
                                </div>
                            )}

                            <ToggleSetting
                                label={t('editorSettings.spellcheck')}
                                description={t('editorSettings.spellcheckDesc')}
                                checked={preferences.editor.spellcheck}
                                onChange={(v) => handleUpdate('editor', 'spellcheck', v)}
                            />
                            <ToggleSetting
                                label={t('editorSettings.lineNumbers')}
                                description={t('editorSettings.lineNumbersDesc')}
                                checked={preferences.editor.line_numbers}
                                onChange={(v) => handleUpdate('editor', 'line_numbers', v)}
                            />
                        </div>
                    )}

                    {/* Invites */}
                    {activeSection === 'invites' && (
                        <div className="space-y-6">
                            <h2 className="text-lg sm:text-xl font-semibold text-text dark:text-dark-text mb-4">
                                {t('invitesSection.title')}
                            </h2>
                            <p className="text-sm sm:text-base text-text-light dark:text-dark-text-muted mb-6">
                                {t('invitesSection.description')}
                            </p>
                            <InviteManager />
                        </div>
                    )}

                    {/* Feedback */}
                    {activeSection === 'feedback' && (
                        <FeedbackSection />
                    )}
                </div>
            </div>
        </div>
    )
}

interface ToggleSettingProps {
    label: string
    description: string
    checked: boolean
    onChange: (checked: boolean) => void
}

function ToggleSetting({ label, description, checked, onChange }: ToggleSettingProps) {
    return (
        <div className="flex items-start sm:items-center justify-between gap-3 py-3 border-b border-gray-100 dark:border-dark-border last:border-0">
            <div className="flex-1 min-w-0">
                <p className="font-medium text-sm sm:text-base text-text dark:text-dark-text">{label}</p>
                <p className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">{description}</p>
            </div>
            <button
                role="switch"
                aria-checked={checked}
                onClick={() => onChange(!checked)}
                className={`relative flex-shrink-0 w-10 h-5 sm:w-11 sm:h-6 rounded-full transition-colors ${checked ? 'bg-primary' : 'bg-gray-300 dark:bg-gray-600'
                    }`}
            >
                <span
                    className={`absolute top-0.5 w-4 h-4 sm:w-5 sm:h-5 bg-white rounded-full shadow transition-transform ${checked ? 'translate-x-5.5 left-0.5' : 'translate-x-0.5 left-0'
                        }`}
                    style={{ transform: checked ? 'translateX(20px)' : 'translateX(2px)' }}
                />
            </button>
        </div>
    )
}

'use client'

import { cn } from '@/lib/utils'
import { CheckCircle, Award } from 'lucide-react'

interface SkillBadgeProps {
