                                    <span>ΓÇó</span>
                                    <span className="flex items-center gap-1">
                                        <TrendingUp className="w-3 h-3" />
                                        {post.vote_count}
                                    </span>
                                    <span>ΓÇó</span>
                                    <span className="flex items-center gap-1">
                                        <Clock className="w-3 h-3" />
