            {/* View All Link */}
            {posts.length > 0 && (
                <Link
                    href="/feed?sort=hot"
                    className="flex items-center justify-center gap-2 p-3 text-sm font-medium text-primary dark:text-secondary hover:bg-primary/5 dark:hover:bg-secondary/5 transition-colors border-t border-gray-100 dark:border-dark-border"
                >
                    {t('viewAll')}
                    <ChevronRight className="w-4 h-4" />
                </Link>
            )}
        </div>
    )
}

'use client'

import { CheckCircle, AlertTriangle, HelpCircle, Clock, Users, FileText, Link2 } from 'lucide-react'
import type { TrustProfile } from '@/types/advanced'

interface TrustProfileCardProps {
    profile: TrustProfile
    compact?: boolean
}

export function TrustProfileCard({ profile, compact = false }: TrustProfileCardProps) {
    const dimensions = [
        { key: 't1', label: 'Source', score: profile.t1_source_score, icon: Users },
        { key: 't2', label: 'Method', score: profile.t2_method_score, icon: FileText },
        { key: 't3', label: 'Proximity', score: profile.t3_proximity_score, icon: Link2 },
        { key: 't4', label: 'Temporal', score: profile.t4_temporal_score, icon: Clock },
        { key: 't5', label: 'Validation', score: profile.t5_validation_score, icon: CheckCircle },
    ]

    const avgScore = Math.round(
        (profile.t1_source_score + profile.t2_method_score + profile.t3_proximity_score +
            profile.t4_temporal_score + profile.t5_validation_score) / 5
    )

    if (compact) {
        return (
            <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${getScoreColor(avgScore)}`} />
                <span className="text-xs text-text-light">{profile.trust_summary || 'Trust profile available'}</span>
            </div>
        )
    }

    return (
        <div className="bg-white dark:bg-dark-card rounded-xl border border-gray-200 dark:border-dark-border p-4">
            <div className="flex items-center justify-between mb-4">
                <h4 className="font-medium flex items-center gap-2">
                    <span className={`w-3 h-3 rounded-full ${getScoreColor(avgScore)}`} />
                    Trust Profile
                </h4>
                <span className="text-sm text-text-light">
                    Overall: {avgScore}/100
                </span>
            </div>

            {/* Trust Summary */}
            {profile.trust_summary && (
                <p className="text-sm text-text-light mb-4 italic">
                    &quot;{profile.trust_summary}&quot;
                </p>
            )}

            {/* 5 Dimension Bars */}
            <div className="space-y-3">
                {dimensions.map(({ key, label, score, icon: Icon }) => (
                    <div key={key} className="space-y-1">
                        <div className="flex items-center justify-between text-sm">
                            <span className="flex items-center gap-1.5 text-text-light">
                                <Icon className="w-3.5 h-3.5" />
                                {label}
                            </span>
                            <span className={getScoreTextColor(score)}>{score}</span>
                        </div>
                        <div className="h-1.5 bg-gray-100 dark:bg-dark-border rounded-full overflow-hidden">
                            <div
                                className={`h-full rounded-full transition-all ${getBarColor(score)}`}
                                style={{ width: `${score}%` }}
                            />
                        </div>
                    </div>
                ))}
            </div>

            {/* Contradictions Warning */}
            {profile.t5_contradicting_count > 0 && (
                <div className="mt-4 p-3 bg-red-50 dark:bg-red-900/20 rounded-lg border border-red-200 dark:border-red-800">
                    <div className="flex items-start gap-2 text-sm text-red-700 dark:text-red-400">
                        <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
                        <div>
                            <span className="font-medium">Contradicted by {profile.t5_contradicting_count} source(s)</span>
                            {profile.t5_contradictions && profile.t5_contradictions.length > 0 && (
                                <p className="text-xs mt-1">{profile.t5_contradictions[0].detail}</p>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Corroboration Info */}
            {profile.t5_corroborating_count > 0 && (
                <div className="mt-3 flex items-center gap-2 text-sm text-green-600 dark:text-green-400">
                    <CheckCircle className="w-4 h-4" />
                    Corroborated by {profile.t5_corroborating_count} source(s)
                </div>
            )}

            {/* Time Sensitivity */}
            {profile.t4_is_time_sensitive && (
                <div className="mt-2 flex items-center gap-2 text-sm text-amber-600 dark:text-amber-400">
                    <Clock className="w-4 h-4" />
                    Time-sensitive data
                    {profile.t4_data_timestamp && (
                        <span className="text-text-light">
                            (from {new Date(profile.t4_data_timestamp).toLocaleDateString()})
                        </span>
                    )}
                </div>
            )}
        </div>
    )
}

function getScoreColor(score: number): string {
    if (score >= 80) return 'bg-green-500'
    if (score >= 60) return 'bg-blue-500'
    if (score >= 40) return 'bg-amber-500'
    return 'bg-red-500'
}

function getBarColor(score: number): string {
    if (score >= 80) return 'bg-green-500'
    if (score >= 60) return 'bg-blue-500'
    if (score >= 40) return 'bg-amber-500'
    return 'bg-red-500'
}

function getScoreTextColor(score: number): string {
    if (score >= 80) return 'text-green-600 dark:text-green-400 font-medium'
    if (score >= 60) return 'text-blue-600 dark:text-blue-400'
    if (score >= 40) return 'text-amber-600 dark:text-amber-400'
    return 'text-red-600 dark:text-red-400'
}

// Compact badge version
interface TrustBadgeProps {
    score: number
    size?: 'sm' | 'md'
}

export function TrustBadge({ score, size = 'md' }: TrustBadgeProps) {
    const getLabel = (s: number) => {
        if (s >= 80) return 'High Trust'
        if (s >= 60) return 'Medium Trust'
        if (s >= 40) return 'Low Trust'
        return 'Unverified'
    }

    // More subtle badge styles per design guidelines
    const getBadgeStyle = (s: number) => {
        if (s >= 80) return 'bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 border border-green-200 dark:border-green-800/50'
        if (s >= 60) return 'bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 border border-blue-200 dark:border-blue-800/50'
        if (s >= 40) return 'bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 border border-amber-200 dark:border-amber-800/50'
        return 'bg-gray-50 dark:bg-gray-800/50 text-gray-600 dark:text-gray-400 border border-gray-200 dark:border-gray-700'
    }

    const sizeClasses = size === 'sm'
        ? 'text-xs px-2 py-0.5 gap-1'
        : 'text-sm px-2.5 py-1 gap-1.5'

    return (
        <span className={`inline-flex items-center rounded-md font-medium ${sizeClasses} ${getBadgeStyle(score)}`}>
            <span className={`w-1.5 h-1.5 rounded-full ${getScoreColor(score)}`} />
            {getLabel(score)}
        </span>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Skeleton } from '@/components/ui/skeleton'
import {
    Flame,
    Award,
    Star,
    Zap,
    Trophy,
    CheckCircle,
    PenTool,
    Footprints
} from 'lucide-react'

interface UserStreak {
    currentStreak: number
    longestStreak: number
    lastPostDate: string | null
    isActiveToday: boolean
}

interface Badge {
    id: string
    name: string
    description: string
    icon_url: string
    awarded_at: string
}

const BADGE_ICONS: Record<string, React.ElementType> = {
    footprints: Footprints,
    pen_tool: PenTool,
    check_circle: CheckCircle,
    star: Star,
    verified: Award,
    trophy: Trophy,
    default: Award,
}

/**
 * Calculate streak from post dates
 */
function calculateStreak(postDates: Date[]): UserStreak {
    if (postDates.length === 0) {
        return {
            currentStreak: 0,
            longestStreak: 0,
            lastPostDate: null,
            isActiveToday: false,
        }
    }

    const today = new Date()
    today.setHours(0, 0, 0, 0)

    const sortedDates = postDates
        .map(d => {
            const date = new Date(d)
            date.setHours(0, 0, 0, 0)
            return date
        })
        .sort((a, b) => b.getTime() - a.getTime())

    // Get unique dates
    const uniqueDates = [...new Set(sortedDates.map(d => d.getTime()))]
        .map(t => new Date(t))
        .sort((a, b) => b.getTime() - a.getTime())

    if (uniqueDates.length === 0) {
        return {
            currentStreak: 0,
            longestStreak: 0,
            lastPostDate: null,
            isActiveToday: false,
        }
    }

    const lastPostDate = uniqueDates[0]
    const isActiveToday = lastPostDate.getTime() === today.getTime()
    const yesterday = new Date(today)
    yesterday.setDate(yesterday.getDate() - 1)

    // Calculate current streak
    let currentStreak = 0
    let checkDate = isActiveToday ? today : yesterday

    for (const date of uniqueDates) {
        if (date.getTime() === checkDate.getTime()) {
            currentStreak++
            checkDate = new Date(checkDate)
            checkDate.setDate(checkDate.getDate() - 1)
        } else if (date.getTime() < checkDate.getTime()) {
            break
        }
    }

    // Calculate longest streak
    let longestStreak = 0
    let tempStreak = 1

    for (let i = 0; i < uniqueDates.length - 1; i++) {
        const current = uniqueDates[i]
        const next = uniqueDates[i + 1]
        const diffDays = Math.round((current.getTime() - next.getTime()) / (1000 * 60 * 60 * 24))

        if (diffDays === 1) {
            tempStreak++
        } else {
            longestStreak = Math.max(longestStreak, tempStreak)
            tempStreak = 1
        }
    }
    longestStreak = Math.max(longestStreak, tempStreak)

    return {
        currentStreak,
        longestStreak,
        lastPostDate: lastPostDate.toISOString(),
        isActiveToday,
    }
}

export function UserStreakBadge({ userId }: { userId: string }) {
    const [streak, setStreak] = useState<UserStreak | null>(null)
    const [loading, setLoading] = useState(true)
    const supabase = createClient()

    useEffect(() => {
        const loadStreak = async () => {
            try {
                const thirtyDaysAgo = new Date()
                thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30)

                const { data: posts } = await supabase
                    .from('posts')
                    .select('created_at')
                    .eq('author_id', userId)
                    .eq('status', 'published')
                    .gte('created_at', thirtyDaysAgo.toISOString())
                    .order('created_at', { ascending: false })

                if (posts) {
                    const postDates = posts.map((p: any) => new Date(p.created_at))
                    setStreak(calculateStreak(postDates))
                }
            } catch (error) {
                console.error('Error loading streak:', error)
            } finally {
                setLoading(false)
            }
        }

        loadStreak()
    }, [userId, supabase])

    if (loading) {
        return <Skeleton className="w-16 h-6 rounded-full" />
    }

    if (!streak || streak.currentStreak === 0) {
        return null
    }

    return (
        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-md bg-gray-100 dark:bg-dark-surface border border-gray-200 dark:border-dark-border">
            <span className="text-xs text-text-light dark:text-dark-text-muted">Streak</span>
            <span className="text-sm font-medium text-text dark:text-dark-text">
                {streak.currentStreak}d
            </span>
        </div>
    )
}

export function UserBadgesDisplay({ userId, limit = 5 }: { userId: string; limit?: number }) {
    const [badges, setBadges] = useState<Badge[]>([])
    const [loading, setLoading] = useState(true)
    const supabase = createClient()

    useEffect(() => {
        const loadBadges = async () => {
            try {
                const { data } = await supabase
                    .from('user_badges')
                    .select(`
            awarded_at,
            badge:badges(id, name, description, icon_url)
          `)
                    .eq('user_id', userId)
                    .order('awarded_at', { ascending: false })
                    .limit(limit)

                if (data) {
                    setBadges(
                        data.map((item: any) => ({
                            id: item.badge.id,
                            name: item.badge.name,
                            description: item.badge.description,
                            icon_url: item.badge.icon_url,
                            awarded_at: item.awarded_at,
                        }))
                    )
                }
            } catch (error) {
                console.error('Error loading badges:', error)
            } finally {
                setLoading(false)
            }
        }

        loadBadges()
    }, [userId, supabase, limit])

    if (loading) {
        return (
            <div className="flex gap-2">
                {Array.from({ length: 3 }).map((_, i) => (
                    <Skeleton key={i} className="w-8 h-8 rounded-full" />
                ))}
            </div>
        )
    }

    if (badges.length === 0) {
        return null
    }

    return (
        <div className="flex flex-wrap gap-2">
            {badges.map((badge) => {
                const IconComponent = BADGE_ICONS[badge.icon_url] || BADGE_ICONS.default
                return (
                    <div
                        key={badge.id}
                        className="group relative inline-flex items-center justify-center w-7 h-7 rounded-md bg-gray-100 dark:bg-dark-surface border border-gray-200 dark:border-dark-border cursor-help transition-colors hover:border-gray-300 dark:hover:border-gray-600"
                        title={`${badge.name}: ${badge.description}`}
                    >
                        <IconComponent className="w-3.5 h-3.5 text-text-light dark:text-dark-text-muted" />

                        {/* Tooltip */}
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                            <div className="font-medium">{badge.name}</div>
                            <div className="text-gray-400 dark:text-gray-500">{badge.description}</div>
                        </div>
                    </div>
                )
            })}
        </div>
    )
}

/**
 * Combined streak and badges component for profile cards
 */
export function UserAchievements({ userId }: { userId: string }) {
    return (
        <div className="flex flex-wrap items-center gap-3">
            <UserStreakBadge userId={userId} />
            <UserBadgesDisplay userId={userId} />
        </div>
    )
}

/**
 * Streak encouragement banner
 */
export function StreakEncouragement({ userId }: { userId: string }) {
    const [streak, setStreak] = useState<UserStreak | null>(null)
    const supabase = createClient()

    useEffect(() => {
        const loadStreak = async () => {
            const thirtyDaysAgo = new Date()
            thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30)

            const { data: posts } = await supabase
                .from('posts')
                .select('created_at')
                .eq('author_id', userId)
                .eq('status', 'published')
                .gte('created_at', thirtyDaysAgo.toISOString())

            if (posts) {
                setStreak(calculateStreak(posts.map((p: any) => new Date(p.created_at))))
            }
        }

        loadStreak()
    }, [userId, supabase])

    if (!streak) return null

    if (streak.isActiveToday) {
        return (
            <div className="flex items-center gap-2 p-3 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg">
                <Zap className="w-5 h-5 text-green-500" />
                <span className="text-sm text-green-700 dark:text-green-300">
                    Great! You&apos;ve posted today. Keep your <strong>{streak.currentStreak}-day streak</strong> going!
                </span>
