'use client'

import { useState, useEffect, useMemo } from 'react'
import { Zap, Trophy, Target, ChevronRight, Loader2 } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { UserLevelBadge, getTierFromLevel } from './UserLevelBadge'
import { cn } from '@/lib/utils'
import Link from 'next/link'
import { useTranslations } from 'next-intl'

interface UserProgress {
    xp_points: number
    level: number
    current_level: {
        level: number
        name: string
        tier: string
        xp_required: number
        perks: string[]
        color: string
    }
    next_level: {
        level: number
        name: string
        tier: string
        xp_required: number
        perks: string[]
        color: string
    } | null
    xp_to_next_level: number
    progress_percentage: number
    achievements_unlocked: number
    total_achievements: number
}

interface UserProgressCardProps {
    userId: string
    compact?: boolean
}

export function UserProgressCard({ userId, compact = false }: UserProgressCardProps) {
    const [progress, setProgress] = useState<UserProgress | null>(null)
    const [loading, setLoading] = useState(true)
    const supabase = useMemo(() => createClient(), [])
    const t = useTranslations('Gamification')
    const tCommon = useTranslations('Common')

    useEffect(() => {
        const fetchProgress = async () => {
            const { data, error } = await supabase.rpc('get_user_progress', {
                p_user_id: userId
            })
            if (!error && data?.success) {
                setProgress(data)
            }
            setLoading(false)
        }
        fetchProgress()
    }, [userId, supabase])


    if (loading) {
        return (
            <div className={cn(
                "bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border",
                compact ? "p-4" : "p-6"
            )}>
                <div className="flex items-center justify-center py-8">
                    <Loader2 className="w-6 h-6 animate-spin text-primary" />
                </div>
            </div>
        )
    }

    if (!progress) return null

    const tier = getTierFromLevel(progress.level)

    // Compact version for sidebar/profile header
    if (compact) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                <div className="flex items-center justify-between mb-3">
                    <UserLevelBadge
                        level={progress.level}
                        tier={tier}
                        name={progress.current_level?.name}
                    />
                    <span className="text-xs text-text-light dark:text-dark-text-muted">
                        {progress.xp_points.toLocaleString()} XP
                    </span>
                </div>

                {/* Progress bar */}
                {progress.next_level && (
                    <div className="space-y-1">
                        <div className="h-2 bg-gray-100 dark:bg-dark-border rounded-full overflow-hidden">
                            <div
                                className={cn(
                                    "h-full rounded-full transition-all duration-500",
                                    tier === 'bronze' && "bg-gradient-to-r from-amber-500 to-amber-600",
                                    tier === 'silver' && "bg-gradient-to-r from-gray-400 to-gray-500",
                                    tier === 'gold' && "bg-gradient-to-r from-yellow-400 to-yellow-500",
                                    tier === 'platinum' && "bg-gradient-to-r from-purple-500 to-purple-600"
                                )}
                                style={{ width: `${Math.min(progress.progress_percentage, 100)}%` }}
                            />
                        </div>
                        <p className="text-xs text-text-light dark:text-dark-text-muted text-right">
                            {(progress.xp_to_next_level || 0).toLocaleString()} XP to Level {progress.next_level?.level}
                        </p>
                    </div>
                )}
            </div>
        )
    }

    // Full version
    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-dark-border flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <Zap className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                    <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wide">{t('yourProgress')}</h3>
                </div>
                <Link
                    href="/achievements"
                    className="flex items-center gap-1 text-sm text-primary hover:underline"
                >
                    {tCommon('viewAll')}
                    <ChevronRight className="w-4 h-4" />
                </Link>
            </div>

            {/* Level Section */}
            <div className="p-6 bg-gradient-to-br from-gray-50 to-white dark:from-dark-bg dark:to-dark-surface">
                <div className="flex items-center gap-4 mb-4">
                    <div className={cn(
                        "w-10 h-10 rounded-lg flex items-center justify-center",
                        tier === 'bronze' && "bg-gradient-to-br from-amber-400 to-amber-600",
                        tier === 'silver' && "bg-gradient-to-br from-gray-300 to-gray-500",
                        tier === 'gold' && "bg-gradient-to-br from-yellow-300 to-yellow-500",
                        tier === 'platinum' && "bg-gradient-to-br from-purple-400 to-purple-600"
                    )}>
                        <span className="text-lg font-bold text-white">{progress.level}</span>
                    </div>
                    <div>
                        <p className="font-semibold text-text dark:text-dark-text">
                            {progress.current_level?.name || `Level ${progress.level}`}
                        </p>
                        <p className="text-sm text-text-light dark:text-dark-text-muted capitalize">
                            {tier} Tier
                        </p>
                    </div>
                </div>

                {/* XP Progress */}
                {progress.next_level && (
                    <div className="space-y-2">
                        <div className="flex justify-between text-sm">
                            <span className="text-text dark:text-dark-text font-medium">
                                {progress.xp_points.toLocaleString()} XP
                            </span>
                            <span className="text-text-light dark:text-dark-text-muted">
                                {progress.next_level?.xp_required?.toLocaleString() || 'Max'} XP
                            </span>
                        </div>
                        <div className="h-3 bg-gray-200 dark:bg-dark-border rounded-full overflow-hidden">
                            <div
                                className={cn(
                                    "h-full rounded-full transition-all duration-700",
                                    tier === 'bronze' && "bg-gradient-to-r from-amber-400 to-amber-600",
                                    tier === 'silver' && "bg-gradient-to-r from-gray-300 to-gray-500",
                                    tier === 'gold' && "bg-gradient-to-r from-yellow-300 to-yellow-500",
                                    tier === 'platinum' && "bg-gradient-to-r from-purple-400 to-purple-600"
                                )}
                                style={{ width: `${Math.min(progress.progress_percentage, 100)}%` }}
                            />
                        </div>
                        <p className="text-xs text-center text-text-light dark:text-dark-text-muted">
                            {(progress.xp_to_next_level || 0).toLocaleString()} XP until {progress.next_level?.name}
                        </p>
                    </div>
                )}
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 divide-x divide-gray-100 dark:divide-dark-border border-t border-gray-100 dark:border-dark-border">
                <div className="p-4 text-center">
                    <div className="flex items-center justify-center gap-1 text-lg font-bold text-text dark:text-dark-text">
                        <Zap className="w-4 h-4 text-yellow-500" />
                        {progress.xp_points.toLocaleString()}
                    </div>
                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-1">{t('totalXp')}</p>
                </div>
                <div className="p-4 text-center">
                    <div className="flex items-center justify-center gap-1 text-lg font-bold text-text dark:text-dark-text">
                        <Trophy className="w-4 h-4 text-primary" />
                        {progress.achievements_unlocked}/{progress.total_achievements}
                    </div>
                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-1">{t('achievementsLabel')}</p>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { GraduationCap, Clock, CheckCircle, XCircle, User, Calendar, ChevronDown, ChevronUp, Loader2 } from 'lucide-react'
import Image from 'next/image'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface PromotionRequest {
    id: string
    user_id: string
    current_role: string
    requested_role: string
    reason: string
    status: 'pending' | 'approved' | 'rejected'
    admin_notes: string | null
    created_at: string
    reviewed_at: string | null
    user?: {
        id: string
        name: string
        email: string
        avatar_url: string | null
    }
}

export function AdminPromotionRequests() {
    const t = useTranslations('Promotion')
    const tCommon = useTranslations('Common')
    const tUser = useTranslations('UserManagement.roles')
    const [requests, setRequests] = useState<PromotionRequest[]>([])
    const [loading, setLoading] = useState(true)
    const [processingId, setProcessingId] = useState<string | null>(null)
    const [expandedId, setExpandedId] = useState<string | null>(null)
    const [adminNotes, setAdminNotes] = useState<Record<string, string>>({})
    const { showToast } = useToast()
    const supabase = useMemo(() => createClient(), [])

    const fetchRequests = useCallback(async () => {
        const { data, error } = await supabase
            .from('role_promotion_requests')
            .select(`
                *,
                user:users!user_id(id, name, email, avatar_url)
            `)
            .eq('status', 'pending')
            .order('created_at', { ascending: false })

        if (!error && data) {
            setRequests(data)
        }
        setLoading(false)
    }, [supabase])

    useEffect(() => {
        fetchRequests()
    }, [fetchRequests])


    const handleDecision = async (requestId: string, decision: 'approved' | 'rejected') => {
        setProcessingId(requestId)
        try {
            const { data, error } = await supabase.rpc('review_promotion_request', {
                p_request_id: requestId,
                p_decision: decision,
                p_admin_notes: adminNotes[requestId] || null
            })

            if (error) throw error

            if (data?.success) {
                showToast(t('requestProcessed', { decision: decision === 'approved' ? t('approve') : t('reject') }), 'success')
                fetchRequests()
            } else {
                throw new Error(data?.error || t('processError'))
            }
        } catch (error) {
            showToast(error instanceof Error ? error.message : t('processError'), 'error')
        } finally {
            setProcessingId(null)
        }
    }

    if (loading) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                <div className="animate-pulse space-y-4">
                    <div className="h-6 bg-gray-200 dark:bg-dark-border rounded w-48" />
                    <div className="h-32 bg-gray-200 dark:bg-dark-border rounded" />
                </div>
            </div>
        )
    }

    return (
        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-dark-border flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <GraduationCap className="w-5 h-5 text-primary" />
                    <h3 className="font-semibold text-text dark:text-dark-text">{t('rolePromotionRequests')}</h3>
                </div>
                {requests.length > 0 && (
                    <span className="px-2 py-1 bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-xs font-medium rounded-full">
                        {t('pendingCount', { count: requests.length })}
                    </span>
                )}
            </div>

            {/* Content */}
            <div className="divide-y divide-gray-100 dark:divide-dark-border">
                {requests.length === 0 ? (
                    <div className="p-8 text-center">
                        <CheckCircle className="w-8 h-8 text-green-500 mx-auto mb-2" />
                        <p className="text-text-light dark:text-dark-text-muted">{t('noPending')}</p>
                    </div>
                ) : (
                    requests.map((request) => (
                        <div key={request.id} className="p-4">
                            {/* Request Header */}
                            <div className="flex items-start justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-full bg-gray-100 dark:bg-dark-border flex items-center justify-center overflow-hidden">
                                        {request.user?.avatar_url ? (
                                            <Image
                                                src={request.user.avatar_url}
                                                alt={request.user.name}
                                                width={40}
                                                height={40}
                                                className="w-full h-full object-cover"
                                            />
                                        ) : (
                                            <User className="w-5 h-5 text-text-light" />
                                        )}
                                    </div>
                                    <div>
                                        <p className="font-medium text-text dark:text-dark-text">
                                            {request.user?.name || tCommon('unknown')}
                                        </p>
                                        <div className="flex items-center gap-2 text-xs text-text-light dark:text-dark-text-muted">
                                            <span className="capitalize">{tUser(request.current_role as any)}</span>
                                            <span>ΓåÆ</span>
                                            <span className="text-primary font-medium capitalize">{tUser(request.requested_role as any)}</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2 text-xs text-text-light dark:text-dark-text-muted">
                                    <Calendar className="w-3 h-3" />
                                    {new Date(request.created_at).toLocaleDateString()}
                                </div>
                            </div>

                            {/* Expand/Collapse Toggle */}
                            <button
                                onClick={() => setExpandedId(expandedId === request.id ? null : request.id)}
                                className="mt-3 flex items-center gap-1 text-sm text-primary hover:underline"
                            >
                                {expandedId === request.id ? (
                                    <>
                                        <ChevronUp className="w-4 h-4" />
                                        {t('hideDetails')}
                                    </>
                                ) : (
                                    <>
                                        <ChevronDown className="w-4 h-4" />
                                        {t('showReason')}
                                    </>
                                )}
                            </button>

                            {/* Expanded Content */}
                            {expandedId === request.id && (
                                <div className="mt-4 space-y-4">
                                    {/* Reason */}
                                    <div className="p-3 bg-gray-50 dark:bg-dark-bg rounded-lg">
                                        <p className="text-sm text-text dark:text-dark-text whitespace-pre-wrap">
                                            {request.reason}
                                        </p>
                                    </div>

                                    {/* Admin Notes Input */}
                                    <div>
                                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                                            {t('adminNotesLabel')}
                                        </label>
                                        <textarea
                                            value={adminNotes[request.id] || ''}
                                            onChange={(e) => setAdminNotes({ ...adminNotes, [request.id]: e.target.value })}
                                            placeholder={t('adminNotesPlaceholder')}
                                            rows={2}
                                            className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder:text-text-light dark:placeholder:text-dark-text-muted focus:ring-2 focus:ring-primary focus:border-transparent resize-none text-sm"
                                        />
                                    </div>

                                    {/* Action Buttons */}
                                    <div className="flex gap-2">
                                        <Button
                                            variant="outline"
                                            onClick={() => handleDecision(request.id, 'rejected')}
                                            disabled={processingId === request.id}
                                            className="flex-1 gap-2 text-red-600 border-red-200 hover:bg-red-50 dark:text-red-400 dark:border-red-800 dark:hover:bg-red-900/20"
                                        >
                                            {processingId === request.id ? (
                                                <Loader2 className="w-4 h-4 animate-spin" />
                                            ) : (
                                                <XCircle className="w-4 h-4" />
                                            )}
                                            {t('reject')}
                                        </Button>
                                        <Button
                                            onClick={() => handleDecision(request.id, 'approved')}
                                            disabled={processingId === request.id}
                                            className="flex-1 gap-2 bg-green-600 hover:bg-green-700"
                                        >
                                            {processingId === request.id ? (
                                                <Loader2 className="w-4 h-4 animate-spin" />
                                            ) : (
                                                <CheckCircle className="w-4 h-4" />
                                            )}
                                            {t('approve')}
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))
                )}
            </div>
        </div>
    )
}

