'use client'

import { useState, useMemo, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { useToast } from '@/components/ui/toast'
import { Shield, ShieldCheck, Users, AlertTriangle, Loader2, Check, ArrowRight } from 'lucide-react'
import { useTranslations } from 'next-intl'

interface User {
    id: string
    email: string
    name: string | null
    role: 'researcher' | 'moderator' | 'admin'
}

interface RolePromotionDialogProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    user: User
    onSuccess: () => void
}

export function RolePromotionDialog({
    open,
    onOpenChange,
    user,
    onSuccess
}: RolePromotionDialogProps) {
    const t = useTranslations('Promotion')
    const tCommon = useTranslations('Common')
    const tUser = useTranslations('UserManagement.roles')

    const roles = useMemo(() => [
        {
            value: 'researcher',
            label: tUser('researcher'),
            description: t('researcherDesc'),
            icon: Users,
        },
        {
            value: 'moderator',
            label: tUser('moderator'),
            description: t('moderatorDesc'),
            icon: Shield,
        },
        {
            value: 'admin',
            label: tUser('admin'),
            description: t('adminDesc'),
            icon: ShieldCheck,
        }
    ], [t, tUser])

    const [selectedRole, setSelectedRole] = useState(user.role)
    const [reason, setReason] = useState('')
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()

    // Reset state when dialog opens with new user
    useEffect(() => {
        if (open) {
            setSelectedRole(user.role)
            setReason('')
            setError(null)
        }
    }, [open, user.role])

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (selectedRole === user.role) {
            onOpenChange(false)
            return
        }

        if (!reason.trim()) {
            setError(t('reasonLabel')) // Or a more specific error key if available
            return
        }

        setLoading(true)
        setError(null)

        try {
            const { data, error: rpcError } = await supabase.rpc('promote_user_role', {
                target_user_id: user.id,
                new_role: selectedRole,
                change_reason: reason.trim()
            })

            if (rpcError) {
                setError(rpcError.message)
                return
            }

            if (!data.success) {
                setError(data.error || t('processError'))
                return
            }

            showToast(t('requestProcessed', { decision: tUser(selectedRole) }), 'success')
            onSuccess()
            onOpenChange(false)
            setReason('')
        } catch (err) {
            setError(tCommon('errors.unknown'))
        } finally {
            setLoading(false)
        }
    }

    const currentRoleData = roles.find(r => r.value === user.role)
    const selectedRoleData = roles.find(r => r.value === selectedRole)
    const isPromotion = roles.findIndex(r => r.value === selectedRole) > roles.findIndex(r => r.value === user.role)
    const isDemotion = roles.findIndex(r => r.value === selectedRole) < roles.findIndex(r => r.value === user.role)
    const hasChange = selectedRole !== user.role

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-lg bg-white dark:bg-dark-surface border-gray-200 dark:border-dark-border">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2 text-lg text-text dark:text-dark-text">
                        <div className="p-2 rounded-lg bg-primary/10 dark:bg-primary/20">
                            <Shield className="w-5 h-5 text-primary dark:text-primary-light" />
                        </div>
                        {t('changeRoleTitle')}
                    </DialogTitle>
                    <DialogDescription className="text-base text-text-light dark:text-dark-text-muted">
                        {t('changeRoleSubtitle', { name: user.name || tCommon('anonymous') })}
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-5 mt-2">
                    {/* Role Change Preview */}
                    {hasChange && currentRoleData && selectedRoleData && (
                        <div className="flex items-center justify-center gap-3 p-4 rounded-xl bg-gray-50 dark:bg-dark-border/50 border border-gray-200 dark:border-dark-border">
                            <div className="flex items-center gap-2">
                                <div className="p-2 rounded-lg bg-gray-200 dark:bg-dark-border">
                                    <currentRoleData.icon className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                </div>
                                <span className="font-medium text-text dark:text-dark-text">{currentRoleData.label}</span>
                            </div>
                            <ArrowRight className={`w-5 h-5 ${isPromotion ? 'text-green-500' : 'text-accent'}`} />
                            <div className="flex items-center gap-2">
                                <div className="p-2 rounded-lg bg-primary/10 dark:bg-primary/20">
                                    <selectedRoleData.icon className="w-4 h-4 text-primary dark:text-primary-light" />
                                </div>
                                <span className="font-medium text-text dark:text-dark-text">{selectedRoleData.label}</span>
                            </div>
                        </div>
                    )}

                    {/* Role Selection */}
                    <div className="space-y-3">
                        <Label className="text-sm font-semibold text-text dark:text-dark-text">{t('selectNewRole')}</Label>
                        <div className="space-y-2">
                            {roles.map((role) => {
                                const Icon = role.icon
                                const isSelected = selectedRole === role.value
                                const isCurrent = user.role === role.value

                                return (
                                    <button
                                        key={role.value}
                                        type="button"
                                        onClick={() => !isCurrent && setSelectedRole(role.value as typeof user.role)}
                                        className={`
                                            w-full p-4 rounded-xl border-2 text-left transition-all duration-200
                                            ${isSelected
                                                ? 'border-primary dark:border-primary-light bg-primary/5 dark:bg-primary/10'
                                                : 'border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface hover:border-gray-300 dark:hover:border-gray-600'
                                            }
                                            ${isCurrent ? 'cursor-default' : 'cursor-pointer'}
                                        `}
                                    >
                                        <div className="flex items-start gap-4">
                                            <div className={`p-2.5 rounded-xl transition-all ${isSelected
                                                ? 'bg-primary/10 dark:bg-primary/20'
                                                : 'bg-gray-100 dark:bg-dark-border'
                                                }`}>
                                                <Icon className={`w-5 h-5 ${isSelected
                                                    ? 'text-primary dark:text-primary-light'
                                                    : 'text-text-light dark:text-dark-text-muted'
                                                    }`} />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <span className="font-semibold text-text dark:text-dark-text">
                                                        {role.label}
                                                    </span>
                                                    {isCurrent && (
                                                        <span className="inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded-full bg-primary/10 dark:bg-primary/20 text-primary dark:text-primary-light font-medium">
                                                            <Check className="w-3 h-3" />
                                                            {tCommon('current')}
                                                        </span>
                                                    )}
                                                </div>
                                                <p className="text-sm text-text-light dark:text-dark-text-muted">
                                                    {role.description}
                                                </p>
                                            </div>
                                            {isSelected && !isCurrent && (
                                                <div className="flex-shrink-0">
                                                    <div className="w-5 h-5 rounded-full flex items-center justify-center bg-primary dark:bg-primary-light">
                                                        <Check className="w-3.5 h-3.5 text-white" />
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </button>
                                )
                            })}
                        </div>
                    </div>

                    {/* Warning for Admin Promotion */}
                    {selectedRole === 'admin' && user.role !== 'admin' && (
                        <div className="flex items-start gap-3 p-4 rounded-xl bg-accent/10 dark:bg-accent/20 border border-accent/30 dark:border-accent/40">
                            <div className="p-1.5 rounded-lg bg-accent/20 dark:bg-accent/30">
                                <AlertTriangle className="w-4 h-4 text-accent dark:text-accent-light" />
                            </div>
                            <div>
                                <p className="font-semibold text-accent dark:text-accent-light text-sm">{t('adminWarningTitle')}</p>
                                <p className="mt-1 text-sm text-text-light dark:text-dark-text-muted">
                                    {t('adminWarningDesc')}
                                </p>
                            </div>
                        </div>
                    )}

                    {/* Demotion Warning */}
                    {isDemotion && (
                        <div className="flex items-start gap-3 p-4 rounded-xl bg-accent/10 dark:bg-accent/20 border border-accent/30 dark:border-accent/40">
                            <div className="p-1.5 rounded-lg bg-accent/20 dark:bg-accent/30">
                                <AlertTriangle className="w-4 h-4 text-accent dark:text-accent-light" />
                            </div>
                            <div>
                                <p className="font-semibold text-accent dark:text-accent-light text-sm">{t('demotionWarningTitle')}</p>
                                <p className="mt-1 text-sm text-text-light dark:text-dark-text-muted">
                                    {t('demotionWarningDesc')}
                                </p>
                            </div>
                        </div>
                    )}

                    {/* Reason Input */}
                    {hasChange && (
                        <div className="space-y-2">
                            <Label htmlFor="reason" className="text-sm font-semibold text-text dark:text-dark-text">
                                {t('reasonLabel')} <span className="text-accent">*</span>
                            </Label>
                            <textarea
                                id="reason"
                                value={reason}
                                onChange={(e) => {
                                    setReason(e.target.value)
                                    setError(null)
                                }}
                                placeholder={t('reasonPlaceholder')}
                                rows={3}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder:text-text-light dark:placeholder:text-dark-text-muted resize-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-colors"
                            />
                            <p className="text-xs text-text-light dark:text-dark-text-muted flex items-center gap-1">
                                <Shield className="w-3 h-3" />
                                {t('auditLogNote')}
                            </p>
                        </div>
                    )}

                    {/* Error Message */}
                    {error && (
                        <div className="p-4 rounded-xl bg-accent/10 dark:bg-accent/20 border border-accent/30 dark:border-accent/40">
                            <p className="text-sm text-accent dark:text-accent-light font-medium">{error}</p>
                        </div>
                    )}

                    <DialogFooter className="gap-2 sm:gap-2">
                        <Button
                            type="button"
                            variant="outline"
                            onClick={() => onOpenChange(false)}
                            disabled={loading}
                            className="flex-1 sm:flex-none"
                        >
                            {tCommon('cancel')}
                        </Button>
                        <Button
                            type="submit"
                            disabled={loading || !hasChange}
                            className="flex-1 sm:flex-none"
                        >
                            {loading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                            {!hasChange
                                ? t('noChange')
                                : isPromotion
                                    ? t('promoteAction')
                                    : isDemotion
                                        ? t('demoteAction')
                                        : t('updateAction')}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    Users, GitBranch, Shield, AlertTriangle,
    RefreshCw, ChevronRight, CheckCircle, XCircle,
    Clock, Loader2
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'

interface GovernanceStats {
    total_users_in_tree: number
    pending_promotions: number
    invite_blocked_users: number
    trust_recalc_queue_size: number
}

interface PromotionRequest {
    id: string
    user_id: string
    target_role: string
    current_role: string
    required_moderator_endorsements: number
    required_admin_endorsements: number
    created_at: string
    user: { id: string; name: string; email: string; role: string }
    endorsements: Array<{
        id: string
        endorser_role: string
        justification: string
        endorser: { id: string; name: string }
    }>
}

export function TrustGovernanceDashboard() {
    const [stats, setStats] = useState<GovernanceStats | null>(null)
    const [promotions, setPromotions] = useState<PromotionRequest[]>([])
    const [loading, setLoading] = useState(true)
    const [processingQueue, setProcessingQueue] = useState(false)
    const supabase = createClient()

    useEffect(() => {
        loadData()
    }, [])

    const loadData = async () => {
        setLoading(true)
        try {
            const [statsRes, promotionsRes] = await Promise.all([
                fetch('/api/admin/trust-governance'),
                fetch('/api/admin/trust-governance?metric=promotions')
            ])

            if (statsRes.ok) {
                setStats(await statsRes.json())
            }
            if (promotionsRes.ok) {
                const data = await promotionsRes.json()
                setPromotions(data.data || [])
            }
        } catch (error) {
            console.error('Failed to load governance data:', error)
        } finally {
            setLoading(false)
        }
    }

    const processQueue = async () => {
        setProcessingQueue(true)
        try {
            const res = await fetch('/api/admin/trust-governance', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'process-trust-queue' })
            })
            if (res.ok) {
                const { processed } = await res.json()
                alert(`Processed ${processed} trust recalculations`)
                loadData()
            }
        } finally {
            setProcessingQueue(false)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center p-12">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-display font-bold text-text dark:text-dark-text">
                        Trust Governance
                    </h1>
                    <p className="text-text-light dark:text-dark-text-muted mt-1">
                        Legible, accountable, and reversible governance
                    </p>
                </div>
                <button
                    onClick={loadData}
                    className="btn btn-outline flex items-center gap-2"
                >
                    <RefreshCw className="w-4 h-4" />
                    Refresh
                </button>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <StatCard
                    icon={GitBranch}
                    label="Users in Tree"
                    value={stats?.total_users_in_tree || 0}
                    color="text-blue-500"
                />
                <StatCard
                    icon={Shield}
                    label="Pending Promotions"
                    value={stats?.pending_promotions || 0}
                    color="text-amber-500"
                />
                <StatCard
                    icon={AlertTriangle}
                    label="Blocked Users"
                    value={stats?.invite_blocked_users || 0}
                    color="text-red-500"
                />
                <div className="bg-white dark:bg-dark-surface p-4 rounded-xl border border-gray-200 dark:border-dark-border">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Clock className="w-5 h-5 text-purple-500" />
                            <div>
                                <p className="text-sm text-text-light dark:text-dark-text-muted">Recalc Queue</p>
                                <p className="text-xl font-bold text-text dark:text-dark-text">
                                    {stats?.trust_recalc_queue_size || 0}
                                </p>
                            </div>
                        </div>
                        <button
                            onClick={processQueue}
                            disabled={processingQueue || (stats?.trust_recalc_queue_size || 0) === 0}
                            className="btn btn-sm btn-primary"
                        >
                            {processingQueue ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Process'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Pending Promotions */}
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border">
                <div className="p-4 border-b border-gray-200 dark:border-dark-border">
                    <h2 className="text-lg font-semibold text-text dark:text-dark-text">
                        Pending Promotion Requests
                    </h2>
                </div>
                <div className="divide-y divide-gray-100 dark:divide-dark-border">
                    {promotions.length === 0 ? (
                        <div className="p-8 text-center text-text-light dark:text-dark-text-muted">
                            No pending promotion requests
                        </div>
                    ) : (
                        promotions.map(req => (
                            <PromotionCard key={req.id} request={req} onUpdate={loadData} />
                        ))
                    )}
                </div>
            </div>
        </div>
    )
}

function StatCard({ icon: Icon, label, value, color }: {
    icon: React.ElementType
    label: string
    value: number
    color: string
}) {
    return (
        <div className="bg-white dark:bg-dark-surface p-4 rounded-xl border border-gray-200 dark:border-dark-border">
            <div className="flex items-center gap-3">
                <Icon className={`w-5 h-5 ${color}`} />
                <div>
                    <p className="text-sm text-text-light dark:text-dark-text-muted">{label}</p>
                    <p className="text-xl font-bold text-text dark:text-dark-text">{value}</p>
                </div>
            </div>
        </div>
    )
}

function PromotionCard({ request, onUpdate }: { request: PromotionRequest; onUpdate: () => void }) {
    const [endorsing, setEndorsing] = useState(false)
    const [justification, setJustification] = useState('')
    const [showEndorse, setShowEndorse] = useState(false)

    const modCount = request.endorsements.filter(e => e.endorser_role === 'moderator').length
    const adminCount = request.endorsements.filter(e => e.endorser_role === 'admin').length

    const handleEndorse = async () => {
        if (justification.length < 20) {
            alert('Justification must be at least 20 characters')
            return
        }

        setEndorsing(true)
        try {
            const res = await fetch('/api/admin/trust-governance', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'endorse',
                    request_id: request.id,
                    justification
                })
            })

            if (res.ok) {
                setJustification('')
                setShowEndorse(false)
                onUpdate()
            } else {
                const { error } = await res.json()
                alert(error)
            }
        } finally {
            setEndorsing(false)
        }
    }

    return (
        <div className="p-4">
            <div className="flex items-start justify-between">
                <div>
                    <div className="flex items-center gap-2">
                        <span className="font-medium text-text dark:text-dark-text">
                            {request.user.name}
                        </span>
                        <ChevronRight className="w-4 h-4 text-text-light" />
                        <span className="px-2 py-0.5 bg-primary/10 text-primary text-sm rounded">
                            {request.target_role}
                        </span>
                    </div>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                        Currently: {request.current_role}
                    </p>
                </div>

                <div className="text-right">
                    <div className="flex items-center gap-4 text-sm">
                        <span className={modCount >= request.required_moderator_endorsements ? 'text-green-500' : 'text-text-light'}>
                            Mods: {modCount}/{request.required_moderator_endorsements}
                        </span>
                        <span className={adminCount >= request.required_admin_endorsements ? 'text-green-500' : 'text-text-light'}>
                            Admins: {adminCount}/{request.required_admin_endorsements}
                        </span>
                    </div>
                </div>
            </div>

            {/* Endorsements */}
            {request.endorsements.length > 0 && (
                <div className="mt-3 space-y-2">
                    {request.endorsements.map(e => (
                        <div key={e.id} className="text-sm bg-gray-50 dark:bg-dark-bg p-2 rounded">
                            <span className="font-medium">{e.endorser.name}</span>
                            <span className="text-text-light dark:text-dark-text-muted"> ({e.endorser_role}): </span>
                            <span className="text-text dark:text-dark-text">{e.justification}</span>
                        </div>
                    ))}
                </div>
            )}

            {/* Actions */}
            <div className="mt-4 flex items-center gap-2">
                {showEndorse ? (
                    <div className="flex-1 flex items-center gap-2">
                        <input
                            type="text"
                            value={justification}
                            onChange={(e) => setJustification(e.target.value)}
                            placeholder="Justification (min 20 chars)"
                            className="flex-1 px-3 py-2 border rounded-lg text-sm"
                        />
                        <button
                            onClick={handleEndorse}
                            disabled={endorsing || justification.length < 20}
                            className="btn btn-sm btn-primary"
                        >
                            {endorsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <CheckCircle className="w-4 h-4" />}
                        </button>
                        <button
                            onClick={() => setShowEndorse(false)}
                            className="btn btn-sm btn-outline"
                        >
                            <XCircle className="w-4 h-4" />
                        </button>
                    </div>
                ) : (
                    <button
                        onClick={() => setShowEndorse(true)}
                        className="btn btn-sm btn-outline"
                    >
                        Endorse
                    </button>
                )}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import Image from 'next/image'
import { createClient } from '@/lib/supabase/client'
import {
    Users,
    Search,
    Filter,
    ChevronDown,
    Shield,
    ShieldCheck,
    ShieldX,
    MoreHorizontal,
    Mail,
    Calendar,
    FileText,
    MessageSquare,
    Loader2,
    ChevronLeft,
    ChevronRight,
    Ban,
    CheckCircle,
    AlertTriangle
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { useToast } from '@/components/ui/toast'
import { RolePromotionDialog } from './RolePromotionDialog'
import { format } from 'date-fns'
import { useTranslations } from 'next-intl'

interface AdminUser {
    id: string
    email: string
    name: string | null
    role: 'researcher' | 'moderator' | 'admin'
    avatar_url: string | null
    created_at: string
    is_verified_author: boolean
    suspended_at: string | null
    suspension_reason: string | null
    post_count: number
    comment_count: number
}

interface UserListResponse {
    users: AdminUser[]
    total: number
    page: number
    page_size: number
    total_pages: number
}

export function UserManagement() {
    const [users, setUsers] = useState<AdminUser[]>([])
    const [loading, setLoading] = useState(true)
    const [totalUsers, setTotalUsers] = useState(0)
    const [totalPages, setTotalPages] = useState(1)
    const [page, setPage] = useState(1)
    const [pageSize] = useState(20)
    const [searchQuery, setSearchQuery] = useState('')
    const [roleFilter, setRoleFilter] = useState<string | null>(null)
    const [sortBy, setSortBy] = useState('created_at')
    const [sortOrder, setSortOrder] = useState('desc')
    const [selectedUser, setSelectedUser] = useState<AdminUser | null>(null)
    const [showRoleDialog, setShowRoleDialog] = useState(false)
    const [processingUserId, setProcessingUserId] = useState<string | null>(null)
    const [showActionMenu, setShowActionMenu] = useState<string | null>(null)
    const [currentUserRole, setCurrentUserRole] = useState<string | null>(null)

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()
    const t = useTranslations('UserManagement')
    const tCommon = useTranslations('Common')

    // Fetch current user's role on mount
    useEffect(() => {
        async function fetchCurrentUserRole() {
            const { data: { user } } = await supabase.auth.getUser()
            if (user) {
                const { data } = await supabase
                    .from('users')
                    .select('role')
                    .eq('id', user.id)
                    .single()
                if (data) setCurrentUserRole(data.role)
            }
        }
        fetchCurrentUserRole()
    }, [supabase])

    const loadUsers = useCallback(async () => {
        setLoading(true)
        try {
            const { data, error } = await supabase.rpc('get_admin_users', {
                page_number: page,
                page_size: pageSize,
                role_filter: roleFilter,
                search_query: searchQuery || null,
                sort_by: sortBy,
                sort_order: sortOrder
            })

            if (error) {
                console.error('Error loading users:', error)
                showToast(tCommon('errors.failedToLoad'), 'error')
                return
            }

            const result = data as UserListResponse
            setUsers(result.users || [])
            setTotalUsers(result.total)
            setTotalPages(result.total_pages)
        } catch (error) {
            console.error('Error:', error)
            showToast(tCommon('errors.general'), 'error')
        } finally {
            setLoading(false)
        }
    }, [page, pageSize, roleFilter, searchQuery, sortBy, sortOrder, supabase, showToast, tCommon])

    useEffect(() => {
        loadUsers()
    }, [loadUsers])

    // Debounced search
    useEffect(() => {
        const timer = setTimeout(() => {
            if (page !== 1) setPage(1)
            else loadUsers()
        }, 300)
        return () => clearTimeout(timer)
    }, [searchQuery, loadUsers, page])

    const handleRoleChange = (user: AdminUser) => {
        // Only admins can change roles
        if (currentUserRole !== 'admin') {
            showToast(t('adminOnly'), 'error')
            return
        }
        setSelectedUser(user)
        setShowRoleDialog(true)
        setShowActionMenu(null)
    }

    const handleSuspend = async (user: AdminUser) => {
        // Moderators cannot suspend admins
        if (currentUserRole === 'moderator' && user.role === 'admin') {
            showToast(t('moderatorRestriction'), 'error')
            setShowActionMenu(null)
            return
        }
        setProcessingUserId(user.id)
        setShowActionMenu(null)
        try {
            const { data, error } = await supabase.rpc('suspend_user', {
                target_user_id: user.id,
                suspend: !user.suspended_at,
                reason: user.suspended_at ? null : 'Suspended by admin'
            })

            if (error || !data.success) {
                showToast(data?.error || tCommon('errors.updateFailed'), 'error')
                return
            }

            showToast(
                user.suspended_at ? t('unsuspendedSuccess') : t('suspendedSuccess'),
                'success'
            )
            loadUsers()
        } catch (error) {
            showToast(tCommon('errors.general'), 'error')
        } finally {
            setProcessingUserId(null)
        }
    }

    const getRoleBadge = (role: string, isVerified: boolean, suspended: boolean) => {
        if (suspended) {
            return (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300">
                    <Ban className="w-3 h-3" />
                    {t('suspended')}
                </span>
            )
        }

        const styles = {
            admin: 'bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300',
            moderator: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300',
            researcher: 'bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300'
        }

        const icons = {
            admin: ShieldCheck,
            moderator: Shield,
            researcher: Users
        }

        const Icon = icons[role as keyof typeof icons] || Users

        return (
            <div className="flex items-center gap-1.5">
                <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium capitalize ${styles[role as keyof typeof styles] || styles.researcher}`}>
                    <Icon className="w-3 h-3" />
                    {t(`roles.${role}`)}
                </span>
                {isVerified && (
                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300">
                        <CheckCircle className="w-3 h-3" />
                        {t('verified')}
                    </span>
                )}
            </div>
        )
    }

    return (
        <div className="space-y-4 sm:space-y-6">
            {/* Header & Filters */}
            <div className="flex flex-col gap-3 sm:gap-4">
                <div className="relative w-full">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light dark:text-dark-text-muted" />
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder={t('searchPlaceholder')}
                        className="w-full pl-10 pr-4 py-2 sm:py-2.5 rounded-lg border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-sm text-text dark:text-dark-text focus:ring-2 focus:ring-primary/20 focus:border-primary"
                    />
                </div>

                <div className="flex items-center gap-2 overflow-x-auto">
                    {/* Role Filter */}
                    <Select
                        value={roleFilter || 'all'}
                        onValueChange={(value) => {
                            setRoleFilter(value === 'all' ? null : value)
                            setPage(1)
                        }}
                    >
                        <SelectTrigger className="w-[120px] sm:w-[140px] bg-white dark:bg-dark-surface text-xs sm:text-sm flex-shrink-0">
                            <SelectValue placeholder={t('allRoles')} />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">{t('allRoles')}</SelectItem>
                            <SelectItem value="researcher">{t('researchers')}</SelectItem>
                            <SelectItem value="moderator">{t('moderators')}</SelectItem>
                            <SelectItem value="admin">{t('admins')}</SelectItem>
                        </SelectContent>
                    </Select>

                    {/* Sort */}
                    <Select
                        value={`${sortBy}-${sortOrder}`}
                        onValueChange={(value) => {
                            const [by, order] = value.split('-')
                            setSortBy(by)
                            setSortOrder(order)
                            setPage(1)
                        }}
                    >
                        <SelectTrigger className="w-[120px] sm:w-[140px] bg-white dark:bg-dark-surface text-xs sm:text-sm flex-shrink-0">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="created_at-desc">{t('sort.newest')}</SelectItem>
                            <SelectItem value="created_at-asc">{t('sort.oldest')}</SelectItem>
                            <SelectItem value="name-asc">{t('sort.nameAZ')}</SelectItem>
                            <SelectItem value="name-desc">{t('sort.nameZA')}</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* User Count */}
            <div className="text-sm text-text-light dark:text-dark-text-muted">
                {t('showing', { count: users.length, total: totalUsers })}
            </div>

            {/* Users List */}
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <Loader2 className="w-6 h-6 animate-spin text-primary" />
                    </div>
                ) : users.length === 0 ? (
                    <div className="text-center py-12 text-text-light dark:text-dark-text-muted">
                        <Users className="w-12 h-12 mx-auto mb-4 opacity-30" />
                        <p>{t('noUsers')}</p>
                    </div>
                ) : (
                    <>
                        {/* Mobile Card View */}
                        <div className="md:hidden divide-y divide-gray-100 dark:divide-dark-border">
                            {users.map((user) => (
                                <div key={user.id} className="p-3 space-y-2">
                                    <div className="flex items-start justify-between gap-2">
                                        <div className="flex items-center gap-2 min-w-0 flex-1">
                                            <div className="w-9 h-9 rounded-full bg-gray-200 dark:bg-dark-border flex items-center justify-center overflow-hidden flex-shrink-0">
                                                {user.avatar_url ? (
                                                    <Image
                                                        src={user.avatar_url}
                                                        alt=""
                                                        width={36}
                                                        height={36}
                                                        className="w-full h-full object-cover"
                                                    />
                                                ) : (
                                                    <Users className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                                )}
                                            </div>
                                            <div className="min-w-0 flex-1">
                                                <p className="font-medium text-sm text-text dark:text-dark-text truncate">
                                                    {user.name || tCommon('unknown')}
                                                </p>
                                                <p className="text-xs text-text-light dark:text-dark-text-muted truncate">
                                                    {user.email}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="relative flex-shrink-0">
                                            <button
                                                onClick={() => setShowActionMenu(showActionMenu === user.id ? null : user.id)}
                                                disabled={processingUserId === user.id}
                                                className="p-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors disabled:opacity-50"
                                            >
                                                {processingUserId === user.id ? (
                                                    <Loader2 className="w-4 h-4 animate-spin" />
                                                ) : (
                                                    <MoreHorizontal className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                                )}
                                            </button>
                                            {showActionMenu === user.id && (
                                                <>
                                                    <div className="fixed inset-0 z-10" onClick={() => setShowActionMenu(null)} />
                                                    <div className="absolute right-0 top-full mt-1 w-44 bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-lg shadow-lg z-20 py-1">
                                                        {currentUserRole === 'admin' && (
                                                            <button
                                                                onClick={() => handleRoleChange(user)}
                                                                className="w-full px-3 py-2 text-left text-sm text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-border flex items-center gap-2"
                                                            >
                                                                <Shield className="w-4 h-4" />
                                                                {t('changeRole')}
                                                            </button>
                                                        )}
                                                        {!(currentUserRole === 'moderator' && user.role === 'admin') && (
                                                            <button
                                                                onClick={() => handleSuspend(user)}
                                                                className={`w-full px-3 py-2 text-left text-sm flex items-center gap-2 ${user.suspended_at
                                                                    ? 'text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20'
                                                                    : 'text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20'
                                                                    }`}
                                                            >
                                                                {user.suspended_at ? (
                                                                    <><CheckCircle className="w-4 h-4" />{t('unsuspend')}</>
                                                                ) : (
                                                                    <><Ban className="w-4 h-4" />{t('suspend')}</>
                                                                )}
                                                            </button>
                                                        )}
                                                    </div>
                                                </>
                                            )}
                                        </div>
                                    </div>
                                    <div className="flex flex-wrap items-center gap-2 text-xs">
                                        {getRoleBadge(user.role, user.is_verified_author, !!user.suspended_at)}
                                        <span className="flex items-center gap-1 text-text-light dark:text-dark-text-muted">
                                            <Calendar className="w-3 h-3" />
                                            {format(new Date(user.created_at), 'MMM d, yyyy')}
                                        </span>
                                        <span className="flex items-center gap-1 text-text-light dark:text-dark-text-muted">
                                            <FileText className="w-3 h-3" />
                                            {user.post_count}
                                        </span>
                                        <span className="flex items-center gap-1 text-text-light dark:text-dark-text-muted">
                                            <MessageSquare className="w-3 h-3" />
                                            {user.comment_count}
                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Desktop Table View */}
                        <div className="hidden md:block overflow-x-auto">
                            <table className="w-full">
                                <thead className="bg-gray-50 dark:bg-dark-border/50 border-b border-gray-200 dark:border-dark-border">
                                    <tr>
                                        <th className="px-4 py-3 text-start text-xs font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                                            {t('user')}
                                        </th>
                                        <th className="px-4 py-3 text-start text-xs font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                                            {t('role')}
                                        </th>
                                        <th className="px-4 py-3 text-start text-xs font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                                            {t('joined')}
                                        </th>
                                        <th className="px-4 py-3 text-start text-xs font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                                            {t('activity.label')}
                                        </th>
                                        <th className="px-4 py-3 text-end text-xs font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                                            {t('actions')}
                                        </th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                                    {users.map((user) => (
                                        <tr
                                            key={user.id}
                                            className="hover:bg-gray-50 dark:hover:bg-dark-border/30 transition-colors"
                                        >
                                            <td className="px-4 py-3">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-gray-200 dark:bg-dark-border flex items-center justify-center overflow-hidden">
                                                        {user.avatar_url ? (
                                                            <Image
                                                                src={user.avatar_url}
                                                                alt=""
                                                                width={40}
                                                                height={40}
                                                                className="w-full h-full object-cover"
                                                            />
                                                        ) : (
                                                            <Users className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
                                                        )}
                                                    </div>
                                                    <div>
                                                        <p className="font-medium text-text dark:text-dark-text">
                                                            {user.name || tCommon('unknown')}
                                                        </p>
                                                        <p className="text-sm text-text-light dark:text-dark-text-muted flex items-center gap-1">
                                                            <Mail className="w-3 h-3" />
                                                            {user.email}
                                                        </p>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-4 py-3">
                                                {getRoleBadge(user.role, user.is_verified_author, !!user.suspended_at)}
                                            </td>
                                            <td className="px-4 py-3 text-sm text-text-light dark:text-dark-text-muted">
                                                <div className="flex items-center gap-1">
                                                    <Calendar className="w-3.5 h-3.5" />
                                                    {format(new Date(user.created_at), 'MMM d, yyyy')}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3">
                                                <div className="flex items-center gap-4 text-sm text-text-light dark:text-dark-text-muted">
                                                    <span className="flex items-center gap-1" title={t('activity.posts')}>
                                                        <FileText className="w-3.5 h-3.5" />
                                                        {user.post_count}
                                                    </span>
                                                    <span className="flex items-center gap-1" title={t('activity.comments')}>
                                                        <MessageSquare className="w-3.5 h-3.5" />
                                                        {user.comment_count}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 text-right">
                                                <div className="relative inline-block">
                                                    <button
                                                        onClick={() => setShowActionMenu(showActionMenu === user.id ? null : user.id)}
                                                        disabled={processingUserId === user.id}
                                                        className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors disabled:opacity-50"
                                                    >
                                                        {processingUserId === user.id ? (
                                                            <Loader2 className="w-4 h-4 animate-spin" />
                                                        ) : (
                                                            <MoreHorizontal className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                                        )}
                                                    </button>

                                                    {showActionMenu === user.id && (
                                                        <>
                                                            <div
                                                                className="fixed inset-0 z-10"
                                                                onClick={() => setShowActionMenu(null)}
                                                            />
                                                            <div className="absolute right-0 top-full mt-1 w-48 bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-lg shadow-lg z-20 py-1">
                                                                {/* Only show Change Role to admins */}
                                                                {currentUserRole === 'admin' && (
                                                                    <button
                                                                        onClick={() => handleRoleChange(user)}
                                                                        className="w-full px-4 py-2 text-left text-sm text-text dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-border flex items-center gap-2"
                                                                    >
                                                                        <Shield className="w-4 h-4" />
                                                                        {t('changeRole')}
                                                                    </button>
                                                                )}
                                                                {/* Moderators cannot suspend admins */}
                                                                {!(currentUserRole === 'moderator' && user.role === 'admin') && (
                                                                    <button
                                                                        onClick={() => handleSuspend(user)}
                                                                        className={`w-full px-4 py-2 text-left text-sm flex items-center gap-2 ${user.suspended_at
                                                                            ? 'text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20'
                                                                            : 'text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20'
                                                                            }`}
                                                                    >
                                                                        {user.suspended_at ? (
                                                                            <>
                                                                                <CheckCircle className="w-4 h-4" />
                                                                                {t('unsuspend')}
                                                                            </>
                                                                        ) : (
                                                                            <>
                                                                                <Ban className="w-4 h-4" />
                                                                                {t('suspend')}
                                                                            </>
                                                                        )}
                                                                    </button>
                                                                )}
                                                            </div>
                                                        </>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </>
                )}
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex flex-col sm:flex-row items-center justify-between gap-2">
                    <p className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">
                        {tCommon('pagination', { current: page, total: totalPages })}
                    </p>
                    <div className="flex items-center gap-2">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1 || loading}
                            className="text-xs sm:text-sm px-2 sm:px-3"
                        >
                            <ChevronLeft className="w-4 h-4" />
                            <span className="hidden sm:inline">{tCommon('previous')}</span>
                        </Button>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages || loading}
                            className="text-xs sm:text-sm px-2 sm:px-3"
                        >
                            <span className="hidden sm:inline">{tCommon('next')}</span>
                            <ChevronRight className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            )}

            {/* Role Change Dialog */}
            {selectedUser && (
                <RolePromotionDialog
                    open={showRoleDialog}
                    onOpenChange={setShowRoleDialog}
                    user={selectedUser}
                    onSuccess={() => {
                        loadUsers()
                        setSelectedUser(null)
                    }}
                />
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import {
    MessagesSquare,
    Plus,
    Filter,
    Search,
    AlertTriangle,
    FileText,
    User,
    MessageSquareWarning,
    Calendar,
    Flag,
    Shield,
    Loader2,
    ChevronLeft,
    ChevronRight,
    Archive,
    Clock
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { format, formatDistanceToNow } from 'date-fns'
import { ThreadView } from './ThreadView'
import { NewThreadDialog } from './NewThreadDialog'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface CoordinationThread {
    id: string
    object_type: string
    object_id: string
    title: string
    object_state: string
    priority: string
    trigger_event: string
    created_by_name: string | null
    message_count: number
    last_message_at: string | null
    archived_at: string | null
    created_at: string
    updated_at: string
}

interface CoordinationCenterProps {
    isAdmin: boolean
}

const objectTypeIcons: Record<string, typeof FileText> = {
    post: FileText,
    user: User,
    comment: MessagesSquare,
    report: AlertTriangle,
    appeal: MessageSquareWarning,
    event: Calendar,
    resource: FileText
}

const stateColors: Record<string, string> = {
    ACTIVE: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300',
    UNDER_REVIEW: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300',
    CONTESTED: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300',
    REVOKED: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300',
    ARCHIVED: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300'
}

const priorityColors: Record<string, string> = {
    low: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400',
    normal: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300',
    high: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300',
    urgent: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300'
}

const triggerEventLabels: Record<string, string> = {
    manual: 'manual',
    auto_report: 'auto_report',
    auto_appeal: 'auto_appeal',
    auto_flag: 'auto_flag',
    auto_moderation: 'auto_moderation'
}

export function CoordinationCenter({ isAdmin }: CoordinationCenterProps) {
    const [threads, setThreads] = useState<CoordinationThread[]>([])
    const [loading, setLoading] = useState(true)
    const [page, setPage] = useState(1)
    const [totalPages, setTotalPages] = useState(1)
    const [total, setTotal] = useState(0)

    // Filters
    const [objectTypeFilter, setObjectTypeFilter] = useState<string | null>(null)
    const [stateFilter, setStateFilter] = useState<string | null>(null)
    const [priorityFilter, setPriorityFilter] = useState<string | null>(null)
    const [includeArchived, setIncludeArchived] = useState(false)

    // Selected thread
    const [selectedThreadId, setSelectedThreadId] = useState<string | null>(null)
    const [showNewThreadDialog, setShowNewThreadDialog] = useState(false)

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()
    const t = useTranslations('Coordination')
    const tCommon = useTranslations('Common')

    const loadThreads = useCallback(async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                pageSize: '20',
                includeArchived: includeArchived.toString()
            })
            if (objectTypeFilter) params.set('objectType', objectTypeFilter)
            if (stateFilter) params.set('objectState', stateFilter)
            if (priorityFilter) params.set('priority', priorityFilter)

            const response = await fetch(`/api/coordination?${params}`)
            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || t('loadError'))
            }

            setThreads(data.threads || [])
            setTotalPages(data.total_pages || 1)
            setTotal(data.total || 0)
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setLoading(false)
        }
    }, [page, objectTypeFilter, stateFilter, priorityFilter, includeArchived, showToast, t])

    useEffect(() => {
        loadThreads()
    }, [loadThreads])

    const handleThreadCreated = () => {
        setShowNewThreadDialog(false)
        loadThreads()
        showToast(t('threadCreatedSuccess'), 'success')
    }

    if (selectedThreadId) {
        return (
            <ThreadView
                threadId={selectedThreadId}
                isAdmin={isAdmin}
                onBack={() => {
                    setSelectedThreadId(null)
                    loadThreads()
                }}
            />
        )
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                <div>
                    <h2 className="text-xl font-display font-semibold text-text dark:text-dark-text flex items-center gap-2">
                        <MessagesSquare className="w-5 h-5 text-primary" />
                        {t('coordinationCenter')}
                    </h2>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                        {t('description')}
                    </p>
                </div>
                <Button onClick={() => setShowNewThreadDialog(true)} className="whitespace-nowrap self-start sm:self-auto" size="sm">
                    <Plus className="w-4 h-4 mr-1 sm:mr-2" />
                    <span className="hidden xs:inline">{t('newThread')}</span>
                    <span className="xs:hidden">{t('new')}</span>
                </Button>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                    <p className="text-sm text-text-light dark:text-dark-text-muted">{t('totalThreads')}</p>
                    <p className="text-2xl font-bold text-text dark:text-dark-text">{total}</p>
                </div>
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                    <p className="text-sm text-text-light dark:text-dark-text-muted">{t('underReview')}</p>
                    <p className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">
                        {threads.filter(t => t.object_state === 'UNDER_REVIEW').length}
                    </p>
                </div>
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                    <p className="text-sm text-text-light dark:text-dark-text-muted">{t('urgent')}</p>
                    <p className="text-2xl font-bold text-red-600 dark:text-red-400">
                        {threads.filter(t => t.priority === 'urgent').length}
                    </p>
                </div>
                <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                    <p className="text-sm text-text-light dark:text-dark-text-muted">{t('contested')}</p>
                    <p className="text-2xl font-bold text-orange-600 dark:text-orange-400">
                        {threads.filter(t => t.object_state === 'CONTESTED').length}
                    </p>
                </div>
            </div>

            {/* Filters */}
            <div className="flex flex-wrap items-center gap-3 p-4 bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border">
                <Filter className="w-4 h-4 text-text-light dark:text-dark-text-muted" />

                <Select
                    value={objectTypeFilter || 'all'}
                    onValueChange={(value) => setObjectTypeFilter(value === 'all' ? null : value)}
                >
                    <SelectTrigger className="w-[140px] bg-white dark:bg-dark-surface">
                        <SelectValue placeholder={t('allTypes')} />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="all">{t('allTypes')}</SelectItem>
                        <SelectItem value="post">{t('types.post')}</SelectItem>
                        <SelectItem value="user">{t('types.user')}</SelectItem>
                        <SelectItem value="comment">{t('types.comment')}</SelectItem>
                        <SelectItem value="report">{t('types.report')}</SelectItem>
                        <SelectItem value="appeal">{t('types.appeal')}</SelectItem>
                        <SelectItem value="event">{t('types.event')}</SelectItem>
                        <SelectItem value="resource">{t('types.resource')}</SelectItem>
                    </SelectContent>
                </Select>

                <Select
                    value={stateFilter || 'all'}
                    onValueChange={(value) => setStateFilter(value === 'all' ? null : value)}
                >
                    <SelectTrigger className="w-[140px] bg-white dark:bg-dark-surface">
                        <SelectValue placeholder={t('allStates')} />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="all">{t('allStates')}</SelectItem>
                        <SelectItem value="ACTIVE">{t('active')}</SelectItem>
                        <SelectItem value="UNDER_REVIEW">{t('underReview')}</SelectItem>
                        <SelectItem value="CONTESTED">{t('contested')}</SelectItem>
                        <SelectItem value="REVOKED">{t('revoked')}</SelectItem>
                    </SelectContent>
                </Select>

                <Select
                    value={priorityFilter || 'all'}
                    onValueChange={(value) => setPriorityFilter(value === 'all' ? null : value)}
                >
                    <SelectTrigger className="w-[130px] bg-white dark:bg-dark-surface">
                        <SelectValue placeholder={t('allPriorities')} />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="all">{t('allPriorities')}</SelectItem>
                        <SelectItem value="low">{t('low')}</SelectItem>
                        <SelectItem value="normal">{t('normal')}</SelectItem>
                        <SelectItem value="high">{t('high')}</SelectItem>
                        <SelectItem value="urgent">{t('urgent')}</SelectItem>
                    </SelectContent>
                </Select>

                <label className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted cursor-pointer">
                    <input
                        type="checkbox"
                        checked={includeArchived}
                        onChange={(e) => setIncludeArchived(e.target.checked)}
                        className="rounded border-gray-300 dark:border-dark-border"
                    />
                    {t('includeArchived')}
                </label>
            </div>

            {/* Threads List */}
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <Loader2 className="w-6 h-6 animate-spin text-primary" />
                    </div>
                ) : threads.length === 0 ? (
                    <div className="text-center py-12 text-text-light dark:text-dark-text-muted">
                        <MessagesSquare className="w-12 h-12 mx-auto mb-4 opacity-30" />
                        <p>{t('noThreads')}</p>
                        <p className="text-sm mt-1">{t('createOrFilter')}</p>
                    </div>
                ) : (
                    <div className="divide-y divide-gray-100 dark:divide-dark-border">
                        {threads.map((thread) => {
                            const Icon = objectTypeIcons[thread.object_type] || FileText
                            return (
                                <button
                                    key={thread.id}
                                    onClick={() => setSelectedThreadId(thread.id)}
                                    className="w-full p-4 text-left hover:bg-gray-50 dark:hover:bg-dark-border/30 transition-colors"
                                >
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-1">
                                                <Icon className="w-4 h-4 text-text-light dark:text-dark-text-muted flex-shrink-0" />
                                                <span className={cn(
                                                    'px-2 py-0.5 rounded-full text-xs font-medium',
                                                    stateColors[thread.object_state]
                                                )}>
                                                    {thread.object_state === 'UNDER_REVIEW' ? t('underReview') :
                                                        thread.object_state === 'CONTESTED' ? t('contested') :
                                                            thread.object_state === 'REVOKED' ? t('revoked') :
                                                                thread.object_state === 'ACTIVE' ? t('active') :
                                                                    thread.object_state}
                                                </span>
                                                <span className={cn(
                                                    'px-2 py-0.5 rounded-full text-xs font-medium capitalize',
                                                    priorityColors[thread.priority]
                                                )}>
                                                    {t(thread.priority as any)}
                                                </span>
                                                {thread.trigger_event !== 'manual' && (
                                                    <span className="px-2 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300">
                                                        {t(`triggers.${thread.trigger_event}` as any)}
                                                    </span>
                                                )}
                                                {thread.archived_at && (
                                                    <Archive className="w-3.5 h-3.5 text-gray-400" />
                                                )}
                                            </div>
                                            <h3 className="font-medium text-text dark:text-dark-text truncate">
                                                {thread.title}
                                            </h3>
                                            <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                                                {t('createdWithMessages', {
                                                    name: thread.created_by_name || t('system'),
                                                    count: thread.message_count
                                                })}
                                            </p>
                                        </div>
                                        <div className="text-right flex-shrink-0">
                                            <p className="text-sm text-text-light dark:text-dark-text-muted flex items-center gap-1">
                                                <Clock className="w-3.5 h-3.5" />
                                                {formatDistanceToNow(new Date(thread.updated_at), { addSuffix: true })}
                                            </p>
                                        </div>
                                    </div>
                                </button>
                            )
                        })}
                    </div>
                )}
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex items-center justify-between">
                    <p className="text-sm text-text-light dark:text-dark-text-muted">
                        {tCommon('pagination', { current: page, total: totalPages })}
                    </p>
                    <div className="flex items-center gap-2">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1 || loading}
                        >
                            <ChevronLeft className="w-4 h-4" />
                            {tCommon('previous')}
                        </Button>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages || loading}
                        >
                            {tCommon('next')}
                            <ChevronRight className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            )}


            {/* New Thread Dialog */}
            {showNewThreadDialog && (
                <NewThreadDialog
                    open={showNewThreadDialog}
                    onOpenChange={setShowNewThreadDialog}
                    onSuccess={handleThreadCreated}
                />
            )}
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useToast } from '@/components/ui/toast'
import {
    Send,
    Loader2,
    FileText,
    Flag,
    CheckCircle,
    HelpCircle,
    ArrowUpRight,
    ChevronDown
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface NewMessageFormProps {
    threadId: string
    isAdmin: boolean
    currentState: string
    onSuccess: () => void
}

const messageTypes = [
    { value: 'NOTE', labelKey: 'messageTypes.note', icon: FileText, descriptionKey: 'messageDescriptions.NOTE' },
    { value: 'FLAG', labelKey: 'messageTypes.flag', icon: Flag, descriptionKey: 'messageDescriptions.FLAG' },
    { value: 'DECISION', labelKey: 'messageTypes.decision', icon: CheckCircle, descriptionKey: 'messageDescriptions.DECISION' },
    { value: 'RATIONALE', labelKey: 'messageTypes.rationale', icon: HelpCircle, descriptionKey: 'messageDescriptions.RATIONALE' },
    { value: 'REQUEST_REVIEW', labelKey: 'messageTypes.request_review', icon: ArrowUpRight, descriptionKey: 'messageDescriptions.REQUEST_REVIEW' }
]

const actionTypes = [
    { value: '', labelKey: 'actions.noAction' },
    { value: 'revoke_content', labelKey: 'actions.revoke_content' },
    { value: 'reinstate_content', labelKey: 'actions.reinstate_content' },
    { value: 'suspend_user', labelKey: 'actions.suspend_user', adminOnly: true },
    { value: 'reinstate_user', labelKey: 'actions.reinstate_user', adminOnly: true },
    { value: 'lock_object', labelKey: 'actions.lock_object' },
    { value: 'unlock_object', labelKey: 'actions.unlock_object' },
    { value: 'change_state', labelKey: 'actions.change_state' },
    { value: 'escalate', labelKey: 'actions.escalate' },
    { value: 'close_thread', labelKey: 'actions.close_thread' }
]

const confidenceLevels = [
    { value: '', labelKey: 'confidencesDesc.notSpecified' },
    { value: 'confident', labelKey: 'confidencesDesc.confident' },
    { value: 'provisional', labelKey: 'confidencesDesc.provisional' },
    { value: 'contested', labelKey: 'confidencesDesc.contested' }
]

const stateOptions = [
    { value: '', labelKey: 'states.noChange' },
    { value: 'ACTIVE', labelKey: 'states.ACTIVE' },
    { value: 'UNDER_REVIEW', labelKey: 'states.UNDER_REVIEW' },
    { value: 'CONTESTED', labelKey: 'states.CONTESTED' },
    { value: 'REVOKED', labelKey: 'states.REVOKED' }
]

export function NewMessageForm({ threadId, isAdmin, currentState, onSuccess }: NewMessageFormProps) {
    const t = useTranslations('Coordination')
    const [messageType, setMessageType] = useState('NOTE')
    const [content, setContent] = useState('')
    const [actionType, setActionType] = useState('')
    const [newState, setNewState] = useState('')
    const [decisionConfidence, setDecisionConfidence] = useState('')
    const [reviewPending, setReviewPending] = useState(false)
    const [reviewPendingHours, setReviewPendingHours] = useState<number | undefined>()
    const [submitting, setSubmitting] = useState(false)
    const [expanded, setExpanded] = useState(false)

    const { showToast } = useToast()

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!content.trim()) {
            showToast(t('form.contentRequired'), 'error')
            return
        }

        setSubmitting(true)
        try {
            const response = await fetch(`/api/coordination/${threadId}/messages`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    messageType,
                    content: content.trim(),
                    actionType: actionType || undefined,
                    newState: newState || undefined,
                    decisionConfidence: decisionConfidence || undefined,
                    reviewPending,
                    reviewPendingHours
                })
            })
            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || t('loadError'))
            }

            // Reset form
            setContent('')
            setActionType('')
            setNewState('')
            setDecisionConfidence('')
            setReviewPending(false)
            setReviewPendingHours(undefined)
            setExpanded(false)

            onSuccess()
            showToast(t('form.messageAddedSuccess'), 'success')
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setSubmitting(false)
        }
    }

    const selectedType = messageTypes.find(t => t.value === messageType)

    return (
        <form onSubmit={handleSubmit} className="p-4 space-y-4">
            {/* Message Type Selector */}
            <div className="flex flex-wrap gap-2">
                {messageTypes.map((type) => {
                    const Icon = type.icon
                    return (
                        <button
                            key={type.value}
                            type="button"
                            onClick={() => setMessageType(type.value)}
                            className={cn(
                                'flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors',
                                messageType === type.value
                                    ? 'bg-primary text-white'
                                    : 'bg-gray-100 text-text-light dark:bg-dark-border dark:text-dark-text-muted hover:bg-gray-200 dark:hover:bg-dark-border/70'
                            )}
                        >
                            <Icon className="w-4 h-4" />
                            {t(type.labelKey as any)}
                        </button>
                    )
                })}
            </div>

            {/* Content */}
            <textarea
                placeholder={selectedType ? t(selectedType.descriptionKey as any) : t('form.enterMessage')}
                value={content}
                onChange={(e) => setContent(e.target.value)}
                className="w-full p-3 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text resize-none focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none"
                rows={3}
            />

            {/* Advanced Options Toggle */}
            <button
                type="button"
                onClick={() => setExpanded(!expanded)}
                className="flex items-center gap-2 text-sm text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text"
            >
                <ChevronDown className={cn('w-4 h-4 transition-transform', expanded && 'rotate-180')} />
                {expanded ? t('form.hideOptions') : t('form.showOptions')}
            </button>

            {/* Advanced Options */}
            {expanded && (
                <div className="space-y-4 p-4 bg-gray-50 dark:bg-dark-border/30 rounded-lg">
                    {/* Action Type */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('form.actionOptional')}
                        </label>
                        <select
                            value={actionType}
                            onChange={(e) => setActionType(e.target.value)}
                            className="select-input"
                        >
                            {actionTypes
                                .filter(a => isAdmin || !a.adminOnly)
                                .map(action => (
                                    <option key={action.value} value={action.value}>
                                        {t(action.labelKey as any)}
                                    </option>
                                ))
                            }
                        </select>
                    </div>

                    {/* State Change */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('form.changeStateOptional')}
                        </label>
                        <select
                            value={newState}
                            onChange={(e) => setNewState(e.target.value)}
                            className="select-input"
                        >
                            {stateOptions.map(state => (
                                <option
                                    key={state.value}
                                    value={state.value}
                                    disabled={state.value === currentState}
                                >
                                    {t(state.labelKey as any)} {state.value === currentState ? t('states.current') : ''}
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* Decision Confidence (only for DECISION type) */}
                    {messageType === 'DECISION' && (
                        <>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                                    {t('form.decisionConfidence')}
                                </label>
                                <select
                                    value={decisionConfidence}
                                    onChange={(e) => setDecisionConfidence(e.target.value)}
                                    className="select-input"
                                >
                                    {confidenceLevels.map(level => (
                                        <option key={level.value} value={level.value}>
                                            {t(level.labelKey as any)}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Review Pending */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={reviewPending}
                                        onChange={(e) => setReviewPending(e.target.checked)}
                                        className="rounded border-gray-300 dark:border-dark-border"
                                    />
                                    <span className="text-sm text-text dark:text-dark-text">
                                        {t('form.markAsPending')}
                                    </span>
                                </label>
                                {reviewPending && (
                                    <div className="ml-6">
                                        <label className="block text-sm text-text-light dark:text-dark-text-muted mb-1">
                                            {t('form.reviewWindow')}
                                        </label>
                                        <input
                                            type="number"
                                            min={1}
                                            max={168}
                                            value={reviewPendingHours || ''}
                                            onChange={(e) => setReviewPendingHours(e.target.value ? parseInt(e.target.value) : undefined)}
                                            placeholder="e.g., 24"
                                            className="w-32 px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text"
                                        />
                                    </div>
                                )}
                            </div>
                        </>
                    )}
                </div>
            )}

            {/* Submit Button */}
            <div className="flex justify-end">
                <Button type="submit" disabled={submitting || !content.trim()}>
                    {submitting ? (
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : (
                        <Send className="w-4 h-4 mr-2" />
                    )}
                    {t('form.addMessage', { type: selectedType ? t(selectedType.labelKey as any) : t('types.post') })}
                </Button>
            </div>
        </form>
    )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import {
    X,
    FileText,
    User,
    MessagesSquare,
    AlertTriangle,
    MessageSquareWarning,
    Calendar,
    Loader2,
    Search,
    Check
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { useTranslations } from 'next-intl'

interface NewThreadDialogProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    onSuccess: () => void
    // Optional pre-selected object
    preSelectedType?: string
    preSelectedId?: string
    preSelectedTitle?: string
}

interface SearchResult {
    id: string
    title: string
    subtitle?: string
}

const objectTypes = [
    { value: 'post', labelKey: 'types.post', icon: FileText, table: 'posts', titleField: 'title' },
    { value: 'user', labelKey: 'types.user', icon: User, table: 'users', titleField: 'name' },
    { value: 'report', labelKey: 'types.report', icon: AlertTriangle, table: 'reports', titleField: 'reason' },
    { value: 'appeal', labelKey: 'types.appeal', icon: MessageSquareWarning, table: 'moderation_appeals', titleField: 'dispute_reason' },
    { value: 'event', labelKey: 'types.event', icon: Calendar, table: 'events', titleField: 'title' },
    { value: 'resource', labelKey: 'types.resource', icon: FileText, table: 'resources', titleField: 'title' }
]

const priorities = [
    { value: 'low', labelKey: 'low', color: 'bg-gray-100 text-gray-600' },
    { value: 'normal', labelKey: 'normal', color: 'bg-blue-100 text-blue-700' },
    { value: 'high', labelKey: 'high', color: 'bg-orange-100 text-orange-700' },
    { value: 'urgent', labelKey: 'urgent', color: 'bg-red-100 text-red-700' }
]

export function NewThreadDialog({
    open,
    onOpenChange,
    onSuccess,
    preSelectedType,
    preSelectedId,
    preSelectedTitle
}: NewThreadDialogProps) {
    const [objectType, setObjectType] = useState(preSelectedType || 'post')
    const t = useTranslations('Coordination')
    const tCommon = useTranslations('Common')

    const [selectedObject, setSelectedObject] = useState<SearchResult | null>(
        preSelectedId ? { id: preSelectedId, title: preSelectedTitle || t('selectedObject') } : null
    )
    const [searchQuery, setSearchQuery] = useState('')
    const [searchResults, setSearchResults] = useState<SearchResult[]>([])
    const [searching, setSearching] = useState(false)
    const [showResults, setShowResults] = useState(false)

    const [title, setTitle] = useState('')
    const [description, setDescription] = useState('')
    const [priority, setPriority] = useState('normal')
    const [initialMessage, setInitialMessage] = useState('')
    const [submitting, setSubmitting] = useState(false)

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()

    // Reset selected object when type changes
    useEffect(() => {
        if (!preSelectedId) {
            setSelectedObject(null)
            setSearchQuery('')
            setSearchResults([])
        }
    }, [objectType, preSelectedId])

    // Search for objects
    useEffect(() => {
        const searchObjects = async () => {
            if (searchQuery.length < 2) {
                setSearchResults([])
                return
            }

            setSearching(true)
            try {
                const typeConfig = objectTypes.find(t => t.value === objectType)
                if (!typeConfig) return

                let query = supabase
                    .from(typeConfig.table)
                    .select('id, ' + typeConfig.titleField)
                    .limit(10)

                // Add search filter based on type
                if (typeConfig.value === 'user') {
                    query = query.or(`name.ilike.%${searchQuery}%,email.ilike.%${searchQuery}%`)
                } else if (typeConfig.value === 'report') {
                    query = query.ilike('reason', `%${searchQuery}%`)
                } else if (typeConfig.value === 'appeal') {
                    query = query.ilike('dispute_reason', `%${searchQuery}%`)
                } else {
                    query = query.ilike(typeConfig.titleField, `%${searchQuery}%`)
                }

                const { data, error } = await query

                if (error) {
                    console.error('Search error:', error)
                    return
                }

                const results: SearchResult[] = (data || []).map((item: any) => ({
                    id: item.id,
                    title: item[typeConfig.titleField] || 'Untitled',
                    subtitle: item.email // For users
                }))

                setSearchResults(results)
            } catch (error) {
                console.error('Search error:', error)
            } finally {
                setSearching(false)
            }
        }

        const debounce = setTimeout(searchObjects, 300)
        return () => clearTimeout(debounce)
    }, [searchQuery, objectType, supabase])

    const handleSelectObject = (result: SearchResult) => {
        setSelectedObject(result)
        setSearchQuery('')
        setShowResults(false)
        // Auto-fill title if empty
        if (!title) {
            setTitle(`${t('reviewTitlePrefix')}${result.title.substring(0, 50)}${result.title.length > 50 ? '...' : ''}`)
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!selectedObject || !title.trim()) {
            showToast(t('selectObjectAndTitle'), 'error')
            return
        }

        setSubmitting(true)
        try {
            const response = await fetch('/api/coordination', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    objectType,
                    objectId: selectedObject.id,
                    title: title.trim(),
                    description: description.trim() || undefined,
                    priority,
                    initialMessage: initialMessage.trim() || undefined,
                    initialMessageType: 'NOTE'
                })
            })
            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || t('loadError'))
            }

            onSuccess()
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setSubmitting(false)
        }
    }

    if (!open) return null

    const currentTypeConfig = objectTypes.find(t => t.value === objectType)
    const TypeIcon = currentTypeConfig?.icon || FileText

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
            <div className="bg-white dark:bg-dark-surface rounded-xl w-full max-w-lg mx-4 max-h-[90vh] overflow-y-auto">
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-gray-100 dark:border-dark-border">
                    <h2 className="text-lg font-semibold text-text dark:text-dark-text">
                        {t('newCoordinationThread')}
                    </h2>
                    <button
                        onClick={() => onOpenChange(false)}
                        className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors outline-none"
                    >
                        <X className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-4 space-y-4">
                    {/* Object Type */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                            {t('objectType')}
                        </label>
                        <div className="grid grid-cols-3 gap-2">
                            {objectTypes.map((type) => {
                                const Icon = type.icon
                                return (
                                    <button
                                        key={type.value}
                                        type="button"
                                        onClick={() => setObjectType(type.value)}
                                        disabled={!!preSelectedType}
                                        className={cn(
                                            'flex flex-col items-center gap-1 p-3 rounded-lg text-sm transition-colors',
                                            objectType === type.value
                                                ? 'bg-primary text-white'
                                                : 'bg-gray-100 text-text-light dark:bg-dark-border dark:text-dark-text-muted hover:bg-gray-200 dark:hover:bg-dark-border/70',
                                            preSelectedType && 'opacity-50 cursor-not-allowed'
                                        )}
                                    >
                                        <Icon className="w-5 h-5" />
                                        {t(type.labelKey as any)}
                                    </button>
                                )
                            })}
                        </div>
                    </div>

                    {/* Object Search */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('searchObject', { type: t(currentTypeConfig?.labelKey as any) })}
                        </label>

                        {selectedObject ? (
                            <div className="flex items-center justify-between p-3 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg">
                                <div className="flex items-center gap-2">
                                    <Check className="w-4 h-4 text-green-600 dark:text-green-400" />
                                    <div>
                                        <p className="text-sm font-medium text-green-800 dark:text-green-200 truncate max-w-[280px]">
                                            {selectedObject.title}
                                        </p>
                                        <p className="text-xs text-green-600 dark:text-green-400 font-mono">
                                            {selectedObject.id.substring(0, 8)}...
                                        </p>
                                    </div>
                                </div>
                                {!preSelectedId && (
                                    <button
                                        type="button"
                                        onClick={() => setSelectedObject(null)}
                                        className="text-xs text-green-700 dark:text-green-300 hover:underline"
                                    >
                                        {t('change')}
                                    </button>
                                )}
                            </div>
                        ) : (
                            <div className="relative">
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                    <input
                                        type="text"
                                        placeholder={t('searchPlaceholder', { type: t(currentTypeConfig?.labelKey as any) })}
                                        value={searchQuery}
                                        onChange={(e) => {
                                            setSearchQuery(e.target.value)
                                            setShowResults(true)
                                        }}
                                        onFocus={() => setShowResults(true)}
                                        className="w-full pl-10 pr-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text outline-none focus:ring-2 focus:ring-primary/20"
                                    />
                                    {searching && (
                                        <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-text-light" />
                                    )}
                                </div>

                                {/* Search Results */}
                                {showResults && searchResults.length > 0 && (
                                    <div className="absolute z-10 w-full mt-1 bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-lg shadow-lg max-h-48 overflow-y-auto">
                                        {searchResults.map((result) => (
                                            <button
                                                key={result.id}
                                                type="button"
                                                onClick={() => handleSelectObject(result)}
                                                className="w-full px-3 py-2 text-left hover:bg-gray-50 dark:hover:bg-dark-border transition-colors"
                                            >
                                                <p className="text-sm text-text dark:text-dark-text truncate">
                                                    {result.title}
                                                </p>
                                                {result.subtitle && (
                                                    <p className="text-xs text-text-light dark:text-dark-text-muted">
                                                        {result.subtitle}
                                                    </p>
                                                )}
                                                <p className="text-xs text-text-light dark:text-dark-text-muted font-mono">
                                                    {result.id.substring(0, 8)}...
                                                </p>
                                            </button>
                                        ))}
                                    </div>
                                )}

                                {showResults && searchQuery.length >= 2 && searchResults.length === 0 && !searching && (
                                    <div className="absolute z-10 w-full mt-1 bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-lg shadow-lg p-3">
                                        <p className="text-sm text-text-light dark:text-dark-text-muted text-center">
                                            {t('noObjectsFound', { type: t(currentTypeConfig?.labelKey as any) })}
                                        </p>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                    {/* Title */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('threadTitle')}
                        </label>
                        <input
                            type="text"
                            placeholder={t('threadTitlePlaceholder')}
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text outline-none focus:ring-2 focus:ring-primary/20"
                        />
                    </div>

                    {/* Description */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('descriptionOptional')}
                        </label>
                        <textarea
                            placeholder={t('descriptionPlaceholder')}
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text resize-none outline-none focus:ring-2 focus:ring-primary/20"
                            rows={2}
                        />
                    </div>

                    {/* Priority */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                            {t('priority')}
                        </label>
                        <div className="flex gap-2">
                            {priorities.map((p) => (
                                <button
                                    key={p.value}
                                    type="button"
                                    onClick={() => setPriority(p.value)}
                                    className={cn(
                                        'px-3 py-1.5 rounded-lg text-sm font-medium transition-colors',
                                        priority === p.value
                                            ? p.color
                                            : 'bg-gray-50 text-text-light dark:bg-dark-border dark:text-dark-text-muted'
                                    )}
                                >
                                    {t(p.labelKey as any)}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Initial Message */}
                    <div>
                        <label className="block text-sm font-medium text-text dark:text-dark-text mb-1">
                            {t('initialMessageOptional')}
                        </label>
                        <textarea
                            placeholder={t('initialMessagePlaceholder')}
                            value={initialMessage}
                            onChange={(e) => setInitialMessage(e.target.value)}
                            className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text resize-none outline-none focus:ring-2 focus:ring-primary/20"
                            rows={3}
                        />
                    </div>

                    {/* Actions */}
                    <div className="flex gap-2 justify-end pt-2">
                        <Button type="button" variant="ghost" onClick={() => onOpenChange(false)}>
                            {tCommon('cancel')}
                        </Button>
                        <Button type="submit" disabled={submitting || !selectedObject || !title.trim()}>
                            {submitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                            {t('createThread')}
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useToast } from '@/components/ui/toast'
import {
    ArrowLeft,
    FileText,
    User,
    MessagesSquare,
    AlertTriangle,
    MessageSquareWarning,
    Calendar,
    Clock,
    Archive,
    ChevronDown,
    Send,
    Loader2,
    Shield,
    Flag,
    CheckCircle,
    XCircle,
    HelpCircle,
    ArrowUpRight
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { format, formatDistanceToNow } from 'date-fns'
import { cn } from '@/lib/utils'
import { NewMessageForm } from './NewMessageForm'
import { useTranslations } from 'next-intl'

interface ThreadMessage {
    id: string
    author_id: string
    author_name: string | null
    author_role: string
    message_type: string
    content: string
    action_type: string | null
    action_data: any
    action_executed: boolean
    action_executed_at: string | null
    action_result: any
    decision_confidence: string | null
    review_pending: boolean
    review_pending_until: string | null
    review_completed_at: string | null
    old_state: string | null
    new_state: string | null
    version: number
    is_current_version: boolean
    created_at: string
}

interface Thread {
    id: string
    object_type: string
    object_id: string
    title: string
    description: string | null
    object_state: string
    priority: string
    trigger_event: string
    created_by: string
    created_by_name: string | null
    archived_at: string | null
    archive_reason: string | null
    created_at: string
    updated_at: string
}

interface ThreadViewProps {
    threadId: string
    isAdmin: boolean
    onBack: () => void
}

const messageTypeConfig: Record<string, { icon: typeof FileText; color: string; labelKey: string }> = {
    NOTE: { icon: FileText, color: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300', labelKey: 'messageTypes.note' },
    FLAG: { icon: Flag, color: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300', labelKey: 'messageTypes.flag' },
    DECISION: { icon: CheckCircle, color: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300', labelKey: 'messageTypes.decision' },
    RATIONALE: { icon: HelpCircle, color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300', labelKey: 'messageTypes.rationale' },
    REQUEST_REVIEW: { icon: ArrowUpRight, color: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300', labelKey: 'messageTypes.request_review' }
}

const objectTypeIcons: Record<string, typeof FileText> = {
    post: FileText,
    user: User,
    comment: MessagesSquare,
    report: AlertTriangle,
    appeal: MessageSquareWarning,
    event: Calendar,
    resource: FileText
}

const stateColors: Record<string, string> = {
    ACTIVE: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300',
    UNDER_REVIEW: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300',
    CONTESTED: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300',
    REVOKED: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300',
    ARCHIVED: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300'
}

const confidenceColors: Record<string, string> = {
    confident: 'text-green-600 dark:text-green-400',
    provisional: 'text-yellow-600 dark:text-yellow-400',
    contested: 'text-red-600 dark:text-red-400'
}

export function ThreadView({ threadId, isAdmin, onBack }: ThreadViewProps) {
    const [thread, setThread] = useState<Thread | null>(null)
    const [messages, setMessages] = useState<ThreadMessage[]>([])
    const [loading, setLoading] = useState(true)
    const [archiving, setArchiving] = useState(false)
    const [showArchiveDialog, setShowArchiveDialog] = useState(false)
    const [archiveReason, setArchiveReason] = useState('')

    const supabase = useMemo(() => createClient(), [])
    const { showToast } = useToast()
    const t = useTranslations('Coordination')

    const loadThread = useCallback(async () => {
        setLoading(true)
        try {
            const response = await fetch(`/api/coordination/${threadId}`)
            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || t('loadError'))
            }

            setThread(data.thread)
            setMessages(data.messages || [])
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setLoading(false)
        }
    }, [threadId, t, showToast])

    useEffect(() => {
        loadThread()
    }, [threadId, loadThread])


    const handleArchive = async () => {
        if (!isAdmin) return

        setArchiving(true)
        try {
            const response = await fetch(`/api/coordination/${threadId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'archive', reason: archiveReason })
            })
            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || t('loadError'))
            }

            showToast(t('archiveSuccess'), 'success')
            onBack()
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setArchiving(false)
            setShowArchiveDialog(false)
        }
    }

    const handleMessageAdded = () => {
        loadThread()
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-6 h-6 animate-spin text-primary" />
            </div>
        )
    }

    if (!thread) {
        return (
            <div className="text-center py-12">
                <p className="text-text-light dark:text-dark-text-muted">{t('threadNotFound')}</p>
                <Button variant="ghost" onClick={onBack} className="mt-4">
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    {t('backToThreads')}
                </Button>
            </div>
        )
    }

    const ObjectIcon = objectTypeIcons[thread.object_type] || FileText

    const getStateLabel = (state: string) => {
        switch (state) {
            case 'UNDER_REVIEW': return t('underReview')
            case 'CONTESTED': return t('contested')
            case 'REVOKED': return t('revoked')
            case 'ACTIVE': return t('active')
            case 'ARCHIVED': return t('archived')
            default: return state.replace('_', ' ')
        }
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                    <Button variant="ghost" size="sm" onClick={onBack} className="mb-2 -ml-2">
                        <ArrowLeft className="w-4 h-4 mr-2" />
                        {t('backToThreads')}
                    </Button>
                    <div className="flex items-center gap-2 mb-2">
                        <ObjectIcon className="w-5 h-5 text-text-light dark:text-dark-text-muted" />
                        <span className={cn('px-2 py-0.5 rounded-full text-xs font-medium', stateColors[thread.object_state])}>
                            {getStateLabel(thread.object_state)}
                        </span>
                        {thread.archived_at && (
                            <span className="flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300">
                                <Archive className="w-3 h-3" />
                                {t('archived')}
                            </span>
                        )}
                    </div>
                    <h2 className="text-xl font-display font-semibold text-text dark:text-dark-text">
                        {thread.title}
                    </h2>
                    {thread.description && (
                        <p className="text-sm text-text-light dark:text-dark-text-muted mt-1">
                            {thread.description}
                        </p>
                    )}
                    <p className="text-xs text-text-light dark:text-dark-text-muted mt-2">
                        {t('createdWithMessages', {
                            name: thread.created_by_name || t('system'),
                            count: messages.length,
                            date: format(new Date(thread.created_at), 'PPP')
                        })}
                    </p>
                </div>
                {isAdmin && !thread.archived_at && (
                    <Button variant="outline" size="sm" onClick={() => setShowArchiveDialog(true)}>
                        <Archive className="w-4 h-4 mr-2" />
                        {t('archiveThread')}
                    </Button>
                )}
            </div>

            {/* Timeline */}
            <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-dark-border">
                    <h3 className="font-medium text-text dark:text-dark-text flex items-center gap-2">
                        <MessagesSquare className="w-4 h-4" />
                        {t('timeline')} {t('entries', { count: messages.length })}
                    </h3>
                </div>

                <div className="divide-y divide-gray-100 dark:divide-dark-border">
                    {messages.map((message, index) => {
                        const config = messageTypeConfig[message.message_type] || messageTypeConfig.NOTE
                        const TypeIcon = config.icon

                        return (
                            <div key={message.id} className="p-4">
                                {/* State change indicator */}
                                {message.old_state && message.new_state && message.old_state !== message.new_state && (
                                    <div className="mb-3 flex items-center justify-center">
                                        <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-gray-50 dark:bg-dark-border text-xs">
                                            <span className={cn('px-1.5 py-0.5 rounded', stateColors[message.old_state])}>
                                                {getStateLabel(message.old_state)}
                                            </span>
                                            <span className="text-text-light dark:text-dark-text-muted">ΓåÆ</span>
                                            <span className={cn('px-1.5 py-0.5 rounded', stateColors[message.new_state])}>
                                                {getStateLabel(message.new_state)}
                                            </span>
                                        </div>
                                    </div>
                                )}

                                <div className="flex items-start gap-3">
                                    <div className="flex-shrink-0 mt-1">
                                        <div className={cn('w-8 h-8 rounded-full flex items-center justify-center', config.color)}>
                                            <TypeIcon className="w-4 h-4" />
                                        </div>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="font-medium text-text dark:text-dark-text">
                                                {message.author_name || t('unknown')}
                                            </span>
                                            <span className={cn('px-1.5 py-0.5 rounded text-xs', config.color)}>
                                                {t(config.labelKey as any)}
                                            </span>
                                            {message.decision_confidence && (
                                                <span className={cn('text-xs font-medium', confidenceColors[message.decision_confidence])}>
                                                    ({t(`confidences.${message.decision_confidence}` as any)})
                                                </span>
                                            )}
                                            {message.review_pending && (
                                                <span className="px-1.5 py-0.5 rounded text-xs bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300">
                                                    ΓÅ│ {t('reviewPending')}
                                                </span>
                                            )}
                                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                {formatDistanceToNow(new Date(message.created_at), { addSuffix: true })}
                                            </span>
                                        </div>
                                        <p className="text-text dark:text-dark-text whitespace-pre-wrap">
                                            {message.content}
                                        </p>
                                        {message.action_type && (
                                            <div className="mt-2 p-2 rounded bg-gray-50 dark:bg-dark-border text-sm">
                                                <span className="font-medium text-text dark:text-dark-text">
                                                    {t('action')}: {message.action_type.replace(/_/g, ' ')}
                                                </span>
                                                {message.action_executed && (
                                                    <span className="ml-2 text-green-600 dark:text-green-400">Γ£ô {t('executed')}</span>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )
                    })}
                </div>

                {/* New Message Form */}
                {!thread.archived_at && (
                    <div className="border-t border-gray-100 dark:border-dark-border">
                        <NewMessageForm
                            threadId={threadId}
                            isAdmin={isAdmin}
                            currentState={thread.object_state}
                            onSuccess={handleMessageAdded}
                        />
                    </div>
                )}
            </div>

            {/* Archive Dialog */}
            {showArchiveDialog && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
                    <div className="bg-white dark:bg-dark-surface rounded-xl p-6 w-full max-w-md mx-4">
                        <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-2">
                            {t('archiveThread')}
                        </h3>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                            {t('archiveDescription')}
                        </p>
                        <textarea
                            placeholder={t('archiveReasonPlaceholder')}
                            value={archiveReason}
                            onChange={(e) => setArchiveReason(e.target.value)}
                            className="w-full p-3 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text mb-4 resize-none outline-none focus:ring-2 focus:ring-primary/20"
                            rows={3}
                        />
                        <div className="flex gap-2 justify-end">
                            <Button variant="ghost" onClick={() => setShowArchiveDialog(false)}>
                                {t('Common.cancel' as any)}
                            </Button>
                            <Button onClick={handleArchive} disabled={archiving}>
                                {archiving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                                {t('archiveThread')}
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useTranslations } from 'next-intl'
import { Plus, Edit2, Trash2, Layers, Database, ChevronRight, Loader2, X, Save, AlertCircle } from 'lucide-react'
import { SchemaRegistry, SchemaField, SchemaItem, ContentType } from '@/types'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { useToast } from '@/components/ui/toast'

const CONTENT_TYPES: ContentType[] = ['article', 'question', 'answer', 'resource', 'event', 'trace']
const FIELD_TYPES_NEEDING_REGISTRY = ['registry_ref', 'registry_ref_multi']
const FIELD_TYPES_NEEDING_OPTIONS = ['select', 'multiselect']

type EditMode = 'none' | 'registry' | 'item' | 'field'

interface EditState {
    mode: EditMode
    id?: string // for editing existing
    parentId?: string // for creating items under a registry
}

export function SchemaDashboard() {
    const t = useTranslations('Admin')
    const [registries, setRegistries] = useState<SchemaRegistry[]>([])
    const [fields, setFields] = useState<SchemaField[]>([])
    const [loading, setLoading] = useState(true)
    const [editState, setEditState] = useState<EditState>({ mode: 'none' })
    const { showToast } = useToast()

    useEffect(() => {
        loadData()
    }, [])

    async function loadData() {
        setLoading(true)
        try {
            const [regRes, fieldRes] = await Promise.all([
                fetch('/api/admin/schema?type=registries'),
                fetch('/api/admin/schema?type=fields')
            ])

            if (regRes.ok) {
                const { data } = await regRes.json()
                setRegistries(data || [])
            }
            if (fieldRes.ok) {
                const { data } = await fieldRes.json()
                setFields(data || [])
            }
        } catch (err) {
            console.error('Failed to load schema data', err)
        } finally {
            setLoading(false)
        }
    }

    async function handleDelete(type: 'registry' | 'item' | 'field', id: string) {
        if (!confirm(t(`schemaRegistry.${type}.deleteConfirm`))) return

        try {
            const res = await fetch('/api/admin/schema', {
                method: 'DELETE',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ type, id })
            })

            if (res.ok) {
                showToast(t(`schemaRegistry.${type}.deleted`), 'success')
                loadData()
            } else {
                const { error } = await res.json()
                showToast(error || t('schemaRegistry.actions.deleteFailed'), 'error')
            }
        } catch (err) {
            showToast(t('schemaRegistry.actions.deleteFailed'), 'error')
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center p-12">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="p-2.5 rounded-lg bg-primary/10 dark:bg-teal-900/50">
                        <Database className="w-6 h-6 text-primary dark:text-teal-400" />
                    </div>
                    <div>
                        <h1 className="text-2xl font-display font-bold text-primary dark:text-white">
                            {t('schemaRegistry.title')}
                        </h1>
                        <p className="text-sm text-text-light dark:text-gray-400">
                            {t('schemaRegistry.subtitle')}
                        </p>
                    </div>
                </div>
            </div>

            <Tabs defaultValue="registries" className="w-full">
                <TabsList className="mb-4 bg-gray-100 dark:bg-gray-800 p-1 rounded-lg">
                    <TabsTrigger value="registries" className="flex items-center gap-2 data-[state=active]:bg-white dark:data-[state=active]:bg-gray-700 dark:text-gray-300 dark:data-[state=active]:text-white rounded-md px-4 py-2">
                        <Database className="w-4 h-4" />
                        {t('schemaRegistry.tabs.registries')}
                    </TabsTrigger>
                    <TabsTrigger value="fields" className="flex items-center gap-2 data-[state=active]:bg-white dark:data-[state=active]:bg-gray-700 dark:text-gray-300 dark:data-[state=active]:text-white rounded-md px-4 py-2">
                        <Layers className="w-4 h-4" />
                        {t('schemaRegistry.tabs.fields')}
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="registries">
                    <div className="mb-4">
                        <Button onClick={() => setEditState({ mode: 'registry' })} className="gap-2 bg-primary hover:bg-primary-dark text-white">
                            <Plus className="w-4 h-4" /> {t('schemaRegistry.newRegistry')}
                        </Button>
                    </div>
                    <div className="grid grid-cols-1 gap-4">
                        {registries.map(reg => (
                            <RegistryCard
                                key={reg.id}
                                registry={reg}
                                onEdit={() => setEditState({ mode: 'registry', id: reg.id })}
                                onDelete={() => handleDelete('registry', reg.id)}
                                onAddItem={() => setEditState({ mode: 'item', parentId: reg.id })}
                                onEditItem={(itemId) => setEditState({ mode: 'item', id: itemId, parentId: reg.id })}
                                onDeleteItem={(itemId) => handleDelete('item', itemId)}
                            />
                        ))}
                        {registries.length === 0 && (
                            <div className="card p-8 text-center">
                                <Database className="w-12 h-12 mx-auto text-text-light dark:text-gray-500 mb-3" />
                                <p className="text-text-light dark:text-gray-400">{t('schemaRegistry.noRegistries')}</p>
                            </div>
                        )}
                    </div>
                </TabsContent>

                <TabsContent value="fields">
                    <div className="mb-4">
                        <Button onClick={() => setEditState({ mode: 'field' })} className="gap-2 bg-primary hover:bg-primary-dark text-white">
                            <Plus className="w-4 h-4" /> {t('schemaRegistry.newField')}
                        </Button>
                    </div>
                    <div className="grid grid-cols-1 gap-4">
                        {fields.map(field => (
                            <FieldCard
                                key={field.id}
                                field={field}
                                onEdit={() => setEditState({ mode: 'field', id: field.id })}
                                onDelete={() => handleDelete('field', field.id)}
                            />
                        ))}
                        {fields.length === 0 && (
                            <div className="card p-8 text-center">
                                <Layers className="w-12 h-12 mx-auto text-text-light dark:text-gray-500 mb-3" />
                                <p className="text-text-light dark:text-gray-400">{t('schemaRegistry.noFields')}</p>
                            </div>
                        )}
                    </div>
                </TabsContent>
            </Tabs>

            {/* Edit Modal */}
            {editState.mode !== 'none' && (
                <EditModal
                    mode={editState.mode}
                    id={editState.id}
                    parentId={editState.parentId}
                    registries={registries}
                    fields={fields}
                    onClose={() => setEditState({ mode: 'none' })}
                    onSaved={() => {
                        setEditState({ mode: 'none' })
                        loadData()
                    }}
                />
            )}
        </div>
    )
}

interface RegistryCardProps {
    registry: SchemaRegistry
    onEdit: () => void
    onDelete: () => void
    onAddItem: () => void
    onEditItem: (id: string) => void
    onDeleteItem: (id: string) => void
}

function RegistryCard({ registry, onEdit, onDelete, onAddItem, onEditItem, onDeleteItem }: RegistryCardProps) {
    const t = useTranslations('Admin')
    const [expanded, setExpanded] = useState(false)

    return (
        <div className="card card-hover p-5">
            <div className="flex items-start justify-between mb-3">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-display font-semibold text-lg text-primary dark:text-white">
                            {registry.display_name}
                        </h3>
                        <span className="px-2 py-0.5 text-xs bg-primary/10 dark:bg-teal-800/50 text-primary dark:text-teal-300 rounded-full font-mono">
                            {registry.registry_key}
                        </span>
                    </div>
                    <p className="text-sm text-text-light dark:text-gray-300">
                        {registry.description}
                    </p>
                </div>
                <div className="flex items-center gap-1">
                    <Button variant="ghost" size="sm" onClick={onEdit} title="Edit registry" className="text-text-light dark:text-gray-400 hover:text-primary dark:hover:text-white">
                        <Edit2 className="w-4 h-4" />
                    </Button>
                    <Button variant="ghost" size="sm" onClick={onDelete} title="Delete registry" className="text-text-light dark:text-gray-400 hover:text-accent dark:hover:text-red-400">
                        <Trash2 className="w-4 h-4" />
                    </Button>
                </div>
            </div>

            <div className="mt-4 pt-4 border-t border-gray-100 dark:border-dark-border">
                <div className="flex items-center justify-between mb-3">
                    <h4 className="text-xs font-semibold uppercase tracking-wider text-text-light dark:text-gray-400">
                        {t('schemaRegistry.registry.items')} ({registry.items?.length || 0})
                    </h4>
                    <div className="flex items-center gap-2">
                        <Button variant="ghost" size="sm" onClick={onAddItem} className="text-xs gap-1 text-primary dark:text-teal-400 hover:bg-primary/10">
                            <Plus className="w-3 h-3" /> {t('schemaRegistry.registry.addItem')}
                        </Button>
                        {(registry.items?.length || 0) > 4 && (
                            <button onClick={() => setExpanded(!expanded)} className="text-xs text-primary dark:text-teal-400 hover:underline font-medium">
                                {expanded ? t('schemaRegistry.registry.showLess') : t('schemaRegistry.registry.showAll')}
                            </button>
                        )}
                    </div>
                </div>
                <div className="flex flex-wrap gap-2">
                    {registry.items?.sort((a, b) => a.sort_order - b.sort_order).slice(0, expanded ? undefined : 8).map(item => (
                        <div key={item.id} className="group flex items-center gap-1 px-2 py-1 text-xs bg-gray-50 dark:bg-gray-800 text-text dark:text-gray-200 rounded-md border border-gray-200 dark:border-gray-600 hover:border-primary/30 dark:hover:border-teal-500/50 transition-colors">
                            <span>{item.display_name}</span>
                            <button
                                onClick={() => onEditItem(item.id)}
                                className="opacity-0 group-hover:opacity-100 transition-opacity p-0.5 hover:bg-primary/10 rounded ml-0.5"
                            >
                                <Edit2 className="w-2.5 h-2.5 text-primary dark:text-teal-400" />
                            </button>
                            <button
                                onClick={() => onDeleteItem(item.id)}
                                className="opacity-0 group-hover:opacity-100 transition-opacity p-0.5 hover:bg-accent/10 rounded"
                            >
                                <Trash2 className="w-2.5 h-2.5 text-accent dark:text-red-400" />
                            </button>
                        </div>
                    ))}
                    {(!registry.items || registry.items.length === 0) && (
                        <p className="text-sm text-text-light dark:text-gray-400 italic">{t('schemaRegistry.registry.noItems')}</p>
                    )}
                </div>
            </div>
        </div>
    )
}

interface FieldCardProps {
    field: SchemaField
    onEdit: () => void
    onDelete: () => void
}

function FieldCard({ field, onEdit, onDelete }: FieldCardProps) {
    const t = useTranslations('Admin')
    const version = field.current_version

    return (
        <div className="card card-hover p-5">
            <div className="flex items-start justify-between">
                <div>
                    <div className="flex items-center gap-2 flex-wrap mb-2">
                        <h3 className="font-display font-semibold text-lg text-primary dark:text-white">
                            {version?.display_name || field.field_key}
                        </h3>
                        <span className="px-2 py-0.5 text-xs bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-300 rounded-full font-mono">
                            {field.field_key}
                        </span>
                        <span className="px-2 py-0.5 text-xs bg-gray-100 dark:bg-gray-700 text-text-light dark:text-gray-300 rounded-full">
                            v{version?.version}
                        </span>
                    </div>
                    <div className="flex items-center gap-4 text-sm text-text-light dark:text-gray-400">
                        <span className="flex items-center gap-1.5">
                            <span className="text-xs uppercase font-medium">{t('schemaRegistry.field.type')}:</span>
                            <code className="bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-text dark:text-gray-200">{t(`schemaRegistry.types.${version?.field_type}`)}</code>
                        </span>
                        <span className="flex items-center gap-1.5">
                            <span className="text-xs uppercase font-medium">{t('schemaRegistry.field.appliesTo')}:</span>
                            <span className="text-text dark:text-gray-200">{version?.applies_to?.map(ct => t(`schemaRegistry.contentTypes.${ct}`)).join(', ')}</span>
                        </span>
                        {version?.is_required && (
                            <span className="px-2 py-0.5 text-xs bg-accent/10 dark:bg-red-900/30 text-accent dark:text-red-400 rounded-full font-medium">{t('schemaRegistry.field.required')}</span>
                        )}
                    </div>
                    {version?.description && (
                        <p className="mt-2 text-sm text-text-light dark:text-gray-400">{version.description}</p>
                    )}
                </div>
                <div className="flex items-center gap-1">
                    <Button variant="ghost" size="sm" onClick={onEdit} title="Edit field" className="text-text-light dark:text-gray-400 hover:text-primary dark:hover:text-white">
                        <Edit2 className="w-4 h-4" />
                    </Button>
                    <Button variant="ghost" size="sm" onClick={onDelete} title="Delete field" className="text-text-light dark:text-gray-400 hover:text-accent dark:hover:text-red-400">
                        <Trash2 className="w-4 h-4" />
                    </Button>
                </div>
            </div>
        </div>
    )
}

interface EditModalProps {
    mode: 'registry' | 'item' | 'field'
    id?: string
    parentId?: string
    registries: SchemaRegistry[]
    fields: SchemaField[]
    onClose: () => void
    onSaved: () => void
}

function EditModal({ mode, id, parentId, registries, fields, onClose, onSaved }: EditModalProps) {
    const t = useTranslations('Admin')
    const [saving, setSaving] = useState(false)
    const [formData, setFormData] = useState<Record<string, any>>({})
    const { showToast } = useToast()
    const isNew = !id

    useEffect(() => {
        if (id) {
            // Load existing data
            if (mode === 'registry') {
                const reg = registries.find(r => r.id === id)
                if (reg) setFormData({ display_name: reg.display_name, registry_key: reg.registry_key, description: reg.description })
            } else if (mode === 'item') {
                const registry = registries.find(r => r.id === parentId)
                const item = registry?.items?.find(i => i.id === id)
                if (item) setFormData({ display_name: item.display_name, item_key: item.item_key, sort_order: item.sort_order })
            } else if (mode === 'field') {
                const field = fields.find(f => f.id === id)
                if (field) {
                    const v = field.current_version
                    setFormData({
                        field_key: field.field_key,
                        display_name: v?.display_name || '',
                        field_type: v?.field_type || 'text',
                        description: v?.description || '',
                        is_required: v?.is_required || false,
                        applies_to: v?.applies_to || ['article'],
                        registry_id: v?.registry_id || '',
                        options: v?.constraints?.options || []
                    })
                }
            }
        } else {
            // Defaults for new
            if (mode === 'registry') setFormData({ display_name: '', registry_key: '', description: '' })
            else if (mode === 'item') setFormData({ display_name: '', item_key: '', sort_order: 0, registry_id: parentId })
            else if (mode === 'field') setFormData({ field_key: '', display_name: '', field_type: 'text', description: '', is_required: false, applies_to: ['article'], registry_id: '', options: [] })
        }
    }, [id, mode, registries, fields, parentId])

    async function handleSave() {
        // Validation for field constraints
        if (mode === 'field') {
            const fieldType = formData.field_type
            if (FIELD_TYPES_NEEDING_REGISTRY.includes(fieldType) && !formData.registry_id) {
                showToast(t('schemaRegistry.field.errors.registry'), 'error')
                return
            }
            if (FIELD_TYPES_NEEDING_OPTIONS.includes(fieldType) && (!formData.options || formData.options.length === 0)) {
                showToast(t('schemaRegistry.field.errors.options'), 'error')
                return
            }
            if (!formData.applies_to || formData.applies_to.length === 0) {
                showToast(t('schemaRegistry.field.errors.appliesTo'), 'error')
                return
            }
        }

        setSaving(true)
        try {
            const action = isNew
                ? `create_${mode}`
                : `update_${mode}`

            // Build payload, moving options into constraints for fields
            const payload: any = { action, data: { ...formData } }
            if (mode === 'field') {
                // Move options into constraints object
                if (formData.options && formData.options.length > 0) {
                    payload.data.constraints = { options: formData.options }
                }
                delete payload.data.options
            }
            if (!isNew) payload.data.id = id
            if (mode === 'item' && parentId) payload.data.registry_id = parentId

            const res = await fetch('/api/admin/schema', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            })

            if (res.ok) {
                showToast(t(`schemaRegistry.${mode}.saved`), 'success')
                onSaved()
            } else {
                const { error } = await res.json()
                showToast(error || t('schemaRegistry.actions.saveFailed'), 'error')
            }
        } catch (err) {
            showToast(t('schemaRegistry.actions.saveFailed'), 'error')
        } finally {
            setSaving(false)
        }
    }

    const title = isNew
        ? t(`schemaRegistry.${mode}.create`)
        : t(`schemaRegistry.${mode}.edit`)

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
            <div className="bg-white dark:bg-dark-surface rounded-xl p-6 w-full max-w-lg mx-4 shadow-2xl border border-gray-200 dark:border-dark-border max-h-[90vh] overflow-y-auto">
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-xl font-display font-semibold text-primary dark:text-dark-text capitalize">{title}</h2>
                    <Button variant="ghost" size="sm" onClick={onClose} className="text-text-light hover:text-text">
                        <X className="w-5 h-5" />
                    </Button>
                </div>

                <div className="space-y-4">
                    {mode === 'registry' && (
                        <>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.registry.displayName')}</label>
                                <Input value={formData.display_name || ''} onChange={e => setFormData(p => ({ ...p, display_name: e.target.value }))} placeholder="e.g. Research Domains" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.registry.key')}</label>
                                <Input value={formData.registry_key || ''} onChange={e => setFormData(p => ({ ...p, registry_key: e.target.value }))} disabled={!isNew} placeholder="e.g. research_domains" className="font-mono" />
                                {isNew && <p className="mt-1 text-xs text-text-light dark:text-dark-text-muted">{t('schemaRegistry.registry.keyHint')}</p>}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.registry.description')}</label>
                                <Textarea value={formData.description || ''} onChange={e => setFormData(p => ({ ...p, description: e.target.value }))} placeholder="Describe this registry..." />
                            </div>
                        </>
                    )}

                    {mode === 'item' && (
                        <>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.item.displayName')}</label>
                                <Input value={formData.display_name || ''} onChange={e => setFormData(p => ({ ...p, display_name: e.target.value }))} placeholder="e.g. Urban Planning" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.item.key')}</label>
                                <Input value={formData.item_key || ''} onChange={e => setFormData(p => ({ ...p, item_key: e.target.value }))} disabled={!isNew} placeholder="e.g. urban_planning" className="font-mono" />
                                {isNew && <p className="mt-1 text-xs text-text-light dark:text-dark-text-muted">{t('schemaRegistry.item.keyHint')}</p>}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.item.sortOrder')}</label>
                                <Input type="number" value={formData.sort_order || 0} onChange={e => setFormData(p => ({ ...p, sort_order: parseInt(e.target.value) || 0 }))} />
                                <p className="mt-1 text-xs text-text-light dark:text-dark-text-muted">{t('schemaRegistry.item.sortOrderHint')}</p>
                            </div>
                        </>
                    )}

                    {mode === 'field' && (
                        <>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.field.key')}</label>
                                <Input value={formData.field_key || ''} onChange={e => setFormData(p => ({ ...p, field_key: e.target.value }))} disabled={!isNew} placeholder="e.g. research_domain" className="font-mono" />
                                {isNew && <p className="mt-1 text-xs text-text-light dark:text-dark-text-muted">{t('schemaRegistry.field.keyHint')}</p>}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.field.displayName')}</label>
                                <Input value={formData.display_name || ''} onChange={e => setFormData(p => ({ ...p, display_name: e.target.value }))} placeholder="e.g. Research Domain" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.field.type')}</label>
                                <select
                                    value={formData.field_type || 'text'}
                                    onChange={e => setFormData(p => ({ ...p, field_type: e.target.value }))}
                                    className="select-input"
                                >
                                    <option value="text">{t('schemaRegistry.types.text')}</option>
                                    <option value="number">{t('schemaRegistry.types.number')}</option>
                                    <option value="boolean">{t('schemaRegistry.types.boolean')}</option>
                                    <option value="date">{t('schemaRegistry.types.date')}</option>
                                    <option value="datetime">{t('schemaRegistry.types.datetime')}</option>
                                    <option value="url">{t('schemaRegistry.types.url')}</option>
                                    <option value="rich_text">{t('schemaRegistry.types.rich_text')}</option>
                                    <option value="select">{t('schemaRegistry.types.select')}</option>
                                    <option value="multiselect">{t('schemaRegistry.types.multiselect')}</option>
                                    <option value="registry_ref">{t('schemaRegistry.types.registry_ref')}</option>
                                    <option value="registry_ref_multi">{t('schemaRegistry.types.registry_ref_multi')}</option>
                                    <option value="geo_point">{t('schemaRegistry.types.geo_point')}</option>
                                    <option value="geo_polygon">{t('schemaRegistry.types.geo_polygon')}</option>
                                    <option value="json">{t('schemaRegistry.types.json')}</option>
                                    <option value="file">{t('schemaRegistry.types.file')}</option>
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">{t('schemaRegistry.field.description')}</label>
                                <Textarea value={formData.description || ''} onChange={e => setFormData(p => ({ ...p, description: e.target.value }))} placeholder="Describe this field..." />
                            </div>
                            <div className="flex items-center gap-2 p-3 bg-gray-50 dark:bg-dark-bg rounded-lg">
                                <input
                                    type="checkbox"
                                    id="is_required"
                                    checked={formData.is_required || false}
                                    onChange={e => setFormData(p => ({ ...p, is_required: e.target.checked }))}
                                    className="w-4 h-4 rounded border-gray-300 text-primary focus:ring-primary dark:border-gray-600 dark:bg-gray-700 dark:ring-offset-gray-900 accent-primary"
                                />
                                <label htmlFor="is_required" className="text-sm text-text dark:text-dark-text font-medium">{t('schemaRegistry.field.required')}</label>
                            </div>

                            {/* Applies To - Content Type Selection */}
                            <div>
                                <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">{t('schemaRegistry.field.appliesTo')}</label>
                                <div className="flex flex-wrap gap-3 p-3 bg-gray-50 dark:bg-dark-bg rounded-lg">
                                    {CONTENT_TYPES.map(ct => (
                                        <label key={ct} className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={(formData.applies_to || []).includes(ct)}
                                                onChange={e => {
                                                    const current = formData.applies_to || []
                                                    const updated = e.target.checked
                                                        ? [...current, ct]
                                                        : current.filter((t: string) => t !== ct)
                                                    setFormData(p => ({ ...p, applies_to: updated }))
                                                }}
                                                className="w-4 h-4 rounded border-gray-300 text-primary focus:ring-primary dark:border-gray-600 dark:bg-gray-700 dark:ring-offset-gray-900 accent-primary"
                                            />
                                            <span className="text-sm text-text dark:text-dark-text capitalize">{t(`schemaRegistry.contentTypes.${ct}`)}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>

                            {/* Registry Picker - Only for registry_ref types */}
                            {FIELD_TYPES_NEEDING_REGISTRY.includes(formData.field_type) && (
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-1.5">
                                        {t('schemaRegistry.field.registry')} <span className="text-accent">*</span>
                                    </label>
                                    {registries.length === 0 ? (
                                        <div className="flex items-center gap-2 text-amber-600 dark:text-amber-400 text-sm p-3 bg-amber-50 dark:bg-amber-900/20 rounded-lg border border-amber-200 dark:border-amber-800">
                                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                                            {t('schemaRegistry.noRegistries')}
                                        </div>
                                    ) : (
                                        <select
                                            value={formData.registry_id || ''}
                                            onChange={e => setFormData(p => ({ ...p, registry_id: e.target.value }))}
                                            className="select-input"
                                        >
                                            <option value="">{t('schemaRegistry.types.select')}...</option>
                                            {registries.map(reg => (
                                                <option key={reg.id} value={reg.id}>
                                                    {reg.display_name} ({reg.registry_key})
                                                </option>
                                            ))}
                                        </select>
                                    )}
                                </div>
                            )}

                            {/* Options Editor - Only for select/multiselect types */}
                            {FIELD_TYPES_NEEDING_OPTIONS.includes(formData.field_type) && (
                                <div>
                                    <label className="block text-sm font-medium text-text dark:text-dark-text mb-2">
                                        {t('schemaRegistry.field.options')} <span className="text-red-500">*</span>
                                    </label>
                                    <div className="space-y-2">
                                        {(formData.options || []).map((opt: { value: string; label: string }, idx: number) => (
                                            <div key={idx} className="flex items-center gap-2">
                                                <Input
                                                    value={opt.value}
                                                    onChange={e => {
                                                        const opts = [...(formData.options || [])]
                                                        opts[idx] = { ...opts[idx], value: e.target.value }
                                                        setFormData(p => ({ ...p, options: opts }))
                                                    }}
                                                    placeholder={t('schemaRegistry.field.value')}
                                                    className="flex-1"
                                                />
                                                <Input
                                                    value={opt.label}
                                                    onChange={e => {
                                                        const opts = [...(formData.options || [])]
                                                        opts[idx] = { ...opts[idx], label: e.target.value }
                                                        setFormData(p => ({ ...p, options: opts }))
                                                    }}
                                                    placeholder={t('schemaRegistry.field.label')}
                                                    className="flex-1"
                                                />
                                                <Button
                                                    type="button"
                                                    variant="ghost"
                                                    size="sm"
                                                    onClick={() => {
                                                        const opts = (formData.options || []).filter((_: any, i: number) => i !== idx)
                                                        setFormData(p => ({ ...p, options: opts }))
                                                    }}
                                                    className="text-red-500 hover:text-red-600"
                                                >
                                                    <Trash2 className="w-4 h-4" />
                                                </Button>
                                            </div>
                                        ))}
                                        <Button
                                            type="button"
                                            variant="outline"
                                            size="sm"
                                            onClick={() => {
                                                const opts = [...(formData.options || []), { value: '', label: '' }]
                                                setFormData(p => ({ ...p, options: opts }))
                                            }}
                                            className="gap-1"
                                        >
                                            <Plus className="w-3 h-3" /> {t('schemaRegistry.field.addOption')}
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>

                <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-100 dark:border-dark-border">
                    <Button variant="ghost" onClick={onClose} className="text-text-light hover:text-text">{t('schemaRegistry.actions.cancel')}</Button>
                    <Button onClick={handleSave} disabled={saving} className="gap-2 bg-primary hover:bg-primary-dark text-white">
                        {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                        {saving ? t('schemaRegistry.actions.saving') : t('schemaRegistry.actions.save')}
                    </Button>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { TwoFactorVerify } from './TwoFactorVerify'
import { Loader2 } from 'lucide-react'

interface MFAGuardProps {
    children: React.ReactNode
    redirectTo?: string
}

/**
 * MFAGuard checks if the current session requires MFA verification.
 * If so, it shows the 2FA verification UI instead of children.
 * 
 * Use this component to wrap authenticated pages/content.
 */
export function MFAGuard({ children, redirectTo = '/insights' }: MFAGuardProps) {
    const [loading, setLoading] = useState(true)
    const [needsMFA, setNeedsMFA] = useState(false)
    const [factorId, setFactorId] = useState<string | null>(null)

    const supabase = createClient()
    const router = useRouter()

    const checkMFAStatus = useCallback(async () => {
        try {
            // Get the current session's assurance level
            const { data: { session } } = await supabase.auth.getSession()

            if (!session) {
                router.push('/auth/login')
                return
            }

            // Check MFA factors
            const { data: factorsData, error: factorsError } = await supabase.auth.mfa.listFactors()

            if (factorsError) {
                console.error('Error listing factors:', factorsError)
                setLoading(false)
                return
            }

            // Check if user has verified TOTP factors
            const verifiedFactors = factorsData?.totp?.filter(f => f.status === 'verified') || []

            if (verifiedFactors.length === 0) {
                // No MFA factors - user doesn't have 2FA enabled
                setLoading(false)
                return
            }

            // User has 2FA - check if current session is at AAL2
            const { data: aalData, error: aalError } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel()

            if (aalError) {
                console.error('Error getting AAL:', aalError)
                setLoading(false)
                return
            }

            if (aalData.currentLevel === 'aal1' && aalData.nextLevel === 'aal2') {
                // Session is at AAL1 but needs AAL2 - show MFA verification
                setNeedsMFA(true)
                setFactorId(verifiedFactors[0].id)
            }

            setLoading(false)
        } catch (err) {
            console.error('Error checking MFA status:', err)
            setLoading(false)
        }
    }, [supabase, router])

    useEffect(() => {
        void (async () => {
            await checkMFAStatus()
        })()
    }, [checkMFAStatus])

    function handleMFAVerified() {
        setNeedsMFA(false)
        router.refresh()
    }

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-background dark:bg-dark-bg">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    if (needsMFA && factorId) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-background dark:bg-dark-bg px-4">
                <TwoFactorVerify
                    factorId={factorId}
                    onVerified={handleMFAVerified}
                />
            </div>
        )
    }

    return <>{children}</>
}

'use client'

import Image from 'next/image'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useState, useEffect } from 'react'
import { useToast } from '@/components/ui/toast'
import { Shield, ShieldCheck, ShieldOff, Loader2, Copy, Check, AlertTriangle } from 'lucide-react'
import QRCode from 'qrcode'
import { useTranslations } from 'next-intl'

interface TwoFactorSetupProps {
    userId: string
    onEnrollmentComplete?: () => void
}

export function TwoFactorSetup({ userId, onEnrollmentComplete }: TwoFactorSetupProps) {
    const [loading, setLoading] = useState(true)
    const [enrolling, setEnrolling] = useState(false)
    const [verifying, setVerifying] = useState(false)
    const [unenrolling, setUnenrolling] = useState(false)
    const [isEnrolled, setIsEnrolled] = useState(false)
    const [factorId, setFactorId] = useState<string | null>(null)

    // Enrollment state
    const [qrCodeUrl, setQrCodeUrl] = useState<string | null>(null)
    const [secret, setSecret] = useState<string | null>(null)
    const [verificationCode, setVerificationCode] = useState('')
    const [copied, setCopied] = useState(false)

    const supabase = createClient()
    const { showToast } = useToast()
    const t = useTranslations('Settings.twoFactorSetup')

    // Check if user already has 2FA enrolled
    useEffect(() => {
        async function checkEnrollment() {
            setLoading(true)
            try {
                const { data, error } = await supabase.auth.mfa.listFactors()

                if (error) {
                    console.error('Error checking MFA factors:', error)
                    setLoading(false)
                    return
                }

                // Find verified TOTP factor
                const totpFactor = data?.totp?.find(f => f.status === 'verified')
                if (totpFactor) {
                    setIsEnrolled(true)
                    setFactorId(totpFactor.id)
                }
            } catch (err) {
                console.error('Error:', err)
            }
            setLoading(false)
        }

        checkEnrollment()
    }, [supabase])

    // Start enrollment process
    async function startEnrollment() {
        setEnrolling(true)
        try {
            const { data, error } = await supabase.auth.mfa.enroll({
                factorType: 'totp',
                friendlyName: t('authenticatorApp')
            })

            if (error) {
                showToast(error.message, 'error')
                setEnrolling(false)
                return
            }

            if (data?.totp?.qr_code) {
                // Generate QR code image from the URI
                const qrDataUrl = await QRCode.toDataURL(data.totp.uri)
                setQrCodeUrl(qrDataUrl)
                setSecret(data.totp.secret)
                setFactorId(data.id)
            }
        } catch (err) {
            showToast(t('failedToStart'), 'error')
        }
        setEnrolling(false)
    }

    // Verify the enrollment with a code
    async function verifyEnrollment() {
        if (!factorId || verificationCode.length !== 6) {
            showToast(t('enterCode'), 'error')
            return
        }

        setVerifying(true)
        try {
            const { data, error } = await supabase.auth.mfa.challengeAndVerify({
                factorId,
                code: verificationCode
            })

            if (error) {
                showToast(error.message, 'error')
                setVerifying(false)
                return
            }

            setIsEnrolled(true)
            setQrCodeUrl(null)
            setSecret(null)
            setVerificationCode('')
            showToast(t('codeVerified'), 'success')
            onEnrollmentComplete?.()
        } catch (err) {
            showToast(t('verifyFailed'), 'error')
        }
        setVerifying(false)
    }

    // Unenroll from 2FA
    async function unenroll() {
        if (!factorId) return

        setUnenrolling(true)
        try {
            const { error } = await supabase.auth.mfa.unenroll({ factorId })

            if (error) {
                showToast(error.message, 'error')
                setUnenrolling(false)
                return
            }

            setIsEnrolled(false)
            setFactorId(null)
            showToast(t('disabled'), 'success')
        } catch (err) {
            showToast(t('disableFailed'), 'error')
        }
        setUnenrolling(false)
    }

    // Copy secret to clipboard
    function copySecret() {
        if (secret) {
            navigator.clipboard.writeText(secret)
            setCopied(true)
            setTimeout(() => setCopied(false), 2000)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center p-8">
                <Loader2 className="w-6 h-6 animate-spin text-primary" />
            </div>
        )
    }

    // User is enrolled
    if (isEnrolled) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                <div className="flex items-start gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
                        <ShieldCheck className="w-6 h-6 text-green-600 dark:text-green-400" />
                    </div>
                    <div className="flex-1">
                        <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-1">
                            {t('enabled')}
                        </h3>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                            {t('enabledDesc')}
                        </p>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={unenroll}
                            disabled={unenrolling}
                            className="text-accent hover:text-accent"
                        >
                            {unenrolling ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <ShieldOff className="w-4 h-4 mr-2" />
                            )}
                            {t('disable')}
                        </Button>
                    </div>
                </div>
            </div>
        )
    }

    // Enrollment in progress - show QR code
    if (qrCodeUrl && secret) {
        return (
            <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
                <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-4">
                    {t('setupTitle')}
                </h3>

                <div className="space-y-6">
                    {/* Step 1: QR Code */}
                    <div>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                            {t('step1')}
                        </p>
                        <div className="flex justify-center p-4 bg-white rounded-xl">
                            <Image
                                src={qrCodeUrl}
                                alt="2FA QR Code"
                                width={192}
                                height={192}
                                className="w-48 h-48"
                                unoptimized
                            />
                        </div>
                    </div>

                    {/* Manual Entry */}
                    <div>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-2">
                            {t('manualEntry')}
                        </p>
                        <div className="flex items-center gap-2">
                            <code className="flex-1 px-3 py-2 bg-gray-100 dark:bg-dark-bg rounded-lg text-sm font-mono break-all">
                                {secret}
                            </code>
                            <Button variant="outline" size="sm" onClick={copySecret}>
                                {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                            </Button>
                        </div>
                    </div>

                    {/* Step 2: Verify */}
                    <div>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-2">
                            {t('step2')}
                        </p>
                        <div className="flex gap-2">
                            <Input
                                type="text"
                                inputMode="numeric"
                                pattern="[0-9]*"
                                maxLength={6}
                                placeholder="000000"
                                value={verificationCode}
                                onChange={(e) => setVerificationCode(e.target.value.replace(/\D/g, ''))}
                                className="text-center text-lg font-mono tracking-widest"
                            />
                            <Button onClick={verifyEnrollment} disabled={verifying || verificationCode.length !== 6}>
                                {verifying ? <Loader2 className="w-4 h-4 animate-spin" /> : t('verify')}
                            </Button>
                        </div>
                    </div>

                    {/* Warning */}
                    <div className="flex items-start gap-3 p-4 rounded-xl bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800">
                        <AlertTriangle className="w-5 h-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
                        <p className="text-sm text-amber-800 dark:text-amber-300">
                            {t('warning')}
                        </p>
                    </div>
                </div>
            </div>
        )
    }

    // Not enrolled - show setup button
    return (
        <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-6">
            <div className="flex items-start gap-4">
                <div className="w-12 h-12 rounded-2xl bg-gray-100 dark:bg-dark-bg flex items-center justify-center">
                    <Shield className="w-6 h-6 text-text-light dark:text-dark-text-muted" />
                </div>
                <div className="flex-1">
                    <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-1">
                        {t('title')}
                    </h3>
                    <p className="text-sm text-text-light dark:text-dark-text-muted mb-4">
                        {t('description')}
                    </p>
                    <Button onClick={startEnrollment} disabled={enrolling}>
                        {enrolling ? (
                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        ) : (
                            <Shield className="w-4 h-4 mr-2" />
                        )}
                        {t('enable')}
                    </Button>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { useToast } from '@/components/ui/toast'
import { Shield, Loader2 } from 'lucide-react'

interface TwoFactorVerifyProps {
    factorId: string
    onVerified: () => void
    onCancel?: () => void
}

export function TwoFactorVerify({ factorId, onVerified, onCancel }: TwoFactorVerifyProps) {
    const [code, setCode] = useState('')
    const [verifying, setVerifying] = useState(false)
    const [error, setError] = useState<string | null>(null)

    const supabase = createClient()
    const { showToast } = useToast()

    async function handleVerify(e: React.FormEvent) {
        e.preventDefault()

        if (code.length !== 6) {
            setError('Please enter a 6-digit code')
            return
        }

        setVerifying(true)
        setError(null)

        try {
            // Create a challenge first
            const { data: challengeData, error: challengeError } = await supabase.auth.mfa.challenge({
                factorId
            })

            if (challengeError) {
                setError(challengeError.message)
                setVerifying(false)
                return
            }

            // Verify the challenge with the code
            const { data, error: verifyError } = await supabase.auth.mfa.verify({
                factorId,
                challengeId: challengeData.id,
                code
            })

            if (verifyError) {
                setError(verifyError.message)
                setVerifying(false)
                return
            }

            showToast('Verification successful!', 'success')
            onVerified()
        } catch (err) {
            setError('Failed to verify code')
        }
        setVerifying(false)
    }

    return (
        <div className="w-full max-w-md mx-auto">
            <div className="bg-white dark:bg-dark-surface rounded-2xl border border-gray-200 dark:border-dark-border p-8">
                <div className="w-12 h-12 rounded-2xl bg-primary/10 dark:bg-primary/20 flex items-center justify-center mb-6 mx-auto">
                    <Shield className="w-6 h-6 text-primary" />
                </div>

                <h2 className="text-2xl font-bold text-text dark:text-dark-text mb-2 text-center">
                    Two-Factor Authentication
                </h2>
                <p className="text-text-light dark:text-dark-text-muted mb-6 text-center">
                    Enter the 6-digit code from your authenticator app
                </p>

                <form onSubmit={handleVerify} className="space-y-6">
                    <div>
                        <Input
                            type="text"
                            inputMode="numeric"
                            pattern="[0-9]*"
                            maxLength={6}
                            placeholder="000000"
                            value={code}
                            onChange={(e) => {
                                setCode(e.target.value.replace(/\D/g, ''))
                                setError(null)
                            }}
                            className="text-center text-2xl font-mono tracking-[0.5em] h-14"
                            autoFocus
                        />
                        {error && (
                            <p className="text-sm text-accent mt-2 text-center">{error}</p>
                        )}
                    </div>

                    <Button
                        type="submit"
                        className="w-full"
                        disabled={verifying || code.length !== 6}
                    >
                        {verifying ? (
                            <>
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                Verifying...
                            </>
                        ) : (
                            'Verify'
                        )}
                    </Button>

                    {onCancel && (
                        <Button
                            type="button"
                            variant="ghost"
                            className="w-full"
                            onClick={onCancel}
                        >
                            Cancel
                        </Button>
                    )}
                </form>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { ArrowLeft, FileText, Calendar, User, Archive, Mail, MailOpen, Reply, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { CorrespondenceForm } from './CorrespondenceForm'
import { useToast } from '@/components/ui/toast'
import { useTranslations } from 'next-intl'
import { format } from 'date-fns'
import type { Correspondence, CorrespondenceThread } from '@/types'
import { cn } from '@/lib/utils'
import { Link } from '@/navigation'

interface CorrespondenceDetailProps {
    correspondenceId: string
    locale: string
    currentUserId: string
}

export function CorrespondenceDetail({ correspondenceId, locale, currentUserId }: CorrespondenceDetailProps) {
    const router = useRouter()
    const { showToast } = useToast()
    const t = useTranslations('Correspondence')

    const [thread, setThread] = useState<Correspondence[]>([])
    const [loading, setLoading] = useState(true)
    const [showReplyForm, setShowReplyForm] = useState(false)
    const [archiving, setArchiving] = useState(false)

    const fetchThread = async () => {
        try {
            const response = await fetch(`/api/correspondence/${correspondenceId}`)
            const data: CorrespondenceThread = await response.json()

            if (data.success && data.thread) {
                setThread(data.thread)

                // Mark as read if recipient and undelivered
                const rootMessage = data.thread[0]
                if (rootMessage && rootMessage.recipient_id === currentUserId && rootMessage.status === 'delivered') {
                    await fetch(`/api/correspondence/${rootMessage.id}/read`, { method: 'POST' })
                }
            } else {
                showToast(data.error || 'Failed to load correspondence', 'error')
            }
        } catch (error) {
            console.error('Error fetching correspondence:', error)
            showToast('Failed to load correspondence', 'error')
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        fetchThread()
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [correspondenceId])

    const handleArchive = async () => {
        setArchiving(true)
        try {
            const response = await fetch(`/api/correspondence/${correspondenceId}/archive`, { method: 'POST' })
            const result = await response.json()

            if (result.success) {
                showToast(t('archived'), 'success')
                router.push(`/${locale}/correspondence`)
            } else {
                showToast(result.error || 'Failed to archive', 'error')
            }
        } catch (error) {
            showToast('Failed to archive', 'error')
        } finally {
            setArchiving(false)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
        )
    }

    if (thread.length === 0) {
        return (
            <div className="text-center py-12">
                <p className="text-text-light dark:text-dark-text-muted">Correspondence not found</p>
            </div>
        )
    }

    const root = thread[0]
    const reply = thread.length > 1 ? thread[1] : null
    const canReply = root.can_reply && currentUserId === root.recipient_id && !reply

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <Link
                    href="/correspondence"
                    className="inline-flex items-center gap-2 text-text-light dark:text-dark-text-muted hover:text-primary transition-colors"
                >
                    <ArrowLeft className="w-4 h-4 rtl:rotate-180" />
                    Back to Correspondence
                </Link>

                <div className="flex items-center gap-2">
                    {root.recipient_id === currentUserId && root.status !== 'archived' && (
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={handleArchive}
                            disabled={archiving}
                            className="gap-2"
                        >
                            {archiving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Archive className="w-4 h-4" />}
                            {t('archive')}
                        </Button>
                    )}
                </div>
            </div>

            {/* Context Card */}
            {root.post_detail && (
                <Link
                    href={`/post/${root.post_id}`}
                    className="flex items-center gap-3 p-4 bg-primary/5 dark:bg-primary/10 border border-primary/20 rounded-xl hover:border-primary/40 transition-colors"
                >
                    <FileText className="w-5 h-5 text-primary flex-shrink-0" />
                    <div>
                        <p className="text-xs font-medium text-primary uppercase tracking-wide">
                            {t('regardingPost', { title: '' })}
                        </p>
                        <p className="text-sm text-text dark:text-dark-text">
                            {root.post_detail.title}
                        </p>
                    </div>
                </Link>
            )}

            {/* Messages */}
            <div className="space-y-6">
                {thread.map((message, index) => {
                    const isSender = message.sender_id === currentUserId
                    const person = isSender ? message.recipient : message.sender

                    return (
                        <article
                            key={message.id}
                            className={cn(
                                'bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-xl overflow-hidden',
                                index > 0 && 'ml-8'
                            )}
                        >
                            {/* Message Header */}
                            <header className="flex items-start gap-4 p-5 border-b border-gray-100 dark:border-dark-border">
                                <Avatar className="w-12 h-12 flex-shrink-0">
                                    <AvatarImage src={message.sender?.avatar_url} alt={message.sender?.name} />
                                    <AvatarFallback className="bg-primary text-white text-lg">
                                        {message.sender?.name?.[0]?.toUpperCase() || '?'}
                                    </AvatarFallback>
                                </Avatar>

                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="font-semibold text-text dark:text-dark-text">
                                            {message.sender?.name}
                                        </span>
                                        {message.sender?.affiliation && (
                                            <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                ┬╖ {message.sender.affiliation}
                                            </span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-3 text-xs text-text-light dark:text-dark-text-muted">
                                        <span className="flex items-center gap-1">
                                            <Calendar className="w-3 h-3" />
                                            {format(new Date(message.created_at), 'PPP')}
                                        </span>
                                        <span className="flex items-center gap-1">
                                            <User className="w-3 h-3" />
                                            To: {message.recipient?.name}
                                        </span>
                                        {message.status === 'read' && (
                                            <span className="flex items-center gap-1 text-green-600 dark:text-green-400">
                                                <MailOpen className="w-3 h-3" />
                                                Read
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {/* Kind badge */}
                                <span className={cn(
                                    'px-2.5 py-1 text-xs font-medium rounded-full',
                                    message.kind === 'clarification_request' && 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300',
                                    message.kind === 'moderation_notice' && 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300',
                                    message.kind === 'response' && 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300'
                                )}>
                                    {message.kind === 'response' ? 'Reply' : message.kind.replace('_', ' ')}
                                </span>
                            </header>

                            {/* Message Content */}
                            <div className="p-5">
                                <h2 className="text-lg font-semibold text-text dark:text-dark-text mb-4">
                                    {message.subject}
                                </h2>
                                <div className="prose prose-sm dark:prose-invert max-w-none">
                                    <p className="whitespace-pre-wrap text-text dark:text-dark-text leading-relaxed">
                                        {message.body}
                                    </p>
                                </div>
                            </div>
                        </article>
                    )
                })}
            </div>

            {/* Reply Section */}
            {canReply && !showReplyForm && (
                <div className="flex justify-center">
                    <Button
                        onClick={() => setShowReplyForm(true)}
                        className="gap-2"
                    >
                        <Reply className="w-4 h-4" />
                        {t('reply')}
                    </Button>
                </div>
            )}

            {showReplyForm && (
                <div className="ml-8 bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border rounded-xl p-6">
                    <h3 className="text-lg font-semibold text-text dark:text-dark-text mb-4">
                        {t('reply')}
                    </h3>
                    <CorrespondenceForm
                        recipientId={root.sender_id}
                        recipientName={root.sender?.name || 'Unknown'}
                        postId={root.post_id}
                        parentId={root.id}
                        kind="response"
                        onSuccess={() => {
                            setShowReplyForm(false)
                            fetchThread()
                        }}
                    />
                </div>
            )}

            {/* Already replied notice */}
            {reply && root.recipient_id === currentUserId && (
                <div className="text-center py-4 text-text-light dark:text-dark-text-muted text-sm">
                    {t('alreadyReplied')}
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { Inbox, Send as SendIcon, Mail, MailOpen, Archive, FileText, ChevronRight, Loader2, RefreshCw } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { useToast } from '@/components/ui/toast'
import { useTranslations } from 'next-intl'
import { formatDistanceToNow } from 'date-fns'
import type { Correspondence, CorrespondenceInboxResponse, CorrespondenceStatus } from '@/types'
import { cn } from '@/lib/utils'

interface CorrespondenceInboxProps {
    locale: string
}

type TabType = 'received' | 'sent'

export function CorrespondenceInbox({ locale }: CorrespondenceInboxProps) {
    const router = useRouter()
    const { showToast } = useToast()
    const t = useTranslations('Correspondence')

    const [activeTab, setActiveTab] = useState<TabType>('received')
    const [statusFilter, setStatusFilter] = useState<CorrespondenceStatus | null>(null)
    const [items, setItems] = useState<Correspondence[]>([])
    const [loading, setLoading] = useState(true)
    const [page, setPage] = useState(1)
    const [totalPages, setTotalPages] = useState(1)

    const fetchData = useCallback(async () => {
        setLoading(true)
        try {
            const endpoint = activeTab === 'received'
                ? `/api/correspondence/inbox${statusFilter ? `?status=${statusFilter}` : ''}`
                : '/api/correspondence/sent'

            const response = await fetch(`${endpoint}${endpoint.includes('?') ? '&' : '?'}page=${page}`)
            const data: CorrespondenceInboxResponse = await response.json()

            if (data.success) {
                setItems(data.items || [])
                setTotalPages(data.total_pages || 1)
            } else {
                showToast(data.error || 'Failed to load correspondence', 'error')
            }
        } catch (error) {
            console.error('Error fetching correspondence:', error)
            showToast('Failed to load correspondence', 'error')
        } finally {
            setLoading(false)
        }
    }, [activeTab, statusFilter, page, showToast])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    const handleArchive = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation()
        try {
            const response = await fetch(`/api/correspondence/${id}/archive`, { method: 'POST' })
            const result = await response.json()

            if (result.success) {
                showToast(t('archived'), 'success')
                fetchData()
            } else {
                showToast(result.error || 'Failed to archive', 'error')
            }
        } catch (error) {
            showToast('Failed to archive', 'error')
        }
    }

    const getStatusIcon = (status: CorrespondenceStatus) => {
        switch (status) {
            case 'delivered':
                return <Mail className="w-4 h-4 text-primary" />
            case 'read':
                return <MailOpen className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
            case 'archived':
                return <Archive className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
            default:
                return <Mail className="w-4 h-4 text-amber-500" />
        }
    }

    return (
        <div className="space-y-6">
            {/* Tabs */}
            <div className="flex items-center justify-between border-b border-gray-200 dark:border-dark-border">
                <div className="flex gap-1">
                    <button
                        onClick={() => { setActiveTab('received'); setPage(1); }}
                        className={cn(
                            'flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors',
                            activeTab === 'received'
                                ? 'border-primary text-primary dark:text-white'
                                : 'border-transparent text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                        )}
                    >
                        <Inbox className="w-4 h-4" />
                        {t('tabs.received')}
                    </button>
                    <button
                        onClick={() => { setActiveTab('sent'); setPage(1); }}
                        className={cn(
                            'flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors',
                            activeTab === 'sent'
                                ? 'border-primary text-primary dark:text-white'
                                : 'border-transparent text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                        )}
                    >
                        <SendIcon className="w-4 h-4" />
                        {t('tabs.sent')}
                    </button>
                </div>

                <Button variant="ghost" size="sm" onClick={fetchData} disabled={loading}>
                    <RefreshCw className={cn('w-4 h-4', loading && 'animate-spin')} />
                </Button>
            </div>

            {/* Filters (only for received) */}
            {activeTab === 'received' && (
                <div className="flex gap-2">
                    {[
                        { value: null, label: t('filters.all') },
                        { value: 'delivered' as const, label: t('filters.unread') },
                        { value: 'read' as const, label: t('filters.read') },
                        { value: 'archived' as const, label: t('filters.archived') }
                    ].map(filter => (
                        <button
                            key={filter.value || 'all'}
                            onClick={() => { setStatusFilter(filter.value); setPage(1); }}
                            className={cn(
                                'px-3 py-1.5 text-sm rounded-full border transition-colors',
                                statusFilter === filter.value
                                    ? 'bg-primary text-white border-primary'
                                    : 'border-gray-200 dark:border-dark-border text-text-light dark:text-dark-text-muted hover:border-primary/50'
                            )}
                        >
                            {filter.label}
                        </button>
                    ))}
                </div>
            )}

            {/* Content */}
            {loading ? (
                <div className="flex items-center justify-center py-12">
                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                </div>
            ) : items.length === 0 ? (
                <div className="text-center py-12">
                    <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-gray-100 dark:bg-dark-surface flex items-center justify-center">
                        <Mail className="w-8 h-8 text-text-light dark:text-dark-text-muted" />
                    </div>
                    <h3 className="text-lg font-medium text-text dark:text-dark-text mb-1">
                        {t('empty.noMessages')}
                    </h3>
                    <p className="text-text-light dark:text-dark-text-muted">
                        {t('empty.description')}
                    </p>
                </div>
            ) : (
                <div className="divide-y divide-gray-100 dark:divide-dark-border border border-gray-200 dark:border-dark-border rounded-xl overflow-hidden">
                    {items.map(item => {
                        const person = activeTab === 'received' ? item.sender : item.recipient
                        const isUnread = activeTab === 'received' && item.status === 'delivered'

                        return (
                            <div
                                key={item.id}
                                onClick={() => router.push(`/${locale}/correspondence/${item.id}`)}
                                className={cn(
                                    'flex items-start gap-4 p-4 cursor-pointer transition-colors',
                                    'hover:bg-gray-50 dark:hover:bg-dark-surface',
                                    isUnread && 'bg-primary/5 dark:bg-primary/10'
                                )}
                            >
                                {/* Avatar */}
                                <Avatar className="w-10 h-10 flex-shrink-0">
                                    <AvatarImage src={person?.avatar_url} alt={person?.name} />
                                    <AvatarFallback className="bg-primary text-white">
                                        {person?.name?.[0]?.toUpperCase() || '?'}
                                    </AvatarFallback>
                                </Avatar>

                                {/* Content */}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        {getStatusIcon(item.status)}
                                        <span className={cn(
                                            'font-medium truncate',
                                            isUnread ? 'text-text dark:text-dark-text' : 'text-text-light dark:text-dark-text-muted'
                                        )}>
                                            {person?.name}
                                        </span>
                                        <span className="text-xs text-text-light dark:text-dark-text-muted">
                                            {formatDistanceToNow(new Date(item.created_at), { addSuffix: true })}
                                        </span>
                                    </div>

                                    <h4 className={cn(
                                        'text-sm truncate mb-1',
                                        isUnread ? 'font-semibold text-text dark:text-dark-text' : 'text-text dark:text-dark-text'
                                    )}>
                                        {item.subject}
                                    </h4>

                                    {/* Context */}
                                    {item.post_detail && (
                                        <div className="flex items-center gap-1.5 text-xs text-text-light dark:text-dark-text-muted">
                                            <FileText className="w-3 h-3" />
                                            <span className="truncate">{item.post_detail.title}</span>
                                        </div>
                                    )}

                                    {/* Reply indicator */}
                                    {item.has_reply && (
                                        <span className="inline-block mt-1 text-xs text-primary bg-primary/10 px-2 py-0.5 rounded-full">
                                            {t('reply')}
                                        </span>
                                    )}
                                </div>

                                {/* Actions */}
                                <div className="flex items-center gap-2 flex-shrink-0">
                                    {activeTab === 'received' && item.status !== 'archived' && (
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            onClick={(e) => handleArchive(item.id, e)}
                                            className="opacity-0 group-hover:opacity-100"
                                        >
                                            <Archive className="w-4 h-4" />
                                        </Button>
                                    )}
                                    <ChevronRight className="w-4 h-4 text-text-light dark:text-dark-text-muted" />
                                </div>
                            </div>
                        )
                    })}
                </div>
            )}

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex justify-center gap-2">
                    <Button
                        variant="outline"
                        size="sm"
                        disabled={page === 1}
                        onClick={() => setPage(p => p - 1)}
                    >
                        Previous
                    </Button>
                    <span className="flex items-center px-3 text-sm text-text-light dark:text-dark-text-muted">
                        {page} / {totalPages}
                    </span>
                    <Button
                        variant="outline"
                        size="sm"
                        disabled={page === totalPages}
                        onClick={() => setPage(p => p + 1)}
                    >
                        Next
                    </Button>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { SchemaFieldVersion } from '@/types'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Switch } from '@/components/ui/switch'
import { Label } from '@/components/ui/label'
import { RegistrySelect } from './RegistrySelect'
import { cn } from '@/lib/utils'

interface SchemaFieldRendererProps {
    fields: SchemaFieldVersion[]
    values: Record<string, any>
    onChange: (fieldId: string, value: any) => void
    errors?: Record<string, string>
}

export function SchemaFieldRenderer({ fields, values, onChange, errors }: SchemaFieldRendererProps) {
    if (fields.length === 0) return null

    return (
        <div className="space-y-6 pt-4 border-t border-gray-100 dark:border-dark-border">
            <h3 className="text-sm font-semibold text-text-light dark:text-dark-text-muted uppercase tracking-wider">
                Additional Details
            </h3>

            <div className="grid gap-6 md:grid-cols-2">
                {fields.map((field) => {
                    return (
                        <div key={field.id} className={cn(
                            "space-y-2",
                            // Full width for certain types
                            ['rich_text', 'json', 'multiselect', 'registry_ref_multi', 'geo_polygon'].includes(field.field_type) ? "md:col-span-2" : ""
                        )}>
                            <div className="flex items-center gap-2">
                                <Label className="text-sm font-medium text-text dark:text-dark-text">
                                    {field.display_name}
                                </Label>
                                {field.is_required && (
                                    <span className="text-accent text-xs">*</span>
                                )}
                            </div>

                            {field.description && (
                                <p className="text-xs text-text-light dark:text-dark-text-muted">
                                    {field.description}
                                </p>
                            )}

                            <FieldInput
                                field={field}
                                value={values[field.field_id]}
                                onChange={(val) => onChange(field.field_id, val)}
                            />

                            {errors?.[field.field_id] && (
                                <p className="text-sm text-accent">
                                    {errors[field.field_id]}
                                </p>
                            )}
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

function FieldInput({ field, value, onChange }: { field: SchemaFieldVersion, value: any, onChange: (val: any) => void }) {
    switch (field.field_type) {
        case 'text':
        case 'url':
        case 'file': // simplified for now
            return (
                <Input
                    type={field.field_type === 'url' ? 'url' : 'text'}
                    value={value || ''}
                    onChange={(e) => onChange(e.target.value)}
                    placeholder={field.display_name}
                />
            )

        case 'number':
            return (
                <Input
                    type="number"
                    value={value || ''}
                    onChange={(e) => onChange(Number(e.target.value))}
                />
            )

        case 'boolean':
            return (
                <div className="flex items-center gap-2">
                    <Switch
                        checked={!!value}
                        onCheckedChange={onChange}
                    />
                    <span className="text-sm text-text-light">
                        {value ? 'Yes' : 'No'}
                    </span>
                </div>
            )

        case 'date':
        case 'datetime':
            return (
                <Input
                    type={field.field_type === 'datetime' ? 'datetime-local' : 'date'}
                    value={value || ''}
                    onChange={(e) => onChange(e.target.value)}
                />
            )

        case 'rich_text':
            return (
                <Textarea
                    value={value || ''}
                    onChange={(e) => onChange(e.target.value)}
                    className="min-h-[100px]"
                />
            )

        case 'registry_ref':
        case 'registry_ref_multi':
            if (!field.registry_id) return <p className="text-xs text-red-500">Missing registry configuration</p>
            return (
                <RegistrySelect
                    registryId={field.registry_id}
                    value={value}
                    onChange={onChange}
                    multiple={field.field_type === 'registry_ref_multi'}
                />
            )

        case 'select':
            const selectOptions = (field.constraints as any)?.options || []
            return (
                <select
                    value={value || ''}
                    onChange={(e) => onChange(e.target.value)}
                    className="select-input"
                >
                    <option value="">Select an option...</option>
                    {selectOptions.map((opt: any) => {
                        const optionValue = typeof opt === 'string' ? opt : opt.value
                        const optionLabel = typeof opt === 'string' ? opt : opt.label
                        return (
                            <option key={optionValue} value={optionValue}>{optionLabel}</option>
                        )
                    })}
                </select>
            )

        case 'multiselect':
            const multiOptions = (field.constraints as any)?.options || []
            const selectedValues = Array.isArray(value) ? value : []
            return (
                <div className="space-y-2">
                    <div className="flex flex-wrap gap-2">
                        {multiOptions.map((opt: any) => {
                            const optionValue = typeof opt === 'string' ? opt : opt.value
                            const optionLabel = typeof opt === 'string' ? opt : opt.label
                            const isSelected = selectedValues.includes(optionValue)
                            return (
                                <button
                                    key={optionValue}
                                    type="button"
                                    onClick={() => {
                                        if (isSelected) {
                                            onChange(selectedValues.filter((v: string) => v !== optionValue))
                                        } else {
                                            onChange([...selectedValues, optionValue])
                                        }
                                    }}
                                    className={cn(
                                        "px-3 py-1.5 rounded-full text-sm border transition-colors",
                                        isSelected
                                            ? "bg-primary text-white border-primary"
                                            : "bg-white dark:bg-dark-bg border-gray-200 dark:border-dark-border text-text dark:text-dark-text hover:border-primary"
                                    )}
                                >
                                    {optionLabel}
                                </button>
                            )
                        })}
                    </div>
                    {selectedValues.length > 0 && (
                        <p className="text-xs text-text-light dark:text-dark-text-muted">
                            {selectedValues.length} selected
                        </p>
                    )}
                </div>
            )

        case 'geo_point':
            const pointValue = value || { lat: '', lng: '' }
            return (
                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="text-xs text-text-light dark:text-dark-text-muted mb-1 block">Latitude</label>
                        <Input
                            type="number"
                            step="any"
                            placeholder="e.g. 33.5138"
                            value={pointValue.lat || ''}
                            onChange={(e) => onChange({ ...pointValue, lat: parseFloat(e.target.value) || '' })}
                        />
                    </div>
                    <div>
                        <label className="text-xs text-text-light dark:text-dark-text-muted mb-1 block">Longitude</label>
                        <Input
                            type="number"
                            step="any"
                            placeholder="e.g. 36.2765"
                            value={pointValue.lng || ''}
                            onChange={(e) => onChange({ ...pointValue, lng: parseFloat(e.target.value) || '' })}
                        />
                    </div>
                </div>
            )

        case 'geo_polygon':
            const polygonValue = typeof value === 'string' ? value : JSON.stringify(value || [], null, 2)
            return (
                <div className="space-y-2">
                    <Textarea
                        value={polygonValue}
                        onChange={(e) => {
                            try {
                                const parsed = JSON.parse(e.target.value)
                                onChange(parsed)
                            } catch {
                                // Keep as string while user is typing
                                onChange(e.target.value)
                            }
                        }}
                        placeholder='[[lat, lng], [lat, lng], ...]'
                        className="min-h-[80px] font-mono text-sm"
                    />
                    <p className="text-xs text-text-light dark:text-dark-text-muted">
                        Enter coordinates as JSON array: [[lat1, lng1], [lat2, lng2], ...]
                    </p>
                </div>
            )

        case 'json':
            const jsonValue = typeof value === 'string' ? value : JSON.stringify(value || {}, null, 2)
            return (
                <div className="space-y-2">
                    <Textarea
                        value={jsonValue}
                        onChange={(e) => {
                            try {
                                const parsed = JSON.parse(e.target.value)
                                onChange(parsed)
                            } catch {
                                // Keep as string while user is typing
                                onChange(e.target.value)
                            }
                        }}
                        placeholder='{"key": "value"}'
                        className="min-h-[120px] font-mono text-sm"
                    />
                    <p className="text-xs text-text-light dark:text-dark-text-muted">
                        Enter valid JSON data
                    </p>
                </div>
            )

        default:
            return (
                <div className="p-2 border border-dashed rounded text-xs text-gray-500">
                    Unsupported field type: {field.field_type}
                </div>
            )
    }
}

