                        >
                            <ExternalLink className="w-3.5 h-3.5" />
                            Open
                        </a>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    X,
    Link2,
    Copy,
    Check,
    RefreshCw,
    Globe,
    Lock,
    Loader2,
    QrCode,
    ExternalLink
} from 'lucide-react'
import { useToast } from '@/components/ui/toast'
import { createClient } from '@/lib/supabase/client'

interface ShareDialogProps {
    isOpen: boolean
    onClose: () => void
    type: 'survey' | 'poll'
    id: string
    title: string
    currentToken?: string | null
    isPublic?: boolean
}

export function ShareDialog({
    isOpen,
    onClose,
    type,
    id,
    title,
    currentToken,
    isPublic = false
}: ShareDialogProps) {
    const { showToast } = useToast()
    const [publicToken, setPublicToken] = useState<string | null>(currentToken || null)
    const [allowPublic, setAllowPublic] = useState(isPublic)
    const [isGenerating, setIsGenerating] = useState(false)
    const [isSaving, setIsSaving] = useState(false)
    const [copied, setCopied] = useState(false)

    useEffect(() => {
        setPublicToken(currentToken || null)
        setAllowPublic(isPublic)
    }, [currentToken, isPublic])

    const generateToken = () => {
        // SECURITY: Use cryptographically secure random values instead of Math.random()
        const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
        const randomValues = new Uint32Array(16)
        crypto.getRandomValues(randomValues)
        let token = ''
        for (let i = 0; i < 16; i++) {
            token += chars.charAt(randomValues[i] % chars.length)
        }
        return token
    }

    const handleGenerateToken = async () => {
        setIsGenerating(true)
        const supabase = createClient()

        try {
            const newToken = generateToken()
            const table = type === 'survey' ? 'surveys' : 'polls'

            const { error } = await supabase
                .from(table)
                .update({
                    public_token: newToken,
                    allow_public_responses: true
                })
                .eq('id', id)

            if (error) throw error

            setPublicToken(newToken)
            setAllowPublic(true)
            showToast('Public link generated!', 'success')
        } catch (error) {
            showToast('Failed to generate link', 'error')
        } finally {
            setIsGenerating(false)
        }
    }

    const handleTogglePublic = async (enabled: boolean) => {
        setIsSaving(true)
        const supabase = createClient()

        try {
            const table = type === 'survey' ? 'surveys' : 'polls'

            const { error } = await supabase
                .from(table)
                .update({ allow_public_responses: enabled })
                .eq('id', id)

            if (error) throw error

            setAllowPublic(enabled)
            showToast(enabled ? 'Public sharing enabled' : 'Public sharing disabled', 'success')
        } catch (error) {
            showToast('Failed to update sharing settings', 'error')
        } finally {
            setIsSaving(false)
        }
    }

    const handleCopyLink = async () => {
        if (!publicToken) return

        const baseUrl = window.location.origin
        const prefix = type === 'survey' ? 's' : 'p'
        const url = `${baseUrl}/en/${prefix}/${publicToken}`

        try {
            await navigator.clipboard.writeText(url)
            setCopied(true)
            showToast('Link copied!', 'success')
            setTimeout(() => setCopied(false), 2000)
        } catch (error) {
            showToast('Failed to copy', 'error')
        }
    }

    const publicUrl = publicToken
        ? `${typeof window !== 'undefined' ? window.location.origin : ''}/en/${type === 'survey' ? 's' : 'p'}/${publicToken}`
        : null

    if (!isOpen) return null

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
            <div className="bg-white dark:bg-dark-surface rounded-xl max-w-md w-full overflow-hidden shadow-xl">
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-dark-border">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                            <Link2 className="w-5 h-5 text-primary" />
                        </div>
                        <div>
                            <h2 className="font-semibold text-text dark:text-dark-text">
                                Share {type === 'survey' ? 'Survey' : 'Poll'}
                            </h2>
                            <p className="text-sm text-text-light dark:text-dark-text-muted truncate max-w-[200px]">
                                {title}
                            </p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 text-text-light hover:text-text dark:hover:text-dark-text rounded-lg hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Content */}
                <div className="p-4 space-y-4">
                    {/* Public toggle */}
                    <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-dark-bg rounded-lg">
                        <div className="flex items-center gap-3">
                            {allowPublic ? (
                                <Globe className="w-5 h-5 text-emerald-500" />
                            ) : (
                                <Lock className="w-5 h-5 text-gray-400" />
                            )}
                            <div>
                                <p className="font-medium text-text dark:text-dark-text">
                                    Public Access
                                </p>
                                <p className="text-xs text-text-light dark:text-dark-text-muted">
                                    {allowPublic
                                        ? 'Anyone with the link can participate'
                                        : 'Only registered users can participate'
                                    }
                                </p>
                            </div>
                        </div>
                        <button
                            onClick={() => handleTogglePublic(!allowPublic)}
                            disabled={isSaving || !publicToken}
                            className={`relative w-12 h-6 rounded-full transition-colors ${allowPublic ? 'bg-emerald-500' : 'bg-gray-300 dark:bg-dark-border'
                                } ${!publicToken ? 'opacity-50 cursor-not-allowed' : ''}`}
                        >
                            <div className={`absolute w-5 h-5 rounded-full bg-white shadow-sm top-0.5 transition-transform ${allowPublic ? 'translate-x-6' : 'translate-x-0.5'
                                }`} />
                        </button>
                    </div>

                    {/* Public link */}
                    {publicToken ? (
                        <div className="space-y-3">
                            <div className="flex gap-2">
                                <input
                                    type="text"
                                    value={publicUrl || ''}
                                    readOnly
                                    className="flex-1 px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-gray-50 dark:bg-dark-bg text-text dark:text-dark-text text-sm"
                                />
                                <button
                                    onClick={handleCopyLink}
                                    className="btn btn-primary px-3"
                                >
                                    {copied ? (
                                        <Check className="w-4 h-4" />
                                    ) : (
                                        <Copy className="w-4 h-4" />
                                    )}
                                </button>
                            </div>

                            <div className="flex gap-2">
                                <button
                                    onClick={handleGenerateToken}
                                    disabled={isGenerating}
                                    className="flex-1 btn btn-ghost text-sm flex items-center justify-center gap-2"
                                >
                                    {isGenerating ? (
                                        <Loader2 className="w-4 h-4 animate-spin" />
                                    ) : (
                                        <RefreshCw className="w-4 h-4" />
                                    )}
                                    Regenerate Link
                                </button>
                                <a
                                    href={publicUrl || '#'}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="flex-1 btn btn-outline text-sm flex items-center justify-center gap-2"
                                >
                                    <ExternalLink className="w-4 h-4" />
                                    Preview
                                </a>
                            </div>
                        </div>
                    ) : (
                        <button
                            onClick={handleGenerateToken}
                            disabled={isGenerating}
                            className="w-full btn btn-primary py-3 flex items-center justify-center gap-2"
                        >
                            {isGenerating ? (
                                <>
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                    Generating...
                                </>
                            ) : (
                                <>
                                    <Link2 className="w-5 h-5" />
                                    Generate Public Link
                                </>
                            )}
                        </button>
                    )}

                    {/* Info */}
                    {publicToken && (
                        <div className="text-xs text-text-light dark:text-dark-text-muted space-y-1">
                            <p>ΓÇó Responses from public links are anonymous</p>
                            <p>ΓÇó Each device can only respond once</p>
                            <p>ΓÇó You can regenerate the link to invalidate old links</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useCallback } from 'react'
import {
    BarChart3,
    LineChart,
    PieChart,
    AreaChart,
    Upload,
    FileSpreadsheet,
    Calculator,
    Save,
    Download,
    Trash2,
    Plus,
    X,
    ClipboardList,
    Vote,
    Loader2
} from 'lucide-react'
import {
    LineChart as RechartsLine,
    Line,
    BarChart as RechartsBar,
    Bar,
    PieChart as RechartsPie,
    Pie,
    AreaChart as RechartsArea,
    Area,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    Legend,
    Cell
} from 'recharts'
import { useToast } from '@/components/ui/toast'
import { createClient } from '@/lib/supabase/client'
import { useTranslations } from 'next-intl'

interface Survey {
    id: string
    title: string
    response_count: number
    status: string
    created_at: string
}

interface Poll {
    id: string
    question: string
    options: Array<{ id: string; text: string; vote_count: number }>
    total_votes: number
    is_active: boolean
    created_at: string
}

interface StatisticsToolsProps {
    userId?: string
    savedAnalyses: any[]
    availableDatasets: any[]
    userSurveys?: Survey[]
    userPolls?: Poll[]
}


const COLORS = ['#6366F1', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', '#EC4899', '#06B6D4', '#84CC16']


// Sample demo data
const DEMO_DATA = [
    { name: 'Jan', value: 400, secondary: 240 },
    { name: 'Feb', value: 300, secondary: 139 },
    { name: 'Mar', value: 200, secondary: 980 },
    { name: 'Apr', value: 278, secondary: 390 },
    { name: 'May', value: 189, secondary: 480 },
    { name: 'Jun', value: 239, secondary: 380 },
]

const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
        return (
            <div className="bg-white dark:bg-dark-surface border border-gray-200 dark:border-dark-border shadow-lg rounded-lg p-3 text-sm z-50">
                <p className="font-medium text-gray-900 dark:text-gray-100 mb-2">{label}</p>
                {payload.map((entry: any, index: number) => (
                    <div key={index} className="flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color || entry.fill }} />
                        <span className="text-gray-600 dark:text-gray-300 capitalize">{entry.name}:</span>
                        <span className="font-medium text-gray-900 dark:text-gray-100">{entry.value}</span>
                    </div>
                ))}
            </div>
        )
    }
    return null
}

export function StatisticsTools({ userId, savedAnalyses, availableDatasets, userSurveys = [], userPolls = [] }: StatisticsToolsProps) {
    const t = useTranslations('ResearchLab.statisticsPage')
    const [activeTab, setActiveTab] = useState<'charts' | 'calculator' | 'import'>('charts')
    const [chartType, setChartType] = useState('bar')
    const [chartData, setChartData] = useState(DEMO_DATA)
    const [showSecondary, setShowSecondary] = useState(false)
    const [loadingSurvey, setLoadingSurvey] = useState<string | null>(null)
    const [loadingPoll, setLoadingPoll] = useState<string | null>(null)
    const [loadingResource, setLoadingResource] = useState<string | null>(null)
    const { showToast } = useToast()

    // Chart types with localized labels
    const CHART_TYPES = [
        { id: 'bar', label: t('chartTypes.bar'), icon: BarChart3 },
        { id: 'line', label: t('chartTypes.line'), icon: LineChart },
        { id: 'pie', label: t('chartTypes.pie'), icon: PieChart },
        { id: 'area', label: t('chartTypes.area'), icon: AreaChart },
    ]


    // Statistics calculator state
    const [calculatorData, setCalculatorData] = useState('')
    const [statistics, setStatistics] = useState<{
        mean?: number
        median?: number
        mode?: number[]
        stdDev?: number
        min?: number
        max?: number
        sum?: number
        count?: number
    } | null>(null)

    const calculateStatistics = useCallback(() => {
        const numbers = calculatorData
            .split(/[,\s\n]+/)
            .map(n => parseFloat(n.trim()))
            .filter(n => !isNaN(n))

        if (numbers.length === 0) {
            showToast('Please enter valid numbers', 'error')
            return
        }

        const sorted = [...numbers].sort((a, b) => a - b)
        const sum = numbers.reduce((a, b) => a + b, 0)
        const mean = sum / numbers.length

        // Median
        const mid = Math.floor(sorted.length / 2)
        const median = sorted.length % 2 !== 0
            ? sorted[mid]
            : (sorted[mid - 1] + sorted[mid]) / 2

        // Mode
        const frequency: Record<number, number> = {}
        let maxFreq = 0
        numbers.forEach(n => {
            frequency[n] = (frequency[n] || 0) + 1
            maxFreq = Math.max(maxFreq, frequency[n])
        })
        const mode = Object.entries(frequency)
            .filter(([_, freq]) => freq === maxFreq)
            .map(([num, _]) => parseFloat(num))

        // Standard deviation
        const squareDiffs = numbers.map(n => Math.pow(n - mean, 2))
        const avgSquareDiff = squareDiffs.reduce((a, b) => a + b, 0) / numbers.length
        const stdDev = Math.sqrt(avgSquareDiff)

        setStatistics({
            mean: Math.round(mean * 1000) / 1000,
            median: Math.round(median * 1000) / 1000,
            mode: mode.length < numbers.length ? mode : undefined,
            stdDev: Math.round(stdDev * 1000) / 1000,
            min: sorted[0],
            max: sorted[sorted.length - 1],
            sum: Math.round(sum * 1000) / 1000,
            count: numbers.length
        })

        // Also update chart data
        setChartData(numbers.slice(0, 10).map((n, i) => ({
            name: `#${i + 1}`,
            value: n,
            secondary: 0
        })))
    }, [calculatorData, showToast])

    const handleFileImport = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0]
        if (!file) return

        const reader = new FileReader()
        reader.onload = (e) => {
            const text = e.target?.result as string

            if (file.name.endsWith('.csv')) {
                // Parse CSV
                const lines = text.trim().split('\n')
                if (lines.length < 2) {
                    showToast('CSV file needs at least a header and one data row', 'error')
                    return
                }

                const headers = lines[0].split(',').map(h => h.trim())
                const data = lines.slice(1).map(line => {
                    const values = line.split(',').map(v => v.trim())
                    const obj: any = { name: values[0] }
                    headers.slice(1).forEach((header, i) => {
                        const num = parseFloat(values[i + 1])
                        if (!isNaN(num)) obj[header.toLowerCase()] = num
                    })
                    return obj
                })

                setChartData(data.slice(0, 20))
                showToast('CSV imported successfully!', 'success')
            } else if (file.name.endsWith('.json')) {
                try {
                    const json = JSON.parse(text)
                    if (Array.isArray(json)) {
                        setChartData(json.slice(0, 20))
                        showToast('JSON imported successfully!', 'success')
                    } else {
                        showToast('JSON must be an array of objects', 'error')
                    }
                } catch {
                    showToast('Invalid JSON file', 'error')
                }
            }
        }
        reader.readAsText(file)
    }, [showToast])

    const handleImportSurvey = useCallback(async (surveyId: string) => {
        setLoadingSurvey(surveyId)
        const supabase = createClient()

        try {
            // Fetch survey questions and responses
            const { data: questions } = await supabase
                .from('survey_questions')
                .select('id, question_text, question_type, options')
                .eq('survey_id', surveyId)
                .order('order_index', { ascending: true })

            const { data: responses } = await supabase
                .from('survey_responses')
                .select('answers')
                .eq('survey_id', surveyId)

            if (!questions || !responses || responses.length === 0) {
                showToast('No data found', 'error')
                return
            }

            // Transform to chart data - aggregate choice questions
            const importedData: Array<{ name: string; value: number; secondary: number }> = []

            questions.forEach(q => {
                if (q.question_type === 'single_choice' || q.question_type === 'multiple_choice') {
                    const options = (q.options as Array<{ id: string; text: string }>) || []
                    const counts: Record<string, number> = {}
                    options.forEach(opt => { counts[opt.id] = 0 })

                    responses.forEach(r => {
                        const answer = r.answers[q.id]
                        if (Array.isArray(answer)) {
                            answer.forEach(id => { if (counts[id] !== undefined) counts[id]++ })
                        } else if (typeof answer === 'string' && counts[answer] !== undefined) {
                            counts[answer]++
                        }
                    })

                    options.forEach(opt => {
                        importedData.push({
                            name: opt.text.length > 20 ? opt.text.slice(0, 20) + '...' : opt.text,
                            value: counts[opt.id] || 0,
                            secondary: 0
                        })
                    })
                }
            })

            if (importedData.length === 0) {
                showToast('No visualizable data found', 'error')
                return
            }

            setChartData(importedData.slice(0, 20))
            setActiveTab('charts')
            showToast('Survey data imported!', 'success')
        } catch (error) {
            showToast('Failed to import survey data', 'error')
        } finally {
            setLoadingSurvey(null)
        }
    }, [showToast])

    const handleImportPoll = useCallback((poll: Poll) => {
        setLoadingPoll(poll.id)

        try {
            // Transform poll options to chart data
            const importedData = poll.options.map(opt => ({
                name: opt.text.length > 20 ? opt.text.slice(0, 20) + '...' : opt.text,
                value: opt.vote_count,
                secondary: 0
            }))

            setChartData(importedData)
            setActiveTab('charts')
            showToast('Poll data imported!', 'success')
        } catch (error) {
            showToast('Failed to import poll data', 'error')
        } finally {
            setLoadingPoll(null)
        }
    }, [showToast])

    const renderChart = () => {
        const commonProps = {
            data: chartData,
            margin: { top: 20, right: 30, left: 20, bottom: 5 }
        }

        switch (chartType) {
            case 'line':
                return (
                    <RechartsLine {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" className="stroke-gray-200 dark:stroke-gray-700" />
                        <XAxis dataKey="name" className="text-xs" />
                        <YAxis className="text-xs" />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend />
                        <Line type="monotone" dataKey="value" stroke={COLORS[0]} strokeWidth={2} dot={{ r: 4 }} />
                        {showSecondary && <Line type="monotone" dataKey="secondary" stroke={COLORS[1]} strokeWidth={2} dot={{ r: 4 }} />}
                    </RechartsLine>
                )
            case 'pie':
                return (
                    <RechartsPie {...commonProps}>
                        <Pie
                            data={chartData}
                            dataKey="value"
                            nameKey="name"
                            cx="50%"
                            cy="50%"
                            outerRadius={120}
                            label={({ name, percent }: { name?: string | number; percent?: number }) => percent !== undefined ? `${name}: ${(percent * 100).toFixed(0)}%` : String(name)}
                        >
                            {chartData.map((_, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <Tooltip content={<CustomTooltip />} />
                        <Legend />
                    </RechartsPie>
                )
            case 'area':
                return (
                    <RechartsArea {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" className="stroke-gray-200 dark:stroke-gray-700" />
                        <XAxis dataKey="name" className="text-xs" />
                        <YAxis className="text-xs" />
                        <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.05)' }} />
                        <Legend />
                        <Area type="monotone" dataKey="value" stroke={COLORS[0]} fill={`${COLORS[0]}33`} />
                        {showSecondary && <Area type="monotone" dataKey="secondary" stroke={COLORS[1]} fill={`${COLORS[1]}33`} />}
                    </RechartsArea>
                )
            default: // bar
                return (
                    <RechartsBar {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" className="stroke-gray-200 dark:stroke-gray-700" />
                        <XAxis dataKey="name" className="text-xs" />
                        <YAxis className="text-xs" />
                        <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.05)' }} />
                        <Legend />
                        <Bar dataKey="value" fill={COLORS[0]} radius={[4, 4, 0, 0]} />
                        {showSecondary && <Bar dataKey="secondary" fill={COLORS[1]} radius={[4, 4, 0, 0]} />}
                    </RechartsBar>
                )
        }
    }

    return (
        <div>
            <div className="mb-8">
                <h1 className="text-2xl font-display font-bold text-text dark:text-dark-text mb-1">
                    {t('title')}
                </h1>
                <p className="text-text-light dark:text-dark-text-muted">
                    {t('subtitle')}
                </p>
            </div>

            {/* Tabs */}
            <div className="flex gap-1 sm:gap-2 mb-6 border-b border-gray-200 dark:border-dark-border">
                {[
                    { id: 'charts', label: t('tabs.chartBuilder'), icon: BarChart3 },
                    { id: 'calculator', label: t('tabs.calculator'), icon: Calculator },
                    { id: 'import', label: t('tabs.importData'), icon: Upload },
                ].map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`
                            flex items-center gap-2 px-3 sm:px-4 py-3 text-sm font-medium border-b-2 -mb-px transition-colors whitespace-nowrap
                            ${activeTab === tab.id
                                ? 'border-secondary text-primary dark:text-secondary'
                                : 'border-transparent text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                            }
                        `}
                        title={tab.label}
                    >
                        <tab.icon className="w-4 h-4 flex-shrink-0" />
                        <span className="hidden sm:inline">{tab.label}</span>
                    </button>
                ))}
            </div>

            {/* Chart Builder Tab */}
            {activeTab === 'charts' && (
                <div className="grid lg:grid-cols-[1fr_300px] gap-6">
                    {/* Chart Area */}
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <div className="h-80">
                            <ResponsiveContainer width="100%" height="100%">
                                {renderChart()}
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="space-y-4">
                        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                            <h3 className="text-sm font-semibold text-text dark:text-dark-text mb-3">
                                {t('chartType')}
                            </h3>
                            <div className="grid grid-cols-2 gap-2">
                                {CHART_TYPES.map((type) => (
                                    <button
                                        key={type.id}
                                        onClick={() => setChartType(type.id)}
                                        className={`
                                            flex items-center gap-2 p-3 rounded-lg text-sm transition-colors
                                            ${chartType === type.id
                                                ? 'bg-primary text-white'
                                                : 'bg-gray-100 dark:bg-dark-bg text-text-light dark:text-dark-text-muted hover:bg-gray-200 dark:hover:bg-dark-border'
                                            }
                                        `}
                                    >
                                        <type.icon className="w-4 h-4" />
                                        {type.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4">
                            <h3 className="text-sm font-semibold text-text dark:text-dark-text mb-3">
                                {t('options')}
                            </h3>
                            <label className="flex items-center gap-2 cursor-pointer">
                                <input
                                    type="checkbox"
                                    checked={showSecondary}
                                    onChange={(e) => setShowSecondary(e.target.checked)}
                                    className="rounded border-gray-300 text-primary focus:ring-primary"
                                />
                                <span className="text-sm text-text dark:text-dark-text">
                                    {t('showSecondary')}
                                </span>
                            </label>
                        </div>
                    </div>
                </div>
            )}

            {/* Calculator Tab */}
            {activeTab === 'calculator' && (
                <div className="grid lg:grid-cols-2 gap-6">
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-3">
                            {t('enterNumbers')}
                        </h3>
                        <p className="text-sm text-text-light dark:text-dark-text-muted mb-3">
                            {t('enterNumbersDesc')}
                        </p>
                        <textarea
                            value={calculatorData}
                            onChange={(e) => setCalculatorData(e.target.value)}
                            placeholder={t('enterNumbersPlaceholder')}
                            rows={6}
                            className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-bg text-text dark:text-dark-text placeholder-text-light dark:placeholder-dark-text-muted focus:ring-2 focus:ring-primary focus:border-transparent resize-none"
                        />
                        <button
                            onClick={calculateStatistics}
                            className="btn btn-primary w-full mt-4"
                        >
                            <Calculator className="w-4 h-4 mr-2" />
                            {t('calculateStatistics')}
                        </button>
                    </div>

                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-4">
                            {t('results')}
                        </h3>
                        {statistics ? (
                            <div className="grid grid-cols-2 gap-4">
                                <StatBox label={t('stats.count')} value={statistics.count} />
                                <StatBox label={t('stats.sum')} value={statistics.sum} />
                                <StatBox label={t('stats.mean')} value={statistics.mean} />
                                <StatBox label={t('stats.median')} value={statistics.median} />
                                <StatBox label={t('stats.stdDev')} value={statistics.stdDev} />
                                <StatBox label={t('stats.min')} value={statistics.min} />
                                <StatBox label={t('stats.max')} value={statistics.max} />
                                <StatBox label={t('stats.mode')} value={statistics.mode?.join(', ') || 'N/A'} />
                            </div>
                        ) : (
                            <div className="text-center py-12 text-text-light dark:text-dark-text-muted">
                                {t('noResultsYet')}
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Import Tab */}
            {activeTab === 'import' && (
                <div className="grid lg:grid-cols-2 gap-6">
                    {/* Import from File */}
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-4 flex items-center gap-2">
                            <Upload className="w-5 h-5 text-gray-500" />
                            {t('importFromFile')}
                        </h3>
                        <label className="flex flex-col items-center justify-center p-8 border-2 border-dashed border-gray-300 dark:border-dark-border rounded-xl cursor-pointer hover:border-primary transition-colors">
                            <Upload className="w-10 h-10 text-gray-400 mb-3" />
                            <span className="text-sm text-text dark:text-dark-text font-medium">
                                {t('dropFileHere')}
                            </span>
                            <span className="text-xs text-text-light dark:text-dark-text-muted mt-1">
                                {t('orClickToBrowse')}
                            </span>
                            <input
                                type="file"
                                accept=".csv,.json"
                                onChange={handleFileImport}
                                className="hidden"
                            />
                        </label>
                    </div>

                    {/* Import from Resources */}
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-4 flex items-center gap-2">
                            <FileSpreadsheet className="w-5 h-5 text-emerald-500" />
                            {t('importFromResources')}
                        </h3>
                        <p className="text-xs text-text-light dark:text-dark-text-muted mb-3">
                            JSON & CSV files only
                        </p>
                        {availableDatasets.length > 0 ? (
                            <div className="space-y-2 max-h-60 overflow-y-auto">
                                {availableDatasets.map((dataset: any) => (
                                    <button
                                        key={dataset.id}
                                        onClick={async () => {
                                            if (!dataset.file_url) {
                                                showToast('No file URL available', 'error')
                                                return
                                            }
                                            setLoadingResource(dataset.id)
                                            try {
                                                const response = await fetch(dataset.file_url)
                                                const text = await response.text()

                                                if (dataset.file_type?.includes('json')) {
                                                    const json = JSON.parse(text)
                                                    if (Array.isArray(json)) {
                                                        setChartData(json.slice(0, 20))
                                                        setActiveTab('charts')
                                                        showToast('Data imported successfully!', 'success')
                                                    } else {
                                                        showToast('JSON must be an array of objects', 'error')
                                                    }
                                                } else {
                                                    // CSV
                                                    const lines = text.trim().split('\n').filter(l => l.trim())
                                                    if (lines.length < 2) {
                                                        showToast('CSV needs at least a header and one data row', 'error')
                                                        return
                                                    }
                                                    const headers = lines[0].split(',').map(h => h.trim())
                                                    const data = lines.slice(1).map(line => {
                                                        const values = line.split(',').map(v => v.trim())
                                                        const obj: any = { name: values[0] }
                                                        headers.slice(1).forEach((header, i) => {
                                                            const num = parseFloat(values[i + 1])
                                                            if (!isNaN(num)) obj[header.toLowerCase()] = num
                                                        })
                                                        return obj
                                                    })
                                                    setChartData(data.slice(0, 20))
                                                    setActiveTab('charts')
                                                    showToast('CSV imported successfully!', 'success')
                                                }
                                            } catch (error) {
                                                console.error('Import error:', error)
                                                showToast('Failed to import data', 'error')
                                            } finally {
                                                setLoadingResource(null)
                                            }
                                        }}
                                        disabled={loadingResource === dataset.id}
                                        className="w-full flex items-center gap-3 p-3 text-left border border-gray-200 dark:border-dark-border rounded-lg hover:border-primary dark:hover:border-secondary transition-colors disabled:opacity-50"
                                    >
                                        {loadingResource === dataset.id ? (
                                            <Loader2 className="w-5 h-5 text-emerald-500 flex-shrink-0 animate-spin" />
                                        ) : (
                                            <FileSpreadsheet className="w-5 h-5 text-emerald-500 flex-shrink-0" />
                                        )}
                                        <div className="min-w-0 flex-1">
                                            <span className="text-sm text-text dark:text-dark-text truncate block">
                                                {dataset.title}
                                            </span>
                                            {dataset.file_type && (
                                                <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                    {dataset.file_type.includes('json') ? 'JSON' : 'CSV'}
                                                </span>
                                            )}
                                        </div>
                                    </button>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-text-light dark:text-dark-text-muted">
                                {t('noDatasets')}
                            </div>
                        )}
                    </div>

                    {/* Import from Surveys */}
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-4 flex items-center gap-2">
                            <ClipboardList className="w-5 h-5 text-primary" />
                            {t('importFromSurveys')}
                        </h3>
                        {userSurveys.length > 0 ? (
                            <div className="space-y-2 max-h-60 overflow-y-auto">
                                {userSurveys.map((survey) => (
                                    <button
                                        key={survey.id}
                                        onClick={() => handleImportSurvey(survey.id)}
                                        disabled={loadingSurvey === survey.id || survey.response_count === 0}
                                        className={`w-full flex items-center justify-between gap-3 p-3 text-left border rounded-lg transition-colors ${survey.response_count === 0
                                            ? 'border-gray-100 dark:border-dark-border opacity-50 cursor-not-allowed'
                                            : 'border-gray-200 dark:border-dark-border hover:border-primary'
                                            }`}
                                    >
                                        <div className="flex items-center gap-3 min-w-0">
                                            {loadingSurvey === survey.id ? (
                                                <Loader2 className="w-5 h-5 text-primary animate-spin flex-shrink-0" />
                                            ) : (
                                                <ClipboardList className="w-5 h-5 text-primary flex-shrink-0" />
                                            )}
                                            <div className="min-w-0">
                                                <span className="text-sm text-text dark:text-dark-text truncate block">
                                                    {survey.title}
                                                </span>
                                                <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                    {survey.response_count} {t('responses')}
                                                </span>
                                            </div>
                                        </div>
                                        <span className={`text-xs px-2 py-0.5 rounded-full ${survey.status === 'active'
                                            ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400'
                                            : 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'
                                            }`}>
                                            {survey.status === 'active' ? t('active') : t('closed')}
                                        </span>
                                    </button>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-text-light dark:text-dark-text-muted">
                                {userId ? t('noSurveys') : t('loginToSeeSurveys')}
                            </div>
                        )}
                    </div>

                    {/* Import from Polls */}
                    <div className="bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-6">
                        <h3 className="font-medium text-text dark:text-dark-text mb-4 flex items-center gap-2">
                            <Vote className="w-5 h-5 text-amber-500" />
                            {t('importFromPolls')}
                        </h3>
                        {userPolls.length > 0 ? (
                            <div className="space-y-2 max-h-60 overflow-y-auto">
                                {userPolls.map((poll) => (
                                    <button
                                        key={poll.id}
                                        onClick={() => handleImportPoll(poll)}
                                        disabled={loadingPoll === poll.id || poll.total_votes === 0}
                                        className={`w-full flex items-center justify-between gap-3 p-3 text-left border rounded-lg transition-colors ${poll.total_votes === 0
                                            ? 'border-gray-100 dark:border-dark-border opacity-50 cursor-not-allowed'
                                            : 'border-gray-200 dark:border-dark-border hover:border-primary'
                                            }`}
                                    >
                                        <div className="flex items-center gap-3 min-w-0">
                                            {loadingPoll === poll.id ? (
                                                <Loader2 className="w-5 h-5 text-amber-500 animate-spin flex-shrink-0" />
                                            ) : (
                                                <Vote className="w-5 h-5 text-amber-500 flex-shrink-0" />
                                            )}
                                            <div className="min-w-0">
                                                <span className="text-sm text-text dark:text-dark-text truncate block">
                                                    {poll.question}
                                                </span>
                                                <span className="text-xs text-text-light dark:text-dark-text-muted">
                                                    {poll.total_votes} {t('votes')} ΓÇó {poll.options.length} {t('optionsCount')}
                                                </span>
                                            </div>
                                        </div>
                                        <span className={`text-xs px-2 py-0.5 rounded-full ${poll.is_active
                                            ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400'
                                            : 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'
                                            }`}>
                                            {poll.is_active ? t('active') : t('closed')}
                                        </span>
                                    </button>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-text-light dark:text-dark-text-muted">
                                {userId ? t('noPolls') : t('loginToSeePolls')}
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    )
}

function StatBox({ label, value }: { label: string; value: any }) {
    return (
        <div className="bg-gray-50 dark:bg-dark-bg rounded-lg p-3">
            <div className="text-xs text-text-light dark:text-dark-text-muted mb-1">
                {label}
            </div>
            <div className="text-lg font-semibold text-text dark:text-dark-text">
                {value ?? '-'}
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import {
    Plus,
    Trash2,
    GripVertical,
    Save,
    Eye,
    Send,
    ChevronDown,
    ChevronUp,
    Loader2,
    Settings,
    Type,
    List,
    CheckSquare,
    Star,
    Sliders,
    Calendar,
    Hash,
    AlignLeft,
    X
} from 'lucide-react'
import { useToast } from '@/components/ui/toast'
import { useTranslations } from 'next-intl'

interface SurveyBuilderProps {
    userId: string
    existingSurvey?: any
}

interface Question {
    id: string
    question_text: string
    question_type: string
    options?: { id: string; text: string }[]
    required: boolean
    description?: string
}

const QUESTION_TYPES_CONFIG = [
    { id: 'single_choice', labelKey: 'questionTypes.singleChoice', icon: List },
    { id: 'multiple_choice', labelKey: 'questionTypes.multipleChoice', icon: CheckSquare },
    { id: 'text', labelKey: 'questionTypes.shortText', icon: Type },
    { id: 'long_text', labelKey: 'questionTypes.longText', icon: AlignLeft },
    { id: 'scale', labelKey: 'questionTypes.scale', icon: Sliders },
    { id: 'rating', labelKey: 'questionTypes.rating', icon: Star },
    { id: 'number', labelKey: 'questionTypes.number', icon: Hash },
    { id: 'date', labelKey: 'questionTypes.date', icon: Calendar },
]

export function SurveyBuilder({ userId, existingSurvey }: SurveyBuilderProps) {
    const router = useRouter()
    const { showToast } = useToast()
    const t = useTranslations('Surveys')
    const tPolls = useTranslations('Polls')

    const [title, setTitle] = useState(existingSurvey?.title || '')
    const [description, setDescription] = useState(existingSurvey?.description || '')
    const [questions, setQuestions] = useState<Question[]>(existingSurvey?.questions || [])
    const [isAnonymous, setIsAnonymous] = useState(existingSurvey?.is_anonymous || false)
    const [saving, setSaving] = useState(false)
    const [showPreview, setShowPreview] = useState(false)
    const [expandedQuestion, setExpandedQuestion] = useState<string | null>(null)
    const [showSettings, setShowSettings] = useState(false)
    const [showAddQuestion, setShowAddQuestion] = useState(false)

    const addQuestion = (type: string) => {
        const newQuestion: Question = {
            id: `q_${Date.now()}`,
            question_text: '',
            question_type: type,
            required: false,
            options: type === 'single_choice' || type === 'multiple_choice'
                ? [{ id: 'opt_1', text: '' }, { id: 'opt_2', text: '' }]
                : undefined
        }
        setQuestions([...questions, newQuestion])
        setExpandedQuestion(newQuestion.id)
        setShowAddQuestion(false) // Close the panel after adding
    }

    const updateQuestion = (id: string, updates: Partial<Question>) => {
        setQuestions(questions.map(q =>
            q.id === id ? { ...q, ...updates } : q
        ))
    }

    const removeQuestion = (id: string) => {
        setQuestions(questions.filter(q => q.id !== id))
    }

    const addOption = (questionId: string) => {
        setQuestions(questions.map(q => {
            if (q.id !== questionId || !q.options) return q
            return {
                ...q,
                options: [...q.options, { id: `opt_${q.options.length + 1}`, text: '' }]
            }
        }))
    }

    const updateOption = (questionId: string, optionId: string, text: string) => {
        setQuestions(questions.map(q => {
            if (q.id !== questionId || !q.options) return q
            return {
                ...q,
                options: q.options.map(opt =>
                    opt.id === optionId ? { ...opt, text } : opt
                )
            }
        }))
    }

    const removeOption = (questionId: string, optionId: string) => {
        setQuestions(questions.map(q => {
            if (q.id !== questionId || !q.options || q.options.length <= 2) return q
            return {
                ...q,
                options: q.options.filter(opt => opt.id !== optionId)
            }
        }))
    }

    const moveQuestion = (index: number, direction: 'up' | 'down') => {
        if (
            (direction === 'up' && index === 0) ||
            (direction === 'down' && index === questions.length - 1)
        ) return

        const newQuestions = [...questions]
        const newIndex = direction === 'up' ? index - 1 : index + 1
            ;[newQuestions[index], newQuestions[newIndex]] = [newQuestions[newIndex], newQuestions[index]]
        setQuestions(newQuestions)
    }

    const handleSave = async (publish: boolean = false) => {
        if (!title.trim()) {
            showToast('Please enter a survey title', 'error')
            return
        }

        if (questions.length === 0) {
            showToast('Please add at least one question', 'error')
            return
        }

        // Validate questions
        for (const q of questions) {
            if (!q.question_text.trim()) {
                showToast('Please fill in all question texts', 'error')
                return
            }
            if (q.options) {
                const emptyOptions = q.options.filter(opt => !opt.text.trim())
                if (emptyOptions.length > 0) {
                    showToast('Please fill in all options', 'error')
                    return
                }
            }
        }

        setSaving(true)

        try {
            const isEditing = !!existingSurvey?.id
            const url = isEditing ? `/api/surveys/${existingSurvey.id}` : '/api/surveys'
            const method = isEditing ? 'PUT' : 'POST'

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    title,
                    description,
                    questions,
                    is_anonymous: isAnonymous,
                    status: publish ? 'active' : 'draft'
                })
            })

            if (!response.ok) {
                throw new Error('Failed to save survey')
            }

            const survey = await response.json()
            showToast(publish ? 'Survey published!' : 'Survey saved!', 'success')
            router.push(`/research-lab/surveys/${survey.id || existingSurvey.id}`)
        } catch (error) {
            showToast('Failed to save survey', 'error')
        } finally {
            setSaving(false)
        }
    }

    const getQuestionTypeIcon = (type: string) => {
        const config = QUESTION_TYPES_CONFIG.find(t => t.id === type)
        return config?.icon || Type
    }

    return (
        <div>
            {/* Header - Mobile responsive */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
                <h1 className="text-xl sm:text-2xl font-display font-bold text-text dark:text-dark-text">
                    {existingSurvey ? t('editSurvey') : t('createSurvey')}
                </h1>
                <div className="flex items-center gap-2 overflow-x-auto pb-2 sm:pb-0 -mx-1 px-1 scrollbar-hide">
                    <button
                        onClick={() => setShowSettings(!showSettings)}
                        className="btn btn-ghost text-xs sm:text-sm whitespace-nowrap px-2 sm:px-4"
                    >
                        <Settings className="w-4 h-4 sm:me-2" />
                        <span className="hidden sm:inline">{t('settings')}</span>
                    </button>
                    <button
                        onClick={() => setShowPreview(!showPreview)}
                        className="btn btn-ghost text-xs sm:text-sm whitespace-nowrap px-2 sm:px-4"
                    >
                        <Eye className="w-4 h-4 sm:me-2" />
                        <span className="hidden sm:inline">{t('preview')}</span>
                    </button>
                    <button
                        onClick={() => handleSave(false)}
                        disabled={saving}
                        className="btn btn-outline text-xs sm:text-sm whitespace-nowrap px-2 sm:px-4"
                    >
                        {saving ? <Loader2 className="w-4 h-4 animate-spin sm:me-2" /> : <Save className="w-4 h-4 sm:me-2" />}
                        <span className="hidden sm:inline">{t('saveDraft')}</span>
                    </button>
                    <button
                        onClick={() => handleSave(true)}
                        disabled={saving}
                        className="btn btn-primary text-xs sm:text-sm whitespace-nowrap px-3 sm:px-4"
                    >
                        <Send className="w-4 h-4 sm:me-2" />
                        <span className="hidden sm:inline">{t('publish')}</span>
                    </button>
                </div>
            </div>

