                                <span className="text-sm sm:text-base text-text dark:text-dark-text font-medium">{tPolls('anonymous')}</span>
                                <p className="text-xs sm:text-sm text-text-light dark:text-dark-text-muted">
                                    {t('anonymousDesc')}
                                </p>
                            </div>
                        </label>
