                        {/* Collapsible Question Types Grid */}
                        {showAddQuestion && (
                            <div className="mt-3 bg-white dark:bg-dark-surface rounded-xl border border-gray-200 dark:border-dark-border p-4 animate-in slide-in-from-top-2 duration-200">
