// Syria center and bounds
const SYRIA_CENTER: [number, number] = [35.0, 38.0]
const SYRIA_BOUNDS: [[number, number], [number, number]] = [
    [32.0, 35.5],
    [37.5, 42.5]
]

interface SpatialMapProps {
    spatialCoverage?: string | null
    spatialGeometry?: {
        type: string
        coordinates: number[] | number[][] | number[][][]
    } | null
    className?: string
    height?: string
    showLayerToggle?: boolean
    interactive?: boolean
}

export function SpatialMap({
    spatialCoverage,
    spatialGeometry,
    className = '',
    height = '280px',
    showLayerToggle = true,
    interactive = true
}: SpatialMapProps) {
    const t = useTranslations('Spatial')
    const [mounted, setMounted] = useState(false)
    const [showOSM, setShowOSM] = useState(true)
    const [expanded, setExpanded] = useState(false)

    // Parse spatial coverage to find matching location
    const matchedLocation = spatialCoverage
        ? Object.entries(SYRIA_LOCATIONS).find(([key]) =>
            spatialCoverage.toLowerCase().includes(key.toLowerCase())
        )?.[1]
        : null

    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect -- Intentional SSR hydration pattern
        setMounted(true)
    }, [])

    if (!mounted) {
        return (
            <div
                className={`bg-gray-100 dark:bg-dark-surface rounded-xl animate-pulse flex items-center justify-center ${className}`}
                style={{ height }}
            >
                <MapPin className="w-8 h-8 text-gray-400" />
            </div>
        )
    }

    const mapContent = (
        <div className="relative" style={{ height: expanded ? '70vh' : height }}>
            <MapContainer
                center={matchedLocation ? [matchedLocation.lat, matchedLocation.lng] : SYRIA_CENTER}
                zoom={matchedLocation ? 10 : 6}
                maxBounds={SYRIA_BOUNDS}
                minZoom={5}
                maxZoom={15}
                scrollWheelZoom={interactive}
                dragging={interactive}
                zoomControl={interactive}
                style={{ height: '100%', width: '100%', borderRadius: '0.75rem' }}
                className="z-0"
            >
                {/* Base tile layer - OpenStreetMap */}
                {showOSM && (
                    <TileLayer
                        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                    />
                )}

                {/* Auto-focus controller */}
                <MapViewController
                    center={matchedLocation ? [matchedLocation.lat, matchedLocation.lng] : SYRIA_CENTER}
                    zoom={matchedLocation ? 10 : 6}
                    bounds={(() => {
                        if (spatialGeometry?.type === 'Polygon' && spatialGeometry.coordinates) {
                            const coords = spatialGeometry.coordinates as any[]
                            let points: number[][] = []

                            // Handle standard GeoJSON number[][][] and simple number[][]
                            if (coords.length > 0) {
                                if (Array.isArray(coords[0]) && Array.isArray(coords[0][0])) {
                                    points = coords[0] as number[][]
                                } else {
                                    points = coords as number[][]
                                }
                            }

                            if (points.length > 0) {
                                const lats = points.map(c => c[1])
                                const lngs = points.map(c => c[0])
                                const minLat = Math.min(...lats)
                                const maxLat = Math.max(...lats)
                                const minLng = Math.min(...lngs)
                                const maxLng = Math.max(...lngs)

                                // Add 5% padding (reduced from 10%)
                                const latPad = (maxLat - minLat) * 0.05
                                const lngPad = (maxLng - minLng) * 0.05

                                return [
                                    [minLat - latPad, minLng - lngPad],
                                    [maxLat + latPad, maxLng + lngPad]
                                ] as [[number, number], [number, number]]
                            }
                        } else if (spatialGeometry?.type === 'Circle' && spatialGeometry.coordinates) {
                            // Focus on circle with padding equivalent to radius
                            const lat = spatialGeometry.coordinates[1] as number
                            const lng = spatialGeometry.coordinates[0] as number
                            // Rough approximation: 1 degree approx 111km
                            const radiusDeg = ((spatialGeometry as any).radius || 5000) / 111000
                            const pad = radiusDeg * 1.5
                            return [
                                [lat - pad, lng - pad],
                                [lat + pad, lng + pad]
                            ] as [[number, number], [number, number]]
                        } else if (spatialGeometry?.type === 'Point' && spatialGeometry.coordinates) {
                            // Focus on point
                            const lat = spatialGeometry.coordinates[1] as number
                            const lng = spatialGeometry.coordinates[0] as number
                            const pad = 0.05 // rough "zoom level 12-13" equivalent box
                            return [
                                [lat - pad, lng - pad],
                                [lat + pad, lng + pad]
                            ] as [[number, number], [number, number]]
                        }

                        return undefined
                    })()}
                />

                {/* Fallback neutral tiles */}
                {!showOSM && (
                    <TileLayer
                        attribution='&copy; <a href="https://carto.com/">CARTO</a>'
                        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
                    />
                )}

                {matchedLocation && (
                    <Circle
                        center={[matchedLocation.lat, matchedLocation.lng]}
                        radius={matchedLocation.radius}
                        pathOptions={{
                            color: '#1A3D40',
                            fillColor: '#4AA3A5',
                            fillOpacity: 0.15,
                            weight: 2,
                            dashArray: '5, 5'
                        }}
                    />
                )}

                {/* Render saved geometry */}
                {spatialGeometry && spatialGeometry.type === 'Point' && spatialGeometry.coordinates && spatialGeometry.coordinates.length >= 2 && (
                    <Marker position={[spatialGeometry.coordinates[1] as number, spatialGeometry.coordinates[0] as number]} />
                )}
                {spatialGeometry && spatialGeometry.type === 'Polygon' && spatialGeometry.coordinates && (
                    <Polygon
                        positions={(() => {
                            const coords = spatialGeometry.coordinates as any[]
                            if (!coords || coords.length === 0) return []

                            // Check for standard GeoJSON (number[][][]) - Array of rings
                            if (Array.isArray(coords[0]) && Array.isArray(coords[0][0])) {
                                return (coords[0] as number[][]).map(c => [c[1], c[0]] as [number, number])
                            }
                            // Check for simple Polygon (number[][]) - Array of points
                            else if (Array.isArray(coords[0]) && typeof coords[0][0] === 'number') {
                                return (coords as number[][]).map(c => [c[1], c[0]] as [number, number])
                            }

                            return []
                        })()}
                        pathOptions={{
                            color: '#1A3D40',
                            fillColor: '#4AA3A5',
                            fillOpacity: 0.2,
                            weight: 2
                        }}
                    />
                )}
                {spatialGeometry && (spatialGeometry as any).radius && spatialGeometry.coordinates && spatialGeometry.coordinates.length >= 2 && (
                    <Circle
                        center={[spatialGeometry.coordinates[1] as number, spatialGeometry.coordinates[0] as number]}
                        radius={(spatialGeometry as any).radius}
                        pathOptions={{
                            color: '#1A3D40',
                            fillColor: '#4AA3A5',
                            fillOpacity: 0.2,
                            weight: 2
                        }}
                    />
                )}
            </MapContainer>

            {/* Layer Toggle */}
            {showLayerToggle && (
                <div className="absolute top-3 right-3 z-10 flex gap-2">
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setShowOSM(!showOSM)}
                        className="bg-white/90 dark:bg-dark-surface/90 backdrop-blur-sm shadow-sm"
                    >
                        <Layers className="w-4 h-4 mr-1" />
                        {showOSM ? 'OSM' : 'Light'}
                    </Button>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setExpanded(!expanded)}
                        className="bg-white/90 dark:bg-dark-surface/90 backdrop-blur-sm shadow-sm"
                    >
                        {expanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
                    </Button>
                </div>
            )}

            {/* Location Label */}
            {spatialCoverage && (
                <div className="absolute bottom-3 left-3 z-10 px-3 py-1.5 bg-white/90 dark:bg-dark-surface/90 backdrop-blur-sm rounded-lg shadow-sm text-sm font-medium text-text dark:text-dark-text flex items-center gap-2">
                    <MapPin className="w-4 h-4 text-primary" />
                    {spatialCoverage}
                </div>
            )}
        </div>
    )

    return (
        <div className={className}>
            {expanded ? (
                <Dialog open={expanded} onOpenChange={setExpanded}>
                    <DialogContent className="max-w-4xl p-0 overflow-hidden">
                        <DialogHeader className="p-4 pb-0">
                            <DialogTitle className="flex items-center gap-2">
                                <MapPin className="w-5 h-5 text-primary" />
                                {t('spatialContext')}
                            </DialogTitle>
                        </DialogHeader>
                        <div className="p-4 pt-2">
                            {mapContent}
                        </div>
                    </DialogContent>
                </Dialog>
            ) : (
                mapContent
            )}
        </div>
    )
}

'use client'

import { createContext, useContext, useState, useEffect, useCallback, useMemo, ReactNode } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { User as SupabaseUser, Session } from '@supabase/supabase-js'
import type { UserRole } from '@/types'

// ΓöÇΓöÇΓöÇ Public types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export interface AuthUser {
  id: string
  email?: string
  name?: string
  avatarUrl?: string
  role: UserRole
}

interface AuthContextType {
  /** The resolved user (null when logged out or still loading) */
  user: AuthUser | null
  /** Raw Supabase session ΓÇö useful for token access */
  session: Session | null
  /** True while the initial auth check is in progress */
  isLoading: boolean
  /** Convenience boolean ΓÇö false while loading */
  isAuthenticated: boolean
  /** Force a re-fetch of user profile data (role, avatar, etc.) */
  refreshProfile: () => Promise<void>
  /** Sign out and redirect to home */
  signOut: () => Promise<void>
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

// ΓöÇΓöÇΓöÇ Hook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function useAuth(): AuthContextType {
  const ctx = useContext(AuthContext)
  if (!ctx) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return ctx
}

// ΓöÇΓöÇΓöÇ Provider ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface AuthProviderProps {
  children: ReactNode
  /** Pre-fetched user from the server layout (avoids an extra round-trip) */
  serverUser?: { id: string; email?: string } | null
}

export function AuthProvider({ children, serverUser }: AuthProviderProps) {
  const supabase = useMemo(() => createClient(), [])

  const [session, setSession] = useState<Session | null>(null)
  const [authUser, setAuthUser] = useState<AuthUser | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  // ΓöÇΓöÇ Fetch profile (role + avatar) from users table ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchProfile = useCallback(
    async (userId: string, email?: string, meta?: Record<string, unknown>) => {
      const { data } = await supabase
        .from('users')
        .select('name, avatar_url, role')
        .eq('id', userId)
        .maybeSingle()

      const resolved: AuthUser = {
        id: userId,
        email: email ?? undefined,
        name: data?.name ?? (meta?.full_name as string) ?? (meta?.name as string) ?? undefined,
        avatarUrl: data?.avatar_url ?? (meta?.avatar_url as string) ?? undefined,
        role: (data?.role as UserRole) ?? 'member',
      }

      setAuthUser(resolved)
      return resolved
    },
    [supabase],
  )

  // ΓöÇΓöÇ Public refresh helper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const refreshProfile = useCallback(async () => {
    if (authUser?.id) {
      await fetchProfile(authUser.id, authUser.email)
    }
  }, [authUser?.id, authUser?.email, fetchProfile])

  // ΓöÇΓöÇ Sign out ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const signOut = useCallback(async () => {
    await supabase.auth.signOut()
    setSession(null)
    setAuthUser(null)
    // Redirect handled by the auth state change listener below ΓÇö
    // but also do a hard navigate to clear any stale client state.
    window.location.href = '/'
  }, [supabase])

  // ΓöÇΓöÇ Bootstrap: get the initial session then listen for changes ΓöÇΓöÇ
  useEffect(() => {
    let mounted = true

    // 1. Resolve initial session
    async function init() {
      try {
        const { data: { session: currentSession } } = await supabase.auth.getSession()

        if (!mounted) return

        if (currentSession?.user) {
          setSession(currentSession)
          await fetchProfile(
            currentSession.user.id,
            currentSession.user.email ?? undefined,
            currentSession.user.user_metadata,
          )
        } else if (serverUser) {
          // Fallback: use the server-provided user hint
          await fetchProfile(serverUser.id, serverUser.email)
        }
      } catch {
        // Auth unavailable ΓÇö treat as logged-out
      } finally {
        if (mounted) setIsLoading(false)
      }
    }

    init()

    // 2. Subscribe to auth changes (sign-in, sign-out, token refresh)
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, newSession) => {
        if (!mounted) return

        setSession(newSession)

        if (newSession?.user) {
          await fetchProfile(
            newSession.user.id,
            newSession.user.email ?? undefined,
            newSession.user.user_metadata,
          )
        } else {
          setAuthUser(null)
        }

        // On sign-out, loading is already false ΓÇö nothing extra to do
      },
    )

    return () => {
      mounted = false
      subscription.unsubscribe()
    }
  }, [supabase, serverUser, fetchProfile])

  // ΓöÇΓöÇ Memoised context value ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const value = useMemo<AuthContextType>(
    () => ({
      user: authUser,
      session,
      isLoading,
      isAuthenticated: !isLoading && authUser !== null,
      refreshProfile,
      signOut,
    }),
    [authUser, session, isLoading, refreshProfile, signOut],
  )

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

