// API utilities for standardized responses and error handling
import { NextResponse } from 'next/server'
import type { PostgrestError } from '@supabase/supabase-js'

export interface ApiResponse<T = any> {
  success: boolean
  data?: T
  error?: string
  message?: string
  requestId?: string
}

/**
 * Generate a unique request ID for tracing and debugging
 * Format: req_<timestamp_base36>_<random_9chars>
 * Example: req_lz5k8m2_a1b2c3d4e
 */
export function generateRequestId(): string {
  return `req_${Date.now().toString(36)}_${Math.random().toString(36).substring(2, 11)}`
}

/**
 * Add request ID header to a response
 */
export function withRequestId(response: NextResponse, requestId: string): NextResponse {
  response.headers.set('x-request-id', requestId)
  return response
}

/**
 * Create a successful JSON response
 */
export function successResponse<T>(data: T, status = 200, requestId?: string): NextResponse<ApiResponse<T>> {
  const response = NextResponse.json(
    {
      success: true,
      data,
      ...(requestId && { requestId }),
    },
    { status }
  )
  if (requestId) {
    response.headers.set('x-request-id', requestId)
  }
  return response
}

/**
 * Create an error JSON response
 */
export function errorResponse(
  message: string,
  status = 400,
  requestId?: string
): NextResponse<ApiResponse> {
  const response = NextResponse.json(
    {
      success: false,
      error: message,
      ...(requestId && { requestId }),
    },
    { status }
  )
  if (requestId) {
    response.headers.set('x-request-id', requestId)
  }
  return response
}

/**
 * Handle Supabase/Postgres errors
 */
export function handleSupabaseError(error: PostgrestError | Error | null): NextResponse<ApiResponse> {
  if (!error) {
    return errorResponse('An unknown error occurred', 500)
  }

  // Check if it's a PostgrestError
  if ('code' in error) {
    const pgError = error as PostgrestError

    // Map common Postgres error codes to user-friendly messages
    switch (pgError.code) {
      case '23505': // unique_violation
        return errorResponse('A record with this information already exists', 409)
      case '23503': // foreign_key_violation
        return errorResponse('Referenced record does not exist', 400)
      case '23502': // not_null_violation
        return errorResponse('Required field is missing', 400)
      case 'PGRST116': // No rows found
        return errorResponse('Record not found', 404)
      case '42501': // insufficient_privilege
        return errorResponse('Insufficient permissions', 403)
      default:
        return errorResponse(pgError.message || 'Database error occurred', 500)
    }
  }

  // Handle regular errors
  return errorResponse(error.message || 'An error occurred', 500)
}

/**
 * Handle authentication errors
 */
export function unauthorizedResponse(message = 'Authentication required'): NextResponse<ApiResponse> {
  return errorResponse(message, 401)
}

/**
 * Handle authorization errors
 */
export function forbiddenResponse(message = 'Insufficient permissions'): NextResponse<ApiResponse> {
  return errorResponse(message, 403)
}

/**
 * Handle not found errors
 */
export function notFoundResponse(message = 'Resource not found'): NextResponse<ApiResponse> {
  return errorResponse(message, 404)
}

/**
 * Handle validation errors
 */
export function validationErrorResponse(message: string): NextResponse<ApiResponse> {
  return errorResponse(message, 422)
}

/**
 * Parse and validate request body
 */
export async function parseRequestBody<T>(request: Request): Promise<T> {
  try {
    const body = await request.json()
    return body as T
  } catch {
    throw new Error('Invalid JSON in request body')
  }
}

/**
 * SECURITY: Validate and sanitize pagination parameters to prevent DoS attacks
 * Enforces maximum limits and ensures non-negative values
 */
export function sanitizePaginationParams(
  params: URLSearchParams,
  options: { maxLimit?: number; defaultLimit?: number } = {}
): { limit: number; offset: number } {
  const { maxLimit = 100, defaultLimit = 20 } = options

  let limit = parseInt(params.get('limit') || String(defaultLimit), 10)
  let offset = parseInt(params.get('offset') || '0', 10)

  // Ensure non-negative and within bounds
  limit = Math.max(1, Math.min(limit, maxLimit))
  offset = Math.max(0, offset)

  // Prevent extremely large offsets that could cause performance issues
  offset = Math.min(offset, 10000)

  return { limit, offset }
}

/**
 * Get query parameters from URL
 */
export function getQueryParams(request: Request): URLSearchParams {
  const { searchParams } = new URL(request.url)
  return searchParams
}

/**
 * Validate required fields in an object
 */
export function validateRequiredFields<T extends Record<string, any>>(
  data: T,
  requiredFields: (keyof T)[]
): void {
  const missing = requiredFields.filter(field => !data[field])

  if (missing.length > 0) {
    throw new Error(`Missing required fields: ${missing.join(', ')}`)
  }
}

/**
 * Wrap async route handler with error handling and request ID tracking
 */
export function withErrorHandling(
  handler: (request: Request, context?: any) => Promise<NextResponse>,
  options?: {
    cache?: {
      enabled?: boolean
      maxAge?: number
      staleWhileRevalidate?: number
      vary?: string[]
    }
  }
) {
  return async (request: Request, context?: any): Promise<NextResponse> => {
    // Generate request ID for correlation
    const requestId = generateRequestId()

    try {
      const response = await handler(request, context)

      // Always add request ID to successful responses
      response.headers.set('x-request-id', requestId)

      const cacheOptions = options?.cache
      if (cacheOptions && cacheOptions.enabled !== false && request.method === 'GET') {
        if (!response.headers.has('Cache-Control')) {
          const maxAge = cacheOptions.maxAge ?? 60
          const stale = cacheOptions.staleWhileRevalidate ?? 300
          response.headers.set('Cache-Control', `s-maxage=${maxAge}, stale-while-revalidate=${stale}`)
        }

        const varyHeaders = cacheOptions.vary ?? ['Authorization', 'Cookie']
        if (varyHeaders.length > 0) {
          const existing = response.headers.get('Vary')
          const current = existing
            ? existing.split(',').map(header => header.trim()).filter(Boolean)
            : []
          const merged = Array.from(new Set([...current, ...varyHeaders]))
          response.headers.set('Vary', merged.join(', '))
        }
      }

      return response
    } catch (error) {
      // Log with request ID for correlation
      console.error(`[${requestId}] API Error:`, error)

      if (error instanceof Error) {
        // Handle specific error types
        if (error.message === 'Unauthorized') {
          return withRequestId(unauthorizedResponse(), requestId)
        }
        if (error.message.startsWith('Forbidden')) {
          return withRequestId(forbiddenResponse(error.message), requestId)
        }
        if (error.message.includes('not found')) {
          return withRequestId(notFoundResponse(), requestId)
        }

        return errorResponse(error.message, 400, requestId)
      }

      return errorResponse('An unexpected error occurred', 500, requestId)
    }
  }
}

/**
 * Extract user ID from path parameters
 */
export function extractIdFromParams(params: any): string {
  const id = params?.id

  if (!id || typeof id !== 'string') {
    throw new Error('Invalid or missing ID parameter')
  }

  return id
}

/**
 * SECURITY: Validate request origin for CSRF protection
 * This should be used on all state-changing (mutation) endpoints that use cookie auth
 * 
 * @param request - The incoming request
 * @returns true if origin is valid, false otherwise
 */
export function validateOrigin(request: Request): boolean {
  const origin = request.headers.get('origin')
  const referer = request.headers.get('referer')

  // Get allowed origins from environment
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || process.env.SITE_URL || 'https://syriahub.com'
  const vercelUrl = process.env.NEXT_PUBLIC_VERCEL_URL ? `https://${process.env.NEXT_PUBLIC_VERCEL_URL}` : null

  const allowedOrigins = [
    siteUrl,
    new URL(siteUrl).origin,
    'https://syriahub.org',
    'https://www.syriahub.org',
    'https://syriahub.com',
    'https://www.syriahub.com',
    'http://localhost:3000',
    'http://127.0.0.1:3000',
  ]

  if (vercelUrl) {
    allowedOrigins.push(vercelUrl)
  }

  // In development, be more permissive
  if (process.env.NODE_ENV === 'development') {
    return true
  }

  // Check origin header first (preferred)
  if (origin) {
    return allowedOrigins.some(allowed => origin === allowed || origin === new URL(allowed).origin)
  }

  // Fall back to referer header
  if (referer) {
    try {
      const refererOrigin = new URL(referer).origin
      return allowedOrigins.some(allowed => refererOrigin === allowed || refererOrigin === new URL(allowed).origin)
    } catch {
      return false
    }
  }

  // If no origin or referer, reject (could be a direct request from non-browser)
  // Exception: Some legitimate tools don't send origin, but we err on the side of security
  return false
}

/**
 * SECURITY: Middleware wrapper to validate origin on mutation endpoints
 * Use this on POST, PUT, PATCH, DELETE handlers that use cookie auth
 */
export function withOriginValidation<T extends any[]>(
  handler: (request: Request, ...args: T) => Promise<NextResponse>
) {
  return async (request: Request, ...args: T): Promise<NextResponse> => {
    // Only validate on mutation methods
    if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(request.method)) {
      if (!validateOrigin(request)) {
        return errorResponse('Invalid request origin', 403)
      }
    }
    return handler(request, ...args)
  }
}

/**
 * Academic Citation Export Module
 * Generates BibTeX, RIS, and other citation formats from post data
 */

export interface CitationData {
    id: string
    title: string
    author: {
        name?: string
        email?: string
        affiliation?: string
    }
    abstract?: string
    content?: string
    tags?: string[]
    created_at: string
    updated_at?: string
    url?: string
    doi?: string
    license?: string
}

/**
 * Generate a citation key from title and author
 */
function generateCiteKey(data: CitationData): string {
    const authorPart = (data.author?.name || 'unknown')
        .split(' ')
        .pop()
        ?.toLowerCase()
        .replace(/[^a-z]/g, '') || 'unknown'

    const year = new Date(data.created_at).getFullYear()

    const titlePart = (data.title || 'untitled')
        .split(' ')
        .slice(0, 2)
        .join('')
        .toLowerCase()
        .replace(/[^a-z]/g, '')
        .slice(0, 10)

    return `${authorPart}${year}${titlePart}`
}

/**
 * Format author name for BibTeX (Last, First)
 */
function formatAuthorBibTeX(author: CitationData['author']): string {
    if (!author?.name) return 'Unknown Author'

    const parts = author.name.trim().split(/\s+/)
    if (parts.length === 1) return parts[0]

    const lastName = parts.pop()
    const firstName = parts.join(' ')
    return `${lastName}, ${firstName}`
}

/**
 * Format author name for RIS (Last,First)
 */
function formatAuthorRIS(author: CitationData['author']): string {
    if (!author?.name) return 'Unknown Author'

    const parts = author.name.trim().split(/\s+/)
    if (parts.length === 1) return parts[0]

    const lastName = parts.pop()
    const firstName = parts.join(' ')
    return `${lastName},${firstName}`
}

/**
 * Escape special characters for BibTeX
 */
function escapeBibTeX(text: string): string {
    return text
        .replace(/\\/g, '\\textbackslash{}')
        .replace(/&/g, '\\&')
        .replace(/%/g, '\\%')
        .replace(/\$/g, '\\$')
        .replace(/#/g, '\\#')
        .replace(/_/g, '\\_')
        .replace(/\{/g, '\\{')
        .replace(/\}/g, '\\}')
        .replace(/~/g, '\\textasciitilde{}')
        .replace(/\^/g, '\\textasciicircum{}')
}

/**
 * Get abstract from content (first 300 chars of content)
 */
function getAbstract(data: CitationData): string {
    if (data.abstract) return data.abstract
    if (!data.content) return ''

    // Remove markdown formatting and truncate
    const plainText = data.content
        .replace(/[#*_`\[\]]/g, '')
        .replace(/\n+/g, ' ')
        .trim()

    if (plainText.length <= 300) return plainText
    return plainText.slice(0, 297) + '...'
}

// ==================== BibTeX Export ====================

/**
 * Generate BibTeX citation
 * @article{citekey,
 *   author = {Last, First},
 *   title = {Title},
 *   year = {2024},
 *   ...
 * }
 */
export function generateBibTeX(data: CitationData): string {
    const citeKey = generateCiteKey(data)
    const date = new Date(data.created_at)
    const abstract = getAbstract(data)

    const fields: string[] = []

    fields.push(`  author = {${formatAuthorBibTeX(data.author)}}`)
    fields.push(`  title = {${escapeBibTeX(data.title)}}`)
    fields.push(`  year = {${date.getFullYear()}}`)
    fields.push(`  month = {${date.toLocaleString('en', { month: 'short' }).toLowerCase()}}`)

    if (data.url) {
        fields.push(`  url = {${data.url}}`)
    }

    if (data.doi) {
        fields.push(`  doi = {${data.doi}}`)
    }

    if (abstract) {
        fields.push(`  abstract = {${escapeBibTeX(abstract)}}`)
    }

    if (data.tags && data.tags.length > 0) {
        fields.push(`  keywords = {${data.tags.join(', ')}}`)
    }

    if (data.author?.affiliation) {
        fields.push(`  institution = {${escapeBibTeX(data.author.affiliation)}}`)
    }

    fields.push(`  note = {Published on SyriaHub}`)

    return `@article{${citeKey},\n${fields.join(',\n')}\n}`
}

// ==================== RIS Export ====================

/**
 * Generate RIS (Research Information Systems) citation
 * Used by EndNote, Zotero, Mendeley, etc.
 */
export function generateRIS(data: CitationData): string {
    const date = new Date(data.created_at)
    const abstract = getAbstract(data)

    const lines: string[] = []

    // Type of reference (JOUR = Journal Article, ELEC = Web Page, RPRT = Report)
    lines.push('TY  - ELEC')

    // Authors
    lines.push(`AU  - ${formatAuthorRIS(data.author)}`)

    // Title
    lines.push(`TI  - ${data.title}`)

    // Publication year
    lines.push(`PY  - ${date.getFullYear()}`)

    // Date
    lines.push(`DA  - ${date.getFullYear()}/${String(date.getMonth() + 1).padStart(2, '0')}/${String(date.getDate()).padStart(2, '0')}`)

    // Abstract
    if (abstract) {
        lines.push(`AB  - ${abstract}`)
    }

    // Keywords
    if (data.tags && data.tags.length > 0) {
        data.tags.forEach(tag => {
            lines.push(`KW  - ${tag}`)
        })
    }

    // URL
    if (data.url) {
        lines.push(`UR  - ${data.url}`)
    }

    // DOI
    if (data.doi) {
        lines.push(`DO  - ${data.doi}`)
    }

    // Publisher
    lines.push('PB  - SyriaHub')

    // Database provider
    lines.push('DP  - SyriaHub Research Platform')

    // Unique ID
    lines.push(`ID  - ${data.id}`)

    // End of reference
    lines.push('ER  - ')

    return lines.join('\n')
}

// ==================== Other Formats ====================

/**
 * Generate APA 7th Edition citation
 */
export function generateAPA(data: CitationData): string {
    const date = new Date(data.created_at)
    const authorName = data.author?.name || 'Unknown Author'
    const year = date.getFullYear()

    // Format: Author, A. A. (Year, Month Day). Title. SyriaHub. URL
    const parts = authorName.split(' ')
    let formattedAuthor: string

    if (parts.length === 1) {
        formattedAuthor = parts[0]
    } else {
        const lastName = parts.pop()
        const initials = parts.map(n => `${n[0]}.`).join(' ')
        formattedAuthor = `${lastName}, ${initials}`
    }

    const monthDay = date.toLocaleDateString('en-US', { month: 'long', day: 'numeric' })

    let citation = `${formattedAuthor} (${year}, ${monthDay}). ${data.title}. SyriaHub.`

    if (data.url) {
        citation += ` ${data.url}`
    }

    return citation
}

/**
 * Generate MLA 9th Edition citation
 */
export function generateMLA(data: CitationData): string {
    const date = new Date(data.created_at)
    const authorName = data.author?.name || 'Unknown Author'

    // Format: Last, First. "Title." SyriaHub, Day Month Year, URL.
    const parts = authorName.split(' ')
    let formattedAuthor: string

    if (parts.length === 1) {
        formattedAuthor = parts[0]
    } else {
        const lastName = parts.pop()
        const firstName = parts.join(' ')
        formattedAuthor = `${lastName}, ${firstName}`
    }

    const day = date.getDate()
    const month = date.toLocaleDateString('en-US', { month: 'short' })
    const year = date.getFullYear()

    let citation = `${formattedAuthor}. "${data.title}." SyriaHub, ${day} ${month}. ${year}`

    if (data.url) {
        citation += `, ${data.url}`
    }

    citation += '.'

    return citation
}

/**
 * Generate Chicago 17th Edition citation
 */
export function generateChicago(data: CitationData): string {
    const date = new Date(data.created_at)
    const authorName = data.author?.name || 'Unknown Author'

    // Format: Last, First. "Title." SyriaHub. Published Month Day, Year. URL.
    const parts = authorName.split(' ')
    let formattedAuthor: string

    if (parts.length === 1) {
        formattedAuthor = parts[0]
    } else {
        const lastName = parts.pop()
        const firstName = parts.join(' ')
        formattedAuthor = `${lastName}, ${firstName}`
    }

    const publishedDate = date.toLocaleDateString('en-US', {
        month: 'long',
        day: 'numeric',
        year: 'numeric'
    })

    let citation = `${formattedAuthor}. "${data.title}." SyriaHub. Published ${publishedDate}.`

    if (data.url) {
        citation += ` ${data.url}.`
    }

    return citation
}

// ==================== Export Helpers ====================

export type CitationFormat = 'bibtex' | 'ris' | 'apa' | 'mla' | 'chicago'

/**
 * Generate citation in specified format
 */
export function generateCitation(data: CitationData, format: CitationFormat): string {
    switch (format) {
        case 'bibtex':
            return generateBibTeX(data)
        case 'ris':
            return generateRIS(data)
        case 'apa':
            return generateAPA(data)
        case 'mla':
            return generateMLA(data)
        case 'chicago':
            return generateChicago(data)
        default:
            throw new Error(`Unknown citation format: ${format}`)
    }
}

/**
 * Get MIME type for citation format
 */
export function getCitationMimeType(format: CitationFormat): string {
    switch (format) {
        case 'bibtex':
            return 'application/x-bibtex'
        case 'ris':
            return 'application/x-research-info-systems'
        default:
            return 'text/plain'
    }
}

/**
 * Get file extension for citation format
 */
export function getCitationFileExtension(format: CitationFormat): string {
    switch (format) {
        case 'bibtex':
            return '.bib'
        case 'ris':
            return '.ris'
        default:
            return '.txt'
    }
}

/**
 * Download citation as file
 */
export function downloadCitation(data: CitationData, format: CitationFormat): void {
    const citation = generateCitation(data, format)
    const mimeType = getCitationMimeType(format)
    const extension = getCitationFileExtension(format)

    const blob = new Blob([citation], { type: mimeType })
    const url = URL.createObjectURL(blob)

    const link = document.createElement('a')
    link.href = url
    link.download = `${generateCiteKey(data)}${extension}`
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    URL.revokeObjectURL(url)
}

// ==================== Platform Citations ====================

/**
 * Generate a query hash for reproducible citations
 * Creates a stable identifier for a specific search query and filters
 */
export function generateQueryHash(query: string, filters: Record<string, any>, timestamp: number): string {
    const data = JSON.stringify({ query, filters, timestamp })
    let hash = 0
    for (let i = 0; i < data.length; i++) {
        const char = data.charCodeAt(i)
        hash = ((hash << 5) - hash) + char
        hash = hash & hash // Convert to 32bit integer
    }
    return Math.abs(hash).toString(36).substring(0, 8).toUpperCase()
}

/**
 * Web reference data for external sources
 */
export interface WebReferenceData {
    title: string
    url: string
    source: string
    snippet?: string
    accessDate?: string
}

/**
 * Generate SyriaHub Platform citation for web references
 * Format: Title. (Source). Retrieved via SyriaHub Research Platform [SH-HASH]. Access date: Date. URL
 */
export function generatePlatformCitation(
    data: WebReferenceData,
    queryHash?: string,
    searchQuery?: string
): string {
    const accessDate = data.accessDate || new Date().toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    })
    const hashPart = queryHash ? ` [SH-${queryHash}]` : ''
    const queryPart = searchQuery ? ` Search: "${searchQuery}".` : ''

    return `${data.title}. (${data.source || 'Web'}).${queryPart} Retrieved via SyriaHub Research Platform${hashPart}. Access date: ${accessDate}. ${data.url}`
}

/**
 * Generate APA-style web citation
 */
export function generateWebAPA(data: WebReferenceData): string {
    const accessDate = data.accessDate || new Date().toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    })
    const author = data.source || 'Unknown Author'

    return `${author}. (n.d.). ${data.title}. Retrieved ${accessDate}, from ${data.url}`
}

/**
 * Generate Chicago-style web citation
 */
export function generateWebChicago(data: WebReferenceData): string {
    const accessDate = data.accessDate || new Date().toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    })
    const author = data.source || 'Unknown Author'

    return `${author}. "${data.title}." Accessed ${accessDate}. ${data.url}.`
}

/**
 * Generate all citation formats for a web reference
 */
export function generateWebCitations(
    data: WebReferenceData,
    queryHash?: string,
    searchQuery?: string
): {
    apa: string
    chicago: string
    platform: string
} {
    return {
        apa: generateWebAPA(data),
        chicago: generateWebChicago(data),
        platform: generatePlatformCitation(data, queryHash, searchQuery)
    }
}

// ==================== Reproducible Share Links ====================

/**
 * Generate a reproducible share link with encoded parameters
 * Allows other researchers to reproduce the exact same search
 */
export function generateShareableLink(
    baseUrl: string,
    params: {
        query: string
        source?: 'internal' | 'web' | 'all'
        disciplines?: string[]
        evidenceTiers?: string[]
        minTrust?: number
        date?: string
    }
): string {
    const searchParams = new URLSearchParams()

    searchParams.set('q', params.query)
    if (params.source) searchParams.set('src', params.source)
    if (params.disciplines?.length) searchParams.set('disc', params.disciplines.join(','))
    if (params.evidenceTiers?.length) searchParams.set('tier', params.evidenceTiers.join(','))
    if (params.minTrust) searchParams.set('trust', params.minTrust.toString())
    if (params.date) searchParams.set('dt', params.date)
    searchParams.set('ts', Date.now().toString())

    return `${baseUrl}?${searchParams.toString()}`
}

/**
 * Parse a shareable link back to search parameters
 */
export function parseShareableLink(url: string): {
    query: string
    source?: 'internal' | 'web' | 'all'
    disciplines?: string[]
    evidenceTiers?: string[]
    minTrust?: number
    date?: string
    timestamp?: number
} | null {
    try {
        const urlObj = new URL(url)
        const params = urlObj.searchParams

        const query = params.get('q')
        if (!query) return null

        return {
            query,
            source: params.get('src') as 'internal' | 'web' | 'all' | undefined,
            disciplines: params.get('disc')?.split(',').filter(Boolean),
            evidenceTiers: params.get('tier')?.split(',').filter(Boolean),
            minTrust: params.get('trust') ? parseInt(params.get('trust')!) : undefined,
            date: params.get('dt') || undefined,
            timestamp: params.get('ts') ? parseInt(params.get('ts')!) : undefined
        }
    } catch {
        return null
    }
}

import nodemailer from 'nodemailer'
import { Resend } from 'resend'
import { createServerClient } from './supabaseClient'

interface EmailOptions {
  to: string
  subject: string
  html: string
  text?: string
}

// Email configuration constants
const EMAIL_CONFIG = {
  fromName: 'SyriaHub via PluraGate',
  fromEmail: process.env.RESEND_FROM_EMAIL || 'admin@pluragate.org',
  replyTo: process.env.SMTP_REPLY_TO || 'admin@pluragate.org',
}

// Invitation-specific email configuration (uses syriahub.org domain)
const INVITATION_EMAIL_CONFIG = {
  fromName: 'SyriaHub',
  fromEmail: process.env.INVITATION_FROM_EMAIL || 'invitations@syriahub.org',
  replyTo: process.env.INVITATION_REPLY_TO || 'invitations@syriahub.org',
}

// Initialize Resend client (if API key is available)
const resend = process.env.RESEND_API_KEY ? new Resend(process.env.RESEND_API_KEY) : null

// Create reusable nodemailer transporter (fallback)
const createTransporter = () => {
  const host = process.env.SMTP_HOST || 'smtp.gmail.com'
  const port = parseInt(process.env.SMTP_PORT || '465')

  // Secure is true for port 465, false for most others (which use STARTTLS)
  // Allow explicit override via SMTP_SECURE env var
  const secure = process.env.SMTP_SECURE !== undefined
    ? process.env.SMTP_SECURE === 'true'
    : port === 465

  const config = {
    host,
    port,
    secure,
    auth: {
      user: process.env.SMTP_USER,
      pass: process.env.SMTP_PASSWORD, // App password for Google Workspace or provider key
    },
    // Add timeouts to prevent hanging processes
    connectionTimeout: 10000,
    greetingTimeout: 10000,
    socketTimeout: 10000,
  }

  // Debug log (sanitized)
  console.log(`≡ƒôº Creating mail transporter for ${host}:${port} (secure: ${secure})`)

  return nodemailer.createTransport(config)
}

/**
 * Send email using Resend (preferred) or fallback to nodemailer
 */
export async function sendEmail({ to, subject, html, text }: EmailOptions): Promise<boolean> {
  const supabase = await createServerClient()

  try {
    // Only use Supabase Edge Functions if explicitly requested
    if (process.env.USE_EDGE_FUNCTIONS === 'true') {
      const { data, error } = await supabase.functions.invoke('send-email', {
        body: { to, subject, html, text },
      })

      if (error) throw error

      // Log to database
      await supabase.from('email_logs').insert({
        recipient_email: to,
        subject,
        status: 'sent',
        sent_at: new Date().toISOString(),
      })

      return true
    }

    // Use Resend if API key is configured (better deliverability)
    if (resend) {
      console.log('≡ƒôº Sending email via Resend...')

      const { data, error } = await resend.emails.send({
        from: `${EMAIL_CONFIG.fromName} <${EMAIL_CONFIG.fromEmail}>`,
        to: [to],
        subject,
        html,
        text: text || html.replace(/<[^>]*>/g, ''),
        replyTo: EMAIL_CONFIG.replyTo,
        headers: {
          'List-Unsubscribe': '<mailto:unsubscribe@pluragate.org>',
        },
      })

      if (error) {
        console.error('Γ¥î Resend error:', error.message)
        throw new Error(error.message)
      }

      console.log('Γ£à Email sent via Resend:', data?.id)

      // Log to database
      await supabase.from('email_logs').insert({
        recipient_email: to,
        subject,
        status: 'sent',
        sent_at: new Date().toISOString(),
      })

      return true
    }

    // Fallback to nodemailer (Gmail SMTP)
    console.log('≡ƒôº Sending email via nodemailer (SMTP fallback)...')
    const transporter = createTransporter()

    // Verify transporter connection before sending
    try {
      await transporter.verify()
    } catch (verifyError: any) {
      console.error('Γ¥î SMTP Connection Verification Failed:', verifyError.message)
      throw verifyError
    }

    await transporter.sendMail({
      from: `"${EMAIL_CONFIG.fromName}" <${process.env.SMTP_USER || EMAIL_CONFIG.fromEmail}>`,
      replyTo: EMAIL_CONFIG.replyTo,
      to,
      subject,
      html,
      text: text || html.replace(/<[^>]*>/g, ''),
      headers: {
        'List-Unsubscribe': '<mailto:unsubscribe@pluragate.org>',
        'List-Unsubscribe-Post': 'List-Unsubscribe=One-Click',
      },
    })

    // Log to database
    await supabase.from('email_logs').insert({
      recipient_email: to,
      subject,
      status: 'sent',
      sent_at: new Date().toISOString(),
    })

    return true
  } catch (error: any) {
    // Careful with logging to avoid triggering RangeError if the error object is circular or too large
    // Just log the message and code
    console.error(`Γ¥î Email send error [${error.code || 'UNKNOWN'}]:`, error.message)

    // Log failure to database
    try {
      await supabase.from('email_logs').insert({
        recipient_email: to,
        subject,
        status: 'failed',
        error_message: error.message,
      })
    } catch (logError) {
      console.error('Failed to log email failure to database')
    }

    return false
  }
}

