/**
 * External Data Service
 * 
 * Integrates with external APIs for research data:
 * - ReliefWeb: Social impact reports and documents
 * - HDX: Data Exchange datasets
 * - World Bank: Economic indicators and data
 */

import { createClient } from '@/lib/supabase/server'
import * as crypto from 'crypto'

export interface ExternalResult {
    id: string
    title: string
    snippet: string
    url: string
    source: string
    source_id: string
    date?: string
    type?: string
}

interface CacheEntry {
    response_data: unknown
    valid_until: string
}

/**
 * Generate a hash for caching purposes
 */
function hashQuery(query: string, params?: Record<string, unknown>): string {
    const content = JSON.stringify({ query, params })
    return crypto.createHash('md5').update(content).digest('hex')
}

/**
 * Check cache for existing data
 */
async function getCachedData(
    supabase: Awaited<ReturnType<typeof createClient>>,
    sourceId: string,
    queryHash: string
): Promise<unknown | null> {
    const { data } = await supabase.rpc('get_cached_external_data', {
        p_source_id: sourceId,
        p_query_hash: queryHash
    })

    if (data) {
        return (data as CacheEntry).response_data
    }
    return null
}

/**
 * Store data in cache
 */
async function cacheData(
    supabase: Awaited<ReturnType<typeof createClient>>,
    sourceId: string,
    queryHash: string,
    queryParams: Record<string, unknown>,
    responseData: unknown,
    cacheDays: number = 7
): Promise<void> {
    const validUntil = new Date()
    validUntil.setDate(validUntil.getDate() + cacheDays)

    await supabase.from('external_data_cache').insert({
        source_id: sourceId,
        query_hash: queryHash,
        query_params: queryParams,
        response_data: responseData,
        valid_until: validUntil.toISOString()
    })
}

/**
 * Search ReliefWeb API
 * Documentation: https://reliefweb.int/help/api
 */
export async function searchReliefWeb(query: string, limit: number = 5): Promise<ExternalResult[]> {
    try {
        const params = new URLSearchParams({
            appname: 'syriahub',
            query: {
                value: query,
                operator: 'AND'
            }
        } as never)

        const response = await fetch(
            `https://api.reliefweb.int/v1/reports?appname=syriahub&query[value]=${encodeURIComponent(query)}&limit=${limit}&preset=latest`,
            {
                headers: {
                    'Accept': 'application/json'
                },
                next: { revalidate: 3600 } // Cache for 1 hour
            }
        )

        if (!response.ok) {
            console.error('ReliefWeb API error:', response.status)
            return []
        }

        const data = await response.json()

        return (data.data || []).map((item: { id: string; fields: { title: string; body?: string; url_alias?: string; date?: { created?: string }; source?: { name?: string }[] } }) => ({
            id: `reliefweb-${item.id}`,
            title: item.fields?.title || 'Untitled',
            snippet: item.fields?.body?.substring(0, 200) || '',
            url: item.fields?.url_alias
                ? `https://reliefweb.int${item.fields.url_alias}`
                : `https://reliefweb.int/node/${item.id}`,
            source: 'ReliefWeb',
            source_id: 'reliefweb',
            date: item.fields?.date?.created,
            type: 'report'
        }))
    } catch (error) {
        console.error('ReliefWeb search error:', error)
        return []
    }
}

/**
 * Search Humanitarian Data Exchange (HDX)
 * Documentation: https://data.humdata.org/api/3
 */
export async function searchHDX(query: string, limit: number = 5): Promise<ExternalResult[]> {
    try {
        const response = await fetch(
            `https://data.humdata.org/api/3/action/package_search?q=${encodeURIComponent(query)}&rows=${limit}`,
            {
                headers: {
                    'Accept': 'application/json'
                },
                next: { revalidate: 3600 }
            }
        )

        if (!response.ok) {
            console.error('HDX API error:', response.status)
            return []
        }

        const data = await response.json()

        return (data.result?.results || []).map((item: { id: string; title: string; notes?: string; name: string; organization?: { title?: string }; metadata_created?: string }) => ({
            id: `hdx-${item.id}`,
            title: item.title || 'Untitled Dataset',
            snippet: item.notes?.substring(0, 200) || '',
            url: `https://data.humdata.org/dataset/${item.name}`,
            source: 'HDX',
            source_id: 'hdx',
            date: item.metadata_created,
            type: 'dataset'
        }))
    } catch (error) {
        console.error('HDX search error:', error)
        return []
    }
}

/**
 * Search World Bank Data API
 * Documentation: https://datahelpdesk.worldbank.org/knowledgebase/topics/125589
 */
export async function searchWorldBank(query: string, limit: number = 5): Promise<ExternalResult[]> {
    try {
        // World Bank doesn't have a direct search API, so we search for Syria indicators
        // and filter based on query keywords
        const response = await fetch(
            `https://api.worldbank.org/v2/country/SYR/indicator?format=json&per_page=50`,
            {
                headers: {
                    'Accept': 'application/json'
                },
                next: { revalidate: 86400 } // Cache for 24 hours (indicators don't change often)
            }
        )

        if (!response.ok) {
            console.error('World Bank API error:', response.status)
            // Return fallback link to World Bank Syria page
            return [{
                id: 'worldbank-syria',
                title: `World Bank Data: ${query}`,
                snippet: 'Explore World Bank data and indicators for Syria including GDP, population, and development metrics.',
                url: 'https://data.worldbank.org/country/syria',
                source: 'World Bank',
                source_id: 'worldbank',
                type: 'data'
            }]
        }

        const data = await response.json()
        const indicators = data[1] || []

        // Filter indicators by query keywords
        const queryLower = query.toLowerCase()
        const filteredIndicators = indicators
            .filter((ind: { indicator?: { value?: string } }) =>
                ind.indicator?.value?.toLowerCase().includes(queryLower) ||
                queryLower.split(' ').some((word: string) =>
                    ind.indicator?.value?.toLowerCase().includes(word)
                )
            )
            .slice(0, limit)

        if (filteredIndicators.length === 0) {
            // Return general Syria data link
            return [{
                id: 'worldbank-syria-search',
                title: `World Bank: Syria Development Data`,
                snippet: `Explore World Bank data related to "${query}". Access economic indicators, development metrics, and research.`,
                url: `https://data.worldbank.org/country/syria`,
                source: 'World Bank',
                source_id: 'worldbank',
                type: 'data'
            }]
        }

        return filteredIndicators.map((item: { indicator?: { id?: string; value?: string }; date?: string; value?: number }) => ({
            id: `worldbank-${item.indicator?.id}`,
            title: item.indicator?.value || 'Syria Indicator',
            snippet: `Latest value: ${item.value || 'N/A'} (${item.date || 'N/A'})`,
            url: `https://data.worldbank.org/indicator/${item.indicator?.id}?locations=SY`,
            source: 'World Bank',
            source_id: 'worldbank',
            date: item.date,
            type: 'indicator'
        }))
    } catch (error) {
        console.error('World Bank search error:', error)
        return [{
            id: 'worldbank-fallback',
            title: 'World Bank Syria Data',
            snippet: 'Access World Bank economic and development data for Syria.',
            url: 'https://data.worldbank.org/country/syria',
            source: 'World Bank',
            source_id: 'worldbank',
            type: 'data'
        }]
    }
}

/**
 * Search all external sources
 */
export async function searchAllExternalSources(query: string, limit: number = 3): Promise<ExternalResult[]> {
    const [reliefwebResults, hdxResults, worldbankResults] = await Promise.allSettled([
        searchReliefWeb(query, limit),
        searchHDX(query, limit),
        searchWorldBank(query, limit)
    ])

    const results: ExternalResult[] = []

    if (reliefwebResults.status === 'fulfilled') {
        results.push(...reliefwebResults.value)
    }
    if (hdxResults.status === 'fulfilled') {
        results.push(...hdxResults.value)
    }
    if (worldbankResults.status === 'fulfilled') {
        results.push(...worldbankResults.value)
    }

    return results
}

/**
 * Search external sources with caching
 */
export async function searchExternalWithCache(
    query: string,
    limit: number = 3
): Promise<ExternalResult[]> {
    try {
        const supabase = await createClient()
        const queryHash = hashQuery(query, { limit })

        // Check cache first
        const cached = await getCachedData(supabase, 'combined', queryHash)
        if (cached) {
            return cached as ExternalResult[]
        }

        // Fetch fresh data
        const results = await searchAllExternalSources(query, limit)

        // Cache results if any
        if (results.length > 0) {
            await cacheData(supabase, 'combined', queryHash, { query, limit }, results, 7)
        }

        return results
    } catch (error) {
        console.error('External search with cache error:', error)
        // Fall back to direct search without caching
        return searchAllExternalSources(query, limit)
    }
}

'use client'

import { useState, useEffect, useCallback, useRef } from 'react'

export interface DraftData {
    title: string
    content: string
    tags: string
    contentType: 'article' | 'question' | 'trace'
    coverImage: string | null
    license: string
    lastSaved: number
    // Spatial Insight Engine fields
    temporalCoverageStart?: string
    temporalCoverageEnd?: string
    spatialCoverage?: string
    spatialGeometry?: any // GeoJSON geometry object
}

interface UseAutosaveOptions {
    key: string
    debounceMs?: number
    enabled?: boolean
}

interface UseAutosaveResult {
    hasDraft: boolean
    draftData: DraftData | null
    lastSaved: Date | null
    restoreDraft: () => DraftData | null
    clearDraft: () => void
    saveDraft: (data: Omit<DraftData, 'lastSaved'>) => void
}

const AUTOSAVE_INTERVAL = 30000 // 30 seconds
const DRAFT_EXPIRY_HOURS = 72 // Keep drafts for 72 hours

export function useAutosave({
    key,
    debounceMs = 2000,
    enabled = true,
}: UseAutosaveOptions): UseAutosaveResult {
    const [state, setState] = useState<{
        hasDraft: boolean
        draftData: DraftData | null
        lastSaved: Date | null
    }>({
        hasDraft: false,
        draftData: null,
        lastSaved: null
    })
    const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null)
    const pendingDataRef = useRef<Omit<DraftData, 'lastSaved'> | null>(null)
    const storageKey = `syrealize_draft_${key}`

    // Immediate save function (no debounce) - used for beforeunload
    const flushSave = useCallback(() => {
        if (!enabled || !pendingDataRef.current) return
        
        const data = pendingDataRef.current
        if (!data.title.trim() && !data.content.trim()) return

        try {
            const draftWithTimestamp: DraftData = {
                ...data,
                lastSaved: Date.now(),
            }
            localStorage.setItem(storageKey, JSON.stringify(draftWithTimestamp))
            pendingDataRef.current = null
        } catch (error) {
            console.error('Error flushing draft:', error)
        }
    }, [storageKey, enabled])

    // Check for existing draft on mount - ALWAYS check regardless of `enabled` preference
    // This ensures users can restore drafts even if they've disabled autosave
    useEffect(() => {
        try {
            const stored = localStorage.getItem(storageKey)
            if (stored) {
                const parsed: DraftData = JSON.parse(stored)
                const expiryTime = parsed.lastSaved + DRAFT_EXPIRY_HOURS * 60 * 60 * 1000

                if (Date.now() > expiryTime) {
                    // Draft expired, clean up
                    localStorage.removeItem(storageKey)
                    setTimeout(() => {
                        setState({ hasDraft: false, draftData: null, lastSaved: null })
                    }, 0)
                } else if (parsed.title || parsed.content) {
                    // Valid draft exists
                    setTimeout(() => {
                        setState({
                            hasDraft: true,
                            draftData: parsed,
                            lastSaved: new Date(parsed.lastSaved)
                        })
                    }, 0)
                }
            }
        } catch (error) {
            console.error('Error loading draft:', error)
            localStorage.removeItem(storageKey)
        }
    }, [storageKey]) // Removed `enabled` dependency - always check for drafts

    // Save pending drafts when user leaves or switches tabs
    useEffect(() => {
        if (!enabled) return

        const handleBeforeUnload = () => {
            flushSave()
        }

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'hidden') {
                flushSave()
            }
        }

        window.addEventListener('beforeunload', handleBeforeUnload)
        document.addEventListener('visibilitychange', handleVisibilityChange)

        return () => {
            window.removeEventListener('beforeunload', handleBeforeUnload)
            document.removeEventListener('visibilitychange', handleVisibilityChange)
            flushSave() // Also flush on unmount
        }
    }, [enabled, flushSave])

    // Save draft function
    const saveDraft = useCallback(
        (data: Omit<DraftData, 'lastSaved'>) => {
            if (!enabled) return

            // Store pending data for flush on unmount/beforeunload
            pendingDataRef.current = data

            // Clear any pending saves
            if (saveTimeoutRef.current) {
                clearTimeout(saveTimeoutRef.current)
            }

            // Debounce the save
            saveTimeoutRef.current = setTimeout(() => {
                try {
                    // Don't save empty drafts
                    if (!data.title.trim() && !data.content.trim()) {
                        pendingDataRef.current = null
                        return
                    }

                    const draftWithTimestamp: DraftData = {
                        ...data,
                        lastSaved: Date.now(),
                    }

                    localStorage.setItem(storageKey, JSON.stringify(draftWithTimestamp))
                    pendingDataRef.current = null // Clear pending after successful save
                    setState({
                        hasDraft: true,
                        draftData: draftWithTimestamp,
                        lastSaved: new Date(draftWithTimestamp.lastSaved)
                    })
                } catch (error) {
                    console.error('Error saving draft:', error)
                }
            }, debounceMs)
        },
        [storageKey, debounceMs, enabled]
    )

    // Restore draft function
    const restoreDraft = useCallback((): DraftData | null => {
        return state.draftData
    }, [state.draftData])

    // Clear draft function
    const clearDraft = useCallback(() => {
        if (saveTimeoutRef.current) {
            clearTimeout(saveTimeoutRef.current)
        }
        pendingDataRef.current = null // Clear pending data
        localStorage.removeItem(storageKey)
        setState({ hasDraft: false, draftData: null, lastSaved: null })
    }, [storageKey])

    // Cleanup timeout on unmount
    useEffect(() => {
        return () => {
            if (saveTimeoutRef.current) {
                clearTimeout(saveTimeoutRef.current)
            }
        }
    }, [])

    return {
        ...state,
        restoreDraft,
        clearDraft,
        saveDraft,
    }
}

// Utility to format time since last save
export function formatTimeSince(date: Date): string {
    const seconds = Math.floor((Date.now() - date.getTime()) / 1000)

    if (seconds < 60) {
        return 'Just now'
    }

    const minutes = Math.floor(seconds / 60)
    if (minutes < 60) {
        return `${minutes}m ago`
    }

    const hours = Math.floor(minutes / 60)
    if (hours < 24) {
        return `${hours}h ago`
    }

    const days = Math.floor(hours / 24)
    return `${days}d ago`
}

/**
 * Offline Storage Module
 * Provides IndexedDB-based storage for offline functionality:
 * - Draft queue for saving posts when offline
 * - Article cache for offline reading
 * - Background sync coordination
 */

const DB_NAME = 'syriahub-offline'
const DB_VERSION = 1

interface DraftPost {
    id: string
    title: string
    content: string
    tags: string[]
    createdAt: number
    updatedAt: number
    syncStatus: 'pending' | 'syncing' | 'synced' | 'failed'
    retryCount: number
}

interface CachedArticle {
    id: string
    title: string
    content: string
    author: {
        name: string
        avatar_url?: string
    }
    tags: string[]
    created_at: string
    cachedAt: number
}

let db: IDBDatabase | null = null

/**
 * Initialize IndexedDB
 */
export async function initOfflineStorage(): Promise<boolean> {
    return new Promise((resolve, reject) => {
        if (!('indexedDB' in window)) {
            console.warn('[Offline] IndexedDB not supported')
            resolve(false)
            return
        }

        const request = indexedDB.open(DB_NAME, DB_VERSION)

        request.onerror = () => {
            console.error('[Offline] Failed to open database:', request.error)
            reject(request.error)
        }

        request.onsuccess = () => {
            db = request.result
            console.log('[Offline] Database initialized')
            resolve(true)
        }

        request.onupgradeneeded = (event) => {
            const database = (event.target as IDBOpenDBRequest).result

            // Drafts store
            if (!database.objectStoreNames.contains('drafts')) {
                const draftsStore = database.createObjectStore('drafts', { keyPath: 'id' })
                draftsStore.createIndex('syncStatus', 'syncStatus', { unique: false })
                draftsStore.createIndex('updatedAt', 'updatedAt', { unique: false })
            }

            // Articles cache store
            if (!database.objectStoreNames.contains('articles')) {
                const articlesStore = database.createObjectStore('articles', { keyPath: 'id' })
                articlesStore.createIndex('cachedAt', 'cachedAt', { unique: false })
            }

            // Pending actions store (for future use)
            if (!database.objectStoreNames.contains('pending_actions')) {
                database.createObjectStore('pending_actions', { keyPath: 'id', autoIncrement: true })
            }
        }
    })
}

/**
 * Get database instance
 */
function getDB(): IDBDatabase {
    if (!db) {
        throw new Error('Database not initialized. Call initOfflineStorage() first.')
    }
    return db
}

// ==================== DRAFT MANAGEMENT ====================

/**
 * Save or update a draft
 */
export async function saveDraft(draft: Omit<DraftPost, 'syncStatus' | 'retryCount'>): Promise<string> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['drafts'], 'readwrite')
        const store = transaction.objectStore('drafts')

        const draftData: DraftPost = {
            ...draft,
            updatedAt: Date.now(),
            syncStatus: 'pending',
            retryCount: 0,
        }

        const request = store.put(draftData)

        request.onsuccess = () => {
            console.log('[Offline] Draft saved:', draft.id)
            resolve(draft.id)

            // Trigger background sync if available
            if ('serviceWorker' in navigator && 'sync' in (window as any).registration) {
                ; (navigator.serviceWorker.ready as Promise<ServiceWorkerRegistration>)
                    .then((reg) => (reg as any).sync.register('sync-drafts'))
                    .catch(console.error)
            }
        }

        request.onerror = () => {
            console.error('[Offline] Failed to save draft:', request.error)
            reject(request.error)
        }
    })
}

/**
 * Get a draft by ID
 */
export async function getDraft(id: string): Promise<DraftPost | null> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['drafts'], 'readonly')
        const store = transaction.objectStore('drafts')
        const request = store.get(id)

        request.onsuccess = () => resolve(request.result || null)
        request.onerror = () => reject(request.error)
    })
}

/**
 * Get all drafts, optionally filtered by sync status
 */
export async function getAllDrafts(status?: DraftPost['syncStatus']): Promise<DraftPost[]> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['drafts'], 'readonly')
        const store = transaction.objectStore('drafts')

        let request: IDBRequest

        if (status) {
            const index = store.index('syncStatus')
            request = index.getAll(status)
        } else {
            request = store.getAll()
        }

        request.onsuccess = () => {
            const drafts = request.result as DraftPost[]
            // Sort by updated time, newest first
            drafts.sort((a, b) => b.updatedAt - a.updatedAt)
            resolve(drafts)
        }
        request.onerror = () => reject(request.error)
    })
}

/**
 * Delete a draft
 */
export async function deleteDraft(id: string): Promise<void> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['drafts'], 'readwrite')
        const store = transaction.objectStore('drafts')
        const request = store.delete(id)

        request.onsuccess = () => resolve()
        request.onerror = () => reject(request.error)
    })
}

/**
 * Update draft sync status
 */
export async function updateDraftStatus(
    id: string,
    status: DraftPost['syncStatus'],
    incrementRetry = false
): Promise<void> {
    const draft = await getDraft(id)
    if (!draft) return

    draft.syncStatus = status
    if (incrementRetry) {
        draft.retryCount += 1
    }

    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['drafts'], 'readwrite')
        const store = transaction.objectStore('drafts')
        const request = store.put(draft)

        request.onsuccess = () => resolve()
        request.onerror = () => reject(request.error)
    })
}

// ==================== ARTICLE CACHE ====================

/**
 * Cache an article for offline reading
 */
export async function cacheArticle(article: Omit<CachedArticle, 'cachedAt'>): Promise<void> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['articles'], 'readwrite')
        const store = transaction.objectStore('articles')

        const cachedArticle: CachedArticle = {
            ...article,
            cachedAt: Date.now(),
        }

        const request = store.put(cachedArticle)

        request.onsuccess = () => {
            console.log('[Offline] Article cached:', article.id)
            resolve()
        }
        request.onerror = () => reject(request.error)
    })
}

/**
 * Get a cached article
 */
export async function getCachedArticle(id: string): Promise<CachedArticle | null> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['articles'], 'readonly')
        const store = transaction.objectStore('articles')
        const request = store.get(id)

        request.onsuccess = () => resolve(request.result || null)
        request.onerror = () => reject(request.error)
    })
}

/**
 * Get all cached articles
 */
export async function getAllCachedArticles(): Promise<CachedArticle[]> {
    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['articles'], 'readonly')
        const store = transaction.objectStore('articles')
        const request = store.getAll()

        request.onsuccess = () => {
            const articles = request.result as CachedArticle[]
            // Sort by cached time, newest first
            articles.sort((a, b) => b.cachedAt - a.cachedAt)
            resolve(articles)
        }
        request.onerror = () => reject(request.error)
    })
}

/**
 * Clean up old cached articles (older than 7 days)
 */
export async function cleanupArticleCache(maxAgeDays = 7): Promise<number> {
    const maxAge = maxAgeDays * 24 * 60 * 60 * 1000
    const cutoffTime = Date.now() - maxAge
    let deletedCount = 0

    return new Promise((resolve, reject) => {
        const database = getDB()
        const transaction = database.transaction(['articles'], 'readwrite')
        const store = transaction.objectStore('articles')
        const index = store.index('cachedAt')
        const range = IDBKeyRange.upperBound(cutoffTime)
        const cursorRequest = index.openCursor(range)

        cursorRequest.onsuccess = (event) => {
            const cursor = (event.target as IDBRequest).result
            if (cursor) {
                cursor.delete()
                deletedCount++
                cursor.continue()
            }
        }

        transaction.oncomplete = () => {
            console.log('[Offline] Cleaned up', deletedCount, 'old articles')
            resolve(deletedCount)
        }
        transaction.onerror = () => reject(transaction.error)
    })
}

// ==================== SYNC MANAGEMENT ====================

/**
 * Get count of pending items
 */
export async function getPendingCount(): Promise<number> {
    const drafts = await getAllDrafts('pending')
    return drafts.length
}

/**
 * Check if we're online
 */
export function isOnline(): boolean {
    return navigator.onLine
}

/**
 * Register online/offline listeners
 */
export function registerConnectivityListeners(
    onOnline?: () => void,
    onOffline?: () => void
): () => void {
    const handleOnline = () => {
        console.log('[Offline] Connection restored')
        onOnline?.()
    }

    const handleOffline = () => {
        console.log('[Offline] Connection lost')
        onOffline?.()
    }

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    // Return cleanup function
    return () => {
        window.removeEventListener('online', handleOnline)
        window.removeEventListener('offline', handleOffline)
    }
}

/**
 * Sync pending drafts when online
 */
export async function syncPendingDrafts(
    submitFn: (draft: DraftPost) => Promise<boolean>
): Promise<{ synced: number; failed: number }> {
    const pendingDrafts = await getAllDrafts('pending')
    let synced = 0
    let failed = 0

    for (const draft of pendingDrafts) {
        if (draft.retryCount >= 3) {
            await updateDraftStatus(draft.id, 'failed')
            failed++
            continue
        }

        await updateDraftStatus(draft.id, 'syncing')

        try {
            const success = await submitFn(draft)
            if (success) {
                await deleteDraft(draft.id)
                synced++
            } else {
                await updateDraftStatus(draft.id, 'pending', true)
                failed++
            }
        } catch (error) {
            console.error('[Offline] Sync failed for draft:', draft.id, error)
            await updateDraftStatus(draft.id, 'pending', true)
            failed++
        }
    }

    return { synced, failed }
}

import { createClient, SupabaseClient } from '@supabase/supabase-js'
import { config } from 'dotenv'

// Load environment variables for scripts
config({ path: '.env.local' })

// ==================== Configuration ====================

// Rate limiting: Maximum AI analyses per hour (persistent via database)
const MAX_ANALYSES_PER_HOUR = 30

// Model configuration - use gpt-4o-mini for cost efficiency
const OPENAI_MODEL = 'gpt-4o-mini' // ~$0.15/1M input vs $2.50/1M for gpt-4o
const MAX_TOKENS = 1000 // Limit response size

// Content limits to reduce token usage
const MAX_CONTENT_LENGTH = 3000 // Truncate long posts
const MAX_CONTEXT_POSTS = 5 // Fewer comparison posts
const MAX_CONTEXT_CONTENT_LENGTH = 200 // Shorter excerpts

// ==================== Rate Limiting (Database-backed) ====================

async function checkRateLimit(supabase: SupabaseClient): Promise<{ allowed: boolean; remaining: number }> {
    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString()

    // Count recent analyses from database
    const { count, error } = await supabase
        .from('ai_rate_limits')
        .select('*', { count: 'exact', head: true })
        .eq('action_type', 'recommendation_analysis')
        .gte('executed_at', oneHourAgo)

    if (error) {
        console.error('[RecomAI] Rate limit check failed:', error)
        // Fail open but log the issue
        return { allowed: true, remaining: MAX_ANALYSES_PER_HOUR }
    }

    const used = count || 0
    const remaining = MAX_ANALYSES_PER_HOUR - used

    if (remaining <= 0) {
        console.warn(`[RecomAI] Rate limit reached: ${used}/${MAX_ANALYSES_PER_HOUR} per hour`)
        return { allowed: false, remaining: 0 }
    }

    return { allowed: true, remaining }
}

async function recordAnalysis(supabase: SupabaseClient): Promise<void> {
    const { error } = await supabase
        .from('ai_rate_limits')
        .insert({ action_type: 'recommendation_analysis' })

    if (error) {
        console.error('[RecomAI] Failed to record analysis:', error)
    }
}

// ==================== Supabase Client ====================

const getSupabase = () => {
    const url = process.env.NEXT_PUBLIC_SUPABASE_URL
    const key = process.env.SUPABASE_SERVICE_ROLE_KEY
    if (!url || !key) throw new Error('Supabase credentials missing')
    return createClient(url, key)
}

// ==================== Main Analysis Function ====================

export interface AnalysisResult {
    trustProfile: any
    relationships: any[]
    disciplines: string[]
    evidence: any
}

/**
 * Analyzes a post to extract trust vectors, disciplines, and relationships.
 * Includes rate limiting and cost optimization.
 */
export async function analyzePostForRecommendations(
    postId: string,
    title: string,
    content: string,
    tags: string[] = [],
    options: { force?: boolean } = {}
): Promise<AnalysisResult | null> {
    try {
        const supabase = getSupabase()

        // 1. Check rate limit
        const rateCheck = await checkRateLimit(supabase)
        if (!rateCheck.allowed) {
            console.log(`[RecomAI] Skipping analysis due to rate limit. Remaining: ${rateCheck.remaining}`)
            return null
        }

        // 2. Check if already analyzed (skip unless forced)
        if (!options.force) {
            const { data: existing } = await supabase
                .from('trust_profiles')
                .select('id, updated_at')
                .eq('content_id', postId)
                .eq('content_type', 'post')
                .single()

            if (existing) {
                const lastUpdate = new Date(existing.updated_at)
                const hoursSinceUpdate = (Date.now() - lastUpdate.getTime()) / (1000 * 60 * 60)

                // Skip if analyzed within the last 24 hours
                if (hoursSinceUpdate < 24) {
                    console.log(`[RecomAI] Skipping: Post already analyzed ${hoursSinceUpdate.toFixed(1)}h ago`)
                    return null
                }
            }
        }

        // 3. Check API key
        const apiKey = process.env.OPENAI_API_KEY
        if (!apiKey) {
            console.error('[RecomAI] OPENAI_API_KEY is missing')
            return null
        }

        console.log(`[RecomAI] Analyzing: ${title} (${postId})`)

        // 4. Fetch context posts (limited for cost)
        const { data: recentPosts } = await supabase
            .from('posts')
            .select('id, title, content, tags')
            .eq('status', 'published')
            .neq('id', postId)
            .order('created_at', { ascending: false })
            .limit(MAX_CONTEXT_POSTS)

        const recentPostsText = recentPosts?.map(p =>
            `ID: ${p.id}\nTitle: ${p.title}\nContent: ${p.content.slice(0, MAX_CONTEXT_CONTENT_LENGTH)}...`
        ).join('\n---\n') || 'No recent posts.'

        // 5. Truncate content for cost efficiency
        const truncatedContent = content.length > MAX_CONTENT_LENGTH
            ? content.slice(0, MAX_CONTENT_LENGTH) + '...[truncated]'
            : content

        // 6. Optimized prompt (shorter, focused)
        const systemPrompt = `Analyze Syrian conflict research. Output JSON:
{
  "trust_profile": { "t1_source_score": 0-100, "t2_method_score": 0-100, "t3_proximity_type": "on_site"|"remote"|"inferred", "t3_proximity_score": 0-100, "t4_conflict_phase": "pre_conflict"|"active_conflict"|"de_escalation"|"early_reconstruction"|"active_reconstruction" },
  "disciplines": ["string"],
  "evidence": { "evidence_type": "field_survey"|"satellite_imagery"|"academic_paper"|"ngo_assessment"|"news_article"|"expert_commentary", "evidence_tier": "primary"|"secondary"|"derived"|"interpretive" },
  "relationships": [ { "target_id": "uuid", "relationship": "contradicts"|"supports"|"same_site", "detail": "string" } ]
}`

        const userPrompt = `Post: "${title}"\nTags: ${tags.join(', ')}\nContent: ${truncatedContent}\n\nContext posts:\n${recentPostsText}`

        // 7. Make API call with cost controls
        console.log(`[RecomAI] Calling ${OPENAI_MODEL}...`)
        const response = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify({
                model: OPENAI_MODEL,
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ],
                response_format: { type: 'json_object' },
                max_tokens: MAX_TOKENS,
                temperature: 0.3 // Lower temperature for more consistent output
            })
        })

        if (!response.ok) {
            const errorText = await response.text()
            throw new Error(`OpenAI API Error: ${response.status} ${errorText}`)
        }

        // Record successful API call for rate limiting
        await recordAnalysis(supabase)

        const data = await response.json()
        const analysis = JSON.parse(data.choices[0].message.content || '{}')

        // Log token usage for cost monitoring
        if (data.usage) {
            console.log(`[RecomAI] Tokens used: ${data.usage.total_tokens} (input: ${data.usage.prompt_tokens}, output: ${data.usage.completion_tokens})`)
        }

        // 8. Store results
        const { error: trustError } = await supabase
            .from('trust_profiles')
            .upsert({
                content_id: postId,
                content_type: 'post',
                ...analysis.trust_profile,
                updated_at: new Date().toISOString()
            }, { onConflict: 'content_id,content_type' })

        if (trustError) console.error('[RecomAI] Trust Profile Error:', trustError)

        if (analysis.disciplines?.length > 0) {
            const disciplineInserts = analysis.disciplines.map((d: string, i: number) => ({
                content_id: postId,
                content_type: 'post',
                discipline: d,
                is_primary: i === 0
            }))
            await supabase.from('content_disciplines').upsert(disciplineInserts, { onConflict: 'content_id,content_type,discipline' })
        }

        if (analysis.evidence) {
            await supabase.from('content_evidence').upsert({
                content_id: postId,
                content_type: 'post',
                ...analysis.evidence
            }, { onConflict: 'content_id,content_type' })
        }

        if (analysis.relationships?.length > 0) {
            const relationshipInserts = analysis.relationships.map((r: any) => ({
                source_id: postId,
                source_type: 'post',
                target_id: r.target_id,
                target_type: 'post',
                relationship: r.relationship,
                relationship_detail: r.detail,
                detected_by: 'ai',
                confidence: 0.8
            }))
            await supabase.from('content_relationships').upsert(
                relationshipInserts,
                { onConflict: 'source_id,source_type,target_id,target_type,relationship' }
            )
        }

        console.log(`[RecomAI] Γ£à Analysis complete for ${postId}`)
        return analysis

    } catch (error) {
        console.error('[RecomAI] Γ¥î Error:', error)
        return null
    }
}

/**
 * Get current rate limit status (database-backed)
 */
export async function getRateLimitStatus(): Promise<{ used: number; limit: number; remaining: number }> {
    try {
        const supabase = getSupabase()
        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString()

        const { count, error } = await supabase
            .from('ai_rate_limits')
            .select('*', { count: 'exact', head: true })
            .eq('action_type', 'recommendation_analysis')
            .gte('executed_at', oneHourAgo)

        if (error) {
            console.error('[RecomAI] Rate limit status check failed:', error)
            return { used: 0, limit: MAX_ANALYSES_PER_HOUR, remaining: MAX_ANALYSES_PER_HOUR }
        }

        const used = count || 0
        return {
            used,
            limit: MAX_ANALYSES_PER_HOUR,
            remaining: Math.max(0, MAX_ANALYSES_PER_HOUR - used)
        }
    } catch (error) {
        console.error('[RecomAI] Rate limit status error:', error)
        return { used: 0, limit: MAX_ANALYSES_PER_HOUR, remaining: MAX_ANALYSES_PER_HOUR }
    }
}

